RICETTE_DB=[{id:"tpl_1021",nome:"Pasta al pesto genovese",nome_en:"Pasta with Genoese pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare basilico, pinoli, aglio, pecorino, parmigiano e olio a freddo. Cuocere le trofie in acqua salata. Scolare al dente, mantecare con il pesto aggiungendo un cucchiaio di acqua di cottura.",note_en:"Blend basil, pine nuts, garlic, pecorino, parmesan and oil cold. Cook trofie in salted water. Drain al dente, toss with pesto adding a spoonful of cooking water.",ingredienti:[{nome:"Trofie",qt:"320g"},{nome:"Basilico fresco",qt:"60g"},{nome:"Pinoli",qt:"40g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Pecorino grattugiato",qt:"20g"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Pasta al pesto genovese (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:13,gs:3,g:18,z:2,ch:55,fi:2.5,ca:120,fe:2,mg:40,k2:200,na:180,zn:1.2,fo:30,se:8,col:8}},{id:"tpl_1022",nome:"Pasta e fagioli napoletana",nome_en:"Neapolitan pasta and beans",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio, rosmarino e pomodoro. Aggiungere fagioli borlotti lessati e brodo. Cuocere 15 minuti. Aggiungere pasta mista corta e cuocere al dente. Finire con olio crudo e pepe.",note_en:"Sauté garlic, rosemary and tomato. Add boiled borlotti beans and stock. Cook 15 minutes. Add mixed short pasta and cook al dente. Finish with raw oil and pepper.",ingredienti:[{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Pasta mista",qt:"200g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"500ml"}],_dbEntry:{n:"Pasta e fagioli napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:1,g:7,z:3,ch:52,fi:9,ca:70,fe:3.5,mg:60,k2:580,na:320,zn:1.5,fo:120,se:6,col:0}},{id:"tpl_1023",nome:"Risotto ai funghi porcini",nome_en:"Porcini mushroom risotto",categoria:"Primo piatto",porzioni:4,note:"Ammollare i porcini secchi 30 minuti. Soffriggere scalogno, aggiungere riso e tostare. Sfumare con vino bianco. Aggiungere brodo caldo mestolo per mestolo. Aggiungere i porcini ammollati. Mantecare con burro e parmigiano.",note_en:"Soak dried porcini 30 minutes. Sauté shallot, add rice and toast. Deglaze with white wine. Add hot stock ladle by ladle. Add soaked porcini. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Porcini secchi",qt:"30g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano grattugiato",qt:"50g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto ai funghi porcini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:5,g:10,z:2,ch:60,fi:1.5,ca:110,fe:1.5,mg:30,k2:220,na:350,zn:1,fo:25,se:10,col:30}},{id:"tpl_1024",nome:"Spaghetti alla carbonara",nome_en:"Spaghetti carbonara",categoria:"Primo piatto",porzioni:4,note:"Rosolare guanciale a cubetti in padella senza olio fino a croccante. Sbattere tuorli con pecorino e pepe nero. Cuocere gli spaghetti al dente, scolare tenendo acqua di cottura. Mantecare fuori fuoco amalgamando uova e guanciale con poca acqua di cottura.",note_en:"Brown diced guanciale in pan without oil until crispy. Beat egg yolks with pecorino and black pepper. Cook spaghetti al dente, drain keeping cooking water. Toss off heat combining eggs and guanciale with a little cooking water.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Guanciale",qt:"150g"},{nome:"Tuorli d uovo",qt:"6"},{nome:"Pecorino romano",qt:"80g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Spaghetti alla carbonara (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:22,gs:8,g:20,z:1,ch:55,fi:1,ca:200,fe:2,mg:35,k2:250,na:700,zn:2.5,fo:60,se:20,col:320}},{id:"tpl_1025",nome:"Lasagne al forno classiche",nome_en:"Classic baked lasagne",categoria:"Primo piatto",porzioni:6,note:"Preparare ragu di carne con macinato, pomodoro e soffritto. Preparare besciamella. Alternare strati di pasta, ragu, besciamella e parmigiano in teglia. Cuocere in forno a 180 C per 45 minuti.",note_en:"Prepare meat ragu with mince, tomato and soffritto. Make bechamel. Alternate layers of pasta, ragu, bechamel and parmesan in baking dish. Bake at 180 C for 45 minutes.",ingredienti:[{nome:"Lasagne fresche",qt:"400g"},{nome:"Macinato misto",qt:"400g"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Latte intero",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"80g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Lasagne al forno classiche (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:6,g:16,z:4,ch:38,fi:2,ca:220,fe:2.5,mg:35,k2:420,na:480,zn:3,fo:40,se:18,col:85}},{id:"tpl_1026",nome:"Minestra di ceci e rosmarino",nome_en:"Chickpea and rosemary soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio e rosmarino in olio. Aggiungere ceci lessati e brodo. Frullare meta della zuppa per darle cremosita. Aggiungere pasta corta o pasta mista. Cuocere al dente e servire con olio crudo.",note_en:"Sauté garlic and rosemary in oil. Add cooked chickpeas and stock. Blend half the soup for creaminess. Add short pasta. Cook al dente and serve with raw oil.",ingredienti:[{nome:"Ceci cotti",qt:"500g"},{nome:"Pasta corta",qt:"160g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Minestra di ceci e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:15,gs:1,g:8,z:2,ch:52,fi:11,ca:80,fe:4,mg:65,k2:600,na:280,zn:2,fo:140,se:5,col:0}},{id:"tpl_1027",nome:"Risotto alla milanese",nome_en:"Milanese saffron risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla in burro e midollo. Tostare il riso, sfumare con vino bianco. Aggiungere brodo caldo a mestoli. A meta cottura aggiungere lo zafferano sciolto in brodo caldo. Mantecare con burro freddo e parmigiano.",note_en:"Sauté onion in butter and marrow. Toast rice, deglaze with white wine. Add hot stock in ladles. Halfway through add saffron dissolved in hot stock. Stir in cold butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Cipolla bianca",qt:"1"},{nome:"Midollo di bue",qt:"30g"},{nome:"Burro",qt:"60g"},{nome:"Parmigiano",qt:"60g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo di carne",qt:"1L"}],_dbEntry:{n:"Risotto alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:12,gs:7,g:14,z:2,ch:58,fi:.5,ca:130,fe:1.5,mg:28,k2:200,na:400,zn:1.2,fo:20,se:8,col:45}},{id:"tpl_1028",nome:"Pasta al pomodoro fresco",nome_en:"Pasta with fresh tomato",categoria:"Primo piatto",porzioni:4,note:"Scottare i pomodori in acqua bollente, pelarli e tagliarli a pezzi. Soffriggere aglio in olio, aggiungere pomodori e cuocere 15 minuti. Cuocere la pasta al dente. Condire con il sugo e basilico fresco.",note_en:"Blanch tomatoes in boiling water, peel and chop. Sauté garlic in oil, add tomatoes and cook 15 minutes. Cook pasta al dente. Dress with sauce and fresh basil.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori maturi",qt:"600g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Pasta al pomodoro fresco (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:11,gs:1,g:8,z:5,ch:60,fi:3,ca:40,fe:2,mg:38,k2:380,na:160,zn:.9,fo:35,se:7,col:0}},{id:"tpl_1029",nome:"Gnocchi al gorgonzola e noci",nome_en:"Gnocchi with gorgonzola and walnuts",categoria:"Primo piatto",porzioni:4,note:"Sciogliere il gorgonzola a fuoco basso con panna e poco latte. Aggiustare di sale e pepe. Cuocere gli gnocchi in acqua salata finche vengono a galla. Scolare e condire con la crema di gorgonzola. Aggiungere gherigli di noce tritati.",note_en:"Melt gorgonzola over low heat with cream and a little milk. Season with salt and pepper. Cook gnocchi in salted water until they float. Drain and dress with gorgonzola cream. Add chopped walnuts.",ingredienti:[{nome:"Gnocchi di patate",qt:"600g"},{nome:"Gorgonzola dolce",qt:"150g"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Gherigli di noce",qt:"50g"},{nome:"Latte",qt:"50ml"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Gnocchi al gorgonzola e noci (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:14,gs:9,g:18,z:2,ch:52,fi:2,ca:180,fe:1.5,mg:45,k2:280,na:520,zn:1.8,fo:25,se:6,col:55}},{id:"tpl_1030",nome:"Penne all arrabbiata",nome_en:"Penne arrabbiata",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in abbondante olio. Aggiungere pomodori pelati spezzettati e cuocere 20 minuti. Cuocere le penne al dente. Scolare e saltare nel sugo. Aggiungere prezzemolo tritato.",note_en:"Sauté garlic and chilli in plenty of oil. Add chopped peeled tomatoes and cook 20 minutes. Cook penne al dente. Drain and toss in sauce. Add chopped parsley.",ingredienti:[{nome:"Penne rigate",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Penne all arrabbiata (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:11,gs:1,g:10,z:4,ch:60,fi:3,ca:35,fe:2.2,mg:38,k2:380,na:200,zn:.9,fo:30,se:7,col:0}},{id:"tpl_1031",nome:"Ribollita toscana",nome_en:"Tuscan ribollita",categoria:"Primo piatto",porzioni:6,note:"Soffriggere cipolla, carota, sedano. Aggiungere fagioli cannellini, cavolo nero, verza, pane raffermo e brodo. Cuocere 40 minuti. Aggiustare di sale. La ribollita si riscalda il giorno dopo con olio crudo.",note_en:"Sauté onion, carrot, celery. Add cannellini beans, cavolo nero, savoy cabbage, stale bread and stock. Cook 40 minutes. Season with salt. Ribollita is reheated the next day with raw oil.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Cavolo nero",qt:"300g"},{nome:"Verza",qt:"200g"},{nome:"Pane raffermo toscano",qt:"200g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo vegetale",qt:"800ml"}],_dbEntry:{n:"Ribollita toscana (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:1,g:7,z:4,ch:44,fi:10,ca:100,fe:3.5,mg:55,k2:550,na:360,zn:1.5,fo:110,se:4,col:0}},{id:"tpl_1032",nome:"Pasta con le sarde",nome_en:"Pasta with sardines",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla con finocchietto selvatico. Aggiungere sarde fresche pulite, pinoli, uvetta e zafferano. Cuocere 10 minuti. Cuocere i bucatini al dente, condire con il sugo. Tostare pangrattato in olio e spolverare sul piatto.",note_en:"Sauté onion with wild fennel. Add cleaned fresh sardines, pine nuts, raisins and saffron. Cook 10 minutes. Cook bucatini al dente, dress with sauce. Toast breadcrumbs in oil and sprinkle over dish.",ingredienti:[{nome:"Bucatini",qt:"320g"},{nome:"Sarde fresche",qt:"300g"},{nome:"Finocchietto selvatico",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Pinoli",qt:"30g"},{nome:"Uvetta",qt:"30g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Pangrattato",qt:"40g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con le sarde (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:20,gs:2,g:12,z:5,ch:58,fi:3,ca:120,fe:2.5,mg:50,k2:380,na:280,zn:1.5,fo:45,se:30,col:45}},{id:"tpl_1033",nome:"Risotto al radicchio e speck",nome_en:"Risotto with radicchio and speck",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Aggiungere speck a cubetti e rosolare. Aggiungere radicchio tagliato e far appassire. Tostare il riso e sfumare con vino rosso. Aggiungere brodo caldo. Mantecare con burro e parmigiano.",note_en:"Sauté shallot in butter. Add diced speck and brown. Add sliced radicchio and wilt. Toast rice and deglaze with red wine. Add hot stock. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Vialone Nano",qt:"320g"},{nome:"Radicchio",qt:"200g"},{nome:"Speck",qt:"100g"},{nome:"Scalogno",qt:"2"},{nome:"Vino rosso",qt:"100ml"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto al radicchio e speck (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:15,gs:5,g:11,z:3,ch:58,fi:1.5,ca:100,fe:2,mg:28,k2:280,na:650,zn:1.5,fo:30,se:12,col:35}},{id:"tpl_1034",nome:"Zuppa di lenticchie rosse",nome_en:"Red lentil soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e curcuma in olio. Aggiungere lenticchie rosse lavate e brodo. Cuocere 25 minuti. Frullare fino a crema liscia. Aggiustare di sale e pepe. Servire con pane tostato e olio al rosmarino.",note_en:"Sauté onion, garlic and turmeric in oil. Add washed red lentils and stock. Cook 25 minutes. Blend to smooth cream. Season with salt and pepper. Serve with toasted bread and rosemary oil.",ingredienti:[{nome:"Lenticchie rosse",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zuppa di lenticchie rosse (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:17,gs:.8,g:5,z:3,ch:48,fi:10,ca:55,fe:4,mg:65,k2:620,na:350,zn:2,fo:160,se:6,col:0}},{id:"tpl_1035",nome:"Pasta con broccoli e acciughe",nome_en:"Pasta with broccoli and anchovies",categoria:"Primo piatto",porzioni:4,note:"Lessare i broccoli in acqua salata, tenere lacqua di cottura per la pasta. Soffriggere aglio, acciughe e peperoncino in olio fino a sciogliere le acciughe. Cuocere la pasta nell acqua dei broccoli. Saltare tutto insieme.",note_en:"Boil broccoli in salted water, keep cooking water for pasta. Sauté garlic, anchovies and chilli in oil until anchovies dissolve. Cook pasta in broccoli water. Toss everything together.",ingredienti:[{nome:"Orecchiette",qt:"320g"},{nome:"Broccoli",qt:"400g"},{nome:"Acciughe sott olio",qt:"6"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con broccoli e acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:15,gs:1.5,g:10,z:3,ch:55,fi:5,ca:80,fe:2.5,mg:55,k2:450,na:380,zn:1.5,fo:90,se:12,col:12}},{id:"tpl_1036",nome:"Risi e bisi veneti",nome_en:"Venetian rice and peas",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla e pancetta in burro. Aggiungere piselli freschi e brodo. Aggiungere il riso e cuocere aggiungendo brodo. Il piatto deve risultare piu morbido di un risotto. Mantecare con burro e parmigiano.",note_en:"Sauté onion and pancetta in butter. Add fresh peas and stock. Add rice and cook adding stock. Dish should be softer than a risotto. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Vialone Nano",qt:"280g"},{nome:"Piselli freschi",qt:"400g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Brodo vegetale",qt:"1.2L"}],_dbEntry:{n:"Risi e bisi veneti (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:14,gs:4,g:10,z:5,ch:54,fi:5,ca:100,fe:2,mg:40,k2:350,na:420,zn:1.2,fo:60,se:8,col:35}},{id:"tpl_1037",nome:"Pasta alla norma",nome_en:"Pasta alla Norma",categoria:"Primo piatto",porzioni:4,note:"Friggere melanzane a cubetti in olio abbondante, scolare su carta. Preparare sugo di pomodoro con aglio e basilico. Cuocere la pasta al dente. Condire con sugo, melanzane fritte e ricotta salata grattugiata.",note_en:"Fry diced aubergine in plenty of oil, drain on paper. Prepare tomato sauce with garlic and basil. Cook pasta al dente. Dress with sauce, fried aubergine and grated salted ricotta.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Melanzane",qt:"400g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Ricotta salata",qt:"80g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio per friggere",qt:"200ml"}],_dbEntry:{n:"Pasta alla norma (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:13,gs:2,g:14,z:5,ch:62,fi:4,ca:100,fe:2,mg:38,k2:400,na:280,zn:1,fo:40,se:8,col:10}},{id:"tpl_1038",nome:"Zuppa di farro e verdure",nome_en:"Farro and vegetable soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, carota, sedano e aglio. Aggiungere farro perlato, pomodori a cubetti e brodo vegetale. Cuocere 40 minuti. Aggiungere erbe aromatiche. Servire con olio extravergine a crudo.",note_en:"Sauté onion, carrot, celery and garlic. Add pearled farro, diced tomatoes and vegetable stock. Cook 40 minutes. Add aromatic herbs. Serve with raw extra virgin olive oil.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori a pezzetti",qt:"200g"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Erbe miste",qt:"q.b."}],_dbEntry:{n:"Zuppa di farro e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:10,gs:.5,g:5,z:4,ch:48,fi:7,ca:50,fe:2.5,mg:55,k2:450,na:320,zn:1.5,fo:55,se:6,col:0}},{id:"tpl_1039",nome:"Pasta e patate alla napoletana",nome_en:"Neapolitan pasta and potatoes",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e rosmarino. Aggiungere patate a cubetti e pomodori. Versare brodo e cuocere 20 minuti. Aggiungere pasta mista e finire la cottura. Il piatto deve essere cremoso. Finire con pecorino e olio.",note_en:"Sauté onion, garlic and rosemary. Add diced potatoes and tomatoes. Pour in stock and cook 20 minutes. Add mixed pasta and finish cooking. Dish should be creamy. Finish with pecorino and oil.",ingredienti:[{nome:"Pasta mista",qt:"200g"},{nome:"Patate",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"800ml"}],_dbEntry:{n:"Pasta e patate alla napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:10,gs:1.5,g:7,z:3,ch:58,fi:4,ca:80,fe:2,mg:40,k2:700,na:380,zn:1,fo:35,se:5,col:8}},{id:"tpl_1040",nome:"Risotto al limone e gamberi",nome_en:"Lemon and prawn risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere gamberi sgusciati, rosolare e togliere. Tostare il riso, sfumare con prosecco. Aggiungere brodo di pesce. A cottura quasi ultimata rimettere i gamberi. Mantecare con olio e scorza di limone.",note_en:"Sauté shallot in oil. Add peeled prawns, brown and remove. Toast rice, deglaze with prosecco. Add fish stock. Near end of cooking return prawns. Stir in oil and lemon zest.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Limone",qt:"2"},{nome:"Prosecco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Risotto al limone e gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:18,gs:1.5,g:8,z:2,ch:54,fi:.5,ca:80,fe:2,mg:45,k2:380,na:380,zn:2,fo:35,se:25,col:120}},{id:"tpl_1041",nome:"Strozzapreti al ragu di salsiccia",nome_en:"Strozzapreti with sausage ragu",categoria:"Primo piatto",porzioni:4,note:"Rosolare la salsiccia sbriciolata con cipolla e aglio. Sfumare con vino rosso. Aggiungere pomodoro e cuocere 30 minuti. Cuocere gli strozzapreti al dente. Condire con il ragu e pecorino grattugiato.",note_en:"Brown crumbled sausage with onion and garlic. Deglaze with red wine. Add tomato and cook 30 minutes. Cook strozzapreti al dente. Dress with ragu and grated pecorino.",ingredienti:[{nome:"Strozzapreti",qt:"320g"},{nome:"Salsiccia",qt:"250g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"100ml"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Strozzapreti al ragu di salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:20,gs:5,g:15,z:4,ch:56,fi:2.5,ca:90,fe:2.5,mg:35,k2:380,na:580,zn:2.5,fo:30,se:15,col:55}},{id:"tpl_1042",nome:"Pasta al tonno e capperi",nome_en:"Pasta with tuna and capers",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere tonno sgocciolato sbriciolato. Aggiungere capperi, olive, pomodorini. Cuocere 10 minuti. Cuocere la pasta al dente. Condire con il sugo e prezzemolo fresco.",note_en:"Sauté garlic in oil, add drained crumbled tuna. Add capers, olives, cherry tomatoes. Cook 10 minutes. Cook pasta al dente. Dress with sauce and fresh parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Tonno sott olio",qt:"200g"},{nome:"Capperi",qt:"30g"},{nome:"Olive nere",qt:"60g"},{nome:"Pomodorini",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta al tonno e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:22,gs:2,g:10,z:3,ch:54,fi:2.5,ca:50,fe:2,mg:45,k2:450,na:680,zn:1.5,fo:35,se:35,col:30}},{id:"tpl_1043",nome:"Pasta alla gricia",nome_en:"Pasta alla gricia",categoria:"Primo piatto",porzioni:4,note:"Rosolare il guanciale tagliato a listelli in padella senza olio fino a croccante. Cuocere i rigatoni al dente, scolare tenendo acqua di cottura. Mantecare in padella con guanciale, pecorino grattugiato e pepe nero. Aggiungere acqua di cottura per ottenere una crema.",note_en:"Brown guanciale strips in pan without oil until crispy. Cook rigatoni al dente, drain keeping cooking water. Toss in pan with guanciale, grated pecorino and black pepper. Add cooking water to achieve a cream.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Guanciale",qt:"150g"},{nome:"Pecorino romano",qt:"80g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla gricia (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:19,gs:7,g:16,z:1,ch:58,fi:1,ca:170,fe:1.5,mg:30,k2:220,na:700,zn:2,fo:20,se:15,col:55}},{id:"tpl_1044",nome:"Zuppa di cipolle gratinata",nome_en:"Gratineed onion soup",categoria:"Primo piatto",porzioni:4,note:"Affettare cipolle e cuocere lentamente in burro per 40 minuti fino a caramellare. Sfumare con vino bianco. Aggiungere brodo di carne. Versare in ciotole da forno, coprire con pane tostato e formaggio groviera. Gratinare in forno a 200 C.",note_en:"Slice onions and cook slowly in butter for 40 minutes until caramelised. Deglaze with white wine. Add beef stock. Pour into oven bowls, cover with toasted bread and gruyere. Gratinee in oven at 200 C.",ingredienti:[{nome:"Cipolle",qt:"800g"},{nome:"Brodo di carne",qt:"800ml"},{nome:"Burro",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Pane raffermo",qt:"100g"},{nome:"Groviera",qt:"100g"}],_dbEntry:{n:"Zuppa di cipolle gratinata (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:5,g:12,z:10,ch:35,fi:3,ca:250,fe:1,mg:30,k2:280,na:650,zn:1.5,fo:30,se:6,col:40}},{id:"tpl_1045",nome:"Risotto agli asparagi",nome_en:"Asparagus risotto",categoria:"Primo piatto",porzioni:4,note:"Cuocere gli asparagi, tenere le punte e frullare i gambi con poco brodo. Soffriggere scalogno, tostare riso e sfumare con vino bianco. Aggiungere brodo e la crema di asparagi. A meta cottura aggiungere le punte. Mantecare con burro e parmigiano.",note_en:"Cook asparagus, keep tips and blend stalks with a little stock. Sauté shallot, toast rice and deglaze with white wine. Add stock and asparagus cream. Halfway add tips. Stir in butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Asparagi",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto agli asparagi (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:4,g:9,z:3,ch:59,fi:2.5,ca:90,fe:2,mg:30,k2:300,na:350,zn:1,fo:80,se:5,col:25}},{id:"tpl_1046",nome:"Pasta con zucchine e fiori",nome_en:"Pasta with courgettes and flowers",categoria:"Primo piatto",porzioni:4,note:"Affettare le zucchine e saltare in olio con aglio. Aggiungere i fiori di zucca puliti. Cuocere la pasta al dente. Amalgamare con le zucchine, aggiungere pecorino e menta fresca.",note_en:"Slice courgettes and sauté in oil with garlic. Add cleaned courgette flowers. Cook pasta al dente. Combine with courgettes, add pecorino and fresh mint.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Zucchine",qt:"400g"},{nome:"Fiori di zucca",qt:"8"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pecorino",qt:"50g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con zucchine e fiori (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:13,gs:2,g:9,z:4,ch:56,fi:3,ca:120,fe:2,mg:42,k2:380,na:240,zn:1.2,fo:50,se:8,col:10}},{id:"tpl_1047",nome:"Minestrone alla genovese",nome_en:"Genoese minestrone",categoria:"Primo piatto",porzioni:6,note:"Soffriggere le verdure a cubetti. Aggiungere fagioli, patate e brodo. Cuocere 30 minuti. Aggiungere pasta corta e cuocere al dente. Condire con un cucchiaio di pesto genovese. Servire tiepido.",note_en:"Sauté diced vegetables. Add beans, potatoes and stock. Cook 30 minutes. Add short pasta and cook al dente. Dress with a spoonful of Genoese pesto. Serve warm.",ingredienti:[{nome:"Verdure miste stagionali",qt:"600g"},{nome:"Fagioli borlotti cotti",qt:"250g"},{nome:"Patate",qt:"200g"},{nome:"Pasta corta",qt:"100g"},{nome:"Pesto genovese",qt:"80g"},{nome:"Brodo vegetale",qt:"1.5L"}],_dbEntry:{n:"Minestrone alla genovese (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:1,g:8,z:5,ch:42,fi:8,ca:80,fe:2.5,mg:50,k2:500,na:380,zn:1.2,fo:90,se:5,col:3}},{id:"tpl_1048",nome:"Pasta al forno siciliana",nome_en:"Sicilian baked pasta",categoria:"Primo piatto",porzioni:6,note:"Cuocere pasta al dente. Preparare sugo di carne con macinato e pomodoro. In teglia alternare pasta, sugo, piselli, uova sode affettate e caciocavallo. Chiudere con sugo e formaggio. Cuocere in forno a 180 C per 30 minuti.",note_en:"Cook pasta al dente. Prepare meat sauce with mince and tomato. In baking dish alternate pasta, sauce, peas, sliced hard-boiled eggs and caciocavallo. Top with sauce and cheese. Bake at 180 C for 30 minutes.",ingredienti:[{nome:"Rigatoni",qt:"400g"},{nome:"Macinato di manzo",qt:"300g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Piselli",qt:"100g"},{nome:"Uova sode",qt:"3"},{nome:"Caciocavallo",qt:"150g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Pasta al forno siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:22,gs:5,g:14,z:4,ch:52,fi:3,ca:180,fe:3,mg:38,k2:380,na:480,zn:3,fo:45,se:18,col:140}},{id:"tpl_1049",nome:"Spaghetti alle vongole in bianco",nome_en:"Spaghetti with clams in white sauce",categoria:"Primo piatto",porzioni:4,note:"Far aprire le vongole in padella coperta con aglio e vino bianco. Filtrare il liquido. Soffriggere aglio e prezzemolo. Aggiungere il liquido delle vongole. Cuocere gli spaghetti al dente. Saltare in padella con le vongole e il loro liquido.",note_en:"Open clams in covered pan with garlic and white wine. Filter liquid. Sauté garlic and parsley. Add clam liquid. Cook spaghetti al dente. Toss in pan with clams and their liquid.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Vongole",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Spaghetti alle vongole in bianco (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:18,gs:1.5,g:10,z:2,ch:52,fi:1,ca:80,fe:3.5,mg:45,k2:380,na:380,zn:2,fo:30,se:22,col:35}},{id:"tpl_1050",nome:"Risotto al nero di seppia",nome_en:"Black squid ink risotto",categoria:"Primo piatto",porzioni:4,note:"Pulire le seppie tenendo il sacchetto del nero. Rosolare cipolla e aglio in olio. Aggiungere le seppie a pezzi e sfumare con vino bianco. Tostare il riso nella base. Aggiungere brodo di pesce e il nero di seppia. Mantecare con olio crudo.",note_en:"Clean squid keeping ink sac. Brown onion and garlic in oil. Add squid pieces and deglaze with white wine. Toast rice in base. Add fish stock and squid ink. Stir in raw oil.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Seppie",qt:"400g"},{nome:"Nero di seppia",qt:"2 bustine"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"120ml"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo di pesce",qt:"1L"}],_dbEntry:{n:"Risotto al nero di seppia (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:20,gs:1.5,g:9,z:2,ch:52,fi:.5,ca:50,fe:2.5,mg:50,k2:420,na:380,zn:2,fo:25,se:30,col:80}},{id:"tpl_1051",nome:"Pasta al pistacchio di Bronte",nome_en:"Pasta with Bronte pistachio",categoria:"Primo piatto",porzioni:4,note:"Frullare pistacchi con aglio, olio e poca acqua per creare il pesto. Rosolare la salsiccia sbriciolata. Cuocere i rigatoni al dente. Mantecare con pesto di pistacchio, salsiccia e un mestolo di acqua di cottura.",note_en:"Blend pistachios with garlic, oil and a little water to make pesto. Brown crumbled sausage. Cook rigatoni al dente. Toss with pistachio pesto, sausage and a ladle of cooking water.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pistacchi di Bronte",qt:"100g"},{nome:"Salsiccia",qt:"200g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Pasta al pistacchio di Bronte (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:20,gs:4,g:22,z:3,ch:55,fi:3,ca:80,fe:2.5,mg:55,k2:520,na:480,zn:2,fo:35,se:10,col:40}},{id:"tpl_1052",nome:"Minestra di orzo e verdure",nome_en:"Barley and vegetable soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere le verdure a cubetti. Aggiungere orzo perlato, pomodori e brodo. Cuocere 40 minuti mescolando spesso. Condire con olio extravergine e prezzemolo. Servire caldo con parmigiano a parte.",note_en:"Sauté diced vegetables. Add pearled barley, tomatoes and stock. Cook 40 minutes stirring often. Season with extra virgin olive oil and parsley. Serve hot with parmesan on the side.",ingredienti:[{nome:"Orzo perlato",qt:"250g"},{nome:"Carote",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori",qt:"200g"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Minestra di orzo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:.5,g:5,z:4,ch:50,fi:7,ca:45,fe:2.5,mg:45,k2:420,na:310,zn:1.5,fo:35,se:8,col:0}},{id:"tpl_1053",nome:"Caserecce al pesto di rucola",nome_en:"Caserecce with rocket pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare rucola, pinoli, aglio, parmigiano e olio per il pesto. Cuocere le caserecce al dente. Scolare tenendo acqua di cottura. Mantecare con il pesto di rucola, aggiungendo acqua di cottura per ammorbidire. Guarnire con scaglie di parmigiano.",note_en:"Blend rocket, pine nuts, garlic, parmesan and oil for pesto. Cook caserecce al dente. Drain keeping cooking water. Toss with rocket pesto, adding cooking water to soften. Garnish with parmesan shavings.",ingredienti:[{nome:"Caserecce",qt:"320g"},{nome:"Rucola",qt:"80g"},{nome:"Pinoli",qt:"30g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Caserecce al pesto di rucola (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:3,g:17,z:2,ch:58,fi:2,ca:120,fe:2,mg:38,k2:250,na:200,zn:1.2,fo:50,se:8,col:8}},{id:"tpl_1054",nome:"Riso pilaf con verdure",nome_en:"Vegetable pilaf rice",categoria:"Primo piatto",porzioni:4,note:"Tostare il riso Basmati in burro con cipolla. Aggiungere brodo bollente in quantita doppia rispetto al riso. Chiudere il coperchio e cuocere a fuoco bassissimo 18 minuti senza mai aprire. Sgranare con una forchetta e aggiungere verdure saltate.",note_en:"Toast Basmati rice in butter with onion. Add boiling stock in double the amount of rice. Cover and cook on very low heat 18 minutes without opening. Fluff with fork and add sautéed vegetables.",ingredienti:[{nome:"Riso Basmati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Burro",qt:"30g"},{nome:"Verdure miste",qt:"250g"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Spezie aromatiche",qt:"q.b."}],_dbEntry:{n:"Riso pilaf con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:7,gs:2,g:6,z:4,ch:58,fi:3,ca:45,fe:1.5,mg:35,k2:280,na:280,zn:.8,fo:30,se:5,col:10}},{id:"tpl_1055",nome:"Pasta con peperoni arrostiti",nome_en:"Pasta with roasted peppers",categoria:"Primo piatto",porzioni:4,note:"Arrostire i peperoni in forno o sul gas, pelarli e tagliarli a listarelle. Soffriggere aglio in olio, aggiungere i peperoni, acciughe e capperi. Cuocere la pasta al dente. Saltare tutto insieme con prezzemolo.",note_en:"Roast peppers in oven or on gas, peel and slice. Sauté garlic in oil, add peppers, anchovies and capers. Cook pasta al dente. Toss everything together with parsley.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Peperoni rossi",qt:"4"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con peperoni arrostiti (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:1.5,g:9,z:6,ch:60,fi:3,ca:50,fe:2.5,mg:45,k2:420,na:420,zn:1,fo:55,se:10,col:8}},{id:"tpl_1056",nome:"Zuppa di pane toscana",nome_en:"Tuscan bread soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodori maturi spezzettati. Aggiungere pane toscano raffermo spezzettato e brodo vegetale. Cuocere mescolando finche il pane si ammorbidisce. Aggiustare di sale e pepe. Servire con olio crudo.",note_en:"Sauté garlic in oil, add roughly chopped ripe tomatoes. Add crumbled stale Tuscan bread and vegetable stock. Cook stirring until bread softens. Season with salt and pepper. Serve with raw oil.",ingredienti:[{nome:"Pane toscano raffermo",qt:"300g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Zuppa di pane toscana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:7,gs:1,g:10,z:5,ch:44,fi:4,ca:55,fe:2,mg:30,k2:350,na:440,zn:.8,fo:30,se:5,col:0}},{id:"tpl_1057",nome:"Pasta alla sorrentina",nome_en:"Pasta alla sorrentina",categoria:"Primo piatto",porzioni:4,note:"Preparare sugo di pomodoro fresco con basilico. Cuocere i rigatoni al dente. In teglia alternare pasta, sugo, mozzarella a cubetti e parmigiano. Cuocere in forno a 200 C per 15 minuti finche la mozzarella fila.",note_en:"Make fresh tomato sauce with basil. Cook rigatoni al dente. In baking dish alternate pasta, sauce, diced mozzarella and parmesan. Bake at 200 C for 15 minutes until mozzarella melts and stretches.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Mozzarella",qt:"200g"},{nome:"Parmigiano",qt:"50g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta alla sorrentina (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:5,g:14,z:5,ch:56,fi:2.5,ca:250,fe:1.5,mg:38,k2:350,na:380,zn:2,fo:35,se:12,col:40}},{id:"tpl_1058",nome:"Pasta con la mollica di pane",nome_en:"Pasta with toasted breadcrumbs",categoria:"Primo piatto",porzioni:4,note:"Tostare la mollica di pane in olio con aglio e acciughe fino a doratura. Condire con peperoncino. Cuocere la pasta al dente. Scolare e condire con la mollica tostata, aglio e prezzemolo.",note_en:"Toast breadcrumbs in oil with garlic and anchovies until golden. Season with chilli. Cook pasta al dente. Drain and dress with toasted crumbs, garlic and parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Mollica di pane",qt:"80g"},{nome:"Acciughe",qt:"4"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con la mollica di pane (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:12,gs:1.5,g:12,z:2,ch:60,fi:2,ca:45,fe:2.5,mg:35,k2:230,na:420,zn:.9,fo:25,se:8,col:5}},{id:"tpl_1059",nome:"Risotto zucca e amaretti",nome_en:"Pumpkin and amaretti risotto",categoria:"Primo piatto",porzioni:4,note:"Arrostire la zucca in forno. Soffriggere scalogno in burro, tostare il riso, sfumare con vino bianco. Aggiungere brodo e la polpa di zucca schiacciata. Mantecare con burro e parmigiano. Servire con amaretti sbriciolati.",note_en:"Roast pumpkin in oven. Sauté shallot in butter, toast rice, deglaze with white wine. Add stock and mashed pumpkin flesh. Stir in butter and parmesan. Serve with crumbled amaretti.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Zucca",qt:"400g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"50g"},{nome:"Amaretti",qt:"30g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto zucca e amaretti (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:11,gs:5,g:11,z:8,ch:62,fi:2,ca:100,fe:1.5,mg:30,k2:380,na:350,zn:1,fo:28,se:6,col:30}},{id:"tpl_1060",nome:"Pasta con ragù alla bolognese",nome_en:"Pasta with Bolognese ragu",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, carota, sedano. Aggiungere macinato misto e rosolare. Sfumare con vino rosso. Aggiungere pomodori e latte. Cuocere a fuoco lento almeno 2 ore. Servire con tagliatelle al uovo e parmigiano.",note_en:"Sauté onion, carrot, celery. Add mixed mince and brown. Deglaze with red wine. Add tomatoes and milk. Cook on low heat at least 2 hours. Serve with egg tagliatelle and parmesan.",ingredienti:[{nome:"Tagliatelle all uovo",qt:"320g"},{nome:"Macinato misto",qt:"400g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Vino rosso",qt:"100ml"},{nome:"Latte",qt:"50ml"},{nome:"Parmigiano",qt:"50g"}],_dbEntry:{n:"Pasta con ragu alla bolognese (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:25,gs:5,g:14,z:4,ch:52,fi:2.5,ca:120,fe:3,mg:40,k2:480,na:420,zn:3.5,fo:50,se:18,col:75}},{id:"tpl_1061",nome:"Minestrone di primavera",nome_en:"Spring minestrone",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla e aglio. Aggiungere carote, piselli, asparagi a pezzetti, spinaci e brodo. Cuocere 20 minuti. Aggiungere pasta corta o pastina. Servire con parmigiano e olio extravergine a crudo.",note_en:"Sauté onion and garlic. Add carrots, peas, chopped asparagus, spinach and stock. Cook 20 minutes. Add short pasta or pastina. Serve with parmesan and raw extra virgin olive oil.",ingredienti:[{nome:"Pastina",qt:"120g"},{nome:"Piselli",qt:"150g"},{nome:"Asparagi",qt:"200g"},{nome:"Carote",qt:"2"},{nome:"Spinaci freschi",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Minestrone di primavera (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:10,gs:.5,g:4,z:5,ch:46,fi:7,ca:80,fe:2.5,mg:48,k2:480,na:330,zn:1.2,fo:100,se:5,col:5}},{id:"tpl_1062",nome:"Pasta alla puttanesca",nome_en:"Pasta puttanesca",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere acciughe fino a scioglierle. Aggiungere olive nere, capperi e pomodori. Cuocere 20 minuti. Cuocere gli spaghetti al dente e saltarli nel sugo. Finire con prezzemolo.",note_en:"Sauté garlic in oil, add anchovies until dissolved. Add black olives, capers and tomatoes. Cook 20 minutes. Cook spaghetti al dente and toss in sauce. Finish with parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Acciughe",qt:"6"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta alla puttanesca (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:12,gs:1.5,g:10,z:4,ch:58,fi:3,ca:55,fe:2.5,mg:40,k2:420,na:850,zn:1,fo:30,se:10,col:8}},{id:"tpl_1063",nome:"Risotto ai gamberi e lime",nome_en:"Prawn and lime risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere gamberi sgusciati e rosolare brevemente, togliere. Tostare il riso, sfumare con vino bianco. Aggiungere brodo di pesce. Mantecare con olio, succo e scorza di lime. Aggiungere i gamberi.",note_en:"Sauté shallot in oil. Add peeled prawns and brown briefly, remove. Toast rice, deglaze with white wine. Add fish stock. Stir in oil, lime juice and zest. Add prawns.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Lime",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Risotto ai gamberi e lime (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:17,gs:1,g:7,z:2,ch:54,fi:.5,ca:70,fe:2,mg:45,k2:380,na:360,zn:1.8,fo:30,se:28,col:115}},{id:"tpl_1064",nome:"Pasta alla checca",nome_en:"Pasta alla checca",categoria:"Primo piatto",porzioni:4,note:"Tagliare pomodori a cubetti, condire con aglio, basilico, olio e sale. Marinare 30 minuti a temperatura ambiente. Cuocere la pasta al dente, scolare e condire immediatamente con il sugo freddo. Aggiungere mozzarella a cubetti.",note_en:"Dice tomatoes, season with garlic, basil, oil and salt. Marinate 30 minutes at room temperature. Cook pasta al dente, drain and immediately dress with cold sauce. Add diced mozzarella.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Mozzarella",qt:"150g"},{nome:"Basilico",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Pasta alla checca (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:3,g:14,z:4,ch:58,fi:2.5,ca:220,fe:1.5,mg:35,k2:380,na:280,zn:1.5,fo:40,se:10,col:25}},{id:"tpl_1065",nome:"Pasta con crema di melanzane",nome_en:"Pasta with aubergine cream",categoria:"Primo piatto",porzioni:4,note:"Grigliare le melanzane, frullarle con aglio, tahini, succo di limone e olio per una crema. Cuocere la pasta al dente. Mantecare con la crema di melanzane, aggiungendo acqua di cottura. Guarnire con pomodorini e menta.",note_en:"Grill aubergines, blend with garlic, tahini, lemon juice and oil for a cream. Cook pasta al dente. Toss with aubergine cream, adding cooking water. Garnish with cherry tomatoes and mint.",ingredienti:[{nome:"Pennette",qt:"320g"},{nome:"Melanzane",qt:"500g"},{nome:"Tahini",qt:"30g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pomodorini",qt:"100g"}],_dbEntry:{n:"Pasta con crema di melanzane (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:12,gs:1.5,g:11,z:5,ch:60,fi:5,ca:55,fe:2.5,mg:48,k2:420,na:220,zn:1.2,fo:50,se:6,col:0}},{id:"tpl_1066",nome:"Soup di pomodoro e basilico",nome_en:"Tomato and basil soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla e aglio in olio. Aggiungere pomodori pelati e brodo vegetale. Cuocere 20 minuti. Frullare fino a crema liscia. Condire con basilico fresco e olio extravergine. Servire con crostini di pane.",note_en:"Brown onion and garlic in oil. Add peeled tomatoes and vegetable stock. Cook 20 minutes. Blend to smooth cream. Season with fresh basil and extra virgin olive oil. Serve with bread croutons.",ingredienti:[{nome:"Pomodori pelati",qt:"800g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane per crostini",qt:"100g"}],_dbEntry:{n:"Soup di pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:1,g:8,z:8,ch:32,fi:3.5,ca:50,fe:2,mg:30,k2:480,na:340,zn:.5,fo:30,se:5,col:0}},{id:"tpl_1067",nome:"Pasta con il baccala",nome_en:"Pasta with salt cod",categoria:"Primo piatto",porzioni:4,note:"Dissalare il baccala 48 ore cambiando l acqua. Soffriggere aglio, cipolla e pomodorini. Aggiungere il baccala a pezzi e cuocere 15 minuti. Cuocere la pasta al dente. Saltare nel sugo con prezzemolo e olive.",note_en:"Desalt cod for 48 hours changing water. Sauté garlic, onion and cherry tomatoes. Add cod pieces and cook 15 minutes. Cook pasta al dente. Toss in sauce with parsley and olives.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Baccala dissalato",qt:"400g"},{nome:"Pomodorini",qt:"250g"},{nome:"Olive nere",qt:"50g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Pasta con il baccala (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:22,gs:1.5,g:9,z:3,ch:52,fi:2.5,ca:60,fe:2,mg:50,k2:520,na:680,zn:1.5,fo:30,se:28,col:45}},{id:"tpl_1068",nome:"Risotto alla crema di scampi",nome_en:"Scampi cream risotto",categoria:"Primo piatto",porzioni:4,note:"Sgusciare gli scampi. Preparare un fumetto con i carapaci. Soffriggere scalogno, tostare il riso, sfumare con brandy. Aggiungere il fumetto di scampi. Mantecare con burro e la polpa degli scampi saltata brevemente.",note_en:"Shell langoustines. Make a bisque with the shells. Sauté shallot, toast rice, flambé with brandy. Add langoustine bisque. Stir in butter and briefly sautéed langoustine flesh.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Scampi",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Brandy",qt:"50ml"},{nome:"Burro",qt:"40g"},{nome:"Pomodori",qt:"100g"},{nome:"Erbe aromatiche",qt:"q.b."}],_dbEntry:{n:"Risotto alla crema di scampi (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:3,g:9,z:2,ch:52,fi:.5,ca:80,fe:2,mg:50,k2:420,na:480,zn:2,fo:40,se:30,col:140}},{id:"tpl_1069",nome:"Pasta fredda al pesto e pomodorini",nome_en:"Cold pasta with pesto and cherry tomatoes",categoria:"Primo piatto",porzioni:4,note:"Cuocere la pasta al dente, sciacquare con acqua fredda. Condire con pesto genovese, pomodorini halved, olive e mozzarella. Lasciare riposare in frigorifero 30 minuti prima di servire.",note_en:"Cook pasta al dente, rinse with cold water. Dress with Genoese pesto, halved cherry tomatoes, olives and mozzarella. Rest in refrigerator 30 minutes before serving.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Pesto genovese",qt:"80g"},{nome:"Pomodorini",qt:"200g"},{nome:"Mozzarella",qt:"125g"},{nome:"Olive",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pasta fredda al pesto e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:4,g:16,z:4,ch:56,fi:3,ca:200,fe:2,mg:38,k2:300,na:420,zn:1.5,fo:40,se:8,col:20}},{id:"tpl_1070",nome:"Pasta con crema di piselli e menta",nome_en:"Pasta with pea and mint cream",categoria:"Primo piatto",porzioni:4,note:"Cuocere i piselli in acqua salata. Frullarli con menta, parmigiano e olio fino a crema. Cuocere la pasta al dente. Mantecare con la crema di piselli aggiungendo acqua di cottura. Guarnire con piselli interi e menta fresca.",note_en:"Cook peas in salted water. Blend with mint, parmesan and oil to a cream. Cook pasta al dente. Toss with pea cream adding cooking water. Garnish with whole peas and fresh mint.",ingredienti:[{nome:"Mezze penne",qt:"320g"},{nome:"Piselli freschi",qt:"500g"},{nome:"Menta fresca",qt:"15g"},{nome:"Parmigiano",qt:"50g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con crema di piselli e menta (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:16,gs:2,g:10,z:5,ch:58,fi:7,ca:80,fe:2.5,mg:45,k2:380,na:200,zn:1.2,fo:70,se:5,col:5}},{id:"tpl_1071",nome:"Fusilli con pomodorini e ricotta",nome_en:"Fusilli with cherry tomatoes and ricotta",categoria:"Primo piatto",porzioni:4,note:"Saltare i pomodorini in olio con aglio fino a far scoppiare. Cuocere i fusilli al dente. Scolare e mantecare con i pomodorini, ricotta fresca, basilico e olio. Aggiungere parmigiano se gradito.",note_en:"Sauté cherry tomatoes in oil with garlic until they burst. Cook fusilli al dente. Drain and toss with cherry tomatoes, fresh ricotta, basil and oil. Add parmesan if desired.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Pomodorini",qt:"300g"},{nome:"Ricotta fresca",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Fusilli con pomodorini e ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:15,gs:2.5,g:11,z:4,ch:58,fi:2.5,ca:150,fe:1.5,mg:35,k2:320,na:220,zn:1,fo:35,se:8,col:18}},{id:"tpl_1072",nome:"Pasta al pesto di pistacchi",nome_en:"Pasta with pistachio pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare pistacchi non salati tostati con aglio, basilico, parmigiano e olio per fare il pesto. Cuocere la pasta al dente. Mantecare con il pesto di pistacchi e acqua di cottura.",note_en:"Blend toasted unsalted pistachios with garlic, basil, parmesan and oil to make pesto. Cook pasta al dente. Toss with pistachio pesto and cooking water.",ingredienti:[{nome:"Linguine",qt:"320g"},{nome:"Pistacchi non salati",qt:"100g"},{nome:"Basilico",qt:"20g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Pasta al pesto di pistacchi (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:16,gs:3,g:22,z:3,ch:56,fi:3.5,ca:120,fe:2.5,mg:60,k2:500,na:180,zn:1.5,fo:35,se:5,col:5}},{id:"tpl_1073",nome:"Tagliatelle al tartufo nero",nome_en:"Tagliatelle with black truffle",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in burro e olio. Aggiungere tartufo nero grattugiato o a lamelle. Cuocere le tagliatelle fresche. Mantecare con burro, tartufo e parmigiano. Servire immediatamente.",note_en:"Sauté garlic in butter and oil. Add grated or sliced black truffle. Cook fresh tagliatelle. Toss with butter, truffle and parmesan. Serve immediately.",ingredienti:[{nome:"Tagliatelle fresche",qt:"400g"},{nome:"Tartufo nero",qt:"40g"},{nome:"Burro",qt:"60g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Parmigiano",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Tagliatelle al tartufo nero (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:15,gs:9,g:18,z:2,ch:56,fi:1.5,ca:130,fe:2,mg:25,k2:200,na:350,zn:1.5,fo:25,se:5,col:120}},{id:"tpl_1074",nome:"Zuppa di zucca e zenzero",nome_en:"Pumpkin and ginger soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla in olio. Aggiungere zucca a cubetti, zenzero fresco grattugiato e brodo vegetale. Cuocere 25 minuti. Frullare fino a crema vellutata. Aggiustare di sale. Servire con panna acida e semi di zucca tostati.",note_en:"Brown onion in oil. Add diced pumpkin, fresh grated ginger and vegetable stock. Cook 25 minutes. Blend to velvety cream. Season with salt. Serve with sour cream and toasted pumpkin seeds.",ingredienti:[{nome:"Zucca",qt:"600g"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Panna acida",qt:"50g"},{nome:"Semi di zucca",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zuppa di zucca e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:1.5,g:8,z:8,ch:28,fi:3,ca:55,fe:1.5,mg:30,k2:560,na:320,zn:.8,fo:35,se:5,col:8}},{id:"tpl_1075",nome:"Pasta con cozze e zafferano",nome_en:"Pasta with mussels and saffron",categoria:"Primo piatto",porzioni:4,note:"Far aprire le cozze in padella con aglio e vino bianco. Sgusciare la meta. Soffriggere scalogno, aggiungere zafferano sciolto in brodo. Cuocere gli spaghetti. Saltare con le cozze e il loro liquido filtrato.",note_en:"Open mussels in pan with garlic and white wine. Shell half. Sauté shallot, add saffron dissolved in stock. Cook spaghetti. Toss with mussels and their filtered liquid.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Cozze",qt:"800g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"150ml"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con cozze e zafferano (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:18,gs:1.5,g:9,z:2,ch:52,fi:2,ca:80,fe:4,mg:50,k2:380,na:480,zn:2.5,fo:35,se:30,col:38}},{id:"tpl_1076",nome:"Risotto al caprino e noci",nome_en:"Goat cheese and walnut risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Tostare il riso, sfumare con vino bianco. Aggiungere brodo vegetale. A cottura quasi ultimata aggiungere caprino a pezzi e noci tritate. Mantecare con burro. Servire con miele e noci intere.",note_en:"Sauté shallot in butter. Toast rice, deglaze with white wine. Add vegetable stock. Near end of cooking add crumbled goat cheese and chopped walnuts. Stir in butter. Serve with honey and whole walnuts.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Caprino fresco",qt:"150g"},{nome:"Noci",qt:"60g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Miele",qt:"20g"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto al caprino e noci (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:6,g:16,z:4,ch:56,fi:1.5,ca:120,fe:1.5,mg:40,k2:280,na:350,zn:1.5,fo:30,se:6,col:28}},{id:"tpl_1077",nome:"Pasta e lenticchie",nome_en:"Pasta and lentils",categoria:"Primo piatto",porzioni:4,note:"Soffriggere sedano, carota e cipolla. Aggiungere lenticchie rosse o verdi e brodo. Cuocere 20 minuti. Aggiungere pasta corta e cuocere. Il piatto deve rimanere semi-brodoso. Condire con olio crudo, aglio e peperoncino.",note_en:"Sauté celery, carrot and onion. Add red or green lentils and stock. Cook 20 minutes. Add short pasta and cook. Dish should remain semi-soupy. Season with raw oil, garlic and chilli.",ingredienti:[{nome:"Pasta corta",qt:"200g"},{nome:"Lenticchie",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta e lenticchie (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:15,gs:.8,g:6,z:3,ch:52,fi:9,ca:55,fe:4,mg:60,k2:580,na:300,zn:2,fo:145,se:6,col:0}},{id:"tpl_1078",nome:"Pasta con bottarga di muggine",nome_en:"Pasta with grey mullet bottarga",categoria:"Primo piatto",porzioni:4,note:"Cuocere gli spaghetti al dente. Soffriggere aglio in olio. Scolare la pasta e mantecare con olio, aglio e bottarga grattugiata abbondante. Aggiungere poco prezzemolo e scorza di limone. Servire con bottarga a lamelle.",note_en:"Cook spaghetti al dente. Sauté garlic in oil. Drain pasta and toss with oil, garlic and generous grated bottarga. Add a little parsley and lemon zest. Serve with bottarga in slices.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Bottarga di muggine",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Limone",qt:"1"},{nome:"Prezzemolo",qt:"10g"}],_dbEntry:{n:"Pasta con bottarga di muggine (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:2,g:14,z:1,ch:56,fi:1,ca:50,fe:2,mg:38,k2:280,na:680,zn:1.5,fo:20,se:30,col:110}},{id:"tpl_1079",nome:"Vellutata di asparagi",nome_en:"Asparagus velouté",categoria:"Primo piatto",porzioni:4,note:"Lessare gli asparagi in acqua salata, tenere le punte. Frullare i gambi con scalogno soffritto, panna e brodo. Portare a consistenza vellutata. Aggiustare di sale e pepe. Servire con le punte e crostini.",note_en:"Boil asparagus in salted water, keep tips. Blend stalks with sautéed shallot, cream and stock. Bring to velvety consistency. Season with salt and pepper. Serve with tips and croutons.",ingredienti:[{nome:"Asparagi",qt:"600g"},{nome:"Scalogno",qt:"2"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Burro",qt:"30g"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Vellutata di asparagi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:7,gs:4,g:11,z:5,ch:22,fi:3.5,ca:60,fe:2.5,mg:25,k2:380,na:350,zn:.8,fo:90,se:5,col:35}},{id:"tpl_1080",nome:"Pasta ai quattro formaggi",nome_en:"Pasta with four cheeses",categoria:"Primo piatto",porzioni:4,note:"Sciogliere in padella gorgonzola, taleggio, fontina e parmigiano con un pocod di panna. Mescolare fino a crema omogenea. Cuocere la pasta al dente. Mantecare con la crema di formaggi e acqua di cottura.",note_en:"Melt gorgonzola, taleggio, fontina and parmesan in a pan with a little cream. Stir to smooth cream. Cook pasta al dente. Toss with cheese cream and cooking water.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Gorgonzola",qt:"80g"},{nome:"Taleggio",qt:"80g"},{nome:"Fontina",qt:"80g"},{nome:"Parmigiano",qt:"40g"},{nome:"Panna da cucina",qt:"80ml"}],_dbEntry:{n:"Pasta ai quattro formaggi (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:22,gs:11,g:20,z:3,ch:55,fi:1,ca:420,fe:1.5,mg:30,k2:200,na:780,zn:3,fo:20,se:10,col:75}},{id:"tpl_1081",nome:"Pasta con noci e gorgonzola",nome_en:"Pasta with walnuts and gorgonzola",categoria:"Primo piatto",porzioni:4,note:"Sciogliere il gorgonzola in panna. Tostare le noci in padella. Cuocere la pasta al dente. Mantecare con la crema di gorgonzola e le noci. Guarnire con rucola e pepe.",note_en:"Melt gorgonzola in cream. Toast walnuts in pan. Cook pasta al dente. Toss with gorgonzola cream and walnuts. Garnish with rocket and pepper.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Gorgonzola",qt:"150g"},{nome:"Noci",qt:"80g"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Rucola",qt:"30g"}],_dbEntry:{n:"Pasta con noci e gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:18,gs:9,g:22,z:2.5,ch:54,fi:2.5,ca:220,fe:1.5,mg:48,k2:300,na:600,zn:2,fo:28,se:8,col:45}},{id:"tpl_1082",nome:"Zuppa di pesce alla livornese",nome_en:"Livornese fish soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio e peperoncino in olio. Aggiungere pomodori, cacciucco o misto di pesce e brodo. Cuocere 20 minuti. Servire su pane tostato strofinato con aglio.",note_en:"Sauté onion, garlic and chilli in oil. Add tomatoes, mixed fish and stock. Cook 20 minutes. Serve on toasted bread rubbed with garlic.",ingredienti:[{nome:"Pesce misto",qt:"600g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Brodo di pesce",qt:"500ml"},{nome:"Pane",qt:"150g"}],_dbEntry:{n:"Zuppa di pesce alla livornese (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:28,gs:2,g:10,z:4,ch:22,fi:2,ca:80,fe:2.5,mg:50,k2:550,na:480,zn:2,fo:35,se:35,col:90}},{id:"tpl_1083",nome:"Pasta con crema di sedano rapa",nome_en:"Pasta with celeriac cream",categoria:"Primo piatto",porzioni:4,note:"Cuocere sedano rapa a cubetti in brodo fino a morbido. Frullare con parmigiano e olio fino a crema. Cuocere la pasta al dente. Mantecare con la crema di sedano rapa. Guarnire con nocciole tostate e prezzemolo.",note_en:"Cook diced celeriac in stock until soft. Blend with parmesan and oil to a cream. Cook pasta al dente. Toss with celeriac cream. Garnish with toasted hazelnuts and parsley.",ingredienti:[{nome:"Penne",qt:"320g"},{nome:"Sedano rapa",qt:"400g"},{nome:"Parmigiano",qt:"50g"},{nome:"Nocciole tostate",qt:"40g"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con crema di sedano rapa (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:14,gs:2,g:13,z:3,ch:58,fi:3,ca:110,fe:2,mg:40,k2:380,na:280,zn:1.5,fo:35,se:6,col:5}},{id:"tpl_1084",nome:"Pasta e ceci speziata",nome_en:"Spiced pasta and chickpeas",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla, aglio, cumino, curcuma e peperoncino in olio. Aggiungere ceci e pomodori. Cuocere 15 minuti. Aggiungere pasta corta e brodo. Cuocere al dente. Servire con foglie di coriandolo fresco.",note_en:"Sauté onion, garlic, cumin, turmeric and chilli in oil. Add chickpeas and tomatoes. Cook 15 minutes. Add short pasta and stock. Cook al dente. Serve with fresh coriander leaves.",ingredienti:[{nome:"Pasta corta",qt:"200g"},{nome:"Ceci cotti",qt:"400g"},{nome:"Pomodori",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta e ceci speziata (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:.8,g:6,z:3,ch:54,fi:10,ca:65,fe:4,mg:68,k2:560,na:300,zn:2,fo:130,se:6,col:0}},{id:"tpl_1085",nome:"Spaghetti al cartoccio con frutti di mare",nome_en:"Spaghetti en papillote with seafood",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere misto di frutti di mare, vino bianco e pomodorini. Cuocere 5 minuti. Mescolare con spaghetti a meta cottura. Chiudere in carta forno e cuocere in forno a 200 C per 12 minuti.",note_en:"Sauté garlic in oil, add mixed seafood, white wine and cherry tomatoes. Cook 5 minutes. Mix with halfway-cooked spaghetti. Seal in baking paper and bake at 200 C for 12 minutes.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Frutti di mare misti",qt:"500g"},{nome:"Pomodorini",qt:"200g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Spaghetti al cartoccio con frutti di mare (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:1.5,g:9,z:3,ch:52,fi:2,ca:80,fe:3,mg:48,k2:420,na:480,zn:2,fo:30,se:30,col:80}},{id:"tpl_1086",nome:"Pasta con broccoletti e salsiccia",nome_en:"Pasta with turnip tops and sausage",categoria:"Primo piatto",porzioni:4,note:"Lessare i broccoletti in acqua salata. Soffriggere la salsiccia sbriciolata con aglio e peperoncino. Cuocere le orecchiette nell acqua dei broccoletti. Saltare tutto insieme con olio abbondante.",note_en:"Boil turnip tops in salted water. Brown crumbled sausage with garlic and chilli. Cook orecchiette in the turnip top water. Toss everything together with plenty of oil.",ingredienti:[{nome:"Orecchiette",qt:"320g"},{nome:"Cime di rapa",qt:"400g"},{nome:"Salsiccia",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con broccoletti e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:20,gs:5,g:16,z:3,ch:56,fi:5,ca:120,fe:3,mg:55,k2:500,na:480,zn:2.5,fo:80,se:15,col:45}},{id:"tpl_1087",nome:"Minestrone estivo con basilico",nome_en:"Summer minestrone with basil",categoria:"Primo piatto",porzioni:4,note:"Cuocere zucchine, pomodori, melanzane, fagiolini e cipolla in brodo vegetale. Aggiungere pasta corta. Cuocere al dente. Condire con pesto di basilico fresco. Servire tiepido o freddo.",note_en:"Cook courgettes, tomatoes, aubergines, green beans and onion in vegetable stock. Add short pasta. Cook al dente. Dress with fresh basil pesto. Serve warm or cold.",ingredienti:[{nome:"Ditalini",qt:"150g"},{nome:"Zucchine",qt:"200g"},{nome:"Pomodori",qt:"200g"},{nome:"Melanzane",qt:"150g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pesto fresco",qt:"60g"},{nome:"Brodo vegetale",qt:"1.2L"}],_dbEntry:{n:"Minestrone estivo con basilico (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:9,gs:.8,g:7,z:5,ch:43,fi:6,ca:60,fe:2,mg:42,k2:450,na:310,zn:1,fo:55,se:5,col:2}},{id:"tpl_1088",nome:"Risotto con spinaci e fontina",nome_en:"Risotto with spinach and fontina",categoria:"Primo piatto",porzioni:4,note:"Lessare gli spinaci, strizzarli e frullarne meta. Soffriggere scalogno in burro, tostare il riso, sfumare con vino. Aggiungere brodo e la crema di spinaci. Mantecare con burro e fontina. Aggiungere gli spinaci interi rimasti.",note_en:"Boil spinach, squeeze out water and blend half. Sauté shallot in butter, toast rice, deglaze with wine. Add stock and spinach cream. Stir in butter and fontina. Add remaining whole spinach.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Spinaci freschi",qt:"400g"},{nome:"Fontina",qt:"100g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto con spinaci e fontina (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:6,g:12,z:3,ch:55,fi:3,ca:220,fe:2.5,mg:45,k2:350,na:480,zn:1.8,fo:120,se:8,col:40}},{id:"tpl_1089",nome:"Pasta con l aglio e olio",nome_en:"Pasta with garlic and oil",categoria:"Primo piatto",porzioni:4,note:"Affettare aglio finissimo e dorarlo in abbondante olio a fuoco dolcissimo. Aggiungere peperoncino. Cuocere gli spaghetti al dente, tenere acqua di cottura. Mantecare aglio olio e peperoncino con la pasta aggiungendo acqua. Finire con prezzemolo abbondante.",note_en:"Slice garlic very thin and brown in plenty of oil on very low heat. Add chilli. Cook spaghetti al dente, keep cooking water. Toss garlic oil and chilli with pasta adding water. Finish with plenty of parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Peperoncino",qt:"2"},{nome:"Olio extravergine",qt:"80ml"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Pasta con l aglio e olio (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:11,gs:1.5,g:16,z:1,ch:60,fi:1.5,ca:30,fe:2,mg:35,k2:220,na:120,zn:.8,fo:20,se:6,col:0}},{id:"tpl_1090",nome:"Trofie al pesto con fagiolini e patate",nome_en:"Trofie pesto with green beans and potatoes",categoria:"Primo piatto",porzioni:4,note:"Lessare le patate a cubetti e i fagiolini nella stessa acqua salata. Cuocere le trofie con le patate. Scolare tutto. Condire con pesto genovese, parmigiano e pecorino. Amalgamare bene.",note_en:"Boil diced potatoes and green beans in the same salted water. Cook trofie with potatoes. Drain everything. Dress with Genoese pesto, parmesan and pecorino. Mix well.",ingredienti:[{nome:"Trofie",qt:"320g"},{nome:"Patate",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pesto genovese",qt:"100g"},{nome:"Parmigiano",qt:"30g"},{nome:"Pecorino",qt:"20g"}],_dbEntry:{n:"Trofie al pesto con fagiolini e patate (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:3,g:16,z:3,ch:62,fi:5,ca:130,fe:2,mg:48,k2:420,na:350,zn:1.2,fo:50,se:6,col:6}},{id:"tpl_1091",nome:"Pasta con sugo di pomodoro e basilico",nome_en:"Pasta with tomato and basil sauce",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodori pelati e schiacciare. Cuocere 20 minuti. Aggiungere basilico fresco. Cuocere i rigatoni al dente. Condire con il sugo e parmigiano.",note_en:"Sauté garlic in oil, add peeled tomatoes and crush. Cook 20 minutes. Add fresh basil. Cook rigatoni al dente. Dress with sauce and parmesan.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Pasta con sugo di pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:13,gs:1,g:8,z:5,ch:60,fi:2.5,ca:90,fe:2,mg:35,k2:380,na:250,zn:1,fo:30,se:7,col:5}},{id:"tpl_1092",nome:"Vellutata di carote e zenzero",nome_en:"Carrot and ginger velouté",categoria:"Primo piatto",porzioni:4,note:"Rosolare cipolla in olio. Aggiungere carote a pezzi e zenzero grattugiato. Versare brodo vegetale e cuocere 25 minuti. Frullare con latte di cocco. Aggiustare di sale e servire con semi di sesamo tostati.",note_en:"Brown onion in oil. Add carrot pieces and grated ginger. Pour in vegetable stock and cook 25 minutes. Blend with coconut milk. Season with salt and serve with toasted sesame seeds.",ingredienti:[{nome:"Carote",qt:"600g"},{nome:"Cipolla",qt:"1"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Latte di cocco",qt:"100ml"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Semi di sesamo",qt:"20g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Vellutata di carote e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:3,g:7,z:10,ch:26,fi:5,ca:55,fe:1.5,mg:30,k2:580,na:320,zn:.5,fo:30,se:4,col:0}},{id:"tpl_1093",nome:"Pasta con sugo di peperoni e pomodoro",nome_en:"Pasta with pepper and tomato sauce",categoria:"Primo piatto",porzioni:4,note:"Grigliare i peperoni e spellarli. Soffriggere cipolla, aggiungere peperoni e pomodori. Cuocere 20 minuti. Frullare meta del sugo per renderlo cremoso. Cuocere la pasta al dente e condire.",note_en:"Grill peppers and peel. Sauté onion, add peppers and tomatoes. Cook 20 minutes. Blend half the sauce to make it creamy. Cook pasta al dente and dress.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Peperoni rossi",qt:"3"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Pasta con sugo di peperoni e pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:11,gs:1,g:8,z:7,ch:60,fi:4,ca:45,fe:2,mg:42,k2:450,na:240,zn:.9,fo:50,se:6,col:0}},{id:"tpl_1094",nome:"Risotto con gamberetti e limone",nome_en:"Risotto with shrimps and lemon",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in olio. Aggiungere i gamberetti sgusciati, sfumare con vino bianco. Togliere i gamberetti. Tostare il riso nella base, aggiungere brodo di pesce. Mantecare con olio, succo di limone e scorza. Rimettere i gamberetti.",note_en:"Sauté shallot in oil. Add peeled shrimps, deglaze with white wine. Remove shrimps. Toast rice in base, add fish stock. Stir in oil, lemon juice and zest. Return shrimps.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Gamberetti",qt:"300g"},{nome:"Scalogno",qt:"2"},{nome:"Limone",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Brodo di pesce",qt:"1L"}],_dbEntry:{n:"Risotto con gamberetti e limone (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:16,gs:1,g:7,z:2,ch:54,fi:.5,ca:70,fe:1.8,mg:42,k2:360,na:360,zn:1.5,fo:28,se:25,col:105}},{id:"tpl_1095",nome:"Pasta con agnello e rosmarino",nome_en:"Pasta with lamb and rosemary",categoria:"Primo piatto",porzioni:4,note:"Rosolare pezzi di agnello con rosmarino, aglio e cipolla. Sfumare con vino rosso. Aggiungere pomodori e cuocere 45 minuti. Cuocere la pasta al dente. Condire con il sugo di agnello e pecorino.",note_en:"Brown lamb pieces with rosemary, garlic and onion. Deglaze with red wine. Add tomatoes and cook 45 minutes. Cook pasta al dente. Dress with lamb sauce and pecorino.",ingredienti:[{nome:"Mezze maniche",qt:"320g"},{nome:"Agnello",qt:"300g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"100ml"},{nome:"Pecorino",qt:"40g"}],_dbEntry:{n:"Pasta con agnello e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:24,gs:5,g:14,z:4,ch:54,fi:2.5,ca:100,fe:3,mg:42,k2:450,na:400,zn:4,fo:35,se:18,col:70}},{id:"tpl_1096",nome:"Zuppa di verza e patate",nome_en:"Savoy cabbage and potato soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere pancetta con cipolla. Aggiungere verza a strisce, patate a cubetti e brodo. Cuocere 30 minuti. Aggiungere pastina o orzo. Servire con parmigiano e olio crudo.",note_en:"Brown pancetta with onion. Add shredded savoy cabbage, diced potatoes and stock. Cook 30 minutes. Add pastina or barley. Serve with parmesan and raw oil.",ingredienti:[{nome:"Pastina",qt:"120g"},{nome:"Verza",qt:"400g"},{nome:"Patate",qt:"300g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Zuppa di verza e patate (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:12,gs:2,g:7,z:4,ch:44,fi:5,ca:100,fe:1.5,mg:38,k2:580,na:420,zn:1,fo:55,se:5,col:18}},{id:"tpl_1097",nome:"Pasta con sugo alla pescatora",nome_en:"Pasta with fisherman sauce",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodorini, vino bianco e misto di cozze, vongole, gamberi e calamari. Coprire e cuocere 10 minuti. Cuocere gli spaghetti al dente. Saltare nel sugo con prezzemolo abbondante.",note_en:"Sauté garlic in oil, add cherry tomatoes, white wine and mixed mussels, clams, prawns and squid. Cover and cook 10 minutes. Cook spaghetti al dente. Toss in sauce with plenty of parsley.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Cozze",qt:"300g"},{nome:"Vongole",qt:"300g"},{nome:"Gamberi",qt:"200g"},{nome:"Calamari",qt:"150g"},{nome:"Pomodorini",qt:"200g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con sugo alla pescatora (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:25,gs:1.5,g:9,z:3,ch:52,fi:2,ca:100,fe:4,mg:55,k2:480,na:500,zn:3,fo:40,se:35,col:95}},{id:"tpl_1098",nome:"Riso integrale con verdure e curcuma",nome_en:"Brown rice with vegetables and turmeric",categoria:"Primo piatto",porzioni:4,note:"Cuocere il riso integrale 35 minuti in acqua salata. Saltare le verdure con curcuma, zenzero e olio. Mescolare riso e verdure. Aggiustare di sale. Servire con salsa di yogurt e coriandolo.",note_en:"Cook brown rice 35 minutes in salted water. Sauté vegetables with turmeric, ginger and oil. Mix rice and vegetables. Season with salt. Serve with yoghurt sauce and coriander.",ingredienti:[{nome:"Riso integrale",qt:"300g"},{nome:"Verdure miste",qt:"350g"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Yogurt naturale",qt:"100g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Coriandolo fresco",qt:"10g"}],_dbEntry:{n:"Riso integrale con verdure e curcuma (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:.8,g:6,z:5,ch:56,fi:5,ca:55,fe:2,mg:55,k2:380,na:280,zn:1.2,fo:40,se:8,col:2}},{id:"tpl_1099",nome:"Pasta con sugo di carciofi e pancetta",nome_en:"Pasta with artichoke and pancetta sauce",categoria:"Primo piatto",porzioni:4,note:"Mondare i carciofi e tagliarli. Soffriggere pancetta, aglio e carciofi in olio. Sfumare con vino bianco. Cuocere 15 minuti. Cuocere la pasta al dente. Condire con il sugo, parmigiano e prezzemolo.",note_en:"Trim artichokes and slice. Sauté pancetta, garlic and artichokes in oil. Deglaze with white wine. Cook 15 minutes. Cook pasta al dente. Dress with sauce, parmesan and parsley.",ingredienti:[{nome:"Penne rigate",qt:"320g"},{nome:"Carciofi",qt:"4"},{nome:"Pancetta",qt:"80g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"80ml"},{nome:"Parmigiano",qt:"40g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con sugo di carciofi e pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:17,gs:3,g:11,z:3,ch:58,fi:5,ca:80,fe:2.5,mg:45,k2:380,na:480,zn:1.5,fo:65,se:8,col:20}},{id:"tpl_1100",nome:"Minestra di farro e fagioli",nome_en:"Farro and bean soup",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio, rosmarino e salvia. Aggiungere fagioli borlotti, farro perlato e brodo. Cuocere 40 minuti. Schiacciare una parte dei fagioli per addensare. Aggiustare di sale. Servire con olio extravergine e pane.",note_en:"Sauté garlic, rosemary and sage. Add borlotti beans, pearled farro and stock. Cook 40 minutes. Mash some beans to thicken. Season with salt. Serve with extra virgin oil and bread.",ingredienti:[{nome:"Farro perlato",qt:"200g"},{nome:"Fagioli borlotti cotti",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Salvia",qt:"4 foglie"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Minestra di farro e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:.5,g:5,z:3,ch:52,fi:10,ca:65,fe:3.5,mg:55,k2:550,na:310,zn:1.5,fo:115,se:6,col:0}},{id:"tpl_1101",nome:"Pasta con crema di ceci e rosmarino",nome_en:"Pasta with chickpea and rosemary cream",categoria:"Primo piatto",porzioni:4,note:"Frullare ceci cotti con brodo, rosmarino, aglio e olio fino a crema liscia. Cuocere la pasta al dente. Mantecare con la crema di ceci aggiungendo acqua di cottura. Guarnire con ceci interi soffritti e rosmarino croccante.",note_en:"Blend cooked chickpeas with stock, rosemary, garlic and oil to smooth cream. Cook pasta al dente. Toss with chickpea cream adding cooking water. Garnish with fried whole chickpeas and crispy rosemary.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Ceci cotti",qt:"400g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Brodo vegetale",qt:"300ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pasta con crema di ceci e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:15,gs:1,g:9,z:2,ch:60,fi:9,ca:70,fe:4,mg:60,k2:560,na:240,zn:2,fo:140,se:5,col:0}},{id:"tpl_1102",nome:"Pasta alla sorrentina veloce",nome_en:"Quick pasta alla sorrentina",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere pomodorini e cuocere 10 minuti. Cuocere la pasta al dente. Scolare e saltare con il sugo. Aggiungere mozzarella a cubetti e basilico. Il calore sciogliera la mozzarella.",note_en:"Sauté garlic in oil, add cherry tomatoes and cook 10 minutes. Cook pasta al dente. Drain and toss with sauce. Add diced mozzarella and basil. The heat will melt the mozzarella.",ingredienti:[{nome:"Paccheri",qt:"320g"},{nome:"Pomodorini",qt:"300g"},{nome:"Mozzarella",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Pasta alla sorrentina veloce (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:4,g:13,z:4,ch:58,fi:2.5,ca:240,fe:1.5,mg:38,k2:340,na:360,zn:2,fo:35,se:10,col:30}},{id:"tpl_1103",nome:"Pasta con le fave",nome_en:"Pasta with fava beans",categoria:"Primo piatto",porzioni:4,note:"Sgranare e spellare le fave. Soffriggere cipollotto, aglio e guanciale. Aggiungere le fave e un poco di brodo. Cuocere la pasta al dente. Condire con il sughetto di fave, pecorino e menta.",note_en:"Shell and skin fava beans. Sauté spring onion, garlic and guanciale. Add fava beans and a little stock. Cook pasta al dente. Dress with fava bean sauce, pecorino and mint.",ingredienti:[{nome:"Maccheroni",qt:"320g"},{nome:"Fave fresche sgranate",qt:"400g"},{nome:"Guanciale",qt:"80g"},{nome:"Cipollotto",qt:"2"},{nome:"Pecorino",qt:"50g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta con le fave (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:18,gs:3,g:10,z:3,ch:58,fi:8,ca:80,fe:3,mg:55,k2:560,na:420,zn:1.5,fo:160,se:8,col:22}},{id:"tpl_1104",nome:"Risotto con brie e noci",nome_en:"Risotto with brie and walnuts",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Tostare il riso, sfumare con vino bianco. Aggiungere brodo vegetale. A cottura quasi ultimata aggiungere brie a pezzi senza crosta. Mantecare con burro. Servire con gherigli di noce.",note_en:"Sauté shallot in butter. Toast rice, deglaze with white wine. Add vegetable stock. Near end of cooking add rindless brie pieces. Stir in butter. Serve with walnut halves.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Brie",qt:"150g"},{nome:"Noci",qt:"50g"},{nome:"Scalogno",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"1L"}],_dbEntry:{n:"Risotto con brie e noci (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:8,g:18,z:2,ch:54,fi:1.5,ca:160,fe:1.5,mg:30,k2:230,na:450,zn:1.5,fo:25,se:6,col:50}},{id:"tpl_1105",nome:"Pasta con gamberi e pomodorini",nome_en:"Pasta with prawns and cherry tomatoes",categoria:"Primo piatto",porzioni:4,note:"Soffriggere aglio in olio, aggiungere gamberi sgusciati. Sfumare con vino bianco. Aggiungere pomodorini tagliati a meta e cuocere 10 minuti. Cuocere la pasta al dente e saltare nel sugo. Aggiungere prezzemolo.",note_en:"Sauté garlic in oil, add peeled prawns. Deglaze with white wine. Add halved cherry tomatoes and cook 10 minutes. Cook pasta al dente and toss in sauce. Add parsley.",ingredienti:[{nome:"Linguine",qt:"320g"},{nome:"Gamberi",qt:"300g"},{nome:"Pomodorini",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"100ml"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con gamberi e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:1.5,g:8,z:3,ch:55,fi:2,ca:60,fe:2.5,mg:45,k2:420,na:340,zn:1.8,fo:35,se:25,col:110}},{id:"tpl_1106",nome:"Zuppa di fagioli e castagne",nome_en:"Bean and chestnut soup",categoria:"Primo piatto",porzioni:4,note:"Lessare le castagne. Cuocere i fagioli cannellini con rosmarino e aglio. Unire fagioli, castagne e brodo. Frullare meta. Cuocere 15 minuti. Servire con olio crudo e rametto di rosmarino.",note_en:"Boil chestnuts. Cook cannellini beans with rosemary and garlic. Combine beans, chestnuts and stock. Blend half. Cook 15 minutes. Serve with raw oil and rosemary sprig.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"350g"},{nome:"Castagne cotte",qt:"200g"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Zuppa di fagioli e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:10,gs:.5,g:5,z:4,ch:50,fi:9,ca:60,fe:3,mg:55,k2:580,na:280,zn:1.5,fo:85,se:4,col:0}},{id:"tpl_1107",nome:"Pasta con le polpette di carne",nome_en:"Pasta with meat meatballs",categoria:"Primo piatto",porzioni:4,note:"Preparare polpette di macinato misto con uova, parmigiano e prezzemolo. Rosolare le polpette in olio. Preparare sugo di pomodoro. Cuocere le polpette nel sugo 20 minuti. Cuocere gli spaghetti al dente. Servire con polpette e sugo.",note_en:"Prepare mixed mince meatballs with eggs, parmesan and parsley. Brown meatballs in oil. Make tomato sauce. Cook meatballs in sauce 20 minutes. Cook spaghetti al dente. Serve with meatballs and sauce.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Macinato misto",qt:"400g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"50g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta con le polpette di carne (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:26,gs:4,g:14,z:5,ch:55,fi:2.5,ca:110,fe:3,mg:42,k2:500,na:400,zn:4,fo:40,se:20,col:100}},{id:"tpl_1108",nome:"Pasta fredda con verdure grigliate",nome_en:"Cold pasta with grilled vegetables",categoria:"Primo piatto",porzioni:4,note:"Grigliare zucchine, melanzane e peperoni. Tagliare a pezzi e marinare con olio, aglio e basilico. Cuocere la pasta al dente, sciacquare in acqua fredda. Mescolare con le verdure grigliate e olive.",note_en:"Grill courgettes, aubergines and peppers. Cut into pieces and marinate with oil, garlic and basil. Cook pasta al dente, rinse in cold water. Mix with grilled vegetables and olives.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Zucchine",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Olive",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Pasta fredda con verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:11,gs:1.5,g:12,z:5,ch:60,fi:5,ca:55,fe:2,mg:45,k2:420,na:300,zn:1,fo:55,se:6,col:0}},{id:"tpl_1109",nome:"Risotto al pomodoro e basilico",nome_en:"Tomato and basil risotto",categoria:"Primo piatto",porzioni:4,note:"Soffriggere cipolla in olio. Tostare il riso, sfumare con vino bianco. Aggiungere brodo caldo e passata di pomodoro. Cuocere 18 minuti. Mantecare con burro, parmigiano e basilico fresco.",note_en:"Sauté onion in oil. Toast rice, deglaze with white wine. Add hot stock and tomato passata. Cook 18 minutes. Stir in butter, parmesan and fresh basil.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico",qt:"15g"},{nome:"Burro",qt:"40g"},{nome:"Parmigiano",qt:"50g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"700ml"}],_dbEntry:{n:"Risotto al pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:4,g:9,z:5,ch:62,fi:2.5,ca:90,fe:1.5,mg:30,k2:380,na:320,zn:1,fo:28,se:7,col:25}},{id:"tpl_1110",nome:"Pasta con sugo di cinghiale",nome_en:"Pasta with wild boar sauce",categoria:"Primo piatto",porzioni:4,note:"Marinare il cinghiale con vino rosso e aromi. Rosolare con soffritto. Sfumare con la marinatura filtrata. Aggiungere pomodoro e cuocere 2 ore. Cuocere i pici o le pappardelle. Condire con il ragu.",note_en:"Marinate wild boar with red wine and aromatics. Brown with soffritto. Deglaze with strained marinade. Add tomato and cook 2 hours. Cook pici or pappardelle. Dress with ragu.",ingredienti:[{nome:"Pappardelle",qt:"320g"},{nome:"Cinghiale",qt:"500g"},{nome:"Vino rosso",qt:"300ml"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Rosmarino",qt:"q.b."}],_dbEntry:{n:"Pasta con sugo di cinghiale (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:28,gs:4,g:12,z:4,ch:52,fi:2.5,ca:60,fe:3.5,mg:38,k2:500,na:380,zn:4.5,fo:40,se:18,col:75}},{id:"tpl_1111",nome:"Pasta con pesto di rucola e noci",nome_en:"Pasta with rocket and walnut pesto",categoria:"Primo piatto",porzioni:4,note:"Frullare rucola, noci, parmigiano, aglio e olio per creare il pesto. Cuocere le farfalle al dente. Mantecare con il pesto e acqua di cottura. Guarnire con pomodorini e scaglie di parmigiano.",note_en:"Blend rocket, walnuts, parmesan, garlic and oil to make pesto. Cook farfalle al dente. Toss with pesto and cooking water. Garnish with cherry tomatoes and parmesan shavings.",ingredienti:[{nome:"Farfalle",qt:"320g"},{nome:"Rucola",qt:"100g"},{nome:"Noci",qt:"50g"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"70ml"},{nome:"Pomodorini",qt:"100g"}],_dbEntry:{n:"Pasta con pesto di rucola e noci (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:15,gs:3,g:19,z:3,ch:57,fi:2.5,ca:120,fe:2.5,mg:50,k2:340,na:220,zn:1.5,fo:50,se:8,col:5}},{id:"tpl_1112",nome:"Vellutata di funghi e timo",nome_en:"Mushroom and thyme velouté",categoria:"Primo piatto",porzioni:4,note:"Soffriggere scalogno in burro. Aggiungere funghi misti tagliati e timo. Versare brodo e panna. Cuocere 20 minuti. Frullare fino a velluto. Aggiustare di sale. Servire con funghi trifolati e crostini.",note_en:"Sauté shallot in butter. Add sliced mixed mushrooms and thyme. Pour in stock and cream. Cook 20 minutes. Blend to velvet. Season with salt. Serve with trifolati mushrooms and croutons.",ingredienti:[{nome:"Funghi misti",qt:"500g"},{nome:"Scalogno",qt:"2"},{nome:"Timo",qt:"4 rametti"},{nome:"Panna da cucina",qt:"100ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Burro",qt:"30g"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Vellutata di funghi e timo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:5,g:12,z:3,ch:22,fi:3.5,ca:40,fe:2,mg:25,k2:450,na:350,zn:1,fo:30,se:8,col:40}},{id:"tpl_1113",nome:"Pasta con ricotta e limone",nome_en:"Pasta with ricotta and lemon",categoria:"Primo piatto",porzioni:4,note:"Amalgamare ricotta con scorza e succo di limone, parmigiano, sale e pepe. Cuocere i fusilli al dente. Scolare tenendo acqua di cottura. Mantecare con la crema di ricotta aggiungendo acqua per ammorbidire. Guarnire con foglie di basilico.",note_en:"Mix ricotta with lemon zest and juice, parmesan, salt and pepper. Cook fusilli al dente. Drain keeping cooking water. Toss with ricotta cream adding water to soften. Garnish with basil leaves.",ingredienti:[{nome:"Fusilli",qt:"320g"},{nome:"Ricotta",qt:"200g"},{nome:"Limone",qt:"2"},{nome:"Parmigiano",qt:"40g"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Pasta con ricotta e limone (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:3,g:9,z:4,ch:60,fi:2,ca:160,fe:1.5,mg:30,k2:250,na:180,zn:1.2,fo:35,se:8,col:25}},{id:"tpl_1114",nome:"Zuppa di coda di bue",nome_en:"Oxtail soup",categoria:"Primo piatto",porzioni:4,note:"Rosolare la coda a pezzi con verdure. Sfumare con vino rosso. Aggiungere brodo e cuocere 3 ore a fuoco lento. Disossare la coda e rimettere la carne nel brodo. Aggiustare di sale e servire con pasta corta.",note_en:"Brown oxtail pieces with vegetables. Deglaze with red wine. Add stock and cook 3 hours on low heat. Debone oxtail and return meat to broth. Season with salt and serve with short pasta.",ingredienti:[{nome:"Coda di bue",qt:"800g"},{nome:"Pasta corta",qt:"120g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Vino rosso",qt:"200ml"},{nome:"Brodo di carne",qt:"1L"}],_dbEntry:{n:"Zuppa di coda di bue (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:24,gs:4,g:11,z:3,ch:28,fi:2,ca:55,fe:3,mg:30,k2:420,na:420,zn:5,fo:20,se:15,col:90}},{id:"tpl_1115",nome:"Pasta e fagioli con le cotiche",nome_en:"Pasta and beans with pork rind",categoria:"Primo piatto",porzioni:4,note:"Sbollentare le cotiche e tagliarle a listarelle. Soffriggere cipolla, aglio e lardo. Aggiungere cotiche, fagioli borlotti e pomodori. Versare brodo e cuocere 1 ora. Aggiungere pasta mista e finire.",note_en:"Blanch pork rind and cut into strips. Sauté onion, garlic and lard. Add pork rind, borlotti beans and tomatoes. Pour in stock and cook 1 hour. Add mixed pasta and finish.",ingredienti:[{nome:"Pasta mista",qt:"200g"},{nome:"Fagioli borlotti",qt:"300g"},{nome:"Cotiche di maiale",qt:"150g"},{nome:"Lardo",qt:"50g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo",qt:"800ml"}],_dbEntry:{n:"Pasta e fagioli con le cotiche (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:4,g:12,z:3,ch:50,fi:8,ca:70,fe:3.5,mg:55,k2:580,na:500,zn:2.5,fo:105,se:8,col:35}},{id:"tpl_1116",nome:"Pasta al forno con carne e bechamel",nome_en:"Baked pasta with meat and bechamel",categoria:"Primo piatto",porzioni:6,note:"Preparare ragu di carne. Preparare besciamella. Cuocere la pasta al dente. In una teglia alternare strati di pasta, ragu e besciamella. Aggiungere parmigiano. Cuocere in forno a 180 C per 35 minuti.",note_en:"Make meat ragu. Make bechamel. Cook pasta al dente. In a baking dish alternate layers of pasta, ragu and bechamel. Add parmesan. Bake at 180 C for 35 minutes.",ingredienti:[{nome:"Maccheroni",qt:"400g"},{nome:"Macinato di manzo",qt:"400g"},{nome:"Latte",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"50g"},{nome:"Parmigiano",qt:"80g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Pasta al forno con carne e bechamel (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:22,gs:5,g:14,z:4,ch:50,fi:2.5,ca:200,fe:2.5,mg:35,k2:450,na:480,zn:3,fo:35,se:18,col:80}},{id:"tpl_1117",nome:"Pasta con sugo di verdure arrostite",nome_en:"Pasta with roasted vegetable sauce",categoria:"Primo piatto",porzioni:4,note:"Arrostire melanzane, zucchine e peperoni in forno con olio. Frullare meta per fare la base del sugo. Soffriggere aglio, aggiungere il sugo e le verdure a pezzi. Cuocere la pasta e saltare nel sugo.",note_en:"Roast aubergines, courgettes and peppers in oven with oil. Blend half for sauce base. Sauté garlic, add sauce and vegetable pieces. Cook pasta and toss in sauce.",ingredienti:[{nome:"Pasta corta",qt:"320g"},{nome:"Melanzane",qt:"200g"},{nome:"Zucchine",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Basilico",qt:"15g"}],_dbEntry:{n:"Pasta con sugo di verdure arrostite (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:1.5,g:10,z:6,ch:60,fi:5.5,ca:50,fe:2,mg:45,k2:480,na:200,zn:1,fo:55,se:7,col:0}},{id:"tpl_1118",nome:"Pasta alla crema di parmigiano",nome_en:"Pasta with parmesan cream",categoria:"Primo piatto",porzioni:4,note:"Sciogliere parmigiano grattugiato con acqua calda di cottura della pasta e olio extravergine fino a crema. Cuocere la pasta al dente. Mantecare con la crema di parmigiano fuori dal fuoco. Aggiungere pepe nero abbondante.",note_en:"Dissolve grated parmesan with hot pasta cooking water and extra virgin oil until creamy. Cook pasta al dente. Toss off heat with parmesan cream. Add plenty of black pepper.",ingredienti:[{nome:"Spaghetti",qt:"320g"},{nome:"Parmigiano grattugiato",qt:"120g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla crema di parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:5,g:13,z:2,ch:58,fi:1,ca:350,fe:1.5,mg:30,k2:180,na:420,zn:2.5,fo:15,se:8,col:28}},{id:"tpl_1119",nome:"Minestrone invernale con legumi",nome_en:"Winter minestrone with legumes",categoria:"Primo piatto",porzioni:6,note:"Soffriggere sedano, cipolla e carota. Aggiungere cavolo, broccoli, fagioli, lenticchie e brodo. Cuocere 35 minuti. Aggiungere pasta corta. Servire con parmigiano e olio crudo.",note_en:"Sauté celery, onion and carrot. Add cabbage, broccoli, beans, lentils and stock. Cook 35 minutes. Add short pasta. Serve with parmesan and raw oil.",ingredienti:[{nome:"Pasta corta",qt:"160g"},{nome:"Fagioli misti cotti",qt:"300g"},{nome:"Lenticchie cotte",qt:"150g"},{nome:"Cavolo",qt:"200g"},{nome:"Broccoli",qt:"200g"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.5L"}],_dbEntry:{n:"Minestrone invernale con legumi (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:13,gs:.5,g:5,z:4,ch:46,fi:11,ca:80,fe:3.5,mg:60,k2:600,na:340,zn:1.8,fo:130,se:5,col:0}},{id:"tpl_1120",nome:"Pasta con sugo alle noci e panna",nome_en:"Pasta with walnut and cream sauce",categoria:"Primo piatto",porzioni:4,note:"Tostare le noci in padella. Frullarle con aglio, parmigiano e panna per fare la salsa. Cuocere i rigatoni al dente. Mantecare con la salsa di noci aggiungendo acqua di cottura. Guarnire con noci intere.",note_en:"Toast walnuts in pan. Blend with garlic, parmesan and cream to make sauce. Cook rigatoni al dente. Toss with walnut sauce adding cooking water. Garnish with whole walnuts.",ingredienti:[{nome:"Rigatoni",qt:"320g"},{nome:"Noci",qt:"100g"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Parmigiano",qt:"50g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pasta con sugo alle noci e panna (ricetta)",c:"Ricette",src:"RICETTE",k:470,p:16,gs:5,g:21,z:3,ch:55,fi:2.5,ca:130,fe:1.5,mg:45,k2:280,na:250,zn:1.5,fo:25,se:7,col:28}},{id:"tpl_1121",nome:"Pollo alla cacciatora",nome_en:"Hunter-style chicken",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di pollo in olio. Aggiungere cipolla, aglio, pomodori pelati, olive, capperi e vino rosso. Cuocere coperto a fuoco medio 45 minuti. Aggiustare di sale e guarnire con prezzemolo.",note_en:"Brown chicken pieces in oil. Add onion, garlic, peeled tomatoes, olives, capers and red wine. Cover and cook over medium heat 45 minutes. Season with salt and garnish with parsley.",ingredienti:[{nome:"Pollo a pezzi",qt:"1.2kg"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"120ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pollo alla cacciatora (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:32,gs:3,g:14,z:4,ch:6,fi:2,ca:40,fe:1.8,mg:38,k2:520,na:420,zn:2.5,fo:22,se:24,col:110}},{id:"tpl_1122",nome:"Ossobuco alla milanese",nome_en:"Milanese ossobuco",categoria:"Secondo piatto",porzioni:4,note:"Infarinare gli ossibuchi. Rosolare in burro e olio. Sfumare con vino bianco. Aggiungere brodo e cuocere 1.5 ore. Preparare gremolada con prezzemolo, aglio e scorza di limone. Servire con risotto alla milanese.",note_en:"Flour the ossobuco. Brown in butter and oil. Deglaze with white wine. Add stock and cook 1.5 hours. Prepare gremolata with parsley, garlic and lemon zest. Serve with Milanese risotto.",ingredienti:[{nome:"Ossobuco di vitello",qt:"4 pezzi"},{nome:"Farina",qt:"40g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Burro",qt:"40g"},{nome:"Brodo di carne",qt:"400ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Ossobuco alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:38,gs:6,g:16,z:2,ch:10,fi:.5,ca:55,fe:2.5,mg:40,k2:580,na:380,zn:5,fo:18,se:28,col:140}},{id:"tpl_1123",nome:"Scaloppine al limone",nome_en:"Lemon veal escalopes",categoria:"Secondo piatto",porzioni:4,note:"Battere e infarinare le scaloppine. Rosolare in burro e olio fino a doratura. Sfumare con succo di limone e poco brodo. Cuocere 2 minuti. Guarnire con fette di limone e prezzemolo.",note_en:"Flatten and flour the escalopes. Brown in butter and oil until golden. Deglaze with lemon juice and a little stock. Cook 2 minutes. Garnish with lemon slices and parsley.",ingredienti:[{nome:"Fesa di vitello",qt:"600g"},{nome:"Farina",qt:"40g"},{nome:"Limone",qt:"2"},{nome:"Burro",qt:"40g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Prezzemolo",qt:"15g"},{nome:"Brodo",qt:"80ml"}],_dbEntry:{n:"Scaloppine al limone (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:5,g:13,z:1,ch:8,fi:.2,ca:30,fe:1.5,mg:30,k2:420,na:280,zn:3.5,fo:15,se:22,col:120}},{id:"tpl_1124",nome:"Bistecca alla fiorentina",nome_en:"Florentine T-bone steak",categoria:"Secondo piatto",porzioni:2,note:"Portare la bistecca a temperatura ambiente. Grigliare su brace ardente 3-4 minuti per lato. Salare solo a fine cottura. Servire con olio extravergine, rosmarino e limone. La carne deve restare rosa al centro.",note_en:"Bring steak to room temperature. Grill on hot coals 3-4 minutes per side. Salt only at end of cooking. Serve with extra virgin oil, rosemary and lemon. Meat should remain pink in centre.",ingredienti:[{nome:"Bistecca Fiorentina",qt:"1kg"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sale grosso",qt:"q.b."},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Bistecca alla fiorentina (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:52,gs:8,g:24,z:0,ch:0,fi:0,ca:20,fe:3.5,mg:45,k2:700,na:200,zn:8,fo:12,se:38,col:145}},{id:"tpl_1125",nome:"Polpette di carne al sugo",nome_en:"Meatballs in tomato sauce",categoria:"Secondo piatto",porzioni:4,note:"Mescolare carne macinata, pane bagnato, uova, parmigiano, aglio e prezzemolo. Formare le polpette. Rosolare in olio. Cuocere nel sugo di pomodoro 30 minuti a fuoco lento.",note_en:"Mix minced meat, soaked bread, eggs, parmesan, garlic and parsley. Shape into meatballs. Brown in oil. Cook in tomato sauce 30 minutes on low heat.",ingredienti:[{nome:"Macinato misto",qt:"500g"},{nome:"Pane raffermo",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"50g"},{nome:"Passata di pomodoro",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Polpette di carne al sugo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:28,gs:5,g:18,z:5,ch:22,fi:2,ca:120,fe:3,mg:40,k2:580,na:520,zn:4,fo:35,se:20,col:130}},{id:"tpl_1126",nome:"Involtini di manzo con prosciutto e salvia",nome_en:"Beef rolls with ham and sage",categoria:"Secondo piatto",porzioni:4,note:"Battere le fettine di manzo. Disporre su ciascuna una fetta di prosciutto crudo e foglie di salvia. Arrotolare e fissare con stecchini. Rosolare in burro e olio. Sfumare con vino bianco. Cuocere 15 minuti.",note_en:"Flatten beef slices. Place on each a slice of raw ham and sage leaves. Roll up and secure with toothpicks. Brown in butter and oil. Deglaze with white wine. Cook 15 minutes.",ingredienti:[{nome:"Fettine di manzo",qt:"600g"},{nome:"Prosciutto crudo",qt:"120g"},{nome:"Salvia",qt:"16 foglie"},{nome:"Burro",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Involtini di manzo con prosciutto e salvia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:36,gs:5,g:16,z:1,ch:2,fi:0,ca:25,fe:2.5,mg:30,k2:480,na:650,zn:5,fo:10,se:25,col:110}},{id:"tpl_1127",nome:"Vitello tonnato",nome_en:"Veal with tuna sauce",categoria:"Secondo piatto",porzioni:6,note:"Cuocere il girello di vitello in brodo con verdure aromatiche 1.5 ore. Lasciare raffreddare nel brodo. Frullare tonno sott olio, capperi, acciughe, succo di limone e maionese. Affettare la carne sottilmente e nappare con la salsa tonnata.",note_en:"Cook veal topside in stock with aromatic vegetables 1.5 hours. Let cool in stock. Blend canned tuna, capers, anchovies, lemon juice and mayonnaise. Slice meat thinly and coat with tuna sauce.",ingredienti:[{nome:"Girello di vitello",qt:"800g"},{nome:"Tonno sott olio",qt:"160g"},{nome:"Capperi",qt:"40g"},{nome:"Acciughe",qt:"4"},{nome:"Maionese",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"}],_dbEntry:{n:"Vitello tonnato (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:34,gs:4,g:16,z:1,ch:3,fi:.3,ca:35,fe:2,mg:35,k2:450,na:580,zn:3.5,fo:15,se:32,col:120}},{id:"tpl_1128",nome:"Arrosto di maiale alle erbe",nome_en:"Herb-roasted pork loin",categoria:"Secondo piatto",porzioni:6,note:"Massaggiare la lonza con aglio tritato, rosmarino, salvia, sale e pepe. Legare e lasciare marinare 2 ore. Rosolare in olio da tutti i lati. Cuocere in forno a 180 C per 60 minuti. Lasciare riposare 10 minuti prima di affettare.",note_en:"Rub pork loin with minced garlic, rosemary, sage, salt and pepper. Tie and marinate 2 hours. Brown in oil on all sides. Bake at 180 C for 60 minutes. Rest 10 minutes before slicing.",ingredienti:[{nome:"Lonza di maiale",qt:"1kg"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Salvia",qt:"10 foglie"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Arrosto di maiale alle erbe (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:34,gs:4,g:14,z:0,ch:1,fi:.2,ca:20,fe:1.2,mg:32,k2:520,na:320,zn:3,fo:8,se:30,col:95}},{id:"tpl_1129",nome:"Agnello al forno con patate",nome_en:"Oven-roasted lamb with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Marinare i pezzi di agnello con aglio, rosmarino, olio e vino bianco per 2 ore. Disporre in teglia con patate a spicchi. Cuocere in forno a 190 C per 60-70 minuti rigirando a meta cottura.",note_en:"Marinate lamb pieces with garlic, rosemary, oil and white wine for 2 hours. Arrange in baking dish with wedge-cut potatoes. Bake at 190 C for 60-70 minutes turning halfway through.",ingredienti:[{nome:"Coscio di agnello a pezzi",qt:"1kg"},{nome:"Patate",qt:"600g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Vino bianco",qt:"150ml"}],_dbEntry:{n:"Agnello al forno con patate (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:35,gs:5,g:18,z:2,ch:28,fi:2.5,ca:35,fe:2.5,mg:45,k2:680,na:280,zn:5,fo:20,se:18,col:100}},{id:"tpl_1130",nome:"Spezzatino di manzo con piselli",nome_en:"Beef stew with peas",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il manzo a bocconcini e infarinare. Rosolare in olio con cipolla. Sfumare con vino rosso. Aggiungere pomodori e brodo. Cuocere 1.5 ore. Aggiungere i piselli negli ultimi 15 minuti.",note_en:"Cut beef into pieces and flour. Brown in oil with onion. Deglaze with red wine. Add tomatoes and stock. Cook 1.5 hours. Add peas in last 15 minutes.",ingredienti:[{nome:"Manzo per spezzatino",qt:"700g"},{nome:"Piselli",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino rosso",qt:"150ml"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Farina",qt:"30g"},{nome:"Brodo",qt:"300ml"}],_dbEntry:{n:"Spezzatino di manzo con piselli (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:35,gs:3,g:12,z:4,ch:18,fi:4,ca:45,fe:4,mg:50,k2:700,na:380,zn:5,fo:55,se:22,col:95}},{id:"tpl_1131",nome:"Coniglio alla ligure",nome_en:"Ligurian-style rabbit",categoria:"Secondo piatto",porzioni:4,note:"Rosolare il coniglio a pezzi in olio. Aggiungere aglio, olive taggiasche, pinoli, capperi e timo. Sfumare con vino bianco. Aggiungere poco brodo e cuocere coperto 50 minuti.",note_en:"Brown rabbit pieces in oil. Add garlic, Taggiasca olives, pine nuts, capers and thyme. Deglaze with white wine. Add a little stock and cook covered 50 minutes.",ingredienti:[{nome:"Coniglio",qt:"1.2kg"},{nome:"Olive taggiasche",qt:"100g"},{nome:"Pinoli",qt:"30g"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Timo",qt:"4 rametti"}],_dbEntry:{n:"Coniglio alla ligure (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:34,gs:3,g:15,z:1,ch:3,fi:1.5,ca:35,fe:2.2,mg:38,k2:550,na:480,zn:3.5,fo:18,se:20,col:95}},{id:"tpl_1132",nome:"Petto di pollo con limone e capperi",nome_en:"Chicken breast with lemon and capers",categoria:"Secondo piatto",porzioni:4,note:"Battere i petti di pollo. Infarinare leggermente. Cuocere in padella con olio 4 minuti per lato. Aggiungere capperi, succo di limone e prezzemolo. Cuocere 3 minuti ancora e servire.",note_en:"Flatten chicken breasts. Flour lightly. Cook in pan with oil 4 minutes per side. Add capers, lemon juice and parsley. Cook 3 more minutes and serve.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Limone",qt:"2"},{nome:"Capperi",qt:"40g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Farina",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Petto di pollo con limone e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:34,gs:1.5,g:7,z:1,ch:6,fi:.5,ca:25,fe:1.5,mg:35,k2:480,na:350,zn:2,fo:18,se:26,col:85}},{id:"tpl_1133",nome:"Saltimbocca alla romana",nome_en:"Saltimbocca alla romana",categoria:"Secondo piatto",porzioni:4,note:"Sovrapporre una fetta di prosciutto e una foglia di salvia su ogni fettina di vitello. Fissare con uno stecchino. Cuocere in burro dalla parte del prosciutto prima, poi girare. Sfumare con vino bianco e servire con il fondo di cottura.",note_en:"Place a slice of ham and a sage leaf on each veal fillet. Secure with a toothpick. Cook in butter ham-side first, then turn. Deglaze with white wine and serve with cooking juices.",ingredienti:[{nome:"Fesa di vitello",qt:"500g"},{nome:"Prosciutto crudo",qt:"100g"},{nome:"Salvia",qt:"12 foglie"},{nome:"Burro",qt:"50g"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Saltimbocca alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:32,gs:7,g:16,z:0,ch:1,fi:0,ca:20,fe:1.5,mg:28,k2:420,na:680,zn:3,fo:8,se:22,col:125}},{id:"tpl_1134",nome:"Braciole di maiale in umido",nome_en:"Braised pork chops",categoria:"Secondo piatto",porzioni:4,note:"Rosolare le braciole in olio con aglio. Aggiungere pomodori, vino bianco e rosmarino. Cuocere coperto a fuoco lento 40 minuti. Le braciole devono risultare tenere e il sugo ridotto.",note_en:"Brown pork chops in oil with garlic. Add tomatoes, white wine and rosemary. Cook covered on low heat 40 minutes. Chops should be tender and sauce reduced.",ingredienti:[{nome:"Braciole di maiale",qt:"4"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Vino bianco",qt:"120ml"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Braciole di maiale in umido (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:30,gs:4,g:16,z:4,ch:8,fi:1.5,ca:30,fe:1.8,mg:35,k2:580,na:320,zn:3.5,fo:15,se:25,col:95}},{id:"tpl_1135",nome:"Pollo al forno con verdure mediterranee",nome_en:"Oven chicken with Mediterranean vegetables",categoria:"Secondo piatto",porzioni:4,note:"Disporre i pezzi di pollo in teglia con zucchine, peperoni, pomodori, olive e aglio. Condire con olio, origano e vino bianco. Cuocere in forno a 200 C per 50-60 minuti.",note_en:"Arrange chicken pieces in baking dish with courgettes, peppers, tomatoes, olives and garlic. Season with oil, oregano and white wine. Bake at 200 C for 50-60 minutes.",ingredienti:[{nome:"Pollo a pezzi",qt:"1.2kg"},{nome:"Zucchine",qt:"200g"},{nome:"Peperoni",qt:"2"},{nome:"Pomodori",qt:"300g"},{nome:"Olive nere",qt:"60g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Pollo al forno con verdure mediterranee (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:32,gs:3,g:14,z:5,ch:10,fi:3,ca:45,fe:2,mg:45,k2:620,na:320,zn:2.5,fo:28,se:22,col:100}},{id:"tpl_1136",nome:"Polpettone al forno",nome_en:"Baked meatloaf",categoria:"Secondo piatto",porzioni:6,note:"Mescolare macinato, uova, parmigiano, pane ammollato, aglio e prezzemolo. Formare un polpettone. Avvolgere con pancetta a fette. Cuocere in forno a 180 C per 50 minuti. Affettare e servire con sugo di cottura.",note_en:"Mix mince, eggs, parmesan, soaked bread, garlic and parsley. Shape into a loaf. Wrap with bacon slices. Bake at 180 C for 50 minutes. Slice and serve with cooking juices.",ingredienti:[{nome:"Macinato di manzo",qt:"600g"},{nome:"Pancetta a fette",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"60g"},{nome:"Pane raffermo",qt:"80g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"}],_dbEntry:{n:"Polpettone al forno (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:30,gs:6,g:20,z:2,ch:12,fi:.5,ca:100,fe:3,mg:35,k2:480,na:580,zn:4.5,fo:20,se:25,col:140}},{id:"tpl_1137",nome:"Fegato alla veneziana",nome_en:"Venetian liver with onions",categoria:"Secondo piatto",porzioni:4,note:"Affettare finemente le cipolle e stufarle in burro e olio a fuoco lento 20 minuti fino a caramellare. Aggiungere il fegato a fettine sottili. Cuocere a fuoco vivo 3 minuti per lato. Sfumare con poco aceto. Salare e guarnire con prezzemolo.",note_en:"Slice onions finely and stew in butter and oil on low heat 20 minutes until caramelised. Add thinly sliced liver. Cook on high heat 3 minutes per side. Deglaze with a little vinegar. Season and garnish with parsley.",ingredienti:[{nome:"Fegato di vitello",qt:"500g"},{nome:"Cipolle",qt:"500g"},{nome:"Burro",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto di vino bianco",qt:"20ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Fegato alla veneziana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:28,gs:5,g:12,z:6,ch:8,fi:1,ca:15,fe:12,mg:22,k2:450,na:280,zn:5,fo:320,se:40,col:380}},{id:"tpl_1138",nome:"Cotoletta alla milanese",nome_en:"Milanese breaded veal cutlet",categoria:"Secondo piatto",porzioni:4,note:"Battere le costolette di vitello. Passarle in uovo sbattuto e poi in pangrattato premendo bene. Friggere in abbondante burro chiarificato a 160 C fino a doratura da entrambi i lati. Scolare e salare. Servire con spicchi di limone.",note_en:"Flatten veal cutlets. Dip in beaten egg then press into breadcrumbs. Fry in plenty of clarified butter at 160 C until golden on both sides. Drain and salt. Serve with lemon wedges.",ingredienti:[{nome:"Costolette di vitello con osso",qt:"4"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Burro chiarificato",qt:"150g"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Cotoletta alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:35,gs:18,g:34,z:1,ch:18,fi:.5,ca:50,fe:2,mg:30,k2:380,na:380,zn:4,fo:12,se:22,col:220}},{id:"tpl_1139",nome:"Salsicce e fagioli all'uccelletto",nome_en:"Sausages with cannellini beans",categoria:"Secondo piatto",porzioni:4,note:"Bucherellare le salsicce e cuocerle in padella senza olio 10 minuti. Aggiungere aglio e salvia. Unire i fagioli cannellini con poco sugo di pomodoro. Cuocere insieme 15 minuti a fuoco lento.",note_en:"Pierce sausages and cook in pan without oil 10 minutes. Add garlic and sage. Add cannellini beans with a little tomato sauce. Cook together 15 minutes on low heat.",ingredienti:[{nome:"Salsicce di maiale",qt:"500g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Passata di pomodoro",qt:"150g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Salvia",qt:"6 foglie"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Salsicce e fagioli all uccelletto (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:26,gs:8,g:22,z:3,ch:22,fi:7,ca:70,fe:3.5,mg:60,k2:700,na:780,zn:3.5,fo:90,se:18,col:70}},{id:"tpl_1140",nome:"Petto di pollo al gorgonzola",nome_en:"Chicken breast with gorgonzola",categoria:"Secondo piatto",porzioni:4,note:"Cuocere i petti di pollo in padella con olio 5 minuti per lato. Togliere la carne e nella stessa padella sciogliere il gorgonzola con la panna. Rimettere il pollo nella salsa e cuocere 3 minuti. Guarnire con noci e erba cipollina.",note_en:"Cook chicken breasts in pan with oil 5 minutes per side. Remove meat and melt gorgonzola with cream in same pan. Return chicken to sauce and cook 3 minutes. Garnish with walnuts and chives.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Gorgonzola dolce",qt:"120g"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Noci",qt:"40g"},{nome:"Erba cipollina",qt:"15g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Petto di pollo al gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:38,gs:9,g:20,z:1,ch:2,fi:.5,ca:130,fe:1.5,mg:42,k2:520,na:480,zn:2.5,fo:15,se:28,col:120}},{id:"tpl_1141",nome:"Stracotto di manzo",nome_en:"Slow-braised beef",categoria:"Secondo piatto",porzioni:6,note:"Rosolare il pezzo di manzo intero con cipolla, carota e sedano. Sfumare con vino rosso. Aggiungere brodo e pomodori. Cuocere 3 ore a fuoco bassissimo coperto. La carne deve sfaldarsi. Servire con il fondo ristretto.",note_en:"Brown whole beef piece with onion, carrot and celery. Deglaze with red wine. Add stock and tomatoes. Cook 3 hours on very low heat covered. Meat should fall apart. Serve with reduced cooking juices.",ingredienti:[{nome:"Cappello del prete",qt:"1kg"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Vino rosso",qt:"300ml"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Brodo di carne",qt:"400ml"}],_dbEntry:{n:"Stracotto di manzo (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:38,gs:4,g:13,z:4,ch:8,fi:2,ca:30,fe:3.5,mg:42,k2:620,na:350,zn:6,fo:18,se:28,col:100}},{id:"tpl_1142",nome:"Tacchino in umido alle olive",nome_en:"Turkey stew with olives",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di tacchino in olio. Aggiungere cipolla, aglio, olive verdi, capperi, pomodori e vino bianco. Cuocere coperto 45 minuti. Aggiustare di sale e servire con polenta o patate lesse.",note_en:"Brown turkey pieces in oil. Add onion, garlic, green olives, capers, tomatoes and white wine. Cook covered 45 minutes. Season with salt and serve with polenta or boiled potatoes.",ingredienti:[{nome:"Petto di tacchino a pezzi",qt:"800g"},{nome:"Olive verdi",qt:"100g"},{nome:"Capperi",qt:"30g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Tacchino in umido alle olive (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:36,gs:2,g:10,z:4,ch:6,fi:2,ca:40,fe:2,mg:42,k2:580,na:520,zn:2.5,fo:20,se:30,col:85}},{id:"tpl_1143",nome:"Anatra all'arancia",nome_en:"Duck with orange",categoria:"Secondo piatto",porzioni:4,note:"Rosolare l'anatra a pezzi in padella. Trasferire in forno a 180 C per 40 minuti. Preparare salsa con succo e scorza di arancia, brodo e miele. Versare sulla carne e cuocere altri 20 minuti glassando.",note_en:"Brown duck pieces in pan. Transfer to oven at 180 C for 40 minutes. Make sauce with orange juice and zest, stock and honey. Pour over meat and cook 20 more minutes glazing.",ingredienti:[{nome:"Anatra a pezzi",qt:"1.2kg"},{nome:"Arance",qt:"3"},{nome:"Miele",qt:"30ml"},{nome:"Brodo di pollo",qt:"200ml"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Anatra all arancia (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:35,gs:7,g:22,z:8,ch:10,fi:.5,ca:30,fe:3,mg:35,k2:520,na:280,zn:4,fo:12,se:22,col:135}},{id:"tpl_1144",nome:"Pollo al marsala",nome_en:"Chicken with Marsala wine",categoria:"Secondo piatto",porzioni:4,note:"Infarinare i petti di pollo. Rosolare in burro e olio fino a doratura. Sfumare con vino Marsala e cuocere a fuoco vivace 5 minuti. Aggiungere funghi champignon a fette. Cuocere altri 10 minuti. Regolare di sale.",note_en:"Flour chicken breasts. Brown in butter and oil until golden. Deglaze with Marsala wine and cook on high heat 5 minutes. Add sliced champignon mushrooms. Cook another 10 minutes. Season with salt.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Funghi champignon",qt:"300g"},{nome:"Marsala",qt:"150ml"},{nome:"Burro",qt:"30g"},{nome:"Farina",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pollo al marsala (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:35,gs:4,g:12,z:3,ch:12,fi:1,ca:20,fe:2,mg:35,k2:520,na:280,zn:2.5,fo:18,se:28,col:95}},{id:"tpl_1145",nome:"Brasato al Barolo",nome_en:"Beef braised in Barolo wine",categoria:"Secondo piatto",porzioni:6,note:"Marinare il manzo nel Barolo con verdure aromatiche per 12 ore. Rosolare bene in olio. Aggiungere la marinatura filtrata. Cuocere a fuoco lentissimo 3 ore. Ristringere il fondo e servire con polenta.",note_en:"Marinate beef in Barolo with aromatic vegetables for 12 hours. Brown well in oil. Add strained marinade. Cook on very low heat 3 hours. Reduce cooking liquid and serve with polenta.",ingredienti:[{nome:"Cappello del prete",qt:"1kg"},{nome:"Vino Barolo",qt:"750ml"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Alloro",qt:"2 foglie"},{nome:"Chiodi di garofano",qt:"3"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Brasato al Barolo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:40,gs:4,g:14,z:5,ch:8,fi:2,ca:35,fe:4,mg:45,k2:680,na:320,zn:6.5,fo:20,se:30,col:110}},{id:"tpl_1146",nome:"Maialino al forno con patate e rosmarino",nome_en:"Roast suckling pig with potatoes and rosemary",categoria:"Secondo piatto",porzioni:6,note:"Massaggiare il maialino con aglio, rosmarino, sale, pepe e olio. Disporre con patate in teglia. Cuocere in forno a 200 C per 90 minuti. La cotenna deve risultare croccante. Bagnare con vino bianco a meta cottura.",note_en:"Rub suckling pig with garlic, rosemary, salt, pepper and oil. Arrange with potatoes in baking dish. Bake at 200 C for 90 minutes. Skin should be crispy. Baste with white wine halfway through.",ingredienti:[{nome:"Maialino da latte a pezzi",qt:"1.5kg"},{nome:"Patate",qt:"800g"},{nome:"Rosmarino",qt:"4 rametti"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Vino bianco",qt:"200ml"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Maialino al forno con patate e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:38,gs:8,g:24,z:2,ch:22,fi:2,ca:30,fe:2,mg:40,k2:720,na:380,zn:4.5,fo:12,se:28,col:120}},{id:"tpl_1147",nome:"Costine di maiale al forno con miele e soia",nome_en:"Pork ribs glazed with honey and soy",categoria:"Secondo piatto",porzioni:4,note:"Marinare le costine con soia, miele, aglio, zenzero e olio per 4 ore. Cuocere in forno a 180 C per 60 minuti coperte con carta stagnola. Scoprire e cuocere altri 20 minuti per glassare.",note_en:"Marinate ribs with soy, honey, garlic, ginger and oil for 4 hours. Bake at 180 C for 60 minutes covered with foil. Uncover and cook 20 more minutes to glaze.",ingredienti:[{nome:"Costine di maiale",qt:"1.2kg"},{nome:"Salsa di soia",qt:"60ml"},{nome:"Miele",qt:"50ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Olio di sesamo",qt:"20ml"}],_dbEntry:{n:"Costine di maiale al forno con miele e soia (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:32,gs:7,g:22,z:12,ch:14,fi:.2,ca:35,fe:1.8,mg:30,k2:480,na:820,zn:4,fo:8,se:22,col:95}},{id:"tpl_1148",nome:"Straccetti di manzo con rucola",nome_en:"Beef strips with rocket",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il manzo a straccetti sottili. Cuocere in padella caldissima con olio 2 minuti. Sfumare con limone. Disporre su letto di rucola fresca. Condire con parmigiano a scaglie, olio crudo e pepe.",note_en:"Cut beef into thin strips. Cook in very hot pan with oil 2 minutes. Deglaze with lemon. Arrange on fresh rocket. Dress with parmesan shavings, raw oil and pepper.",ingredienti:[{nome:"Manzo taglio magro",qt:"500g"},{nome:"Rucola",qt:"120g"},{nome:"Parmigiano a scaglie",qt:"50g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Straccetti di manzo con rucola (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:4,g:14,z:1,ch:2,fi:.5,ca:100,fe:3,mg:30,k2:480,na:260,zn:5,fo:35,se:22,col:85}},{id:"tpl_1149",nome:"Bocconcini di pollo al sesamo e miele",nome_en:"Chicken bites with sesame and honey",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il pollo a bocconcini. Marinare con soia, miele, aglio e zenzero 30 minuti. Passare nei semi di sesamo. Cuocere in padella con olio di sesamo 8-10 minuti. Servire con insalata di cetrioli.",note_en:"Cut chicken into bite-sized pieces. Marinate with soy, honey, garlic and ginger 30 minutes. Coat in sesame seeds. Cook in sesame oil pan 8-10 minutes. Serve with cucumber salad.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Semi di sesamo",qt:"60g"},{nome:"Salsa di soia",qt:"40ml"},{nome:"Miele",qt:"30ml"},{nome:"Zenzero",qt:"15g"},{nome:"Olio di sesamo",qt:"20ml"}],_dbEntry:{n:"Bocconcini di pollo al sesamo e miele (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:36,gs:2.5,g:12,z:8,ch:10,fi:1,ca:70,fe:2.5,mg:50,k2:500,na:620,zn:2.5,fo:20,se:30,col:85}},{id:"tpl_1150",nome:"Petto di tacchino panato al forno",nome_en:"Breaded turkey breast baked",categoria:"Secondo piatto",porzioni:4,note:"Battere le fettine di tacchino. Passare in uovo sbattuto con aglio e prezzemolo, poi in pangrattato. Disporre in teglia con olio e cuocere in forno a 200 C per 20 minuti rigirando a meta. Risulta croccante e leggero.",note_en:"Flatten turkey slices. Dip in beaten egg with garlic and parsley, then breadcrumbs. Place in oiled baking dish and bake at 200 C for 20 minutes turning halfway. Light and crispy result.",ingredienti:[{nome:"Petto di tacchino",qt:"600g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"80g"},{nome:"Parmigiano",qt:"40g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Petto di tacchino panato al forno (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:36,gs:2.5,g:9,z:1,ch:14,fi:.5,ca:80,fe:2,mg:35,k2:480,na:360,zn:2.5,fo:15,se:28,col:110}},{id:"tpl_1151",nome:"Branzino al forno alle erbe aromatiche",nome_en:"Herb-baked sea bass",categoria:"Secondo piatto",porzioni:4,note:"Incidere il branzino sui fianchi. Farcire la pancia con aglio, prezzemolo, limone e timo. Condire esternamente con olio, sale e pepe. Cuocere in forno a 200 C per 25-30 minuti. Servire con spicchi di limone.",note_en:"Score sea bass on sides. Fill belly with garlic, parsley, lemon and thyme. Season outside with oil, salt and pepper. Bake at 200 C for 25-30 minutes. Serve with lemon wedges.",ingredienti:[{nome:"Branzino intero",qt:"1kg"},{nome:"Limone",qt:"2"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Timo",qt:"4 rametti"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Branzino al forno alle erbe aromatiche (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:32,gs:1.5,g:10,z:1,ch:2,fi:.3,ca:45,fe:1.5,mg:40,k2:580,na:280,zn:1.5,fo:20,se:35,col:85}},{id:"tpl_1152",nome:"Baccalà alla livornese",nome_en:"Livorno-style salt cod",categoria:"Secondo piatto",porzioni:4,note:"Dissalare il baccalà 48 ore cambiando l'acqua. Infarinare e friggere in olio. Preparare sugo di pomodoro con aglio, olive nere e capperi. Cuocere il baccalà nel sugo 15 minuti a fuoco lento.",note_en:"Desalt cod 48 hours changing water. Flour and fry in oil. Make tomato sauce with garlic, black olives and capers. Cook cod in sauce 15 minutes on low heat.",ingredienti:[{nome:"Baccalà ammollato",qt:"700g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Farina",qt:"50g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Baccalà alla livornese (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:30,gs:2,g:12,z:4,ch:10,fi:2,ca:50,fe:1.5,mg:45,k2:620,na:620,zn:1.5,fo:18,se:42,col:75}},{id:"tpl_1153",nome:"Salmone in crosta di erbe",nome_en:"Herb-crusted salmon",categoria:"Secondo piatto",porzioni:4,note:"Mescolare pangrattato, prezzemolo, aneto, scorza di limone, aglio e olio. Pressare il composto sul filetto di salmone. Cuocere in forno a 200 C per 15-18 minuti. La crosta deve risultare dorata e croccante.",note_en:"Mix breadcrumbs, parsley, dill, lemon zest, garlic and oil. Press mixture onto salmon fillet. Bake at 200 C for 15-18 minutes. Crust should be golden and crispy.",ingredienti:[{nome:"Filetto di salmone",qt:"700g"},{nome:"Pangrattato",qt:"60g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aneto",qt:"15g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Salmone in crosta di erbe (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:34,gs:4,g:17,z:1,ch:6,fi:.5,ca:30,fe:1.2,mg:42,k2:620,na:220,zn:1,fo:25,se:48,col:95}},{id:"tpl_1154",nome:"Merluzzo al pomodoro e olive",nome_en:"Cod with tomato and olives",categoria:"Secondo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in olio. Aggiungere pomodori pelati e olive. Cuocere 10 minuti. Adagiare i filetti di merluzzo nel sugo. Cuocere coperto 12 minuti. Guarnire con prezzemolo e capperi.",note_en:"Sauté garlic and chilli in oil. Add peeled tomatoes and olives. Cook 10 minutes. Place cod fillets in sauce. Cook covered 12 minutes. Garnish with parsley and capers.",ingredienti:[{nome:"Filetti di merluzzo",qt:"700g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Olive nere",qt:"80g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Merluzzo al pomodoro e olive (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:28,gs:1.5,g:9,z:4,ch:8,fi:2,ca:55,fe:1.5,mg:45,k2:680,na:480,zn:1.5,fo:22,se:38,col:65}},{id:"tpl_1155",nome:"Orata alla siciliana",nome_en:"Sicilian-style sea bream",categoria:"Secondo piatto",porzioni:4,note:"Farcire l'orata con aglio, limone e origano. Coprire con pomodorini, olive, capperi e patate. Condire con olio e vino bianco. Cuocere in forno a 200 C per 35 minuti.",note_en:"Fill sea bream with garlic, lemon and oregano. Cover with cherry tomatoes, olives, capers and potatoes. Dress with oil and white wine. Bake at 200 C for 35 minutes.",ingredienti:[{nome:"Orata intera",qt:"1kg"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Patate",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Orata alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:30,gs:2,g:10,z:4,ch:18,fi:2.5,ca:50,fe:2,mg:45,k2:720,na:380,zn:1.5,fo:28,se:32,col:80}},{id:"tpl_1156",nome:"Calamari ripieni al forno",nome_en:"Stuffed baked squid",categoria:"Secondo piatto",porzioni:4,note:"Pulire i calamari tenendo i mantelli interi. Preparare il ripieno con tentacoli tritati, pangrattato, prezzemolo, aglio, pinoli e uvetta. Farcire i mantelli e chiudere con stecchino. Cuocere in forno con pomodori e olio a 180 C per 25 minuti.",note_en:"Clean squid keeping mantles whole. Prepare stuffing with minced tentacles, breadcrumbs, parsley, garlic, pine nuts and raisins. Fill mantles and close with toothpick. Bake with tomatoes and oil at 180 C for 25 minutes.",ingredienti:[{nome:"Calamari medi",qt:"800g"},{nome:"Pangrattato",qt:"60g"},{nome:"Pinoli",qt:"25g"},{nome:"Uvetta",qt:"25g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pomodorini",qt:"200g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Calamari ripieni al forno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:26,gs:1.5,g:9,z:5,ch:16,fi:1.5,ca:50,fe:2.5,mg:50,k2:550,na:320,zn:2,fo:22,se:38,col:240}},{id:"tpl_1157",nome:"Gamberoni all'aglio e prezzemolo",nome_en:"King prawns with garlic and parsley",categoria:"Secondo piatto",porzioni:4,note:"Pulire i gamberoni lasciando la testa. Rosolare aglio in olio. Aggiungere i gamberoni e cuocere 3 minuti per lato. Sfumare con vino bianco. Aggiungere prezzemolo e peperoncino. Servire subito con pane tostato.",note_en:"Clean king prawns leaving heads on. Sauté garlic in oil. Add prawns and cook 3 minutes per side. Deglaze with white wine. Add parsley and chilli. Serve immediately with toasted bread.",ingredienti:[{nome:"Gamberoni",qt:"800g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"30g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Gamberoni all aglio e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:28,gs:1.5,g:10,z:1,ch:3,fi:.3,ca:80,fe:2,mg:45,k2:500,na:380,zn:2.5,fo:18,se:42,col:170}},{id:"tpl_1158",nome:"Polpo alla luciana",nome_en:"Neapolitan stewed octopus",categoria:"Secondo piatto",porzioni:4,note:"Mettere il polpo in casseruola con pomodorini, aglio, prezzemolo, olive, capperi e olio senza aggiungere acqua. Cuocere coperto a fuoco lentissimo 50 minuti nel suo liquido. Il polpo deve risultare tenerissimo.",note_en:"Place octopus in pan with cherry tomatoes, garlic, parsley, olives, capers and oil without adding water. Cook covered on very low heat 50 minutes in its own juices. Octopus should be very tender.",ingredienti:[{nome:"Polpo",qt:"1kg"},{nome:"Pomodorini",qt:"300g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Polpo alla luciana (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:28,gs:1.5,g:8,z:3,ch:5,fi:2,ca:60,fe:3.5,mg:55,k2:620,na:520,zn:2.5,fo:18,se:48,col:90}},{id:"tpl_1159",nome:"Sgombro al forno con erbe",nome_en:"Herb-baked mackerel",categoria:"Secondo piatto",porzioni:4,note:"Incidere gli sgombri puliti. Farcire con fettine di limone, aglio, prezzemolo e origano. Condire con olio e sale. Cuocere in forno a 200 C per 20 minuti. Ricco di Omega-3 e veloce da preparare.",note_en:"Score cleaned mackerel. Fill with lemon slices, garlic, parsley and oregano. Season with oil and salt. Bake at 200 C for 20 minutes. Rich in Omega-3 and quick to prepare.",ingredienti:[{nome:"Sgombri interi",qt:"4"},{nome:"Limone",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Sgombro al forno con erbe (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:26,gs:4,g:18,z:1,ch:2,fi:.3,ca:30,fe:1.5,mg:38,k2:480,na:220,zn:1.5,fo:12,se:45,col:80}},{id:"tpl_1160",nome:"Pesce spada alla siciliana",nome_en:"Sicilian-style swordfish",categoria:"Secondo piatto",porzioni:4,note:"Marinare le fette di pesce spada con olio, limone, aglio e origano 30 minuti. Cuocere in padella caldissima 3 minuti per lato. Condire con salmoriglio (olio, limone, aglio, origano) e servire con capperi.",note_en:"Marinate swordfish steaks with oil, lemon, garlic and oregano 30 minutes. Cook in very hot pan 3 minutes per side. Dress with salmoriglio (oil, lemon, garlic, oregano) and serve with capers.",ingredienti:[{nome:"Pesce spada",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Origano",qt:"2 cucchiaini"},{nome:"Capperi",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pesce spada alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:32,gs:2,g:13,z:1,ch:3,fi:.5,ca:30,fe:1.5,mg:42,k2:580,na:320,zn:1.5,fo:12,se:55,col:80}},{id:"tpl_1161",nome:"Branzino in crosta di sale",nome_en:"Sea bass in salt crust",categoria:"Secondo piatto",porzioni:4,note:"Coprire completamente il branzino con sale grosso misto ad albumi montati a neve. Cuocere in forno a 220 C per 30 minuti. Rompere la crosta al tavolo. La carne risulta succosa e saporita senza essere salata.",note_en:"Completely cover sea bass with coarse salt mixed with whisked egg whites. Bake at 220 C for 30 minutes. Break crust at the table. Meat is juicy and flavourful without being salty.",ingredienti:[{nome:"Branzino intero",qt:"1kg"},{nome:"Sale grosso",qt:"1.5kg"},{nome:"Albumi",qt:"3"},{nome:"Limone",qt:"1"},{nome:"Timo",qt:"3 rametti"},{nome:"Alloro",qt:"2 foglie"}],_dbEntry:{n:"Branzino in crosta di sale (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:32,gs:1,g:8,z:0,ch:1,fi:.2,ca:40,fe:1.2,mg:38,k2:560,na:280,zn:1.2,fo:18,se:35,col:80}},{id:"tpl_1162",nome:"Sogliola al burro e capperi",nome_en:"Sole with butter and capers",categoria:"Secondo piatto",porzioni:4,note:"Infarinare i filetti di sogliola. Cuocere in burro e olio 3 minuti per lato. Togliere il pesce e nella stessa padella aggiungere capperi, succo di limone e prezzemolo. Versare il burro ai capperi sulla sogliola.",note_en:"Flour sole fillets. Cook in butter and oil 3 minutes per side. Remove fish and in same pan add capers, lemon juice and parsley. Pour caper butter over sole.",ingredienti:[{nome:"Filetti di sogliola",qt:"700g"},{nome:"Capperi",qt:"40g"},{nome:"Burro",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Limone",qt:"1"},{nome:"Prezzemolo",qt:"15g"},{nome:"Farina",qt:"40g"}],_dbEntry:{n:"Sogliola al burro e capperi (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:28,gs:8,g:14,z:1,ch:8,fi:.3,ca:40,fe:1,mg:35,k2:450,na:420,zn:1,fo:15,se:30,col:115}},{id:"tpl_1163",nome:"Cozze al vino bianco e prezzemolo",nome_en:"Mussels with white wine and parsley",categoria:"Secondo piatto",porzioni:4,note:"Pulire e spazzolare le cozze. Soffriggere aglio e peperoncino in olio. Aggiungere le cozze e il vino bianco. Cuocere coperto a fuoco vivo 5 minuti finche si aprono. Aggiungere abbondante prezzemolo. Servire con pane tostato.",note_en:"Clean and scrub mussels. Sauté garlic and chilli in oil. Add mussels and white wine. Cook covered on high heat 5 minutes until they open. Add plenty of parsley. Serve with toasted bread.",ingredienti:[{nome:"Cozze",qt:"1.5kg"},{nome:"Vino bianco",qt:"200ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"30g"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Cozze al vino bianco e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:18,gs:1.5,g:8,z:2,ch:8,fi:.5,ca:70,fe:4,mg:45,k2:420,na:480,zn:2.5,fo:35,se:45,col:60}},{id:"tpl_1164",nome:"Trota salmonata al cartoccio",nome_en:"Salmon trout en papillote",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di trota su carta da forno. Aggiungere fettine di limone, aneto, pomodorini e olio. Chiudere a cartoccio. Cuocere in forno a 190 C per 18 minuti. Aprire il cartoccio al tavolo per godere dell'aroma.",note_en:"Place trout fillets on parchment paper. Add lemon slices, dill, cherry tomatoes and oil. Seal into parcel. Bake at 190 C for 18 minutes. Open parcel at table to enjoy the aroma.",ingredienti:[{nome:"Filetti di trota salmonata",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aneto fresco",qt:"20g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aglio",qt:"2 spicchi"}],_dbEntry:{n:"Trota salmonata al cartoccio (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:30,gs:3.5,g:14,z:2,ch:3,fi:.5,ca:35,fe:1.2,mg:38,k2:580,na:200,zn:1.5,fo:18,se:42,col:90}},{id:"tpl_1165",nome:"Tonno in crosta di sesamo con zenzero",nome_en:"Sesame-crusted tuna with ginger",categoria:"Secondo piatto",porzioni:4,note:"Impanare le bistecche di tonno nei semi di sesamo nero e bianco. Cuocere in padella caldissima con poco olio 2 minuti per lato. Il tonno deve restare rosato al centro. Servire con salsa di soia e zenzero grattugiato.",note_en:"Coat tuna steaks in black and white sesame seeds. Cook in very hot pan with little oil 2 minutes per side. Tuna should remain pink in centre. Serve with soy sauce and grated ginger.",ingredienti:[{nome:"Filetto di tonno fresco",qt:"600g"},{nome:"Semi di sesamo misti",qt:"80g"},{nome:"Salsa di soia",qt:"40ml"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Olio di sesamo",qt:"20ml"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Tonno in crosta di sesamo con zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:36,gs:2.5,g:13,z:1,ch:4,fi:1,ca:100,fe:2,mg:55,k2:580,na:720,zn:1.5,fo:15,se:80,col:60}},{id:"tpl_1166",nome:"Spigola in acqua pazza",nome_en:"Sea bass in crazy water",categoria:"Secondo piatto",porzioni:4,note:"Rosolare la spigola intera in olio con aglio e peperoncino. Aggiungere pomodorini, prezzemolo e acqua. Cuocere coperto 20 minuti. L'acqua di cottura si trasforma in un brodo aromatico delizioso.",note_en:"Brown whole sea bass in oil with garlic and chilli. Add cherry tomatoes, parsley and water. Cook covered 20 minutes. Cooking liquid transforms into a delicious aromatic broth.",ingredienti:[{nome:"Spigola intera",qt:"1kg"},{nome:"Pomodorini",qt:"250g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Prezzemolo",qt:"25g"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Acqua",qt:"200ml"}],_dbEntry:{n:"Spigola in acqua pazza (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:30,gs:1.5,g:10,z:2,ch:3,fi:.8,ca:45,fe:1.5,mg:40,k2:600,na:250,zn:1.2,fo:20,se:38,col:78}},{id:"tpl_1167",nome:"Filetti di platessa alle erbe",nome_en:"Plaice fillets with herbs",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di platessa in teglia. Cospargere con pangrattato, prezzemolo, aglio, scorza di limone e olio. Cuocere in forno a 200 C per 15 minuti finche la superficie e dorata. Servire con verdure a vapore.",note_en:"Arrange plaice fillets in baking dish. Sprinkle with breadcrumbs, parsley, garlic, lemon zest and oil. Bake at 200 C for 15 minutes until surface is golden. Serve with steamed vegetables.",ingredienti:[{nome:"Filetti di platessa",qt:"700g"},{nome:"Pangrattato",qt:"50g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Filetti di platessa alle erbe (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:26,gs:1.5,g:8,z:1,ch:8,fi:.5,ca:40,fe:1,mg:32,k2:480,na:250,zn:1,fo:18,se:28,col:60}},{id:"tpl_1168",nome:"Seppie in umido con piselli",nome_en:"Cuttlefish stew with peas",categoria:"Secondo piatto",porzioni:4,note:"Pulire le seppie e tagliarle ad anelli. Soffriggere cipolla e aglio in olio. Aggiungere le seppie e sfumare con vino bianco. Unire i piselli e pomodori. Cuocere coperto 35 minuti. Aggiungere prezzemolo.",note_en:"Clean cuttlefish and cut into rings. Sauté onion and garlic in oil. Add cuttlefish and deglaze with white wine. Add peas and tomatoes. Cook covered 35 minutes. Add parsley.",ingredienti:[{nome:"Seppie",qt:"800g"},{nome:"Piselli",qt:"300g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"120ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Seppie in umido con piselli (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:1.5,g:8,z:5,ch:12,fi:4,ca:55,fe:2.5,mg:52,k2:580,na:380,zn:2,fo:50,se:40,col:180}},{id:"tpl_1169",nome:"Nasello al forno con patate",nome_en:"Baked hake with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Affettare le patate e disporle in teglia con olio. Adagiare i filetti di nasello sopra. Condire con aglio, prezzemolo, olio e vino bianco. Cuocere in forno a 190 C per 30 minuti.",note_en:"Slice potatoes and arrange in oiled baking dish. Place hake fillets on top. Season with garlic, parsley, oil and white wine. Bake at 190 C for 30 minutes.",ingredienti:[{nome:"Filetti di nasello",qt:"700g"},{nome:"Patate",qt:"500g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Nasello al forno con patate (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:28,gs:1.5,g:9,z:1,ch:22,fi:2,ca:45,fe:1.5,mg:42,k2:720,na:250,zn:1.2,fo:20,se:32,col:65}},{id:"tpl_1170",nome:"Sardine in saor veneziane",nome_en:"Venetian sweet-sour sardines",categoria:"Secondo piatto",porzioni:4,note:"Friggere le sardine infarinate. Stufare cipolle in olio finche morbide. Sfumare con aceto, aggiungere uvetta e pinoli. Alternare strati di sardine e cipolle in un contenitore. Lasciare marinare 24 ore in frigorifero.",note_en:"Fry floured sardines. Stew onions in oil until soft. Deglaze with vinegar, add raisins and pine nuts. Alternate layers of sardines and onions in a container. Marinate 24 hours in fridge.",ingredienti:[{nome:"Sardine fresche",qt:"600g"},{nome:"Cipolle",qt:"400g"},{nome:"Aceto di vino bianco",qt:"100ml"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Farina",qt:"60g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Sardine in saor veneziane (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:22,gs:3,g:16,z:8,ch:20,fi:2,ca:85,fe:2.5,mg:42,k2:480,na:280,zn:2,fo:18,se:38,col:72}},{id:"tpl_1171",nome:"Patate arrosto al rosmarino",nome_en:"Roast potatoes with rosemary",categoria:"Contorno",porzioni:4,note:"Tagliare le patate a spicchi. Bollire 10 minuti. Scolare e asciugare bene. Disporre in teglia con olio abbondante, rosmarino, aglio e sale. Cuocere in forno a 220 C per 35-40 minuti rigirando ogni 10 minuti.",note_en:"Cut potatoes into wedges. Boil 10 minutes. Drain and dry well. Arrange in baking dish with plenty of oil, rosemary, garlic and salt. Bake at 220 C for 35-40 minutes turning every 10 minutes.",ingredienti:[{nome:"Patate a pasta gialla",qt:"800g"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Sale grosso",qt:"q.b."}],_dbEntry:{n:"Patate arrosto al rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:3.5,gs:1.5,g:10,z:1,ch:28,fi:2.5,ca:15,fe:1,mg:28,k2:580,na:200,zn:.5,fo:22,se:2,col:0}},{id:"tpl_1172",nome:"Spinaci saltati con aglio e olio",nome_en:"Sautéed spinach with garlic and oil",categoria:"Contorno",porzioni:4,note:"Lavare gli spinaci. Soffriggere aglio e peperoncino in olio. Aggiungere gli spinaci freschi e cuocere a fuoco vivo 5 minuti mescolando. Salare e servire come contorno versatile.",note_en:"Wash spinach. Sauté garlic and chilli in oil. Add fresh spinach and cook on high heat 5 minutes stirring. Season with salt and serve as versatile side dish.",ingredienti:[{nome:"Spinaci freschi",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Spinaci saltati con aglio e olio (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:5,gs:1,g:7,z:1,ch:4,fi:4,ca:160,fe:3.5,mg:80,k2:680,na:180,zn:1,fo:180,se:2,col:0}},{id:"tpl_1173",nome:"Caponata siciliana",nome_en:"Sicilian caponata",categoria:"Contorno",porzioni:6,note:"Friggere le melanzane a cubetti. Soffriggere cipolla in olio. Aggiungere sedano, pomodori, olive, capperi. Sfumare con aceto e zucchero per il sapore agrodolce. Aggiungere le melanzane e cuocere 20 minuti. Ottima fredda.",note_en:"Fry diced aubergine. Sauté onion in oil. Add celery, tomatoes, olives, capers. Deglaze with vinegar and sugar for sweet-sour flavour. Add aubergine and cook 20 minutes. Excellent cold.",ingredienti:[{nome:"Melanzane",qt:"600g"},{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"3 coste"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Olive verdi",qt:"80g"},{nome:"Capperi",qt:"40g"},{nome:"Aceto di vino",qt:"50ml"},{nome:"Zucchero",qt:"20g"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Caponata siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:2,g:12,z:8,ch:14,fi:5,ca:45,fe:1.5,mg:35,k2:480,na:380,zn:.5,fo:28,se:2,col:0}},{id:"tpl_1174",nome:"Fagiolini verdi al vapore con mandorle",nome_en:"Steamed green beans with almonds",categoria:"Contorno",porzioni:4,note:"Cuocere i fagiolini a vapore 8 minuti: devono restare croccanti. Tostare le mandorle a lamelle in padella. Condire i fagiolini con olio, limone, sale e mandorle tostate.",note_en:"Steam green beans 8 minutes: they should remain crunchy. Toast flaked almonds in pan. Dress beans with oil, lemon, salt and toasted almonds.",ingredienti:[{nome:"Fagiolini verdi",qt:"600g"},{nome:"Mandorle a lamelle",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Fagiolini verdi al vapore con mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4.5,gs:1,g:7,z:3,ch:8,fi:4.5,ca:60,fe:1.5,mg:42,k2:340,na:10,zn:.8,fo:48,se:2,col:0}},{id:"tpl_1175",nome:"Zucchine trifolate",nome_en:"Sautéed courgettes with garlic",categoria:"Contorno",porzioni:4,note:"Tagliare le zucchine a rondelle o listarelle. Soffriggere aglio in olio. Aggiungere le zucchine e cuocere a fuoco vivo 8-10 minuti. Aggiungere prezzemolo e menta. Salare. Ottime calde o fredde.",note_en:"Cut courgettes into rounds or strips. Sauté garlic in oil. Add courgettes and cook on high heat 8-10 minutes. Add parsley and mint. Season with salt. Excellent hot or cold.",ingredienti:[{nome:"Zucchine",qt:"700g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Menta",qt:"5g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zucchine trifolate (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2.5,gs:1.2,g:7,z:3,ch:5,fi:2,ca:25,fe:.8,mg:22,k2:350,na:10,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1176",nome:"Broccoli al vapore con olio al limone",nome_en:"Steamed broccoli with lemon oil",categoria:"Contorno",porzioni:4,note:"Dividere i broccoli in cimette. Cuocere a vapore 8 minuti: devono restare al dente e di colore verde vivo. Condire con emulsione di olio extravergine, succo di limone, sale e pepe.",note_en:"Divide broccoli into florets. Steam 8 minutes: should remain al dente and bright green. Dress with emulsion of extra virgin oil, lemon juice, salt and pepper.",ingredienti:[{nome:"Broccoli",qt:"700g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Broccoli al vapore con olio al limone (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:5,gs:1.2,g:7,z:2,ch:6,fi:5,ca:65,fe:1,mg:25,k2:380,na:45,zn:.6,fo:100,se:3,col:0}},{id:"tpl_1177",nome:"Carote glassate al miele e timo",nome_en:"Honey-glazed carrots with thyme",categoria:"Contorno",porzioni:4,note:"Pelare le carote e tagliarle a bastoncini. Cuocere in padella con burro, acqua e miele coperto 10 minuti. Scoprire e alzare il fuoco per glassare. Aggiungere timo fresco e poco aceto balsamico.",note_en:"Peel carrots and cut into sticks. Cook in pan with butter, water and honey covered 10 minutes. Uncover and increase heat to glaze. Add fresh thyme and a little balsamic vinegar.",ingredienti:[{nome:"Carote",qt:"600g"},{nome:"Burro",qt:"25g"},{nome:"Miele",qt:"30ml"},{nome:"Timo",qt:"4 rametti"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Carote glassate al miele e timo (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1.5,gs:2,g:5,z:12,ch:16,fi:3.5,ca:42,fe:.7,mg:18,k2:420,na:90,zn:.3,fo:22,se:1,col:12}},{id:"tpl_1178",nome:"Peperoni arrostiti",nome_en:"Roasted peppers",categoria:"Contorno",porzioni:4,note:"Arrostire i peperoni interi direttamente sulla fiamma o in forno a 250 C finche la pelle e nera. Chiudere in sacchetto di plastica 15 minuti. Pelare, eliminare semi e filamenti. Condire con olio, aglio e basilico.",note_en:"Roast whole peppers directly on flame or in oven at 250 C until skin is black. Close in plastic bag 15 minutes. Peel, remove seeds and membranes. Dress with oil, garlic and basil.",ingredienti:[{nome:"Peperoni misti",qt:"800g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Peperoni arrostiti (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2,gs:1.2,g:7,z:6,ch:8,fi:3,ca:20,fe:.8,mg:18,k2:380,na:10,zn:.3,fo:35,se:1,col:0}},{id:"tpl_1179",nome:"Carciofi alla romana",nome_en:"Roman-style artichokes",categoria:"Contorno",porzioni:4,note:"Pulire i carciofi lasciando il gambo. Farcire con menta, prezzemolo e aglio. Disporli in casseruola con olio e acqua. Cuocere coperto a fuoco lento 35-40 minuti finche teneri. I gambi devono risultare morbidi.",note_en:"Clean artichokes keeping stems. Fill with mint, parsley and garlic. Arrange in pan with oil and water. Cook covered on low heat 35-40 minutes until tender. Stems should be soft.",ingredienti:[{nome:"Carciofi romaneschi",qt:"4"},{nome:"Menta",qt:"20g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Carciofi alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:4,gs:2,g:10,z:2,ch:10,fi:6,ca:45,fe:1.5,mg:35,k2:420,na:80,zn:.6,fo:68,se:1,col:0}},{id:"tpl_1180",nome:"Verdure grigliate miste",nome_en:"Mixed grilled vegetables",categoria:"Contorno",porzioni:4,note:"Affettare melanzane, zucchine, peperoni e cipolla rossa. Condire con olio e sale. Grigliare su piastra caldissima 3-4 minuti per lato. Condire con olio crudo, aglio, basilico e aceto balsamico.",note_en:"Slice aubergines, courgettes, peppers and red onion. Season with oil and salt. Grill on very hot griddle 3-4 minutes per side. Dress with raw oil, garlic, basil and balsamic vinegar.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Zucchine",qt:"300g"},{nome:"Peperoni",qt:"2"},{nome:"Cipolla rossa",qt:"2"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Aceto balsamico",qt:"20ml"},{nome:"Basilico",qt:"10g"}],_dbEntry:{n:"Verdure grigliate miste (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2.5,gs:1.5,g:8,z:6,ch:8,fi:4,ca:25,fe:.8,mg:25,k2:450,na:15,zn:.4,fo:35,se:1,col:0}},{id:"tpl_1181",nome:"Purè di patate classico",nome_en:"Classic mashed potatoes",categoria:"Contorno",porzioni:4,note:"Lessare le patate con la buccia. Pelare e passare allo schiacciapatate. Aggiungere burro, latte caldo e noce moscata. Mescolare energicamente finche il pure e liscio e cremoso. Regolare di sale.",note_en:"Boil potatoes in their skins. Peel and pass through potato ricer. Add butter, hot milk and nutmeg. Stir vigorously until mash is smooth and creamy. Season with salt.",ingredienti:[{nome:"Patate farinose",qt:"800g"},{nome:"Burro",qt:"60g"},{nome:"Latte intero",qt:"150ml"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Pure di patate classico (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:4,gs:4,g:8,z:3,ch:26,fi:2,ca:60,fe:.8,mg:22,k2:480,na:120,zn:.4,fo:15,se:2,col:22}},{id:"tpl_1182",nome:"Lenticchie in umido",nome_en:"Stewed lentils",categoria:"Contorno",porzioni:4,note:"Soffriggere cipolla, carota e sedano in olio. Aggiungere lenticchie lavate, pomodori e brodo. Cuocere 30 minuti. Aggiungere rosmarino. Le lenticchie devono essere morbide ma non sfatte. Ottimo con salsicce.",note_en:"Sauté onion, carrot and celery in oil. Add washed lentils, tomatoes and stock. Cook 30 minutes. Add rosemary. Lentils should be soft but not mushy. Excellent with sausages.",ingredienti:[{nome:"Lenticchie verdi",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Brodo",qt:"500ml"}],_dbEntry:{n:"Lenticchie in umido (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:.8,g:6,z:3,ch:30,fi:10,ca:45,fe:3.5,mg:55,k2:580,na:250,zn:2,fo:130,se:4,col:0}},{id:"tpl_1183",nome:"Fagioli all'uccelletto toscani",nome_en:"Tuscan cannellini beans",categoria:"Contorno",porzioni:4,note:"Soffriggere aglio e salvia in olio. Aggiungere i fagioli cannellini cotti. Unire poca passata di pomodoro e brodo. Cuocere 15 minuti a fuoco lento. Il sugo deve ristringere. Ottimi con salsicce o come contorno.",note_en:"Sauté garlic and sage in oil. Add cooked cannellini beans. Add a little tomato passata and stock. Cook 15 minutes on low heat. Sauce should thicken. Excellent with sausages or as side dish.",ingredienti:[{nome:"Fagioli cannellini cotti",qt:"600g"},{nome:"Passata di pomodoro",qt:"200g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Salvia",qt:"6 foglie"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Fagioli all uccelletto toscani (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:11,gs:1,g:7,z:3,ch:25,fi:8,ca:65,fe:2.5,mg:52,k2:620,na:200,zn:1.5,fo:90,se:3,col:0}},{id:"tpl_1184",nome:"Cime di rapa saltate",nome_en:"Sautéed turnip tops",categoria:"Contorno",porzioni:4,note:"Lessare le cime di rapa in acqua salata 5 minuti. Scolare. Saltare in padella con olio, aglio e peperoncino a fuoco vivo 5 minuti. Ottima con la pasta (orecchiette) o come contorno.",note_en:"Boil turnip tops in salted water 5 minutes. Drain. Sauté in pan with oil, garlic and chilli on high heat 5 minutes. Excellent with pasta (orecchiette) or as side dish.",ingredienti:[{nome:"Cime di rapa",qt:"800g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Acciughe",qt:"2"}],_dbEntry:{n:"Cime di rapa saltate (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:1.5,g:8,z:2,ch:4,fi:5.5,ca:110,fe:2.5,mg:38,k2:380,na:180,zn:.8,fo:120,se:2,col:3}},{id:"tpl_1185",nome:"Funghi trifolati",nome_en:"Sautéed mushrooms with garlic and parsley",categoria:"Contorno",porzioni:4,note:"Pulire i funghi e tagliarli a fette. Soffriggere aglio in olio a fuoco vivo. Aggiungere i funghi e cuocere senza mescolare per 5 minuti. Saltare e aggiungere prezzemolo e succo di limone. Salare a fine cottura.",note_en:"Clean mushrooms and slice. Sauté garlic in oil on high heat. Add mushrooms and cook without stirring for 5 minutes. Toss and add parsley and lemon juice. Season at end of cooking.",ingredienti:[{nome:"Funghi misti o porcini",qt:"600g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"0.5"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Funghi trifolati (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:1.5,g:8,z:1,ch:4,fi:3.5,ca:15,fe:1.5,mg:18,k2:480,na:15,zn:1,fo:22,se:6,col:0}},{id:"tpl_1186",nome:"Zucca al forno con cannella e cumino",nome_en:"Roasted pumpkin with cinnamon and cumin",categoria:"Contorno",porzioni:4,note:"Tagliare la zucca a spicchi lasciando la buccia. Condire con olio, cannella, cumino, sale e pepe. Cuocere in forno a 200 C per 30-35 minuti. La zucca deve caramellare ai bordi. Servire con yogurt al lime.",note_en:"Cut pumpkin into wedges leaving skin. Season with oil, cinnamon, cumin, salt and pepper. Bake at 200 C for 30-35 minutes. Pumpkin should caramelise at edges. Serve with lime yogurt.",ingredienti:[{nome:"Zucca",qt:"800g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Yogurt greco",qt:"100g"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Zucca al forno con cannella e cumino (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:4,gs:1.5,g:8,z:5,ch:12,fi:2.5,ca:55,fe:1,mg:22,k2:450,na:80,zn:.5,fo:25,se:2,col:2}},{id:"tpl_1187",nome:"Finocchi gratinati",nome_en:"Gratin fennel",categoria:"Contorno",porzioni:4,note:"Lessare i finocchi tagliati a meta in acqua salata 15 minuti. Scolare e disporre in teglia. Coprire con besciamella e parmigiano. Cuocere in forno a 200 C per 20 minuti fino a doratura.",note_en:"Boil halved fennel in salted water 15 minutes. Drain and arrange in baking dish. Cover with bechamel and parmesan. Bake at 200 C for 20 minutes until golden.",ingredienti:[{nome:"Finocchi",qt:"600g"},{nome:"Latte",qt:"300ml"},{nome:"Farina",qt:"25g"},{nome:"Burro",qt:"25g"},{nome:"Parmigiano",qt:"50g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Finocchi gratinati (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:7,gs:4,g:8,z:5,ch:12,fi:4,ca:200,fe:1,mg:25,k2:480,na:200,zn:1,fo:35,se:3,col:25}},{id:"tpl_1188",nome:"Melanzane alla parmigiana",nome_en:"Aubergine parmigiana",categoria:"Contorno",porzioni:6,note:"Friggere le melanzane a fette in olio abbondante. Scolare su carta. Alternare in teglia strati di melanzane, sugo di pomodoro, mozzarella e parmigiano. Cuocere in forno a 180 C per 40 minuti.",note_en:"Fry aubergine slices in plenty of oil. Drain on paper. Alternate in baking dish layers of aubergine, tomato sauce, mozzarella and parmesan. Bake at 180 C for 40 minutes.",ingredienti:[{nome:"Melanzane",qt:"1kg"},{nome:"Mozzarella",qt:"300g"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Parmigiano",qt:"80g"},{nome:"Basilico",qt:"15g"},{nome:"Olio per friggere",qt:"200ml"}],_dbEntry:{n:"Melanzane alla parmigiana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:5,g:22,z:6,ch:16,fi:5,ca:280,fe:1.5,mg:45,k2:520,na:420,zn:2,fo:45,se:5,col:30}},{id:"tpl_1189",nome:"Bruschetta al pomodoro e basilico",nome_en:"Bruschetta with tomato and basil",categoria:"Antipasto",porzioni:4,note:"Tostare le fette di pane casereccio sulla griglia. Strofinare con aglio. Condire con pomodori a dadini, basilico fresco, olio extravergine e sale grosso. Servire subito per mantenere il croccante.",note_en:"Toast slices of country bread on grill. Rub with garlic. Top with diced tomatoes, fresh basil, extra virgin oil and coarse salt. Serve immediately to keep crispness.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Pomodori maturi",qt:"400g"},{nome:"Basilico",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Sale grosso",qt:"q.b."}],_dbEntry:{n:"Bruschetta al pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1,g:7,z:4,ch:20,fi:2,ca:30,fe:1.2,mg:22,k2:320,na:200,zn:.5,fo:18,se:3,col:0}},{id:"tpl_1190",nome:"Carpaccio di manzo con rucola e parmigiano",nome_en:"Beef carpaccio with rocket and parmesan",categoria:"Antipasto",porzioni:4,note:"Affettare il filetto di manzo sottilissimo (oppure usare filetto gia affettato). Disporre su piatto. Condire con olio extravergine, succo di limone, sale e pepe. Coprire con rucola fresca e scaglie di parmigiano.",note_en:"Slice beef fillet very thin (or use pre-sliced fillet). Arrange on plate. Dress with extra virgin oil, lemon juice, salt and pepper. Cover with fresh rocket and parmesan shavings.",ingredienti:[{nome:"Filetto di manzo",qt:"400g"},{nome:"Rucola",qt:"100g"},{nome:"Parmigiano a scaglie",qt:"60g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Carpaccio di manzo con rucola e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:4,g:13,z:1,ch:2,fi:.5,ca:110,fe:2.5,mg:25,k2:420,na:280,zn:4,fo:28,se:18,col:55}},{id:"tpl_1191",nome:"Insalata caprese",nome_en:"Caprese salad",categoria:"Antipasto",porzioni:4,note:"Affettare i pomodori e la mozzarella di bufala. Alternare le fette su piatto da portata. Condire con olio extravergine di qualita, sale e foglie di basilico. Non aggiungere aceto. Servire a temperatura ambiente.",note_en:"Slice tomatoes and buffalo mozzarella. Alternate slices on serving plate. Dress with quality extra virgin oil, salt and basil leaves. Do not add vinegar. Serve at room temperature.",ingredienti:[{nome:"Pomodori cuore di bue",qt:"4"},{nome:"Mozzarella di bufala",qt:"250g"},{nome:"Basilico fresco",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata caprese (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:12,gs:5,g:16,z:4,ch:5,fi:1,ca:280,fe:.5,mg:18,k2:320,na:380,zn:1.5,fo:20,se:5,col:45}},{id:"tpl_1192",nome:"Tartare di tonno con avocado",nome_en:"Tuna tartare with avocado",categoria:"Antipasto",porzioni:4,note:"Tagliare il tonno fresco a cubetti piccoli. Condire con olio di sesamo, soia, zenzero grattugiato e cipollotto. Disporre su base di avocado schiacciato con lime. Guarnire con sesamo e microgreens.",note_en:"Cut fresh tuna into small cubes. Dress with sesame oil, soy, grated ginger and spring onion. Arrange on base of avocado mashed with lime. Garnish with sesame and microgreens.",ingredienti:[{nome:"Tonno fresco",qt:"400g"},{nome:"Avocado",qt:"2"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"15ml"},{nome:"Zenzero fresco",qt:"10g"},{nome:"Lime",qt:"1"},{nome:"Cipollotto",qt:"2"}],_dbEntry:{n:"Tartare di tonno con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:28,gs:3,g:16,z:1,ch:5,fi:4,ca:25,fe:1.5,mg:45,k2:680,na:580,zn:1.5,fo:38,se:55,col:48}},{id:"tpl_1193",nome:"Burrata con pomodori confit e pesto",nome_en:"Burrata with confit tomatoes and pesto",categoria:"Antipasto",porzioni:4,note:"Preparare i pomodorini confit in forno con olio, aglio e zucchero a 120 C per 2 ore. Disporre la burrata su piatto. Aggiungere i pomodori confit e cucchiaiate di pesto. Condire con olio e pane casereccio tostato.",note_en:"Prepare confit cherry tomatoes in oven with oil, garlic and sugar at 120 C for 2 hours. Place burrata on plate. Add confit tomatoes and spoonfuls of pesto. Dress with oil and toasted country bread.",ingredienti:[{nome:"Burrata",qt:"250g"},{nome:"Pomodorini",qt:"300g"},{nome:"Pesto al basilico",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Zucchero",qt:"10g"}],_dbEntry:{n:"Burrata con pomodori confit e pesto (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:9,g:24,z:5,ch:8,fi:1.5,ca:250,fe:.5,mg:20,k2:280,na:380,zn:1.2,fo:20,se:4,col:40}},{id:"tpl_1194",nome:"Tonno e fagioli",nome_en:"Tuna and bean salad",categoria:"Antipasto",porzioni:4,note:"Scolare il tonno e sminuzzarlo. Scolare i fagioli cannellini. Mescolare con cipolla rossa affettata sottile. Condire con olio extravergine, succo di limone, sale e pepe. Guarnire con prezzemolo.",note_en:"Drain and flake tuna. Drain cannellini beans. Mix with thinly sliced red onion. Dress with extra virgin oil, lemon juice, salt and pepper. Garnish with parsley.",ingredienti:[{nome:"Tonno sott olio",qt:"200g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Tonno e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:22,gs:1.5,g:10,z:2,ch:20,fi:7,ca:65,fe:3,mg:55,k2:700,na:480,zn:2,fo:88,se:38,col:35}},{id:"tpl_1195",nome:"Insalata russa",nome_en:"Russian salad",categoria:"Antipasto",porzioni:6,note:"Lessare separatamente patate, carote, fagiolini e piselli. Tagliare tutto a cubetti uniformi. Aggiungere cetriolini sott'aceto. Condire con maionese. Servire fredda decorata con uova sode e verdure.",note_en:"Boil separately potatoes, carrots, green beans and peas. Cut everything into uniform cubes. Add pickled gherkins. Dress with mayonnaise. Serve cold decorated with hard-boiled eggs and vegetables.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Carote",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Piselli",qt:"150g"},{nome:"Cetriolini",qt:"80g"},{nome:"Maionese",qt:"150g"},{nome:"Uova sode",qt:"2"}],_dbEntry:{n:"Insalata russa (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:6,gs:4,g:16,z:4,ch:18,fi:4,ca:40,fe:1.2,mg:30,k2:450,na:480,zn:.8,fo:45,se:5,col:75}},{id:"tpl_1196",nome:"Insalata greca",nome_en:"Greek salad",categoria:"Insalata",porzioni:4,note:"Tagliare pomodori, cetrioli e cipolla rossa. Aggiungere olive Kalamata e feta sbriciolata. Condire con olio extravergine, origano, sale e pepe. Non aggiungere aceto. La semplicita e il segreto.",note_en:"Cut tomatoes, cucumbers and red onion. Add Kalamata olives and crumbled feta. Dress with extra virgin oil, oregano, salt and pepper. Do not add vinegar. Simplicity is the secret.",ingredienti:[{nome:"Pomodori maturi",qt:"400g"},{nome:"Cetriolo",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Olive Kalamata",qt:"80g"},{nome:"Feta",qt:"150g"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata greca (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:5,g:16,z:5,ch:8,fi:3,ca:200,fe:1,mg:28,k2:420,na:680,zn:1.5,fo:30,se:5,col:30}},{id:"tpl_1197",nome:"Bowl di quinoa con verdure e ceci",nome_en:"Quinoa bowl with vegetables and chickpeas",categoria:"Insalata",porzioni:4,note:"Cuocere la quinoa in brodo vegetale. Arrostire i ceci con cumino e paprika. Preparare verdure arrostite. Comporre le bowl con quinoa, ceci, verdure, avocado e salsa tahini al limone.",note_en:"Cook quinoa in vegetable stock. Roast chickpeas with cumin and paprika. Prepare roasted vegetables. Compose bowls with quinoa, chickpeas, vegetables, avocado and lemon tahini sauce.",ingredienti:[{nome:"Quinoa",qt:"200g"},{nome:"Ceci cotti",qt:"300g"},{nome:"Avocado",qt:"2"},{nome:"Zucchine grigliate",qt:"200g"},{nome:"Tahini",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Cumino",qt:"1 cucchiaino"}],_dbEntry:{n:"Bowl di quinoa con verdure e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:2,g:18,z:3,ch:50,fi:12,ca:80,fe:4.5,mg:90,k2:750,na:280,zn:3,fo:160,se:6,col:0}},{id:"tpl_1198",nome:"Insalata di farro con pomodorini e mozzarella",nome_en:"Farro salad with cherry tomatoes and mozzarella",categoria:"Insalata",porzioni:4,note:"Cuocere il farro perlato in acqua salata 25 minuti. Scolare e raffreddare. Mescolare con pomodorini, mozzarella, rucola, basilico e olio. Aggiustare di sale e servire a temperatura ambiente.",note_en:"Cook pearl farro in salted water 25 minutes. Drain and cool. Mix with cherry tomatoes, mozzarella, rocket, basil and oil. Season with salt and serve at room temperature.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Pomodorini",qt:"250g"},{nome:"Mozzarella",qt:"200g"},{nome:"Rucola",qt:"60g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata di farro con pomodorini e mozzarella (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:4,g:14,z:4,ch:48,fi:4,ca:220,fe:2,mg:55,k2:420,na:320,zn:2,fo:40,se:8,col:25}},{id:"tpl_1199",nome:"Panzanella toscana",nome_en:"Tuscan bread salad",categoria:"Insalata",porzioni:4,note:"Bagnare il pane raffermo con acqua e aceto. Strizzare bene. Mescolare con pomodori maturi, cetriolo, cipolla rossa, basilico e olio extravergine. Lasciare riposare 30 minuti prima di servire.",note_en:"Soak stale bread with water and vinegar. Squeeze well. Mix with ripe tomatoes, cucumber, red onion, basil and extra virgin oil. Rest 30 minutes before serving.",ingredienti:[{nome:"Pane sciocco toscano raffermo",qt:"300g"},{nome:"Pomodori maturi",qt:"500g"},{nome:"Cetriolo",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Basilico",qt:"20g"},{nome:"Aceto di vino",qt:"30ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Panzanella toscana (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:5,gs:1.5,g:12,z:5,ch:30,fi:3,ca:55,fe:1.5,mg:28,k2:420,na:300,zn:.5,fo:25,se:4,col:0}},{id:"tpl_1200",nome:"Insalata di polpo e patate",nome_en:"Octopus and potato salad",categoria:"Insalata",porzioni:4,note:"Cuocere il polpo in acqua con aglio, alloro e limone per 50 minuti. Lasciare raffreddare nel brodo. Tagliare a pezzi. Lessare le patate e tagliarle a cubetti. Condire con olio, limone, prezzemolo, sedano e olive.",note_en:"Cook octopus in water with garlic, bay leaf and lemon for 50 minutes. Let cool in broth. Cut into pieces. Boil potatoes and dice. Dress with oil, lemon, parsley, celery and olives.",ingredienti:[{nome:"Polpo",qt:"800g"},{nome:"Patate",qt:"400g"},{nome:"Sedano",qt:"2 coste"},{nome:"Olive nere",qt:"60g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Limone",qt:"2"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Insalata di polpo e patate (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:26,gs:1.5,g:10,z:2,ch:20,fi:3,ca:60,fe:2.5,mg:50,k2:680,na:380,zn:2,fo:28,se:45,col:80}},{id:"tpl_1201",nome:"Tabouleh libanese",nome_en:"Lebanese tabbouleh",categoria:"Insalata",porzioni:4,note:"Idratare il bulgur in acqua calda 20 minuti. Scolare e raffreddare. Tritare abbondante prezzemolo e menta. Tagliare pomodori e cetriolo. Condire con olio extravergine e succo di limone abbondante.",note_en:"Hydrate bulgur in hot water 20 minutes. Drain and cool. Finely chop plenty of parsley and mint. Dice tomatoes and cucumber. Dress with extra virgin oil and plenty of lemon juice.",ingredienti:[{nome:"Bulgur",qt:"200g"},{nome:"Prezzemolo",qt:"100g"},{nome:"Menta fresca",qt:"30g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Cetriolo",qt:"1"},{nome:"Limone",qt:"2"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Tabouleh libanese (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:6,gs:1.5,g:12,z:4,ch:32,fi:5,ca:55,fe:3.5,mg:55,k2:520,na:30,zn:1,fo:120,se:3,col:0}},{id:"tpl_1202",nome:"Insalata di lenticchie e spinaci baby",nome_en:"Lentil and baby spinach salad",categoria:"Insalata",porzioni:4,note:"Cuocere le lenticchie verdi al dente. Raffreddare. Mescolare con spinaci baby, pomodorini, cipolla rossa, cetriolo. Condire con vinaigrette al limone (olio, limone, senape, miele). Aggiungere semi di girasole tostati.",note_en:"Cook green lentils al dente. Cool. Mix with baby spinach, cherry tomatoes, red onion, cucumber. Dress with lemon vinaigrette (oil, lemon, mustard, honey). Add toasted sunflower seeds.",ingredienti:[{nome:"Lenticchie verdi",qt:"200g"},{nome:"Spinaci baby",qt:"120g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Semi di girasole",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Limone",qt:"1"},{nome:"Senape",qt:"10g"}],_dbEntry:{n:"Insalata di lenticchie e spinaci baby (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:14,gs:1.5,g:12,z:4,ch:30,fi:10,ca:70,fe:4.5,mg:75,k2:680,na:120,zn:2.5,fo:160,se:8,col:0}},{id:"tpl_1203",nome:"Wrap integrale con pollo e avocado",nome_en:"Whole wheat wrap with chicken and avocado",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e affettarlo. Schiacciare l'avocado con limone e sale. Spalmare sulla piadina integrale. Aggiungere pollo, lattuga, pomodoro, cipolla rossa e yogurt greco. Arrotolare e tagliare a meta.",note_en:"Grill chicken breast and slice. Mash avocado with lemon and salt. Spread on whole wheat flatbread. Add chicken, lettuce, tomato, red onion and Greek yogurt. Roll up and cut in half.",ingredienti:[{nome:"Piadina integrale",qt:"2"},{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"60g"},{nome:"Pomodoro",qt:"1"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Yogurt greco",qt:"60g"}],_dbEntry:{n:"Wrap integrale con pollo e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:34,gs:3,g:14,z:4,ch:42,fi:8,ca:80,fe:2.5,mg:55,k2:680,na:420,zn:2.5,fo:55,se:22,col:75}},{id:"tpl_1204",nome:"Insalata di barbabietole e formaggio di capra",nome_en:"Beetroot and goat cheese salad",categoria:"Insalata",porzioni:4,note:"Arrostire le barbabietole in forno a 200 C per 45 minuti. Pelare e tagliare a spicchi. Disporre su letto di insalata mista con noci tostate e formaggio di capra sbriciolato. Condire con vinaigrette all'arancia.",note_en:"Roast beetroots in oven at 200 C for 45 minutes. Peel and cut into wedges. Arrange on mixed salad with toasted walnuts and crumbled goat cheese. Dress with orange vinaigrette.",ingredienti:[{nome:"Barbabietole",qt:"400g"},{nome:"Formaggio di capra",qt:"120g"},{nome:"Gherigli di noce",qt:"60g"},{nome:"Insalata mista",qt:"100g"},{nome:"Arancia",qt:"1"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Insalata di barbabietole e formaggio di capra (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:5,g:18,z:10,ch:18,fi:4.5,ca:130,fe:2,mg:35,k2:520,na:280,zn:1.5,fo:50,se:4,col:20}},{id:"tpl_1205",nome:"Tiramisù classico",nome_en:"Classic tiramisù",categoria:"Dolce",porzioni:8,note:"Montare i tuorli con lo zucchero. Aggiungere il mascarpone. Montare gli albumi a neve e incorporare. Inzuppare i savoiardi nel caffe. Alternare strati di crema e biscotti. Spolverare con cacao. Raffreddare 4 ore.",note_en:"Whisk egg yolks with sugar. Add mascarpone. Whisk egg whites stiff and fold in. Soak ladyfingers in coffee. Alternate layers of cream and biscuits. Dust with cocoa. Refrigerate 4 hours.",ingredienti:[{nome:"Mascarpone",qt:"500g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"100g"},{nome:"Savoiardi",qt:"300g"},{nome:"Caffe espresso",qt:"300ml"},{nome:"Cacao amaro",qt:"30g"}],_dbEntry:{n:"Tiramisu classico (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:10,gs:14,g:24,z:28,ch:40,fi:.5,ca:100,fe:1,mg:20,k2:150,na:120,zn:1,fo:20,se:8,col:185}},{id:"tpl_1206",nome:"Panna cotta alla vaniglia con coulis di fragole",nome_en:"Vanilla panna cotta with strawberry coulis",categoria:"Dolce",porzioni:6,note:"Scaldare panna con zucchero e vaniglia. Ammorbidire la gelatina in acqua fredda. Sciogliere nella panna calda. Versare negli stampini e raffreddare 4 ore. Preparare coulis di fragole con fragole frullate e zucchero a velo.",note_en:"Heat cream with sugar and vanilla. Soften gelatine in cold water. Dissolve in hot cream. Pour into moulds and refrigerate 4 hours. Prepare strawberry coulis with blended strawberries and icing sugar.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Zucchero",qt:"80g"},{nome:"Gelatina in fogli",qt:"10g"},{nome:"Baccello di vaniglia",qt:"1"},{nome:"Fragole",qt:"200g"},{nome:"Zucchero a velo",qt:"30g"}],_dbEntry:{n:"Panna cotta alla vaniglia con coulis di fragole (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:3,gs:12,g:18,z:22,ch:25,fi:.5,ca:80,fe:.2,mg:8,k2:120,na:30,zn:.3,fo:8,se:2,col:60}},{id:"tpl_1207",nome:"Crostata di marmellata",nome_en:"Jam tart",categoria:"Dolce",porzioni:8,note:"Impastare farina, burro freddo, zucchero, uova e scorza di limone fino a ottenere pasta frolla. Riposare 30 minuti. Stendere nella teglia imburrata. Farcire con marmellata. Decorare con strisce di pasta. Cuocere a 180 C per 35 minuti.",note_en:"Mix flour, cold butter, sugar, eggs and lemon zest to make shortcrust pastry. Rest 30 minutes. Roll into buttered tin. Fill with jam. Decorate with pastry strips. Bake at 180 C for 35 minutes.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Burro",qt:"150g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Marmellata",qt:"300g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Crostata di marmellata (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:4.5,gs:7,g:13,z:28,ch:50,fi:1,ca:30,fe:1,mg:15,k2:120,na:80,zn:.5,fo:12,se:4,col:70}},{id:"tpl_1208",nome:"Mousse al cioccolato fondente",nome_en:"Dark chocolate mousse",categoria:"Dolce",porzioni:6,note:"Sciogliere il cioccolato fondente a bagno maria. Montare gli albumi a neve. Montare la panna. Amalgamare il cioccolato tiepido con la panna montata. Incorporare gli albumi con movimenti dal basso. Raffreddare 2 ore.",note_en:"Melt dark chocolate over double boiler. Whisk egg whites stiff. Whip cream. Fold tepid chocolate into whipped cream. Fold in egg whites with bottom-to-top movements. Refrigerate 2 hours.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"200g"},{nome:"Panna fresca",qt:"250ml"},{nome:"Albumi",qt:"3"},{nome:"Zucchero",qt:"30g"}],_dbEntry:{n:"Mousse al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:5,gs:11,g:22,z:20,ch:28,fi:3,ca:40,fe:3,mg:60,k2:280,na:40,zn:1.5,fo:8,se:4,col:35}},{id:"tpl_1209",nome:"Torta di mele e cannella",nome_en:"Apple and cinnamon cake",categoria:"Dolce",porzioni:8,note:"Sbattere uova, zucchero e olio. Aggiungere farina, lievito, cannella e mele a cubetti. Versare in teglia imburrata. Cuocere in forno a 180 C per 40 minuti. Controllare con lo stecchino. Spolverare con zucchero a velo.",note_en:"Beat eggs, sugar and oil. Add flour, baking powder, cinnamon and diced apples. Pour into buttered tin. Bake at 180 C for 40 minutes. Check with toothpick. Dust with icing sugar.",ingredienti:[{nome:"Mele",qt:"4"},{nome:"Farina",qt:"250g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"100ml"},{nome:"Lievito",qt:"16g"},{nome:"Cannella",qt:"2 cucchiaini"}],_dbEntry:{n:"Torta di mele e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:4.5,gs:1.5,g:10,z:24,ch:42,fi:2,ca:30,fe:1,mg:18,k2:180,na:80,zn:.5,fo:15,se:5,col:70}},{id:"tpl_1210",nome:"Torta al cioccolato fondente",nome_en:"Dark chocolate cake",categoria:"Dolce",porzioni:8,note:"Sciogliere burro e cioccolato. Aggiungere uova, zucchero, farina e lievito. Versare in teglia. Cuocere a 180 C per 30-35 minuti. L'interno deve restare leggermente umido. Servire con ganache o zucchero a velo.",note_en:"Melt butter and chocolate. Add eggs, sugar, flour and baking powder. Pour into tin. Bake at 180 C for 30-35 minutes. Inside should remain slightly moist. Serve with ganache or icing sugar.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"200g"},{nome:"Burro",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Farina",qt:"100g"},{nome:"Lievito",qt:"8g"}],_dbEntry:{n:"Torta al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:6,gs:14,g:22,z:28,ch:42,fi:2.5,ca:40,fe:3.5,mg:55,k2:250,na:120,zn:1.5,fo:15,se:5,col:130}},{id:"tpl_1211",nome:"Cheesecake ai frutti di bosco",nome_en:"Berry cheesecake",categoria:"Dolce",porzioni:8,note:"Tritare i biscotti e mescolare con burro fuso. Pressare nella teglia. Montare formaggio spalmabile con zucchero, panna e limone. Versare sulla base. Raffreddare 6 ore. Decorare con coulis di frutti di bosco.",note_en:"Crush biscuits and mix with melted butter. Press into tin. Whip cream cheese with sugar, cream and lemon. Pour over base. Refrigerate 6 hours. Decorate with berry coulis.",ingredienti:[{nome:"Formaggio spalmabile",qt:"400g"},{nome:"Biscotti secchi",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Panna fresca",qt:"150ml"},{nome:"Zucchero",qt:"100g"},{nome:"Frutti di bosco misti",qt:"200g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Cheesecake ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:6,gs:15,g:24,z:24,ch:34,fi:1,ca:80,fe:.5,mg:12,k2:150,na:280,zn:.5,fo:10,se:3,col:75}},{id:"tpl_1212",nome:"Cannoli siciliani",nome_en:"Sicilian cannoli",categoria:"Dolce",porzioni:8,note:"Preparare la sfoglia con farina, strutto, zucchero, vino bianco e cacao. Avvolgere su cannolicchi e friggere. Mescolare ricotta setacciata con zucchero a velo, gocce di cioccolato e scorza d'arancia candita. Farcire i cannoli al momento.",note_en:"Make pastry with flour, lard, sugar, white wine and cocoa. Wrap around cannoli moulds and fry. Mix sieved ricotta with icing sugar, chocolate chips and candied orange peel. Fill cannoli at time of serving.",ingredienti:[{nome:"Ricotta di pecora",qt:"500g"},{nome:"Zucchero a velo",qt:"120g"},{nome:"Gocce di cioccolato",qt:"60g"},{nome:"Farina",qt:"300g"},{nome:"Strutto",qt:"30g"},{nome:"Vino bianco",qt:"100ml"}],_dbEntry:{n:"Cannoli siciliani (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:10,gs:8,g:14,z:22,ch:48,fi:1,ca:150,fe:1,mg:25,k2:150,na:80,zn:1,fo:12,se:6,col:45}},{id:"tpl_1213",nome:"Semifreddo al pistacchio",nome_en:"Pistachio semifreddo",categoria:"Dolce",porzioni:8,note:"Montare tuorli con zucchero. Montare panna. Tritare i pistacchi finemente. Amalgamare tutto delicatamente. Versare in stampo foderato con pellicola. Congelare almeno 6 ore. Servire con salsa di cioccolato bianco.",note_en:"Whisk egg yolks with sugar. Whip cream. Finely chop pistachios. Fold everything together gently. Pour into cling-film-lined mould. Freeze at least 6 hours. Serve with white chocolate sauce.",ingredienti:[{nome:"Pistacchi non salati",qt:"100g"},{nome:"Tuorli",qt:"4"},{nome:"Zucchero",qt:"100g"},{nome:"Panna fresca",qt:"300ml"},{nome:"Cioccolato bianco",qt:"80g"}],_dbEntry:{n:"Semifreddo al pistacchio (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:8,gs:14,g:28,z:28,ch:32,fi:1.5,ca:90,fe:1.5,mg:40,k2:320,na:40,zn:1.5,fo:12,se:4,col:180}},{id:"tpl_1214",nome:"Torta di carote e mandorle",nome_en:"Carrot and almond cake",categoria:"Dolce",porzioni:8,note:"Mescolare carote grattugiate, farina di mandorle, uova, zucchero, olio e lievito. Versare in teglia. Cuocere a 180 C per 35 minuti. Naturalmente umida e ricca di fibre. Spolverare con zucchero a velo e decorare con mandorle.",note_en:"Mix grated carrots, almond flour, eggs, sugar, oil and baking powder. Pour into tin. Bake at 180 C for 35 minutes. Naturally moist and fibre-rich. Dust with icing sugar and decorate with almonds.",ingredienti:[{nome:"Carote",qt:"300g"},{nome:"Farina di mandorle",qt:"200g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"120g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito",qt:"10g"},{nome:"Mandorle intere",qt:"40g"}],_dbEntry:{n:"Torta di carote e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:2.5,g:18,z:20,ch:30,fi:4,ca:80,fe:2,mg:55,k2:320,na:60,zn:1.2,fo:18,se:5,col:70}},{id:"tpl_1215",nome:"Granita al limone siciliana",nome_en:"Sicilian lemon granita",categoria:"Dolce",porzioni:6,note:"Sciogliere lo zucchero in acqua calda. Raffreddare. Aggiungere succo e scorza di limoni non trattati. Versare in contenitore basso e congelare. Ogni 30 minuti grattare con forchetta per formare i cristalli. Servire con brioche.",note_en:"Dissolve sugar in hot water. Cool. Add juice and zest of untreated lemons. Pour into shallow container and freeze. Every 30 minutes scrape with fork to form crystals. Serve with brioche.",ingredienti:[{nome:"Limoni non trattati",qt:"6"},{nome:"Zucchero",qt:"150g"},{nome:"Acqua",qt:"500ml"}],_dbEntry:{n:"Granita al limone siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:.2,gs:0,g:0,z:22,ch:28,fi:.5,ca:8,fe:.1,mg:5,k2:55,na:2,zn:.05,fo:5,se:0,col:0}},{id:"tpl_1216",nome:"Porridge di avena con frutti di bosco",nome_en:"Oat porridge with berries",categoria:"Colazione",porzioni:2,note:"Cuocere i fiocchi di avena con latte o acqua per 5-7 minuti mescolando. Aggiustare la consistenza con altro liquido. Servire in ciotola con frutti di bosco freschi, miele, semi di chia e noci. Proteico e nutriente.",note_en:"Cook oats with milk or water for 5-7 minutes stirring. Adjust consistency with more liquid. Serve in bowl with fresh berries, honey, chia seeds and walnuts. Protein-rich and nutritious.",ingredienti:[{nome:"Fiocchi di avena",qt:"80g"},{nome:"Latte",qt:"300ml"},{nome:"Frutti di bosco misti",qt:"100g"},{nome:"Miele",qt:"20ml"},{nome:"Semi di chia",qt:"10g"},{nome:"Noci",qt:"20g"}],_dbEntry:{n:"Porridge di avena con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:2.5,g:11,z:18,ch:54,fi:7,ca:220,fe:3,mg:75,k2:480,na:80,zn:2,fo:32,se:8,col:12}},{id:"tpl_1217",nome:"Toast con avocado e uova in camicia",nome_en:"Avocado toast with poached eggs",categoria:"Colazione",porzioni:2,note:"Tostare il pane integrale. Schiacciare l'avocado maturo con limone, sale e pepe. Cuocere le uova in camicia in acqua con aceto. Spalmare l'avocado sul pane. Adagiare le uova in camicia. Condire con peperoncino e semi di sesamo.",note_en:"Toast wholegrain bread. Mash ripe avocado with lemon, salt and pepper. Poach eggs in water with vinegar. Spread avocado on bread. Place poached eggs on top. Season with chilli and sesame seeds.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Limone",qt:"0.5"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Aceto di vino",qt:"20ml"}],_dbEntry:{n:"Toast con avocado e uova in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:16,gs:4,g:22,z:2,ch:30,fi:9,ca:80,fe:3.5,mg:55,k2:620,na:280,zn:2,fo:120,se:20,col:185}},{id:"tpl_1218",nome:"Yogurt greco con granola e frutta fresca",nome_en:"Greek yogurt with granola and fresh fruit",categoria:"Colazione",porzioni:2,note:"Tostare fiocchi di avena con miele, noci e semi in forno a 160 C per 20 minuti. Raffreddare. Servire con yogurt greco, granola croccante e frutta fresca di stagione. Ricco di proteine e probiotici.",note_en:"Toast oats with honey, nuts and seeds in oven at 160 C for 20 minutes. Cool. Serve with Greek yogurt, crunchy granola and fresh seasonal fruit. Rich in protein and probiotics.",ingredienti:[{nome:"Yogurt greco intero",qt:"300g"},{nome:"Fiocchi di avena",qt:"60g"},{nome:"Miele",qt:"25ml"},{nome:"Noci miste",qt:"30g"},{nome:"Frutta fresca di stagione",qt:"200g"}],_dbEntry:{n:"Yogurt greco con granola e frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:18,gs:3,g:12,z:22,ch:48,fi:4,ca:200,fe:2,mg:55,k2:520,na:80,zn:2,fo:28,se:8,col:15}},{id:"tpl_1219",nome:"Frittata alle erbe e verdure",nome_en:"Herb and vegetable frittata",categoria:"Colazione",porzioni:4,note:"Sbattere le uova con sale, pepe e erbe aromatiche. Soffriggere cipolla e verdure a dadini. Versare le uova sulle verdure. Cuocere coperto a fuoco lento 8 minuti. Gratinare sotto il grill 3 minuti. Ottima calda o fredda.",note_en:"Beat eggs with salt, pepper and herbs. Sauté onion and diced vegetables. Pour eggs over vegetables. Cook covered on low heat 8 minutes. Grill under broiler 3 minutes. Excellent hot or cold.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Prezzemolo",qt:"15g"},{nome:"Basilico",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Frittata alle erbe e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:14,gs:3.5,g:13,z:3,ch:6,fi:2,ca:80,fe:2.5,mg:28,k2:350,na:200,zn:1.5,fo:55,se:22,col:280}},{id:"tpl_1220",nome:"Chia pudding alla vaniglia",nome_en:"Vanilla chia pudding",categoria:"Colazione",porzioni:2,note:"Mescolare semi di chia con latte vegetale, miele e vaniglia. Lasciare riposare in frigorifero tutta la notte mescolando dopo 30 minuti. Al mattino il pudding e pronto. Servire con frutta fresca e sciroppo d'acero.",note_en:"Mix chia seeds with plant milk, honey and vanilla. Rest in fridge overnight stirring after 30 minutes. In the morning pudding is ready. Serve with fresh fruit and maple syrup.",ingredienti:[{nome:"Semi di chia",qt:"50g"},{nome:"Latte di mandorla",qt:"300ml"},{nome:"Miele",qt:"20ml"},{nome:"Vaniglia",qt:"0.5 cucchiaino"},{nome:"Frutta mista",qt:"100g"}],_dbEntry:{n:"Chia pudding alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:1.5,g:12,z:14,ch:32,fi:12,ca:280,fe:4,mg:90,k2:320,na:60,zn:2,fo:22,se:15,col:0}},{id:"tpl_1221",nome:"Banana bread integrale con noci",nome_en:"Wholegrain banana bread with walnuts",categoria:"Colazione",porzioni:8,note:"Schiacciare le banane mature. Mescolare con uova, olio, miele e vaniglia. Aggiungere farina integrale, lievito e bicarbonato. Incorporare le noci tritate. Cuocere in stampo da plum cake a 175 C per 60 minuti.",note_en:"Mash ripe bananas. Mix with eggs, oil, honey and vanilla. Add wholemeal flour, baking powder and bicarbonate. Fold in chopped walnuts. Bake in loaf tin at 175 C for 60 minutes.",ingredienti:[{nome:"Banane mature",qt:"3"},{nome:"Farina integrale",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60ml"},{nome:"Noci",qt:"60g"},{nome:"Lievito",qt:"10g"}],_dbEntry:{n:"Banana bread integrale con noci (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:1.5,g:11,z:16,ch:40,fi:4,ca:30,fe:1.5,mg:38,k2:320,na:80,zn:1,fo:20,se:8,col:45}},{id:"tpl_1222",nome:"Energy balls con datteri e cacao",nome_en:"Energy balls with dates and cocoa",categoria:"Spuntino",porzioni:4,note:"Frullare datteri denocciolati con mandorle, cacao, cocco rapato e un pizzico di sale. L'impasto deve essere appiccicoso. Formare palline. Rotolare nel cocco rapato. Conservare in frigorifero.",note_en:"Blend pitted dates with almonds, cocoa, desiccated coconut and pinch of salt. Mixture should be sticky. Shape into balls. Roll in desiccated coconut. Store in fridge.",ingredienti:[{nome:"Datteri Medjool",qt:"200g"},{nome:"Mandorle",qt:"100g"},{nome:"Cacao amaro",qt:"30g"},{nome:"Cocco rapato",qt:"40g"}],_dbEntry:{n:"Energy balls con datteri e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4.5,gs:3,g:8,z:20,ch:24,fi:4,ca:40,fe:1.5,mg:42,k2:280,na:5,zn:.8,fo:8,se:2,col:0}},{id:"tpl_1223",nome:"Hummus classico con crudité",nome_en:"Classic hummus with crudités",categoria:"Spuntino",porzioni:6,note:"Frullare ceci cotti con tahini, aglio, succo di limone, olio e sale fino a crema liscia. Aggiungere acqua fredda per ammorbidire. Servire con bastoncini di carota, sedano, cetriolo e peperoni.",note_en:"Blend cooked chickpeas with tahini, garlic, lemon juice, oil and salt until smooth cream. Add cold water to soften. Serve with sticks of carrot, celery, cucumber and peppers.",ingredienti:[{nome:"Ceci cotti",qt:"400g"},{nome:"Tahini",qt:"60g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Carote",qt:"2"},{nome:"Cetriolo",qt:"1"},{nome:"Peperoni",qt:"1"}],_dbEntry:{n:"Hummus classico con crudite (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:8,gs:1.5,g:10,z:3,ch:20,fi:7,ca:65,fe:2.5,mg:55,k2:480,na:180,zn:1.5,fo:100,se:5,col:0}},{id:"tpl_1224",nome:"Smoothie bowl verde con banana e spinaci",nome_en:"Green smoothie bowl with banana and spinach",categoria:"Colazione",porzioni:2,note:"Frullare spinaci baby, banana congelata, latte di cocco e proteine in polvere. Versare in ciotola. Decorare con fette di banana fresca, mirtilli, semi di canapa, granola e filo di miele. Consumare subito.",note_en:"Blend baby spinach, frozen banana, coconut milk and protein powder. Pour into bowl. Decorate with fresh banana slices, blueberries, hemp seeds, granola and drizzle of honey. Consume immediately.",ingredienti:[{nome:"Spinaci baby",qt:"60g"},{nome:"Banana congelata",qt:"2"},{nome:"Latte di cocco",qt:"100ml"},{nome:"Mirtilli",qt:"80g"},{nome:"Granola",qt:"30g"},{nome:"Semi di canapa",qt:"15g"},{nome:"Miele",qt:"15ml"}],_dbEntry:{n:"Smoothie bowl verde con banana e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:8,gs:5,g:10,z:28,ch:52,fi:7,ca:80,fe:2.5,mg:62,k2:680,na:60,zn:1.5,fo:80,se:4,col:0}},{id:"tpl_1225",nome:"Crema di zucca e zenzero",nome_en:"Pumpkin and ginger cream soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere zucca a cubetti, zenzero grattugiato e brodo vegetale. Cuocere 25 minuti. Frullare fino a crema liscia. Aggiustare di sale. Servire con panna acida, semi di zucca tostati e olio al peperoncino.",note_en:"Sauté onion in oil. Add diced pumpkin, grated ginger and vegetable stock. Cook 25 minutes. Blend until smooth cream. Season with salt. Serve with sour cream, toasted pumpkin seeds and chilli oil.",ingredienti:[{nome:"Zucca",qt:"800g"},{nome:"Zenzero fresco",qt:"25g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Panna acida",qt:"60g"},{nome:"Semi di zucca",qt:"20g"}],_dbEntry:{n:"Crema di zucca e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4.5,gs:3,g:9,z:6,ch:20,fi:3,ca:60,fe:1.5,mg:35,k2:580,na:280,zn:.8,fo:35,se:3,col:10}},{id:"tpl_1226",nome:"Zuppa di patate e porro",nome_en:"Potato and leek soup",categoria:"Zuppa",porzioni:4,note:"Stufare i porri affettati in burro. Aggiungere patate a cubetti e brodo. Cuocere 25 minuti. Frullare meta della zuppa per darle cremosita mantenendo pezzi. Aggiungere panna e servire con crostini e erba cipollina.",note_en:"Stew sliced leeks in butter. Add diced potatoes and stock. Cook 25 minutes. Blend half the soup for creaminess while keeping chunks. Add cream and serve with croutons and chives.",ingredienti:[{nome:"Porri",qt:"400g"},{nome:"Patate",qt:"500g"},{nome:"Burro",qt:"30g"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Zuppa di patate e porro (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4.5,gs:4,g:8,z:4,ch:32,fi:4,ca:70,fe:1.5,mg:35,k2:620,na:280,zn:.8,fo:45,se:3,col:25}},{id:"tpl_1227",nome:"Acquacotta maremmana",nome_en:"Maremma acquacotta",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, sedano, pomodori e peperoncino in olio. Aggiungere acqua e cuocere 30 minuti. Versare sulla zuppa due uova per persona: si cuociono direttamente nella zuppa calda. Servire su pane tostato sfregato con aglio.",note_en:"Sauté onion, celery, tomatoes and chilli in oil. Add water and cook 30 minutes. Break two eggs per person directly into hot soup to cook. Serve on toasted bread rubbed with garlic.",ingredienti:[{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"3 coste"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Uova",qt:"4"},{nome:"Pane casereccio",qt:"4 fette"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Acquacotta maremmana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:12,gs:3,g:14,z:5,ch:24,fi:3,ca:65,fe:2.5,mg:30,k2:420,na:320,zn:1.2,fo:45,se:15,col:185}},{id:"tpl_1228",nome:"Zuppa di cipolla alla francese",nome_en:"French onion soup",categoria:"Zuppa",porzioni:4,note:"Caramellare lentamente le cipolle affettate in burro per 45 minuti. Sfumare con vino bianco e brandy. Aggiungere brodo di carne. Cuocere 20 minuti. Versare in ciotole da forno. Coprire con pane tostato e gruviera. Gratinare.",note_en:"Slowly caramelise sliced onions in butter for 45 minutes. Deglaze with white wine and brandy. Add beef stock. Cook 20 minutes. Pour into oven bowls. Cover with toasted bread and gruyère. Gratinate.",ingredienti:[{nome:"Cipolle",qt:"1kg"},{nome:"Burro",qt:"50g"},{nome:"Brodo di carne",qt:"1L"},{nome:"Vino bianco",qt:"150ml"},{nome:"Pane baguette",qt:"4 fette"},{nome:"Gruviera",qt:"120g"}],_dbEntry:{n:"Zuppa di cipolla alla francese (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:7,g:14,z:8,ch:30,fi:3,ca:280,fe:1.5,mg:30,k2:380,na:480,zn:2,fo:22,se:8,col:45}},{id:"tpl_1229",nome:"Crema di piselli alla menta",nome_en:"Pea cream with mint",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere piselli surgelati e brodo. Cuocere 10 minuti. Frullare con foglie di menta fresca, succo di limone e olio. Servire calda o fredda con uno spoon di panna acida e menta.",note_en:"Sauté onion in oil. Add frozen peas and stock. Cook 10 minutes. Blend with fresh mint leaves, lemon juice and oil. Serve hot or cold with a spoonful of sour cream and mint.",ingredienti:[{nome:"Piselli surgelati",qt:"500g"},{nome:"Cipolla",qt:"1"},{nome:"Menta fresca",qt:"20g"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"},{nome:"Panna acida",qt:"60g"}],_dbEntry:{n:"Crema di piselli alla menta (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:10,gs:2,g:7,z:6,ch:22,fi:8,ca:45,fe:2.5,mg:42,k2:480,na:220,zn:1.2,fo:80,se:3,col:10}},{id:"tpl_1230",nome:"Jota triestina con crauti e fagioli",nome_en:"Triestine jota with sauerkraut and beans",categoria:"Zuppa",porzioni:6,note:"Soffriggere lardo e aglio. Aggiungere fagioli borlotti, crauti, patate e brodo. Cuocere 45 minuti. Aggiustare con un cucchiaio di farina per addensare. La jota deve risultare densa e saporita. Servire calda con pancetta croccante.",note_en:"Sauté lard and garlic. Add borlotti beans, sauerkraut, potatoes and stock. Cook 45 minutes. Adjust with a spoonful of flour to thicken. Jota should be thick and flavourful. Serve hot with crispy bacon.",ingredienti:[{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Crauti",qt:"300g"},{nome:"Patate",qt:"200g"},{nome:"Lardo",qt:"60g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Brodo",qt:"800ml"},{nome:"Farina",qt:"20g"}],_dbEntry:{n:"Jota triestina con crauti e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:14,gs:4,g:10,z:3,ch:36,fi:10,ca:65,fe:3,mg:55,k2:680,na:620,zn:2,fo:100,se:5,col:18}},{id:"tpl_1231",nome:"Crema di carote allo zenzero e arancia",nome_en:"Carrot cream with ginger and orange",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio. Aggiungere carote a rondelle, zenzero grattugiato e succo di arancia. Versare brodo e cuocere 25 minuti. Frullare. Regolare di sale. Guarnire con creme fraiche e semi di sesamo tostati.",note_en:"Sauté onion in oil. Add sliced carrots, grated ginger and orange juice. Pour in stock and cook 25 minutes. Blend. Season with salt. Garnish with crème fraîche and toasted sesame seeds.",ingredienti:[{nome:"Carote",qt:"700g"},{nome:"Zenzero fresco",qt:"20g"},{nome:"Arancia",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Creme fraiche",qt:"40g"}],_dbEntry:{n:"Crema di carote allo zenzero e arancia (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:3,gs:2,g:7,z:10,ch:20,fi:4.5,ca:55,fe:1,mg:20,k2:520,na:220,zn:.5,fo:30,se:2,col:8}},{id:"tpl_1232",nome:"Stracciatella romana",nome_en:"Roman egg-drop soup",categoria:"Zuppa",porzioni:4,note:"Portare a bollore il brodo di carne. Sbattere uova con parmigiano, sale e noce moscata. Versare il composto a filo nel brodo bollente mescolando. Le uova si raggrinziscono formando i caratteristici fiocchi. Servire con parmigiano.",note_en:"Bring meat stock to boil. Beat eggs with parmesan, salt and nutmeg. Pour mixture in a thin stream into boiling stock while stirring. Eggs curdle forming characteristic flakes. Serve with parmesan.",ingredienti:[{nome:"Brodo di carne",qt:"1L"},{nome:"Uova",qt:"3"},{nome:"Parmigiano",qt:"60g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Stracciatella romana (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:14,gs:4,g:10,z:.5,ch:4,fi:0,ca:180,fe:1.5,mg:18,k2:220,na:380,zn:1.5,fo:15,se:15,col:185}},{id:"tpl_1233",nome:"Minestrone estivo di verdure fresche",nome_en:"Summer fresh vegetable minestrone",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla e aglio in olio. Aggiungere zucchine, fagiolini, pomodori, mais e brodo. Cuocere 20 minuti. Aggiungere pasta corta o riso. Servire tiepido con abbondante basilico e parmigiano.",note_en:"Sauté onion and garlic in oil. Add courgettes, green beans, tomatoes, corn and stock. Cook 20 minutes. Add short pasta or rice. Serve warm with plenty of basil and parmesan.",ingredienti:[{nome:"Zucchine",qt:"200g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Mais",qt:"100g"},{nome:"Pasta corta",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Basilico",qt:"20g"}],_dbEntry:{n:"Minestrone estivo di verdure fresche (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:7,gs:1,g:5,z:5,ch:32,fi:5.5,ca:50,fe:1.5,mg:40,k2:520,na:280,zn:.8,fo:50,se:4,col:0}},{id:"tpl_1234",nome:"Brodetto di pesce marchigiano",nome_en:"Marche-style fish brodetto",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e aglio in olio. Aggiungere passata di pomodoro e aceto bianco. Cuocere 10 minuti. Aggiungere pesce misto a pezzi nell'ordine di cottura: prima i molluschi, poi il pesce. Cuocere 20 minuti. Servire su pane abbrustolito.",note_en:"Sauté onion and garlic in oil. Add tomato passata and white vinegar. Cook 10 minutes. Add mixed fish pieces in order of cooking: molluscs first, then fish. Cook 20 minutes. Serve on toasted bread.",ingredienti:[{nome:"Pesce misto da zuppa",qt:"1kg"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Aceto bianco",qt:"30ml"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Pane casereccio",qt:"4 fette"}],_dbEntry:{n:"Brodetto di pesce marchigiano (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:30,gs:2.5,g:10,z:5,ch:18,fi:2,ca:80,fe:2.5,mg:55,k2:620,na:480,zn:2,fo:28,se:45,col:95}},{id:"tpl_1235",nome:"Zuppa di miso con tofu e wakame",nome_en:"Miso soup with tofu and wakame",categoria:"Zuppa",porzioni:4,note:"Preparare il dashi con kombu e katsuobushi. Filtrare. Sciogliere il miso nel dashi tiepido (non bollire il miso). Aggiungere tofu a cubetti, alghe wakame reidratate e cipollotto affettato. Servire subito.",note_en:"Prepare dashi with kombu and bonito flakes. Strain. Dissolve miso in warm dashi (do not boil miso). Add diced tofu, rehydrated wakame seaweed and sliced spring onion. Serve immediately.",ingredienti:[{nome:"Miso bianco",qt:"60g"},{nome:"Tofu sodo",qt:"200g"},{nome:"Alghe wakame secche",qt:"10g"},{nome:"Cipollotto",qt:"3"},{nome:"Kombu",qt:"10g"},{nome:"Katsuobushi",qt:"15g"}],_dbEntry:{n:"Zuppa di miso con tofu e wakame (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:8,gs:.5,g:3,z:2,ch:10,fi:2,ca:80,fe:2,mg:45,k2:320,na:780,zn:1.2,fo:25,se:5,col:0}},{id:"tpl_1236",nome:"Crema di asparagi con uovo in camicia",nome_en:"Asparagus cream with poached egg",categoria:"Zuppa",porzioni:4,note:"Lessare gli asparagi 10 minuti tenendo le punte. Frullare i gambi con brodo, scalogno stufato e panna. Setacciare. Aggiustare di sale. Servire la crema con una punta di asparago e un uovo in camicia al centro.",note_en:"Boil asparagus 10 minutes keeping tips. Blend stems with stock, stewed shallot and cream. Strain. Season with salt. Serve cream with an asparagus tip and a poached egg in the centre.",ingredienti:[{nome:"Asparagi",qt:"700g"},{nome:"Scalogno",qt:"2"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Uova",qt:"4"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Crema di asparagi con uovo in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:12,gs:4,g:12,z:4,ch:12,fi:4,ca:70,fe:3.5,mg:30,k2:450,na:250,zn:1.5,fo:150,se:18,col:185}},{id:"tpl_1237",nome:"Lombata di maiale alla griglia con salsa verde",nome_en:"Grilled pork loin with green sauce",categoria:"Secondo piatto",porzioni:4,note:"Condire le fettine di lombata con olio, aglio, timo e pepe. Grigliare su piastra caldissima 3-4 minuti per lato. Preparare salsa verde con prezzemolo, acciughe, capperi, aglio, olio e aceto. Servire la carne nappata di salsa.",note_en:"Season pork loin slices with oil, garlic, thyme and pepper. Grill on very hot griddle 3-4 minutes per side. Make green sauce with parsley, anchovies, capers, garlic, oil and vinegar. Serve meat topped with sauce.",ingredienti:[{nome:"Lombata di maiale",qt:"600g"},{nome:"Prezzemolo",qt:"50g"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"30g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Aceto di vino",qt:"20ml"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Lombata di maiale alla griglia con salsa verde (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:30,gs:4,g:18,z:.5,ch:2,fi:.5,ca:35,fe:1.8,mg:32,k2:480,na:380,zn:3,fo:15,se:22,col:85}},{id:"tpl_1238",nome:"Spiedini di pollo e verdure",nome_en:"Chicken and vegetable skewers",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il petto di pollo a cubetti. Alternare su spiedini con peperone, zucchine, cipolla e pomodorini. Marinare con olio, limone, aglio e origano 1 ora. Cuocere su griglia o in forno 20 minuti rigirando.",note_en:"Cut chicken breast into cubes. Alternate on skewers with pepper, courgettes, onion and cherry tomatoes. Marinate with oil, lemon, garlic and oregano 1 hour. Cook on grill or in oven 20 minutes turning.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Peperone",qt:"2"},{nome:"Zucchine",qt:"2"},{nome:"Cipolla rossa",qt:"2"},{nome:"Pomodorini",qt:"12"},{nome:"Limone",qt:"1"},{nome:"Origano",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Spiedini di pollo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:30,gs:1.5,g:9,z:5,ch:10,fi:3,ca:35,fe:1.5,mg:40,k2:620,na:180,zn:2,fo:35,se:22,col:80}},{id:"tpl_1239",nome:"Hamburger di manzo artigianale",nome_en:"Artisan beef burger",categoria:"Secondo piatto",porzioni:4,note:"Mescolare manzo macinato con sale e pepe. Formare 4 hamburger da 150g. Cuocere su piastra caldissima 4 minuti per lato. Servire su panino con lattuga, pomodoro, cipolla rossa, cetrioli e salse a scelta.",note_en:"Mix minced beef with salt and pepper. Shape 4 burgers of 150g each. Cook on very hot griddle 4 minutes per side. Serve in bun with lettuce, tomato, red onion, gherkins and chosen sauces.",ingredienti:[{nome:"Macinato di manzo (20% grasso)",qt:"600g"},{nome:"Panini per hamburger",qt:"4"},{nome:"Lattuga",qt:"80g"},{nome:"Pomodoro",qt:"2"},{nome:"Cipolla rossa",qt:"1"},{nome:"Cetriolini",qt:"4"},{nome:"Cheddar",qt:"4 fette"}],_dbEntry:{n:"Hamburger di manzo artigianale (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:36,gs:10,g:28,z:6,ch:44,fi:2,ca:180,fe:4,mg:40,k2:500,na:720,zn:6,fo:30,se:22,col:110}},{id:"tpl_1240",nome:"Coscia di pollo ripiena al forno",nome_en:"Stuffed chicken leg baked",categoria:"Secondo piatto",porzioni:4,note:"Disossare le cosce di pollo. Farcire con spinaci saltati, ricotta, parmigiano e noce moscata. Richiudere e legare. Cuocere in forno a 190 C per 35-40 minuti. Servire con sugo del fondo di cottura.",note_en:"Debone chicken legs. Fill with sautéed spinach, ricotta, parmesan and nutmeg. Close and tie. Bake at 190 C for 35-40 minutes. Serve with cooking juice sauce.",ingredienti:[{nome:"Cosce di pollo disossate",qt:"4"},{nome:"Spinaci",qt:"200g"},{nome:"Ricotta",qt:"150g"},{nome:"Parmigiano",qt:"40g"},{nome:"Noce moscata",qt:"q.b."},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Coscia di pollo ripiena al forno (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:34,gs:6,g:18,z:2,ch:3,fi:1.5,ca:130,fe:2,mg:35,k2:480,na:280,zn:3,fo:30,se:28,col:120}},{id:"tpl_1241",nome:"Coda alla vaccinara",nome_en:"Roman oxtail in tomato sauce",categoria:"Secondo piatto",porzioni:6,note:"Rosolare i pezzi di coda con soffritto di cipolla, carota, sedano. Sfumare con vino bianco. Aggiungere pomodori, uvetta, pinoli, cacao e cannella. Cuocere 3 ore a fuoco lentissimo. Piatto della tradizione romana.",note_en:"Brown oxtail pieces with onion, carrot, celery soffritto. Deglaze with white wine. Add tomatoes, raisins, pine nuts, cocoa and cinnamon. Cook 3 hours on very low heat. Traditional Roman dish.",ingredienti:[{nome:"Coda di bue",qt:"1.5kg"},{nome:"Pomodori pelati",qt:"500g"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Cacao amaro",qt:"20g"},{nome:"Cannella",qt:"0.5 cucchiaino"},{nome:"Sedano",qt:"3 coste"},{nome:"Vino bianco",qt:"150ml"}],_dbEntry:{n:"Coda alla vaccinara (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:40,gs:5,g:18,z:7,ch:12,fi:3,ca:50,fe:4,mg:45,k2:650,na:420,zn:7,fo:22,se:28,col:115}},{id:"tpl_1242",nome:"Trippa alla romana",nome_en:"Roman-style tripe",categoria:"Secondo piatto",porzioni:4,note:"Lessare la trippa precotta 30 minuti. Soffriggere cipolla, aglio e peperoncino. Aggiungere trippa tagliata, pomodori e menta. Cuocere 30 minuti. Spolverare con pecorino romano abbondante. Piatto tipico della tradizione romanesca.",note_en:"Boil pre-cooked tripe 30 minutes. Sauté onion, garlic and chilli. Add sliced tripe, tomatoes and mint. Cook 30 minutes. Generously sprinkle with pecorino romano. Typical Roman tradition dish.",ingredienti:[{nome:"Trippa precotta",qt:"800g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Pecorino romano",qt:"80g"},{nome:"Menta",qt:"15g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Trippa alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:28,gs:5,g:14,z:5,ch:10,fi:2,ca:160,fe:2,mg:22,k2:380,na:520,zn:3.5,fo:12,se:20,col:130}},{id:"tpl_1243",nome:"Arista di maiale in porchetta",nome_en:"Pork loin in porchetta style",categoria:"Secondo piatto",porzioni:6,note:"Aprire la lonza a libro. Cospargere internamente con aglio, rosmarino, finocchietto selvatico, sale e pepe. Arrotolare e legare. Cuocere in forno a 160 C per 2 ore. La cotenna deve risultare croccante.",note_en:"Open pork loin like a book. Sprinkle inside with garlic, rosemary, wild fennel, salt and pepper. Roll and tie. Bake at 160 C for 2 hours. Skin should be crispy.",ingredienti:[{nome:"Lonza di maiale con cotenna",qt:"1.2kg"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Rosmarino",qt:"4 rametti"},{nome:"Finocchietto selvatico",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Arista di maiale in porchetta (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:35,gs:5,g:18,z:0,ch:1,fi:.3,ca:22,fe:1.5,mg:32,k2:500,na:300,zn:3.5,fo:8,se:28,col:100}},{id:"tpl_1244",nome:"Baccalà fritto in pastella alla birra",nome_en:"Beer-battered salt cod",categoria:"Secondo piatto",porzioni:4,note:"Dissalare il baccalà. Preparare pastella con farina, birra fredda, sale e pepe fino a consistenza cremosa. Passare il baccalà nella pastella. Friggere in olio a 180 C finche dorato e croccante. Servire con maionese e limone.",note_en:"Desalt cod. Make batter with flour, cold beer, salt and pepper to creamy consistency. Coat cod in batter. Fry in oil at 180 C until golden and crispy. Serve with mayonnaise and lemon.",ingredienti:[{nome:"Baccalà ammollato",qt:"600g"},{nome:"Farina 00",qt:"150g"},{nome:"Birra chiara",qt:"200ml"},{nome:"Olio per friggere",qt:"500ml"},{nome:"Limone",qt:"2"},{nome:"Maionese",qt:"80g"}],_dbEntry:{n:"Baccalà fritto in pastella alla birra (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:26,gs:4,g:20,z:1,ch:22,fi:.5,ca:40,fe:1.2,mg:38,k2:480,na:580,zn:1.2,fo:12,se:35,col:75}},{id:"tpl_1245",nome:"Cernia al forno con verdure mediterranee",nome_en:"Grouper baked with Mediterranean vegetables",categoria:"Secondo piatto",porzioni:4,note:"Disporre filetti di cernia in teglia con zucchine, pomodorini, olive e capperi. Condire con olio, aglio, origano e vino bianco. Cuocere in forno a 190 C per 25 minuti. Piatto completo e leggero.",note_en:"Arrange grouper fillets in baking dish with courgettes, cherry tomatoes, olives and capers. Season with oil, garlic, oregano and white wine. Bake at 190 C for 25 minutes. Complete and light dish.",ingredienti:[{nome:"Filetti di cernia",qt:"700g"},{nome:"Zucchine",qt:"200g"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"25g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cernia al forno con verdure mediterranee (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:30,gs:1.5,g:10,z:4,ch:8,fi:3,ca:50,fe:1.5,mg:45,k2:680,na:380,zn:1.5,fo:22,se:42,col:70}},{id:"tpl_1246",nome:"Scampi alla busara",nome_en:"Scampi alla busara",categoria:"Secondo piatto",porzioni:4,note:"Soffriggere aglio e peperoncino in olio. Aggiungere passata di pomodoro e vino bianco. Cuocere 10 minuti. Aggiungere gli scampi. Cuocere 8 minuti. Gli scampi devono risultare rossi e succulenti. Servire con polenta bianca o pane.",note_en:"Sauté garlic and chilli in oil. Add tomato passata and white wine. Cook 10 minutes. Add scampi. Cook 8 minutes. Scampi should be red and succulent. Serve with white polenta or bread.",ingredienti:[{nome:"Scampi",qt:"1kg"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Vino bianco",qt:"150ml"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Scampi alla busara (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:24,gs:1.5,g:9,z:4,ch:8,fi:1.5,ca:80,fe:2.5,mg:50,k2:550,na:580,zn:2,fo:18,se:40,col:145}},{id:"tpl_1247",nome:"Capesante gratinate con pancetta",nome_en:"Scallops gratin with bacon",categoria:"Secondo piatto",porzioni:4,note:"Disporre le capesante nelle mezze valve. Cospargere con pangrattato, prezzemolo, aglio e olio. Aggiungere una fettina di pancetta su ogni capasanta. Gratinare sotto il grill 5-6 minuti finche dorato.",note_en:"Place scallops in half shells. Sprinkle with breadcrumbs, parsley, garlic and oil. Add a slice of bacon on each scallop. Gratinate under grill 5-6 minutes until golden.",ingredienti:[{nome:"Capesante",qt:"12"},{nome:"Pancetta affumicata",qt:"80g"},{nome:"Pangrattato",qt:"40g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Capesante gratinate con pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:3,g:10,z:1,ch:8,fi:.5,ca:30,fe:1,mg:42,k2:420,na:480,zn:2.5,fo:15,se:25,col:55}},{id:"tpl_1248",nome:"Asparagi alla piastra con uova e parmigiano",nome_en:"Griddled asparagus with eggs and parmesan",categoria:"Contorno",porzioni:4,note:"Pulire gli asparagi e togliere la parte dura. Condire con olio e sale. Cuocere su piastra calda 8-10 minuti rigirando. Disporre su piatto con uova sode affettate, scaglie di parmigiano e vinaigrette al limone.",note_en:"Clean asparagus and remove tough ends. Season with oil and salt. Cook on hot griddle 8-10 minutes turning. Arrange on plate with sliced hard-boiled eggs, parmesan shavings and lemon vinaigrette.",ingredienti:[{nome:"Asparagi verdi",qt:"600g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano a scaglie",qt:"50g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Asparagi alla piastra con uova e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:12,gs:3,g:10,z:2,ch:5,fi:4,ca:120,fe:3.5,mg:32,k2:400,na:200,zn:1.5,fo:130,se:15,col:95}},{id:"tpl_1249",nome:"Topinambur arrosto con rosmarino",nome_en:"Roasted Jerusalem artichoke with rosemary",categoria:"Contorno",porzioni:4,note:"Lavare e tagliare i topinambur a spicchi senza sbucciarli. Condire con olio, rosmarino, aglio e sale. Cuocere in forno a 200 C per 30-35 minuti finche dorati e caramellati.",note_en:"Wash and cut Jerusalem artichokes into wedges without peeling. Season with oil, rosemary, garlic and salt. Bake at 200 C for 30-35 minutes until golden and caramelised.",ingredienti:[{nome:"Topinambur",qt:"700g"},{nome:"Rosmarino",qt:"3 rametti"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"35ml"}],_dbEntry:{n:"Topinambur arrosto con rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:3,gs:1.5,g:8,z:3,ch:16,fi:3,ca:20,fe:3,mg:20,k2:440,na:8,zn:.5,fo:15,se:1,col:0}},{id:"tpl_1250",nome:"Piselli alla menta e pancetta",nome_en:"Peas with mint and bacon",categoria:"Contorno",porzioni:4,note:"Rosolare la pancetta a cubetti in padella. Aggiungere i piselli freschi o surgelati con un mestolo di brodo. Cuocere 8 minuti. Aggiungere menta fresca e un filo di olio crudo. Semplice e gustoso.",note_en:"Brown diced bacon in pan. Add fresh or frozen peas with a ladle of stock. Cook 8 minutes. Add fresh mint and a drizzle of raw oil. Simple and tasty.",ingredienti:[{nome:"Piselli",qt:"500g"},{nome:"Pancetta",qt:"80g"},{nome:"Menta fresca",qt:"10g"},{nome:"Brodo",qt:"100ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Piselli alla menta e pancetta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:10,gs:2.5,g:8,z:5,ch:16,fi:5,ca:30,fe:1.5,mg:30,k2:350,na:320,zn:1,fo:55,se:3,col:18}},{id:"tpl_1251",nome:"Bietole con pinoli e uvetta",nome_en:"Swiss chard with pine nuts and raisins",categoria:"Contorno",porzioni:4,note:"Lessare le bietole con gambi 5 minuti. Soffriggere aglio in olio. Aggiungere le bietole strizzate, uvetta e pinoli. Saltare a fuoco vivo 5 minuti. Condire con olio crudo e poco aceto balsamico.",note_en:"Boil Swiss chard with stems 5 minutes. Sauté garlic in oil. Add squeezed chard, raisins and pine nuts. Sauté on high heat 5 minutes. Dress with raw oil and a little balsamic vinegar.",ingredienti:[{nome:"Bietole",qt:"800g"},{nome:"Uvetta",qt:"40g"},{nome:"Pinoli",qt:"30g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Aceto balsamico",qt:"15ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Bietole con pinoli e uvetta (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:5,gs:1.5,g:9,z:8,ch:12,fi:5,ca:120,fe:3.5,mg:75,k2:680,na:250,zn:.8,fo:45,se:2,col:0}},{id:"tpl_1252",nome:"Cavolo rosso in umido alla tedesca",nome_en:"German-style braised red cabbage",categoria:"Contorno",porzioni:6,note:"Affettare il cavolo rosso. Soffriggere cipolla in strutto o burro. Aggiungere cavolo, mela a pezzi, aceto, zucchero e chiodi di garofano. Cuocere coperto 45 minuti. Il sapore deve essere agrodolce. Ottimo con maiale.",note_en:"Slice red cabbage. Sauté onion in lard or butter. Add cabbage, apple pieces, vinegar, sugar and cloves. Cook covered 45 minutes. Flavour should be sweet-sour. Excellent with pork.",ingredienti:[{nome:"Cavolo rosso",qt:"800g"},{nome:"Mela",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Aceto di vino",qt:"50ml"},{nome:"Zucchero",qt:"30g"},{nome:"Chiodi di garofano",qt:"3"},{nome:"Burro",qt:"30g"}],_dbEntry:{n:"Cavolo rosso in umido alla tedesca (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:2,gs:2,g:4,z:12,ch:18,fi:5,ca:65,fe:1,mg:22,k2:380,na:60,zn:.3,fo:25,se:1,col:10}},{id:"tpl_1253",nome:"Barbabietole al forno con balsamico",nome_en:"Oven-roasted beetroot with balsamic",categoria:"Contorno",porzioni:4,note:"Avvolgere le barbabietole intere in carta stagnola con timo e olio. Cuocere in forno a 200 C per 60 minuti. Pelare mentre ancora calde. Tagliare a spicchi. Condire con aceto balsamico, olio e semi di finocchio.",note_en:"Wrap whole beetroots in foil with thyme and oil. Bake at 200 C for 60 minutes. Peel while still hot. Cut into wedges. Dress with balsamic vinegar, oil and fennel seeds.",ingredienti:[{nome:"Barbabietole",qt:"600g"},{nome:"Timo",qt:"3 rametti"},{nome:"Aceto balsamico",qt:"25ml"},{nome:"Semi di finocchio",qt:"5g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Barbabietole al forno con balsamico (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:1,g:5,z:8,ch:14,fi:3.5,ca:25,fe:1,mg:22,k2:380,na:80,zn:.5,fo:95,se:1,col:0}},{id:"tpl_1254",nome:"Crocchette di patate al forno",nome_en:"Baked potato croquettes",categoria:"Contorno",porzioni:4,note:"Preparare pure di patate denso con burro, parmigiano e tuorlo. Formare le crocchette. Passare in uovo sbattuto e pangrattato. Cuocere in forno a 200 C per 20-25 minuti fino a doratura. Piu leggere delle versioni fritte.",note_en:"Make thick mash with butter, parmesan and egg yolk. Shape croquettes. Coat in beaten egg and breadcrumbs. Bake at 200 C for 20-25 minutes until golden. Lighter than fried versions.",ingredienti:[{nome:"Patate",qt:"700g"},{nome:"Parmigiano",qt:"60g"},{nome:"Burro",qt:"30g"},{nome:"Tuorli",qt:"2"},{nome:"Uovo intero",qt:"1"},{nome:"Pangrattato",qt:"80g"}],_dbEntry:{n:"Crocchette di patate al forno (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:8,gs:4,g:9,z:2,ch:32,fi:2.5,ca:110,fe:1.2,mg:22,k2:420,na:220,zn:1,fo:18,se:5,col:90}},{id:"tpl_1255",nome:"Ratatouille provenzale",nome_en:"Provençal ratatouille",categoria:"Contorno",porzioni:6,note:"Soffriggere cipolla e aglio. Aggiungere a strati zucchine, melanzane e peperoni a cubetti. Aggiungere pomodori, timo, origano e basilico. Cuocere coperto 30 minuti poi scoperto 15. Ottima calda o fredda.",note_en:"Sauté onion and garlic. Add diced courgettes, aubergines and peppers in layers. Add tomatoes, thyme, oregano and basil. Cook covered 30 minutes then uncovered 15. Excellent hot or cold.",ingredienti:[{nome:"Zucchine",qt:"300g"},{nome:"Melanzane",qt:"300g"},{nome:"Peperoni",qt:"2"},{nome:"Pomodori maturi",qt:"400g"},{nome:"Cipolla",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Timo",qt:"3 rametti"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Ratatouille provenzale (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:1.5,g:8,z:7,ch:8,fi:4.5,ca:30,fe:1,mg:28,k2:480,na:15,zn:.4,fo:38,se:1.5,col:0}},{id:"tpl_1256",nome:"Purè di cavolfiore",nome_en:"Cauliflower mash",categoria:"Contorno",porzioni:4,note:"Lessare il cavolfiore a cimette finche tenerissimo. Frullare con burro, latte caldo, parmigiano e noce moscata. Il risultato e simile al pure di patate ma piu leggero. Servire con erba cipollina e olio crudo.",note_en:"Boil cauliflower florets until very tender. Blend with butter, hot milk, parmesan and nutmeg. Result is similar to mashed potato but lighter. Serve with chives and raw oil.",ingredienti:[{nome:"Cavolfiore",qt:"800g"},{nome:"Burro",qt:"30g"},{nome:"Latte",qt:"80ml"},{nome:"Parmigiano",qt:"40g"},{nome:"Noce moscata",qt:"q.b."},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Pure di cavolfiore (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:6,gs:3,g:6,z:4,ch:8,fi:4,ca:100,fe:.8,mg:22,k2:380,na:150,zn:.8,fo:60,se:3,col:18}},{id:"tpl_1257",nome:"Edamame al sale e sesamo",nome_en:"Edamame with salt and sesame",categoria:"Contorno",porzioni:4,note:"Cuocere gli edamame in acqua salata 5 minuti. Scolare. Cospargere con sale marino in fiocchi, semi di sesamo tostati e poche gocce di olio di sesamo. Mangiare direttamente dal baccello. Snack proteico ottimale.",note_en:"Cook edamame in salted water 5 minutes. Drain. Sprinkle with sea salt flakes, toasted sesame seeds and a few drops of sesame oil. Eat directly from pod. Optimal protein snack.",ingredienti:[{nome:"Edamame surgelati",qt:"400g"},{nome:"Sale marino in fiocchi",qt:"q.b."},{nome:"Semi di sesamo tostati",qt:"20g"},{nome:"Olio di sesamo",qt:"10ml"}],_dbEntry:{n:"Edamame al sale e sesamo (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:12,gs:1,g:6,z:2,ch:10,fi:6,ca:55,fe:2.5,mg:55,k2:380,na:200,zn:1.5,fo:180,se:3,col:0}},{id:"tpl_1258",nome:"Cavolfiore arrosto con curcuma e ceci",nome_en:"Roasted cauliflower with turmeric and chickpeas",categoria:"Contorno",porzioni:4,note:"Tagliare il cavolfiore a fette spesse. Mescolare con ceci lessati, curcuma, paprika, olio e sale. Cuocere in forno a 220 C per 30 minuti. Servire con yogurt al limone e coriandolo fresco.",note_en:"Cut cauliflower into thick slices. Mix with boiled chickpeas, turmeric, paprika, oil and salt. Bake at 220 C for 30 minutes. Serve with lemon yogurt and fresh coriander.",ingredienti:[{nome:"Cavolfiore",qt:"600g"},{nome:"Ceci cotti",qt:"200g"},{nome:"Curcuma",qt:"1.5 cucchiaini"},{nome:"Paprika",qt:"1 cucchiaino"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cavolfiore arrosto con curcuma e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:9,gs:1.5,g:9,z:4,ch:22,fi:7.5,ca:70,fe:2.5,mg:45,k2:580,na:200,zn:1.5,fo:110,se:4,col:2}},{id:"tpl_1259",nome:"Polenta taragna con funghi",nome_en:"Taragna polenta with mushrooms",categoria:"Contorno",porzioni:4,note:"Preparare la polenta taragna (mix farina gialla e grano saraceno) in acqua salata 40 minuti mescolando continuamente. Aggiungere burro e taleggio. Servire con funghi porcini trifolati in aglio e prezzemolo.",note_en:"Prepare taragna polenta (yellow flour and buckwheat mix) in salted water 40 minutes stirring continuously. Add butter and taleggio. Serve with porcini mushrooms sautéed with garlic and parsley.",ingredienti:[{nome:"Farina per polenta taragna",qt:"250g"},{nome:"Funghi porcini",qt:"300g"},{nome:"Taleggio",qt:"100g"},{nome:"Burro",qt:"50g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Polenta taragna con funghi (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:10,gs:7,g:14,z:1,ch:40,fi:3,ca:120,fe:2,mg:35,k2:380,na:320,zn:1.5,fo:18,se:5,col:35}},{id:"tpl_1260",nome:"Scarola saltata all'aglio e acciughe",nome_en:"Sautéed escarole with garlic and anchovies",categoria:"Contorno",porzioni:4,note:"Lessare la scarola tagliata in acqua salata 5 minuti. Soffriggere aglio, acciughe e peperoncino in olio finche le acciughe si sciolgono. Aggiungere la scarola strizzata. Saltare 5 minuti. Aggiustare di sale.",note_en:"Boil chopped escarole in salted water 5 minutes. Sauté garlic, anchovies and chilli in oil until anchovies dissolve. Add squeezed escarole. Sauté 5 minutes. Season with salt.",ingredienti:[{nome:"Scarola",qt:"800g"},{nome:"Acciughe sott olio",qt:"5"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Olive nere",qt:"40g"},{nome:"Capperi",qt:"20g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Scarola saltata all aglio e acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:4.5,gs:1.5,g:8,z:1,ch:4,fi:5,ca:90,fe:2,mg:35,k2:380,na:420,zn:.8,fo:58,se:5,col:8}},{id:"tpl_1261",nome:"Crostini con fegatini di pollo",nome_en:"Chicken liver crostini",categoria:"Antipasto",porzioni:6,note:"Rosolare cipolla e salvia in burro. Aggiungere i fegatini puliti. Sfumare con Marsala. Cuocere 10 minuti. Frullare grossolanamente aggiungendo burro. Tostare il pane toscano e spalmare il paté. Tipico antipasto toscano.",note_en:"Sauté onion and sage in butter. Add cleaned chicken livers. Deglaze with Marsala. Cook 10 minutes. Blend roughly adding butter. Toast Tuscan bread and spread pâté. Typical Tuscan starter.",ingredienti:[{nome:"Fegatini di pollo",qt:"300g"},{nome:"Pane toscano sciocco",qt:"8 fette"},{nome:"Cipolla",qt:"1"},{nome:"Salvia",qt:"6 foglie"},{nome:"Marsala",qt:"80ml"},{nome:"Burro",qt:"60g"}],_dbEntry:{n:"Crostini con fegatini di pollo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:5,g:10,z:3,ch:20,fi:1,ca:40,fe:8,mg:22,k2:280,na:220,zn:2.5,fo:220,se:30,col:230}},{id:"tpl_1262",nome:"Arancini di riso siciliani",nome_en:"Sicilian rice arancini",categoria:"Antipasto",porzioni:8,note:"Preparare riso con zafferano. Raffreddare. Formare palline con al centro ragu e piselli. Passare in uovo e pangrattato. Friggere in olio profondo a 180 C fino a doratura. Scolare e servire caldi.",note_en:"Cook rice with saffron. Cool. Shape balls with ragu and peas inside. Coat with egg and breadcrumbs. Deep-fry in oil at 180 C until golden. Drain and serve hot.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Macinato di manzo",qt:"150g"},{nome:"Piselli",qt:"100g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Parmigiano",qt:"60g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Olio per friggere",qt:"500ml"}],_dbEntry:{n:"Arancini di riso siciliani (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:14,gs:5,g:16,z:2,ch:48,fi:2,ca:80,fe:2,mg:28,k2:250,na:320,zn:2,fo:28,se:12,col:75}},{id:"tpl_1263",nome:"Frittelle di baccalà",nome_en:"Salt cod fritters",categoria:"Antipasto",porzioni:6,note:"Dissalare il baccalà. Lessare e sminuzzare. Mescolare con pastella di farina, acqua, prezzemolo, aglio e pepe. Friggere cucchiaiate in olio a 170 C finche dorate. Servire con salsa aioli o maionese al limone.",note_en:"Desalt cod. Boil and flake. Mix with batter of flour, water, parsley, garlic and pepper. Fry spoonfuls in oil at 170 C until golden. Serve with aioli or lemon mayonnaise.",ingredienti:[{nome:"Baccalà ammollato",qt:"400g"},{nome:"Farina",qt:"100g"},{nome:"Acqua",qt:"120ml"},{nome:"Prezzemolo",qt:"20g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio per friggere",qt:"400ml"}],_dbEntry:{n:"Frittelle di baccala (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:16,gs:2,g:10,z:.5,ch:16,fi:.5,ca:30,fe:.8,mg:28,k2:320,na:380,zn:.8,fo:10,se:28,col:45}},{id:"tpl_1264",nome:"Prosciutto crudo con fichi freschi",nome_en:"Cured ham with fresh figs",categoria:"Antipasto",porzioni:4,note:"Disporre le fette di prosciutto crudo DOP su piatto da portata. Accompagnare con fichi freschi tagliati a meta. Il contrasto dolce-salato e perfetto. Completare con rucola, grana a scaglie e olio extravergine.",note_en:"Arrange DOP cured ham slices on serving plate. Accompany with halved fresh figs. Sweet-salt contrast is perfect. Complete with rocket, grana shavings and extra virgin oil.",ingredienti:[{nome:"Prosciutto crudo DOP",qt:"200g"},{nome:"Fichi freschi",qt:"8"},{nome:"Rucola",qt:"60g"},{nome:"Grana Padano a scaglie",qt:"40g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Prosciutto crudo con fichi freschi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:16,gs:3,g:9,z:12,ch:18,fi:2.5,ca:80,fe:1,mg:20,k2:320,na:780,zn:1.5,fo:12,se:12,col:40}},{id:"tpl_1265",nome:"Bruschetta con porcini e tartufo nero",nome_en:"Bruschetta with porcini and black truffle",categoria:"Antipasto",porzioni:4,note:"Trifolite i porcini freschi con aglio e prezzemolo. Tostare il pane casereccio. Strofinare con aglio. Disporre i funghi sul pane. Aggiungere scaglie di tartufo nero o poco olio al tartufo. Piatto nobile e aromatico.",note_en:"Sauté fresh porcini with garlic and parsley. Toast country bread. Rub with garlic. Place mushrooms on bread. Add black truffle shavings or a little truffle oil. Noble and aromatic dish.",ingredienti:[{nome:"Funghi porcini freschi",qt:"300g"},{nome:"Pane casereccio",qt:"4 fette"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Olio al tartufo nero",qt:"20ml"},{nome:"Tartufo nero",qt:"20g"}],_dbEntry:{n:"Bruschetta con porcini e tartufo nero (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:6,gs:1.5,g:8,z:2,ch:25,fi:3,ca:25,fe:2,mg:22,k2:380,na:180,zn:1,fo:22,se:6,col:0}},{id:"tpl_1266",nome:"Torta della nonna",nome_en:"Grandmother's cream pie",categoria:"Dolce",porzioni:8,note:"Preparare pasta frolla e crema pasticciera. Foderare una teglia con meta della frolla. Versare la crema. Coprire con la restante frolla. Cospargere con pinoli. Cuocere a 180 C per 35 minuti. Spolverare con zucchero a velo.",note_en:"Make shortcrust pastry and custard cream. Line baking tin with half the pastry. Pour in cream. Cover with remaining pastry. Sprinkle with pine nuts. Bake at 180 C for 35 minutes. Dust with icing sugar.",ingredienti:[{nome:"Farina",qt:"300g"},{nome:"Burro",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Latte",qt:"300ml"},{nome:"Amido di mais",qt:"40g"},{nome:"Pinoli",qt:"50g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Torta della nonna (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:8,gs:8,g:16,z:26,ch:50,fi:1,ca:90,fe:1.2,mg:20,k2:160,na:120,zn:.8,fo:20,se:5,col:130}},{id:"tpl_1267",nome:"Zabaione caldo con savoiardi",nome_en:"Warm zabaglione with ladyfingers",categoria:"Dolce",porzioni:4,note:"Sbattere i tuorli con lo zucchero finche chiari. Aggiungere il Marsala. Cuocere a bagno maria montando continuamente fino a raddoppio del volume. Servire subito in coppa con savoiardi per intingere.",note_en:"Whisk egg yolks with sugar until pale. Add Marsala. Cook over double boiler whisking continuously until doubled in volume. Serve immediately in glass with ladyfingers for dipping.",ingredienti:[{nome:"Tuorli",qt:"4"},{nome:"Zucchero",qt:"60g"},{nome:"Marsala secco",qt:"80ml"},{nome:"Savoiardi",qt:"100g"}],_dbEntry:{n:"Zabaione caldo con savoiardi (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:2.5,g:7,z:25,ch:38,fi:.2,ca:35,fe:1.2,mg:12,k2:120,na:50,zn:.8,fo:25,se:10,col:205}},{id:"tpl_1268",nome:"Creme brulée alla vaniglia",nome_en:"Vanilla crème brûlée",categoria:"Dolce",porzioni:6,note:"Scaldare panna con vaniglia. Sbattere tuorli con zucchero. Temperare con la panna calda. Versare nei ramequin. Cuocere a bagno maria in forno a 150 C per 40 minuti. Raffreddare. Cospargere con zucchero e caramellare con cannello.",note_en:"Heat cream with vanilla. Whisk egg yolks with sugar. Temper with hot cream. Pour into ramekins. Bake in water bath at 150 C for 40 minutes. Cool. Sprinkle with sugar and caramelise with blowtorch.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Tuorli",qt:"5"},{nome:"Zucchero",qt:"80g"},{nome:"Zucchero di canna (per caramellare)",qt:"60g"},{nome:"Baccello di vaniglia",qt:"2"}],_dbEntry:{n:"Creme brulee alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:4.5,gs:14,g:22,z:22,ch:25,fi:0,ca:70,fe:.5,mg:8,k2:100,na:30,zn:.5,fo:12,se:3,col:220}},{id:"tpl_1269",nome:"Budino di riso al forno",nome_en:"Baked rice pudding",categoria:"Dolce",porzioni:6,note:"Cuocere il riso nel latte con zucchero, scorza di limone e cannella 20 minuti. Aggiungere uova sbattute. Versare in stampo imburrato. Cuocere in forno a 180 C per 30 minuti finche dorato. Ottimo tiepido.",note_en:"Cook rice in milk with sugar, lemon zest and cinnamon 20 minutes. Add beaten eggs. Pour into buttered mould. Bake at 180 C for 30 minutes until golden. Excellent warm.",ingredienti:[{nome:"Riso",qt:"150g"},{nome:"Latte intero",qt:"700ml"},{nome:"Zucchero",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Burro",qt:"20g"},{nome:"Limone",qt:"1"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Budino di riso al forno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:8,gs:4,g:7,z:18,ch:40,fi:.3,ca:150,fe:.8,mg:20,k2:280,na:90,zn:.8,fo:20,se:6,col:80}},{id:"tpl_1270",nome:"Macedonia di frutta con menta e limone",nome_en:"Fruit salad with mint and lemon",categoria:"Dolce",porzioni:6,note:"Tagliare la frutta di stagione a pezzi uniformi. Condire con succo di limone, zucchero a velo e foglioline di menta fresca. Mescolare delicatamente. Lasciare riposare 15 minuti. Servire fredda. Leggera e vitaminica.",note_en:"Cut seasonal fruit into uniform pieces. Dress with lemon juice, icing sugar and fresh mint leaves. Mix gently. Rest 15 minutes. Serve cold. Light and vitamin-rich.",ingredienti:[{nome:"Frutta mista di stagione",qt:"1kg"},{nome:"Limone",qt:"1"},{nome:"Zucchero a velo",qt:"20g"},{nome:"Menta fresca",qt:"10g"}],_dbEntry:{n:"Macedonia di frutta con menta e limone (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1,gs:0,g:.3,z:16,ch:20,fi:3,ca:25,fe:.5,mg:15,k2:320,na:5,zn:.2,fo:22,se:1,col:0}},{id:"tpl_1271",nome:"Muffin ai mirtilli e fiocchi d'avena",nome_en:"Blueberry and oat muffins",categoria:"Colazione",porzioni:12,note:"Mescolare farina integrale, fiocchi di avena, lievito e sale. A parte sbattere uova, olio, miele e yogurt. Unire liquidi ai solidi. Incorporare i mirtilli. Versare nei pirottini. Cuocere a 180 C per 20-22 minuti.",note_en:"Mix wholemeal flour, oats, baking powder and salt. Separately beat eggs, oil, honey and yogurt. Combine wet and dry ingredients. Fold in blueberries. Pour into cases. Bake at 180 C for 20-22 minutes.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Fiocchi di avena",qt:"60g"},{nome:"Mirtilli",qt:"150g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60ml"},{nome:"Lievito",qt:"10g"}],_dbEntry:{n:"Muffin ai mirtilli e fiocchi d avena (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:5,gs:1,g:6,z:10,ch:26,fi:3,ca:40,fe:1.2,mg:25,k2:150,na:80,zn:.8,fo:15,se:5,col:30}},{id:"tpl_1272",nome:"Pancakes integrali con frutti di bosco",nome_en:"Wholegrain pancakes with berries",categoria:"Colazione",porzioni:4,note:"Mescolare farina integrale, farina di avena, lievito, bicarbonato e sale. Sbattere uova, latte, yogurt e olio. Unire. Cuocere in padella antiaderente calda, 2 minuti per lato. Servire con frutti di bosco freschi e sciroppo d'acero.",note_en:"Mix wholemeal flour, oat flour, baking powder, bicarbonate and salt. Beat eggs, milk, yogurt and oil. Combine. Cook in hot non-stick pan, 2 minutes per side. Serve with fresh berries and maple syrup.",ingredienti:[{nome:"Farina integrale",qt:"100g"},{nome:"Farina di avena",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"200ml"},{nome:"Yogurt",qt:"80g"},{nome:"Frutti di bosco",qt:"150g"},{nome:"Sciroppo d acero",qt:"30ml"}],_dbEntry:{n:"Pancakes integrali con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:11,gs:2,g:7,z:14,ch:42,fi:5,ca:120,fe:2.5,mg:40,k2:320,na:200,zn:1.5,fo:35,se:8,col:90}},{id:"tpl_1273",nome:"Barrette di cereali e frutta secca fatte in casa",nome_en:"Homemade cereal and nut bars",categoria:"Spuntino",porzioni:12,note:"Scaldare miele con burro di arachidi. Mescolare con fiocchi di avena, riso soffiato, frutta secca tritata e semi. Versare in teglia rivestita di carta forno. Compattare bene. Congelare 1 ora. Tagliare a barrette.",note_en:"Heat honey with peanut butter. Mix with oats, puffed rice, chopped nuts and seeds. Pour into parchment-lined tin. Press down firmly. Freeze 1 hour. Cut into bars.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Riso soffiato",qt:"60g"},{nome:"Frutta secca mista",qt:"100g"},{nome:"Semi misti",qt:"50g"},{nome:"Miele",qt:"80ml"},{nome:"Burro di arachidi",qt:"80g"}],_dbEntry:{n:"Barrette di cereali e frutta secca fatte in casa (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5.5,gs:2,g:9,z:12,ch:26,fi:3,ca:35,fe:1.5,mg:42,k2:200,na:20,zn:1,fo:12,se:4,col:0}},{id:"tpl_1274",nome:"Kefir con semi di chia e frutta secca",nome_en:"Kefir with chia seeds and dried fruit",categoria:"Colazione",porzioni:2,note:"Versare il kefir in ciotola. Aggiungere semi di chia e lasciare riposare 10 minuti. Aggiungere frutta secca ammollata, granola e cannella. Il kefir apporta probiotici, i semi omega-3. Colazione completa e funzionale.",note_en:"Pour kefir into bowl. Add chia seeds and rest 10 minutes. Add soaked dried fruit, granola and cinnamon. Kefir provides probiotics, seeds provide omega-3. Complete functional breakfast.",ingredienti:[{nome:"Kefir intero",qt:"300ml"},{nome:"Semi di chia",qt:"20g"},{nome:"Albicocche secche",qt:"40g"},{nome:"Prugne secche",qt:"30g"},{nome:"Granola",qt:"30g"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Kefir con semi di chia e frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:12,gs:2,g:7,z:22,ch:44,fi:8,ca:280,fe:2.5,mg:55,k2:580,na:100,zn:1.5,fo:18,se:5,col:12}},{id:"tpl_1275",nome:"Mini frittate al forno in stampini muffin",nome_en:"Mini baked frittatas in muffin tin",categoria:"Spuntino",porzioni:12,note:"Sbattere le uova con latte, sale e pepe. Aggiungere verdure a dadini (peperoni, spinaci, pomodorini) e formaggio. Versare nei stampini muffin oliati. Cuocere a 180 C per 18-20 minuti. Si conservano in frigorifero 3 giorni.",note_en:"Beat eggs with milk, salt and pepper. Add diced vegetables (peppers, spinach, cherry tomatoes) and cheese. Pour into oiled muffin tin. Bake at 180 C for 18-20 minutes. Store in fridge 3 days.",ingredienti:[{nome:"Uova",qt:"8"},{nome:"Latte",qt:"80ml"},{nome:"Peperoni",qt:"1"},{nome:"Spinaci",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Feta o ricotta",qt:"80g"},{nome:"Erba cipollina",qt:"15g"}],_dbEntry:{n:"Mini frittate al forno in stampini muffin (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:8.5,gs:2.5,g:6.5,z:2,ch:3,fi:1,ca:80,fe:1.5,mg:18,k2:200,na:200,zn:1,fo:28,se:15,col:190}},{id:"tpl_1276",nome:"Coniglio alla cacciatora",nome_en:"Hunter-style rabbit",categoria:"Secondo piatto",porzioni:4,note:"Rosolare il coniglio a pezzi in olio. Aggiungere cipolla, aglio, pomodori pelati, vino rosso, rosmarino e timo. Cuocere coperto 50 minuti. Scoprire e restringere il sugo 10 minuti. Servire con polenta o patate.",note_en:"Brown rabbit pieces in oil. Add onion, garlic, peeled tomatoes, red wine, rosemary and thyme. Cook covered 50 minutes. Uncover and reduce sauce 10 minutes. Serve with polenta or potatoes.",ingredienti:[{nome:"Coniglio",qt:"1.2kg"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino rosso",qt:"150ml"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Timo",qt:"3 rametti"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Coniglio alla cacciatora (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:34,gs:3,g:12,z:4,ch:6,fi:2,ca:35,fe:2.5,mg:40,k2:580,na:350,zn:3.5,fo:20,se:22,col:90}},{id:"tpl_1277",nome:"Petto d'anatra con salsa al mirtillo",nome_en:"Duck breast with blueberry sauce",categoria:"Secondo piatto",porzioni:4,note:"Incidere la pelle dell'anatra a rombi. Cuocere dalla parte della pelle in padella a fuoco medio 8 minuti, poi girare 5 minuti. Lasciare riposare. In una casseruola cuocere mirtilli, porto, miele e brodo per la salsa.",note_en:"Score duck skin in diamonds. Cook skin-side down in pan on medium heat 8 minutes, then turn 5 minutes. Rest. In saucepan cook blueberries, port, honey and stock for sauce.",ingredienti:[{nome:"Petto d anatra",qt:"600g"},{nome:"Mirtilli",qt:"150g"},{nome:"Vino Porto",qt:"80ml"},{nome:"Miele",qt:"20ml"},{nome:"Brodo di pollo",qt:"100ml"}],_dbEntry:{n:"Petto d anatra con salsa al mirtillo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:32,gs:6,g:20,z:10,ch:12,fi:1.5,ca:25,fe:3,mg:35,k2:480,na:200,zn:3.5,fo:15,se:22,col:130}},{id:"tpl_1278",nome:"Quaglie al forno con uva e vin santo",nome_en:"Baked quail with grapes and Vin Santo",categoria:"Secondo piatto",porzioni:4,note:"Farcire le quaglie con spicchi d'aglio e salvia. Rosolare in burro e olio. Aggiungere uva nera intera e Vin Santo. Cuocere in forno a 190 C per 25 minuti. Ottimo con polenta morbida.",note_en:"Fill quails with garlic cloves and sage. Brown in butter and oil. Add whole black grapes and Vin Santo. Bake at 190 C for 25 minutes. Excellent with soft polenta.",ingredienti:[{nome:"Quaglie",qt:"4"},{nome:"Uva nera",qt:"200g"},{nome:"Vin Santo",qt:"100ml"},{nome:"Burro",qt:"30g"},{nome:"Salvia",qt:"8 foglie"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Quaglie al forno con uva e vin santo (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:30,gs:5,g:16,z:10,ch:10,fi:.8,ca:35,fe:3.5,mg:28,k2:450,na:200,zn:3,fo:12,se:18,col:115}},{id:"tpl_1279",nome:"Lonza di maiale con finocchio e arance",nome_en:"Pork loin with fennel and oranges",categoria:"Secondo piatto",porzioni:4,note:"Marinare la lonza con succo d'arancia, scorza, finocchietto, aglio e olio per 2 ore. Rosolare in padella. Aggiungere finocchio a spicchi e la marinatura. Cuocere coperto 40 minuti. Fresco e profumato.",note_en:"Marinate pork loin with orange juice, zest, fennel fronds, garlic and oil for 2 hours. Brown in pan. Add fennel wedges and marinade. Cook covered 40 minutes. Fresh and fragrant.",ingredienti:[{nome:"Lonza di maiale",qt:"700g"},{nome:"Finocchio",qt:"2"},{nome:"Arance",qt:"2"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Finocchietto",qt:"15g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Lonza di maiale con finocchio e arance (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:32,gs:3,g:12,z:6,ch:10,fi:3.5,ca:55,fe:1.5,mg:35,k2:620,na:180,zn:3,fo:30,se:28,col:90}},{id:"tpl_1280",nome:"Petto di pollo con crosta di pistacchi",nome_en:"Chicken breast with pistachio crust",categoria:"Secondo piatto",porzioni:4,note:"Tritare i pistacchi con pangrattato, prezzemolo e scorza di limone. Spalmare senape sui petti di pollo. Impanare con il composto ai pistacchi. Cuocere in forno a 200 C per 20 minuti. Elegante e nutriente.",note_en:"Chop pistachios with breadcrumbs, parsley and lemon zest. Spread mustard on chicken breasts. Coat with pistachio mix. Bake at 200 C for 20 minutes. Elegant and nutritious.",ingredienti:[{nome:"Petto di pollo",qt:"600g"},{nome:"Pistacchi non salati",qt:"80g"},{nome:"Pangrattato",qt:"40g"},{nome:"Senape di Digione",qt:"30g"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Petto di pollo con crosta di pistacchi (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:36,gs:2.5,g:13,z:2,ch:10,fi:2,ca:40,fe:2,mg:55,k2:580,na:320,zn:2.5,fo:22,se:28,col:85}},{id:"tpl_1281",nome:"Zuppa di vongole alla napoletana",nome_en:"Neapolitan clam soup",categoria:"Secondo piatto",porzioni:4,note:"Lasciare spurgare le vongole in acqua salata 2 ore. Soffriggere aglio in olio. Aggiungere le vongole con vino bianco. Cuocere coperto 5 minuti. Aggiungere pomodorini e prezzemolo. Servire con pane tostato.",note_en:"Soak clams in salted water 2 hours to purge. Sauté garlic in oil. Add clams with white wine. Cook covered 5 minutes. Add cherry tomatoes and parsley. Serve with toasted bread.",ingredienti:[{nome:"Vongole",qt:"1.5kg"},{nome:"Pomodorini",qt:"200g"},{nome:"Aglio",qt:"4 spicchi"},{nome:"Vino bianco",qt:"150ml"},{nome:"Prezzemolo",qt:"30g"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Pane tostato",qt:"4 fette"}],_dbEntry:{n:"Zuppa di vongole alla napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1.5,g:10,z:3,ch:10,fi:1.5,ca:80,fe:12,mg:55,k2:500,na:580,zn:2.5,fo:22,se:30,col:50}},{id:"tpl_1282",nome:"Salmone al cartoccio con limone e aneto",nome_en:"Salmon en papillote with lemon and dill",categoria:"Secondo piatto",porzioni:4,note:"Posizionare il filetto di salmone su carta da forno. Condire con olio, succo di limone, scorza, aneto e fettine di cipolla. Chiudere il cartoccio ermeticamente. Cuocere in forno a 190 C per 18 minuti.",note_en:"Place salmon fillet on parchment paper. Season with oil, lemon juice, zest, dill and onion slices. Seal parcel tightly. Bake at 190 C for 18 minutes.",ingredienti:[{nome:"Filetto di salmone",qt:"700g"},{nome:"Limone",qt:"2"},{nome:"Aneto fresco",qt:"25g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Salmone al cartoccio con limone e aneto (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:32,gs:3.5,g:15,z:2,ch:3,fi:.5,ca:30,fe:1,mg:42,k2:600,na:180,zn:1,fo:22,se:48,col:90}},{id:"tpl_1283",nome:"Alici fritte dorate",nome_en:"Golden fried anchovies",categoria:"Secondo piatto",porzioni:4,note:"Pulire le alici togliendo testa e lisca. Infarinare e scrollare la farina in eccesso. Friggere in olio a 180 C per 2-3 minuti finche dorate. Scolare su carta assorbente. Salare e servire con limone.",note_en:"Clean anchovies removing head and backbone. Flour and shake off excess. Fry in oil at 180 C for 2-3 minutes until golden. Drain on paper. Salt and serve with lemon.",ingredienti:[{nome:"Alici fresche",qt:"600g"},{nome:"Farina",qt:"80g"},{nome:"Olio per friggere",qt:"400ml"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Alici fritte dorate (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:24,gs:3,g:14,z:.5,ch:10,fi:.3,ca:180,fe:3,mg:38,k2:380,na:200,zn:1.5,fo:10,se:38,col:90}},{id:"tpl_1284",nome:"Rana pescatrice in salsa verde",nome_en:"Monkfish in green sauce",categoria:"Secondo piatto",porzioni:4,note:"Tagliare la rana pescatrice a tranci. Infarinare e rosolare in olio. Preparare salsa verde con prezzemolo, aglio, acciughe, capperi, cetriolini e olio. Nappare il pesce con la salsa e cuocere 10 minuti.",note_en:"Cut monkfish into steaks. Flour and brown in oil. Make green sauce with parsley, garlic, anchovies, capers, gherkins and oil. Coat fish with sauce and cook 10 minutes.",ingredienti:[{nome:"Rana pescatrice",qt:"800g"},{nome:"Prezzemolo",qt:"50g"},{nome:"Acciughe",qt:"4"},{nome:"Capperi",qt:"30g"},{nome:"Cetriolini",qt:"30g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Rana pescatrice in salsa verde (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:30,gs:2,g:12,z:1,ch:6,fi:.8,ca:40,fe:1.5,mg:45,k2:600,na:480,zn:1.5,fo:18,se:38,col:55}},{id:"tpl_1285",nome:"Fritto misto di paranza",nome_en:"Mixed small fish fry",categoria:"Secondo piatto",porzioni:4,note:"Pulire alici, gamberi piccoli, calamari e totanetti. Asciugare bene. Infarinare con semola di grano duro. Friggere in abbondante olio a 180-190 C pochi pezzi alla volta. Scolare e salare. Servire con limone.",note_en:"Clean anchovies, small prawns, squid and baby cuttlefish. Dry well. Coat with semolina flour. Fry in plenty of oil at 180-190 C in small batches. Drain and salt. Serve with lemon.",ingredienti:[{nome:"Alici fresche",qt:"200g"},{nome:"Gamberi piccoli",qt:"200g"},{nome:"Calamari piccoli",qt:"200g"},{nome:"Semola di grano duro",qt:"120g"},{nome:"Olio per friggere",qt:"600ml"},{nome:"Limone",qt:"2"}],_dbEntry:{n:"Fritto misto di paranza (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:28,gs:4,g:18,z:.5,ch:22,fi:.5,ca:120,fe:3,mg:42,k2:420,na:300,zn:2,fo:18,se:40,col:180}},{id:"tpl_1286",nome:"Fave fresche con pecorino e menta",nome_en:"Fresh broad beans with pecorino and mint",categoria:"Contorno",porzioni:4,note:"Sgranare le fave fresche. Sbollentare 2 minuti e pelare. Mescolare con pecorino a scaglie, foglie di menta fresca e olio extravergine. Condire con sale e pepe. Antipasto o contorno primaverile per eccellenza.",note_en:"Shell fresh broad beans. Blanch 2 minutes and peel. Mix with pecorino shavings, fresh mint leaves and extra virgin oil. Season with salt and pepper. The quintessential spring starter or side.",ingredienti:[{nome:"Fave fresche sgranate",qt:"500g"},{nome:"Pecorino a scaglie",qt:"80g"},{nome:"Menta fresca",qt:"10g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Fave fresche con pecorino e menta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:12,gs:3,g:9,z:2,ch:14,fi:7,ca:160,fe:2,mg:42,k2:420,na:320,zn:1.5,fo:100,se:3,col:15}},{id:"tpl_1287",nome:"Cous cous di verdure arrostite",nome_en:"Roasted vegetable couscous",categoria:"Contorno",porzioni:4,note:"Arrostire zucchine, peperoni, melanzane e cipolla in forno. Preparare il cous cous con brodo bollente e olio. Mescolare con le verdure arrostite, uvetta, mandorle tostate, prezzemolo e cumino.",note_en:"Roast courgettes, peppers, aubergines and onion in oven. Prepare couscous with boiling stock and oil. Mix with roasted vegetables, raisins, toasted almonds, parsley and cumin.",ingredienti:[{nome:"Cous cous",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"2"},{nome:"Melanzane",qt:"150g"},{nome:"Uvetta",qt:"30g"},{nome:"Mandorle tostate",qt:"40g"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cous cous di verdure arrostite (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:9,gs:1.5,g:12,z:8,ch:46,fi:6,ca:50,fe:2,mg:55,k2:480,na:180,zn:1,fo:45,se:5,col:0}},{id:"tpl_1288",nome:"Puntarelle alla romana con acciughe",nome_en:"Roman puntarelle with anchovies",categoria:"Contorno",porzioni:4,note:"Tagliare le puntarelle a listarelle e immergerle in acqua fredda con ghiaccio 30 minuti finche si arricciassero. Pestare acciughe con aglio e olio. Scolare le puntarelle e condire con la salsa di acciughe e aceto.",note_en:"Cut puntarelle into strips and soak in cold iced water 30 minutes until they curl. Pound anchovies with garlic and oil. Drain puntarelle and dress with anchovy sauce and vinegar.",ingredienti:[{nome:"Puntarelle",qt:"500g"},{nome:"Acciughe sott olio",qt:"6"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Aceto di vino",qt:"25ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Puntarelle alla romana con acciughe (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4.5,gs:1.5,g:8,z:1,ch:4,fi:5,ca:55,fe:2,mg:25,k2:350,na:350,zn:.5,fo:45,se:5,col:8}},{id:"tpl_1289",nome:"Patate al cartoccio con panna acida",nome_en:"Jacket potatoes with sour cream",categoria:"Contorno",porzioni:4,note:"Lavare bene le patate. Strofinarle con olio e sale grosso. Avvolgerle in carta stagnola. Cuocere in forno a 220 C per 60 minuti. Aprire e farcire con panna acida, erba cipollina e bacon croccante.",note_en:"Wash potatoes well. Rub with oil and coarse salt. Wrap in foil. Bake at 220 C for 60 minutes. Open and fill with sour cream, chives and crispy bacon.",ingredienti:[{nome:"Patate grandi",qt:"4"},{nome:"Panna acida",qt:"120g"},{nome:"Erba cipollina",qt:"15g"},{nome:"Bacon",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Patate al cartoccio con panna acida (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:8,gs:4,g:12,z:2,ch:40,fi:3.5,ca:55,fe:1.5,mg:38,k2:800,na:280,zn:.8,fo:30,se:3,col:25}},{id:"tpl_1290",nome:"Porri in padella con aceto balsamico",nome_en:"Leeks with balsamic vinegar",categoria:"Contorno",porzioni:4,note:"Tagliare i porri a rondelle spesse. Soffriggere in olio a fuoco medio 10 minuti finche morbidi. Sfumare con aceto balsamico. Aggiungere miele. Cuocere altri 5 minuti. Guarnire con timo e noci tritate.",note_en:"Cut leeks into thick rounds. Sauté in oil over medium heat 10 minutes until soft. Deglaze with balsamic vinegar. Add honey. Cook 5 more minutes. Garnish with thyme and chopped walnuts.",ingredienti:[{nome:"Porri",qt:"600g"},{nome:"Aceto balsamico",qt:"30ml"},{nome:"Miele",qt:"15ml"},{nome:"Timo",qt:"3 rametti"},{nome:"Noci",qt:"30g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Porri in padella con aceto balsamico (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3,gs:1.5,g:8,z:7,ch:12,fi:3.5,ca:60,fe:1.5,mg:22,k2:350,na:15,zn:.5,fo:45,se:2,col:0}},{id:"tpl_1291",nome:"Supplì romani al telefono",nome_en:"Roman suppli",categoria:"Antipasto",porzioni:8,note:"Preparare riso cotto nel sugo di carne con parmigiano. Raffreddare. Formare le palline con un pezzo di mozzarella al centro. Passare in uovo sbattuto e pangrattato. Friggere in olio a 180 C finche dorati.",note_en:"Make rice cooked in meat sauce with parmesan. Cool. Shape balls with a piece of mozzarella in centre. Coat in beaten egg and breadcrumbs. Fry in oil at 180 C until golden.",ingredienti:[{nome:"Riso",qt:"250g"},{nome:"Mozzarella",qt:"150g"},{nome:"Sugo di carne",qt:"200ml"},{nome:"Parmigiano",qt:"50g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Olio per friggere",qt:"500ml"}],_dbEntry:{n:"Suppli romani al telefono (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:11,gs:4,g:13,z:2,ch:36,fi:1,ca:120,fe:1.5,mg:22,k2:200,na:360,zn:1.5,fo:18,se:10,col:65}},{id:"tpl_1292",nome:"Bagna cauda piemontese",nome_en:"Piedmontese bagna cauda",categoria:"Antipasto",porzioni:6,note:"Sciogliere le acciughe in aglio e olio a fuoco bassissimo 15 minuti. Aggiungere burro a pezzetti e mescolare fino a crema. Mantenere calda. Servire con verdure crude e cotte: peperoni, sedano, cavolo, topinambur, cipolle.",note_en:"Melt anchovies in garlic and oil on very low heat 15 minutes. Add butter pieces and stir to cream. Keep warm. Serve with raw and cooked vegetables: peppers, celery, cabbage, Jerusalem artichoke, onions.",ingredienti:[{nome:"Acciughe sotto sale",qt:"150g"},{nome:"Aglio",qt:"8 spicchi"},{nome:"Olio extravergine",qt:"150ml"},{nome:"Burro",qt:"80g"},{nome:"Verdure miste per intingere",qt:"800g"}],_dbEntry:{n:"Bagna cauda piemontese (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:8,gs:6,g:20,z:5,ch:8,fi:4,ca:80,fe:1.5,mg:30,k2:450,na:600,zn:.8,fo:40,se:15,col:45}},{id:"tpl_1293",nome:"Gazpacho andaluso",nome_en:"Andalusian gazpacho",categoria:"Antipasto",porzioni:6,note:"Frullare pomodori maturi, cetriolo, peperone rosso, aglio, cipolla e pane raffermo imbevuto. Aggiungere olio, aceto e sale. Setacciare. Raffreddare almeno 2 ore. Servire con guarnizione di dadini di verdure e crostini.",note_en:"Blend ripe tomatoes, cucumber, red pepper, garlic, onion and soaked stale bread. Add oil, vinegar and salt. Strain. Refrigerate at least 2 hours. Serve garnished with diced vegetables and croutons.",ingredienti:[{nome:"Pomodori maturi",qt:"700g"},{nome:"Cetriolo",qt:"1"},{nome:"Peperone rosso",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Pane raffermo",qt:"60g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Aceto di vino bianco",qt:"30ml"}],_dbEntry:{n:"Gazpacho andaluso (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:2.5,gs:1.5,g:10,z:6,ch:8,fi:3,ca:25,fe:1,mg:22,k2:480,na:180,zn:.4,fo:30,se:2,col:0}},{id:"tpl_1294",nome:"Carpaccio di salmone con lime e zenzero",nome_en:"Salmon carpaccio with lime and ginger",categoria:"Antipasto",porzioni:4,note:"Affettare il salmone freschissimo sottilissimo. Disporre su piatto freddo. Marinare 5 minuti con succo di lime, scorza, zenzero grattugiato, olio di sesamo e cipollotto. Guarnire con sesamo e microgreens.",note_en:"Slice very fresh salmon paper-thin. Arrange on cold plate. Marinate 5 minutes with lime juice, zest, grated ginger, sesame oil and spring onion. Garnish with sesame and microgreens.",ingredienti:[{nome:"Salmone fresco filetto",qt:"400g"},{nome:"Lime",qt:"2"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Olio di sesamo",qt:"20ml"},{nome:"Cipollotto",qt:"2"},{nome:"Semi di sesamo",qt:"15g"}],_dbEntry:{n:"Carpaccio di salmone con lime e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:3,g:12,z:1,ch:2,fi:.3,ca:25,fe:.8,mg:38,k2:520,na:180,zn:.8,fo:20,se:42,col:70}},{id:"tpl_1295",nome:"Focaccia genovese all'olio",nome_en:"Genoese olive oil focaccia",categoria:"Antipasto",porzioni:8,note:"Impastare farina, acqua, lievito, olio e sale. Far lievitare 2 ore. Stendere nella teglia oleata. Fare le tipiche fossette con le dita. Spennellare con salamoia (acqua e sale). Aggiungere olio abbondante. Lievitare 30 min. Cuocere a 220 C per 20 min.",note_en:"Mix flour, water, yeast, oil and salt. Rise 2 hours. Spread in oiled tin. Make typical dimples with fingers. Brush with brine (water and salt). Add plenty of oil. Rise 30 min. Bake at 220 C for 20 min.",ingredienti:[{nome:"Farina 0",qt:"500g"},{nome:"Acqua",qt:"350ml"},{nome:"Lievito di birra",qt:"7g"},{nome:"Olio extravergine",qt:"80ml"},{nome:"Sale",qt:"12g"}],_dbEntry:{n:"Focaccia genovese all olio (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:6.5,gs:1.5,g:8,z:.5,ch:40,fi:1.5,ca:15,fe:1.5,mg:18,k2:120,na:380,zn:.6,fo:30,se:15,col:0}},{id:"tpl_1296",nome:"Insalata nizzarda",nome_en:"Niçoise salad",categoria:"Insalata",porzioni:4,note:"Comporre su piatto grande: lattuga, pomodori, uova sode, fagiolini lessati al dente, patate lesse, tonno, olive nere, acciughe e cetriolini. Condire con vinaigrette alla senape. Non mescolare: ogni elemento deve essere visibile.",note_en:"Compose on large plate: lettuce, tomatoes, hard-boiled eggs, al dente boiled green beans, boiled potatoes, tuna, black olives, anchovies and gherkins. Dress with mustard vinaigrette. Do not mix: each element must be visible.",ingredienti:[{nome:"Lattuga",qt:"1"},{nome:"Tonno sott olio",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Fagiolini",qt:"150g"},{nome:"Patate novelle",qt:"200g"},{nome:"Olive nere",qt:"60g"},{nome:"Acciughe",qt:"6"},{nome:"Senape",qt:"10g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata nizzarda (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:20,gs:3,g:16,z:3,ch:16,fi:4,ca:75,fe:3,mg:45,k2:620,na:680,zn:2,fo:60,se:28,col:165}},{id:"tpl_1297",nome:"Bowl di orzo con salmone affumicato",nome_en:"Barley bowl with smoked salmon",categoria:"Insalata",porzioni:4,note:"Cuocere l'orzo perlato. Raffreddare. Comporre le bowl con orzo, salmone affumicato a strisce, avocado a fette, cetriolo, ravanelli e rucola. Condire con crema di yogurt, aneto e limone.",note_en:"Cook pearl barley. Cool. Compose bowls with barley, smoked salmon strips, sliced avocado, cucumber, radishes and rocket. Dress with yogurt cream, dill and lemon.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Salmone affumicato",qt:"200g"},{nome:"Avocado",qt:"2"},{nome:"Cetriolo",qt:"1"},{nome:"Ravanelli",qt:"8"},{nome:"Yogurt greco",qt:"100g"},{nome:"Aneto",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Bowl di orzo con salmone affumicato (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:22,gs:3.5,g:16,z:3,ch:48,fi:6.5,ca:80,fe:2,mg:58,k2:680,na:680,zn:2,fo:55,se:30,col:30}},{id:"tpl_1298",nome:"Insalata di mare classica",nome_en:"Classic seafood salad",categoria:"Insalata",porzioni:6,note:"Lessare separatamente calamari, gamberi, cozze e vongole. Tagliare i calamari ad anelli. Condire tutto con olio extravergine, succo di limone, aglio, prezzemolo, sedano e peperoncino. Lasciare marinare 1 ora.",note_en:"Boil separately squid, prawns, mussels and clams. Cut squid into rings. Dress everything with extra virgin oil, lemon juice, garlic, parsley, celery and chilli. Marinate 1 hour.",ingredienti:[{nome:"Calamari",qt:"300g"},{nome:"Gamberi",qt:"300g"},{nome:"Cozze",qt:"400g"},{nome:"Vongole",qt:"300g"},{nome:"Sedano",qt:"2 coste"},{nome:"Limone",qt:"2"},{nome:"Prezzemolo",qt:"25g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Insalata di mare classica (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:26,gs:1.5,g:9,z:2,ch:6,fi:1,ca:100,fe:4,mg:55,k2:550,na:480,zn:3,fo:28,se:42,col:170}},{id:"tpl_1299",nome:"Poke bowl hawaiiano con tonno",nome_en:"Hawaiian tuna poke bowl",categoria:"Insalata",porzioni:2,note:"Tagliare il tonno freschissimo a cubetti. Marinare con soia, olio di sesamo, cipollotto e zenzero. Cuocere il riso per sushi. Comporre le bowl con riso, tonno marinato, avocado, edamame, cetriolo e alghe.",note_en:"Cut very fresh tuna into cubes. Marinate with soy, sesame oil, spring onion and ginger. Cook sushi rice. Compose bowls with rice, marinated tuna, avocado, edamame, cucumber and seaweed.",ingredienti:[{nome:"Tonno fresco",qt:"250g"},{nome:"Riso per sushi",qt:"200g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"80g"},{nome:"Cetriolo",qt:"0.5"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"15ml"},{nome:"Alghe nori",qt:"2 fogli"}],_dbEntry:{n:"Poke bowl hawaiiano con tonno (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:34,gs:3,g:16,z:3,ch:52,fi:7,ca:40,fe:2.5,mg:65,k2:750,na:720,zn:2,fo:55,se:72,col:48}},{id:"tpl_1300",nome:"Insalata tiepida di lenticchie e salsiccia",nome_en:"Warm lentil and sausage salad",categoria:"Insalata",porzioni:4,note:"Cuocere le lenticchie con alloro. Rosolare la salsiccia sbriciolata. Mescolare lenticchie calde con salsiccia, sedano, carota, cipolla rossa e senape. Condire con aceto di mele e olio. Servire tiepida.",note_en:"Cook lentils with bay leaf. Brown crumbled sausage. Mix warm lentils with sausage, celery, carrot, red onion and mustard. Dress with apple cider vinegar and oil. Serve warm.",ingredienti:[{nome:"Lenticchie verdi",qt:"250g"},{nome:"Salsiccia di maiale",qt:"200g"},{nome:"Sedano",qt:"2 coste"},{nome:"Carota",qt:"1"},{nome:"Cipolla rossa",qt:"1"},{nome:"Senape",qt:"15g"},{nome:"Aceto di mele",qt:"20ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata tiepida di lenticchie e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:22,gs:5,g:16,z:3,ch:32,fi:9,ca:55,fe:5,mg:62,k2:720,na:520,zn:3,fo:150,se:12,col:45}},{id:"tpl_1301",nome:"Ricotta al forno con miele e limone",nome_en:"Baked ricotta with honey and lemon",categoria:"Dolce",porzioni:6,note:"Mescolare ricotta con uova, zucchero, scorza di limone e vaniglia. Versare in teglia imburrata. Cuocere a 170 C per 35-40 minuti. Raffreddare e servire con miele, fichi freschi o frutti di bosco.",note_en:"Mix ricotta with eggs, sugar, lemon zest and vanilla. Pour into buttered tin. Bake at 170 C for 35-40 minutes. Cool and serve with honey, fresh figs or berries.",ingredienti:[{nome:"Ricotta fresca",qt:"500g"},{nome:"Uova",qt:"2"},{nome:"Zucchero",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Vaniglia",qt:"1 cucchiaino"},{nome:"Miele",qt:"40ml"},{nome:"Frutti di bosco",qt:"100g"}],_dbEntry:{n:"Ricotta al forno con miele e limone (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:11,gs:5,g:10,z:20,ch:26,fi:.3,ca:200,fe:.5,mg:18,k2:180,na:120,zn:1,fo:15,se:8,col:90}},{id:"tpl_1302",nome:"Ciambella allo yogurt",nome_en:"Yogurt ring cake",categoria:"Dolce",porzioni:8,note:"Usare il vasetto di yogurt come unità di misura. Mescolare yogurt, olio, uova, zucchero, farina, lievito e scorza di limone. Versare nello stampo a ciambella. Cuocere a 180 C per 35 minuti. La ciambella della tradizione italiana.",note_en:"Use yogurt pot as unit of measure. Mix yogurt, oil, eggs, sugar, flour, baking powder and lemon zest. Pour into ring mould. Bake at 180 C for 35 minutes. Italian tradition ring cake.",ingredienti:[{nome:"Yogurt intero",qt:"125g"},{nome:"Farina",qt:"250g"},{nome:"Zucchero",qt:"200g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito",qt:"16g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Ciambella allo yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5.5,gs:1.5,g:9,z:24,ch:44,fi:.8,ca:40,fe:1,mg:15,k2:120,na:80,zn:.5,fo:12,se:5,col:70}},{id:"tpl_1303",nome:"Cantuccini alle mandorle",nome_en:"Almond cantuccini biscotti",categoria:"Dolce",porzioni:20,note:"Impastare farina, zucchero, uova, mandorle intere non pelate, lievito e scorza d'arancia. Formare filoncini. Cuocere a 180 C per 25 minuti. Tagliare in diagonale e biscottare in forno a 150 C per 15 minuti. Ottimi inzuppati nel Vin Santo.",note_en:"Mix flour, sugar, eggs, whole unpeeled almonds, baking powder and orange zest. Shape into logs. Bake at 180 C for 25 minutes. Cut diagonally and dry in oven at 150 C for 15 minutes. Excellent dunked in Vin Santo.",ingredienti:[{nome:"Farina",qt:"300g"},{nome:"Zucchero",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Mandorle intere",qt:"200g"},{nome:"Lievito",qt:"8g"},{nome:"Arancia",qt:"1"}],_dbEntry:{n:"Cantuccini alle mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3.5,gs:.5,g:4.5,z:12,ch:18,fi:1,ca:25,fe:.8,mg:22,k2:100,na:30,zn:.5,fo:8,se:3,col:18}},{id:"tpl_1304",nome:"Panna cotta al caffè",nome_en:"Coffee panna cotta",categoria:"Dolce",porzioni:6,note:"Scaldare panna con zucchero e caffè espresso ristretto. Ammorbidire gelatina in acqua fredda. Sciogliere nella panna calda. Versare in bicchieri o stampini. Raffreddare 4 ore. Servire con salsa al cioccolato fondente.",note_en:"Heat cream with sugar and strong espresso. Soften gelatine in cold water. Dissolve in hot cream. Pour into glasses or moulds. Refrigerate 4 hours. Serve with dark chocolate sauce.",ingredienti:[{nome:"Panna fresca",qt:"500ml"},{nome:"Caffe espresso",qt:"80ml"},{nome:"Zucchero",qt:"70g"},{nome:"Gelatina in fogli",qt:"10g"},{nome:"Cioccolato fondente",qt:"60g"}],_dbEntry:{n:"Panna cotta al caffe (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:3,gs:13,g:20,z:16,ch:20,fi:.3,ca:75,fe:.5,mg:10,k2:120,na:30,zn:.3,fo:5,se:2,col:65}},{id:"tpl_1305",nome:"Frutta di stagione al forno con cannella",nome_en:"Seasonal baked fruit with cinnamon",categoria:"Dolce",porzioni:4,note:"Tagliare pesche, albicocche, fichi o mele a meta. Disporre in teglia. Cospargere con cannella, zucchero di canna, poche gocce di succo d'arancia. Cuocere a 180 C per 20-25 minuti. Servire con gelato alla vaniglia o yogurt.",note_en:"Halve peaches, apricots, figs or apples. Arrange in baking dish. Sprinkle with cinnamon, brown sugar, a few drops of orange juice. Bake at 180 C for 20-25 minutes. Serve with vanilla ice cream or yogurt.",ingredienti:[{nome:"Frutta mista di stagione",qt:"800g"},{nome:"Zucchero di canna",qt:"40g"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Arancia (succo)",qt:"0.5"},{nome:"Yogurt o gelato",qt:"150g"}],_dbEntry:{n:"Frutta di stagione al forno con cannella (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:.5,g:1.5,z:22,ch:30,fi:4,ca:35,fe:.5,mg:18,k2:350,na:20,zn:.3,fo:15,se:2,col:5}},{id:"tpl_1306",nome:"Golden milk latte con curcuma e zenzero",nome_en:"Turmeric and ginger golden milk latte",categoria:"Colazione",porzioni:2,note:"Scaldare il latte con curcuma, zenzero in polvere, cannella, pepe nero e miele. Non portare a ebollizione. Montare il latte con frullino. Versare in tazza. Il pepe nero esalta l'assorbimento della curcumina.",note_en:"Heat milk with turmeric, ground ginger, cinnamon, black pepper and honey. Do not boil. Froth milk with whisk. Pour into cup. Black pepper enhances curcumin absorption.",ingredienti:[{nome:"Latte di mandorla o vaccino",qt:"400ml"},{nome:"Curcuma",qt:"1 cucchiaino"},{nome:"Zenzero in polvere",qt:"0.5 cucchiaino"},{nome:"Cannella",qt:"0.5 cucchiaino"},{nome:"Pepe nero",qt:"1 pizzico"},{nome:"Miele",qt:"20ml"}],_dbEntry:{n:"Golden milk latte con curcuma e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:3,gs:1,g:3,z:12,ch:18,fi:.5,ca:200,fe:.5,mg:20,k2:200,na:80,zn:.3,fo:5,se:2,col:5}},{id:"tpl_1307",nome:"Pane tostato con ricotta e miele",nome_en:"Toast with ricotta and honey",categoria:"Colazione",porzioni:2,note:"Tostare due fette di pane integrale. Spalmare abbondante ricotta fresca. Condire con miele, noci tritate e cannella. Aggiungere fettine di banana o mirtilli. Colazione proteica e naturalmente dolce.",note_en:"Toast two slices of wholegrain bread. Spread plenty of fresh ricotta. Top with honey, chopped walnuts and cinnamon. Add banana slices or blueberries. Naturally sweet protein breakfast.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Ricotta fresca",qt:"120g"},{nome:"Miele",qt:"20ml"},{nome:"Noci",qt:"20g"},{nome:"Banana",qt:"1"},{nome:"Cannella",qt:"0.5 cucchiaino"}],_dbEntry:{n:"Pane tostato con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:12,gs:2.5,g:8,z:18,ch:46,fi:5,ca:140,fe:1.8,mg:35,k2:380,na:180,zn:1.2,fo:22,se:8,col:22}},{id:"tpl_1308",nome:"Frullato proteico post-allenamento",nome_en:"Post-workout protein shake",categoria:"Spuntino",porzioni:1,note:"Frullare banana congelata, latte, proteine in polvere (vaniglia o cioccolato), burro di mandorle e semi di chia. Se troppo denso aggiungere latte. Consumare entro 30 minuti dall'allenamento per massimizzare la sintesi proteica.",note_en:"Blend frozen banana, milk, protein powder (vanilla or chocolate), almond butter and chia seeds. If too thick add more milk. Consume within 30 minutes of training to maximise protein synthesis.",ingredienti:[{nome:"Banana congelata",qt:"1"},{nome:"Latte",qt:"250ml"},{nome:"Proteine in polvere",qt:"30g"},{nome:"Burro di mandorle",qt:"20g"},{nome:"Semi di chia",qt:"10g"}],_dbEntry:{n:"Frullato proteico post-allenamento (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:30,gs:2,g:10,z:16,ch:40,fi:4.5,ca:280,fe:1.5,mg:65,k2:580,na:120,zn:1.5,fo:18,se:5,col:15}},{id:"tpl_1309",nome:"Crackers di segale con avocado e cetriolo",nome_en:"Rye crackers with avocado and cucumber",categoria:"Spuntino",porzioni:2,note:"Spalmare l'avocado schiacciato con limone e sale sui crackers di segale. Aggiungere fettine sottili di cetriolo, semi di sesamo e pepe. Snack veloce, ricco di grassi buoni e fibre. Ottimo a meta mattina.",note_en:"Spread avocado mashed with lemon and salt on rye crackers. Add thin cucumber slices, sesame seeds and pepper. Quick snack, rich in healthy fats and fibre. Excellent mid-morning.",ingredienti:[{nome:"Crackers di segale",qt:"4"},{nome:"Avocado",qt:"0.5"},{nome:"Cetriolo",qt:"0.5"},{nome:"Limone",qt:"0.5"},{nome:"Semi di sesamo",qt:"5g"}],_dbEntry:{n:"Crackers di segale con avocado e cetriolo (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:1.5,g:8,z:1,ch:22,fi:7,ca:20,fe:1.2,mg:28,k2:280,na:180,zn:.8,fo:45,se:3,col:0}},{id:"tpl_1310",nome:"Uova in cocotte con prosciutto e parmigiano",nome_en:"Eggs en cocotte with ham and parmesan",categoria:"Colazione",porzioni:4,note:"Imburrare 4 cocotte. Adagiare una fetta di prosciutto cotto in ciascuna. Rompere un uovo dentro. Aggiungere un cucchiaio di panna, parmigiano grattugiato e pepe. Cuocere a bagno maria in forno a 180 C per 12 minuti.",note_en:"Butter 4 ramekins. Place a slice of cooked ham in each. Break an egg inside. Add a spoonful of cream, grated parmesan and pepper. Bake in water bath at 180 C for 12 minutes.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Prosciutto cotto",qt:"4 fette"},{nome:"Panna da cucina",qt:"40ml"},{nome:"Parmigiano",qt:"30g"},{nome:"Burro",qt:"15g"}],_dbEntry:{n:"Uova in cocotte con prosciutto e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:14,gs:5.5,g:14,z:1,ch:1.5,fi:0,ca:90,fe:1.2,mg:12,k2:160,na:480,zn:1.2,fo:22,se:18,col:230}},{id:"tpl_1311",nome:"Zuppa toscana con cavolo nero e fagioli",nome_en:"Tuscan soup with cavolo nero and beans",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, carota e sedano in olio. Aggiungere fagioli cannellini, cavolo nero a strisce e pomodori. Versare brodo e cuocere 35 minuti. Aggiustare di sale. Servire su fette di pane tostato con olio crudo.",note_en:"Sauté onion, carrot and celery in oil. Add cannellini beans, sliced cavolo nero and tomatoes. Pour in stock and cook 35 minutes. Season with salt. Serve on toasted bread slices with raw oil.",ingredienti:[{nome:"Cavolo nero",qt:"400g"},{nome:"Fagioli cannellini cotti",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Brodo vegetale",qt:"1.2L"},{nome:"Pane toscano",qt:"4 fette"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Zuppa toscana con cavolo nero e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:11,gs:1,g:7,z:4,ch:35,fi:10,ca:100,fe:3.5,mg:60,k2:680,na:320,zn:1.5,fo:110,se:4,col:0}},{id:"tpl_1312",nome:"Borscht di barbabietole con panna acida",nome_en:"Beetroot borscht with sour cream",categoria:"Zuppa",porzioni:6,note:"Rosolare cipolla, carota e sedano in olio. Aggiungere barbabietole grattugiate, cavolo, pomodori e brodo. Cuocere 40 minuti. Aggiungere aceto e zucchero. Servire calda o fredda con panna acida e aneto.",note_en:"Brown onion, carrot and celery in oil. Add grated beetroot, cabbage, tomatoes and stock. Cook 40 minutes. Add vinegar and sugar. Serve hot or cold with sour cream and dill.",ingredienti:[{nome:"Barbabietole",qt:"400g"},{nome:"Cavolo bianco",qt:"200g"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Brodo di carne",qt:"1L"},{nome:"Aceto di vino",qt:"30ml"},{nome:"Panna acida",qt:"100g"},{nome:"Aneto",qt:"15g"}],_dbEntry:{n:"Borscht di barbabietole con panna acida (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4.5,gs:3,g:6,z:10,ch:20,fi:5,ca:65,fe:1.5,mg:30,k2:550,na:320,zn:.5,fo:55,se:3,col:15}},{id:"tpl_1313",nome:"Crema di pomodoro fresco con basilico",nome_en:"Fresh tomato cream with basil",categoria:"Zuppa",porzioni:4,note:"Rosolare cipolla e aglio in olio. Aggiungere pomodori maturi pelati e a pezzi. Cuocere 20 minuti. Frullare con basilico fresco e olio extravergine. Setacciare. Regolare di sale. Servire calda o fredda con crostini.",note_en:"Sauté onion and garlic in oil. Add peeled and chopped ripe tomatoes. Cook 20 minutes. Blend with fresh basil and extra virgin oil. Strain. Season. Serve hot or cold with croutons.",ingredienti:[{nome:"Pomodori maturi",qt:"1kg"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"25g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Pane per crostini",qt:"80g"}],_dbEntry:{n:"Crema di pomodoro fresco con basilico (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:3,gs:1.5,g:9,z:7,ch:10,fi:3,ca:25,fe:1,mg:22,k2:480,na:150,zn:.4,fo:30,se:2,col:0}},{id:"tpl_1314",nome:"Minestra di orzo e fagioli borlotti",nome_en:"Barley and borlotti bean soup",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, carota, sedano, lardo o pancetta. Aggiungere fagioli borlotti e orzo perlato. Versare brodo abbondante. Cuocere 40 minuti finche l'orzo e cotto. La zuppa si addensa raffreddando. Servire con olio crudo.",note_en:"Sauté onion, carrot, celery, lard or pancetta. Add borlotti beans and pearl barley. Pour in plenty of stock. Cook 40 minutes until barley is cooked. Soup thickens as it cools. Serve with raw oil.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Fagioli borlotti cotti",qt:"400g"},{nome:"Pancetta",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Brodo vegetale",qt:"1.5L"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Minestra di orzo e fagioli borlotti (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:2,g:8,z:3,ch:44,fi:10,ca:70,fe:3,mg:55,k2:600,na:380,zn:2,fo:110,se:5,col:10}},{id:"tpl_1315",nome:"Zuppa di ceci e baccalà",nome_en:"Chickpea and salt cod soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e rosmarino in olio. Aggiungere ceci lessati e pomodori. Cuocere 15 minuti. Aggiungere il baccalà dissalato a bocconcini. Cuocere 15 minuti. Aggiustare di sale. Guarnire con olio e peperoncino.",note_en:"Sauté garlic and rosemary in oil. Add cooked chickpeas and tomatoes. Cook 15 minutes. Add desalted cod pieces. Cook 15 minutes. Season with salt. Garnish with oil and chilli.",ingredienti:[{nome:"Ceci cotti",qt:"400g"},{nome:"Baccalà ammollato",qt:"400g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Rosmarino",qt:"2 rametti"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Peperoncino",qt:"1"}],_dbEntry:{n:"Zuppa di ceci e baccala (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:26,gs:1.5,g:8,z:3,ch:28,fi:8,ca:80,fe:3.5,mg:65,k2:700,na:450,zn:2,fo:130,se:35,col:55}},{id:"tpl_1316",nome:"Passato di verdure invernale",nome_en:"Winter vegetable passato",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla in olio. Aggiungere patate, carote, sedano rapa, zucca e brodo. Cuocere 30 minuti. Frullare fino a crema liscia. Regolare la consistenza con brodo. Servire con un filo di olio crudo, semi di zucca e pane tostato.",note_en:"Sauté onion in oil. Add potatoes, carrots, celeriac, pumpkin and stock. Cook 30 minutes. Blend until smooth cream. Adjust consistency with stock. Serve with raw oil drizzle, pumpkin seeds and toast.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Carote",qt:"200g"},{nome:"Sedano rapa",qt:"200g"},{nome:"Zucca",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Brodo vegetale",qt:"1L"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Semi di zucca",qt:"20g"}],_dbEntry:{n:"Passato di verdure invernale (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:3.5,gs:1,g:6,z:5,ch:22,fi:4.5,ca:45,fe:1.2,mg:28,k2:560,na:220,zn:.6,fo:30,se:2,col:0}},{id:"tpl_1317",nome:"Zuppa di pesce mediterranea",nome_en:"Mediterranean fish soup",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, aglio e finocchio in olio. Aggiungere passata di pomodoro, vino bianco e zafferano. Cuocere 10 minuti. Aggiungere pesce misto a pezzi, crostacei e molluschi. Cuocere 20 minuti. Servire con croutons.",note_en:"Sauté onion, garlic and fennel in oil. Add tomato passata, white wine and saffron. Cook 10 minutes. Add mixed fish pieces, shellfish and molluscs. Cook 20 minutes. Serve with croutons.",ingredienti:[{nome:"Pesce misto da zuppa",qt:"1kg"},{nome:"Passata di pomodoro",qt:"400g"},{nome:"Finocchio",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Zuppa di pesce mediterranea (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:30,gs:2,g:10,z:5,ch:12,fi:2,ca:80,fe:3,mg:58,k2:700,na:480,zn:2.5,fo:30,se:48,col:100}},{id:"tpl_1318",nome:"Zuppa di porcini e castagne",nome_en:"Porcini and chestnut soup",categoria:"Zuppa",porzioni:4,note:"Ammollare i porcini secchi 30 minuti. Soffriggere scalogno in burro. Aggiungere porcini scolati e castagne lesse. Versare brodo e il liquido di ammollo filtrato. Cuocere 25 minuti. Frullare meta zuppa. Guarnire con porcini trifolati.",note_en:"Soak dried porcini 30 minutes. Sauté shallot in butter. Add drained porcini and boiled chestnuts. Pour in stock and strained soaking liquid. Cook 25 minutes. Blend half soup. Garnish with sautéed porcini.",ingredienti:[{nome:"Porcini secchi",qt:"30g"},{nome:"Castagne lessate",qt:"250g"},{nome:"Scalogno",qt:"3"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Burro",qt:"30g"},{nome:"Timo",qt:"3 rametti"}],_dbEntry:{n:"Zuppa di porcini e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:3,g:7,z:5,ch:34,fi:5.5,ca:30,fe:2.5,mg:38,k2:480,na:180,zn:1,fo:35,se:8,col:18}},{id:"tpl_1319",nome:"Crema di topinambur e tartufo",nome_en:"Jerusalem artichoke and truffle cream",categoria:"Zuppa",porzioni:4,note:"Lessare il topinambur con scalogno. Frullare con brodo, panna e olio. Setacciare per ottenere una crema vellutata. Regolare di sale. Servire con julienne di topinambur croccante, olio al tartufo e chips di prosciutto.",note_en:"Boil Jerusalem artichoke with shallot. Blend with stock, cream and oil. Strain to obtain velvet cream. Season. Serve with crispy Jerusalem artichoke julienne, truffle oil and crispy ham chips.",ingredienti:[{nome:"Topinambur",qt:"600g"},{nome:"Scalogno",qt:"2"},{nome:"Panna da cucina",qt:"80ml"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Olio al tartufo",qt:"15ml"},{nome:"Prosciutto crudo",qt:"40g"}],_dbEntry:{n:"Crema di topinambur e tartufo (ricetta)",c:"Ricette",src:"RICETTE",k:195,p:6,gs:4,g:11,z:4,ch:18,fi:3.5,ca:25,fe:3.5,mg:22,k2:480,na:320,zn:.5,fo:18,se:3,col:28}},{id:"tpl_1320",nome:"Zuppa di fagioli neri alla messicana",nome_en:"Mexican black bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, aglio, peperone e jalapeño in olio. Aggiungere fagioli neri, cumino, coriandolo e brodo. Cuocere 20 minuti. Frullare meta. Servire con tortilla chips, avocado, panna acida e lime.",note_en:"Sauté onion, garlic, pepper and jalapeño in oil. Add black beans, cumin, coriander and stock. Cook 20 minutes. Blend half. Serve with tortilla chips, avocado, sour cream and lime.",ingredienti:[{nome:"Fagioli neri cotti",qt:"500g"},{nome:"Peperone",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Cumino",qt:"2 cucchiaini"},{nome:"Coriandolo",qt:"20g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Avocado",qt:"1"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Zuppa di fagioli neri alla messicana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:13,gs:1,g:7,z:3,ch:38,fi:12,ca:65,fe:4,mg:75,k2:700,na:320,zn:2.5,fo:150,se:4,col:5}},{id:"tpl_1321",nome:"Cassoeula lombarda",nome_en:"Lombard cassoeula pork and cabbage",categoria:"Secondo piatto",porzioni:6,note:"Rosolare verze tagliate con cipolla in olio. Aggiungere costine, salsiccia, cotechino e verzini a pezzi. Versare poco vino bianco e brodo. Cuocere coperto 2 ore. Piatto invernale lombardo per eccellenza da gustare con polenta.",note_en:"Sauté sliced savoy cabbage with onion in oil. Add ribs, sausage, cotechino and small sausages. Pour in a little white wine and stock. Cook covered 2 hours. Quintessential Lombard winter dish, best with polenta.",ingredienti:[{nome:"Verza",qt:"1kg"},{nome:"Costine di maiale",qt:"500g"},{nome:"Salsiccia",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"150ml"},{nome:"Brodo",qt:"300ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Cassoeula lombarda (ricetta)",c:"Ricette",src:"RICETTE",k:450,p:30,gs:9,g:26,z:4,ch:12,fi:6,ca:80,fe:3,mg:50,k2:650,na:680,zn:5,fo:55,se:22,col:85}},{id:"tpl_1322",nome:"Porceddu sardo al forno",nome_en:"Sardinian roast suckling pig",categoria:"Secondo piatto",porzioni:8,note:"Massaggiare il maialino con lardo, aglio, mirto, sale e pepe. Cuocere lentamente al forno a 140 C per 3-4 ore bagnando con vino bianco. Alzare a 220 C per gli ultimi 20 minuti per croccantare la cotenna.",note_en:"Rub suckling pig with lard, garlic, myrtle, salt and pepper. Roast slowly at 140 C for 3-4 hours basting with white wine. Raise to 220 C for last 20 minutes to crisp the skin.",ingredienti:[{nome:"Maialino da latte",qt:"3kg"},{nome:"Lardo",qt:"80g"},{nome:"Aglio",qt:"6 spicchi"},{nome:"Mirto",qt:"4 rametti"},{nome:"Vino bianco",qt:"300ml"},{nome:"Rosmarino",qt:"4 rametti"}],_dbEntry:{n:"Porceddu sardo al forno (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:42,gs:9,g:26,z:0,ch:0,fi:0,ca:25,fe:1.8,mg:35,k2:520,na:380,zn:4.5,fo:10,se:30,col:120}},{id:"tpl_1323",nome:"Tegame di pesce alla pugliese",nome_en:"Apulian fish tray bake",categoria:"Secondo piatto",porzioni:4,note:"Disporre in teglia strati di patate, cipolla, pomodorini, riso crudo e cozze aperte. Condire ogni strato con olio, aglio, prezzemolo e pecorino. Coprire con acqua. Cuocere in forno a 180 C per 45 minuti.",note_en:"Layer in baking dish potatoes, onion, cherry tomatoes, raw rice and opened mussels. Season each layer with oil, garlic, parsley and pecorino. Cover with water. Bake at 180 C for 45 minutes.",ingredienti:[{nome:"Cozze",qt:"1kg"},{nome:"Patate",qt:"400g"},{nome:"Riso",qt:"150g"},{nome:"Pomodorini",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Pecorino",qt:"40g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Prezzemolo",qt:"20g"}],_dbEntry:{n:"Tegame di pesce alla pugliese (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:22,gs:2.5,g:12,z:4,ch:42,fi:3.5,ca:110,fe:5,mg:60,k2:620,na:520,zn:2.5,fo:42,se:40,col:60}},{id:"tpl_1324",nome:"Timballo di riso al forno",nome_en:"Baked rice timbale",categoria:"Primo piatto",porzioni:6,note:"Cuocere il riso al dente. Mescolare con sugo di carne, piselli, mozzarella e parmigiano. Rivestire lo stampo con pangrattato imburrato. Versare il riso. Cuocere in forno a 180 C per 30 minuti. Sformare e servire.",note_en:"Cook rice al dente. Mix with meat sauce, peas, mozzarella and parmesan. Line mould with buttered breadcrumbs. Pour in rice. Bake at 180 C for 30 minutes. Unmould and serve.",ingredienti:[{nome:"Riso",qt:"400g"},{nome:"Sugo di carne",qt:"300ml"},{nome:"Piselli",qt:"150g"},{nome:"Mozzarella",qt:"150g"},{nome:"Parmigiano",qt:"80g"},{nome:"Burro",qt:"40g"},{nome:"Pangrattato",qt:"60g"}],_dbEntry:{n:"Timballo di riso al forno (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:17,gs:5.5,g:14,z:3,ch:55,fi:2,ca:180,fe:2,mg:38,k2:350,na:420,zn:2.5,fo:35,se:15,col:55}},{id:"tpl_1325",nome:"Pasta alla carbonara con guanciale DOP",nome_en:"Carbonara pasta with DOP guanciale",categoria:"Primo piatto",porzioni:4,note:"Rosolare il guanciale tagliato a listarelle senza aggiunta di olio. Sbattere tuorli con pecorino romano DOP e abbondante pepe nero. Cuocere gli spaghetti al dente. Fuori dal fuoco amalgamare uova, guanciale e poca acqua di cottura.",note_en:"Brown guanciale strips without adding oil. Beat egg yolks with DOP pecorino romano and plenty of black pepper. Cook spaghetti al dente. Off heat combine eggs, guanciale and a little cooking water.",ingredienti:[{nome:"Spaghetti di semola",qt:"320g"},{nome:"Guanciale",qt:"180g"},{nome:"Tuorli",qt:"5"},{nome:"Pecorino romano DOP",qt:"100g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Pasta alla carbonara con guanciale DOP (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:24,gs:10,g:22,z:1,ch:57,fi:1,ca:220,fe:2,mg:35,k2:250,na:720,zn:3,fo:55,se:22,col:360}},{id:"tpl_1326",nome:"Risotto alla crema di scampi (versione 2)",nome_en:"Scampi cream risotto (version 2)",categoria:"Primo piatto",porzioni:4,note:"Sgusciare gli scampi tenendo teste e carapaci per il fumetto. Preparare fumetto con teste, cipolla e vino. Tostare il riso in scalogno e burro. Aggiungere il fumetto a mestoli. Aggiungere gli scampi negli ultimi 5 minuti. Mantecare con burro.",note_en:"Shell scampi keeping heads and shells for bisque. Make bisque with heads, onion and wine. Toast rice in shallot and butter. Add bisque ladle by ladle. Add scampi in last 5 minutes. Finish with butter.",ingredienti:[{nome:"Scampi",qt:"600g"},{nome:"Riso Carnaroli",qt:"320g"},{nome:"Scalogno",qt:"2"},{nome:"Vino bianco",qt:"100ml"},{nome:"Burro",qt:"50g"},{nome:"Panna",qt:"60ml"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Risotto alla crema di scampi (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:22,gs:8,g:16,z:2,ch:55,fi:.5,ca:60,fe:1.5,mg:42,k2:380,na:420,zn:2,fo:18,se:38,col:145}},{id:"tpl_1327",nome:"Gnudi di ricotta e spinaci",nome_en:"Ricotta and spinach gnudi",categoria:"Primo piatto",porzioni:4,note:"Strizzare benissimo gli spinaci lessati. Tritare finemente. Mescolare con ricotta, uovo, parmigiano, noce moscata e poca farina. Formare palline. Tuffare in acqua bollente salata. Scolare quando vengono a galla. Condire con burro e salvia.",note_en:"Squeeze boiled spinach very well. Chop finely. Mix with ricotta, egg, parmesan, nutmeg and a little flour. Shape into balls. Drop into salted boiling water. Drain when they float. Dress with butter and sage.",ingredienti:[{nome:"Spinaci",qt:"400g"},{nome:"Ricotta",qt:"300g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano",qt:"60g"},{nome:"Farina",qt:"40g"},{nome:"Burro",qt:"50g"},{nome:"Salvia",qt:"8 foglie"}],_dbEntry:{n:"Gnudi di ricotta e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:16,gs:9,g:18,z:2,ch:20,fi:3,ca:300,fe:3.5,mg:55,k2:450,na:280,zn:2,fo:160,se:12,col:110}},{id:"tpl_1328",nome:"Tortelli di zucca mantovani",nome_en:"Mantua pumpkin tortelli",categoria:"Primo piatto",porzioni:6,note:"Preparare ripieno con zucca al forno, amaretti sbriciolati, mostarda di Mantova, parmigiano e noce moscata. Preparare la sfoglia all'uovo. Formare i tortelli. Cuocere in acqua salata. Condire con burro fuso, salvia e parmigiano abbondante.",note_en:"Make filling with oven-roasted pumpkin, crumbled amaretti, Mantua mostarda, parmesan and nutmeg. Make egg pasta dough. Form tortelli. Cook in salted water. Dress with melted butter, sage and plenty of parmesan.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Zucca",qt:"500g"},{nome:"Amaretti",qt:"40g"},{nome:"Mostarda di Mantova",qt:"40g"},{nome:"Parmigiano",qt:"80g"},{nome:"Burro",qt:"80g"},{nome:"Salvia",qt:"12 foglie"}],_dbEntry:{n:"Tortelli di zucca mantovani (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:15,gs:8,g:16,z:6,ch:58,fi:2.5,ca:180,fe:2.5,mg:42,k2:380,na:320,zn:2,fo:35,se:12,col:150}},{id:"tpl_1329",nome:"Vincisgrassi marchigiani",nome_en:"Marche-style baked pasta vincisgrassi",categoria:"Primo piatto",porzioni:8,note:"Preparare ragu ricco con rigaglie di pollo, vitello, prosciutto e funghi porcini. Preparare besciamella. Foderare teglia con sfoglia all'uovo. Alternare strati con ragu e besciamella. Spolverare con parmigiano. Cuocere a 180 C per 40 minuti.",note_en:"Make rich ragu with chicken giblets, veal, ham and porcini mushrooms. Make bechamel. Line tin with egg pasta. Alternate layers with ragu and bechamel. Sprinkle parmesan. Bake at 180 C for 40 minutes.",ingredienti:[{nome:"Sfoglia all uovo",qt:"400g"},{nome:"Rigaglie di pollo",qt:"200g"},{nome:"Macinato di vitello",qt:"200g"},{nome:"Porcini secchi",qt:"20g"},{nome:"Latte",qt:"500ml"},{nome:"Farina",qt:"50g"},{nome:"Burro",qt:"80g"},{nome:"Parmigiano",qt:"100g"}],_dbEntry:{n:"Vincisgrassi marchigiani (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:24,gs:9,g:20,z:4,ch:50,fi:2,ca:250,fe:3,mg:42,k2:380,na:560,zn:3.5,fo:45,se:20,col:160}},{id:"tpl_1330",nome:"Polenta taragna con spezzatino",nome_en:"Taragna polenta with stew",categoria:"Piatto unico",porzioni:6,note:"Cuocere la polenta taragna 45 minuti. Preparare uno spezzatino di manzo con verdure e vino rosso. Servire la polenta morbida con lo spezzatino sopra. Piatto montano completo e sostanzioso della tradizione lombarda.",note_en:"Cook taragna polenta 45 minutes. Prepare beef stew with vegetables and red wine. Serve soft polenta topped with stew. Complete and hearty mountain dish from Lombard tradition.",ingredienti:[{nome:"Farina per polenta taragna",qt:"300g"},{nome:"Manzo per spezzatino",qt:"600g"},{nome:"Vino rosso",qt:"150ml"},{nome:"Carota",qt:"2"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Burro",qt:"50g"},{nome:"Taleggio",qt:"80g"}],_dbEntry:{n:"Polenta taragna con spezzatino (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:32,gs:8,g:20,z:4,ch:52,fi:4,ca:150,fe:4,mg:50,k2:650,na:420,zn:6,fo:28,se:28,col:95}},{id:"tpl_1331",nome:"Cous cous con verdure e ceci",nome_en:"Couscous with vegetables and chickpeas",categoria:"Piatto unico",porzioni:4,note:"Cuocere il cous cous con acqua bollente salata e olio, sgranare con una forchetta. Saltare in padella zucchine, carote e peperoni a cubetti con cipolla. Unire i ceci lessati e le verdure al cous cous. Condire con olio, menta e limone.",note_en:"Cook couscous with boiling salted water and oil, fluff with a fork. Sauté diced courgettes, carrots and peppers with onion. Add boiled chickpeas and vegetables to couscous. Dress with oil, mint and lemon.",ingredienti:[{nome:"Cous cous",qt:"280g"},{nome:"Ceci lessati",qt:"300g"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Peperoni",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Menta",qt:"10g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Cous cous con verdure e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:410,p:14,gs:1.5,g:9,z:6,ch:68,fi:8,ca:70,fe:3,mg:60,k2:520,na:280,zn:2,fo:90,se:8,col:0}},{id:"tpl_1332",nome:"Poke bowl di salmone e riso",nome_en:"Salmon poke bowl",categoria:"Piatto unico",porzioni:2,note:"Cuocere il riso e condirlo con aceto di riso. Tagliare il salmone crudo a cubetti e marinare con salsa di soia e sesamo. Comporre la bowl con riso, salmone, avocado, edamame, cetriolo e alga nori a listarelle.",note_en:"Cook rice and dress with rice vinegar. Cut raw salmon into cubes and marinate with soy sauce and sesame. Assemble bowl with rice, salmon, avocado, edamame, cucumber and nori strips.",ingredienti:[{nome:"Salmone fresco",qt:"250g"},{nome:"Riso",qt:"160g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"100g"},{nome:"Cetriolo",qt:"100g"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Alga nori",qt:"2 fogli"}],_dbEntry:{n:"Poke bowl di salmone e riso (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:28,gs:4,g:22,z:3,ch:55,fi:6,ca:60,fe:2,mg:70,k2:750,na:680,zn:2,fo:60,se:35,col:45}},{id:"tpl_1333",nome:"Paella di pesce",nome_en:"Seafood paella",categoria:"Piatto unico",porzioni:6,note:"Preparare un soffritto di cipolla, aglio e peperone. Aggiungere il riso e tostarlo con lo zafferano. Bagnare gradualmente con brodo di pesce. Unire cozze, gamberi, calamari e vongole. Cuocere senza mescolare fino ad asciugare il brodo.",note_en:"Prepare a sofrito of onion, garlic and pepper. Add rice and toast with saffron. Gradually add fish stock. Add mussels, prawns, squid and clams. Cook without stirring until stock is absorbed.",ingredienti:[{nome:"Riso",qt:"400g"},{nome:"Cozze",qt:"300g"},{nome:"Gamberi",qt:"250g"},{nome:"Calamari",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Peperone",qt:"1"},{nome:"Brodo di pesce",qt:"900ml"}],_dbEntry:{n:"Paella di pesce (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:26,gs:1.5,g:6,z:2,ch:60,fi:2,ca:80,fe:2.5,mg:55,k2:480,na:580,zn:2,fo:35,se:40,col:110}},{id:"tpl_1334",nome:"Burrito bowl con pollo e fagioli neri",nome_en:"Chicken and black bean burrito bowl",categoria:"Piatto unico",porzioni:4,note:"Cuocere il pollo a cubetti con paprika e cumino. Preparare riso, fagioli neri, mais, pomodorini e avocado a dadini. Comporre la bowl con tutti gli ingredienti e guarnire con lime e coriandolo fresco.",note_en:"Cook diced chicken with paprika and cumin. Prepare rice, black beans, corn, cherry tomatoes and diced avocado. Assemble bowl with all ingredients and garnish with lime and fresh coriander.",ingredienti:[{nome:"Petto di pollo",qt:"400g"},{nome:"Riso",qt:"200g"},{nome:"Fagioli neri",qt:"250g"},{nome:"Mais",qt:"100g"},{nome:"Avocado",qt:"1"},{nome:"Pomodorini",qt:"150g"},{nome:"Lime",qt:"1"},{nome:"Coriandolo",qt:"10g"}],_dbEntry:{n:"Burrito bowl con pollo e fagioli neri (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:32,gs:2,g:12,z:3,ch:60,fi:9,ca:60,fe:3,mg:70,k2:800,na:320,zn:2.5,fo:80,se:26,col:65}},{id:"tpl_1335",nome:"Riso alla cantonese con gamberi e verdure",nome_en:"Cantonese-style rice with prawns and vegetables",categoria:"Piatto unico",porzioni:4,note:"Cuocere il riso e raffreddarlo. Saltare in wok uova strapazzate, piselli, carote e gamberi. Aggiungere il riso freddo e la salsa di soia. Saltare a fuoco vivo qualche minuto mescolando bene.",note_en:"Cook rice and let it cool. Stir-fry scrambled eggs, peas, carrots and prawns in wok. Add cold rice and soy sauce. Stir-fry over high heat a few minutes, mixing well.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Gamberi",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Piselli",qt:"100g"},{nome:"Carote",qt:"80g"},{nome:"Salsa di soia",qt:"30ml"},{nome:"Olio di sesamo",qt:"10ml"}],_dbEntry:{n:"Riso alla cantonese con gamberi e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:22,gs:2,g:9,z:3,ch:65,fi:3,ca:60,fe:2,mg:45,k2:400,na:620,zn:1.5,fo:40,se:28,col:150}},{id:"tpl_1336",nome:"Buddha bowl vegetariano con tofu",nome_en:"Vegetarian tofu Buddha bowl",categoria:"Piatto unico",porzioni:2,note:"Marinare il tofu a cubetti con salsa di soia e zenzero, poi saltare in padella fino a dorare. Comporre la bowl con quinoa, cavolo rosso, carote julienne, avocado ed edamame. Condire con salsa tahina e limone.",note_en:"Marinate diced tofu with soy sauce and ginger, then pan-fry until golden. Assemble bowl with quinoa, red cabbage, julienne carrots, avocado and edamame. Dress with tahini and lemon sauce.",ingredienti:[{nome:"Tofu",qt:"200g"},{nome:"Quinoa",qt:"150g"},{nome:"Cavolo rosso",qt:"100g"},{nome:"Carote",qt:"80g"},{nome:"Avocado",qt:"1"},{nome:"Edamame",qt:"80g"},{nome:"Tahina",qt:"30g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Buddha bowl vegetariano con tofu (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:20,gs:3,g:24,z:4,ch:42,fi:11,ca:220,fe:4,mg:110,k2:750,na:380,zn:2.5,fo:110,se:8,col:0}},{id:"tpl_1337",nome:"Parmigiana di melanzane",nome_en:"Eggplant parmigiana",categoria:"Piatto unico",porzioni:6,note:"Grigliare le melanzane a fette senza friggere. Alternare in teglia strati di melanzane, sugo di pomodoro, mozzarella e parmigiano. Terminare con parmigiano e basilico. Cuocere in forno a 190 C per 35 minuti.",note_en:"Grill eggplant slices without frying. Layer in baking dish alternating eggplant, tomato sauce, mozzarella and parmesan. Finish with parmesan and basil. Bake at 190 C for 35 minutes.",ingredienti:[{nome:"Melanzane",qt:"1kg"},{nome:"Passata di pomodoro",qt:"500g"},{nome:"Mozzarella",qt:"300g"},{nome:"Parmigiano",qt:"80g"},{nome:"Basilico",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Parmigiana di melanzane (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:16,gs:6,g:20,z:6,ch:14,fi:5,ca:280,fe:1.5,mg:35,k2:520,na:420,zn:2,fo:40,se:10,col:35}},{id:"tpl_1338",nome:"Cassoulet di fagioli e salsiccia",nome_en:"Bean and sausage cassoulet",categoria:"Piatto unico",porzioni:6,note:"Rosolare la salsiccia a tocchetti con cipolla, carota e sedano. Aggiungere i fagioli borlotti lessati, pomodori pelati e alloro. Cuocere in forno a 180 C per 40 minuti finché si forma una crosticina in superficie.",note_en:"Brown diced sausage with onion, carrot and celery. Add boiled borlotti beans, peeled tomatoes and bay leaf. Bake at 180 C for 40 minutes until a crust forms on top.",ingredienti:[{nome:"Salsiccia",qt:"400g"},{nome:"Fagioli borlotti",qt:"500g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Alloro",qt:"2 foglie"}],_dbEntry:{n:"Cassoulet di fagioli e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:26,gs:9,g:26,z:5,ch:35,fi:10,ca:90,fe:4,mg:70,k2:850,na:680,zn:3,fo:120,se:18,col:60}},{id:"tpl_1339",nome:"Zuppa di pesce con crostini",nome_en:"Fish soup with croutons",categoria:"Piatto unico",porzioni:4,note:"Rosolare aglio e peperoncino in olio. Aggiungere pomodori pelati e vino bianco. Unire pesce misto e frutti di mare, cuocere 15 minuti. Servire con crostini di pane tostato strofinati con aglio.",note_en:"Brown garlic and chili in oil. Add peeled tomatoes and white wine. Add mixed fish and seafood, cook 15 minutes. Serve with toasted bread croutons rubbed with garlic.",ingredienti:[{nome:"Pesce misto",qt:"600g"},{nome:"Cozze",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Pane casereccio",qt:"200g"}],_dbEntry:{n:"Zuppa di pesce con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:34,gs:1.5,g:8,z:3,ch:38,fi:2.5,ca:100,fe:3,mg:60,k2:650,na:620,zn:2,fo:35,se:45,col:100}},{id:"tpl_1340",nome:"Chili con carne e riso integrale",nome_en:"Chili con carne with brown rice",categoria:"Piatto unico",porzioni:4,note:"Rosolare la carne macinata con cipolla e aglio. Aggiungere fagioli rossi, pomodori pelati, peperoncino e cumino. Cuocere 30 minuti a fuoco lento. Servire con riso integrale lessato.",note_en:"Brown minced meat with onion and garlic. Add kidney beans, peeled tomatoes, chili and cumin. Simmer 30 minutes on low heat. Serve with boiled brown rice.",ingredienti:[{nome:"Macinato di manzo",qt:"400g"},{nome:"Fagioli rossi",qt:"300g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Riso integrale",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Peperoncino",qt:"1"},{nome:"Cumino",qt:"5g"}],_dbEntry:{n:"Chili con carne e riso integrale (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:32,gs:5,g:14,z:4,ch:62,fi:10,ca:70,fe:5,mg:90,k2:850,na:380,zn:5,fo:100,se:22,col:65}},{id:"tpl_1341",nome:"Insalata di riso estiva completa",nome_en:"Complete summer rice salad",categoria:"Piatto unico",porzioni:4,note:"Lessare il riso e raffreddarlo sotto acqua corrente. Condire con tonno, prosciutto cotto a dadini, mais, olive, pomodorini e mozzarelline. Aggiungere olio extravergine e origano.",note_en:"Boil rice and cool under running water. Dress with tuna, diced cooked ham, corn, olives, cherry tomatoes and mozzarella balls. Add extra virgin oil and oregano.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Tonno sott olio",qt:"150g"},{nome:"Prosciutto cotto",qt:"100g"},{nome:"Mais",qt:"100g"},{nome:"Mozzarelline",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olive",qt:"60g"}],_dbEntry:{n:"Insalata di riso estiva completa (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:22,gs:6,g:16,z:4,ch:58,fi:2.5,ca:150,fe:2,mg:40,k2:420,na:680,zn:2,fo:25,se:30,col:55}},{id:"tpl_1342",nome:"Farrotto con funghi e salsiccia",nome_en:"Farro risotto with mushrooms and sausage",categoria:"Piatto unico",porzioni:4,note:"Rosolare la salsiccia sbriciolata con funghi porcini. Tostare il farro e sfumare con vino bianco. Aggiungere brodo vegetale a mestoli, cuocendo come un risotto per 25 minuti. Mantecare con parmigiano.",note_en:"Brown crumbled sausage with porcini mushrooms. Toast farro and deglaze with white wine. Add vegetable stock ladle by ladle, cooking like a risotto for 25 minutes. Finish with parmesan.",ingredienti:[{nome:"Farro perlato",qt:"320g"},{nome:"Salsiccia",qt:"200g"},{nome:"Funghi porcini",qt:"250g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Parmigiano",qt:"50g"}],_dbEntry:{n:"Farrotto con funghi e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:22,gs:7,g:18,z:2,ch:58,fi:8,ca:110,fe:3,mg:80,k2:600,na:520,zn:3,fo:35,se:20,col:45}},{id:"tpl_1343",nome:"Cotoletta di pollo con insalata e patate",nome_en:"Chicken cutlet with salad and potatoes",categoria:"Piatto unico",porzioni:4,note:"Impanare le fettine di pollo con pangrattato e parmigiano. Cuocere in forno su carta forno con poco olio a 200 C per 20 minuti. Servire con patate al forno e insalata mista condita.",note_en:"Bread chicken slices with breadcrumbs and parmesan. Bake on parchment paper with a little oil at 200 C for 20 minutes. Serve with baked potatoes and dressed mixed salad.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Pangrattato",qt:"80g"},{nome:"Parmigiano",qt:"30g"},{nome:"Patate",qt:"500g"},{nome:"Insalata mista",qt:"150g"},{nome:"Uova",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Cotoletta di pollo con insalata e patate (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:36,gs:3,g:14,z:3,ch:45,fi:5,ca:100,fe:2.5,mg:60,k2:900,na:380,zn:2,fo:45,se:30,col:110}},{id:"tpl_1344",nome:"Wok di tofu, verdure e noodles",nome_en:"Tofu, vegetable and noodle stir-fry",categoria:"Piatto unico",porzioni:2,note:"Cuocere i noodles secondo le istruzioni e scolare. Saltare in wok tofu a cubetti fino a dorare, poi aggiungere carote, peperoni, cavolo cinese e germogli di soia. Unire i noodles e salsa di soia, saltare 3 minuti.",note_en:"Cook noodles per instructions and drain. Stir-fry diced tofu in wok until golden, then add carrots, peppers, Chinese cabbage and bean sprouts. Add noodles and soy sauce, stir-fry 3 minutes.",ingredienti:[{nome:"Noodles di riso",qt:"160g"},{nome:"Tofu",qt:"200g"},{nome:"Carote",qt:"80g"},{nome:"Peperoni",qt:"100g"},{nome:"Cavolo cinese",qt:"100g"},{nome:"Germogli di soia",qt:"80g"},{nome:"Salsa di soia",qt:"30ml"}],_dbEntry:{n:"Wok di tofu, verdure e noodles (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:2,g:10,z:5,ch:62,fi:5,ca:180,fe:3,mg:70,k2:520,na:650,zn:1.5,fo:60,se:6,col:0}},{id:"tpl_1345",nome:"Piadina con prosciutto, stracchino e rucola",nome_en:"Piadina with ham, stracchino and rocket",categoria:"Piatto unico",porzioni:2,note:"Preparare la piada con farina, acqua, olio e un pizzico di sale, cuocere su piastra antiaderente. Farcire con stracchino, prosciutto crudo e rucola fresca. Piegare a metà e servire calda.",note_en:"Make flatbread with flour, water, oil and a pinch of salt, cook on non-stick griddle. Fill with stracchino cheese, raw ham and fresh rocket. Fold in half and serve warm.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Stracchino",qt:"150g"},{nome:"Prosciutto crudo",qt:"100g"},{nome:"Rucola",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Piadina con prosciutto, stracchino e rucola (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:24,gs:8,g:22,z:2,ch:58,fi:2,ca:150,fe:2,mg:35,k2:280,na:850,zn:2,fo:25,se:20,col:60}},{id:"tpl_1346",nome:"Bowl mediterraneo con quinoa, feta e verdure grigliate",nome_en:"Mediterranean bowl with quinoa, feta and grilled vegetables",categoria:"Piatto unico",porzioni:2,note:"Cuocere la quinoa e lasciarla raffreddare. Grigliare zucchine, melanzane e peperoni. Comporre la bowl con quinoa, verdure grigliate, feta sbriciolata e olive taggiasche. Condire con olio e origano.",note_en:"Cook quinoa and let it cool. Grill courgettes, eggplant and peppers. Assemble bowl with quinoa, grilled vegetables, crumbled feta and Taggiasca olives. Dress with oil and oregano.",ingredienti:[{nome:"Quinoa",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"100g"},{nome:"Feta",qt:"100g"},{nome:"Olive taggiasche",qt:"40g"}],_dbEntry:{n:"Bowl mediterraneo con quinoa, feta e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:6,g:18,z:5,ch:48,fi:8,ca:220,fe:3,mg:80,k2:650,na:520,zn:2,fo:90,se:8,col:35}},{id:"tpl_1347",nome:"Riso al salto con verdure e uovo",nome_en:"Fried rice cake with vegetables and egg",categoria:"Piatto unico",porzioni:2,note:"Compattare il riso avanzato in una padella antiaderente con poco olio, cuocere fino a formare una crosticina dorata su entrambi i lati. Servire con verdure saltate e un uovo all occhio di bue.",note_en:"Press leftover rice into a non-stick pan with a little oil, cook until a golden crust forms on both sides. Serve with sautéed vegetables and a sunny-side-up egg.",ingredienti:[{nome:"Riso avanzato",qt:"300g"},{nome:"Uova",qt:"2"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"80g"},{nome:"Parmigiano",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Riso al salto con verdure e uovo (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:16,gs:3,g:14,z:3,ch:52,fi:3,ca:110,fe:2,mg:40,k2:380,na:280,zn:1.5,fo:30,se:18,col:190}},{id:"tpl_1348",nome:"Minestrone con orzo e parmigiano",nome_en:"Minestrone with barley and parmesan",categoria:"Piatto unico",porzioni:4,note:"Rosolare cipolla, carota e sedano in olio. Aggiungere zucchine, patate, fagiolini e pomodori pelati. Coprire con brodo vegetale e unire l orzo. Cuocere 30 minuti. Servire con parmigiano grattugiato.",note_en:"Brown onion, carrot and celery in oil. Add courgettes, potatoes, green beans and peeled tomatoes. Cover with vegetable stock and add barley. Cook 30 minutes. Serve with grated parmesan.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Zucchine",qt:"150g"},{nome:"Patate",qt:"150g"},{nome:"Fagiolini",qt:"100g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Minestrone con orzo e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:2.5,g:8,z:5,ch:56,fi:8,ca:150,fe:2.5,mg:60,k2:650,na:380,zn:1.5,fo:60,se:8,col:10}},{id:"tpl_1349",nome:"Involtini di pollo ripieni con contorno di verdure",nome_en:"Stuffed chicken rolls with vegetable side",categoria:"Piatto unico",porzioni:4,note:"Appiattire le fettine di pollo e farcire con spinaci, ricotta e parmigiano. Arrotolare e fissare con stecchini. Rosolare e cuocere in forno a 190 C per 20 minuti. Servire con verdure al vapore.",note_en:"Flatten chicken slices and stuff with spinach, ricotta and parmesan. Roll up and secure with toothpicks. Brown and bake at 190 C for 20 minutes. Serve with steamed vegetables.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Spinaci",qt:"200g"},{nome:"Ricotta",qt:"150g"},{nome:"Parmigiano",qt:"40g"},{nome:"Carote",qt:"150g"},{nome:"Broccoli",qt:"200g"}],_dbEntry:{n:"Involtini di pollo ripieni con contorno di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:40,gs:4,g:14,z:3,ch:12,fi:5,ca:220,fe:2.5,mg:60,k2:750,na:280,zn:2,fo:80,se:32,col:130}},{id:"tpl_1350",nome:"Ciambotta di verdure con uova in camicia",nome_en:"Vegetable ciambotta with poached eggs",categoria:"Piatto unico",porzioni:4,note:"Cuocere in olio patate, melanzane, peperoni, zucchine e pomodori a tocchetti fino a renderli morbidi. Fare delle piccole conche nel composto e cuocere le uova in camicia direttamente nella verdura per 4 minuti.",note_en:"Cook potatoes, eggplant, peppers, courgettes and tomatoes in oil until soft. Make small wells in the mixture and poach eggs directly in the vegetables for 4 minutes.",ingredienti:[{nome:"Patate",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Peperoni",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Pomodori",qt:"200g"},{nome:"Uova",qt:"4"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Ciambotta di verdure con uova in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:2.5,g:16,z:6,ch:32,fi:7,ca:80,fe:2.5,mg:50,k2:850,na:220,zn:1.5,fo:70,se:20,col:190}},{id:"tpl_1351",nome:"Yogurt greco con miele e noci",nome_en:"Greek yogurt with honey and walnuts",categoria:"Spuntino",porzioni:1,note:"Versare lo yogurt greco in una ciotola, aggiungere un cucchiaino di miele e le noci sgusciate spezzettate. Mescolare leggermente e servire subito.",note_en:"Pour Greek yogurt into a bowl, add a teaspoon of honey and crushed shelled walnuts. Stir lightly and serve immediately.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"10g"},{nome:"Noci",qt:"15g"}],_dbEntry:{n:"Yogurt greco con miele e noci (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:14,gs:3,g:11,z:12,ch:12,fi:.5,ca:150,fe:.5,mg:25,k2:220,na:50,zn:1,fo:8,se:5,col:15}},{id:"tpl_1352",nome:"Frullato verde detox",nome_en:"Green detox smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare spinaci freschi, mela, sedano, limone e acqua fino a ottenere un composto omogeneo. Servire fresco appena preparato per mantenere le vitamine.",note_en:"Blend fresh spinach, apple, celery, lemon and water until smooth. Serve fresh right after preparation to preserve vitamins.",ingredienti:[{nome:"Spinaci",qt:"50g"},{nome:"Mela",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Limone",qt:"0.5"},{nome:"Acqua",qt:"150ml"}],_dbEntry:{n:"Frullato verde detox (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2,gs:.1,g:.5,z:16,ch:20,fi:4,ca:60,fe:1.5,mg:35,k2:400,na:40,zn:.4,fo:80,se:2,col:0}},{id:"tpl_1353",nome:"Chips di ceci al forno",nome_en:"Oven-baked chickpea chips",categoria:"Spuntino",porzioni:4,note:"Asciugare bene i ceci lessati con carta assorbente. Condire con olio, paprika e sale. Distribuire su una teglia e cuocere in forno a 200 C per 30-35 minuti girando a metà cottura, finché croccanti.",note_en:"Dry boiled chickpeas well with paper towel. Season with oil, paprika and salt. Spread on a tray and bake at 200 C for 30-35 minutes turning halfway, until crispy.",ingredienti:[{nome:"Ceci lessati",qt:"400g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Paprika",qt:"5g"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di ceci al forno (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:8,gs:.5,g:5,z:2,ch:22,fi:6,ca:50,fe:2,mg:40,k2:280,na:180,zn:1.2,fo:130,se:3,col:0}},{id:"tpl_1354",nome:"Muffin salati con zucchine e feta",nome_en:"Savoury muffins with courgette and feta",categoria:"Spuntino",porzioni:12,note:"Grattugiare le zucchine e strizzarle. Mescolare farina, uova, olio, lievito, zucchine e feta sbriciolata. Versare negli stampini da muffin e cuocere in forno a 180 C per 25 minuti.",note_en:"Grate courgettes and squeeze out water. Mix flour, eggs, oil, baking powder, courgettes and crumbled feta. Pour into muffin tins and bake at 180 C for 25 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Zucchine",qt:"200g"},{nome:"Feta",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Lievito per torte salate",qt:"1 bustina"}],_dbEntry:{n:"Muffin salati con zucchine e feta (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:2,g:8,z:2,ch:15,fi:1,ca:80,fe:1,mg:15,k2:80,na:180,zn:.5,fo:20,se:8,col:45}},{id:"tpl_1355",nome:"Toast integrale con hummus e pomodorini",nome_en:"Wholewheat toast with hummus and cherry tomatoes",categoria:"Spuntino",porzioni:1,note:"Tostare il pane integrale. Spalmare abbondante hummus e guarnire con pomodorini tagliati a metà, un filo di olio e origano.",note_en:"Toast wholewheat bread. Spread plenty of hummus and top with halved cherry tomatoes, a drizzle of oil and oregano.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Hummus",qt:"60g"},{nome:"Pomodorini",qt:"80g"},{nome:"Olio extravergine",qt:"5ml"}],_dbEntry:{n:"Toast integrale con hummus e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:1,g:9,z:3,ch:28,fi:5,ca:40,fe:2,mg:35,k2:280,na:280,zn:1,fo:35,se:4,col:0}},{id:"tpl_1356",nome:"Spiedini di frutta fresca",nome_en:"Fresh fruit skewers",categoria:"Spuntino",porzioni:4,note:"Tagliare la frutta a cubetti di dimensione simile. Infilzare alternando i colori su spiedini di legno. Servire freschi, eventualmente con una spolverata di cocco rapé.",note_en:"Cut fruit into similarly-sized cubes. Skewer alternating colours on wooden sticks. Serve fresh, optionally dusted with desiccated coconut.",ingredienti:[{nome:"Ananas",qt:"150g"},{nome:"Fragole",qt:"150g"},{nome:"Melone",qt:"150g"},{nome:"Uva",qt:"100g"},{nome:"Cocco rapé",qt:"10g"}],_dbEntry:{n:"Spiedini di frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1,gs:.5,g:1,z:18,ch:20,fi:2.5,ca:20,fe:.4,mg:15,k2:250,na:5,zn:.2,fo:25,se:1,col:0}},{id:"tpl_1357",nome:"Popcorn leggero al forno",nome_en:"Light oven-air popcorn",categoria:"Spuntino",porzioni:4,note:"Scoppiare il mais in padella coperta con un filo di olio a fuoco medio, scuotendo di tanto in tanto. Versare in una ciotola e condire con un pizzico di sale, evitando burro aggiunto.",note_en:"Pop corn in a covered pan with a drizzle of oil over medium heat, shaking occasionally. Pour into a bowl and season with a pinch of salt, avoiding added butter.",ingredienti:[{nome:"Mais da popcorn",qt:"100g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Popcorn leggero al forno (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3,gs:.5,g:4,z:.5,ch:20,fi:3.5,ca:5,fe:1,mg:35,k2:100,na:150,zn:.8,fo:10,se:2,col:0}},{id:"tpl_1358",nome:"Palline di cocco e mandorle",nome_en:"Coconut and almond energy balls",categoria:"Spuntino",porzioni:10,note:"Frullare mandorle, datteri denocciolati e cocco rapé fino a ottenere un impasto compatto. Formare delle palline con le mani e passarle nel cocco rapé. Conservare in frigo.",note_en:"Blend almonds, pitted dates and desiccated coconut until a compact dough forms. Shape into balls by hand and roll in desiccated coconut. Store in the fridge.",ingredienti:[{nome:"Mandorle",qt:"150g"},{nome:"Datteri",qt:"150g"},{nome:"Cocco rapé",qt:"60g"}],_dbEntry:{n:"Palline di cocco e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:3,gs:2,g:7,z:11,ch:12,fi:2,ca:35,fe:.8,mg:30,k2:180,na:2,zn:.5,fo:8,se:1,col:0}},{id:"tpl_1359",nome:"Crema di ceci e limone con verdure crude",nome_en:"Lemon chickpea dip with raw vegetables",categoria:"Spuntino",porzioni:4,note:"Frullare ceci lessati, tahina, succo di limone, aglio e olio fino a ottenere una crema liscia. Servire con bastoncini di carota, sedano e finocchio crudi.",note_en:"Blend boiled chickpeas, tahini, lemon juice, garlic and oil until smooth. Serve with raw carrot, celery and fennel sticks.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Tahina",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Carote",qt:"150g"},{nome:"Sedano",qt:"100g"},{nome:"Finocchio",qt:"150g"}],_dbEntry:{n:"Crema di ceci e limone con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:8,gs:1,g:8,z:5,ch:22,fi:7,ca:60,fe:2,mg:45,k2:380,na:150,zn:1.2,fo:90,se:3,col:0}},{id:"tpl_1360",nome:"Frullato di banana e burro di arachidi",nome_en:"Banana and peanut butter smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare la banana con latte, un cucchiaio di burro di arachidi e ghiaccio fino a ottenere una consistenza cremosa. Servire subito.",note_en:"Blend banana with milk, a spoon of peanut butter and ice until creamy. Serve immediately.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Latte",qt:"200ml"},{nome:"Burro di arachidi",qt:"20g"},{nome:"Ghiaccio",qt:"q.b."}],_dbEntry:{n:"Frullato di banana e burro di arachidi (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:11,gs:3,g:12,z:24,ch:34,fi:3,ca:220,fe:.8,mg:60,k2:600,na:120,zn:1,fo:25,se:4,col:10}},{id:"tpl_1361",nome:"Cracker di riso con avocado",nome_en:"Rice crackers with avocado",categoria:"Spuntino",porzioni:1,note:"Schiacciare l avocado con succo di limone e un pizzico di sale. Spalmare sui cracker di riso e guarnire con semi di chia o peperoncino a piacere.",note_en:"Mash avocado with lemon juice and a pinch of salt. Spread on rice crackers and top with chia seeds or chili to taste.",ingredienti:[{nome:"Cracker di riso",qt:"4"},{nome:"Avocado",qt:"0.5"},{nome:"Limone",qt:"0.5"},{nome:"Semi di chia",qt:"5g"}],_dbEntry:{n:"Cracker di riso con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:2,g:12,z:1,ch:16,fi:4,ca:20,fe:1,mg:30,k2:350,na:60,zn:.6,fo:40,se:1,col:0}},{id:"tpl_1362",nome:"Uova sode con verdure crude",nome_en:"Hard-boiled eggs with raw vegetables",categoria:"Spuntino",porzioni:1,note:"Cuocere le uova sode per 9 minuti in acqua bollente, raffreddare e sgusciare. Tagliare a metà e servire con bastoncini di carota e cetriolo, un pizzico di sale e pepe.",note_en:"Hard-boil eggs for 9 minutes in boiling water, cool and shell. Cut in half and serve with carrot and cucumber sticks, a pinch of salt and pepper.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Carote",qt:"80g"},{nome:"Cetriolo",qt:"80g"}],_dbEntry:{n:"Uova sode con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:14,gs:3,g:10,z:4,ch:6,fi:2,ca:60,fe:1.8,mg:20,k2:320,na:140,zn:1.2,fo:45,se:20,col:370}},{id:"tpl_1363",nome:"Mix di frutta secca e semi",nome_en:"Nut and seed mix",categoria:"Spuntino",porzioni:6,note:"Mescolare in una ciotola mandorle, noci, nocciole, semi di zucca e semi di girasole. Conservare in un barattolo ermetico e consumare una porzione da 30 grammi al giorno.",note_en:"Mix almonds, walnuts, hazelnuts, pumpkin seeds and sunflower seeds in a bowl. Store in an airtight jar and eat a 30 gram portion per day.",ingredienti:[{nome:"Mandorle",qt:"80g"},{nome:"Noci",qt:"80g"},{nome:"Nocciole",qt:"60g"},{nome:"Semi di zucca",qt:"40g"},{nome:"Semi di girasole",qt:"40g"}],_dbEntry:{n:"Mix di frutta secca e semi (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1.5,g:17,z:1,ch:5,fi:3,ca:50,fe:1.5,mg:70,k2:220,na:2,zn:1.5,fo:20,se:5,col:0}},{id:"tpl_1364",nome:"Yogurt con granola fatta in casa",nome_en:"Yogurt with homemade granola",categoria:"Spuntino",porzioni:1,note:"Preparare la granola tostando in forno fiocchi d avena, miele, olio e frutta secca a pezzi fino a doratura. Servire lo yogurt in coppa con la granola sopra.",note_en:"Prepare granola by baking oat flakes, honey, oil and chopped nuts until golden. Serve yogurt in a bowl topped with granola.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Fiocchi di avena",qt:"30g"},{nome:"Miele",qt:"10g"},{nome:"Mandorle",qt:"15g"}],_dbEntry:{n:"Yogurt con granola fatta in casa (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:10,gs:2,g:9,z:14,ch:26,fi:3,ca:200,fe:1.2,mg:40,k2:280,na:60,zn:1,fo:15,se:6,col:12}},{id:"tpl_1365",nome:"Toast con ricotta e miele",nome_en:"Toast with ricotta and honey",categoria:"Spuntino",porzioni:1,note:"Tostare il pane integrale e spalmare la ricotta fresca. Aggiungere un cucchiaino di miele e una spolverata di cannella a piacere.",note_en:"Toast wholewheat bread and spread fresh ricotta. Add a teaspoon of honey and a dusting of cinnamon to taste.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Ricotta",qt:"80g"},{nome:"Miele",qt:"10g"},{nome:"Cannella",qt:"q.b."}],_dbEntry:{n:"Toast con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:11,gs:3,g:8,z:11,ch:28,fi:3,ca:150,fe:1.5,mg:30,k2:180,na:180,zn:1,fo:20,se:6,col:25}},{id:"tpl_1366",nome:"Bruschetta leggera con pomodoro",nome_en:"Light tomato bruschetta",categoria:"Spuntino",porzioni:2,note:"Tostare le fette di pane. Tagliare i pomodori a cubetti e condire con basilico, olio, sale e aglio tritato. Distribuire il composto sulle fette di pane appena tostate.",note_en:"Toast bread slices. Dice tomatoes and season with basil, oil, salt and minced garlic. Spoon mixture onto freshly toasted bread slices.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Pomodori",qt:"200g"},{nome:"Basilico",qt:"10g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Bruschetta leggera con pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:5,gs:1,g:5,z:3,ch:26,fi:2.5,ca:30,fe:1.5,mg:25,k2:220,na:220,zn:.8,fo:20,se:4,col:0}},{id:"tpl_1367",nome:"Frappè proteico alla fragola",nome_en:"Strawberry protein shake",categoria:"Spuntino",porzioni:1,note:"Frullare fragole fresche, latte, proteine in polvere e ghiaccio fino a ottenere una consistenza omogenea e cremosa. Servire subito in un bicchiere alto.",note_en:"Blend fresh strawberries, milk, protein powder and ice until smooth and creamy. Serve immediately in a tall glass.",ingredienti:[{nome:"Fragole",qt:"150g"},{nome:"Latte",qt:"200ml"},{nome:"Proteine in polvere",qt:"25g"},{nome:"Ghiaccio",qt:"q.b."}],_dbEntry:{n:"Frappè proteico alla fragola (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:24,gs:1.5,g:3,z:20,ch:22,fi:2,ca:280,fe:.8,mg:35,k2:450,na:120,zn:1,fo:20,se:5,col:10}},{id:"tpl_1368",nome:"Involtini di bresaola e formaggio spalmabile",nome_en:"Bresaola and cream cheese rolls",categoria:"Spuntino",porzioni:2,note:"Spalmare le fette di bresaola con formaggio fresco spalmabile e una foglia di rucola. Arrotolare strette e fissare con uno stecchino. Servire fresche.",note_en:"Spread bresaola slices with fresh cream cheese and a rocket leaf. Roll up tightly and secure with a toothpick. Serve chilled.",ingredienti:[{nome:"Bresaola",qt:"100g"},{nome:"Formaggio spalmabile",qt:"60g"},{nome:"Rucola",qt:"20g"}],_dbEntry:{n:"Involtini di bresaola e formaggio spalmabile (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:20,gs:3,g:7,z:.5,ch:2,fi:.3,ca:70,fe:1.8,mg:20,k2:280,na:520,zn:2,fo:8,se:15,col:35}},{id:"tpl_1369",nome:"Muffin ai mirtilli integrali",nome_en:"Wholewheat blueberry muffins",categoria:"Spuntino",porzioni:12,note:"Mescolare farina integrale, uova, yogurt, olio e zucchero di canna. Incorporare delicatamente i mirtilli. Versare negli stampini e cuocere in forno a 180 C per 22 minuti.",note_en:"Mix wholewheat flour, eggs, yogurt, oil and cane sugar. Gently fold in blueberries. Pour into muffin tins and bake at 180 C for 22 minutes.",ingredienti:[{nome:"Farina integrale",qt:"220g"},{nome:"Mirtilli",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Yogurt bianco",qt:"120g"},{nome:"Zucchero di canna",qt:"80g"},{nome:"Olio di semi",qt:"50ml"}],_dbEntry:{n:"Muffin ai mirtilli integrali (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1,g:6,z:9,ch:22,fi:2.5,ca:40,fe:1,mg:20,k2:100,na:80,zn:.5,fo:15,se:5,col:30}},{id:"tpl_1370",nome:"Barrette di frutta secca e cioccolato fondente",nome_en:"Nut and dark chocolate bars",categoria:"Spuntino",porzioni:10,note:"Sciogliere il cioccolato fondente a bagnomaria. Mescolare con frutta secca tritata, fiocchi d avena e miele. Versare in uno stampo rettangolare, raffreddare in frigo e tagliare a barrette.",note_en:"Melt dark chocolate in a double boiler. Mix with chopped nuts, oat flakes and honey. Pour into a rectangular mold, chill in the fridge and cut into bars.",ingredienti:[{nome:"Cioccolato fondente",qt:"100g"},{nome:"Fiocchi di avena",qt:"100g"},{nome:"Mandorle",qt:"80g"},{nome:"Miele",qt:"40g"}],_dbEntry:{n:"Barrette di frutta secca e cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:3,g:10,z:10,ch:18,fi:2.5,ca:30,fe:1.2,mg:40,k2:150,na:5,zn:.6,fo:10,se:3,col:0}},{id:"tpl_1371",nome:"Pancake proteici alla banana",nome_en:"Protein banana pancakes",categoria:"Colazione",porzioni:2,note:"Schiacciare la banana e mescolarla con uova, proteine in polvere e un pizzico di lievito. Versare piccole quantità in padella antiaderente e cuocere 2 minuti per lato fino a doratura.",note_en:"Mash banana and mix with eggs, protein powder and a pinch of baking powder. Pour small amounts into a non-stick pan and cook 2 minutes per side until golden.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Proteine in polvere",qt:"20g"},{nome:"Lievito",qt:"2g"}],_dbEntry:{n:"Pancake proteici alla banana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:22,gs:2,g:8,z:14,ch:22,fi:2,ca:60,fe:1.5,mg:35,k2:450,na:120,zn:1.2,fo:25,se:15,col:190}},{id:"tpl_1372",nome:"Overnight oats con frutti di bosco",nome_en:"Overnight oats with berries",categoria:"Colazione",porzioni:1,note:"Mescolare fiocchi d avena, latte, yogurt e un cucchiaino di miele in un barattolo. Lasciare riposare in frigo tutta la notte. Al mattino guarnire con frutti di bosco freschi.",note_en:"Mix oat flakes, milk, yogurt and a teaspoon of honey in a jar. Let rest in the fridge overnight. In the morning top with fresh berries.",ingredienti:[{nome:"Fiocchi di avena",qt:"50g"},{nome:"Latte",qt:"100ml"},{nome:"Yogurt bianco",qt:"80g"},{nome:"Miele",qt:"10g"},{nome:"Frutti di bosco",qt:"80g"}],_dbEntry:{n:"Overnight oats con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:13,gs:2.5,g:8,z:18,ch:46,fi:6,ca:220,fe:2,mg:60,k2:400,na:70,zn:1.2,fo:25,se:8,col:12}},{id:"tpl_1373",nome:"Uova strapazzate con avocado toast",nome_en:"Scrambled eggs with avocado toast",categoria:"Colazione",porzioni:1,note:"Strapazzare le uova in padella a fuoco basso mescolando continuamente. Tostare il pane e spalmare l avocado schiacciato con limone e sale. Servire le uova sopra il toast.",note_en:"Scramble eggs in a pan over low heat, stirring constantly. Toast bread and spread mashed avocado with lemon and salt. Serve eggs on top of the toast.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"0.5"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Uova strapazzate con avocado toast (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:17,gs:4,g:20,z:2,ch:24,fi:5,ca:60,fe:2.5,mg:45,k2:520,na:280,zn:1.5,fo:60,se:22,col:370}},{id:"tpl_1374",nome:"Smoothie bowl tropicale",nome_en:"Tropical smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare mango, banana congelata e latte di cocco fino a ottenere una consistenza densa. Versare in una ciotola e guarnire con granola, semi di chia e frutta fresca a fette.",note_en:"Blend mango, frozen banana and coconut milk until thick. Pour into a bowl and top with granola, chia seeds and sliced fresh fruit.",ingredienti:[{nome:"Mango",qt:"150g"},{nome:"Banana congelata",qt:"1"},{nome:"Latte di cocco",qt:"80ml"},{nome:"Granola",qt:"30g"},{nome:"Semi di chia",qt:"10g"}],_dbEntry:{n:"Smoothie bowl tropicale (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:7,gs:6,g:12,z:36,ch:58,fi:7,ca:70,fe:1.8,mg:60,k2:650,na:20,zn:1,fo:40,se:4,col:0}},{id:"tpl_1375",nome:"French toast integrale",nome_en:"Wholewheat French toast",categoria:"Colazione",porzioni:2,note:"Sbattere le uova con latte e cannella. Immergere le fette di pane integrale nel composto e cuocere in padella con poco burro fino a doratura su entrambi i lati. Servire con frutta fresca.",note_en:"Beat eggs with milk and cinnamon. Dip wholewheat bread slices in the mixture and cook in a pan with a little butter until golden on both sides. Serve with fresh fruit.",ingredienti:[{nome:"Pane integrale",qt:"4 fette"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"100ml"},{nome:"Cannella",qt:"q.b."},{nome:"Burro",qt:"15g"}],_dbEntry:{n:"French toast integrale (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:12,gs:3,g:11,z:6,ch:34,fi:4,ca:80,fe:2,mg:35,k2:220,na:280,zn:1,fo:30,se:15,col:200}},{id:"tpl_1376",nome:"Porridge di quinoa al cocco",nome_en:"Coconut quinoa porridge",categoria:"Colazione",porzioni:2,note:"Cuocere la quinoa in latte di cocco e acqua per 15 minuti mescolando di tanto in tanto. Dolcificare con miele e servire caldo guarnito con frutta fresca e cocco rapé.",note_en:"Cook quinoa in coconut milk and water for 15 minutes, stirring occasionally. Sweeten with honey and serve warm topped with fresh fruit and desiccated coconut.",ingredienti:[{nome:"Quinoa",qt:"100g"},{nome:"Latte di cocco",qt:"150ml"},{nome:"Acqua",qt:"150ml"},{nome:"Miele",qt:"15g"},{nome:"Cocco rapé",qt:"10g"}],_dbEntry:{n:"Porridge di quinoa al cocco (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:6,g:12,z:12,ch:40,fi:4,ca:35,fe:2.5,mg:70,k2:320,na:15,zn:1.5,fo:55,se:5,col:0}},{id:"tpl_1377",nome:"Yogurt bowl con frutta e granola",nome_en:"Yogurt bowl with fruit and granola",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt in una ciotola. Aggiungere frutta fresca a fette, granola e un cucchiaino di miele. Mescolare leggermente prima di servire.",note_en:"Pour yogurt into a bowl. Add sliced fresh fruit, granola and a teaspoon of honey. Stir lightly before serving.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Banana",qt:"0.5"},{nome:"Fragole",qt:"80g"},{nome:"Granola",qt:"30g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Yogurt bowl con frutta e granola (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:16,gs:2,g:8,z:26,ch:44,fi:4,ca:180,fe:1.5,mg:40,k2:480,na:60,zn:1.2,fo:35,se:8,col:12}},{id:"tpl_1378",nome:"Frittata di albumi con spinaci",nome_en:"Egg white frittata with spinach",categoria:"Colazione",porzioni:2,note:"Sbattere gli albumi con sale e pepe. Saltare gli spinaci in padella fino ad appassire. Versare gli albumi sugli spinaci e cuocere a fuoco basso coperto fino a rapprendere.",note_en:"Beat egg whites with salt and pepper. Sauté spinach in a pan until wilted. Pour egg whites over spinach and cook covered on low heat until set.",ingredienti:[{nome:"Albumi",qt:"6"},{nome:"Spinaci",qt:"150g"},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Frittata di albumi con spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:20,gs:.5,g:4,z:1,ch:3,fi:2,ca:80,fe:2,mg:35,k2:400,na:250,zn:.8,fo:120,se:20,col:0}},{id:"tpl_1379",nome:"Pane tostato con burro di mandorle e banana",nome_en:"Toast with almond butter and banana",categoria:"Colazione",porzioni:1,note:"Tostare il pane integrale. Spalmare il burro di mandorle e disporre sopra fette sottili di banana. Aggiungere una spolverata di cannella.",note_en:"Toast wholewheat bread. Spread almond butter and arrange thin banana slices on top. Add a dusting of cinnamon.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Burro di mandorle",qt:"20g"},{nome:"Banana",qt:"1"},{nome:"Cannella",qt:"q.b."}],_dbEntry:{n:"Pane tostato con burro di mandorle e banana (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:10,gs:1.5,g:12,z:18,ch:48,fi:6,ca:60,fe:2,mg:80,k2:550,na:220,zn:1,fo:35,se:5,col:0}},{id:"tpl_1380",nome:"Chia pudding alla vaniglia (versione 2)",nome_en:"Vanilla chia pudding (version 2)",categoria:"Colazione",porzioni:2,note:"Mescolare i semi di chia con latte, estratto di vaniglia e miele. Lasciare riposare in frigo per almeno 4 ore o tutta la notte, mescolando dopo i primi 10 minuti per evitare grumi. Servire con frutta fresca.",note_en:"Mix chia seeds with milk, vanilla extract and honey. Rest in the fridge for at least 4 hours or overnight, stirring after the first 10 minutes to avoid clumps. Serve with fresh fruit.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte",qt:"250ml"},{nome:"Miele",qt:"15g"},{nome:"Estratto di vaniglia",qt:"q.b."}],_dbEntry:{n:"Chia pudding alla vaniglia (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:9,gs:2,g:10,z:12,ch:20,fi:8,ca:280,fe:2,mg:70,k2:320,na:60,zn:1,fo:15,se:6,col:8}},{id:"tpl_1381",nome:"Muesli fatto in casa con frutta secca",nome_en:"Homemade muesli with dried fruit",categoria:"Colazione",porzioni:4,note:"Mescolare fiocchi d avena, frutta secca a pezzi, uvetta e semi in una ciotola. Conservare in un barattolo ermetico e servire con latte o yogurt.",note_en:"Mix oat flakes, chopped nuts, raisins and seeds in a bowl. Store in an airtight jar and serve with milk or yogurt.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Mandorle",qt:"40g"},{nome:"Uvetta",qt:"40g"},{nome:"Semi di girasole",qt:"20g"}],_dbEntry:{n:"Muesli fatto in casa con frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:6,gs:1,g:6,z:9,ch:32,fi:4,ca:30,fe:1.8,mg:50,k2:250,na:5,zn:1,fo:20,se:5,col:0}},{id:"tpl_1382",nome:"Crepes integrali con ricotta e miele",nome_en:"Wholewheat crepes with ricotta and honey",categoria:"Colazione",porzioni:2,note:"Preparare la pastella con farina integrale, uova e latte. Cuocere sottili crepes in padella antiaderente. Farcire con ricotta e un filo di miele, arrotolare e servire.",note_en:"Prepare batter with wholewheat flour, eggs and milk. Cook thin crepes in a non-stick pan. Fill with ricotta and a drizzle of honey, roll up and serve.",ingredienti:[{nome:"Farina integrale",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"150ml"},{nome:"Ricotta",qt:"150g"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Crepes integrali con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:16,gs:4,g:11,z:14,ch:42,fi:4,ca:180,fe:2,mg:45,k2:280,na:120,zn:1.2,fo:30,se:15,col:180}},{id:"tpl_1383",nome:"Uova alla benedict light",nome_en:"Light eggs benedict",categoria:"Colazione",porzioni:2,note:"Cuocere le uova in camicia in acqua leggermente acidulata. Tostare il pane integrale e adagiare le uova sopra. Preparare una salsa leggera con yogurt greco, senape e limone al posto della classica olandese.",note_en:"Poach eggs in slightly acidulated water. Toast wholewheat bread and place eggs on top. Prepare a light sauce with Greek yogurt, mustard and lemon instead of classic hollandaise.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Uova alla benedict light (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:22,gs:3,g:16,z:2,ch:22,fi:3,ca:100,fe:2.5,mg:35,k2:320,na:320,zn:1.5,fo:60,se:28,col:380}},{id:"tpl_1384",nome:"Toast con formaggio spalmabile e salmone affumicato",nome_en:"Toast with cream cheese and smoked salmon",categoria:"Colazione",porzioni:1,note:"Tostare il pane di segale. Spalmare il formaggio fresco e adagiare sopra le fette di salmone affumicato. Guarnire con erba cipollina e un giro di limone.",note_en:"Toast rye bread. Spread fresh cheese and lay smoked salmon slices on top. Garnish with chives and a squeeze of lemon.",ingredienti:[{nome:"Pane di segale",qt:"2 fette"},{nome:"Formaggio spalmabile",qt:"40g"},{nome:"Salmone affumicato",qt:"60g"},{nome:"Erba cipollina",qt:"5g"}],_dbEntry:{n:"Toast con formaggio spalmabile e salmone affumicato (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:4,g:13,z:2,ch:24,fi:3,ca:60,fe:1.5,mg:30,k2:280,na:680,zn:1,fo:20,se:20,col:35}},{id:"tpl_1385",nome:"Bowl di yogurt skyr con frutta fresca",nome_en:"Skyr yogurt bowl with fresh fruit",categoria:"Colazione",porzioni:1,note:"Versare lo skyr in una ciotola. Aggiungere frutta fresca tagliata a pezzi, un cucchiaio di semi misti e un filo di miele.",note_en:"Pour skyr into a bowl. Add chopped fresh fruit, a spoon of mixed seeds and a drizzle of honey.",ingredienti:[{nome:"Yogurt skyr",qt:"150g"},{nome:"Mirtilli",qt:"80g"},{nome:"Semi misti",qt:"15g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Bowl di yogurt skyr con frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:.5,g:4,z:20,ch:24,fi:3,ca:200,fe:1,mg:35,k2:280,na:70,zn:1,fo:15,se:10,col:8}},{id:"tpl_1386",nome:"Pancakes di farina d avena",nome_en:"Oat flour pancakes",categoria:"Colazione",porzioni:2,note:"Frullare fiocchi d avena fino a ottenere una farina fine. Mescolare con uova, latte e lievito. Cuocere in padella antiaderente piccole porzioni fino a doratura su entrambi i lati.",note_en:"Blend oat flakes into fine flour. Mix with eggs, milk and baking powder. Cook small portions in a non-stick pan until golden on both sides.",ingredienti:[{nome:"Fiocchi di avena",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Latte",qt:"100ml"},{nome:"Lievito",qt:"3g"}],_dbEntry:{n:"Pancakes di farina d avena (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:14,gs:2,g:9,z:4,ch:38,fi:5,ca:100,fe:2.2,mg:60,k2:320,na:150,zn:1.2,fo:25,se:15,col:190}},{id:"tpl_1387",nome:"Cereali integrali con latte e frutta",nome_en:"Wholegrain cereal with milk and fruit",categoria:"Colazione",porzioni:1,note:"Versare i cereali integrali in una ciotola con il latte freddo. Aggiungere frutta fresca a fette come banana o fragole per completare la colazione.",note_en:"Pour wholegrain cereal into a bowl with cold milk. Add fresh sliced fruit like banana or strawberries to complete breakfast.",ingredienti:[{nome:"Cereali integrali",qt:"50g"},{nome:"Latte",qt:"200ml"},{nome:"Banana",qt:"0.5"}],_dbEntry:{n:"Cereali integrali con latte e frutta (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:2,g:6,z:16,ch:44,fi:5,ca:250,fe:3,mg:50,k2:450,na:180,zn:1.5,fo:30,se:8,col:10}},{id:"tpl_1388",nome:"Brioche integrale fatta in casa",nome_en:"Homemade wholewheat brioche",categoria:"Colazione",porzioni:8,note:"Impastare farina integrale, lievito, latte tiepido, uova, burro e poco zucchero. Lasciare lievitare 2 ore. Formare le brioche e cuocere in forno a 180 C per 20 minuti.",note_en:"Knead wholewheat flour, yeast, warm milk, eggs, butter and a little sugar. Let rise 2 hours. Shape brioches and bake at 180 C for 20 minutes.",ingredienti:[{nome:"Farina integrale",qt:"400g"},{nome:"Latte",qt:"150ml"},{nome:"Uova",qt:"2"},{nome:"Burro",qt:"80g"},{nome:"Lievito di birra",qt:"10g"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Brioche integrale fatta in casa (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:4,g:11,z:6,ch:38,fi:3.5,ca:40,fe:1.8,mg:35,k2:180,na:120,zn:.8,fo:25,se:10,col:75}},{id:"tpl_1389",nome:"Smoothie proteico al cioccolato e banana",nome_en:"Chocolate banana protein smoothie",categoria:"Colazione",porzioni:1,note:"Frullare banana, latte, proteine al cioccolato e un cucchiaio di cacao amaro fino a ottenere una crema omogenea. Servire subito ben freddo.",note_en:"Blend banana, milk, chocolate protein powder and a spoon of unsweetened cocoa until smooth. Serve immediately, well chilled.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Latte",qt:"200ml"},{nome:"Proteine al cioccolato",qt:"25g"},{nome:"Cacao amaro",qt:"10g"}],_dbEntry:{n:"Smoothie proteico al cioccolato e banana (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:26,gs:2,g:5,z:24,ch:38,fi:4,ca:250,fe:1.8,mg:70,k2:650,na:150,zn:1.5,fo:30,se:8,col:10}},{id:"tpl_1390",nome:"Uova in camicia su letto di spinaci",nome_en:"Poached eggs on a bed of spinach",categoria:"Colazione",porzioni:2,note:"Saltare gli spinaci in padella con un filo di olio fino ad appassire. Cuocere le uova in camicia in acqua leggermente acidulata per 3 minuti. Adagiare le uova sugli spinaci e servire con pane tostato.",note_en:"Sauté spinach in a pan with a drizzle of oil until wilted. Poach eggs in slightly acidulated water for 3 minutes. Place eggs on the spinach and serve with toasted bread.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Spinaci",qt:"200g"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Uova in camicia su letto di spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:22,gs:3,g:15,z:2,ch:20,fi:4,ca:120,fe:3.5,mg:60,k2:600,na:280,zn:1.8,fo:150,se:28,col:370}},{id:"tpl_1391",nome:"Insalata di pollo e avocado",nome_en:"Chicken and avocado salad",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e tagliarlo a listarelle. Comporre l insalata con lattuga, avocado a fette, pomodorini e pollo. Condire con olio, limone e un pizzico di sale.",note_en:"Grill chicken breast and cut into strips. Assemble salad with lettuce, sliced avocado, cherry tomatoes and chicken. Dress with oil, lemon and a pinch of salt.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di pollo e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:32,gs:3,g:20,z:2,ch:8,fi:6,ca:40,fe:2,mg:55,k2:750,na:220,zn:1.5,fo:60,se:26,col:80}},{id:"tpl_1392",nome:"Insalata di ceci e tonno",nome_en:"Chickpea and tuna salad",categoria:"Insalata",porzioni:2,note:"Sciacquare i ceci lessati e mescolarli con il tonno sgocciolato, cipolla rossa a fettine sottili e prezzemolo. Condire con olio extravergine, limone e pepe.",note_en:"Rinse boiled chickpeas and mix with drained tuna, thinly sliced red onion and parsley. Dress with extra virgin oil, lemon and pepper.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Tonno sott olio",qt:"160g"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di ceci e tonno (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:28,gs:2,g:14,z:2,ch:34,fi:9,ca:60,fe:3,mg:60,k2:520,na:420,zn:2,fo:120,se:35,col:35}},{id:"tpl_1393",nome:"Insalata di farro e verdure grigliate",nome_en:"Farro salad with grilled vegetables",categoria:"Insalata",porzioni:4,note:"Lessare il farro e raffreddarlo. Grigliare zucchine, melanzane e peperoni a listarelle. Mescolare tutto con olio, aceto balsamico e basilico fresco spezzettato.",note_en:"Boil farro and let cool. Grill courgettes, eggplant and peppers into strips. Mix everything with oil, balsamic vinegar and torn fresh basil.",ingredienti:[{nome:"Farro perlato",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"100g"},{nome:"Basilico",qt:"15g"},{nome:"Aceto balsamico",qt:"15ml"}],_dbEntry:{n:"Insalata di farro e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:9,gs:1,g:6,z:5,ch:54,fi:9,ca:60,fe:2.5,mg:70,k2:480,na:120,zn:1.5,fo:40,se:8,col:0}},{id:"tpl_1394",nome:"Insalata caesar leggera",nome_en:"Light caesar salad",categoria:"Insalata",porzioni:2,note:"Grigliare il pollo e tagliarlo a striscioline. Preparare una salsa leggera con yogurt greco, acciughe, limone e parmigiano. Condire la lattuga romana con la salsa, pollo e crostini integrali.",note_en:"Grill chicken and cut into strips. Prepare a light dressing with Greek yogurt, anchovies, lemon and parmesan. Dress romaine lettuce with sauce, chicken and wholewheat croutons.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Lattuga romana",qt:"150g"},{nome:"Yogurt greco",qt:"60g"},{nome:"Acciughe",qt:"3"},{nome:"Parmigiano",qt:"30g"},{nome:"Pane integrale",qt:"50g"}],_dbEntry:{n:"Insalata caesar leggera (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:36,gs:3,g:11,z:3,ch:22,fi:3,ca:150,fe:2,mg:50,k2:600,na:520,zn:2,fo:60,se:35,col:85}},{id:"tpl_1395",nome:"Insalata di quinoa, feta e melograno",nome_en:"Quinoa salad with feta and pomegranate",categoria:"Insalata",porzioni:4,note:"Lessare la quinoa e lasciarla raffreddare. Mescolare con feta sbriciolata, chicchi di melograno, menta fresca e olio extravergine. Aggiustare di sale.",note_en:"Boil quinoa and let cool. Mix with crumbled feta, pomegranate seeds, fresh mint and extra virgin oil. Adjust salt.",ingredienti:[{nome:"Quinoa",qt:"250g"},{nome:"Feta",qt:"120g"},{nome:"Melograno",qt:"1"},{nome:"Menta",qt:"10g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata di quinoa, feta e melograno (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:13,gs:5,g:15,z:9,ch:44,fi:6,ca:180,fe:3,mg:80,k2:480,na:420,zn:1.5,fo:80,se:8,col:30}},{id:"tpl_1396",nome:"Insalata di polpo e patate (versione 3)",nome_en:"Octopus and potato salad (version 3)",categoria:"Insalata",porzioni:4,note:"Lessare il polpo in acqua con alloro finché tenero, circa 40 minuti. Lessare separatamente le patate e tagliarle a cubetti. Mescolare polpo e patate con prezzemolo, olio, limone e olive.",note_en:"Boil octopus in water with bay leaf until tender, about 40 minutes. Separately boil potatoes and dice. Mix octopus and potatoes with parsley, oil, lemon and olives.",ingredienti:[{nome:"Polpo",qt:"800g"},{nome:"Patate",qt:"300g"},{nome:"Prezzemolo",qt:"20g"},{nome:"Olive nere",qt:"50g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Insalata di polpo e patate (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:26,gs:1,g:9,z:2,ch:24,fi:2.5,ca:50,fe:3.5,mg:60,k2:650,na:380,zn:2.5,fo:35,se:60,col:70}},{id:"tpl_1397",nome:"Insalata di lenticchie e feta",nome_en:"Lentil and feta salad",categoria:"Insalata",porzioni:4,note:"Lessare le lenticchie e lasciarle raffreddare. Mescolare con feta a cubetti, pomodorini, cipolla rossa e prezzemolo. Condire con olio extravergine e succo di limone.",note_en:"Boil lentils and let cool. Mix with diced feta, cherry tomatoes, red onion and parsley. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Lenticchie",qt:"300g"},{nome:"Feta",qt:"100g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipolla rossa",qt:"0.5"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Insalata di lenticchie e feta (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:18,gs:4,g:11,z:4,ch:38,fi:12,ca:150,fe:5,mg:80,k2:650,na:380,zn:2,fo:180,se:8,col:25}},{id:"tpl_1398",nome:"Insalata di riso venere con gamberi",nome_en:"Black rice salad with prawns",categoria:"Insalata",porzioni:4,note:"Lessare il riso venere e lasciarlo raffreddare. Saltare i gamberi in padella con aglio. Mescolare riso, gamberi, avocado a cubetti e coriandolo. Condire con olio e lime.",note_en:"Boil black rice and let cool. Sauté prawns in a pan with garlic. Mix rice, prawns, diced avocado and coriander. Dress with oil and lime.",ingredienti:[{nome:"Riso venere",qt:"250g"},{nome:"Gamberi",qt:"300g"},{nome:"Avocado",qt:"1"},{nome:"Coriandolo",qt:"10g"},{nome:"Lime",qt:"1"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Insalata di riso venere con gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:24,gs:2,g:12,z:2,ch:50,fi:4,ca:60,fe:2,mg:70,k2:650,na:320,zn:1.5,fo:50,se:38,col:145}},{id:"tpl_1399",nome:"Insalata di finocchi, arance e olive",nome_en:"Fennel, orange and olive salad",categoria:"Insalata",porzioni:4,note:"Affettare finemente i finocchi. Pelare le arance a vivo e tagliarle a fette. Comporre l insalata con finocchi, arance e olive nere. Condire con olio extravergine e un pizzico di pepe.",note_en:"Thinly slice fennel. Peel oranges to the flesh and slice. Assemble salad with fennel, oranges and black olives. Dress with extra virgin oil and a pinch of pepper.",ingredienti:[{nome:"Finocchi",qt:"300g"},{nome:"Arance",qt:"3"},{nome:"Olive nere",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata di finocchi, arance e olive (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:2,gs:1,g:7,z:16,ch:20,fi:5,ca:80,fe:1,mg:30,k2:450,na:220,zn:.4,fo:60,se:1,col:0}},{id:"tpl_1400",nome:"Insalata di spinacini, noci e gorgonzola",nome_en:"Baby spinach salad with walnuts and gorgonzola",categoria:"Insalata",porzioni:2,note:"Disporre gli spinacini freschi in una ciotola. Aggiungere noci sgusciate, gorgonzola a cubetti e qualche fetta di pera. Condire con olio extravergine e un cucchiaino di miele.",note_en:"Arrange fresh baby spinach in a bowl. Add shelled walnuts, diced gorgonzola and a few pear slices. Dress with extra virgin oil and a teaspoon of honey.",ingredienti:[{nome:"Spinacini",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Gorgonzola",qt:"80g"},{nome:"Pera",qt:"1"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Insalata di spinacini, noci e gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:11,gs:7,g:24,z:12,ch:16,fi:4,ca:180,fe:2.5,mg:60,k2:520,na:420,zn:1.5,fo:120,se:8,col:25}},{id:"tpl_1401",nome:"Insalata di orzo perlato estiva",nome_en:"Summer pearl barley salad",categoria:"Insalata",porzioni:4,note:"Lessare l orzo perlato e raffreddarlo. Mescolare con pomodorini, cetrioli, feta e olive. Condire con olio extravergine, origano e succo di limone.",note_en:"Boil pearl barley and let cool. Mix with cherry tomatoes, cucumbers, feta and olives. Dress with extra virgin oil, oregano and lemon juice.",ingredienti:[{nome:"Orzo perlato",qt:"280g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cetrioli",qt:"150g"},{nome:"Feta",qt:"100g"},{nome:"Olive",qt:"50g"}],_dbEntry:{n:"Insalata di orzo perlato estiva (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:11,gs:4,g:10,z:5,ch:52,fi:8,ca:150,fe:2.5,mg:60,k2:420,na:420,zn:1.5,fo:40,se:8,col:25}},{id:"tpl_1402",nome:"Insalata di cavolo rosso e mela",nome_en:"Red cabbage and apple coleslaw",categoria:"Insalata",porzioni:4,note:"Affettare finemente il cavolo rosso e la mela a julienne. Mescolare con yogurt greco, senape, succo di limone e un pizzico di sale al posto della maionese classica.",note_en:"Thinly slice red cabbage and julienne the apple. Mix with Greek yogurt, mustard, lemon juice and a pinch of salt instead of classic mayonnaise.",ingredienti:[{nome:"Cavolo rosso",qt:"300g"},{nome:"Mela",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Insalata di cavolo rosso e mela (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4,gs:.5,g:1.5,z:14,ch:18,fi:4,ca:80,fe:1,mg:25,k2:350,na:80,zn:.4,fo:50,se:2,col:2}},{id:"tpl_1403",nome:"Insalata tiepida di fagiolini e uova",nome_en:"Warm green bean and egg salad",categoria:"Insalata",porzioni:2,note:"Lessare i fagiolini al dente e le uova sode. Tagliare le uova a spicchi. Condire i fagiolini tiepidi con olio, aceto e cipollotto tritato, guarnendo con le uova.",note_en:"Boil green beans al dente and hard-boil eggs. Cut eggs into wedges. Dress warm green beans with oil, vinegar and chopped spring onion, garnishing with eggs.",ingredienti:[{nome:"Fagiolini",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Cipollotto",qt:"1"},{nome:"Aceto di vino",qt:"10ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata tiepida di fagiolini e uova (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:3,g:14,z:4,ch:10,fi:4,ca:80,fe:2.5,mg:40,k2:450,na:150,zn:1.2,fo:90,se:22,col:280}},{id:"tpl_1404",nome:"Insalata di kamut con verdure croccanti",nome_en:"Kamut salad with crunchy vegetables",categoria:"Insalata",porzioni:4,note:"Lessare il kamut secondo le istruzioni e raffreddare. Mescolare con carote, sedano e ravanelli tagliati sottili. Condire con olio, limone e semi di sesamo tostati.",note_en:"Boil kamut per instructions and cool. Mix with thinly sliced carrots, celery and radishes. Dress with oil, lemon and toasted sesame seeds.",ingredienti:[{nome:"Kamut",qt:"250g"},{nome:"Carote",qt:"100g"},{nome:"Sedano",qt:"100g"},{nome:"Ravanelli",qt:"80g"},{nome:"Semi di sesamo",qt:"10g"}],_dbEntry:{n:"Insalata di kamut con verdure croccanti (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:9,gs:1,g:6,z:5,ch:54,fi:8,ca:60,fe:3,mg:70,k2:480,na:60,zn:1.5,fo:40,se:8,col:0}},{id:"tpl_1405",nome:"Insalata di rucola, pere e noci",nome_en:"Rocket, pear and walnut salad",categoria:"Insalata",porzioni:2,note:"Disporre la rucola in un piatto. Aggiungere fette sottili di pera, noci sgusciate e scaglie di parmigiano. Condire con olio extravergine e aceto balsamico.",note_en:"Arrange rocket on a plate. Add thin pear slices, shelled walnuts and parmesan shavings. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"80g"},{nome:"Pera",qt:"1"},{nome:"Noci",qt:"40g"},{nome:"Parmigiano",qt:"30g"},{nome:"Aceto balsamico",qt:"10ml"}],_dbEntry:{n:"Insalata di rucola, pere e noci (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:5,g:20,z:14,ch:16,fi:4,ca:180,fe:1.5,mg:50,k2:350,na:220,zn:1.2,fo:60,se:6,col:15}},{id:"tpl_1406",nome:"Insalata di gamberi e avocado",nome_en:"Prawn and avocado salad",categoria:"Insalata",porzioni:2,note:"Sbollentare i gamberi 2 minuti in acqua salata e raffreddare in acqua e ghiaccio. Tagliare l avocado a fette. Comporre l insalata con lattuga, gamberi e avocado. Condire con olio, limone e un pizzico di paprika.",note_en:"Blanch prawns 2 minutes in salted water and cool in ice water. Slice avocado. Assemble salad with lettuce, prawns and avocado. Dress with oil, lemon and a pinch of paprika.",ingredienti:[{nome:"Gamberi",qt:"300g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Paprika",qt:"q.b."}],_dbEntry:{n:"Insalata di gamberi e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:26,gs:2,g:14,z:2,ch:8,fi:6,ca:60,fe:1.5,mg:55,k2:650,na:280,zn:1.5,fo:70,se:38,col:180}},{id:"tpl_1407",nome:"Insalata mediterranea con feta e olive",nome_en:"Mediterranean salad with feta and olives",categoria:"Insalata",porzioni:4,note:"Tagliare a cubetti pomodori, cetrioli e peperoni. Mescolare con feta a cubetti, olive nere e cipolla rossa a fettine. Condire con olio extravergine e origano.",note_en:"Dice tomatoes, cucumbers and peppers. Mix with diced feta, black olives and sliced red onion. Dress with extra virgin oil and oregano.",ingredienti:[{nome:"Pomodori",qt:"250g"},{nome:"Cetrioli",qt:"200g"},{nome:"Peperoni",qt:"100g"},{nome:"Feta",qt:"120g"},{nome:"Olive nere",qt:"60g"},{nome:"Cipolla rossa",qt:"0.5"}],_dbEntry:{n:"Insalata mediterranea con feta e olive (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:9,gs:5,g:16,z:7,ch:12,fi:3,ca:220,fe:1.5,mg:40,k2:480,na:520,zn:1.2,fo:50,se:6,col:30}},{id:"tpl_1408",nome:"Insalata di sedano rapa e mela",nome_en:"Celeriac and apple salad",categoria:"Insalata",porzioni:4,note:"Tagliare il sedano rapa e la mela a julienne sottile. Condire subito con succo di limone per evitare l ossidazione. Aggiungere yogurt greco, senape e un pizzico di sale.",note_en:"Julienne celeriac and apple thinly. Dress immediately with lemon juice to prevent browning. Add Greek yogurt, mustard and a pinch of salt.",ingredienti:[{nome:"Sedano rapa",qt:"300g"},{nome:"Mela",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Senape",qt:"10g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di sedano rapa e mela (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:4,gs:.5,g:1.5,z:12,ch:20,fi:5,ca:70,fe:1,mg:25,k2:400,na:70,zn:.4,fo:40,se:2,col:2}},{id:"tpl_1409",nome:"Insalata di legumi misti",nome_en:"Mixed legume salad",categoria:"Insalata",porzioni:4,note:"Mescolare ceci, fagioli borlotti e lenticchie lessati in una ciotola capiente. Aggiungere sedano, carota a cubetti e prezzemolo. Condire con olio extravergine e aceto di mele.",note_en:"Mix boiled chickpeas, borlotti beans and lentils in a large bowl. Add celery, diced carrot and parsley. Dress with extra virgin oil and apple vinegar.",ingredienti:[{nome:"Ceci lessati",qt:"150g"},{nome:"Fagioli borlotti",qt:"150g"},{nome:"Lenticchie",qt:"150g"},{nome:"Sedano",qt:"80g"},{nome:"Carota",qt:"80g"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Insalata di legumi misti (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:.5,g:5,z:5,ch:42,fi:14,ca:100,fe:4.5,mg:80,k2:700,na:180,zn:2.2,fo:180,se:5,col:0}},{id:"tpl_1410",nome:"Insalata waldorf light",nome_en:"Light waldorf salad",categoria:"Insalata",porzioni:4,note:"Tagliare mele e sedano a cubetti. Aggiungere noci sgusciate e uvetta. Condire con una salsa leggera di yogurt greco e succo di limone al posto della maionese classica.",note_en:"Dice apples and celery. Add shelled walnuts and raisins. Dress with a light sauce of Greek yogurt and lemon juice instead of classic mayonnaise.",ingredienti:[{nome:"Mele",qt:"2"},{nome:"Sedano",qt:"150g"},{nome:"Noci",qt:"50g"},{nome:"Uvetta",qt:"30g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Insalata waldorf light (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:6,gs:1.5,g:12,z:22,ch:26,fi:5,ca:80,fe:1,mg:45,k2:420,na:40,zn:.8,fo:20,se:3,col:2}},{id:"tpl_1411",nome:"Tagliere di formaggi e miele",nome_en:"Cheese board with honey",categoria:"Antipasto",porzioni:4,note:"Disporre su un tagliere una selezione di formaggi misti a pezzi o fette. Accompagnare con miele, noci sgusciate e qualche fetta di pera fresca.",note_en:"Arrange a selection of mixed cheeses cut into pieces or slices on a board. Accompany with honey, shelled walnuts and a few fresh pear slices.",ingredienti:[{nome:"Formaggi misti",qt:"300g"},{nome:"Miele",qt:"40g"},{nome:"Noci",qt:"50g"},{nome:"Pera",qt:"1"}],_dbEntry:{n:"Tagliere di formaggi e miele (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:11,g:26,z:14,ch:16,fi:1.5,ca:450,fe:1,mg:35,k2:220,na:620,zn:2.5,fo:20,se:15,col:70}},{id:"tpl_1412",nome:"Involtini di melanzane grigliate con ricotta",nome_en:"Grilled eggplant rolls with ricotta",categoria:"Antipasto",porzioni:4,note:"Grigliare le fette di melanzana senza olio fino a doratura. Farcire con ricotta mescolata a basilico e un pizzico di sale. Arrotolare e disporre su un piatto da portata.",note_en:"Grill eggplant slices without oil until golden. Fill with ricotta mixed with basil and a pinch of salt. Roll up and arrange on a serving plate.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Ricotta",qt:"250g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Involtini di melanzane grigliate con ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:9,gs:3,g:11,z:5,ch:8,fi:3,ca:150,fe:.8,mg:25,k2:350,na:120,zn:.8,fo:25,se:6,col:25}},{id:"tpl_1413",nome:"Crostini con paté di fegatini",nome_en:"Crostini with chicken liver pâté",categoria:"Antipasto",porzioni:4,note:"Rosolare i fegatini di pollo con cipolla, salvia e capperi. Frullare fino a ottenere un composto omogeneo con un filo di brodo. Spalmare sui crostini di pane tostato.",note_en:"Brown chicken livers with onion, sage and capers. Blend until smooth with a splash of stock. Spread on toasted bread crostini.",ingredienti:[{nome:"Fegatini di pollo",qt:"250g"},{nome:"Cipolla",qt:"0.5"},{nome:"Capperi",qt:"20g"},{nome:"Salvia",qt:"4 foglie"},{nome:"Pane casereccio",qt:"150g"}],_dbEntry:{n:"Crostini con paté di fegatini (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:16,gs:2,g:9,z:2,ch:26,fi:2,ca:30,fe:6,mg:30,k2:380,na:380,zn:2.5,fo:250,se:20,col:280}},{id:"tpl_1414",nome:"Cocktail di gamberi",nome_en:"Prawn cocktail",categoria:"Antipasto",porzioni:4,note:"Sbollentare i gamberi 2 minuti e raffreddare. Preparare una salsa leggera con yogurt greco, ketchup e un goccio di brandy. Servire i gamberi su un letto di lattuga con la salsa.",note_en:"Blanch prawns 2 minutes and cool. Prepare a light sauce with Greek yogurt, ketchup and a splash of brandy. Serve prawns on a bed of lettuce with the sauce.",ingredienti:[{nome:"Gamberi",qt:"400g"},{nome:"Lattuga",qt:"100g"},{nome:"Yogurt greco",qt:"60g"},{nome:"Ketchup",qt:"30g"}],_dbEntry:{n:"Cocktail di gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:26,gs:.5,g:3,z:5,ch:10,fi:1,ca:80,fe:1,mg:45,k2:400,na:420,zn:1.5,fo:35,se:38,col:200}},{id:"tpl_1415",nome:"Polpette di melanzane al forno",nome_en:"Baked eggplant balls",categoria:"Antipasto",porzioni:4,note:"Cuocere le melanzane a vapore e schiacciarle. Mescolare con pangrattato, uovo, parmigiano e prezzemolo. Formare le polpette e cuocere in forno a 200 C per 20 minuti.",note_en:"Steam eggplant and mash. Mix with breadcrumbs, egg, parmesan and parsley. Shape into balls and bake at 200 C for 20 minutes.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Pangrattato",qt:"80g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano",qt:"50g"},{nome:"Prezzemolo",qt:"15g"}],_dbEntry:{n:"Polpette di melanzane al forno (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:8,gs:2,g:6,z:5,ch:20,fi:4,ca:120,fe:1.2,mg:30,k2:350,na:220,zn:1,fo:30,se:8,col:45}},{id:"tpl_1416",nome:"Bruschette miste",nome_en:"Mixed bruschette",categoria:"Antipasto",porzioni:4,note:"Tostare fette di pane casereccio. Preparare tre farciture: pomodoro e basilico, funghi trifolati e formaggio spalmabile con rucola. Distribuire sulle fette e servire subito.",note_en:"Toast slices of country bread. Prepare three toppings: tomato and basil, sautéed mushrooms, and spreadable cheese with rocket. Top slices and serve immediately.",ingredienti:[{nome:"Pane casereccio",qt:"8 fette"},{nome:"Pomodori",qt:"150g"},{nome:"Funghi champignon",qt:"150g"},{nome:"Formaggio spalmabile",qt:"80g"},{nome:"Rucola",qt:"30g"}],_dbEntry:{n:"Bruschette miste (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:3,g:9,z:4,ch:38,fi:3,ca:60,fe:1.8,mg:35,k2:320,na:320,zn:1,fo:35,se:6,col:15}},{id:"tpl_1417",nome:"Carpaccio di salmone con agrumi",nome_en:"Salmon carpaccio with citrus",categoria:"Antipasto",porzioni:4,note:"Affettare sottilmente il salmone fresco e disporlo su un piatto. Condire con succo di lime e arancia, un filo di olio, sale e pepe rosa. Guarnire con scorza di agrumi grattugiata.",note_en:"Thinly slice fresh salmon and arrange on a plate. Dress with lime and orange juice, a drizzle of oil, salt and pink pepper. Garnish with grated citrus zest.",ingredienti:[{nome:"Salmone fresco",qt:"350g"},{nome:"Lime",qt:"1"},{nome:"Arancia",qt:"1"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Pepe rosa",qt:"q.b."}],_dbEntry:{n:"Carpaccio di salmone con agrumi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:2,g:14,z:3,ch:4,fi:.5,ca:20,fe:.8,mg:30,k2:450,na:60,zn:.8,fo:20,se:30,col:45}},{id:"tpl_1418",nome:"Flan di verdure con fonduta leggera",nome_en:"Vegetable flan with light fondue",categoria:"Antipasto",porzioni:4,note:"Cuocere le verdure a vapore e frullarle con uova e poco latte. Versare negli stampini e cuocere a bagnomaria in forno a 170 C per 30 minuti. Servire con una fonduta leggera di formaggio.",note_en:"Steam vegetables and blend with eggs and a little milk. Pour into molds and bake in a water bath at 170 C for 30 minutes. Serve with a light cheese fondue.",ingredienti:[{nome:"Zucchine",qt:"300g"},{nome:"Uova",qt:"3"},{nome:"Latte",qt:"100ml"},{nome:"Formaggio grattugiato",qt:"40g"}],_dbEntry:{n:"Flan di verdure con fonduta leggera (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:11,gs:3,g:9,z:3,ch:6,fi:2,ca:120,fe:1,mg:25,k2:320,na:180,zn:1,fo:45,se:18,col:200}},{id:"tpl_1419",nome:"Involtini di zucchine con formaggio fresco",nome_en:"Courgette rolls with fresh cheese",categoria:"Antipasto",porzioni:4,note:"Grigliare fette sottili di zucchina. Farcire con formaggio fresco spalmabile e menta. Arrotolare e fissare con uno stecchino. Servire freddi o a temperatura ambiente.",note_en:"Grill thin courgette slices. Fill with fresh spreadable cheese and mint. Roll up and secure with a toothpick. Serve cold or at room temperature.",ingredienti:[{nome:"Zucchine",qt:"400g"},{nome:"Formaggio spalmabile",qt:"150g"},{nome:"Menta",qt:"10g"}],_dbEntry:{n:"Involtini di zucchine con formaggio fresco (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:8,gs:4,g:11,z:4,ch:5,fi:1.5,ca:120,fe:.6,mg:20,k2:300,na:150,zn:.6,fo:25,se:5,col:30}},{id:"tpl_1420",nome:"Crema di zucca con crostini",nome_en:"Pumpkin cream with croutons",categoria:"Antipasto",porzioni:4,note:"Cuocere la zucca a cubetti con cipolla in brodo vegetale per 25 minuti. Frullare fino a ottenere una crema liscia. Servire con crostini di pane tostato e un filo di olio.",note_en:"Cook diced pumpkin with onion in vegetable stock for 25 minutes. Blend until smooth. Serve with toasted bread croutons and a drizzle of oil.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Cipolla",qt:"0.5"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane casereccio",qt:"100g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Crema di zucca con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:1,g:6,z:8,ch:30,fi:3,ca:60,fe:1.2,mg:35,k2:450,na:280,zn:.6,fo:30,se:3,col:0}},{id:"tpl_1421",nome:"Tartare di tonno con avocado (versione 2)",nome_en:"Tuna tartare with avocado (version 2)",categoria:"Antipasto",porzioni:4,note:"Tagliare il tonno fresco a cubetti piccoli. Condire con salsa di soia, olio di sesamo e succo di lime. Servire su una base di avocado schiacciato guarnendo con semi di sesamo.",note_en:"Cut fresh tuna into small cubes. Dress with soy sauce, sesame oil and lime juice. Serve on a bed of mashed avocado, garnishing with sesame seeds.",ingredienti:[{nome:"Tonno fresco",qt:"350g"},{nome:"Avocado",qt:"1"},{nome:"Salsa di soia",qt:"20ml"},{nome:"Olio di sesamo",qt:"10ml"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Tartare di tonno con avocado (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:24,gs:2,g:15,z:2,ch:6,fi:4,ca:20,fe:1.2,mg:45,k2:550,na:480,zn:.8,fo:35,se:60,col:40}},{id:"tpl_1422",nome:"Frittatine di verdure in miniatura",nome_en:"Mini vegetable frittatas",categoria:"Antipasto",porzioni:6,note:"Sbattere le uova con verdure miste a cubetti e parmigiano. Versare in stampini da muffin e cuocere in forno a 180 C per 18 minuti finché sode. Servire tiepide.",note_en:"Beat eggs with mixed diced vegetables and parmesan. Pour into muffin tins and bake at 180 C for 18 minutes until set. Serve warm.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Zucchine",qt:"100g"},{nome:"Peperoni",qt:"100g"},{nome:"Parmigiano",qt:"40g"}],_dbEntry:{n:"Frittatine di verdure in miniatura (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:9,gs:2,g:7,z:2,ch:3,fi:1,ca:70,fe:1,mg:15,k2:180,na:150,zn:.8,fo:25,se:15,col:190}},{id:"tpl_1423",nome:"Chips di verdure al forno con salsa yogurt",nome_en:"Baked vegetable chips with yogurt sauce",categoria:"Antipasto",porzioni:4,note:"Affettare sottilmente barbabietola, carota e zucchina. Condire con olio e cuocere in forno a 180 C per 20 minuti finché croccanti. Servire con una salsa di yogurt greco ed erba cipollina.",note_en:"Thinly slice beetroot, carrot and courgette. Season with oil and bake at 180 C for 20 minutes until crispy. Serve with a Greek yogurt and chive sauce.",ingredienti:[{nome:"Barbabietola",qt:"150g"},{nome:"Carota",qt:"150g"},{nome:"Zucchina",qt:"150g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Chips di verdure al forno con salsa yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:5,gs:.5,g:5,z:9,ch:16,fi:4,ca:80,fe:1,mg:25,k2:420,na:80,zn:.5,fo:35,se:2,col:2}},{id:"tpl_1424",nome:"Antipasto di mare misto al forno",nome_en:"Baked mixed seafood antipasto",categoria:"Antipasto",porzioni:4,note:"Disporre in teglia cozze, vongole e gamberi con aglio, prezzemolo e un filo di olio. Cuocere in forno a 200 C per 12 minuti finché i molluschi si aprono. Servire caldo con limone.",note_en:"Arrange mussels, clams and prawns in a baking dish with garlic, parsley and a drizzle of oil. Bake at 200 C for 12 minutes until shellfish open. Serve hot with lemon.",ingredienti:[{nome:"Cozze",qt:"300g"},{nome:"Vongole",qt:"300g"},{nome:"Gamberi",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"15g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Antipasto di mare misto al forno (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:26,gs:.5,g:6,z:1,ch:5,fi:.5,ca:80,fe:4,mg:50,k2:400,na:480,zn:2,fo:30,se:45,col:110}},{id:"tpl_1425",nome:"Terrina di verdure grigliate",nome_en:"Grilled vegetable terrine",categoria:"Antipasto",porzioni:6,note:"Grigliare melanzane, zucchine e peperoni a fette. Alternare gli strati in uno stampo da plumcake foderato di pellicola. Pressare, raffreddare in frigo 3 ore e affettare per servire.",note_en:"Grill eggplant, courgette and pepper slices. Layer alternately in a loaf tin lined with cling film. Press, chill in the fridge 3 hours and slice to serve.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Zucchine",qt:"300g"},{nome:"Peperoni",qt:"250g"},{nome:"Basilico",qt:"15g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Terrina di verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2,gs:.5,g:6,z:6,ch:8,fi:3,ca:25,fe:.7,mg:20,k2:300,na:80,zn:.4,fo:35,se:1,col:0}},{id:"tpl_1426",nome:"Uova ripiene light",nome_en:"Light stuffed eggs",categoria:"Antipasto",porzioni:4,note:"Lessare le uova, tagliarle a metà e prelevare i tuorli. Mescolare i tuorli con yogurt greco, senape ed erba cipollina. Farcire gli albumi con il composto usando una tasca da pasticcere.",note_en:"Boil eggs, halve and remove yolks. Mix yolks with Greek yogurt, mustard and chives. Fill egg whites with the mixture using a piping bag.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Yogurt greco",qt:"40g"},{nome:"Senape",qt:"10g"},{nome:"Erba cipollina",qt:"10g"}],_dbEntry:{n:"Uova ripiene light (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:12,gs:2.5,g:9,z:1,ch:2,fi:.2,ca:50,fe:1.6,mg:15,k2:180,na:150,zn:1,fo:40,se:20,col:370}},{id:"tpl_1427",nome:"Salmone marinato con agrumi",nome_en:"Citrus-marinated salmon",categoria:"Antipasto",porzioni:4,note:"Marinare il salmone fresco con sale, zucchero, succo e scorza di agrumi per almeno 6 ore in frigo. Sciacquare, asciugare e affettare sottilmente prima di servire.",note_en:"Marinate fresh salmon with salt, sugar, citrus juice and zest for at least 6 hours in the fridge. Rinse, pat dry and slice thinly before serving.",ingredienti:[{nome:"Salmone fresco",qt:"400g"},{nome:"Sale",qt:"40g"},{nome:"Zucchero",qt:"20g"},{nome:"Arancia",qt:"1"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Salmone marinato con agrumi (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:22,gs:2,g:15,z:3,ch:3,fi:.2,ca:15,fe:.6,mg:28,k2:420,na:580,zn:.6,fo:20,se:32,col:50}},{id:"tpl_1428",nome:"Involtini di prosciutto e melone",nome_en:"Ham and melon rolls",categoria:"Antipasto",porzioni:4,note:"Tagliare il melone a fette sottili. Avvolgere ogni fetta con una fetta di prosciutto crudo. Disporre su un piatto da portata e servire fresco.",note_en:"Cut melon into thin slices. Wrap each slice with a slice of raw ham. Arrange on a serving plate and serve chilled.",ingredienti:[{nome:"Melone",qt:"1"},{nome:"Prosciutto crudo",qt:"150g"}],_dbEntry:{n:"Involtini di prosciutto e melone (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:14,gs:2,g:6,z:10,ch:12,fi:1,ca:15,fe:.8,mg:20,k2:350,na:680,zn:1.5,fo:20,se:15,col:35}},{id:"tpl_1429",nome:"Vellutata di carciofi con crostini",nome_en:"Artichoke velouté with croutons",categoria:"Antipasto",porzioni:4,note:"Pulire i carciofi e cuocerli con cipolla e patata in brodo vegetale per 25 minuti. Frullare fino a ottenere una crema vellutata. Servire con crostini di pane e un filo di olio.",note_en:"Clean artichokes and cook with onion and potato in vegetable stock for 25 minutes. Blend until velvety. Serve with bread croutons and a drizzle of oil.",ingredienti:[{nome:"Carciofi",qt:"400g"},{nome:"Patata",qt:"150g"},{nome:"Cipolla",qt:"0.5"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pane casereccio",qt:"100g"}],_dbEntry:{n:"Vellutata di carciofi con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:.8,g:5,z:4,ch:32,fi:6,ca:60,fe:1.8,mg:40,k2:480,na:280,zn:.8,fo:60,se:3,col:0}},{id:"tpl_1430",nome:"Cesto di verdure crude in pinzimonio",nome_en:"Raw vegetable basket with pinzimonio dip",categoria:"Antipasto",porzioni:4,note:"Tagliare a bastoncini carote, sedano, finocchio e peperoni. Preparare il pinzimonio con olio extravergine, sale e pepe in ciotoline individuali. Servire le verdure crude con la salsa per intingere.",note_en:"Cut carrots, celery, fennel and peppers into sticks. Prepare pinzimonio with extra virgin oil, salt and pepper in individual bowls. Serve raw vegetables with the dipping sauce.",ingredienti:[{nome:"Carote",qt:"150g"},{nome:"Sedano",qt:"150g"},{nome:"Finocchio",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cesto di verdure crude in pinzimonio (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2,gs:1,g:9,z:6,ch:8,fi:4,ca:60,fe:.8,mg:25,k2:450,na:120,zn:.4,fo:50,se:1,col:0}},{id:"tpl_1431",nome:"Tiramisu light con yogurt",nome_en:"Light yogurt tiramisu",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco con un cucchiaio di zucchero e mascarpone in piccola quantità. Inzuppare leggermente i savoiardi nel caffè. Alternare strati di savoiardi e crema, spolverare con cacao amaro e riposare in frigo 4 ore.",note_en:"Mix Greek yogurt with a spoon of sugar and a small amount of mascarpone. Lightly dip ladyfingers in coffee. Alternate layers of ladyfingers and cream, dust with unsweetened cocoa and chill 4 hours.",ingredienti:[{nome:"Yogurt greco",qt:"400g"},{nome:"Mascarpone",qt:"100g"},{nome:"Savoiardi",qt:"200g"},{nome:"Caffè",qt:"200ml"},{nome:"Cacao amaro",qt:"15g"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Tiramisu light con yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:5,g:10,z:18,ch:32,fi:1,ca:120,fe:1,mg:25,k2:220,na:80,zn:.8,fo:15,se:5,col:60}},{id:"tpl_1432",nome:"Torta di mele senza burro",nome_en:"Butter-free apple cake",categoria:"Dolce",porzioni:8,note:"Mescolare farina, uova, zucchero, olio di semi e lievito. Aggiungere le mele tagliate a fette sottili. Versare in una tortiera e cuocere in forno a 180 C per 40 minuti.",note_en:"Mix flour, eggs, sugar, seed oil and baking powder. Add thinly sliced apples. Pour into a cake tin and bake at 180 C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Mele",qt:"4"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"150g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di mele senza burro (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:1,g:9,z:22,ch:44,fi:2.5,ca:30,fe:1,mg:15,k2:180,na:60,zn:.4,fo:20,se:8,col:60}},{id:"tpl_1433",nome:"Cheesecake proteica al forno",nome_en:"Baked protein cheesecake",categoria:"Dolce",porzioni:8,note:"Frullare fiocchi d avena e usarli come base pressata in uno stampo. Mescolare formaggio spalmabile light, proteine in polvere, uova e un dolcificante. Versare sulla base e cuocere in forno a 160 C per 40 minuti.",note_en:"Blend oat flakes and use as a pressed base in a mold. Mix light cream cheese, protein powder, eggs and a sweetener. Pour over the base and bake at 160 C for 40 minutes.",ingredienti:[{nome:"Formaggio spalmabile light",qt:"400g"},{nome:"Proteine in polvere",qt:"50g"},{nome:"Uova",qt:"3"},{nome:"Fiocchi di avena",qt:"100g"},{nome:"Dolcificante",qt:"q.b."}],_dbEntry:{n:"Cheesecake proteica al forno (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:16,gs:4,g:11,z:6,ch:14,fi:1.5,ca:120,fe:1,mg:20,k2:150,na:220,zn:.8,fo:12,se:10,col:110}},{id:"tpl_1434",nome:"Mousse al cioccolato fondente e avocado",nome_en:"Dark chocolate and avocado mousse",categoria:"Dolce",porzioni:4,note:"Frullare avocado maturo con cioccolato fondente fuso, cacao amaro e un cucchiaio di miele fino a ottenere una consistenza cremosa. Raffreddare in frigo 2 ore prima di servire.",note_en:"Blend ripe avocado with melted dark chocolate, unsweetened cocoa and a spoon of honey until creamy. Chill in the fridge 2 hours before serving.",ingredienti:[{nome:"Avocado",qt:"2"},{nome:"Cioccolato fondente",qt:"100g"},{nome:"Cacao amaro",qt:"15g"},{nome:"Miele",qt:"30g"}],_dbEntry:{n:"Mousse al cioccolato fondente e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:4,gs:5,g:16,z:14,ch:18,fi:6,ca:30,fe:2,mg:60,k2:550,na:5,zn:1,fo:35,se:2,col:0}},{id:"tpl_1435",nome:"Crostata di frutta con crema pasticcera light",nome_en:"Fruit tart with light pastry cream",categoria:"Dolce",porzioni:8,note:"Preparare una frolla con farina, poco burro, uova e zucchero. Cuocere in bianco la base. Preparare una crema pasticcera con latte scremato, uova e amido di mais. Farcire con la crema e guarnire con frutta fresca.",note_en:"Prepare shortcrust with flour, a little butter, eggs and sugar. Blind bake the base. Prepare pastry cream with skimmed milk, eggs and cornstarch. Fill with cream and top with fresh fruit.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Burro",qt:"60g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"100g"},{nome:"Latte scremato",qt:"400ml"},{nome:"Amido di mais",qt:"40g"},{nome:"Frutta fresca mista",qt:"300g"}],_dbEntry:{n:"Crostata di frutta con crema pasticcera light (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:6,gs:3,g:8,z:20,ch:42,fi:2,ca:70,fe:1,mg:20,k2:220,na:60,zn:.5,fo:20,se:10,col:80}},{id:"tpl_1436",nome:"Budino di chia e cioccolato",nome_en:"Chia and chocolate pudding",categoria:"Dolce",porzioni:2,note:"Mescolare i semi di chia con latte, cacao amaro e un cucchiaio di miele. Lasciare riposare in frigo almeno 4 ore mescolando dopo i primi 10 minuti. Servire con frutti di bosco freschi.",note_en:"Mix chia seeds with milk, unsweetened cocoa and a spoon of honey. Rest in the fridge at least 4 hours, stirring after the first 10 minutes. Serve with fresh berries.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte",qt:"250ml"},{nome:"Cacao amaro",qt:"15g"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Budino di chia e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:8,gs:2,g:9,z:14,ch:20,fi:9,ca:270,fe:2.5,mg:80,k2:350,na:60,zn:1,fo:15,se:6,col:8}},{id:"tpl_1437",nome:"Torta di carote e mandorle (versione 3)",nome_en:"Carrot and almond cake (version 3)",categoria:"Dolce",porzioni:8,note:"Grattugiare le carote finemente. Mescolare con farina di mandorle, uova, zucchero di canna e lievito. Versare in una tortiera e cuocere in forno a 170 C per 45 minuti.",note_en:"Finely grate carrots. Mix with almond flour, eggs, cane sugar and baking powder. Pour into a cake tin and bake at 170 C for 45 minutes.",ingredienti:[{nome:"Carote",qt:"250g"},{nome:"Farina di mandorle",qt:"150g"},{nome:"Farina 00",qt:"100g"},{nome:"Uova",qt:"4"},{nome:"Zucchero di canna",qt:"120g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di carote e mandorle (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:8,gs:1.5,g:14,z:16,ch:32,fi:3,ca:60,fe:1.5,mg:45,k2:280,na:60,zn:.8,fo:30,se:8,col:80}},{id:"tpl_1438",nome:"Semifreddo allo yogurt e frutti di bosco",nome_en:"Yogurt and berry semifreddo",categoria:"Dolce",porzioni:6,note:"Montare gli albumi a neve con lo zucchero. Incorporare delicatamente lo yogurt greco e i frutti di bosco frullati. Versare in uno stampo e congelare per almeno 5 ore. Servire a fette.",note_en:"Whip egg whites to stiff peaks with sugar. Gently fold in Greek yogurt and blended berries. Pour into a mold and freeze at least 5 hours. Serve sliced.",ingredienti:[{nome:"Yogurt greco",qt:"300g"},{nome:"Albumi",qt:"3"},{nome:"Zucchero",qt:"80g"},{nome:"Frutti di bosco",qt:"200g"}],_dbEntry:{n:"Semifreddo allo yogurt e frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:9,gs:.5,g:2,z:20,ch:22,fi:2,ca:120,fe:.5,mg:20,k2:220,na:40,zn:.6,fo:15,se:4,col:2}},{id:"tpl_1439",nome:"Biscotti integrali all avena e miele",nome_en:"Wholewheat oat and honey biscuits",categoria:"Dolce",porzioni:20,note:"Mescolare fiocchi d avena, farina integrale, miele, olio di semi e un uovo. Formare piccole palline e schiacciarle su una teglia foderata. Cuocere in forno a 170 C per 15 minuti.",note_en:"Mix oat flakes, wholewheat flour, honey, seed oil and an egg. Shape small balls and flatten on a lined tray. Bake at 170 C for 15 minutes.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Farina integrale",qt:"150g"},{nome:"Miele",qt:"100g"},{nome:"Olio di semi",qt:"60ml"},{nome:"Uova",qt:"1"}],_dbEntry:{n:"Biscotti integrali all avena e miele (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:.5,g:4,z:7,ch:16,fi:1.5,ca:10,fe:.8,mg:15,k2:80,na:10,zn:.4,fo:8,se:3,col:10}},{id:"tpl_1440",nome:"Panna cotta light alla vaniglia",nome_en:"Light vanilla panna cotta",categoria:"Dolce",porzioni:4,note:"Scaldare il latte scremato con estratto di vaniglia e poco zucchero. Sciogliere la gelatina ammollata nel latte caldo. Versare negli stampini e raffreddare in frigo per almeno 4 ore. Servire con salsa di frutti di bosco.",note_en:"Heat skimmed milk with vanilla extract and a little sugar. Dissolve soaked gelatin in the warm milk. Pour into molds and chill in the fridge for at least 4 hours. Serve with berry sauce.",ingredienti:[{nome:"Latte scremato",qt:"400ml"},{nome:"Zucchero",qt:"50g"},{nome:"Gelatina in fogli",qt:"8g"},{nome:"Frutti di bosco",qt:"150g"},{nome:"Estratto di vaniglia",qt:"q.b."}],_dbEntry:{n:"Panna cotta light alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:6,gs:.2,g:1,z:20,ch:24,fi:1.5,ca:180,fe:.4,mg:20,k2:250,na:60,zn:.5,fo:10,se:4,col:5}},{id:"tpl_1441",nome:"Torta soffice al limone",nome_en:"Soft lemon cake",categoria:"Dolce",porzioni:8,note:"Montare le uova con lo zucchero fino a renderle spumose. Incorporare farina, olio di semi, succo e scorza di limone e lievito. Versare in una tortiera e cuocere in forno a 180 C per 35 minuti.",note_en:"Whip eggs with sugar until fluffy. Fold in flour, seed oil, lemon juice and zest, and baking powder. Pour into a cake tin and bake at 180 C for 35 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"150g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Limone",qt:"2"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta soffice al limone (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:6,gs:1.5,g:10,z:20,ch:44,fi:1,ca:30,fe:1,mg:12,k2:100,na:70,zn:.5,fo:20,se:10,col:90}},{id:"tpl_1442",nome:"Gelato allo yogurt fatto in casa",nome_en:"Homemade frozen yogurt",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco, miele e succo di limone. Versare nella gelatiera e mantecare secondo le istruzioni, oppure congelare mescolando ogni 30 minuti per 3 ore. Servire con frutta fresca.",note_en:"Mix Greek yogurt, honey and lemon juice. Churn in an ice cream maker per instructions, or freeze stirring every 30 minutes for 3 hours. Serve with fresh fruit.",ingredienti:[{nome:"Yogurt greco",qt:"500g"},{nome:"Miele",qt:"80g"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Gelato allo yogurt fatto in casa (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:9,gs:1,g:3,z:20,ch:20,fi:.2,ca:150,fe:.2,mg:15,k2:180,na:40,zn:.8,fo:8,se:4,col:8}},{id:"tpl_1443",nome:"Mousse di ricotta e cacao",nome_en:"Ricotta and cocoa mousse",categoria:"Dolce",porzioni:4,note:"Setacciare la ricotta e mescolarla con cacao amaro, miele e un pizzico di cannella fino a ottenere una crema liscia. Servire fredda in coppette guarnendo con granella di nocciole.",note_en:"Sieve ricotta and mix with unsweetened cocoa, honey and a pinch of cinnamon until smooth. Serve chilled in cups, garnishing with chopped hazelnuts.",ingredienti:[{nome:"Ricotta",qt:"300g"},{nome:"Cacao amaro",qt:"20g"},{nome:"Miele",qt:"40g"},{nome:"Nocciole",qt:"20g"}],_dbEntry:{n:"Mousse di ricotta e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:11,gs:5,g:12,z:12,ch:14,fi:2,ca:180,fe:1.5,mg:35,k2:250,na:60,zn:1,fo:20,se:8,col:35}},{id:"tpl_1444",nome:"Crumble di mele e pere",nome_en:"Apple and pear crumble",categoria:"Dolce",porzioni:6,note:"Tagliare mele e pere a cubetti e disporle in una teglia. Preparare un impasto sbriciolato con farina integrale, fiocchi d avena, burro e zucchero di canna. Distribuirlo sopra la frutta e cuocere in forno a 180 C per 30 minuti.",note_en:"Dice apples and pears and arrange in a baking dish. Prepare a crumbly mix with wholewheat flour, oat flakes, butter and cane sugar. Sprinkle over fruit and bake at 180 C for 30 minutes.",ingredienti:[{nome:"Mele",qt:"3"},{nome:"Pere",qt:"2"},{nome:"Farina integrale",qt:"120g"},{nome:"Fiocchi di avena",qt:"80g"},{nome:"Burro",qt:"60g"},{nome:"Zucchero di canna",qt:"60g"}],_dbEntry:{n:"Crumble di mele e pere (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:4,gs:4,g:9,z:22,ch:44,fi:5,ca:25,fe:1.2,mg:25,k2:280,na:40,zn:.5,fo:15,se:5,col:20}},{id:"tpl_1445",nome:"Plumcake integrale alla banana",nome_en:"Wholewheat banana plumcake",categoria:"Dolce",porzioni:10,note:"Schiacciare le banane mature e mescolarle con farina integrale, uova, olio di semi, miele e lievito. Versare in uno stampo da plumcake e cuocere in forno a 170 C per 45 minuti.",note_en:"Mash ripe bananas and mix with wholewheat flour, eggs, seed oil, honey and baking powder. Pour into a loaf tin and bake at 170 C for 45 minutes.",ingredienti:[{nome:"Banane",qt:"3"},{nome:"Farina integrale",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"60g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Plumcake integrale alla banana (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:1,g:7,z:16,ch:36,fi:3.5,ca:25,fe:1.2,mg:30,k2:280,na:60,zn:.5,fo:20,se:6,col:40}},{id:"tpl_1446",nome:"Sorbetto di frutta fresca",nome_en:"Fresh fruit sorbet",categoria:"Dolce",porzioni:4,note:"Congelare la frutta fresca a pezzi per almeno 4 ore. Frullare la frutta congelata con succo di limone e un cucchiaio di miele fino a ottenere una consistenza cremosa. Servire subito.",note_en:"Freeze fresh fruit pieces for at least 4 hours. Blend frozen fruit with lemon juice and a spoon of honey until creamy. Serve immediately.",ingredienti:[{nome:"Frutta fresca mista",qt:"500g"},{nome:"Limone",qt:"0.5"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Sorbetto di frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1,gs:.1,g:.3,z:24,ch:26,fi:3,ca:20,fe:.4,mg:15,k2:280,na:2,zn:.2,fo:20,se:1,col:0}},{id:"tpl_1447",nome:"Torta di ricotta e pere",nome_en:"Ricotta and pear cake",categoria:"Dolce",porzioni:8,note:"Mescolare ricotta, uova, zucchero e farina fino a ottenere un composto omogeneo. Aggiungere le pere tagliate a cubetti. Versare in una tortiera e cuocere in forno a 175 C per 45 minuti.",note_en:"Mix ricotta, eggs, sugar and flour until smooth. Add diced pears. Pour into a cake tin and bake at 175 C for 45 minutes.",ingredienti:[{nome:"Ricotta",qt:"400g"},{nome:"Pere",qt:"2"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"120g"},{nome:"Farina 00",qt:"80g"}],_dbEntry:{n:"Torta di ricotta e pere (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:3,g:11,z:18,ch:30,fi:2,ca:130,fe:1,mg:20,k2:200,na:70,zn:.7,fo:20,se:10,col:90}},{id:"tpl_1448",nome:"Bavarese ai frutti di bosco",nome_en:"Berry bavarian cream",categoria:"Dolce",porzioni:6,note:"Frullare i frutti di bosco con zucchero. Scaldare parte del latte e sciogliere la gelatina ammollata. Unire panna montata leggera e la purea di frutta. Versare negli stampini e raffreddare in frigo per 4 ore.",note_en:"Blend berries with sugar. Heat part of the milk and dissolve soaked gelatin. Fold in lightly whipped cream and fruit purée. Pour into molds and chill in the fridge for 4 hours.",ingredienti:[{nome:"Frutti di bosco",qt:"300g"},{nome:"Latte",qt:"150ml"},{nome:"Panna da montare",qt:"150ml"},{nome:"Zucchero",qt:"70g"},{nome:"Gelatina in fogli",qt:"8g"}],_dbEntry:{n:"Bavarese ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:3,gs:5,g:9,z:18,ch:22,fi:2,ca:70,fe:.5,mg:15,k2:150,na:30,zn:.4,fo:10,se:3,col:25}},{id:"tpl_1449",nome:"Biscotti proteici al cioccolato",nome_en:"Chocolate protein cookies",categoria:"Dolce",porzioni:12,note:"Mescolare proteine in polvere al cioccolato, farina di avena, banana schiacciata e gocce di cioccolato fondente. Formare i biscotti e cuocere in forno a 170 C per 12 minuti.",note_en:"Mix chocolate protein powder, oat flour, mashed banana and dark chocolate chips. Shape cookies and bake at 170 C for 12 minutes.",ingredienti:[{nome:"Proteine al cioccolato",qt:"80g"},{nome:"Farina di avena",qt:"150g"},{nome:"Banana",qt:"1"},{nome:"Gocce di cioccolato fondente",qt:"40g"}],_dbEntry:{n:"Biscotti proteici al cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:7,gs:1,g:3,z:6,ch:14,fi:1.5,ca:20,fe:.8,mg:20,k2:120,na:30,zn:.5,fo:8,se:4,col:2}},{id:"tpl_1450",nome:"Macedonia con yogurt e miele",nome_en:"Fruit salad with yogurt and honey",categoria:"Dolce",porzioni:4,note:"Tagliare a cubetti la frutta fresca di stagione. Condire con succo di limone per evitare l ossidazione. Servire con una quenelle di yogurt greco e un filo di miele.",note_en:"Dice fresh seasonal fruit. Dress with lemon juice to prevent browning. Serve with a quenelle of Greek yogurt and a drizzle of honey.",ingredienti:[{nome:"Frutta fresca mista",qt:"500g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"30g"},{nome:"Limone",qt:"0.5"}],_dbEntry:{n:"Macedonia con yogurt e miele (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:5,gs:.3,g:2,z:26,ch:28,fi:3,ca:80,fe:.5,mg:20,k2:350,na:30,zn:.4,fo:20,se:2,col:2}},{id:"tpl_1451",nome:"Minestrone alla milanese",nome_en:"Milanese-style minestrone",categoria:"Zuppa",porzioni:6,note:"Soffriggere pancetta con cipolla, sedano e carota. Aggiungere verza, patate, fagioli borlotti e pomodoro, coprire con brodo e cuocere a lungo. A metà cottura unire il riso e portare a termine, servire ben caldo con parmigiano.",note_en:"Sauté pancetta with onion, celery and carrot. Add savoy cabbage, potatoes, borlotti beans and tomato, cover with broth and simmer a long time. Halfway through add rice and finish cooking, serve hot with parmesan.",ingredienti:[{nome:"Pancetta",qt:"50g"},{nome:"Verza",qt:"200g"},{nome:"Patate",qt:"150g"},{nome:"Fagioli borlotti",qt:"150g"},{nome:"Pomodori pelati",qt:"100g"},{nome:"Riso",qt:"100g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Minestrone alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:10,gs:2.5,g:8,z:6,ch:35,fi:6,ca:60,fe:2.5,mg:45,k2:550,na:380,zn:1.5,fo:60,se:6,col:8}},{id:"tpl_1452",nome:"Minestrone genovese al pesto",nome_en:"Genoese minestrone with pesto",categoria:"Zuppa",porzioni:4,note:"Cuocere in brodo vegetale fagioli borlotti, patate, zucchine e pasta corta insieme a trenette spezzate. A fine cottura mantecare con una cucchiaiata di pesto genovese fresco. Servire tiepido, non bollente, per non alterare il pesto.",note_en:"Cook borlotti beans, potatoes, zucchini and short pasta with broken trenette in vegetable broth. At the end stir in a spoonful of fresh Genoese pesto. Serve warm, not boiling, to preserve the pesto.",ingredienti:[{nome:"Fagioli borlotti",qt:"150g"},{nome:"Patate",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Pasta corta",qt:"80g"},{nome:"Pesto genovese",qt:"2 cucchiai"},{nome:"Carota",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Minestrone genovese al pesto (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:2,g:10,z:5,ch:38,fi:6,ca:90,fe:2,mg:40,k2:500,na:350,zn:1.1,fo:55,se:5,col:3}},{id:"tpl_1453",nome:"Ribollita toscana (versione 2)",nome_en:"Tuscan ribollita (version 2)",categoria:"Zuppa",porzioni:6,note:"Preparare un passato di cannellini e unirlo a un soffritto di cipolla, carota, sedano, cavolo nero e patate. Cuocere lentamente, poi aggiungere il pane raffermo a fette e lasciar riposare. Riscaldare il giorno dopo con un filo d'olio a crudo.",note_en:"Prepare a cannellini bean purée and combine with a sauté of onion, carrot, celery, cavolo nero and potatoes. Simmer slowly, then add stale bread slices and let it rest. Reheat the next day with a drizzle of raw olive oil.",ingredienti:[{nome:"Fagioli cannellini",qt:"200g"},{nome:"Cavolo nero",qt:"150g"},{nome:"Pane raffermo",qt:"150g"},{nome:"Patate",qt:"100g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Ribollita toscana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:11,gs:1.5,g:9,z:5,ch:45,fi:8,ca:80,fe:3,mg:55,k2:600,na:400,zn:1.6,fo:70,se:6,col:0}},{id:"tpl_1454",nome:"Pasta e ceci",nome_en:"Pasta and chickpea soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio, rosmarino e un'acciuga in olio, aggiungere i ceci lessati e un po' del loro liquido. Frullarne metà per addensare, poi cuocere la pasta direttamente nella zuppa. Servire con pepe e un filo d'olio crudo.",note_en:"Sauté garlic, rosemary and an anchovy in oil, add cooked chickpeas with some of their liquid. Blend half to thicken, then cook the pasta directly in the soup. Serve with pepper and a raw drizzle of oil.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Pasta corta",qt:"120g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Pomodori pelati",qt:"80g"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Pasta e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:1.5,g:9,z:4,ch:45,fi:8,ca:70,fe:3.2,mg:60,k2:500,na:420,zn:1.8,fo:90,se:7,col:0}},{id:"tpl_1455",nome:"Pasta e fagioli alla veneta",nome_en:"Venetian pasta and bean soup",categoria:"Zuppa",porzioni:4,note:"Cuocere i fagioli borlotti con pancetta, aglio e rosmarino, poi frullarne una parte per ottenere una crema densa. Unire la pasta e completare la cottura nel brodo di fagioli. Servire ben densa, quasi da mangiare con la forchetta.",note_en:"Cook borlotti beans with pancetta, garlic and rosemary, then blend part of them for a thick cream. Add pasta and finish cooking in the bean broth. Serve very thick, almost fork-tender.",ingredienti:[{nome:"Fagioli borlotti",qt:"300g"},{nome:"Pancetta",qt:"40g"},{nome:"Pasta corta",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Pasta e fagioli alla veneta (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:15,gs:2,g:9,z:4,ch:48,fi:9,ca:80,fe:3.5,mg:65,k2:550,na:430,zn:1.9,fo:95,se:7,col:5}},{id:"tpl_1456",nome:"Zuppa di lenticchie",nome_en:"Lentil soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, carota e sedano, aggiungere le lenticchie e coprire con brodo vegetale. Cuocere fino a quando le lenticchie sono morbide e il liquido si è ristretto. Regolare di sale e servire con un filo d'olio a crudo.",note_en:"Sauté onion, carrot and celery, add lentils and cover with vegetable broth. Cook until lentils are soft and the liquid has reduced. Adjust salt and serve with a raw drizzle of oil.",ingredienti:[{nome:"Lenticchie secche",qt:"250g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori pelati",qt:"80g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di lenticchie (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:1,g:6,z:4,ch:42,fi:10,ca:50,fe:4.5,mg:60,k2:600,na:350,zn:2,fo:180,se:5,col:0}},{id:"tpl_1457",nome:"Zuppa di lenticchie e castagne",nome_en:"Lentil and chestnut soup",categoria:"Zuppa",porzioni:4,note:"Cuocere insieme lenticchie e castagne secche ammollate in brodo vegetale con alloro e cipolla. Frullare parzialmente per ottenere una consistenza cremosa ma con pezzi interi. Completare con un filo d'olio e pepe nero.",note_en:"Cook lentils and soaked dried chestnuts together in vegetable broth with bay leaf and onion. Partially blend for a creamy texture with some whole pieces left. Finish with a drizzle of oil and black pepper.",ingredienti:[{nome:"Lenticchie secche",qt:"150g"},{nome:"Castagne secche",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Alloro",qt:"1 foglia"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di lenticchie e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:1,g:6,z:8,ch:50,fi:9,ca:55,fe:3.8,mg:65,k2:620,na:330,zn:1.7,fo:140,se:5,col:0}},{id:"tpl_1458",nome:"Vellutata di zucca",nome_en:"Pumpkin velouté",categoria:"Zuppa",porzioni:4,note:"Cuocere la zucca a cubetti con cipolla e patata in brodo vegetale fino a renderla morbida. Frullare fino a ottenere una crema liscia, allungando con brodo se necessario. Mantecare con una noce di burro o un filo di panna e servire con semi di zucca tostati.",note_en:"Cook diced pumpkin with onion and potato in vegetable broth until soft. Blend until smooth, thinning with broth if needed. Finish with a knob of butter or a splash of cream and serve with toasted pumpkin seeds.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Patate",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Vellutata di zucca (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4,gs:3,g:8,z:8,ch:20,fi:3,ca:70,fe:1,mg:25,k2:400,na:300,zn:.6,fo:30,se:3,col:10}},{id:"tpl_1459",nome:"Vellutata di zucca e zenzero",nome_en:"Pumpkin and ginger velouté",categoria:"Zuppa",porzioni:4,note:"Cuocere la zucca con cipolla e una fettina di zenzero fresco in brodo vegetale. Frullare fino a crema liscia e correggere di sale. Servire calda con un filo di olio e crostini di pane tostato.",note_en:"Cook pumpkin with onion and a slice of fresh ginger in vegetable broth. Blend into a smooth cream and adjust salt. Serve hot with a drizzle of oil and toasted bread croutons.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"40g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Vellutata di zucca e zenzero (ricetta)",c:"Ricette",src:"RICETTE",k:175,p:4,gs:3,g:8,z:9,ch:21,fi:3,ca:65,fe:1,mg:25,k2:400,na:290,zn:.6,fo:28,se:3,col:10}},{id:"tpl_1460",nome:"Passato di verdure miste",nome_en:"Mixed vegetable purée soup",categoria:"Zuppa",porzioni:4,note:"Lessare in acqua o brodo carote, patate, zucchine, sedano e pomodoro fino a cottura completa. Frullare tutto fino a ottenere un passato omogeneo. Servire con un filo d'olio extravergine e crostini.",note_en:"Boil carrots, potatoes, zucchini, celery and tomato in water or broth until fully cooked. Blend everything into a smooth purée. Serve with a drizzle of olive oil and croutons.",ingredienti:[{nome:"Carota",qt:"2"},{nome:"Patate",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Sedano",qt:"1 costa"},{nome:"Pomodori pelati",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Passato di verdure miste (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:1,g:6,z:7,ch:18,fi:5,ca:60,fe:1.5,mg:35,k2:450,na:320,zn:.8,fo:50,se:3,col:0}},{id:"tpl_1461",nome:"Crema di broccoli",nome_en:"Cream of broccoli soup",categoria:"Zuppa",porzioni:4,note:"Lessare i broccoli in brodo vegetale insieme a una patata per addensare. Frullare fino a ottenere una crema vellutata e mantecare con formaggio grattugiato. Servire calda con crostini o pinoli tostati.",note_en:"Boil broccoli in vegetable broth together with a potato to thicken. Blend into a velvety cream and finish with grated cheese. Serve hot with croutons or toasted pine nuts.",ingredienti:[{nome:"Broccoli",qt:"400g"},{nome:"Patate",qt:"100g"},{nome:"Parmigiano grattugiato",qt:"20g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Crema di broccoli (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:7,gs:3.5,g:9,z:4,ch:14,fi:5,ca:100,fe:1.5,mg:35,k2:400,na:320,zn:.9,fo:80,se:4,col:15}},{id:"tpl_1462",nome:"Zuppa di cipolle gratinata (versione 2)",nome_en:"Gratinated onion soup (version 2)",categoria:"Zuppa",porzioni:4,note:"Stufare a lungo le cipolle affettate in burro fino a farle caramellare. Bagnare con brodo di carne e cuocere ancora. Versare in cocotte, coprire con pane e formaggio e gratinare in forno.",note_en:"Slowly stew sliced onions in butter until caramelized. Deglaze with meat broth and simmer further. Pour into ramekins, top with bread and cheese, and gratin in the oven.",ingredienti:[{nome:"Cipolle",qt:"500g"},{nome:"Burro",qt:"30g"},{nome:"Pane",qt:"80g"},{nome:"Emmental o groviera",qt:"80g"},{nome:"Brodo di carne",qt:"800ml"}],_dbEntry:{n:"Zuppa di cipolle gratinata (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:9,gs:5,g:11,z:10,ch:27,fi:3,ca:180,fe:1,mg:25,k2:300,na:450,zn:1,fo:25,se:4,col:25}},{id:"tpl_1463",nome:"Zuppa di farro e legumi",nome_en:"Farro and mixed legume soup",categoria:"Zuppa",porzioni:4,note:"Ammollare il farro e cuocerlo insieme a un mix di legumi misti già lessati in brodo vegetale con soffritto di sedano, carota e cipolla. Cuocere finché il farro è tenero e la zuppa si è addensata. Servire con un filo d'olio a crudo.",note_en:"Soak the farro and cook it with a mix of already cooked legumes in vegetable broth with a celery, carrot and onion sauté. Cook until the farro is tender and the soup has thickened. Serve with a raw drizzle of oil.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Legumi misti lessati",qt:"200g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di farro e legumi (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:1,g:6,z:4,ch:48,fi:9,ca:60,fe:3,mg:70,k2:550,na:350,zn:1.8,fo:80,se:6,col:0}},{id:"tpl_1464",nome:"Zuppa di farro alla garfagnina",nome_en:"Garfagnana-style farro soup",categoria:"Zuppa",porzioni:4,note:"Cuocere il farro della Garfagnana con fagioli borlotti, patate e cotenna di maiale in acqua per diverse ore. Insaporire con soffritto di aglio e rosmarino. Servire densa, con un filo d'olio toscano a crudo.",note_en:"Cook Garfagnana farro with borlotti beans, potatoes and pork rind in water for several hours. Season with a garlic and rosemary sauté. Serve thick, with a raw drizzle of Tuscan olive oil.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Fagioli borlotti",qt:"150g"},{nome:"Patate",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di farro alla garfagnina (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:12,gs:1,g:6,z:4,ch:46,fi:8,ca:55,fe:2.8,mg:65,k2:520,na:340,zn:1.6,fo:75,se:6,col:0}},{id:"tpl_1465",nome:"Zuppa di orzo e verdure",nome_en:"Barley and vegetable soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere carota, sedano e cipolla, aggiungere l'orzo perlato e coprire con brodo vegetale. Cuocere finché l'orzo è tenero, unendo zucchine e patate a metà cottura. Servire con pepe macinato fresco.",note_en:"Sauté carrot, celery and onion, add pearl barley and cover with vegetable broth. Cook until the barley is tender, adding zucchini and potatoes halfway through. Serve with freshly ground pepper.",ingredienti:[{nome:"Orzo perlato",qt:"150g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Zucchine",qt:"150g"},{nome:"Patate",qt:"100g"}],_dbEntry:{n:"Zuppa di orzo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:1,g:5,z:5,ch:45,fi:6,ca:50,fe:2,mg:50,k2:450,na:330,zn:1.2,fo:50,se:5,col:0}},{id:"tpl_1466",nome:"Cacciucco alla livornese",nome_en:"Livorno-style cacciucco",categoria:"Zuppa",porzioni:6,note:"Preparare un soffritto di aglio, cipolla e peperoncino, sfumare con vino rosso e aggiungere pomodoro. Unire i vari pesci e molluschi partendo da quelli a cottura più lunga fino a quelli più delicati. Servire su fette di pane abbrustolito strofinato con aglio.",note_en:"Prepare a sauté of garlic, onion and chili, deglaze with red wine and add tomato. Add the various fish and shellfish starting with those needing longer cooking down to the more delicate ones. Serve over toasted bread rubbed with garlic.",ingredienti:[{nome:"Misto di pesce da zuppa",qt:"800g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino rosso",qt:"100ml"},{nome:"Aglio",qt:"3 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Pane",qt:"200g"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Cacciucco alla livornese (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:28,gs:2,g:12,z:4,ch:18,fi:2,ca:80,fe:2.5,mg:55,k2:500,na:550,zn:1.8,fo:40,se:35,col:120}},{id:"tpl_1467",nome:"Zuppa di pesce alla livornese (versione 2)",nome_en:"Livorno-style fish soup (version 2)",categoria:"Zuppa",porzioni:4,note:"Rosolare aglio e cipolla in olio, unire pomodori pelati e cuocere una decina di minuti. Aggiungere tranci di pesce misto e cuocere a fuoco basso finché la polpa è cotta. Servire con crostini di pane e prezzemolo tritato.",note_en:"Brown garlic and onion in oil, add crushed tomatoes and cook for ten minutes. Add mixed fish pieces and cook on low heat until the flesh is done. Serve with bread croutons and chopped parsley.",ingredienti:[{nome:"Misto di pesce da zuppa",qt:"600g"},{nome:"Pomodori pelati",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"150g"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Zuppa di pesce alla livornese (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:25,gs:2,g:11,z:4,ch:17,fi:2,ca:75,fe:2.3,mg:50,k2:480,na:520,zn:1.6,fo:35,se:32,col:110}},{id:"tpl_1468",nome:"Zuppa di cozze",nome_en:"Mussel soup",categoria:"Zuppa",porzioni:4,note:"Aprire le cozze in un tegame con aglio, olio e vino bianco, poi filtrare il liquido di cottura. Preparare un fondo di pomodoro e unire le cozze sgusciate con il loro liquido filtrato. Servire con crostini di pane e prezzemolo.",note_en:"Open the mussels in a pan with garlic, oil and white wine, then strain the cooking liquid. Prepare a tomato base and add the shelled mussels with their strained liquid. Serve with bread croutons and parsley.",ingredienti:[{nome:"Cozze",qt:"1kg"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"100ml"},{nome:"Pane",qt:"100g"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Zuppa di cozze (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1.5,g:8,z:2,ch:12,fi:1,ca:60,fe:4,mg:40,k2:400,na:600,zn:1.8,fo:40,se:40,col:50}},{id:"tpl_1469",nome:"Zuppa di vongole",nome_en:"Clam soup",categoria:"Zuppa",porzioni:4,note:"Spurgare le vongole e aprirle in padella con aglio, olio e vino bianco. Filtrare il liquido e unirlo a un fondo leggero di pomodorini. Rimettere le vongole nel guscio nella zuppa e servire con crostini.",note_en:"Purge the clams and open them in a pan with garlic, oil and white wine. Strain the liquid and add it to a light cherry tomato base. Return the in-shell clams to the soup and serve with croutons.",ingredienti:[{nome:"Vongole",qt:"1kg"},{nome:"Pomodorini",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"100ml"},{nome:"Pane",qt:"100g"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Zuppa di vongole (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:19,gs:1.5,g:9,z:2,ch:14,fi:1,ca:50,fe:6,mg:35,k2:380,na:650,zn:1.6,fo:35,se:45,col:45}},{id:"tpl_1470",nome:"Brodo di pollo con pastina",nome_en:"Chicken broth with pastina",categoria:"Zuppa",porzioni:4,note:"Cuocere il pollo con carota, sedano, cipolla e alloro in acqua fredda per un'ora e mezza a fuoco basso. Filtrare il brodo e cuocervi la pastina fino a cottura. Servire con parmigiano grattugiato.",note_en:"Cook the chicken with carrot, celery, onion and bay leaf in cold water for an hour and a half on low heat. Strain the broth and cook pastina in it until done. Serve with grated parmesan.",ingredienti:[{nome:"Petto di pollo con osso",qt:"400g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Pastina",qt:"80g"},{nome:"Parmigiano grattugiato",qt:"20g"}],_dbEntry:{n:"Brodo di pollo con pastina (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:12,gs:1.5,g:5,z:2,ch:20,fi:1,ca:25,fe:1,mg:20,k2:250,na:500,zn:1,fo:25,se:10,col:25}},{id:"tpl_1471",nome:"Stracciatella alla romana",nome_en:"Roman egg-drop soup",categoria:"Zuppa",porzioni:4,note:"Portare a bollore il brodo di carne. Sbattere le uova con parmigiano, un pizzico di noce moscata e semolino, poi versare a filo nel brodo bollente mescolando con una frusta. Cuocere pochi minuti finché si formano gli stracci e servire subito.",note_en:"Bring the meat broth to a boil. Beat the eggs with parmesan, a pinch of nutmeg and semolina, then pour in a stream into the boiling broth while whisking. Cook a few minutes until strands form and serve immediately.",ingredienti:[{nome:"Brodo di carne",qt:"800ml"},{nome:"Uova",qt:"3"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Semolino",qt:"2 cucchiai"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Stracciatella alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:11,gs:3,g:8,z:1,ch:10,fi:.5,ca:60,fe:1,mg:15,k2:200,na:480,zn:1,fo:25,se:12,col:120}},{id:"tpl_1472",nome:"Passatelli in brodo",nome_en:"Passatelli in broth",categoria:"Zuppa",porzioni:4,note:"Impastare pangrattato, parmigiano, uova e noce moscata fino a ottenere un composto sodo. Passarlo nell'apposito ferro o in uno schiacciapatate a fori larghi direttamente nel brodo bollente. Cuocere pochi minuti finché i passatelli vengono a galla e servire caldo.",note_en:"Mix breadcrumbs, parmesan, eggs and nutmeg into a firm dough. Press it through the passatelli iron or a wide-holed potato ricer directly into the boiling broth. Cook a few minutes until they float and serve hot.",ingredienti:[{nome:"Pangrattato",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Brodo di carne",qt:"1000ml"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Passatelli in brodo (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:14,gs:3.5,g:9,z:1,ch:20,fi:1,ca:100,fe:1.3,mg:20,k2:220,na:520,zn:1.3,fo:25,se:15,col:90}},{id:"tpl_1473",nome:"Zuppa di ceci e castagne",nome_en:"Chickpea and chestnut soup",categoria:"Zuppa",porzioni:4,note:"Cuocere insieme ceci ammollati e castagne secche in acqua con alloro fino a completa cottura. Frullare parzialmente per addensare mantenendo pezzi interi. Condire con olio a crudo e rosmarino tritato.",note_en:"Cook soaked chickpeas and dried chestnuts together in water with bay leaf until fully cooked. Partially blend to thicken while keeping some whole pieces. Season with raw oil and chopped rosemary.",ingredienti:[{nome:"Ceci secchi",qt:"200g"},{nome:"Castagne secche",qt:"100g"},{nome:"Alloro",qt:"1 foglia"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di ceci e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:12,gs:1,g:7,z:9,ch:52,fi:9,ca:60,fe:3,mg:70,k2:600,na:340,zn:1.6,fo:85,se:6,col:0}},{id:"tpl_1474",nome:"Zuppa di fagioli borlotti",nome_en:"Borlotti bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, sedano e carota, unire i fagioli borlotti già lessati con parte del loro brodo di cottura. Cuocere ancora una decina di minuti frullando leggermente per addensare. Servire con olio a crudo e pepe.",note_en:"Sauté onion, celery and carrot, add already-cooked borlotti beans with some of their cooking broth. Cook another ten minutes, blending lightly to thicken. Serve with raw oil and pepper.",ingredienti:[{nome:"Fagioli borlotti",qt:"350g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di fagioli borlotti (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:14,gs:1,g:6,z:4,ch:45,fi:9,ca:70,fe:3.3,mg:65,k2:600,na:360,zn:1.7,fo:90,se:6,col:0}},{id:"tpl_1475",nome:"Zuppa di cannellini e cavolo nero",nome_en:"Cannellini bean and cavolo nero soup",categoria:"Zuppa",porzioni:4,note:"Cuocere i fagioli cannellini con aglio e salvia, poi frullarne una parte. Aggiungere il cavolo nero tagliato a listarelle e cuocere finché appassisce. Servire con crostini di pane e olio a crudo.",note_en:"Cook cannellini beans with garlic and sage, then blend part of them. Add cavolo nero cut into strips and cook until wilted. Serve with bread croutons and raw oil.",ingredienti:[{nome:"Fagioli cannellini",qt:"300g"},{nome:"Cavolo nero",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Salvia",qt:"3 foglie"},{nome:"Pane",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di cannellini e cavolo nero (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:1.2,g:7,z:4,ch:42,fi:9,ca:90,fe:3.5,mg:65,k2:620,na:370,zn:1.6,fo:95,se:6,col:0}},{id:"tpl_1476",nome:"Vellutata di carote e zenzero (versione 2)",nome_en:"Carrot and ginger velouté (version 2)",categoria:"Zuppa",porzioni:4,note:"Cuocere le carote a rondelle con cipolla e zenzero fresco in brodo vegetale finché tenere. Frullare fino a ottenere una crema liscia e vellutata. Servire con semi di sesamo tostati o un filo di olio.",note_en:"Cook sliced carrots with onion and fresh ginger in vegetable broth until tender. Blend into a smooth, velvety cream. Serve with toasted sesame seeds or a drizzle of oil.",ingredienti:[{nome:"Carote",qt:"400g"},{nome:"Zenzero fresco",qt:"15g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Vellutata di carote e zenzero (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:3,g:7,z:10,ch:20,fi:4,ca:50,fe:.8,mg:20,k2:380,na:280,zn:.5,fo:30,se:3,col:10}},{id:"tpl_1477",nome:"Vellutata di sedano rapa",nome_en:"Celeriac velouté",categoria:"Zuppa",porzioni:4,note:"Tagliare a cubetti il sedano rapa e cuocerlo con patata e cipolla in brodo vegetale. Frullare fino a crema omogenea e mantecare con una noce di burro. Servire con crostini o noci tritate.",note_en:"Dice the celeriac and cook it with potato and onion in vegetable broth. Blend into a smooth cream and finish with a knob of butter. Serve with croutons or chopped walnuts.",ingredienti:[{nome:"Sedano rapa",qt:"400g"},{nome:"Patate",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di sedano rapa (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4,gs:4,g:9,z:5,ch:16,fi:3,ca:60,fe:.7,mg:20,k2:350,na:300,zn:.5,fo:25,se:3,col:15}},{id:"tpl_1478",nome:"Crema di funghi porcini",nome_en:"Cream of porcini mushroom soup",categoria:"Zuppa",porzioni:4,note:"Rosolare i funghi porcini con aglio e prezzemolo, unire una patata a cubetti e brodo vegetale. Cuocere fino a cottura completa, poi frullare fino a crema liscia. Mantecare con panna e servire con funghi trifolati a parte.",note_en:"Brown porcini mushrooms with garlic and parsley, add diced potato and vegetable broth. Cook until fully done, then blend into a smooth cream. Finish with cream and serve with sautéed mushrooms on the side.",ingredienti:[{nome:"Funghi porcini",qt:"300g"},{nome:"Patate",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Panna fresca",qt:"50ml"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Crema di funghi porcini (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:6,gs:4.5,g:11,z:3,ch:15,fi:2,ca:50,fe:1.2,mg:20,k2:400,na:350,zn:.9,fo:25,se:8,col:20}},{id:"tpl_1479",nome:"Zuppa di funghi e patate",nome_en:"Mushroom and potato soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e aglio, unire funghi misti a pezzi e patate a cubetti. Coprire con brodo vegetale e cuocere finché le patate sono tenere. Servire con prezzemolo fresco tritato.",note_en:"Sauté onion and garlic, add mixed chopped mushrooms and diced potatoes. Cover with vegetable broth and cook until the potatoes are tender. Serve with fresh chopped parsley.",ingredienti:[{nome:"Funghi misti",qt:"300g"},{nome:"Patate",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Zuppa di funghi e patate (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:6,gs:1.5,g:6,z:3,ch:30,fi:3,ca:40,fe:1.5,mg:30,k2:450,na:330,zn:.9,fo:30,se:8,col:5}},{id:"tpl_1480",nome:"Vellutata di patate e porri",nome_en:"Potato and leek velouté",categoria:"Zuppa",porzioni:4,note:"Stufare i porri affettati in burro, unire le patate a cubetti e coprire con brodo vegetale. Cuocere finché le patate si disfano, poi frullare fino a crema liscia. Servire con erba cipollina fresca tritata.",note_en:"Stew the sliced leeks in butter, add diced potatoes and cover with vegetable broth. Cook until the potatoes fall apart, then blend into a smooth cream. Serve with fresh chopped chives.",ingredienti:[{nome:"Porri",qt:"300g"},{nome:"Patate",qt:"300g"},{nome:"Burro",qt:"20g"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di patate e porri (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:4,g:8,z:4,ch:25,fi:3,ca:50,fe:1,mg:25,k2:400,na:320,zn:.7,fo:30,se:4,col:15}},{id:"tpl_1481",nome:"Zuppa di cavolfiore",nome_en:"Cauliflower soup",categoria:"Zuppa",porzioni:4,note:"Cuocere il cavolfiore a cimette in brodo vegetale con cipolla fino a renderlo morbido. Frullare parzialmente lasciando qualche cimetta intera. Insaporire con curcuma o pepe e servire con crostini.",note_en:"Cook cauliflower florets in vegetable broth with onion until soft. Partially blend, leaving a few florets whole. Season with turmeric or pepper and serve with croutons.",ingredienti:[{nome:"Cavolfiore",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"60g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di cavolfiore (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:2,g:6,z:5,ch:18,fi:4,ca:60,fe:1,mg:25,k2:350,na:300,zn:.6,fo:55,se:5,col:10}},{id:"tpl_1482",nome:"Zuppa di verza e fagioli",nome_en:"Savoy cabbage and bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e pancetta, unire la verza tagliata a listarelle e i fagioli borlotti già cotti. Aggiungere brodo e cuocere finché la verza è tenera. Servire con crostini di pane raffermo.",note_en:"Sauté onion and pancetta, add savoy cabbage cut into strips and already-cooked borlotti beans. Add broth and cook until the cabbage is tender. Serve with stale bread croutons.",ingredienti:[{nome:"Verza",qt:"300g"},{nome:"Fagioli borlotti",qt:"250g"},{nome:"Pancetta",qt:"30g"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di verza e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:13,gs:1,g:6,z:5,ch:40,fi:8,ca:80,fe:3,mg:55,k2:550,na:350,zn:1.5,fo:80,se:6,col:0}},{id:"tpl_1483",nome:"Zuppa valpellinese",nome_en:"Valpellinese cabbage and bread soup",categoria:"Zuppa",porzioni:4,note:"Alternare in una teglia strati di pane raffermo, verza cotta, fontina e speck. Bagnare con brodo di carne fino a coprire e cuocere in forno finché la crosta è dorata. Servire calda direttamente dalla teglia.",note_en:"Layer stale bread, cooked cabbage, fontina cheese and speck in a baking dish. Moisten with meat broth until covered and bake until the crust is golden. Serve hot straight from the dish.",ingredienti:[{nome:"Pane raffermo",qt:"200g"},{nome:"Verza",qt:"300g"},{nome:"Fontina",qt:"150g"},{nome:"Speck",qt:"80g"},{nome:"Brodo di carne",qt:"500ml"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Zuppa valpellinese (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:16,gs:7,g:15,z:5,ch:35,fi:5,ca:250,fe:2,mg:40,k2:400,na:500,zn:1.8,fo:50,se:8,col:35}},{id:"tpl_1484",nome:"Jota triestina",nome_en:"Triestine jota",categoria:"Zuppa",porzioni:6,note:'Cuocere i fagioli con patate, crauti acidi e costine di maiale affumicate a lungo in acqua. Legare con un soffritto di farina e aglio (la cosiddetta "pesta"). Servire calda, tipica del Carso e di Trieste.',note_en:'Cook the beans with potatoes, sauerkraut and smoked pork ribs for a long time in water. Thicken with a garlic and flour sauté (the "pesta"). Serve hot, typical of the Karst and Trieste area.',ingredienti:[{nome:"Fagioli borlotti",qt:"250g"},{nome:"Crauti",qt:"250g"},{nome:"Patate",qt:"200g"},{nome:"Costine di maiale affumicate",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Farina 00",qt:"1 cucchiaio"}],_dbEntry:{n:"Jota triestina (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:15,gs:4,g:12,z:4,ch:38,fi:8,ca:70,fe:2.8,mg:50,k2:480,na:520,zn:1.8,fo:60,se:8,col:25}},{id:"tpl_1485",nome:"Zuppa di cardi",nome_en:"Cardoon soup",categoria:"Zuppa",porzioni:4,note:"Pulire e sbollentare i cardi per eliminare l'amarognolo, poi cuocerli in brodo vegetale con cipolla. Frullare parzialmente per una consistenza cremosa con pezzi interi. Mantecare con parmigiano e servire caldo.",note_en:"Clean and blanch the cardoons to remove bitterness, then cook them in vegetable broth with onion. Partially blend for a creamy texture with some whole pieces. Finish with parmesan and serve hot.",ingredienti:[{nome:"Cardi",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di cardi (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:6,gs:3.5,g:9,z:4,ch:20,fi:4,ca:90,fe:1.2,mg:25,k2:350,na:320,zn:.7,fo:40,se:5,col:15}},{id:"tpl_1486",nome:"Zuppa di finocchi",nome_en:"Fennel soup",categoria:"Zuppa",porzioni:4,note:"Tagliare i finocchi a fette e stufarli con cipolla in olio, poi coprire con brodo vegetale. Cuocere finché i finocchi sono teneri, frullando se si desidera una consistenza più cremosa. Servire con un filo di olio e semi di finocchio.",note_en:"Slice the fennel and stew it with onion in oil, then cover with vegetable broth. Cook until the fennel is tender, blending if a creamier texture is desired. Serve with a drizzle of oil and fennel seeds.",ingredienti:[{nome:"Finocchi",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Patate",qt:"80g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di finocchi (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:4,gs:2,g:6,z:6,ch:18,fi:5,ca:70,fe:1,mg:25,k2:400,na:300,zn:.6,fo:40,se:4,col:5}},{id:"tpl_1487",nome:"Zuppa di piselli e menta",nome_en:"Pea and mint soup",categoria:"Zuppa",porzioni:4,note:"Cuocere i piselli con cipolla in brodo vegetale fino a renderli morbidi. Frullare con foglie di menta fresca fino a ottenere una crema vivace e profumata. Servire con un filo d'olio e qualche foglia di menta a crudo.",note_en:"Cook the peas with onion in vegetable broth until soft. Blend with fresh mint leaves into a bright, fragrant cream. Serve with a drizzle of oil and a few raw mint leaves.",ingredienti:[{nome:"Piselli",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Menta fresca",qt:"10 foglie"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di piselli e menta (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:9,gs:2,g:6,z:6,ch:25,fi:6,ca:40,fe:1.8,mg:30,k2:350,na:300,zn:1,fo:60,se:4,col:5}},{id:"tpl_1488",nome:"Vellutata di piselli",nome_en:"Pea velouté",categoria:"Zuppa",porzioni:4,note:"Cuocere i piselli con una patata e cipolla in brodo vegetale. Frullare fino a crema liscia e mantecare con una noce di burro o un filo di panna. Servire con crostini croccanti.",note_en:"Cook the peas with a potato and onion in vegetable broth. Blend into a smooth cream and finish with a knob of butter or a splash of cream. Serve with crunchy croutons.",ingredienti:[{nome:"Piselli",qt:"400g"},{nome:"Patate",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di piselli (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:8,gs:3.5,g:9,z:6,ch:22,fi:6,ca:45,fe:1.7,mg:28,k2:350,na:300,zn:1,fo:55,se:4,col:12}},{id:"tpl_1489",nome:"Zuppa di ortiche",nome_en:"Nettle soup",categoria:"Zuppa",porzioni:4,note:"Raccogliere e lavare le cime di ortica con guanti, poi sbollentarle brevemente. Stufarle con cipolla e patata in brodo vegetale, quindi frullare fino a crema. Servire con un filo d'olio e crostini.",note_en:"Gather and wash nettle tops with gloves, then blanch them briefly. Stew them with onion and potato in vegetable broth, then blend into a cream. Serve with a drizzle of oil and croutons.",ingredienti:[{nome:"Ortiche fresche",qt:"250g"},{nome:"Patate",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di ortiche (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:6,gs:2.5,g:7,z:3,ch:16,fi:3,ca:100,fe:2.5,mg:40,k2:400,na:300,zn:.8,fo:50,se:4,col:8}},{id:"tpl_1490",nome:"Zuppa di spinaci e patate",nome_en:"Spinach and potato soup",categoria:"Zuppa",porzioni:4,note:"Cuocere le patate a cubetti in brodo vegetale, poi unire gli spinaci freschi e cuocere fino ad appassirli. Frullare parzialmente per una consistenza cremosa ma non liscia. Servire con un filo di olio e scaglie di parmigiano.",note_en:"Cook diced potatoes in vegetable broth, then add fresh spinach and cook until wilted. Partially blend for a creamy but not smooth texture. Serve with a drizzle of oil and parmesan shavings.",ingredienti:[{nome:"Spinaci freschi",qt:"300g"},{nome:"Patate",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Parmigiano a scaglie",qt:"20g"}],_dbEntry:{n:"Zuppa di spinaci e patate (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1.5,g:6,z:3,ch:28,fi:4,ca:90,fe:2.2,mg:45,k2:480,na:320,zn:.8,fo:120,se:5,col:5}},{id:"tpl_1491",nome:"Minestra di riso e verza",nome_en:"Rice and savoy cabbage soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e pancetta, unire la verza tagliata a listarelle e coprire con brodo. Aggiungere il riso e cuocere fino a completa cottura, mescolando spesso. Servire ben calda con parmigiano.",note_en:"Sauté onion and pancetta, add savoy cabbage cut into strips and cover with broth. Add the rice and cook until done, stirring often. Serve piping hot with parmesan.",ingredienti:[{nome:"Riso",qt:"150g"},{nome:"Verza",qt:"250g"},{nome:"Pancetta",qt:"30g"},{nome:"Cipolla",qt:"1"},{nome:"Parmigiano grattugiato",qt:"20g"}],_dbEntry:{n:"Minestra di riso e verza (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:7,gs:1.5,g:5,z:4,ch:38,fi:4,ca:60,fe:1.3,mg:30,k2:350,na:340,zn:1,fo:40,se:5,col:5}},{id:"tpl_1492",nome:"Minestra di riso e zucchine",nome_en:"Rice and zucchini soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla in olio, aggiungere le zucchine a cubetti e rosolare brevemente. Coprire con brodo vegetale, unire il riso e cuocere fino a cottura. Completare con basilico fresco spezzettato.",note_en:"Sauté onion in oil, add diced zucchini and brown briefly. Cover with vegetable broth, add the rice and cook until done. Finish with torn fresh basil.",ingredienti:[{nome:"Riso",qt:"150g"},{nome:"Zucchine",qt:"300g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Minestra di riso e zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:6,gs:1.5,g:5,z:4,ch:37,fi:3,ca:50,fe:1.1,mg:28,k2:330,na:320,zn:.9,fo:35,se:5,col:5}},{id:"tpl_1493",nome:"Zuppa di ceci e rosmarino",nome_en:"Chickpea and rosemary soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e rosmarino in olio, unire i ceci lessati con parte del loro liquido. Cuocere una decina di minuti, frullando in parte per addensare. Servire con crostini di pane e un filo d'olio a crudo.",note_en:"Sauté garlic and rosemary in oil, add cooked chickpeas with some of their liquid. Cook for about ten minutes, blending part of it to thicken. Serve with bread croutons and a raw drizzle of oil.",ingredienti:[{nome:"Ceci lessati",qt:"350g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Pane",qt:"80g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di ceci e rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:1.2,g:8,z:3,ch:45,fi:8,ca:60,fe:3,mg:65,k2:550,na:350,zn:1.6,fo:80,se:6,col:0}},{id:"tpl_1494",nome:"Zuppa di zucca e fagioli",nome_en:"Pumpkin and bean soup",categoria:"Zuppa",porzioni:4,note:"Cuocere la zucca a cubetti con cipolla in brodo vegetale finché morbida. Unire i fagioli cannellini già lessati e cuocere ancora qualche minuto, frullando leggermente per addensare. Servire con un filo d'olio e pepe nero.",note_en:"Cook diced pumpkin with onion in vegetable broth until soft. Add already-cooked cannellini beans and cook a few more minutes, blending lightly to thicken. Serve with a drizzle of oil and black pepper.",ingredienti:[{nome:"Zucca",qt:"350g"},{nome:"Fagioli cannellini",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di zucca e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:11,gs:1,g:6,z:8,ch:42,fi:8,ca:70,fe:2.8,mg:55,k2:550,na:340,zn:1.4,fo:70,se:6,col:0}},{id:"tpl_1495",nome:"Zuppa di zucca e castagne",nome_en:"Pumpkin and chestnut soup",categoria:"Zuppa",porzioni:4,note:"Cuocere la zucca a cubetti insieme alle castagne lessate e sbucciate in brodo vegetale con cipolla. Frullare parzialmente per una consistenza densa con qualche pezzo intero. Servire con un filo d'olio e rosmarino.",note_en:"Cook diced pumpkin together with boiled, peeled chestnuts in vegetable broth with onion. Partially blend for a thick texture with some whole pieces. Serve with a drizzle of oil and rosemary.",ingredienti:[{nome:"Zucca",qt:"300g"},{nome:"Castagne lessate",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di zucca e castagne (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:7,gs:1.5,g:7,z:12,ch:42,fi:6,ca:55,fe:1.8,mg:50,k2:480,na:300,zn:1,fo:50,se:5,col:5}},{id:"tpl_1496",nome:"Crema di zucchine",nome_en:"Cream of zucchini soup",categoria:"Zuppa",porzioni:4,note:"Stufare le zucchine a rondelle con cipolla e una patata in brodo vegetale. Frullare fino a ottenere una crema liscia e vellutata. Servire con foglie di basilico fresco e un filo d'olio.",note_en:"Stew sliced zucchini with onion and a potato in vegetable broth. Blend into a smooth, velvety cream. Serve with fresh basil leaves and a drizzle of oil.",ingredienti:[{nome:"Zucchine",qt:"400g"},{nome:"Patate",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Crema di zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:3,g:7,z:6,ch:14,fi:3,ca:60,fe:.8,mg:25,k2:350,na:300,zn:.6,fo:40,se:3,col:12}},{id:"tpl_1497",nome:"Vellutata di asparagi (versione 2)",nome_en:"Asparagus velouté (version 2)",categoria:"Zuppa",porzioni:4,note:"Cuocere gli asparagi privati della parte legnosa in brodo vegetale con cipolla. Frullare fino a ottenere una crema liscia, tenendo da parte qualche punta per guarnire. Servire con un filo di panna o olio.",note_en:"Cook the asparagus, with the woody ends removed, in vegetable broth with onion. Blend into a smooth cream, keeping a few tips aside for garnish. Serve with a swirl of cream or oil.",ingredienti:[{nome:"Asparagi",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di asparagi (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:6,gs:3.5,g:8,z:4,ch:14,fi:3,ca:40,fe:1.5,mg:25,k2:350,na:300,zn:.9,fo:90,se:5,col:15}},{id:"tpl_1498",nome:"Zuppa di asparagi e patate",nome_en:"Asparagus and potato soup",categoria:"Zuppa",porzioni:4,note:"Cuocere le patate a cubetti in brodo vegetale, unire gli asparagi tagliati a pezzetti e proseguire la cottura. Frullare parzialmente lasciando qualche pezzo intero. Servire con un filo d'olio e pepe.",note_en:"Cook diced potatoes in vegetable broth, add asparagus cut into pieces and continue cooking. Partially blend, leaving some pieces whole. Serve with a drizzle of oil and pepper.",ingredienti:[{nome:"Asparagi",qt:"300g"},{nome:"Patate",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di asparagi e patate (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1.5,g:5,z:4,ch:28,fi:4,ca:45,fe:1.6,mg:30,k2:400,na:320,zn:1,fo:95,se:5,col:5}},{id:"tpl_1499",nome:"Zuppa di pomodoro e basilico",nome_en:"Tomato and basil soup",categoria:"Zuppa",porzioni:4,note:"Cuocere i pomodori pelati con cipolla e una patata per addensare in un filo d'olio. Frullare fino a ottenere una crema liscia e profumare con basilico fresco. Servire con crostini di pane croccante.",note_en:"Cook peeled tomatoes with onion and a potato to thicken in a drizzle of oil. Blend into a smooth cream and flavor with fresh basil. Serve with crunchy bread croutons.",ingredienti:[{nome:"Pomodori pelati",qt:"500g"},{nome:"Patate",qt:"80g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di pomodoro e basilico (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1.5,g:7,z:9,ch:20,fi:3,ca:40,fe:1.2,mg:25,k2:400,na:350,zn:.6,fo:35,se:4,col:0}},{id:"tpl_1500",nome:"Pappa al pomodoro",nome_en:"Tuscan tomato and bread soup",categoria:"Zuppa",porzioni:4,note:"Rosolare aglio in olio, aggiungere i pomodori pelati e cuocere per una ventina di minuti. Unire il pane raffermo a pezzi e il basilico, lasciando che il pane si ammorbidisca. Servire tiepida con un filo d'olio a crudo.",note_en:"Brown garlic in oil, add peeled tomatoes and cook for about twenty minutes. Add stale bread in pieces and basil, letting the bread soften. Serve warm with a raw drizzle of oil.",ingredienti:[{nome:"Pomodori pelati",qt:"500g"},{nome:"Pane raffermo",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Pappa al pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:7,gs:1.5,g:8,z:8,ch:38,fi:4,ca:50,fe:2,mg:35,k2:400,na:380,zn:1,fo:40,se:5,col:0}},{id:"tpl_1501",nome:"Acquacotta maremmana (versione 2)",nome_en:"Maremma-style acquacotta (version 2)",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, sedano e pomodoro in olio, coprire con acqua e cuocere una ventina di minuti. Versare la zuppa su fette di pane raffermo e un uovo per porzione, lasciando che l'uovo si rapprenda nel calore. Completare con pecorino grattugiato.",note_en:"Sauté onion, celery and tomato in oil, cover with water and cook for about twenty minutes. Pour the soup over slices of stale bread and one egg per serving, letting the egg set in the heat. Finish with grated pecorino.",ingredienti:[{nome:"Pomodori pelati",qt:"250g"},{nome:"Cipolla",qt:"2"},{nome:"Sedano",qt:"1 costa"},{nome:"Pane raffermo",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Pecorino grattugiato",qt:"30g"}],_dbEntry:{n:"Acquacotta maremmana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:10,gs:3,g:10,z:5,ch:28,fi:4,ca:100,fe:1.8,mg:30,k2:380,na:420,zn:1.2,fo:40,se:8,col:90}},{id:"tpl_1502",nome:"Zuppa di pane toscana (versione 2)",nome_en:"Tuscan bread soup (version 2)",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, carota e sedano, unire cavolo nero e pomodoro e cuocere con brodo vegetale. Aggiungere il pane raffermo a fette e lasciarlo assorbire il liquido fino a sfaldarsi. Servire con un filo d'olio a crudo.",note_en:"Sauté onion, carrot and celery, add cavolo nero and tomato and cook with vegetable broth. Add stale bread slices and let them absorb the liquid until falling apart. Serve with a raw drizzle of oil.",ingredienti:[{nome:"Pane raffermo",qt:"200g"},{nome:"Cavolo nero",qt:"150g"},{nome:"Pomodori pelati",qt:"100g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di pane toscana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:2,g:9,z:5,ch:38,fi:6,ca:70,fe:2.2,mg:40,k2:420,na:380,zn:1.2,fo:50,se:5,col:5}},{id:"tpl_1503",nome:"Minestra maritata napoletana",nome_en:'Neapolitan "married" soup',categoria:"Zuppa",porzioni:6,note:'Cuocere un misto di carni (gallina, cotenna, salsiccia) in acqua per ottenere un brodo saporito. Unire verdure a foglia verde come scarola, cicoria e verza e cuocere finché tenere, lasciando che i sapori si "sposino". Servire con parmigiano o pecorino grattugiato.',note_en:'Cook a mix of meats (hen, pork rind, sausage) in water to make a flavorful broth. Add leafy greens like escarole, chicory and savoy cabbage and cook until tender, letting the flavors "marry". Serve with grated parmesan or pecorino.',ingredienti:[{nome:"Gallina",qt:"300g"},{nome:"Salsiccia",qt:"150g"},{nome:"Scarola",qt:"200g"},{nome:"Cicoria",qt:"150g"},{nome:"Verza",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"30g"}],_dbEntry:{n:"Minestra maritata napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:16,gs:5,g:14,z:3,ch:14,fi:4,ca:100,fe:2,mg:30,k2:350,na:550,zn:1.8,fo:60,se:10,col:45}},{id:"tpl_1504",nome:"Zuppa di scarola e fagioli",nome_en:"Escarole and bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e peperoncino, unire la scarola lavata e lasciarla appassire. Aggiungere i fagioli cannellini già lessati con parte del brodo di cottura e proseguire la cottura. Servire con crostini di pane e un filo d'olio.",note_en:"Sauté garlic and chili, add the washed escarole and let it wilt. Add already-cooked cannellini beans with some of their cooking broth and continue cooking. Serve with bread croutons and a drizzle of oil.",ingredienti:[{nome:"Scarola",qt:"300g"},{nome:"Fagioli cannellini",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di scarola e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:12,gs:1,g:6,z:4,ch:36,fi:8,ca:90,fe:2.8,mg:55,k2:500,na:360,zn:1.4,fo:70,se:6,col:0}},{id:"tpl_1505",nome:"Zuppa di broccoli e arzilla",nome_en:"Broccoli and skate fish soup",categoria:"Zuppa",porzioni:4,note:"Lessare l'arzilla (razza) in acqua aromatizzata con sedano e carota, poi sfilettarla eliminando le lische. Cuocere i broccoli nello stesso brodo insieme ad aglio e peperoncino, poi riunire il pesce. Servire con crostini di pane strofinati con aglio.",note_en:"Boil the skate in water flavored with celery and carrot, then fillet it removing the bones. Cook the broccoli in the same broth with garlic and chili, then add back the fish. Serve with garlic-rubbed bread croutons.",ingredienti:[{nome:"Razza (arzilla)",qt:"400g"},{nome:"Broccoli",qt:"300g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Pane",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di broccoli e arzilla (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:18,gs:1.5,g:7,z:3,ch:15,fi:4,ca:80,fe:1.5,mg:35,k2:400,na:450,zn:1,fo:60,se:25,col:40}},{id:"tpl_1506",nome:"Zuppa di baccalà",nome_en:"Salt cod soup",categoria:"Zuppa",porzioni:4,note:"Dissalare il baccalà con ammollo prolungato e cambi d'acqua, poi tagliarlo a pezzi. Soffriggere cipolla e pomodoro, unire il baccalà e cuocere delicatamente a fuoco basso. Servire con crostini di pane e prezzemolo fresco.",note_en:"Desalt the cod through prolonged soaking with water changes, then cut into pieces. Sauté onion and tomato, add the cod and cook gently on low heat. Serve with bread croutons and fresh parsley.",ingredienti:[{nome:"Baccalà ammollato",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"100g"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Zuppa di baccalà (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:22,gs:1.5,g:9,z:3,ch:16,fi:2,ca:70,fe:1.5,mg:35,k2:420,na:650,zn:1,fo:30,se:35,col:55}},{id:"tpl_1507",nome:"Zuppa di gamberi e zucchine",nome_en:"Shrimp and zucchini soup",categoria:"Zuppa",porzioni:4,note:"Sgusciare i gamberi e usare i carapaci per fare un fumetto veloce con carota, sedano e cipolla. Nel fumetto filtrato cuocere le zucchine a rondelle, poi unire i gamberi solo per pochi minuti. Servire con crostini e un filo d'olio.",note_en:"Shell the shrimp and use the shells to make a quick stock with carrot, celery and onion. In the strained stock, cook sliced zucchini, then add the shrimp for just a few minutes. Serve with croutons and a drizzle of oil.",ingredienti:[{nome:"Gamberi",qt:"350g"},{nome:"Zucchine",qt:"250g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di gamberi e zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1.2,g:8,z:4,ch:14,fi:2,ca:70,fe:1.2,mg:35,k2:380,na:480,zn:1.5,fo:35,se:30,col:140}},{id:"tpl_1508",nome:"Brodetto alla veneziana",nome_en:"Venetian-style fish stew",categoria:"Zuppa",porzioni:4,note:"Rosolare cipolla in olio, sfumare con aceto di vino bianco e unire pomodoro. Aggiungere il misto di pesce e molluschi partendo da quelli più duri, cuocendo a fuoco dolce. Servire con polenta bianca o crostini di pane.",note_en:"Brown onion in oil, deglaze with white wine vinegar and add tomato. Add the mixed fish and shellfish starting with the firmer ones, cooking on gentle heat. Serve with white polenta or bread croutons.",ingredienti:[{nome:"Misto di pesce da zuppa",qt:"600g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Aceto di vino bianco",qt:"2 cucchiai"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Brodetto alla veneziana (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:26,gs:2,g:11,z:3,ch:16,fi:2,ca:70,fe:2,mg:50,k2:480,na:520,zn:1.7,fo:35,se:35,col:100}},{id:"tpl_1509",nome:"Brodetto di pesce anconetano",nome_en:"Ancona-style fish stew",categoria:"Zuppa",porzioni:4,note:"Preparare un soffritto di cipolla e peperone verde, sfumare con aceto e unire pomodoro concentrato diluito. Aggiungere il misto di pesce dell'Adriatico in ordine di cottura, dai più sodi ai più delicati. Servire con crostini di pane abbrustolito.",note_en:"Prepare a sauté of onion and green pepper, deglaze with vinegar and add diluted tomato paste. Add the mixed Adriatic fish in order of cooking time, from firmer to more delicate. Serve with toasted bread croutons.",ingredienti:[{nome:"Misto di pesce da zuppa",qt:"600g"},{nome:"Peperone verde",qt:"1"},{nome:"Cipolla",qt:"1"},{nome:"Concentrato di pomodoro",qt:"2 cucchiai"},{nome:"Aceto di vino bianco",qt:"1 cucchiaio"},{nome:"Pane",qt:"150g"}],_dbEntry:{n:"Brodetto di pesce anconetano (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:25,gs:2,g:11,z:3,ch:17,fi:2,ca:70,fe:2,mg:50,k2:470,na:510,zn:1.6,fo:35,se:35,col:100}},{id:"tpl_1510",nome:"Zuppa di seppie e piselli",nome_en:"Cuttlefish and pea soup",categoria:"Zuppa",porzioni:4,note:"Rosolare cipolla e aglio, unire le seppie tagliate ad anelli e sfumare con vino bianco. Aggiungere pomodoro e piselli e cuocere finché le seppie sono morbide. Servire con crostini di pane e prezzemolo tritato.",note_en:"Brown onion and garlic, add the cuttlefish cut into rings and deglaze with white wine. Add tomato and peas and cook until the cuttlefish is tender. Serve with bread croutons and chopped parsley.",ingredienti:[{nome:"Seppie",qt:"400g"},{nome:"Piselli",qt:"200g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Vino bianco",qt:"80ml"}],_dbEntry:{n:"Zuppa di seppie e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:20,gs:1.3,g:8,z:5,ch:20,fi:5,ca:60,fe:1.8,mg:40,k2:420,na:420,zn:1.4,fo:60,se:28,col:150}},{id:"tpl_1511",nome:"Zuppa di lenticchie e salsiccia",nome_en:"Lentil and sausage soup",categoria:"Zuppa",porzioni:4,note:"Rosolare la salsiccia sgranata con cipolla, carota e sedano. Unire le lenticchie e coprire con brodo, cuocendo finché sono morbide. Servire ben calda con un filo d'olio e pepe nero.",note_en:"Brown the crumbled sausage with onion, carrot and celery. Add the lentils and cover with broth, cooking until tender. Serve piping hot with a drizzle of oil and black pepper.",ingredienti:[{nome:"Lenticchie secche",qt:"200g"},{nome:"Salsiccia",qt:"200g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Zuppa di lenticchie e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:18,gs:5,g:14,z:4,ch:38,fi:8,ca:60,fe:4,mg:60,k2:600,na:550,zn:2,fo:130,se:8,col:35}},{id:"tpl_1512",nome:"Zuppa di fagioli e cotiche",nome_en:"Bean and pork rind soup",categoria:"Zuppa",porzioni:4,note:"Lessare le cotiche di maiale a lungo fino a intenerirle, poi tagliarle a listarelle. Cuocere i fagioli borlotti con cipolla, pomodoro e le cotiche insieme. Servire calda con crostini di pane e pepe nero.",note_en:"Boil the pork rinds for a long time until tender, then cut them into strips. Cook the borlotti beans with onion, tomato and the rinds together. Serve hot with bread croutons and black pepper.",ingredienti:[{nome:"Fagioli borlotti",qt:"300g"},{nome:"Cotenna di maiale",qt:"150g"},{nome:"Pomodori pelati",qt:"100g"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Zuppa di fagioli e cotiche (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:17,gs:5,g:13,z:3,ch:36,fi:8,ca:70,fe:3,mg:55,k2:550,na:520,zn:1.8,fo:80,se:7,col:40}},{id:"tpl_1513",nome:"Minestrone estivo",nome_en:"Summer minestrone",categoria:"Zuppa",porzioni:4,note:"Tagliare a cubetti zucchine, fagiolini, pomodori e patate novelle. Cuocere in brodo vegetale leggero fino a cottura di tutte le verdure. Servire tiepido con basilico fresco e un filo d'olio a crudo.",note_en:"Dice zucchini, green beans, tomatoes and new potatoes. Cook in a light vegetable broth until all vegetables are done. Serve warm with fresh basil and a raw drizzle of oil.",ingredienti:[{nome:"Zucchine",qt:"150g"},{nome:"Fagiolini",qt:"150g"},{nome:"Pomodori",qt:"150g"},{nome:"Patate novelle",qt:"150g"},{nome:"Basilico fresco",qt:"q.b."}],_dbEntry:{n:"Minestrone estivo (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:6,gs:1,g:5,z:7,ch:26,fi:5,ca:50,fe:1.3,mg:35,k2:400,na:320,zn:.8,fo:50,se:4,col:0}},{id:"tpl_1514",nome:"Minestrone invernale al cavolo nero",nome_en:"Winter minestrone with cavolo nero",categoria:"Zuppa",porzioni:6,note:"Soffriggere cipolla, carota e sedano, unire cavolo nero, patate e fagioli borlotti già lessati. Coprire con brodo e cuocere a lungo finché tutte le verdure sono morbide. Servire con crostini di pane raffermo e olio a crudo.",note_en:"Sauté onion, carrot and celery, add cavolo nero, potatoes and already-cooked borlotti beans. Cover with broth and simmer a long time until all vegetables are soft. Serve with stale bread croutons and raw oil.",ingredienti:[{nome:"Cavolo nero",qt:"200g"},{nome:"Fagioli borlotti",qt:"200g"},{nome:"Patate",qt:"150g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Minestrone invernale al cavolo nero (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:11,gs:1,g:6,z:5,ch:38,fi:8,ca:80,fe:3,mg:55,k2:550,na:370,zn:1.5,fo:75,se:6,col:0}},{id:"tpl_1515",nome:"Zuppa di verdure di stagione",nome_en:"Seasonal vegetable soup",categoria:"Zuppa",porzioni:4,note:"Tagliare a pezzi le verdure di stagione disponibili (carote, zucchine, patate, sedano, pomodoro) e cuocerle in brodo vegetale. Cuocere finché tutte le verdure sono tenere. Servire con un filo d'olio extravergine e basilico fresco.",note_en:"Cut available seasonal vegetables (carrots, zucchini, potatoes, celery, tomato) into pieces and cook in vegetable broth. Cook until all vegetables are tender. Serve with a drizzle of olive oil and fresh basil.",ingredienti:[{nome:"Carota",qt:"1"},{nome:"Zucchine",qt:"150g"},{nome:"Patate",qt:"150g"},{nome:"Sedano",qt:"1 costa"},{nome:"Pomodori",qt:"100g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di verdure di stagione (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:5,gs:1.2,g:6,z:6,ch:20,fi:5,ca:50,fe:1.3,mg:30,k2:400,na:320,zn:.7,fo:50,se:4,col:0}},{id:"tpl_1516",nome:"Zuppa di sedano e patate",nome_en:"Celery and potato soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla e sedano tagliato a pezzetti, unire le patate a cubetti e coprire con brodo vegetale. Cuocere finché le patate si disfano leggermente. Frullare parzialmente e servire con un filo d'olio.",note_en:"Sauté onion and chopped celery, add diced potatoes and cover with vegetable broth. Cook until the potatoes soften and slightly fall apart. Partially blend and serve with a drizzle of oil.",ingredienti:[{nome:"Sedano",qt:"300g"},{nome:"Patate",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di sedano e patate (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:5,gs:1.5,g:6,z:4,ch:27,fi:4,ca:50,fe:1.2,mg:25,k2:400,na:320,zn:.7,fo:35,se:4,col:5}},{id:"tpl_1517",nome:"Zuppa di carciofi",nome_en:"Artichoke soup",categoria:"Zuppa",porzioni:4,note:"Pulire i carciofi eliminando le foglie esterne e le spine, tagliarli a spicchi e metterli in acqua acidulata. Stufarli con cipolla e prezzemolo, poi coprire con brodo vegetale e cuocere fino a cottura. Servire con un filo d'olio a crudo.",note_en:"Clean the artichokes removing outer leaves and thorns, cut into wedges and place in acidulated water. Stew with onion and parsley, then cover with vegetable broth and cook until done. Serve with a raw drizzle of oil.",ingredienti:[{nome:"Carciofi",qt:"4"},{nome:"Cipolla",qt:"1"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Limone",qt:"1/2"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di carciofi (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:6,gs:2.5,g:7,z:3,ch:18,fi:6,ca:60,fe:1.5,mg:35,k2:380,na:330,zn:.8,fo:80,se:5,col:10}},{id:"tpl_1518",nome:"Vellutata di carciofi",nome_en:"Artichoke velouté",categoria:"Zuppa",porzioni:4,note:"Cuocere i cuori di carciofo puliti con patata e cipolla in brodo vegetale. Frullare fino a ottenere una crema liscia e vellutata. Servire con un filo di panna e crostini.",note_en:"Cook cleaned artichoke hearts with potato and onion in vegetable broth. Blend into a smooth, velvety cream. Serve with a swirl of cream and croutons.",ingredienti:[{nome:"Carciofi",qt:"4"},{nome:"Patate",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di carciofi (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:3.8,g:9,z:3,ch:17,fi:5,ca:55,fe:1.4,mg:32,k2:360,na:320,zn:.8,fo:75,se:5,col:15}},{id:"tpl_1519",nome:"Zuppa di rape e fagioli",nome_en:"Turnip greens and bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e peperoncino, unire le cime di rapa lavate e lasciarle appassire. Aggiungere i fagioli cannellini già lessati con parte del loro brodo e proseguire la cottura. Servire con crostini di pane.",note_en:"Sauté garlic and chili, add washed turnip greens and let them wilt. Add already-cooked cannellini beans with some of their broth and continue cooking. Serve with bread croutons.",ingredienti:[{nome:"Cime di rapa",qt:"300g"},{nome:"Fagioli cannellini",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di rape e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:12,gs:1,g:6,z:4,ch:36,fi:8,ca:100,fe:3,mg:55,k2:500,na:350,zn:1.4,fo:80,se:6,col:0}},{id:"tpl_1520",nome:"Zuppa di ceci e porcini",nome_en:"Chickpea and porcini soup",categoria:"Zuppa",porzioni:4,note:"Rosolare i funghi porcini a pezzetti con aglio, unire i ceci lessati e un po' di brodo vegetale. Cuocere una decina di minuti frullando in parte per addensare. Servire con prezzemolo tritato e un filo d'olio.",note_en:"Brown chopped porcini mushrooms with garlic, add cooked chickpeas and some vegetable broth. Cook for about ten minutes, blending part to thicken. Serve with chopped parsley and a drizzle of oil.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Funghi porcini",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di ceci e porcini (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:1.5,g:9,z:4,ch:43,fi:8,ca:55,fe:3,mg:65,k2:550,na:360,zn:1.7,fo:80,se:8,col:0}},{id:"tpl_1521",nome:"Zuppa di farro e ceci",nome_en:"Farro and chickpea soup",categoria:"Zuppa",porzioni:4,note:"Ammollare il farro e cuocerlo insieme ai ceci lessati in brodo vegetale con soffritto di cipolla, carota e sedano. Cuocere finché il farro è tenero. Servire con un filo d'olio a crudo e rosmarino.",note_en:"Soak the farro and cook it with cooked chickpeas in vegetable broth with an onion, carrot and celery sauté. Cook until the farro is tender. Serve with a raw drizzle of oil and rosemary.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Ceci lessati",qt:"250g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Rosmarino",qt:"1 rametto"}],_dbEntry:{n:"Zuppa di farro e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:14,gs:1,g:7,z:4,ch:46,fi:8,ca:55,fe:3,mg:65,k2:540,na:350,zn:1.6,fo:75,se:6,col:0}},{id:"tpl_1522",nome:"Zuppa di orzo e funghi",nome_en:"Barley and mushroom soup",categoria:"Zuppa",porzioni:4,note:"Rosolare i funghi misti con aglio e prezzemolo, unire l'orzo perlato e coprire con brodo vegetale. Cuocere finché l'orzo è tenero, mescolando di tanto in tanto. Servire con pepe nero macinato fresco.",note_en:"Brown mixed mushrooms with garlic and parsley, add pearl barley and cover with vegetable broth. Cook until the barley is tender, stirring occasionally. Serve with freshly ground black pepper.",ingredienti:[{nome:"Orzo perlato",qt:"150g"},{nome:"Funghi misti",qt:"250g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di orzo e funghi (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:8,gs:1.5,g:6,z:3,ch:40,fi:5,ca:40,fe:1.8,mg:40,k2:420,na:330,zn:1.1,fo:40,se:6,col:0}},{id:"tpl_1523",nome:"Crema di patate allo zafferano",nome_en:"Saffron potato cream soup",categoria:"Zuppa",porzioni:4,note:"Cuocere le patate a cubetti con cipolla in brodo vegetale, unendo qualche filamento di zafferano stemperato in acqua tiepida. Frullare fino a ottenere una crema liscia e dorata. Servire con crostini di pane e un filo d'olio.",note_en:"Cook diced potatoes with onion in vegetable broth, adding a few saffron threads dissolved in warm water. Blend into a smooth, golden cream. Serve with bread croutons and a drizzle of oil.",ingredienti:[{nome:"Patate",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Crema di patate allo zafferano (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:4,g:8,z:4,ch:28,fi:3,ca:60,fe:1,mg:25,k2:420,na:330,zn:.7,fo:30,se:4,col:15}},{id:"tpl_1524",nome:"Vellutata di topinambur",nome_en:"Jerusalem artichoke velouté",categoria:"Zuppa",porzioni:4,note:"Pelare i topinambur e cuocerli con cipolla in brodo vegetale finché teneri. Frullare fino a crema liscia, allungando con brodo se necessario. Servire con crostini e un filo d'olio.",note_en:"Peel the Jerusalem artichokes and cook them with onion in vegetable broth until tender. Blend into a smooth cream, thinning with broth if needed. Serve with croutons and a drizzle of oil.",ingredienti:[{nome:"Topinambur",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Vellutata di topinambur (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4,gs:3,g:7,z:6,ch:22,fi:4,ca:50,fe:1,mg:25,k2:400,na:300,zn:.6,fo:30,se:3,col:12}},{id:"tpl_1525",nome:"Zuppa di zucca al curry",nome_en:"Curried pumpkin soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla con curry in polvere, unire la zucca a cubetti e coprire con brodo vegetale. Cuocere finché la zucca è morbida, poi frullare fino a crema. Mantecare con latte di cocco e servire con coriandolo fresco.",note_en:"Sauté onion with curry powder, add diced pumpkin and cover with vegetable broth. Cook until the pumpkin is soft, then blend into a cream. Finish with coconut milk and serve with fresh coriander.",ingredienti:[{nome:"Zucca",qt:"450g"},{nome:"Cipolla",qt:"1"},{nome:"Curry in polvere",qt:"1 cucchiaino"},{nome:"Latte di cocco",qt:"50ml"}],_dbEntry:{n:"Zuppa di zucca al curry (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:3.5,g:9,z:9,ch:22,fi:4,ca:60,fe:1.2,mg:30,k2:400,na:320,zn:.7,fo:35,se:4,col:10}},{id:"tpl_1526",nome:"Zuppa di cavolo nero e fagioli",nome_en:"Cavolo nero and bean soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e peperoncino, unire il cavolo nero a listarelle e lasciarlo appassire. Aggiungere i fagioli borlotti già lessati e un po' di brodo, cuocendo ancora dieci minuti. Servire con crostini di pane e olio a crudo.",note_en:"Sauté garlic and chili, add cavolo nero in strips and let it wilt. Add already-cooked borlotti beans and some broth, cooking another ten minutes. Serve with bread croutons and raw oil.",ingredienti:[{nome:"Cavolo nero",qt:"300g"},{nome:"Fagioli borlotti",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"1"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di cavolo nero e fagioli (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:13,gs:1,g:6,z:4,ch:40,fi:9,ca:90,fe:3.2,mg:60,k2:560,na:360,zn:1.6,fo:85,se:6,col:0}},{id:"tpl_1527",nome:"Zuppa di fave e cicoria",nome_en:"Fava bean and chicory soup",categoria:"Zuppa",porzioni:4,note:"Cuocere le fave secche decorticate in acqua con cipolla fino a disfarle completamente in una crema. Lessare separatamente la cicoria e adagiarla sopra la crema di fave. Servire con un filo d'olio pugliese e crostini.",note_en:"Cook peeled dried fava beans in water with onion until they completely fall apart into a cream. Separately boil the chicory and lay it over the fava cream. Serve with a drizzle of Apulian olive oil and croutons.",ingredienti:[{nome:"Fave secche decorticate",qt:"300g"},{nome:"Cicoria",qt:"250g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di fave e cicoria (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:14,gs:1.2,g:8,z:4,ch:38,fi:9,ca:80,fe:3,mg:60,k2:520,na:350,zn:1.7,fo:90,se:6,col:0}},{id:"tpl_1528",nome:"Zuppa di piselli secchi e speck",nome_en:"Split pea and speck soup",categoria:"Zuppa",porzioni:4,note:"Ammollare i piselli secchi e cuocerli con cipolla e alloro fino a disfarli. Rosolare a parte lo speck a listarelle croccanti e unirlo alla zuppa. Servire calda con crostini di pane.",note_en:"Soak the split peas and cook them with onion and bay leaf until they break down. Separately brown the speck into crispy strips and add to the soup. Serve hot with bread croutons.",ingredienti:[{nome:"Piselli secchi",qt:"250g"},{nome:"Speck",qt:"100g"},{nome:"Cipolla",qt:"1"},{nome:"Alloro",qt:"1 foglia"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di piselli secchi e speck (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:16,gs:3.5,g:10,z:5,ch:38,fi:8,ca:50,fe:3,mg:55,k2:480,na:550,zn:1.7,fo:90,se:7,col:25}},{id:"tpl_1529",nome:"Zuppa di miglio e verdure",nome_en:"Millet and vegetable soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere carota, sedano e cipolla, unire il miglio sciacquato e tostarlo brevemente. Coprire con brodo vegetale e cuocere finché il miglio è tenero, aggiungendo zucchine a metà cottura. Servire con un filo d'olio.",note_en:"Sauté carrot, celery and onion, add rinsed millet and toast briefly. Cover with vegetable broth and cook until the millet is tender, adding zucchini halfway through. Serve with a drizzle of oil.",ingredienti:[{nome:"Miglio",qt:"150g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Zucchine",qt:"150g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Zuppa di miglio e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:7,gs:1,g:6,z:4,ch:38,fi:4,ca:40,fe:1.5,mg:50,k2:400,na:320,zn:1,fo:40,se:5,col:0}},{id:"tpl_1530",nome:"Zuppa valtellinese di grano saraceno",nome_en:"Valtellina buckwheat soup",categoria:"Zuppa",porzioni:4,note:"Cuocere il grano saraceno con patate, verza e fagioli borlotti in brodo vegetale per un tempo prolungato. Mantecare a fine cottura con burro e formaggio Casera a tocchetti. Servire fumante, tipica delle valli alpine lombarde.",note_en:"Cook buckwheat with potatoes, savoy cabbage and borlotti beans in vegetable broth for an extended time. Finish with butter and chunks of Casera cheese. Serve piping hot, typical of the Lombard alpine valleys.",ingredienti:[{nome:"Grano saraceno",qt:"150g"},{nome:"Patate",qt:"150g"},{nome:"Verza",qt:"150g"},{nome:"Fagioli borlotti",qt:"150g"},{nome:"Formaggio Casera",qt:"60g"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Zuppa valtellinese di grano saraceno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:1.5,g:6,z:4,ch:42,fi:6,ca:60,fe:2,mg:55,k2:420,na:350,zn:1.2,fo:40,se:6,col:5}},{id:"tpl_1531",nome:"Zuppa di trippa alla romana",nome_en:"Roman-style tripe soup",categoria:"Zuppa",porzioni:4,note:"Lessare la trippa già pulita, poi tagliarla a listarelle sottili. Soffriggere cipolla, carota e sedano, unire pomodoro e la trippa e cuocere a lungo. Servire con menta romana e pecorino grattugiato.",note_en:"Boil the already-cleaned tripe, then cut it into thin strips. Sauté onion, carrot and celery, add tomato and the tripe and cook for a long time. Serve with Roman mint and grated pecorino.",ingredienti:[{nome:"Trippa",qt:"500g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Mentuccia",qt:"q.b."},{nome:"Pecorino grattugiato",qt:"30g"}],_dbEntry:{n:"Zuppa di trippa alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:20,gs:5,g:14,z:4,ch:18,fi:3,ca:90,fe:2,mg:30,k2:400,na:480,zn:2,fo:40,se:10,col:120}},{id:"tpl_1532",nome:"Zuppa di pollo e verdure",nome_en:"Chicken and vegetable soup",categoria:"Zuppa",porzioni:4,note:"Cuocere il petto di pollo a pezzi con carota, sedano, cipolla e patate in acqua fino a completa cottura. Sfilacciare il pollo se necessario e rimetterlo nella zuppa. Servire caldo con prezzemolo fresco.",note_en:"Cook chicken breast pieces with carrot, celery, onion and potatoes in water until fully cooked. Shred the chicken if needed and return it to the soup. Serve hot with fresh parsley.",ingredienti:[{nome:"Petto di pollo",qt:"300g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"},{nome:"Patate",qt:"150g"},{nome:"Prezzemolo",qt:"q.b."}],_dbEntry:{n:"Zuppa di pollo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:16,gs:2,g:7,z:4,ch:18,fi:3,ca:40,fe:1.3,mg:25,k2:380,na:420,zn:1.2,fo:35,se:15,col:45}},{id:"tpl_1533",nome:"Zuppa di tacchino e orzo",nome_en:"Turkey and barley soup",categoria:"Zuppa",porzioni:4,note:"Cuocere il petto di tacchino a dadini con carota, sedano e cipolla in brodo leggero. Aggiungere l'orzo perlato e proseguire la cottura finché tenero. Servire con pepe nero macinato fresco.",note_en:"Cook diced turkey breast with carrot, celery and onion in a light broth. Add pearl barley and continue cooking until tender. Serve with freshly ground black pepper.",ingredienti:[{nome:"Petto di tacchino",qt:"250g"},{nome:"Orzo perlato",qt:"120g"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Cipolla",qt:"1"}],_dbEntry:{n:"Zuppa di tacchino e orzo (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:17,gs:1.5,g:6,z:3,ch:28,fi:4,ca:35,fe:1.5,mg:30,k2:400,na:400,zn:1.3,fo:35,se:18,col:40}},{id:"tpl_1534",nome:"Brodo vegetale con crostini",nome_en:"Vegetable broth with croutons",categoria:"Zuppa",porzioni:4,note:"Cuocere carota, sedano, cipolla, pomodoro e zucchina in acqua per un'ora a fuoco basso. Filtrare il brodo ottenuto e regolare di sale. Servire caldo con crostini di pane tostato.",note_en:"Cook carrot, celery, onion, tomato and zucchini in water for an hour on low heat. Strain the resulting broth and adjust salt. Serve hot with toasted bread croutons.",ingredienti:[{nome:"Carota",qt:"2"},{nome:"Sedano",qt:"2 coste"},{nome:"Cipolla",qt:"1"},{nome:"Pomodori",qt:"100g"},{nome:"Zucchine",qt:"100g"},{nome:"Pane",qt:"60g"}],_dbEntry:{n:"Brodo vegetale con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:4,gs:.8,g:4,z:4,ch:22,fi:3,ca:40,fe:1,mg:25,k2:350,na:350,zn:.6,fo:35,se:3,col:0}},{id:"tpl_1535",nome:"Zuppa di zucchine e patate",nome_en:"Zucchini and potato soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere cipolla, unire le zucchine e le patate a cubetti e coprire con brodo vegetale. Cuocere finché le verdure sono tenere, frullando parzialmente per addensare. Servire con un filo d'olio e basilico.",note_en:"Sauté onion, add diced zucchini and potatoes and cover with vegetable broth. Cook until the vegetables are tender, partially blending to thicken. Serve with a drizzle of oil and basil.",ingredienti:[{nome:"Zucchine",qt:"250g"},{nome:"Patate",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico fresco",qt:"q.b."}],_dbEntry:{n:"Zuppa di zucchine e patate (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:5,gs:1.5,g:6,z:4,ch:25,fi:3,ca:45,fe:1,mg:28,k2:380,na:320,zn:.7,fo:35,se:4,col:5}},{id:"tpl_1536",nome:"Zuppa di melanzane e pomodoro",nome_en:"Eggplant and tomato soup",categoria:"Zuppa",porzioni:4,note:"Rosolare le melanzane a cubetti in olio con aglio, unire i pomodori pelati e cuocere finché morbide. Frullare parzialmente lasciando qualche pezzo intero. Servire con basilico fresco e un filo d'olio.",note_en:"Brown diced eggplant in oil with garlic, add peeled tomatoes and cook until soft. Partially blend, leaving some pieces whole. Serve with fresh basil and a drizzle of oil.",ingredienti:[{nome:"Melanzane",qt:"350g"},{nome:"Pomodori pelati",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di melanzane e pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:5,gs:1.5,g:9,z:7,ch:20,fi:5,ca:45,fe:1.2,mg:30,k2:400,na:340,zn:.7,fo:40,se:4,col:0}},{id:"tpl_1537",nome:"Zuppa di peperoni arrostiti",nome_en:"Roasted pepper soup",categoria:"Zuppa",porzioni:4,note:"Arrostire i peperoni in forno finché la buccia si stacca facilmente, poi pelarli e privarli dei semi. Frullarli con cipolla stufata e un po' di brodo vegetale fino a ottenere una crema. Servire con un filo d'olio e basilico.",note_en:"Roast the peppers in the oven until the skin comes off easily, then peel and seed them. Blend with stewed onion and a little vegetable broth into a cream. Serve with a drizzle of oil and basil.",ingredienti:[{nome:"Peperoni",qt:"400g"},{nome:"Cipolla",qt:"1"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di peperoni arrostiti (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4,gs:1.3,g:8,z:9,ch:20,fi:4,ca:40,fe:1,mg:25,k2:380,na:330,zn:.6,fo:45,se:4,col:0}},{id:"tpl_1538",nome:"Vellutata di peperoni e pomodoro",nome_en:"Pepper and tomato velouté",categoria:"Zuppa",porzioni:4,note:"Stufare i peperoni a listarelle con cipolla e pomodori pelati fino a cottura completa. Frullare fino a ottenere una crema liscia e vellutata. Mantecare con un filo di panna e servire con crostini.",note_en:"Stew peppers in strips with onion and peeled tomatoes until fully cooked. Blend into a smooth, velvety cream. Finish with a splash of cream and serve with croutons.",ingredienti:[{nome:"Peperoni",qt:"300g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"1"},{nome:"Panna fresca",qt:"30ml"}],_dbEntry:{n:"Vellutata di peperoni e pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:3.5,g:9,z:9,ch:20,fi:4,ca:50,fe:1.1,mg:28,k2:390,na:340,zn:.6,fo:45,se:4,col:12}},{id:"tpl_1539",nome:"Zuppa di castagne e porcini",nome_en:"Chestnut and porcini soup",categoria:"Zuppa",porzioni:4,note:"Rosolare i funghi porcini con aglio e prezzemolo, unire le castagne lessate e sbucciate e coprire con brodo vegetale. Cuocere una ventina di minuti frullando parzialmente per addensare. Servire con crostini di pane e rosmarino.",note_en:"Brown porcini mushrooms with garlic and parsley, add boiled peeled chestnuts and cover with vegetable broth. Cook for about twenty minutes, partially blending to thicken. Serve with bread croutons and rosemary.",ingredienti:[{nome:"Castagne lessate",qt:"250g"},{nome:"Funghi porcini",qt:"200g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Zuppa di castagne e porcini (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:7,gs:1.5,g:8,z:10,ch:42,fi:6,ca:50,fe:1.5,mg:45,k2:480,na:320,zn:.9,fo:40,se:6,col:0}},{id:"tpl_1540",nome:"Zuppa di ceci e bietole",nome_en:"Chickpea and chard soup",categoria:"Zuppa",porzioni:4,note:"Soffriggere aglio e rosmarino, unire le bietole lavate e tagliate a listarelle e lasciarle appassire. Aggiungere i ceci lessati con parte del loro brodo e cuocere ancora una decina di minuti. Servire con crostini di pane e un filo d'olio.",note_en:"Sauté garlic and rosemary, add washed chard cut into strips and let it wilt. Add cooked chickpeas with some of their broth and cook another ten minutes. Serve with bread croutons and a drizzle of oil.",ingredienti:[{nome:"Ceci lessati",qt:"300g"},{nome:"Bietole",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"1 rametto"},{nome:"Pane",qt:"80g"}],_dbEntry:{n:"Zuppa di ceci e bietole (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:13,gs:1.2,g:8,z:4,ch:43,fi:8,ca:90,fe:3.2,mg:65,k2:570,na:360,zn:1.6,fo:95,se:6,col:0}},{id:"tpl_1541",nome:"Parmigiana di melanzane (versione 2)",nome_en:"Eggplant parmigiana (version 2)",categoria:"Piatto unico",porzioni:6,note:"Tagliare le melanzane a fette e friggerle o grigliarle. Preparare un sugo di pomodoro semplice con basilico. Comporre strati di melanzane, sugo, mozzarella e parmigiano in una teglia. Infornare a 180°C per 40 minuti finché gratinata.",note_en:"Slice the eggplants and fry or grill them. Prepare a simple tomato sauce with basil. Layer eggplant, sauce, mozzarella and parmesan in a baking dish. Bake at 180°C for 40 minutes until golden and bubbling.",ingredienti:[{nome:"Melanzane",qt:"1kg"},{nome:"Pomodoro passata",qt:"500g"},{nome:"Mozzarella",qt:"300g"},{nome:"Parmigiano grattugiato",qt:"80g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Parmigiana di melanzane (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:8,g:28,z:8,ch:20,fi:4,ca:320,fe:1.5,mg:35,k2:450,na:420,zn:1.8,fo:40,se:10,col:45}},{id:"tpl_1542",nome:"Cous cous alla trapanese di pesce",nome_en:"Trapani-style fish couscous",categoria:"Piatto unico",porzioni:4,note:"Preparare un brodo di pesce misto con pomodoro, aglio e prezzemolo. Cuocere il cous cous incorporandolo con il brodo di pesce secondo la tradizione trapanese. Servire il cous cous con i pezzi di pesce e mandorle tostate.",note_en:"Prepare a mixed fish broth with tomato, garlic and parsley. Cook the couscous incorporating it with the fish broth in the traditional Trapani style. Serve the couscous with the pieces of fish and toasted almonds.",ingredienti:[{nome:"Cous cous",qt:"320g"},{nome:"Pesce misto (nasello, gamberi, cozze)",qt:"600g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Mandorle",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cous cous alla trapanese di pesce (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:32,gs:3,g:14,z:4,ch:55,fi:4,ca:80,fe:2.5,mg:60,k2:500,na:380,zn:1.5,fo:35,se:40,col:90}},{id:"tpl_1543",nome:"Gnocchi alla sorrentina con contorno di verdure",nome_en:"Sorrento-style gnocchi with vegetable side",categoria:"Piatto unico",porzioni:4,note:"Cuocere gli gnocchi di patate in acqua salata. Condire con sugo di pomodoro fresco e basilico, disporre in una teglia con mozzarella e parmigiano, gratinare in forno. Servire con un contorno di verdure grigliate.",note_en:"Cook the potato gnocchi in salted water. Dress with fresh tomato sauce and basil, arrange in a baking dish with mozzarella and parmesan, gratin in the oven. Serve with a side of grilled vegetables.",ingredienti:[{nome:"Gnocchi di patate",qt:"500g"},{nome:"Pomodori pelati",qt:"400g"},{nome:"Mozzarella",qt:"200g"},{nome:"Parmigiano grattugiato",qt:"50g"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Zucchine",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Gnocchi alla sorrentina con contorno di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:20,gs:9,g:22,z:7,ch:62,fi:5,ca:300,fe:2,mg:45,k2:480,na:400,zn:1.8,fo:38,se:12,col:40}},{id:"tpl_1544",nome:"Riso alla cantonese all'italiana",nome_en:"Italian-style Cantonese rice",categoria:"Piatto unico",porzioni:4,note:"Cuocere il riso e farlo raffreddare. Saltare in padella con uova strapazzate, piselli, prosciutto cotto a dadini e un filo di salsa di soia. Mantecare con olio di semi e servire caldo.",note_en:"Cook the rice and let it cool. Stir-fry in a pan with scrambled eggs, peas, diced cooked ham and a splash of soy sauce. Finish with seed oil and serve hot.",ingredienti:[{nome:"Riso",qt:"320g"},{nome:"Uova",qt:"3"},{nome:"Piselli",qt:"150g"},{nome:"Prosciutto cotto",qt:"120g"},{nome:"Salsa di soia",qt:"20ml"},{nome:"Olio di semi",qt:"20ml"},{nome:"Cipollotto",qt:"1"}],_dbEntry:{n:"Riso alla cantonese all'italiana (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:20,gs:3,g:14,z:3,ch:68,fi:3,ca:60,fe:2,mg:40,k2:300,na:650,zn:1.5,fo:60,se:20,col:180}},{id:"tpl_1545",nome:"Insalata di riso completa",nome_en:"Complete rice salad",categoria:"Piatto unico",porzioni:4,note:"Lessare il riso e raffreddarlo sotto acqua corrente. Condire con tonno, prosciutto cotto a dadini, formaggio, olive, pomodorini e mais. Aggiungere olio e origano, mescolare bene e servire freddo.",note_en:"Boil the rice and cool it under running water. Dress with tuna, diced cooked ham, cheese, olives, cherry tomatoes and corn. Add oil and oregano, mix well and serve cold.",ingredienti:[{nome:"Riso",qt:"320g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Prosciutto cotto",qt:"100g"},{nome:"Formaggio a dadini",qt:"100g"},{nome:"Olive",qt:"60g"},{nome:"Pomodorini",qt:"200g"},{nome:"Mais",qt:"100g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata di riso completa (ricetta)",c:"Ricette",src:"RICETTE",k:490,p:24,gs:5,g:18,z:5,ch:58,fi:3,ca:150,fe:2,mg:45,k2:380,na:550,zn:1.8,fo:40,se:25,col:45}},{id:"tpl_1546",nome:"Farro con legumi e verdure",nome_en:"Farro with legumes and vegetables",categoria:"Piatto unico",porzioni:4,note:"Lessare il farro in acqua salata. Cuocere separatamente ceci e fagioli con carote, sedano e cipolla. Unire il farro ai legumi, insaporire con olio, aglio e rosmarino, servire tiepido.",note_en:"Boil the farro in salted water. Separately cook chickpeas and beans with carrots, celery and onion. Combine the farro with the legumes, season with oil, garlic and rosemary, serve warm.",ingredienti:[{nome:"Farro",qt:"280g"},{nome:"Ceci lessati",qt:"200g"},{nome:"Fagioli borlotti lessati",qt:"200g"},{nome:"Carote",qt:"100g"},{nome:"Sedano",qt:"80g"},{nome:"Cipolla",qt:"60g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Rosmarino",qt:"q.b."}],_dbEntry:{n:"Farro con legumi e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:18,gs:1.5,g:12,z:5,ch:65,fi:12,ca:90,fe:4,mg:90,k2:550,na:200,zn:2.2,fo:90,se:10,col:0}},{id:"tpl_1547",nome:"Polenta con salsiccia e funghi",nome_en:"Polenta with sausage and mushrooms",categoria:"Piatto unico",porzioni:4,note:"Preparare la polenta mescolando farina di mais in acqua bollente salata per 45 minuti. Rosolare la salsiccia a pezzi con funghi trifolati, aglio e prezzemolo. Servire la polenta calda coperta dal sugo di salsiccia e funghi.",note_en:"Prepare the polenta by stirring cornmeal into boiling salted water for 45 minutes. Brown the sausage pieces with sautéed mushrooms, garlic and parsley. Serve the hot polenta topped with the sausage and mushroom sauce.",ingredienti:[{nome:"Farina di mais",qt:"300g"},{nome:"Salsiccia",qt:"320g"},{nome:"Funghi champignon",qt:"300g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"30ml"},{nome:"Vino bianco",qt:"50ml"}],_dbEntry:{n:"Polenta con salsiccia e funghi (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:22,gs:9,g:32,z:3,ch:48,fi:4,ca:40,fe:2.5,mg:50,k2:500,na:600,zn:2.5,fo:25,se:15,col:55}},{id:"tpl_1548",nome:"Tortino di patate con carne e verdure",nome_en:"Potato pie with meat and vegetables",categoria:"Piatto unico",porzioni:4,note:"Lessare e schiacciare le patate per il purè. Preparare un ripieno di carne macinata rosolata con carote e piselli. Alternare strati di purè e ripieno in una teglia, spolverare con formaggio e gratinare in forno per 25 minuti.",note_en:"Boil and mash the potatoes for the puree. Prepare a filling of browned ground meat with carrots and peas. Alternate layers of puree and filling in a baking dish, sprinkle with cheese and gratin in the oven for 25 minutes.",ingredienti:[{nome:"Patate",qt:"600g"},{nome:"Carne macinata di manzo",qt:"300g"},{nome:"Carote",qt:"100g"},{nome:"Piselli",qt:"100g"},{nome:"Formaggio grattugiato",qt:"50g"},{nome:"Burro",qt:"30g"},{nome:"Latte",qt:"100ml"},{nome:"Cipolla",qt:"60g"}],_dbEntry:{n:"Tortino di patate con carne e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:24,gs:10,g:24,z:6,ch:40,fi:5,ca:180,fe:2.5,mg:50,k2:700,na:380,zn:3,fo:40,se:15,col:70}},{id:"tpl_1549",nome:"Paella di mare all'italiana",nome_en:"Italian-style seafood paella",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla e peperoni, aggiungere il riso e tostarlo. Bagnare gradualmente con brodo di pesce e zafferano, unendo cozze, gamberi e calamari a metà cottura. Cuocere finché il riso è cotto e il liquido assorbito.",note_en:"Sauté onion and peppers, add the rice and toast it. Gradually add fish broth and saffron, adding mussels, shrimp and squid halfway through cooking. Cook until the rice is done and the liquid is absorbed.",ingredienti:[{nome:"Riso",qt:"320g"},{nome:"Cozze",qt:"300g"},{nome:"Gamberi",qt:"200g"},{nome:"Calamari",qt:"200g"},{nome:"Peperoni",qt:"150g"},{nome:"Cipolla",qt:"80g"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Brodo di pesce",qt:"600ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Paella di mare all'italiana (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:30,gs:2,g:14,z:4,ch:60,fi:3,ca:100,fe:3,mg:70,k2:500,na:550,zn:2,fo:45,se:45,col:150}},{id:"tpl_1550",nome:"Poke bowl mediterraneo",nome_en:"Mediterranean poke bowl",categoria:"Piatto unico",porzioni:2,note:"Cuocere il riso e lasciarlo raffreddare. Marinare il salmone crudo a cubetti con salsa di soia e succo di limone. Comporre la bowl con riso, salmone, avocado, edamame, pomodorini e semi di sesamo.",note_en:"Cook the rice and let it cool. Marinate the raw salmon cubes with soy sauce and lemon juice. Assemble the bowl with rice, salmon, avocado, edamame, cherry tomatoes and sesame seeds.",ingredienti:[{nome:"Riso",qt:"200g"},{nome:"Salmone fresco",qt:"200g"},{nome:"Avocado",qt:"100g"},{nome:"Edamame",qt:"80g"},{nome:"Pomodorini",qt:"100g"},{nome:"Salsa di soia",qt:"20ml"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Succo di limone",qt:"1"}],_dbEntry:{n:"Poke bowl mediterraneo (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:26,gs:4,g:24,z:4,ch:52,fi:6,ca:60,fe:2,mg:70,k2:700,na:500,zn:1.5,fo:60,se:30,col:40}},{id:"tpl_1551",nome:"Buddha bowl di quinoa e ceci",nome_en:"Quinoa and chickpea buddha bowl",categoria:"Piatto unico",porzioni:2,note:"Cuocere la quinoa in acqua salata. Rosolare i ceci con paprika e cumino. Comporre la bowl con quinoa, ceci speziati, carote julienne, spinaci freschi e una salsa allo yogurt.",note_en:"Cook the quinoa in salted water. Brown the chickpeas with paprika and cumin. Assemble the bowl with quinoa, spiced chickpeas, julienned carrots, fresh spinach and a yogurt sauce.",ingredienti:[{nome:"Quinoa",qt:"160g"},{nome:"Ceci lessati",qt:"200g"},{nome:"Carote",qt:"100g"},{nome:"Spinaci freschi",qt:"80g"},{nome:"Yogurt greco",qt:"100g"},{nome:"Paprika",qt:"q.b."},{nome:"Cumino",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Buddha bowl di quinoa e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:18,gs:2,g:14,z:6,ch:62,fi:12,ca:150,fe:4,mg:100,k2:700,na:250,zn:2.5,fo:120,se:8,col:5}},{id:"tpl_1552",nome:"Risotto alla milanese con ossobuco",nome_en:"Milanese risotto with ossobuco",categoria:"Piatto unico",porzioni:4,note:"Preparare il risotto tostando il riso, sfumando con vino bianco e cuocendo con brodo e zafferano, mantecando con burro e parmigiano. Cuocere separatamente l'ossobuco brasato con verdure e vino per due ore. Servire il risotto con l'ossobuco adagiato sopra.",note_en:"Prepare the risotto by toasting the rice, deglazing with white wine and cooking with broth and saffron, finishing with butter and parmesan. Separately braise the ossobuco with vegetables and wine for two hours. Serve the risotto with the ossobuco on top.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Ossobuco di vitello",qt:"4 pezzi"},{nome:"Zafferano",qt:"1 bustina"},{nome:"Brodo di carne",qt:"800ml"},{nome:"Vino bianco",qt:"100ml"},{nome:"Burro",qt:"60g"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Carote",qt:"80g"},{nome:"Sedano",qt:"60g"},{nome:"Cipolla",qt:"80g"}],_dbEntry:{n:"Risotto alla milanese con ossobuco (ricetta)",c:"Ricette",src:"RICETTE",k:650,p:38,gs:12,g:28,z:3,ch:55,fi:2,ca:150,fe:4,mg:50,k2:600,na:450,zn:4,fo:30,se:25,col:120}},{id:"tpl_1553",nome:"Pasta e fagioli con cotenna",nome_en:"Pasta and beans with pork rind",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla, sedano e carota, aggiungere la cotenna di maiale e i fagioli borlotti con acqua o brodo. Cuocere a fuoco lento per un'ora, unire la pasta corta e cuocere fino a completo assorbimento. Servire con un filo di olio a crudo.",note_en:"Sauté onion, celery and carrot, add the pork rind and borlotti beans with water or broth. Simmer for an hour, add short pasta and cook until the liquid is absorbed. Serve with a drizzle of raw olive oil.",ingredienti:[{nome:"Fagioli borlotti",qt:"300g"},{nome:"Pasta corta",qt:"200g"},{nome:"Cotenna di maiale",qt:"100g"},{nome:"Cipolla",qt:"60g"},{nome:"Sedano",qt:"60g"},{nome:"Carote",qt:"60g"},{nome:"Concentrato di pomodoro",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pasta e fagioli con cotenna (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:20,gs:4,g:14,z:3,ch:65,fi:10,ca:80,fe:3,mg:70,k2:600,na:350,zn:1.8,fo:100,se:10,col:25}},{id:"tpl_1554",nome:"Ribollita toscana (versione 3)",nome_en:"Tuscan ribollita (version 3)",categoria:"Piatto unico",porzioni:4,note:"Preparare un minestrone con cavolo nero, fagioli cannellini, patate, carote e pane raffermo. Cuocere a fuoco lento per almeno un'ora fino a ottenere una consistenza densa. Servire con un filo d'olio extravergine e pepe.",note_en:"Prepare a soup with black cabbage, cannellini beans, potatoes, carrots and stale bread. Simmer for at least an hour until thick. Serve with a drizzle of extra virgin olive oil and pepper.",ingredienti:[{nome:"Cavolo nero",qt:"300g"},{nome:"Fagioli cannellini",qt:"250g"},{nome:"Pane raffermo",qt:"200g"},{nome:"Patate",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Cipolla",qt:"80g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Ribollita toscana (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:15,gs:2,g:14,z:5,ch:58,fi:10,ca:150,fe:4,mg:80,k2:700,na:350,zn:1.8,fo:90,se:8,col:0}},{id:"tpl_1555",nome:"Cassoeula con polenta",nome_en:"Cassoeula with polenta",categoria:"Piatto unico",porzioni:4,note:"Rosolare le costine e le parti di maiale con cipolla, poi unire il verzino tagliato a listarelle. Cuocere lentamente per due ore aggiungendo brodo se necessario. Servire con polenta morbida calda.",note_en:"Brown the ribs and pork cuts with onion, then add the savoy cabbage cut into strips. Cook slowly for two hours, adding broth if needed. Serve with warm soft polenta.",ingredienti:[{nome:"Costine di maiale",qt:"500g"},{nome:"Verza",qt:"600g"},{nome:"Salamini da cuocere",qt:"200g"},{nome:"Cipolla",qt:"80g"},{nome:"Farina di mais",qt:"250g"},{nome:"Vino bianco",qt:"80ml"},{nome:"Concentrato di pomodoro",qt:"20g"}],_dbEntry:{n:"Cassoeula con polenta (ricetta)",c:"Ricette",src:"RICETTE",k:620,p:30,gs:14,g:40,z:4,ch:35,fi:5,ca:80,fe:3,mg:45,k2:550,na:700,zn:3,fo:30,se:20,col:100}},{id:"tpl_1556",nome:"Bagna cauda con verdure e pane",nome_en:"Bagna cauda with vegetables and bread",categoria:"Piatto unico",porzioni:4,note:"Sciogliere le acciughe in olio e burro con aglio a fuoco bassissimo per 30 minuti mescolando continuamente. Servire calda in un tegame di coccio accompagnata da verdure crude e cotte di stagione e crostoni di pane.",note_en:"Melt the anchovies in oil and butter with garlic over very low heat for 30 minutes, stirring constantly. Serve hot in an earthenware pot accompanied by raw and cooked seasonal vegetables and toasted bread.",ingredienti:[{nome:"Acciughe sotto sale",qt:"150g"},{nome:"Aglio",qt:"4 teste"},{nome:"Olio extravergine",qt:"150ml"},{nome:"Burro",qt:"40g"},{nome:"Peperoni",qt:"200g"},{nome:"Cardi",qt:"200g"},{nome:"Pane casereccio",qt:"200g"}],_dbEntry:{n:"Bagna cauda con verdure e pane (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:14,gs:10,g:45,z:5,ch:35,fi:4,ca:100,fe:2,mg:40,k2:400,na:900,zn:1.5,fo:25,se:30,col:30}},{id:"tpl_1557",nome:"Pizzoccheri valtellinesi",nome_en:"Valtellina buckwheat pasta",categoria:"Piatto unico",porzioni:4,note:"Cuocere i pizzoccheri insieme a patate e verza in acqua bollente salata. Scolare e comporre a strati con formaggio Casera e burro fuso all'aglio e salvia. Gratinare brevemente in forno prima di servire.",note_en:"Cook the pizzoccheri together with potatoes and savoy cabbage in boiling salted water. Drain and layer with Casera cheese and butter melted with garlic and sage. Gratin briefly in the oven before serving.",ingredienti:[{nome:"Pizzoccheri",qt:"350g"},{nome:"Patate",qt:"200g"},{nome:"Verza",qt:"200g"},{nome:"Formaggio Casera",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Salvia",qt:"q.b."},{nome:"Parmigiano grattugiato",qt:"40g"}],_dbEntry:{n:"Pizzoccheri valtellinesi (ricetta)",c:"Ricette",src:"RICETTE",k:640,p:24,gs:18,g:32,z:4,ch:70,fi:5,ca:350,fe:2.5,mg:50,k2:500,na:400,zn:2.5,fo:40,se:15,col:70}},{id:"tpl_1558",nome:"Orecchiette con cime di rapa e salsiccia",nome_en:"Orecchiette with turnip greens and sausage",categoria:"Piatto unico",porzioni:4,note:"Lessare le orecchiette insieme alle cime di rapa. Rosolare la salsiccia sbriciolata con aglio e peperoncino in olio extravergine. Scolare pasta e verdure, saltare in padella con la salsiccia e completare con pecorino.",note_en:"Boil the orecchiette together with the turnip greens. Brown the crumbled sausage with garlic and chili in olive oil. Drain the pasta and greens, toss in the pan with the sausage and finish with pecorino.",ingredienti:[{nome:"Orecchiette",qt:"350g"},{nome:"Cime di rapa",qt:"400g"},{nome:"Salsiccia",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Pecorino grattugiato",qt:"40g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Orecchiette con cime di rapa e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:24,gs:8,g:22,z:3,ch:65,fi:5,ca:120,fe:3,mg:50,k2:450,na:500,zn:2,fo:80,se:15,col:45}},{id:"tpl_1559",nome:"Panzanella completa con tonno e uova",nome_en:"Complete panzanella with tuna and eggs",categoria:"Piatto unico",porzioni:4,note:"Ammollare il pane raffermo in acqua e strizzarlo. Tagliare pomodori, cetrioli e cipolla rossa, unire il pane sbriciolato, tonno sgocciolato e uova sode a spicchi. Condire con olio, aceto, sale e basilico.",note_en:"Soak the stale bread in water and squeeze it out. Cut tomatoes, cucumbers and red onion, add the crumbled bread, drained tuna and wedges of hard-boiled egg. Dress with oil, vinegar, salt and basil.",ingredienti:[{nome:"Pane raffermo",qt:"250g"},{nome:"Pomodori",qt:"300g"},{nome:"Cetrioli",qt:"150g"},{nome:"Cipolla rossa",qt:"60g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Uova sode",qt:"3"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Aceto di vino",qt:"20ml"}],_dbEntry:{n:"Panzanella completa con tonno e uova (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:24,gs:4,g:20,z:6,ch:42,fi:4,ca:80,fe:2.5,mg:40,k2:500,na:450,zn:1.8,fo:60,se:30,col:220}},{id:"tpl_1560",nome:"Caponata siciliana con couscous",nome_en:"Sicilian caponata with couscous",categoria:"Piatto unico",porzioni:4,note:"Friggere le melanzane a cubetti e tenerle da parte. Preparare un soffritto con sedano, cipolla, olive, capperi e pomodoro, unire le melanzane e aggiungere zucchero e aceto per l'agrodolce. Servire la caponata su un letto di cous cous cotto a vapore.",note_en:"Fry the diced eggplant and set aside. Prepare a base of celery, onion, olives, capers and tomato, add the eggplant and sugar and vinegar for the sweet-and-sour flavor. Serve the caponata over a bed of steamed couscous.",ingredienti:[{nome:"Melanzane",qt:"500g"},{nome:"Sedano",qt:"100g"},{nome:"Cipolla",qt:"80g"},{nome:"Olive verdi",qt:"80g"},{nome:"Capperi",qt:"30g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cous cous",qt:"240g"},{nome:"Zucchero",qt:"10g"},{nome:"Aceto di vino",qt:"20ml"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Caponata siciliana con couscous (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:10,gs:2,g:20,z:10,ch:62,fi:6,ca:60,fe:2,mg:50,k2:500,na:500,zn:1,fo:40,se:5,col:0}},{id:"tpl_1561",nome:"Timballo di riso alla siciliana",nome_en:"Sicilian rice timbale",categoria:"Piatto unico",porzioni:6,note:"Cuocere il riso e condirlo con ragù di carne, piselli e caciocavallo a dadini. Foderare uno stampo con pangrattato, riempire con il riso condito e cuocere in forno per 40 minuti fino a doratura. Sformare e servire a fette.",note_en:"Cook the rice and dress it with meat ragù, peas and diced caciocavallo. Line a mold with breadcrumbs, fill with the dressed rice and bake for 40 minutes until golden. Unmold and serve in slices.",ingredienti:[{nome:"Riso",qt:"400g"},{nome:"Carne macinata",qt:"300g"},{nome:"Piselli",qt:"150g"},{nome:"Caciocavallo",qt:"150g"},{nome:"Pomodoro passata",qt:"300g"},{nome:"Pangrattato",qt:"60g"},{nome:"Cipolla",qt:"60g"},{nome:"Uova",qt:"2"}],_dbEntry:{n:"Timballo di riso alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:26,gs:9,g:22,z:5,ch:62,fi:3,ca:200,fe:2.5,mg:45,k2:450,na:480,zn:2.5,fo:35,se:15,col:110}},{id:"tpl_1562",nome:"Vellutata di zucca con farro e salsiccia",nome_en:"Pumpkin velouté with farro and sausage",categoria:"Piatto unico",porzioni:4,note:"Cuocere la zucca a cubetti con cipolla e brodo vegetale, frullare fino a ottenere una crema liscia. Lessare il farro separatamente e rosolare la salsiccia a pezzetti. Servire la vellutata con farro e salsiccia al centro, un filo d'olio e semi di zucca.",note_en:"Cook diced pumpkin with onion and vegetable broth, blend until smooth. Separately boil the farro and brown the diced sausage. Serve the velouté with farro and sausage in the center, a drizzle of oil and pumpkin seeds.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Farro",qt:"200g"},{nome:"Salsiccia",qt:"250g"},{nome:"Cipolla",qt:"60g"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Semi di zucca",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Vellutata di zucca con farro e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:20,gs:8,g:22,z:6,ch:48,fi:6,ca:60,fe:2.5,mg:50,k2:600,na:450,zn:2,fo:40,se:15,col:40}},{id:"tpl_1563",nome:"Zuppa di farro e ceci con verdure",nome_en:"Farro and chickpea soup with vegetables",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla, carota e sedano, unire i ceci lessati e il farro con brodo vegetale. Cuocere per 30 minuti fino a consistenza cremosa. Servire con un filo di olio e rosmarino fresco.",note_en:"Sauté onion, carrot and celery, add the boiled chickpeas and farro with vegetable broth. Cook for 30 minutes until creamy. Serve with a drizzle of oil and fresh rosemary.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Ceci lessati",qt:"300g"},{nome:"Cipolla",qt:"60g"},{nome:"Carote",qt:"80g"},{nome:"Sedano",qt:"60g"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Rosmarino",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Zuppa di farro e ceci con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:1.5,g:12,z:4,ch:62,fi:11,ca:80,fe:3.5,mg:85,k2:550,na:300,zn:2,fo:100,se:8,col:0}},{id:"tpl_1564",nome:"Insalata di farro con feta e verdure",nome_en:"Farro salad with feta and vegetables",categoria:"Piatto unico",porzioni:4,note:"Lessare il farro e raffreddarlo. Condire con pomodorini, cetrioli, olive nere, feta a cubetti, origano e olio extravergine. Mescolare bene e lasciare riposare in frigo prima di servire.",note_en:"Boil the farro and cool it. Dress with cherry tomatoes, cucumbers, black olives, diced feta, oregano and olive oil. Mix well and let rest in the fridge before serving.",ingredienti:[{nome:"Farro",qt:"280g"},{nome:"Feta",qt:"150g"},{nome:"Pomodorini",qt:"200g"},{nome:"Cetrioli",qt:"150g"},{nome:"Olive nere",qt:"60g"},{nome:"Origano",qt:"q.b."},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Insalata di farro con feta e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:16,gs:8,g:22,z:5,ch:52,fi:8,ca:220,fe:2.5,mg:60,k2:450,na:550,zn:1.8,fo:60,se:10,col:35}},{id:"tpl_1565",nome:"Cous cous alle verdure e ceci",nome_en:"Couscous with vegetables and chickpeas",categoria:"Piatto unico",porzioni:4,note:"Cuocere il cous cous secondo i tempi di reidratazione con brodo vegetale caldo. Saltare in padella zucchine, peperoni e carote con i ceci lessati e spezie orientali. Unire le verdure al cous cous e servire tiepido.",note_en:"Rehydrate the couscous with hot vegetable broth per package timing. Sauté zucchini, peppers and carrots with the boiled chickpeas and oriental spices. Combine the vegetables with the couscous and serve warm.",ingredienti:[{nome:"Cous cous",qt:"300g"},{nome:"Ceci lessati",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Cumino",qt:"q.b."},{nome:"Curcuma",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cous cous alle verdure e ceci (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:14,gs:1.5,g:12,z:6,ch:68,fi:9,ca:70,fe:3,mg:70,k2:500,na:250,zn:1.8,fo:90,se:6,col:0}},{id:"tpl_1566",nome:"Polpettone di carne con patate e piselli",nome_en:"Meatloaf with potatoes and peas",categoria:"Piatto unico",porzioni:4,note:"Amalgamare carne macinata, uova, pangrattato e parmigiano, formare un polpettone e rosolarlo in padella. Cuocere in forno con patate a tocchetti e piselli per 40 minuti bagnando con brodo di tanto in tanto. Affettare e servire con il contorno.",note_en:"Mix ground meat, eggs, breadcrumbs and parmesan, shape into a loaf and brown in a pan. Bake with chunked potatoes and peas for 40 minutes, basting occasionally with broth. Slice and serve with the side.",ingredienti:[{nome:"Carne macinata mista",qt:"500g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"60g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Patate",qt:"400g"},{nome:"Piselli",qt:"200g"},{nome:"Brodo di carne",qt:"200ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Polpettone di carne con patate e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:32,gs:9,g:26,z:5,ch:38,fi:5,ca:120,fe:3,mg:50,k2:700,na:400,zn:4,fo:45,se:20,col:150}},{id:"tpl_1567",nome:"Torta salata di verdure prosciutto e formaggio",nome_en:"Savory pie with vegetables, ham and cheese",categoria:"Piatto unico",porzioni:6,note:"Stendere la pasta sfoglia in una teglia e bucherellarla. Riempire con verdure saltate, prosciutto cotto a listarelle e formaggio filante. Cuocere in forno a 200°C per 30 minuti fino a doratura.",note_en:"Roll out the puff pastry in a baking dish and prick it. Fill with sautéed vegetables, strips of cooked ham and melting cheese. Bake at 200°C for 30 minutes until golden.",ingredienti:[{nome:"Pasta sfoglia",qt:"230g"},{nome:"Zucchine",qt:"200g"},{nome:"Prosciutto cotto",qt:"150g"},{nome:"Formaggio filante",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Cipolla",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Torta salata di verdure prosciutto e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:18,gs:12,g:28,z:4,ch:32,fi:2,ca:200,fe:1.5,mg:30,k2:300,na:550,zn:1.5,fo:30,se:12,col:100}},{id:"tpl_1568",nome:"Frittata di patate e cipolle con insalata",nome_en:"Potato and onion frittata with salad",categoria:"Piatto unico",porzioni:4,note:"Rosolare patate a fette sottili e cipolla in olio fino a morbidezza. Versare le uova sbattute con sale e cuocere la frittata da entrambi i lati. Servire con un'insalata mista condita.",note_en:"Brown thinly sliced potatoes and onion in oil until soft. Pour in the beaten eggs with salt and cook the frittata on both sides. Serve with a dressed mixed salad.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Patate",qt:"350g"},{nome:"Cipolla",qt:"100g"},{nome:"Insalata mista",qt:"150g"},{nome:"Pomodorini",qt:"100g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Frittata di patate e cipolle con insalata (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:6,g:24,z:4,ch:30,fi:4,ca:60,fe:2.5,mg:40,k2:600,na:350,zn:1.5,fo:50,se:25,col:380}},{id:"tpl_1569",nome:"Involtini di pollo con verdure e riso",nome_en:"Chicken rolls with vegetables and rice",categoria:"Piatto unico",porzioni:4,note:"Farcire fettine di petto di pollo con carote e zucchine julienne, arrotolare e legare con spago da cucina. Rosolare gli involtini e cuocerli in forno con vino bianco. Servire con riso bianco pilaf come contorno.",note_en:"Fill chicken breast slices with julienned carrots and zucchini, roll and tie with kitchen twine. Brown the rolls and bake with white wine. Serve with white pilaf rice as a side.",ingredienti:[{nome:"Petto di pollo",qt:"500g"},{nome:"Carote",qt:"100g"},{nome:"Zucchine",qt:"100g"},{nome:"Riso",qt:"240g"},{nome:"Vino bianco",qt:"50ml"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Brodo vegetale",qt:"300ml"}],_dbEntry:{n:"Involtini di pollo con verdure e riso (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:36,gs:2,g:10,z:3,ch:55,fi:3,ca:40,fe:1.8,mg:50,k2:500,na:350,zn:1.5,fo:30,se:25,col:90}},{id:"tpl_1570",nome:"Spezzatino di manzo con patate e piselli",nome_en:"Beef stew with potatoes and peas",categoria:"Piatto unico",porzioni:4,note:"Rosolare i cubetti di manzo con cipolla, poi sfumare con vino rosso. Aggiungere pomodoro, brodo, patate e piselli, cuocere a fuoco lento per un'ora e mezza. Servire ben caldo con pane casereccio.",note_en:"Brown the beef cubes with onion, then deglaze with red wine. Add tomato, broth, potatoes and peas, simmer for an hour and a half. Serve hot with rustic bread.",ingredienti:[{nome:"Spezzatino di manzo",qt:"500g"},{nome:"Patate",qt:"300g"},{nome:"Piselli",qt:"200g"},{nome:"Cipolla",qt:"80g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Vino rosso",qt:"100ml"},{nome:"Brodo di carne",qt:"300ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Spezzatino di manzo con patate e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:34,gs:6,g:18,z:5,ch:38,fi:5,ca:60,fe:4,mg:60,k2:800,na:400,zn:5,fo:40,se:25,col:100}},{id:"tpl_1571",nome:"Bollito misto con verdure e salsa verde",nome_en:"Mixed boiled meats with vegetables and green sauce",categoria:"Piatto unico",porzioni:6,note:"Lessare in acqua i tagli di manzo, la gallina e il cotechino con carote, sedano e cipolla per circa tre ore, schiumando di tanto in tanto. Preparare la salsa verde con prezzemolo, capperi, acciughe e olio. Servire il bollito a fette con le verdure di cottura e la salsa.",note_en:"Boil the beef cuts, hen and cotechino in water with carrots, celery and onion for about three hours, skimming occasionally. Prepare the green sauce with parsley, capers, anchovies and oil. Serve the boiled meats sliced with the cooking vegetables and the sauce.",ingredienti:[{nome:"Manzo per bollito",qt:"400g"},{nome:"Gallina",qt:"300g"},{nome:"Cotechino",qt:"200g"},{nome:"Carote",qt:"200g"},{nome:"Sedano",qt:"100g"},{nome:"Cipolla",qt:"100g"},{nome:"Prezzemolo fresco",qt:"40g"},{nome:"Capperi",qt:"20g"},{nome:"Acciughe",qt:"20g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Bollito misto con verdure e salsa verde (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:42,gs:12,g:34,z:3,ch:12,fi:3,ca:60,fe:4,mg:45,k2:650,na:550,zn:5,fo:30,se:20,col:140}},{id:"tpl_1572",nome:"Stufato di cinghiale con polenta",nome_en:"Wild boar stew with polenta",categoria:"Piatto unico",porzioni:4,note:"Marinare il cinghiale nel vino rosso con aromi per una notte. Rosolare la carne e cuocerla lentamente con pomodoro e le verdure per due ore fino a intenerirla. Servire con polenta morbida calda.",note_en:"Marinate the wild boar in red wine with aromatics overnight. Brown the meat and cook it slowly with tomato and vegetables for two hours until tender. Serve with warm soft polenta.",ingredienti:[{nome:"Carne di cinghiale",qt:"500g"},{nome:"Vino rosso",qt:"200ml"},{nome:"Farina di mais",qt:"250g"},{nome:"Carote",qt:"100g"},{nome:"Sedano",qt:"80g"},{nome:"Cipolla",qt:"80g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Alloro",qt:"q.b."}],_dbEntry:{n:"Stufato di cinghiale con polenta (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:34,gs:6,g:18,z:4,ch:48,fi:4,ca:40,fe:4,mg:50,k2:600,na:380,zn:4,fo:25,se:20,col:90}},{id:"tpl_1573",nome:"Trippa alla romana con patate",nome_en:"Roman-style tripe with potatoes",categoria:"Piatto unico",porzioni:4,note:"Lessare la trippa già pulita, poi tagliarla a listarelle. Soffriggere con pomodoro, menta romana e pecorino, cuocere a fuoco lento per un'ora. Servire con patate lesse come contorno.",note_en:"Boil the already-cleaned tripe, then cut into strips. Sauté with tomato, Roman mint and pecorino, simmer for an hour. Serve with boiled potatoes as a side.",ingredienti:[{nome:"Trippa",qt:"600g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Patate",qt:"300g"},{nome:"Cipolla",qt:"60g"},{nome:"Pecorino grattugiato",qt:"40g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Trippa alla romana con patate (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:30,gs:6,g:20,z:5,ch:32,fi:4,ca:150,fe:2,mg:40,k2:550,na:500,zn:2.5,fo:30,se:15,col:130}},{id:"tpl_1574",nome:"Salsiccia e friarielli con purè",nome_en:"Sausage and turnip greens with mashed potatoes",categoria:"Piatto unico",porzioni:4,note:"Ripassare i friarielli in padella con aglio, olio e peperoncino. Rosolare la salsiccia a tocchetti fino a cottura completa. Preparare un purè di patate cremoso con burro e latte, servire tutto insieme.",note_en:"Sauté the turnip greens with garlic, oil and chili. Brown the sausage chunks until fully cooked. Prepare a creamy mashed potato with butter and milk, serve everything together.",ingredienti:[{nome:"Salsiccia",qt:"400g"},{nome:"Friarielli (cime di rapa)",qt:"400g"},{nome:"Patate",qt:"400g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Burro",qt:"40g"},{nome:"Latte",qt:"100ml"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Salsiccia e friarielli con purè (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:24,gs:14,g:38,z:4,ch:30,fi:5,ca:100,fe:2.5,mg:50,k2:700,na:650,zn:3,fo:60,se:15,col:70}},{id:"tpl_1575",nome:"Baccalà alla vicentina con polenta",nome_en:"Vicenza-style salt cod with polenta",categoria:"Piatto unico",porzioni:4,note:"Ammollare il baccalà e cuocerlo lentamente in latte con cipolla, acciughe e parmigiano per circa due ore, mescolando spesso. Servire il baccalà mantecato con polenta morbida calda.",note_en:"Soak the salt cod and cook it slowly in milk with onion, anchovies and parmesan for about two hours, stirring often. Serve the creamed cod with warm soft polenta.",ingredienti:[{nome:"Baccalà ammollato",qt:"600g"},{nome:"Latte",qt:"400ml"},{nome:"Cipolla",qt:"100g"},{nome:"Acciughe",qt:"30g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Farina di mais",qt:"250g"},{nome:"Olio extravergine",qt:"80ml"}],_dbEntry:{n:"Baccalà alla vicentina con polenta (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:32,gs:8,g:28,z:4,ch:42,fi:3,ca:200,fe:2,mg:45,k2:500,na:600,zn:2,fo:25,se:40,col:80}},{id:"tpl_1576",nome:"Seppie con piselli e polenta",nome_en:"Cuttlefish with peas and polenta",categoria:"Piatto unico",porzioni:4,note:"Rosolare le seppie tagliate ad anelli con cipolla e prezzemolo, sfumare con vino bianco. Aggiungere i piselli e il pomodoro, cuocere fino a intenerire le seppie. Servire con polenta morbida.",note_en:"Brown the cuttlefish rings with onion and parsley, deglaze with white wine. Add peas and tomato, cook until the cuttlefish is tender. Serve with soft polenta.",ingredienti:[{nome:"Seppie",qt:"500g"},{nome:"Piselli",qt:"250g"},{nome:"Cipolla",qt:"60g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Vino bianco",qt:"60ml"},{nome:"Farina di mais",qt:"250g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Seppie con piselli e polenta (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:26,gs:2,g:12,z:5,ch:58,fi:5,ca:60,fe:2.5,mg:55,k2:550,na:400,zn:1.8,fo:60,se:35,col:200}},{id:"tpl_1577",nome:"Pesce spada alla ghiotta con contorno",nome_en:'Swordfish "alla ghiotta" with side',categoria:"Piatto unico",porzioni:4,note:"Rosolare il pesce spada a tranci con olive, capperi e pomodorini. Aggiungere un trito di sedano, carote e cipolla e cuocere per 15 minuti. Servire con un contorno di patate al forno.",note_en:"Brown the swordfish steaks with olives, capers and cherry tomatoes. Add chopped celery, carrots and onion and cook for 15 minutes. Serve with a side of baked potatoes.",ingredienti:[{nome:"Pesce spada",qt:"500g"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive verdi",qt:"60g"},{nome:"Capperi",qt:"20g"},{nome:"Sedano",qt:"60g"},{nome:"Carote",qt:"60g"},{nome:"Cipolla",qt:"60g"},{nome:"Patate",qt:"300g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pesce spada alla ghiotta con contorno (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:34,gs:3,g:16,z:5,ch:35,fi:4,ca:50,fe:2,mg:60,k2:700,na:450,zn:1.5,fo:40,se:45,col:70}},{id:"tpl_1578",nome:"Involtini di pesce spada con couscous",nome_en:"Swordfish rolls with couscous",categoria:"Piatto unico",porzioni:4,note:"Farcire fette sottili di pesce spada con pangrattato, prezzemolo, pinoli e uvetta, arrotolare a involtino. Cuocere in padella con olio e limone. Servire su un letto di cous cous condito con verdure.",note_en:"Fill thin swordfish slices with breadcrumbs, parsley, pine nuts and raisins, roll into bundles. Cook in a pan with oil and lemon. Serve over a bed of couscous dressed with vegetables.",ingredienti:[{nome:"Pesce spada",qt:"500g"},{nome:"Pangrattato",qt:"60g"},{nome:"Pinoli",qt:"30g"},{nome:"Uvetta",qt:"20g"},{nome:"Cous cous",qt:"240g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Involtini di pesce spada con couscous (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:32,gs:2,g:16,z:6,ch:55,fi:4,ca:60,fe:2,mg:55,k2:500,na:350,zn:1.5,fo:40,se:45,col:65}},{id:"tpl_1579",nome:"Risotto ai frutti di mare",nome_en:"Seafood risotto",categoria:"Piatto unico",porzioni:4,note:"Tostare il riso e sfumare con vino bianco. Aggiungere gradualmente brodo di pesce, unendo cozze, vongole, gamberi e calamari verso metà cottura. Mantecare con prezzemolo e un filo di olio a crudo.",note_en:"Toast the rice and deglaze with white wine. Gradually add fish broth, incorporating mussels, clams, shrimp and squid halfway through cooking. Finish with parsley and a drizzle of raw oil.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Cozze",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Gamberi",qt:"150g"},{nome:"Calamari",qt:"150g"},{nome:"Brodo di pesce",qt:"700ml"},{nome:"Vino bianco",qt:"80ml"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Risotto ai frutti di mare (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:28,gs:2,g:12,z:3,ch:65,fi:2,ca:80,fe:3,mg:60,k2:450,na:500,zn:2,fo:30,se:45,col:130}},{id:"tpl_1580",nome:"Tiella di riso patate e cozze",nome_en:"Rice, potato and mussel tiella",categoria:"Piatto unico",porzioni:4,note:"Comporre a strati in una teglia patate a fette, riso crudo, cozze sgusciate, pomodorini e cipolla. Bagnare con brodo e un filo di olio, cuocere in forno per 45 minuti finché il riso ha assorbito il liquido.",note_en:"Layer sliced potatoes, raw rice, shelled mussels, cherry tomatoes and onion in a baking dish. Moisten with broth and a drizzle of oil, bake for 45 minutes until the rice has absorbed the liquid.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Patate",qt:"300g"},{nome:"Cozze",qt:"400g"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipolla",qt:"80g"},{nome:"Brodo vegetale",qt:"400ml"},{nome:"Pecorino grattugiato",qt:"30g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Tiella di riso patate e cozze (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:18,gs:2,g:12,z:4,ch:65,fi:4,ca:80,fe:3,mg:55,k2:550,na:450,zn:2,fo:35,se:30,col:40}},{id:"tpl_1581",nome:"Impepata di cozze con crostoni",nome_en:"Peppered mussels with toasted bread",categoria:"Piatto unico",porzioni:4,note:"Aprire le cozze in padella con aglio, olio, prezzemolo e abbondante pepe nero. Tostare fette di pane casereccio e strofinarle con aglio. Servire le cozze nel loro brodo con i crostoni per inzupparlo.",note_en:"Open the mussels in a pan with garlic, oil, parsley and plenty of black pepper. Toast slices of rustic bread and rub with garlic. Serve the mussels in their broth with the toasted bread for dipping.",ingredienti:[{nome:"Cozze",qt:"1kg"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Pepe nero",qt:"q.b."},{nome:"Pane casereccio",qt:"250g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Impepata di cozze con crostoni (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:24,gs:2,g:14,z:3,ch:42,fi:3,ca:100,fe:5,mg:60,k2:400,na:600,zn:2,fo:30,se:40,col:60}},{id:"tpl_1582",nome:"Cacciucco alla livornese (versione 2)",nome_en:"Livorno-style fish stew (version 2)",categoria:"Piatto unico",porzioni:4,note:"Preparare un soffritto di cipolla, aglio e peperoncino, sfumare con vino rosso e aggiungere pomodoro. Cuocere il pesce misto e i crostacei nel sugo per circa 20 minuti. Servire il cacciucco con crostoni di pane agliati.",note_en:"Prepare a base of onion, garlic and chili, deglaze with red wine and add tomato. Cook the mixed fish and shellfish in the sauce for about 20 minutes. Serve the stew with garlic-rubbed toasted bread.",ingredienti:[{nome:"Pesce misto da zuppa",qt:"700g"},{nome:"Calamari",qt:"150g"},{nome:"Gamberi",qt:"150g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Vino rosso",qt:"100ml"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Pane casereccio",qt:"200g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Cacciucco alla livornese (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:38,gs:2,g:16,z:5,ch:30,fi:3,ca:80,fe:3,mg:70,k2:700,na:550,zn:2,fo:40,se:50,col:150}},{id:"tpl_1583",nome:"Zuppa di lenticchie e cotechino",nome_en:"Lentil soup with cotechino",categoria:"Piatto unico",porzioni:4,note:"Lessare le lenticchie con carota, sedano e cipolla. Cuocere il cotechino separatamente per circa un'ora. Affettare il cotechino e servirlo sulla zuppa di lenticchie calda.",note_en:"Boil the lentils with carrot, celery and onion. Separately cook the cotechino for about an hour. Slice the cotechino and serve it over the hot lentil soup.",ingredienti:[{nome:"Lenticchie",qt:"300g"},{nome:"Cotechino",qt:"300g"},{nome:"Carote",qt:"80g"},{nome:"Sedano",qt:"60g"},{nome:"Cipolla",qt:"60g"},{nome:"Concentrato di pomodoro",qt:"20g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Zuppa di lenticchie e cotechino (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:26,gs:12,g:30,z:3,ch:45,fi:10,ca:60,fe:4,mg:70,k2:650,na:700,zn:2.5,fo:100,se:15,col:60}},{id:"tpl_1584",nome:"Fagioli all'uccelletto con salsiccia e pane toscano",nome_en:"Tuscan-style beans with sausage and bread",categoria:"Piatto unico",porzioni:4,note:"Rosolare la salsiccia a tocchetti in olio con aglio e salvia. Aggiungere i fagioli cannellini lessati e pomodoro, cuocere a fuoco lento per 20 minuti. Servire con fette di pane casereccio tostato.",note_en:"Brown the sausage chunks in oil with garlic and sage. Add the boiled cannellini beans and tomato, simmer for 20 minutes. Serve with slices of toasted rustic bread.",ingredienti:[{nome:"Salsiccia",qt:"350g"},{nome:"Fagioli cannellini lessati",qt:"300g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Salvia",qt:"q.b."},{nome:"Pane casereccio",qt:"200g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Fagioli all'uccelletto con salsiccia e pane toscano (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:24,gs:10,g:28,z:3,ch:45,fi:9,ca:80,fe:3,mg:70,k2:600,na:600,zn:2.2,fo:80,se:15,col:55}},{id:"tpl_1585",nome:"Farinata di ceci con verdure e affettati",nome_en:"Chickpea farinata with vegetables and cold cuts",categoria:"Piatto unico",porzioni:4,note:"Mescolare farina di ceci con acqua, olio e sale, lasciar riposare l'impasto per due ore. Versare in una teglia e cuocere in forno molto caldo fino a doratura. Servire la farinata calda con verdure grigliate e affettati misti.",note_en:"Mix chickpea flour with water, oil and salt, let the batter rest for two hours. Pour into a baking pan and bake in a very hot oven until golden. Serve the farinata hot with grilled vegetables and mixed cold cuts.",ingredienti:[{nome:"Farina di ceci",qt:"300g"},{nome:"Acqua",qt:"900ml"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Zucchine grigliate",qt:"150g"},{nome:"Peperoni grigliati",qt:"150g"},{nome:"Affettati misti",qt:"150g"}],_dbEntry:{n:"Farinata di ceci con verdure e affettati (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:16,gs:3,g:20,z:3,ch:45,fi:8,ca:60,fe:3,mg:60,k2:500,na:500,zn:1.5,fo:70,se:8,col:20}},{id:"tpl_1586",nome:"Piadina farcita completa con crudo e verdure",nome_en:"Fully-loaded piadina with cured ham and vegetables",categoria:"Piatto unico",porzioni:4,note:"Preparare l'impasto della piadina con farina, strutto e acqua, stendere e cuocere su una piastra calda. Farcire ogni piadina con prosciutto crudo, squacquerone, rucola e pomodorini.",note_en:"Prepare the piadina dough with flour, lard and water, roll out and cook on a hot griddle. Fill each piadina with prosciutto crudo, squacquerone cheese, arugula and cherry tomatoes.",ingredienti:[{nome:"Farina 00",qt:"400g"},{nome:"Strutto",qt:"60g"},{nome:"Prosciutto crudo",qt:"150g"},{nome:"Squacquerone",qt:"200g"},{nome:"Rucola",qt:"60g"},{nome:"Pomodorini",qt:"100g"}],_dbEntry:{n:"Piadina farcita completa con crudo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:22,gs:12,g:26,z:3,ch:58,fi:3,ca:150,fe:2,mg:30,k2:300,na:700,zn:1.5,fo:30,se:15,col:60}},{id:"tpl_1587",nome:"Insalata di farro e gamberi",nome_en:"Farro and shrimp salad",categoria:"Piatto unico",porzioni:4,note:"Lessare il farro e raffreddarlo. Scottare i gamberi in padella con aglio e olio. Unire farro, gamberi, pomodorini e rucola, condire con olio e limone.",note_en:"Boil the farro and cool it. Sear the shrimp in a pan with garlic and oil. Combine farro, shrimp, cherry tomatoes and arugula, dress with oil and lemon.",ingredienti:[{nome:"Farro",qt:"280g"},{nome:"Gamberi",qt:"300g"},{nome:"Pomodorini",qt:"200g"},{nome:"Rucola",qt:"60g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata di farro e gamberi (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:26,gs:1,g:12,z:4,ch:55,fi:7,ca:60,fe:2.5,mg:60,k2:500,na:350,zn:1.5,fo:60,se:35,col:130}},{id:"tpl_1588",nome:"Insalata di orzo con verdure estive",nome_en:"Barley salad with summer vegetables",categoria:"Piatto unico",porzioni:4,note:"Lessare l'orzo perlato e raffreddarlo sotto acqua corrente. Tagliare a cubetti zucchine, peperoni e pomodori, unire feta sbriciolata. Condire con olio, limone e origano, mescolare bene.",note_en:"Boil the pearl barley and cool it under running water. Dice zucchini, peppers and tomatoes, add crumbled feta. Dress with oil, lemon and oregano, mix well.",ingredienti:[{nome:"Orzo perlato",qt:"280g"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Pomodori",qt:"150g"},{nome:"Feta",qt:"120g"},{nome:"Origano",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Insalata di orzo con verdure estive (ricetta)",c:"Ricette",src:"RICETTE",k:430,p:14,gs:6,g:16,z:5,ch:58,fi:8,ca:180,fe:2,mg:55,k2:450,na:450,zn:1.5,fo:60,se:8,col:30}},{id:"tpl_1589",nome:"Torta rustica di verdure e ricotta",nome_en:"Rustic vegetable and ricotta pie",categoria:"Piatto unico",porzioni:6,note:"Foderare una teglia con pasta brisée. Saltare spinaci e ricotta con uova e parmigiano, versare il ripieno nella teglia. Cuocere in forno a 190°C per 35 minuti fino a doratura.",note_en:"Line a baking dish with shortcrust pastry. Sauté spinach and mix with ricotta, eggs and parmesan, pour the filling into the dish. Bake at 190°C for 35 minutes until golden.",ingredienti:[{nome:"Pasta brisée",qt:"230g"},{nome:"Spinaci",qt:"400g"},{nome:"Ricotta",qt:"250g"},{nome:"Uova",qt:"3"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Torta rustica di verdure e ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:18,gs:10,g:26,z:3,ch:32,fi:4,ca:250,fe:2.5,mg:45,k2:450,na:400,zn:1.8,fo:100,se:15,col:160}},{id:"tpl_1590",nome:"Sformato di patate broccoli e salsiccia",nome_en:"Potato, broccoli and sausage bake",categoria:"Piatto unico",porzioni:4,note:"Lessare patate e broccoli, schiacciare le patate a purè. Rosolare la salsiccia sbriciolata, unire il tutto con uova e parmigiano. Versare in una teglia e cuocere in forno per 30 minuti fino a gratinatura.",note_en:"Boil potatoes and broccoli, mash the potatoes. Brown the crumbled sausage, combine everything with eggs and parmesan. Pour into a baking dish and bake for 30 minutes until gratinated.",ingredienti:[{nome:"Patate",qt:"400g"},{nome:"Broccoli",qt:"300g"},{nome:"Salsiccia",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano grattugiato",qt:"50g"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Sformato di patate broccoli e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:22,gs:12,g:28,z:4,ch:38,fi:6,ca:150,fe:2.5,mg:55,k2:750,na:450,zn:2.5,fo:70,se:15,col:130}},{id:"tpl_1591",nome:"Melanzane ripiene di riso e carne",nome_en:"Eggplants stuffed with rice and meat",categoria:"Piatto unico",porzioni:4,note:"Svuotare le melanzane tagliate a metà e cuocere la polpa con carne macinata, riso parzialmente cotto, pomodoro e parmigiano. Riempire le melanzane con il composto e cuocere in forno per 35 minuti.",note_en:"Hollow out the halved eggplants and cook the pulp with ground meat, partially cooked rice, tomato and parmesan. Fill the eggplants with the mixture and bake for 35 minutes.",ingredienti:[{nome:"Melanzane",qt:"4"},{nome:"Riso",qt:"150g"},{nome:"Carne macinata",qt:"250g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Cipolla",qt:"60g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Melanzane ripiene di riso e carne (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:22,gs:6,g:20,z:6,ch:45,fi:6,ca:100,fe:2.5,mg:50,k2:600,na:350,zn:2.5,fo:40,se:15,col:60}},{id:"tpl_1592",nome:"Peperoni ripieni di riso e carne",nome_en:"Peppers stuffed with rice and meat",categoria:"Piatto unico",porzioni:4,note:"Tagliare i peperoni a metà e svuotarli dai semi. Riempirli con un composto di riso, carne macinata, pomodoro e parmigiano. Cuocere in forno a 190°C per 40 minuti fino a doratura.",note_en:"Halve the peppers and remove the seeds. Fill them with a mixture of rice, ground meat, tomato and parmesan. Bake at 190°C for 40 minutes until golden.",ingredienti:[{nome:"Peperoni",qt:"4"},{nome:"Riso",qt:"150g"},{nome:"Carne macinata",qt:"250g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Cipolla",qt:"60g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Peperoni ripieni di riso e carne (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:20,gs:6,g:18,z:8,ch:45,fi:5,ca:90,fe:2.2,mg:45,k2:550,na:350,zn:2.2,fo:45,se:12,col:55}},{id:"tpl_1593",nome:"Pomodori ripieni di riso",nome_en:"Rice-stuffed tomatoes",categoria:"Piatto unico",porzioni:4,note:"Svuotare i pomodori conservando la polpa, mescolarla con riso crudo, basilico, aglio e olio. Riempire i pomodori e cuocerli in forno con patate a spicchi intorno per 50 minuti.",note_en:"Hollow out the tomatoes keeping the pulp, mix it with raw rice, basil, garlic and oil. Fill the tomatoes and bake with potato wedges around them for 50 minutes.",ingredienti:[{nome:"Pomodori grandi",qt:"8"},{nome:"Riso",qt:"200g"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Aglio",qt:"2 spicchi"},{nome:"Patate",qt:"300g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Pomodori ripieni di riso (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:8,gs:1.5,g:14,z:8,ch:65,fi:5,ca:40,fe:2,mg:40,k2:700,na:250,zn:1.2,fo:40,se:5,col:0}},{id:"tpl_1594",nome:"Polpette al sugo con purè di patate",nome_en:"Meatballs in tomato sauce with mashed potatoes",categoria:"Piatto unico",porzioni:4,note:"Preparare le polpette con carne macinata, pane ammollato, uova e parmigiano. Cuocerle nel sugo di pomodoro per 20 minuti. Servire con un purè di patate cremoso al burro.",note_en:"Prepare the meatballs with ground meat, soaked bread, eggs and parmesan. Cook them in tomato sauce for 20 minutes. Serve with creamy buttered mashed potatoes.",ingredienti:[{nome:"Carne macinata",qt:"400g"},{nome:"Pane raffermo",qt:"60g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Patate",qt:"400g"},{nome:"Burro",qt:"30g"},{nome:"Latte",qt:"100ml"}],_dbEntry:{n:"Polpette al sugo con purè di patate (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:28,gs:12,g:28,z:6,ch:40,fi:4,ca:150,fe:3,mg:50,k2:700,na:400,zn:3,fo:40,se:18,col:130}},{id:"tpl_1595",nome:"Cotoletta alla milanese con patate e spinaci",nome_en:"Milanese cutlet with potatoes and spinach",categoria:"Piatto unico",porzioni:4,note:"Impanare le fettine di vitello passandole in uovo e pangrattato, friggerle in burro chiarificato fino a doratura. Saltare gli spinaci in padella con aglio e olio. Servire la cotoletta con spinaci e patate al forno.",note_en:"Bread the veal slices by passing them in egg and breadcrumbs, fry in clarified butter until golden. Sauté the spinach in a pan with garlic and oil. Serve the cutlet with spinach and baked potatoes.",ingredienti:[{nome:"Vitello a fette",qt:"500g"},{nome:"Uova",qt:"2"},{nome:"Pangrattato",qt:"100g"},{nome:"Burro chiarificato",qt:"80g"},{nome:"Spinaci",qt:"300g"},{nome:"Patate",qt:"400g"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Cotoletta alla milanese con patate e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:580,p:36,gs:14,g:32,z:2,ch:38,fi:4,ca:100,fe:3,mg:50,k2:700,na:400,zn:4,fo:60,se:25,col:160}},{id:"tpl_1596",nome:"Saltimbocca alla romana con contorno di verdure",nome_en:"Roman saltimbocca with vegetable side",categoria:"Piatto unico",porzioni:4,note:"Appoggiare una fetta di prosciutto crudo e una foglia di salvia su ogni fettina di vitello, fermare con uno stecchino. Cuocere in padella con burro e sfumare con vino bianco. Servire con verdure saltate in padella.",note_en:"Place a slice of prosciutto crudo and a sage leaf on each veal slice, secure with a toothpick. Cook in a pan with butter and deglaze with white wine. Serve with pan-sautéed vegetables.",ingredienti:[{nome:"Vitello a fette",qt:"500g"},{nome:"Prosciutto crudo",qt:"120g"},{nome:"Salvia fresca",qt:"q.b."},{nome:"Vino bianco",qt:"60ml"},{nome:"Burro",qt:"30g"},{nome:"Zucchine",qt:"200g"},{nome:"Carote",qt:"150g"}],_dbEntry:{n:"Saltimbocca alla romana con contorno di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:38,gs:8,g:24,z:4,ch:15,fi:4,ca:60,fe:2.5,mg:45,k2:650,na:550,zn:4,fo:30,se:25,col:140}},{id:"tpl_1597",nome:"Pollo alla cacciatora con polenta",nome_en:"Chicken cacciatore with polenta",categoria:"Piatto unico",porzioni:4,note:"Rosolare i pezzi di pollo con cipolla, poi sfumare con vino bianco. Aggiungere pomodoro, olive e rosmarino, cuocere a fuoco lento per 40 minuti. Servire con polenta morbida calda.",note_en:"Brown the chicken pieces with onion, then deglaze with white wine. Add tomato, olives and rosemary, simmer for 40 minutes. Serve with warm soft polenta.",ingredienti:[{nome:"Pollo a pezzi",qt:"700g"},{nome:"Pomodori pelati",qt:"250g"},{nome:"Olive nere",qt:"60g"},{nome:"Cipolla",qt:"80g"},{nome:"Vino bianco",qt:"80ml"},{nome:"Farina di mais",qt:"250g"},{nome:"Rosmarino",qt:"q.b."},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Pollo alla cacciatora con polenta (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:36,gs:5,g:18,z:4,ch:48,fi:4,ca:50,fe:2.5,mg:55,k2:650,na:450,zn:2,fo:35,se:25,col:110}},{id:"tpl_1598",nome:"Coniglio alla ligure con patate",nome_en:"Ligurian-style rabbit with potatoes",categoria:"Piatto unico",porzioni:4,note:"Rosolare i pezzi di coniglio con aglio, rosmarino e olive taggiasche, sfumare con vino bianco. Aggiungere le patate a tocchetti e continuare la cottura per 40 minuti. Servire caldo.",note_en:"Brown the rabbit pieces with garlic, rosemary and taggiasca olives, deglaze with white wine. Add the chunked potatoes and continue cooking for 40 minutes. Serve hot.",ingredienti:[{nome:"Coniglio a pezzi",qt:"700g"},{nome:"Patate",qt:"300g"},{nome:"Olive taggiasche",qt:"60g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"q.b."},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Coniglio alla ligure con patate (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:38,gs:5,g:20,z:2,ch:30,fi:3,ca:40,fe:2.5,mg:50,k2:700,na:400,zn:2.5,fo:30,se:25,col:100}},{id:"tpl_1599",nome:"Agnello al forno con patate e carciofi",nome_en:"Roast lamb with potatoes and artichokes",categoria:"Piatto unico",porzioni:4,note:"Marinare l'agnello con aglio, rosmarino e olio. Disporlo in teglia con patate e carciofi a spicchi, cuocere in forno a 200°C per un'ora bagnando con vino bianco. Servire ben caldo.",note_en:"Marinate the lamb with garlic, rosemary and oil. Place it in a baking dish with potato and artichoke wedges, roast at 200°C for an hour, basting with white wine. Serve hot.",ingredienti:[{nome:"Agnello a pezzi",qt:"600g"},{nome:"Patate",qt:"300g"},{nome:"Carciofi",qt:"4"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"q.b."},{nome:"Vino bianco",qt:"100ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Agnello al forno con patate e carciofi (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:34,gs:12,g:32,z:3,ch:30,fi:5,ca:60,fe:3,mg:45,k2:700,na:380,zn:4,fo:40,se:20,col:110}},{id:"tpl_1600",nome:"Maialino al forno con verdure",nome_en:"Roast suckling pig with vegetables",categoria:"Piatto unico",porzioni:4,note:"Marinare il maialino con aglio, rosmarino e finocchietto selvatico. Cuocere in forno a bassa temperatura per due ore con patate e cipolle intorno. Alzare la temperatura finale per rendere la cotenna croccante.",note_en:"Marinate the piglet with garlic, rosemary and wild fennel. Roast at low temperature for two hours with potatoes and onions around it. Raise the temperature at the end to crisp the skin.",ingredienti:[{nome:"Maialino",qt:"700g"},{nome:"Patate",qt:"300g"},{nome:"Cipolle",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"q.b."},{nome:"Finocchietto selvatico",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Maialino al forno con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:600,p:34,gs:16,g:38,z:3,ch:28,fi:4,ca:40,fe:2,mg:40,k2:650,na:400,zn:3,fo:30,se:20,col:120}},{id:"tpl_1601",nome:"Lasagna al forno completa con verdure",nome_en:"Baked lasagna with vegetables",categoria:"Piatto unico",porzioni:6,note:"Preparare un ragù di carne e verdure, unire besciamella e sfoglie di pasta fresca a strati in una teglia. Spolverare con parmigiano e cuocere in forno a 190°C per 40 minuti fino a gratinatura.",note_en:"Prepare a meat and vegetable ragù, layer with béchamel and fresh pasta sheets in a baking dish. Sprinkle with parmesan and bake at 190°C for 40 minutes until gratinated.",ingredienti:[{nome:"Sfoglie di pasta fresca",qt:"300g"},{nome:"Carne macinata",qt:"300g"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Besciamella",qt:"400g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Parmigiano grattugiato",qt:"60g"}],_dbEntry:{n:"Lasagna al forno completa con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:26,gs:12,g:28,z:6,ch:50,fi:3,ca:250,fe:2.5,mg:45,k2:500,na:450,zn:2.5,fo:35,se:18,col:90}},{id:"tpl_1602",nome:"Cannelloni ripieni con insalata",nome_en:"Stuffed cannelloni with salad",categoria:"Piatto unico",porzioni:4,note:"Farcire i cannelloni con ricotta, spinaci e un po' di carne macinata rosolata. Disporli in teglia con besciamella e pomodoro, cuocere in forno per 30 minuti. Servire con un'insalata verde fresca.",note_en:"Fill the cannelloni with ricotta, spinach and a bit of browned ground meat. Arrange in a baking dish with béchamel and tomato, bake for 30 minutes. Serve with a fresh green salad.",ingredienti:[{nome:"Cannelloni",qt:"16"},{nome:"Ricotta",qt:"250g"},{nome:"Spinaci",qt:"200g"},{nome:"Carne macinata",qt:"150g"},{nome:"Besciamella",qt:"300g"},{nome:"Pomodori pelati",qt:"150g"},{nome:"Insalata verde",qt:"100g"},{nome:"Parmigiano grattugiato",qt:"40g"}],_dbEntry:{n:"Cannelloni ripieni con insalata (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:24,gs:11,g:24,z:5,ch:52,fi:4,ca:220,fe:2.5,mg:45,k2:450,na:450,zn:2,fo:60,se:15,col:90}},{id:"tpl_1603",nome:"Vincisgrassi marchigiani (versione 2)",nome_en:"Marche-style vincisgrassi (version 2)",categoria:"Piatto unico",porzioni:6,note:"Preparare un ragù ricco con rigaglie di pollo, salsiccia e carne di maiale. Alternare sfoglie di pasta all'uovo con il ragù e besciamella in una teglia. Cuocere in forno a 190°C per 35 minuti.",note_en:"Prepare a rich ragù with chicken giblets, sausage and pork. Layer egg pasta sheets with the ragù and béchamel in a baking dish. Bake at 190°C for 35 minutes.",ingredienti:[{nome:"Sfoglie di pasta all'uovo",qt:"300g"},{nome:"Rigaglie di pollo",qt:"150g"},{nome:"Salsiccia",qt:"200g"},{nome:"Carne di maiale macinata",qt:"150g"},{nome:"Besciamella",qt:"350g"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Vino bianco",qt:"50ml"}],_dbEntry:{n:"Vincisgrassi marchigiani (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:600,p:28,gs:14,g:32,z:4,ch:48,fi:2,ca:220,fe:3,mg:40,k2:450,na:500,zn:3,fo:30,se:20,col:140}},{id:"tpl_1604",nome:"Timballo di maccheroni alla siciliana",nome_en:"Sicilian macaroni timbale",categoria:"Piatto unico",porzioni:6,note:"Cuocere i maccheroni al dente e condirli con ragù di carne, piselli, uova sode a pezzi e caciocavallo. Foderare una teglia con pasta frolla salata, riempirla con i maccheroni conditi e cuocere in forno per 45 minuti.",note_en:"Cook the macaroni al dente and dress with meat ragù, peas, chopped hard-boiled eggs and caciocavallo. Line a baking dish with savory shortcrust pastry, fill with the dressed macaroni and bake for 45 minutes.",ingredienti:[{nome:"Maccheroni",qt:"400g"},{nome:"Carne macinata",qt:"250g"},{nome:"Piselli",qt:"100g"},{nome:"Uova sode",qt:"3"},{nome:"Caciocavallo",qt:"150g"},{nome:"Pasta frolla salata",qt:"250g"},{nome:"Pomodoro passata",qt:"250g"}],_dbEntry:{n:"Timballo di maccheroni alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:620,p:26,gs:14,g:30,z:5,ch:62,fi:3,ca:180,fe:2.8,mg:45,k2:400,na:500,zn:2.5,fo:35,se:18,col:150}},{id:"tpl_1605",nome:"Zuppa di farro e funghi porcini",nome_en:"Farro and porcini mushroom soup",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla e aglio, aggiungere i funghi porcini a fette e cuocerli finché rilasciano l'acqua. Unire il farro e il brodo vegetale, cuocere per 30 minuti. Servire con prezzemolo fresco e un filo d'olio.",note_en:"Sauté onion and garlic, add sliced porcini mushrooms and cook until they release their water. Add farro and vegetable broth, cook for 30 minutes. Serve with fresh parsley and a drizzle of oil.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Funghi porcini",qt:"300g"},{nome:"Cipolla",qt:"60g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Brodo vegetale",qt:"600ml"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Zuppa di farro e funghi porcini (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:14,gs:1.5,g:12,z:4,ch:60,fi:8,ca:40,fe:2.5,mg:60,k2:550,na:300,zn:1.5,fo:60,se:8,col:0}},{id:"tpl_1606",nome:"Minestrone con orzo e parmigiano (versione 2)",nome_en:"Minestrone with barley and parmesan (version 2)",categoria:"Piatto unico",porzioni:4,note:"Cuocere in brodo vegetale carote, patate, zucchine, fagiolini e piselli. Aggiungere l'orzo perlato e cuocere finché tenero. Servire il minestrone con abbondante parmigiano grattugiato.",note_en:"Cook carrots, potatoes, zucchini, green beans and peas in vegetable broth. Add pearl barley and cook until tender. Serve the minestrone with plenty of grated parmesan.",ingredienti:[{nome:"Orzo perlato",qt:"200g"},{nome:"Carote",qt:"100g"},{nome:"Patate",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Fagiolini",qt:"100g"},{nome:"Piselli",qt:"100g"},{nome:"Brodo vegetale",qt:"800ml"},{nome:"Parmigiano grattugiato",qt:"50g"}],_dbEntry:{n:"Minestrone con orzo e parmigiano (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:14,gs:3,g:10,z:6,ch:60,fi:8,ca:150,fe:2.5,mg:55,k2:600,na:350,zn:1.5,fo:70,se:8,col:15}},{id:"tpl_1607",nome:"Pasta e ceci alla romana",nome_en:"Roman-style pasta and chickpeas",categoria:"Piatto unico",porzioni:4,note:"Soffriggere aglio e rosmarino, aggiungere i ceci lessati e un po' di concentrato di pomodoro con brodo. Cuocere la pasta corta direttamente nel condimento fino a completo assorbimento. Servire con un filo di olio a crudo.",note_en:"Sauté garlic and rosemary, add the boiled chickpeas and a bit of tomato paste with broth. Cook the short pasta directly in the sauce until the liquid is absorbed. Serve with a drizzle of raw oil.",ingredienti:[{nome:"Ceci lessati",qt:"400g"},{nome:"Pasta corta",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Rosmarino",qt:"q.b."},{nome:"Concentrato di pomodoro",qt:"20g"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Pasta e ceci alla romana (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:18,gs:1.5,g:12,z:3,ch:78,fi:10,ca:60,fe:3,mg:70,k2:500,na:300,zn:1.8,fo:90,se:8,col:0}},{id:"tpl_1608",nome:"Pasta e patate con provola",nome_en:"Pasta and potatoes with provola cheese",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla e pancetta, aggiungere le patate a cubetti e cuocere con brodo. Unire la pasta corta e cuocere finché cremosa. Mantecare con provola affumicata a fine cottura.",note_en:"Sauté onion and pancetta, add diced potatoes and cook with broth. Add short pasta and cook until creamy. Finish with smoked provola cheese at the end.",ingredienti:[{nome:"Patate",qt:"400g"},{nome:"Pasta corta",qt:"250g"},{nome:"Pancetta",qt:"100g"},{nome:"Provola affumicata",qt:"120g"},{nome:"Cipolla",qt:"60g"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Pasta e patate con provola (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:20,gs:9,g:22,z:4,ch:68,fi:5,ca:200,fe:2,mg:50,k2:600,na:500,zn:2,fo:40,se:15,col:40}},{id:"tpl_1609",nome:"Zuppa di cavolo nero e fagioli (versione 2)",nome_en:"Black cabbage and bean soup (version 2)",categoria:"Piatto unico",porzioni:4,note:"Soffriggere aglio e peperoncino, aggiungere il cavolo nero tagliato a listarelle e i fagioli cannellini lessati. Cuocere con brodo vegetale per 25 minuti. Servire su fette di pane tostato.",note_en:"Sauté garlic and chili, add the black cabbage cut into strips and the boiled cannellini beans. Cook with vegetable broth for 25 minutes. Serve over slices of toasted bread.",ingredienti:[{nome:"Cavolo nero",qt:"350g"},{nome:"Fagioli cannellini lessati",qt:"300g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Pane casereccio",qt:"200g"},{nome:"Brodo vegetale",qt:"500ml"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Zuppa di cavolo nero e fagioli (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:18,gs:1.5,g:14,z:3,ch:58,fi:12,ca:150,fe:4,mg:80,k2:650,na:400,zn:2,fo:100,se:8,col:0}},{id:"tpl_1610",nome:"Scarola ripiena napoletana",nome_en:"Neapolitan stuffed escarole",categoria:"Piatto unico",porzioni:4,note:"Sbollentare le scarole intere e farcirle con un composto di olive, capperi, pinoli, uvetta e acciughe. Legare le scarole farcite e cuocerle in tegame con olio e un po' d'acqua per 20 minuti. Servire con crostoni di pane casereccio.",note_en:"Blanch the whole escarole heads and fill them with a mixture of olives, capers, pine nuts, raisins and anchovies. Tie the stuffed escarole and cook in a pan with oil and a little water for 20 minutes. Serve with toasted rustic bread.",ingredienti:[{nome:"Scarola",qt:"4 cespi"},{nome:"Olive nere",qt:"60g"},{nome:"Capperi",qt:"30g"},{nome:"Pinoli",qt:"30g"},{nome:"Uvetta",qt:"30g"},{nome:"Acciughe",qt:"20g"},{nome:"Pane casereccio",qt:"150g"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Scarola ripiena napoletana (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:10,gs:2,g:20,z:6,ch:45,fi:7,ca:120,fe:3,mg:45,k2:550,na:550,zn:1.2,fo:90,se:10,col:10}},{id:"tpl_1611",nome:"Gnocchi alla romana con verdure",nome_en:"Roman-style semolina gnocchi with vegetables",categoria:"Piatto unico",porzioni:4,note:"Cuocere il semolino nel latte fino a addensarsi, unire tuorli e parmigiano. Stendere il composto, ricavare dischi e disporli a scaglie in una teglia con burro e parmigiano. Gratinare in forno e servire con verdure saltate.",note_en:"Cook the semolina in milk until thick, add egg yolks and parmesan. Spread the mixture, cut into disks and layer them in a baking dish with butter and parmesan. Gratin in the oven and serve with sautéed vegetables.",ingredienti:[{nome:"Semolino",qt:"250g"},{nome:"Latte",qt:"800ml"},{nome:"Tuorli",qt:"2"},{nome:"Parmigiano grattugiato",qt:"80g"},{nome:"Burro",qt:"60g"},{nome:"Zucchine",qt:"200g"},{nome:"Carote",qt:"150g"}],_dbEntry:{n:"Gnocchi alla romana con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:18,gs:14,g:26,z:6,ch:55,fi:3,ca:300,fe:1.5,mg:40,k2:450,na:350,zn:1.8,fo:25,se:12,col:130}},{id:"tpl_1612",nome:"Gnudi di ricotta e spinaci con contorno",nome_en:"Ricotta and spinach gnudi with side",categoria:"Piatto unico",porzioni:4,note:"Amalgamare ricotta, spinaci lessati e strizzati, uova e parmigiano, formare delle palline e passarle nella farina. Lessarli in acqua salata finché vengono a galla. Servire con burro fuso e salvia, accompagnati da pomodorini saltati.",note_en:"Mix ricotta, boiled and squeezed spinach, eggs and parmesan, shape into balls and dust with flour. Boil in salted water until they float. Serve with melted butter and sage, accompanied by sautéed cherry tomatoes.",ingredienti:[{nome:"Ricotta",qt:"400g"},{nome:"Spinaci",qt:"300g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Farina 00",qt:"80g"},{nome:"Burro",qt:"40g"},{nome:"Salvia",qt:"q.b."},{nome:"Pomodorini",qt:"150g"}],_dbEntry:{n:"Gnudi di ricotta e spinaci con contorno (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:22,gs:12,g:26,z:4,ch:32,fi:4,ca:300,fe:2.5,mg:45,k2:500,na:350,zn:2,fo:90,se:15,col:170}},{id:"tpl_1613",nome:"Farrotto con funghi e salsiccia (versione 2)",nome_en:'Farro "farrotto" with mushrooms and sausage (version 2)',categoria:"Piatto unico",porzioni:4,note:"Tostare il farro perlato, sfumare con vino bianco e cuocerlo aggiungendo brodo poco alla volta come un risotto. Rosolare separatamente funghi e salsiccia, unirli a metà cottura. Mantecare con parmigiano a fine cottura.",note_en:"Toast the pearled farro, deglaze with white wine and cook adding broth a little at a time like a risotto. Separately brown mushrooms and sausage, add them halfway through cooking. Finish with parmesan.",ingredienti:[{nome:"Farro perlato",qt:"300g"},{nome:"Funghi champignon",qt:"250g"},{nome:"Salsiccia",qt:"200g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Vino bianco",qt:"60ml"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Farrotto con funghi e salsiccia (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:22,gs:9,g:24,z:3,ch:58,fi:6,ca:100,fe:2.5,mg:60,k2:500,na:450,zn:2,fo:40,se:15,col:45}},{id:"tpl_1614",nome:"Orzotto alla trentina con speck",nome_en:'Trentino-style barley "orzotto" with speck',categoria:"Piatto unico",porzioni:4,note:"Tostare l'orzo perlato con cipolla e speck a dadini, sfumare con vino bianco. Aggiungere brodo poco a poco cuocendo come un risotto per circa 30 minuti. Mantecare con burro e parmigiano.",note_en:"Toast the pearl barley with onion and diced speck, deglaze with white wine. Add broth gradually, cooking like a risotto for about 30 minutes. Finish with butter and parmesan.",ingredienti:[{nome:"Orzo perlato",qt:"300g"},{nome:"Speck",qt:"150g"},{nome:"Cipolla",qt:"60g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Vino bianco",qt:"60ml"},{nome:"Burro",qt:"30g"},{nome:"Parmigiano grattugiato",qt:"40g"}],_dbEntry:{n:"Orzotto alla trentina con speck (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:20,gs:8,g:20,z:3,ch:65,fi:6,ca:120,fe:2.5,mg:55,k2:450,na:550,zn:2,fo:40,se:15,col:40}},{id:"tpl_1615",nome:"Risotto alla zucca con salsiccia",nome_en:"Pumpkin risotto with sausage",categoria:"Piatto unico",porzioni:4,note:"Rosolare la salsiccia sbriciolata e tenerla da parte. Tostare il riso, sfumare con vino bianco e cuocere con brodo aggiungendo la zucca a cubetti a metà cottura. Mantecare con la salsiccia, burro e parmigiano.",note_en:"Brown the crumbled sausage and set aside. Toast the rice, deglaze with white wine and cook with broth, adding diced pumpkin halfway through. Finish with the sausage, butter and parmesan.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Zucca",qt:"300g"},{nome:"Salsiccia",qt:"200g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Vino bianco",qt:"60ml"},{nome:"Burro",qt:"30g"},{nome:"Parmigiano grattugiato",qt:"40g"}],_dbEntry:{n:"Risotto alla zucca con salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:20,gs:10,g:22,z:6,ch:68,fi:4,ca:100,fe:2,mg:45,k2:500,na:500,zn:2,fo:35,se:12,col:45}},{id:"tpl_1616",nome:"Risotto al radicchio taleggio e noci",nome_en:"Radicchio risotto with taleggio and walnuts",categoria:"Piatto unico",porzioni:4,note:"Rosolare il radicchio tagliato a listarelle con cipolla. Tostare il riso, sfumare con vino rosso e cuocere con brodo, unendo il radicchio a metà cottura. Mantecare con taleggio a cubetti e noci tritate.",note_en:"Sauté the radicchio cut into strips with onion. Toast the rice, deglaze with red wine and cook with broth, adding the radicchio halfway through. Finish with diced taleggio and chopped walnuts.",ingredienti:[{nome:"Riso Carnaroli",qt:"320g"},{nome:"Radicchio",qt:"250g"},{nome:"Taleggio",qt:"150g"},{nome:"Noci",qt:"50g"},{nome:"Brodo vegetale",qt:"700ml"},{nome:"Vino rosso",qt:"60ml"},{nome:"Cipolla",qt:"60g"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Risotto al radicchio taleggio e noci (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:18,gs:10,g:24,z:3,ch:65,fi:3,ca:200,fe:2,mg:50,k2:400,na:400,zn:1.8,fo:30,se:12,col:40}},{id:"tpl_1617",nome:"Cous cous di pesce alla siciliana",nome_en:"Sicilian-style fish couscous",categoria:"Piatto unico",porzioni:4,note:"Preparare un brodo di pesce con pomodoro, cipolla e alloro. Cuocere il cous cous con il brodo di pesce filtrato. Servire il cous cous con i tranci di pesce e le mandorle tostate sopra.",note_en:"Prepare a fish broth with tomato, onion and bay leaf. Cook the couscous with the strained fish broth. Serve the couscous with the fish steaks and toasted almonds on top.",ingredienti:[{nome:"Cous cous",qt:"300g"},{nome:"Pesce misto (gallinella, nasello)",qt:"500g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Cipolla",qt:"60g"},{nome:"Alloro",qt:"q.b."},{nome:"Mandorle",qt:"30g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Cous cous di pesce alla siciliana (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:30,gs:2,g:12,z:4,ch:58,fi:4,ca:60,fe:2.5,mg:55,k2:500,na:350,zn:1.5,fo:35,se:40,col:70}},{id:"tpl_1618",nome:"Insalata di polpo patate e olive",nome_en:"Octopus, potato and olive salad",categoria:"Piatto unico",porzioni:4,note:"Lessare il polpo in abbondante acqua fino a intenerirlo, poi tagliarlo a pezzi. Lessare le patate e tagliarle a cubetti. Unire polpo, patate, olive e prezzemolo, condire con olio, limone e pepe.",note_en:"Boil the octopus in plenty of water until tender, then cut into pieces. Boil the potatoes and dice them. Combine octopus, potatoes, olives and parsley, dress with oil, lemon and pepper.",ingredienti:[{nome:"Polpo",qt:"700g"},{nome:"Patate",qt:"400g"},{nome:"Olive nere",qt:"60g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"60ml"}],_dbEntry:{n:"Insalata di polpo patate e olive (ricetta)",c:"Ricette",src:"RICETTE",k:440,p:32,gs:2,g:18,z:2,ch:32,fi:3,ca:60,fe:3,mg:60,k2:700,na:400,zn:2,fo:40,se:45,col:100}},{id:"tpl_1619",nome:"Insalata di mare con farro",nome_en:"Seafood salad with farro",categoria:"Piatto unico",porzioni:4,note:"Lessare il farro e raffreddarlo. Cuocere a vapore cozze, vongole, calamari e gamberi, sgusciare i molluschi. Unire tutto con il farro, condire con olio, limone e prezzemolo.",note_en:"Boil the farro and cool it. Steam mussels, clams, squid and shrimp, shell the mollusks. Combine everything with the farro, dress with oil, lemon and parsley.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Cozze",qt:"200g"},{nome:"Vongole",qt:"200g"},{nome:"Calamari",qt:"150g"},{nome:"Gamberi",qt:"150g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Insalata di mare con farro (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:28,gs:2,g:14,z:3,ch:50,fi:6,ca:80,fe:3,mg:60,k2:500,na:450,zn:2,fo:40,se:40,col:120}},{id:"tpl_1620",nome:"Poke di salmone mediterraneo",nome_en:"Mediterranean salmon poke",categoria:"Piatto unico",porzioni:2,note:"Cuocere il riso e raffreddarlo. Marinare il salmone a cubetti con olio, limone e erbe aromatiche. Comporre la bowl con riso, salmone, cetrioli, pomodorini, olive e feta.",note_en:"Cook the rice and cool it. Marinate the diced salmon with oil, lemon and herbs. Assemble the bowl with rice, salmon, cucumbers, cherry tomatoes, olives and feta.",ingredienti:[{nome:"Riso",qt:"200g"},{nome:"Salmone fresco",qt:"200g"},{nome:"Cetrioli",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Olive nere",qt:"40g"},{nome:"Feta",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Poke di salmone mediterraneo (ricetta)",c:"Ricette",src:"RICETTE",k:560,p:26,gs:7,g:26,z:4,ch:52,fi:4,ca:150,fe:2,mg:60,k2:600,na:500,zn:1.5,fo:45,se:30,col:45}},{id:"tpl_1621",nome:"Bowl di quinoa con pollo e verdure",nome_en:"Quinoa bowl with chicken and vegetables",categoria:"Piatto unico",porzioni:2,note:"Cuocere la quinoa in acqua salata. Grigliare il petto di pollo a listarelle. Comporre la bowl con quinoa, pollo, avocado, pomodorini e mais, condire con olio e limone.",note_en:"Cook the quinoa in salted water. Grill the chicken breast and slice into strips. Assemble the bowl with quinoa, chicken, avocado, cherry tomatoes and corn, dress with oil and lemon.",ingredienti:[{nome:"Quinoa",qt:"160g"},{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Mais",qt:"80g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Bowl di quinoa con pollo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:36,gs:3,g:18,z:4,ch:48,fi:8,ca:50,fe:2.5,mg:80,k2:700,na:300,zn:2,fo:90,se:20,col:80}},{id:"tpl_1622",nome:"Bowl di farro con tonno e verdure",nome_en:"Farro bowl with tuna and vegetables",categoria:"Piatto unico",porzioni:2,note:"Lessare il farro e raffreddarlo. Unire tonno sgocciolato, pomodorini, mais, olive e cetrioli. Condire con olio extravergine e origano, mescolare bene.",note_en:"Boil the farro and cool it. Add drained tuna, cherry tomatoes, corn, olives and cucumbers. Dress with olive oil and oregano, mix well.",ingredienti:[{nome:"Farro",qt:"200g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Pomodorini",qt:"100g"},{nome:"Mais",qt:"80g"},{nome:"Olive nere",qt:"40g"},{nome:"Cetrioli",qt:"100g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Bowl di farro con tonno e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:24,gs:3,g:16,z:5,ch:55,fi:7,ca:50,fe:2.5,mg:60,k2:500,na:450,zn:1.5,fo:60,se:30,col:30}},{id:"tpl_1623",nome:"Involtini di verza ripieni con purè",nome_en:"Stuffed savoy cabbage rolls with mashed potatoes",categoria:"Piatto unico",porzioni:4,note:"Sbollentare le foglie di verza per ammorbidirle. Farcirle con un composto di carne macinata, riso, uova e parmigiano, arrotolarle a involtino. Cuocerle in tegame con pomodoro e brodo per 30 minuti, servire con purè di patate.",note_en:"Blanch the savoy cabbage leaves to soften them. Fill with a mixture of ground meat, rice, eggs and parmesan, roll into bundles. Cook in a pan with tomato and broth for 30 minutes, serve with mashed potatoes.",ingredienti:[{nome:"Verza",qt:"1 (foglie grandi)"},{nome:"Carne macinata",qt:"300g"},{nome:"Riso",qt:"100g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Patate",qt:"400g"},{nome:"Burro",qt:"30g"},{nome:"Latte",qt:"80ml"}],_dbEntry:{n:"Involtini di verza ripieni con purè (ricetta)",c:"Ricette",src:"RICETTE",k:500,p:24,gs:9,g:22,z:6,ch:48,fi:5,ca:130,fe:2.5,mg:50,k2:700,na:400,zn:2.5,fo:45,se:15,col:90}},{id:"tpl_1624",nome:"Torta pasqualina con contorno",nome_en:"Torta pasqualina with side salad",categoria:"Piatto unico",porzioni:6,note:"Stendere sottili sfoglie di pasta matta in una teglia. Riempire con un composto di bietole, ricotta, parmigiano e uova intere che restano semi-sode nella cottura. Cuocere in forno a 190°C per 40 minuti, servire con un'insalata mista.",note_en:"Roll out thin sheets of simple flour-and-water dough in a baking dish. Fill with a mixture of chard, ricotta, parmesan and whole eggs that stay semi-set during baking. Bake at 190°C for 40 minutes, serve with a mixed salad.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Bietole",qt:"400g"},{nome:"Ricotta",qt:"250g"},{nome:"Uova",qt:"6"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Insalata mista",qt:"100g"}],_dbEntry:{n:"Torta pasqualina con contorno (ricetta)",c:"Ricette",src:"RICETTE",k:460,p:20,gs:8,g:24,z:3,ch:40,fi:4,ca:220,fe:3,mg:45,k2:450,na:350,zn:1.8,fo:100,se:20,col:220}},{id:"tpl_1625",nome:"Frittata di asparagi e patate con insalata",nome_en:"Asparagus and potato frittata with salad",categoria:"Piatto unico",porzioni:4,note:"Rosolare gli asparagi a tocchetti e le patate a fette sottili in olio. Versare le uova sbattute con parmigiano e cuocere la frittata da entrambi i lati. Servire con un'insalata verde fresca.",note_en:"Brown chopped asparagus and thinly sliced potatoes in oil. Pour in the beaten eggs with parmesan and cook the frittata on both sides. Serve with a fresh green salad.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Asparagi",qt:"250g"},{nome:"Patate",qt:"250g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Insalata verde",qt:"100g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Frittata di asparagi e patate con insalata (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:20,gs:6,g:22,z:3,ch:28,fi:4,ca:120,fe:2.5,mg:40,k2:600,na:350,zn:1.8,fo:90,se:25,col:380}},{id:"tpl_1626",nome:"Ciambotta calabrese con uova",nome_en:"Calabrian ciambotta with eggs",categoria:"Piatto unico",porzioni:4,note:"Rosolare cipolla, peperoni, melanzane, zucchine e patate a tocchetti in olio con pomodoro. Cuocere a fuoco lento finché le verdure sono morbide. Aprire delle uova direttamente nel sugo di verdure e cuocere finché rapprese.",note_en:"Brown onion, peppers, eggplant, zucchini and potatoes chopped in oil with tomato. Simmer until the vegetables are soft. Crack eggs directly into the vegetable sauce and cook until set.",ingredienti:[{nome:"Peperoni",qt:"200g"},{nome:"Melanzane",qt:"200g"},{nome:"Zucchine",qt:"200g"},{nome:"Patate",qt:"250g"},{nome:"Cipolla",qt:"80g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Uova",qt:"4"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Ciambotta calabrese con uova (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:16,gs:4,g:20,z:8,ch:38,fi:6,ca:80,fe:2.5,mg:50,k2:700,na:350,zn:1.5,fo:60,se:20,col:280}},{id:"tpl_1627",nome:"Acquacotta maremmana con uovo e pane",nome_en:"Maremma-style acquacotta with egg and bread",categoria:"Piatto unico",porzioni:4,note:"Soffriggere cipolla, sedano e pomodoro in olio, aggiungere acqua e portare a bollore. Disporre fette di pane raffermo nei piatti e versare sopra la zuppa bollente. Completare con un uovo in camicia per porzione e pecorino grattugiato.",note_en:"Sauté onion, celery and tomato in oil, add water and bring to a boil. Place slices of stale bread in the bowls and pour the boiling soup over them. Finish with a poached egg per serving and grated pecorino.",ingredienti:[{nome:"Cipolla",qt:"150g"},{nome:"Sedano",qt:"80g"},{nome:"Pomodori pelati",qt:"200g"},{nome:"Pane raffermo",qt:"250g"},{nome:"Uova",qt:"4"},{nome:"Pecorino grattugiato",qt:"40g"},{nome:"Olio extravergine",qt:"50ml"}],_dbEntry:{n:"Acquacotta maremmana con uovo e pane (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:18,gs:5,g:18,z:5,ch:42,fi:4,ca:120,fe:2.5,mg:35,k2:400,na:450,zn:1.5,fo:50,se:20,col:250}},{id:"tpl_1628",nome:"Riso al salto con verdure e formaggio",nome_en:"Pan-fried rice cake with vegetables and cheese",categoria:"Piatto unico",porzioni:4,note:"Utilizzare riso già cotto avanzato mescolato con parmigiano. Formare delle frittelle di riso e rosolarle in padella con burro finché croccanti fuori e filanti dentro con la mozzarella. Servire con verdure saltate come contorno.",note_en:"Use leftover cooked rice mixed with parmesan. Shape into rice cakes and brown in a pan with butter until crispy outside and stringy inside with mozzarella. Serve with sautéed vegetables as a side.",ingredienti:[{nome:"Riso avanzato",qt:"400g"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Mozzarella",qt:"150g"},{nome:"Burro",qt:"40g"},{nome:"Zucchine",qt:"200g"},{nome:"Carote",qt:"100g"}],_dbEntry:{n:"Riso al salto con verdure e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:520,p:20,gs:12,g:26,z:4,ch:55,fi:3,ca:280,fe:1.5,mg:35,k2:350,na:450,zn:1.8,fo:25,se:12,col:60}},{id:"tpl_1629",nome:"Farro alla contadina con salsiccia e funghi",nome_en:"Farmhouse-style farro with sausage and mushrooms",categoria:"Piatto unico",porzioni:4,note:"Lessare il farro in acqua salata. Rosolare la salsiccia a tocchetti con funghi e aglio in olio extravergine. Unire il farro al condimento, mantecare con un filo d'olio e prezzemolo fresco.",note_en:"Boil the farro in salted water. Brown the sausage chunks with mushrooms and garlic in olive oil. Combine the farro with the dressing, finish with a drizzle of oil and fresh parsley.",ingredienti:[{nome:"Farro",qt:"280g"},{nome:"Salsiccia",qt:"250g"},{nome:"Funghi champignon",qt:"250g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Farro alla contadina con salsiccia e funghi (ricetta)",c:"Ricette",src:"RICETTE",k:540,p:22,gs:9,g:26,z:3,ch:55,fi:7,ca:60,fe:2.5,mg:60,k2:550,na:500,zn:2.2,fo:60,se:15,col:45}},{id:"tpl_1630",nome:"Insalata di cous cous con pollo e verdure",nome_en:"Couscous salad with chicken and vegetables",categoria:"Piatto unico",porzioni:4,note:"Cuocere il cous cous con brodo vegetale caldo e sgranarlo con una forchetta. Grigliare il petto di pollo e tagliarlo a listarelle. Unire cous cous, pollo, zucchine grigliate, pomodorini e menta, condire con olio e limone.",note_en:"Cook the couscous with hot vegetable broth and fluff with a fork. Grill the chicken breast and cut into strips. Combine couscous, chicken, grilled zucchini, cherry tomatoes and mint, dress with oil and lemon.",ingredienti:[{nome:"Cous cous",qt:"300g"},{nome:"Petto di pollo",qt:"300g"},{nome:"Zucchine",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Insalata di cous cous con pollo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:480,p:32,gs:2,g:14,z:4,ch:55,fi:4,ca:40,fe:2,mg:55,k2:550,na:300,zn:1.5,fo:40,se:20,col:80}},{id:"tpl_1631",nome:"Yogurt greco con miele e noci (versione 2)",nome_en:"Greek yogurt with honey and walnuts (version 2)",categoria:"Spuntino",porzioni:1,note:"Versare lo yogurt greco in una ciotola. Aggiungere il miele e mescolare leggermente per creare delle venature dolci. Completare con le noci tritate grossolanamente e una spolverata di cannella.",note_en:"Pour the Greek yogurt into a bowl. Add the honey and mix lightly to create sweet swirls. Top with roughly chopped walnuts and a dusting of cinnamon.",ingredienti:[{nome:"Yogurt greco magro",qt:"150g"},{nome:"Miele",qt:"15g"},{nome:"Noci sgusciate",qt:"15g"},{nome:"Cannella in polvere",qt:"q.b."}],_dbEntry:{n:"Yogurt greco con miele e noci (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:14,gs:1.5,g:11,z:16,ch:20,fi:1,ca:180,fe:1,mg:35,k2:250,na:60,zn:1,fo:15,se:5,col:5}},{id:"tpl_1632",nome:"Yogurt con frutti di bosco e granola",nome_en:"Yogurt with mixed berries and granola",categoria:"Spuntino",porzioni:1,note:"Lavare i frutti di bosco e asciugarli delicatamente. Disporre lo yogurt in una coppa e alternare strati con i frutti di bosco e la granola. Servire subito per mantenere la granola croccante.",note_en:"Wash the berries and pat them dry. Layer the yogurt in a bowl alternating with berries and granola. Serve immediately to keep the granola crunchy.",ingredienti:[{nome:"Yogurt bianco intero",qt:"150g"},{nome:"Mirtilli",qt:"40g"},{nome:"Lamponi",qt:"40g"},{nome:"Granola",qt:"25g"}],_dbEntry:{n:"Yogurt con frutti di bosco e granola (ricetta)",c:"Ricette",src:"RICETTE",k:215,p:9,gs:2.5,g:8,z:15,ch:27,fi:3.5,ca:160,fe:1.2,mg:30,k2:230,na:45,zn:1,fo:20,se:4,col:10}},{id:"tpl_1633",nome:"Hummus di ceci con carote",nome_en:"Chickpea hummus with carrot sticks",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con tahina, succo di limone, aglio e olio fino a ottenere una crema liscia. Aggiustare di sale e regolare la consistenza con acqua fredda. Servire con bastoncini di carota cruda.",note_en:"Blend the boiled chickpeas with tahini, lemon juice, garlic and oil until smooth. Season with salt and adjust texture with cold water. Serve with raw carrot sticks.",ingredienti:[{nome:"Ceci lessati",qt:"240g"},{nome:"Tahina",qt:"30g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Carote",qt:"4"}],_dbEntry:{n:"Hummus di ceci con carote (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:7,gs:1.3,g:9,z:5,ch:19,fi:5.5,ca:50,fe:2,mg:35,k2:320,na:190,zn:1.3,fo:60,se:3,col:0}},{id:"tpl_1634",nome:"Hummus di fave con finocchi",nome_en:"Fava bean hummus with fennel",categoria:"Spuntino",porzioni:4,note:"Cuocere le fave sgusciate fino a renderle morbide, quindi frullarle con olio, limone e aglio. Aggiungere un pizzico di menta fresca tritata. Servire con fette sottili di finocchio crudo.",note_en:"Cook the shelled fava beans until soft, then blend with oil, lemon and garlic. Add a pinch of chopped fresh mint. Serve with thin slices of raw fennel.",ingredienti:[{nome:"Fave secche decorticate",qt:"200g"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Menta fresca",qt:"q.b."},{nome:"Finocchi",qt:"2"}],_dbEntry:{n:"Hummus di fave con finocchi (ricetta)",c:"Ricette",src:"RICETTE",k:175,p:9,gs:1,g:7,z:3,ch:20,fi:6,ca:40,fe:2.3,mg:40,k2:400,na:150,zn:1.4,fo:70,se:2,col:0}},{id:"tpl_1635",nome:"Toast integrale con avocado e pomodorini",nome_en:"Whole wheat toast with avocado and cherry tomatoes",categoria:"Spuntino",porzioni:1,note:"Tostare la fetta di pane integrale. Schiacciare la polpa di avocado con succo di limone, sale e pepe e spalmarla sul pane. Completare con pomodorini tagliati a metà e un filo di olio.",note_en:"Toast the slice of whole wheat bread. Mash the avocado flesh with lemon juice, salt and pepper and spread it on the bread. Top with halved cherry tomatoes and a drizzle of oil.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Avocado",qt:"mezzo"},{nome:"Pomodorini",qt:"6"},{nome:"Limone",qt:"q.b."},{nome:"Olio extravergine",qt:"5ml"}],_dbEntry:{n:"Toast integrale con avocado e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:2.5,g:14,z:3,ch:22,fi:6,ca:30,fe:1.5,mg:45,k2:520,na:180,zn:1,fo:65,se:2,col:0}},{id:"tpl_1636",nome:"Toast con ricotta e miele (versione 2)",nome_en:"Toast with ricotta and honey (version 2)",categoria:"Spuntino",porzioni:1,note:"Tostare leggermente il pane. Spalmare la ricotta ben scolata sulla superficie calda. Completare con un filo di miele e una manciata di noci tritate.",note_en:"Lightly toast the bread. Spread the well-drained ricotta over the warm surface. Finish with a drizzle of honey and a handful of chopped walnuts.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Ricotta vaccina",qt:"80g"},{nome:"Miele",qt:"10g"},{nome:"Noci sgusciate",qt:"10g"}],_dbEntry:{n:"Toast con ricotta e miele (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:225,p:10,gs:3.5,g:10,z:11,ch:22,fi:2,ca:150,fe:1,mg:25,k2:150,na:120,zn:.9,fo:15,se:6,col:20}},{id:"tpl_1637",nome:"Polpettine di lenticchie al forno",nome_en:"Baked lentil balls",categoria:"Spuntino",porzioni:4,note:"Cuocere le lenticchie fino a renderle morbide e schiacciarle grossolanamente. Amalgamare con pangrattato, cipolla tritata, uovo e spezie. Formare delle polpettine e cuocerle in forno a 200 gradi finche dorate.",note_en:"Cook the lentils until soft and coarsely mash them. Combine with breadcrumbs, chopped onion, egg and spices. Shape into small balls and bake at 200 degrees until golden.",ingredienti:[{nome:"Lenticchie secche",qt:"150g"},{nome:"Pangrattato",qt:"40g"},{nome:"Cipolla",qt:"mezza"},{nome:"Uovo",qt:"1"},{nome:"Cumino in polvere",qt:"q.b."},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Polpettine di lenticchie al forno (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:10,gs:.9,g:5,z:2,ch:24,fi:5,ca:35,fe:2.6,mg:35,k2:330,na:160,zn:1.4,fo:80,se:5,col:40}},{id:"tpl_1638",nome:"Polpettine di ceci e zucchine",nome_en:"Chickpea and zucchini balls",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con le zucchine grattugiate e strizzate, aggiungendo pangrattato, aglio e prezzemolo. Formare delle piccole polpette e cuocerle in forno fino a doratura. Servire tiepide.",note_en:"Blend the boiled chickpeas with grated and squeezed zucchini, adding breadcrumbs, garlic and parsley. Shape into small patties and bake until golden. Serve warm.",ingredienti:[{nome:"Ceci lessati",qt:"180g"},{nome:"Zucchine",qt:"150g"},{nome:"Pangrattato",qt:"30g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Polpettine di ceci e zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:.6,g:4,z:3,ch:21,fi:4.5,ca:40,fe:1.8,mg:30,k2:300,na:140,zn:1,fo:60,se:2,col:0}},{id:"tpl_1639",nome:"Crackers di segale fatti in casa",nome_en:"Homemade rye crackers",categoria:"Spuntino",porzioni:8,note:"Impastare la farina di segale con acqua, olio e sale fino a ottenere un composto liscio. Stendere sottilmente e tagliare a quadrotti. Cuocere in forno a 180 gradi finche croccanti.",note_en:"Knead the rye flour with water, oil and salt into a smooth dough. Roll out thinly and cut into squares. Bake at 180 degrees until crisp.",ingredienti:[{nome:"Farina di segale",qt:"250g"},{nome:"Acqua",qt:"110ml"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Sale",qt:"q.b."},{nome:"Semi di sesamo",qt:"15g"}],_dbEntry:{n:"Crackers di segale fatti in casa (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:4,gs:.6,g:5,z:.5,ch:23,fi:3,ca:25,fe:1.3,mg:30,k2:120,na:180,zn:.8,fo:15,se:5,col:0}},{id:"tpl_1640",nome:"Crackers ai semi misti",nome_en:"Mixed seed crackers",categoria:"Spuntino",porzioni:8,note:"Mescolare farina integrale con semi di lino, girasole e sesamo, acqua e olio. Stendere l impasto sottile su carta forno e incidere a rombi. Cuocere finche dorati e lasciar raffreddare per la croccantezza.",note_en:"Mix whole wheat flour with flax, sunflower and sesame seeds, water and oil. Roll the dough thin on baking paper and score into diamonds. Bake until golden and let cool for crispness.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Semi di lino",qt:"20g"},{nome:"Semi di girasole",qt:"20g"},{nome:"Semi di sesamo",qt:"15g"},{nome:"Acqua",qt:"100ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Crackers ai semi misti (ricetta)",c:"Ricette",src:"RICETTE",k:165,p:5,gs:.7,g:8,z:.5,ch:18,fi:3.5,ca:40,fe:1.6,mg:45,k2:150,na:150,zn:1,fo:20,se:6,col:0}},{id:"tpl_1641",nome:"Muffin salati con zucchine e feta (versione 2)",nome_en:"Savory muffins with zucchini and feta (version 2)",categoria:"Spuntino",porzioni:12,note:"Mescolare farina, lievito, uova e latte fino a ottenere una pastella liscia. Incorporare le zucchine grattugiate e la feta sbriciolata. Versare negli stampini e cuocere in forno a 180 gradi per 20 minuti.",note_en:"Mix flour, baking powder, eggs and milk into a smooth batter. Fold in grated zucchini and crumbled feta. Pour into muffin cups and bake at 180 degrees for 20 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"150ml"},{nome:"Zucchine",qt:"150g"},{nome:"Feta",qt:"100g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Muffin salati con zucchine e feta (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:2,g:8,z:2,ch:14,fi:1,ca:70,fe:1,mg:15,k2:90,na:200,zn:.6,fo:20,se:6,col:35}},{id:"tpl_1642",nome:"Muffin salati con prosciutto e formaggio",nome_en:"Savory muffins with ham and cheese",categoria:"Spuntino",porzioni:12,note:"Preparare una pastella con farina, uova, latte e olio. Aggiungere il prosciutto cotto a dadini e il formaggio grattugiato. Cuocere in forno a 180 gradi per circa 20 minuti finche dorati.",note_en:"Prepare a batter with flour, eggs, milk and oil. Add diced cooked ham and grated cheese. Bake at 180 degrees for about 20 minutes until golden.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"150ml"},{nome:"Prosciutto cotto",qt:"100g"},{nome:"Formaggio grattugiato",qt:"60g"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Muffin salati con prosciutto e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:7,gs:2.3,g:9,z:1.5,ch:15,fi:.7,ca:80,fe:1,mg:12,k2:80,na:280,zn:.7,fo:15,se:7,col:45}},{id:"tpl_1643",nome:"Frullato proteico alla banana e cacao",nome_en:"Protein smoothie with banana and cocoa",categoria:"Spuntino",porzioni:1,note:"Frullare la banana con il latte, la proteina in polvere e il cacao amaro fino a ottenere una consistenza cremosa. Aggiungere ghiaccio a piacere e servire subito.",note_en:"Blend the banana with milk, protein powder and unsweetened cocoa until creamy. Add ice as desired and serve immediately.",ingredienti:[{nome:"Banana",qt:"1"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Proteine in polvere",qt:"25g"},{nome:"Cacao amaro in polvere",qt:"10g"}],_dbEntry:{n:"Frullato proteico alla banana e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:22,gs:1.5,g:4,z:22,ch:33,fi:3,ca:220,fe:1.5,mg:60,k2:600,na:110,zn:1.2,fo:30,se:5,col:15}},{id:"tpl_1644",nome:"Frullato verde con spinaci e ananas",nome_en:"Green smoothie with spinach and pineapple",categoria:"Spuntino",porzioni:1,note:"Frullare gli spinaci freschi con l ananas a pezzi, il succo di limone e acqua fredda fino a ottenere una bevanda omogenea. Filtrare se si desidera una consistenza piu liscia e servire ghiacciato.",note_en:"Blend the fresh spinach with pineapple chunks, lemon juice and cold water until smooth. Strain if a smoother texture is desired and serve chilled.",ingredienti:[{nome:"Spinaci freschi",qt:"50g"},{nome:"Ananas fresco",qt:"150g"},{nome:"Limone",qt:"mezzo"},{nome:"Acqua",qt:"100ml"}],_dbEntry:{n:"Frullato verde con spinaci e ananas (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2,gs:.1,g:.5,z:18,ch:23,fi:3,ca:60,fe:1.6,mg:35,k2:350,na:20,zn:.5,fo:90,se:1,col:0}},{id:"tpl_1645",nome:"Barrette energetiche ai datteri e noci",nome_en:"Energy bars with dates and walnuts",categoria:"Spuntino",porzioni:8,note:"Frullare i datteri denocciolati con le noci fino a ottenere un composto appiccicoso. Aggiungere i fiocchi di avena e amalgamare bene. Compattare in una teglia e tagliare a barrette dopo un riposo in frigorifero.",note_en:"Blend the pitted dates with walnuts until a sticky mixture forms. Add the oat flakes and mix well. Press into a tray and cut into bars after chilling in the fridge.",ingredienti:[{nome:"Datteri secchi",qt:"200g"},{nome:"Noci sgusciate",qt:"100g"},{nome:"Fiocchi di avena",qt:"80g"},{nome:"Semi di chia",qt:"15g"}],_dbEntry:{n:"Barrette energetiche ai datteri e noci (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:4,gs:1,g:9,z:18,ch:24,fi:3.5,ca:30,fe:1.4,mg:45,k2:280,na:5,zn:.8,fo:10,se:3,col:0}},{id:"tpl_1646",nome:"Barrette ai fiocchi di avena e miele",nome_en:"Oat and honey bars",categoria:"Spuntino",porzioni:8,note:"Scaldare il miele con un poco di burro finche fluido, quindi versarlo sui fiocchi di avena e la frutta secca tritata. Amalgamare bene e pressare in una teglia rivestita. Cuocere in forno a 170 gradi e tagliare a barrette una volta freddo.",note_en:"Warm the honey with a little butter until runny, then pour over the oat flakes and chopped dried fruit. Mix well and press into a lined tray. Bake at 170 degrees and cut into bars once cool.",ingredienti:[{nome:"Fiocchi di avena",qt:"200g"},{nome:"Miele",qt:"80g"},{nome:"Burro",qt:"30g"},{nome:"Uvetta",qt:"40g"},{nome:"Mandorle a lamelle",qt:"30g"}],_dbEntry:{n:"Barrette ai fiocchi di avena e miele (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:4,gs:2,g:7,z:16,ch:30,fi:2.5,ca:25,fe:1.2,mg:35,k2:170,na:15,zn:.7,fo:10,se:4,col:8}},{id:"tpl_1647",nome:"Bruschetta al pomodoro e basilico (versione 2)",nome_en:"Bruschetta with tomato and basil (version 2)",categoria:"Spuntino",porzioni:4,note:"Tagliare i pomodori a cubetti e condirli con olio, sale e basilico spezzettato a mano. Tostare le fette di pane e strofinarle con aglio. Distribuire il composto di pomodoro sul pane caldo.",note_en:"Dice the tomatoes and season with oil, salt and hand-torn basil. Toast the bread slices and rub with garlic. Spoon the tomato mixture over the warm bread.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Bruschetta al pomodoro e basilico (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:4,gs:.7,g:6,z:3,ch:20,fi:2,ca:25,fe:1.3,mg:20,k2:220,na:200,zn:.6,fo:20,se:3,col:0}},{id:"tpl_1648",nome:"Bruschetta con crema di avocado",nome_en:"Bruschetta with avocado cream",categoria:"Spuntino",porzioni:4,note:"Schiacciare la polpa di avocado con succo di lime, sale e peperoncino in polvere. Tostare le fette di pane e spalmarvi la crema. Completare con semi di sesamo tostati.",note_en:"Mash the avocado flesh with lime juice, salt and chili powder. Toast the bread slices and spread with the cream. Finish with toasted sesame seeds.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Avocado",qt:"2"},{nome:"Lime",qt:"1"},{nome:"Peperoncino in polvere",qt:"q.b."},{nome:"Semi di sesamo",qt:"10g"}],_dbEntry:{n:"Bruschetta con crema di avocado (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4,gs:2.5,g:13,z:1.5,ch:20,fi:5,ca:30,fe:1.2,mg:40,k2:450,na:180,zn:.8,fo:60,se:2,col:0}},{id:"tpl_1649",nome:"Chips di zucchine al forno",nome_en:"Oven-baked zucchini chips",categoria:"Spuntino",porzioni:4,note:"Affettare le zucchine sottilmente con una mandolina. Condire con olio, sale e paprika, quindi disporre su una teglia con carta forno. Cuocere a bassa temperatura finche croccanti, girando a meta cottura.",note_en:"Thinly slice the zucchini with a mandoline. Season with oil, salt and paprika, then arrange on a lined baking tray. Bake at low temperature until crisp, flipping halfway through.",ingredienti:[{nome:"Zucchine",qt:"400g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Paprika dolce",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di zucchine al forno (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2,gs:.5,g:5,z:3,ch:6,fi:2,ca:25,fe:.6,mg:20,k2:280,na:150,zn:.4,fo:25,se:1,col:0}},{id:"tpl_1650",nome:"Chips di patate dolci al forno",nome_en:"Oven-baked sweet potato chips",categoria:"Spuntino",porzioni:4,note:"Tagliare le patate dolci a fette sottili e condirle con olio e rosmarino tritato. Disporle in un unico strato su una teglia e cuocere in forno caldo, girandole a meta cottura per una doratura uniforme.",note_en:"Cut the sweet potatoes into thin slices and season with oil and chopped rosemary. Arrange in a single layer on a tray and bake in a hot oven, flipping halfway for even browning.",ingredienti:[{nome:"Patate dolci",qt:"400g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di patate dolci al forno (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:2,gs:.6,g:5,z:6,ch:22,fi:3,ca:30,fe:.7,mg:22,k2:340,na:120,zn:.3,fo:15,se:1,col:0}},{id:"tpl_1651",nome:"Uova sode con avocado",nome_en:"Hard-boiled eggs with avocado",categoria:"Spuntino",porzioni:1,note:"Cuocere le uova in acqua bollente per circa nove minuti, quindi raffreddarle e sgusciarle. Tagliarle a meta e servirle accanto a fette di avocado condite con sale e limone.",note_en:"Cook the eggs in boiling water for about nine minutes, then cool and peel them. Cut in half and serve alongside avocado slices seasoned with salt and lemon.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Avocado",qt:"mezzo"},{nome:"Limone",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Uova sode con avocado (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:14,gs:3.5,g:19,z:.5,ch:4,fi:3.5,ca:55,fe:1.8,mg:30,k2:400,na:150,zn:1.3,fo:80,se:15,col:330}},{id:"tpl_1652",nome:"Uova sode con spinaci saltati",nome_en:"Hard-boiled eggs with sauteed spinach",categoria:"Spuntino",porzioni:1,note:"Saltare gli spinaci in padella con un filo di olio e aglio fino ad appassirli. Cuocere le uova sode, sgusciarle e tagliarle a spicchi. Servire le uova sopra il letto di spinaci ancora caldi.",note_en:"Saute the spinach in a pan with a drizzle of oil and garlic until wilted. Hard-boil the eggs, peel and cut into wedges. Serve the eggs over the still-warm spinach bed.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Spinaci freschi",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"8ml"}],_dbEntry:{n:"Uova sode con spinaci saltati (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:15,gs:2.8,g:14,z:.5,ch:3,fi:2.5,ca:100,fe:3.2,mg:50,k2:450,na:120,zn:1.4,fo:150,se:16,col:330}},{id:"tpl_1653",nome:"Mix di frutta secca e semi (versione 2)",nome_en:"Mixed nuts and seeds snack (version 2)",categoria:"Spuntino",porzioni:4,note:"Mescolare mandorle, noci, nocciole e semi di zucca in una ciotola. Tostare leggermente il tutto in padella antiaderente per pochi minuti mescolando spesso. Lasciar raffreddare e conservare in un vasetto ermetico.",note_en:"Mix almonds, walnuts, hazelnuts and pumpkin seeds in a bowl. Lightly toast everything in a nonstick pan for a few minutes, stirring often. Let cool and store in an airtight jar.",ingredienti:[{nome:"Mandorle",qt:"40g"},{nome:"Noci sgusciate",qt:"40g"},{nome:"Nocciole",qt:"30g"},{nome:"Semi di zucca",qt:"30g"}],_dbEntry:{n:"Mix di frutta secca e semi (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:7,gs:1.8,g:20,z:1.5,ch:6,fi:3,ca:50,fe:2,mg:80,k2:280,na:5,zn:1.6,fo:20,se:4,col:0}},{id:"tpl_1654",nome:"Mix di frutta secca al miele",nome_en:"Honey-glazed mixed nuts",categoria:"Spuntino",porzioni:4,note:"Scaldare il miele in un pentolino finche fluido. Versarlo sulla frutta secca mescolando bene per ricoprirla uniformemente. Distribuire su carta forno e lasciar raffreddare finche croccante.",note_en:"Warm the honey in a small pot until runny. Pour over the mixed nuts, stirring well to coat evenly. Spread on baking paper and let cool until crisp.",ingredienti:[{nome:"Mandorle",qt:"40g"},{nome:"Anacardi",qt:"40g"},{nome:"Noci pecan",qt:"30g"},{nome:"Miele",qt:"20g"}],_dbEntry:{n:"Mix di frutta secca al miele (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:6,gs:2.3,g:18,z:9,ch:14,fi:2.5,ca:40,fe:1.6,mg:70,k2:250,na:5,zn:1.4,fo:15,se:5,col:0}},{id:"tpl_1655",nome:"Yogurt con mela e cannella",nome_en:"Yogurt with apple and cinnamon",categoria:"Spuntino",porzioni:1,note:"Tagliare la mela a cubetti piccoli e saltarla brevemente in padella con un poco di cannella. Lasciarla intiepidire e mescolarla allo yogurt bianco. Completare con qualche fiocco di avena croccante.",note_en:"Dice the apple into small cubes and briefly saute in a pan with a little cinnamon. Let it cool slightly and mix into the plain yogurt. Finish with a few crunchy oat flakes.",ingredienti:[{nome:"Yogurt bianco intero",qt:"150g"},{nome:"Mela",qt:"1"},{nome:"Cannella in polvere",qt:"q.b."},{nome:"Fiocchi di avena",qt:"15g"}],_dbEntry:{n:"Yogurt con mela e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:7,gs:2.6,g:6,z:22,ch:30,fi:3.5,ca:170,fe:1,mg:25,k2:280,na:50,zn:.8,fo:15,se:4,col:12}},{id:"tpl_1656",nome:"Skyr con lamponi e granola",nome_en:"Skyr with raspberries and granola",categoria:"Spuntino",porzioni:1,note:"Versare lo skyr in una ciotola e mescolarlo leggermente. Distribuire sopra i lamponi freschi e la granola croccante. Servire subito.",note_en:"Pour the skyr into a bowl and stir lightly. Spread the fresh raspberries and crunchy granola on top. Serve immediately.",ingredienti:[{nome:"Skyr",qt:"150g"},{nome:"Lamponi",qt:"60g"},{nome:"Granola",qt:"20g"}],_dbEntry:{n:"Skyr con lamponi e granola (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:17,gs:.5,g:2,z:12,ch:22,fi:4,ca:180,fe:1.3,mg:30,k2:280,na:60,zn:1.2,fo:20,se:5,col:5}},{id:"tpl_1657",nome:"Hummus di barbabietola con verdure crude",nome_en:"Beetroot hummus with raw vegetables",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con la barbabietola cotta, tahina, limone e aglio fino a ottenere una crema vellutata dal colore intenso. Aggiustare di sale. Servire con bastoncini di sedano e carota.",note_en:"Blend the boiled chickpeas with cooked beetroot, tahini, lemon and garlic until a velvety, vividly colored cream forms. Adjust the salt. Serve with celery and carrot sticks.",ingredienti:[{nome:"Ceci lessati",qt:"200g"},{nome:"Barbabietola cotta",qt:"100g"},{nome:"Tahina",qt:"25g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Sedano",qt:"2 coste"},{nome:"Carote",qt:"2"}],_dbEntry:{n:"Hummus di barbabietola con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:6,gs:1.1,g:8,z:6,ch:20,fi:5,ca:45,fe:1.9,mg:35,k2:380,na:180,zn:1.2,fo:65,se:3,col:0}},{id:"tpl_1658",nome:"Hummus di piselli con crostini",nome_en:"Pea hummus with croutons",categoria:"Spuntino",porzioni:4,note:"Cuocere brevemente i piselli e frullarli con olio, limone e una foglia di menta. Regolare la densita con acqua fredda. Servire con piccoli crostini di pane tostato.",note_en:"Briefly cook the peas and blend with oil, lemon and a mint leaf. Adjust the density with cold water. Serve with small toasted bread croutons.",ingredienti:[{nome:"Piselli surgelati",qt:"250g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Limone",qt:"1"},{nome:"Menta fresca",qt:"q.b."},{nome:"Pane casereccio",qt:"80g"}],_dbEntry:{n:"Hummus di piselli con crostini (ricetta)",c:"Ricette",src:"RICETTE",k:195,p:7,gs:1,g:8,z:4,ch:24,fi:5,ca:35,fe:1.7,mg:30,k2:280,na:200,zn:1,fo:60,se:3,col:0}},{id:"tpl_1659",nome:"Toast con hummus e cetrioli",nome_en:"Toast with hummus and cucumber",categoria:"Spuntino",porzioni:1,note:"Tostare la fetta di pane integrale e spalmarvi uno strato generoso di hummus. Aggiungere fette sottili di cetriolo e una spolverata di paprika. Servire subito.",note_en:"Toast the whole wheat bread slice and spread a generous layer of hummus. Add thin cucumber slices and a dusting of paprika. Serve immediately.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Hummus di ceci",qt:"50g"},{nome:"Cetrioli",qt:"mezzo"},{nome:"Paprika dolce",qt:"q.b."}],_dbEntry:{n:"Toast con hummus e cetrioli (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1,g:7,z:3,ch:25,fi:4.5,ca:35,fe:1.6,mg:30,k2:260,na:220,zn:1,fo:50,se:3,col:0}},{id:"tpl_1660",nome:"Toast con uovo e avocado",nome_en:"Toast with egg and avocado",categoria:"Spuntino",porzioni:1,note:"Tostare il pane e spalmarvi la polpa di avocado schiacciata con sale e limone. Cuocere un uovo in camicia o al tegamino e adagiarlo sopra. Completare con pepe macinato fresco.",note_en:"Toast the bread and spread with mashed avocado seasoned with salt and lemon. Cook an egg poached or fried and place it on top. Finish with freshly ground pepper.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Avocado",qt:"mezzo"},{nome:"Uovo",qt:"1"},{nome:"Limone",qt:"q.b."},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Toast con uovo e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:10,gs:3,g:16,z:2,ch:20,fi:5.5,ca:40,fe:2,mg:40,k2:480,na:180,zn:1.2,fo:70,se:14,col:186}},{id:"tpl_1661",nome:"Polpettine di quinoa e verdure",nome_en:"Quinoa and vegetable balls",categoria:"Spuntino",porzioni:4,note:"Cuocere la quinoa e lasciarla raffreddare. Mescolarla con carote e zucchine grattugiate, uovo e pangrattato. Formare delle polpettine e cuocerle in forno finche dorate e compatte.",note_en:"Cook the quinoa and let it cool. Mix with grated carrots and zucchini, egg and breadcrumbs. Shape into small balls and bake until golden and firm.",ingredienti:[{nome:"Quinoa",qt:"120g"},{nome:"Carote",qt:"80g"},{nome:"Zucchine",qt:"80g"},{nome:"Uovo",qt:"1"},{nome:"Pangrattato",qt:"30g"},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Polpettine di quinoa e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:165,p:6,gs:.8,g:5,z:2.5,ch:24,fi:2.5,ca:30,fe:1.5,mg:35,k2:250,na:120,zn:1,fo:40,se:8,col:40}},{id:"tpl_1662",nome:"Polpettine di tonno e patate",nome_en:"Tuna and potato balls",categoria:"Spuntino",porzioni:4,note:"Lessare le patate e schiacciarle ancora calde. Unire il tonno sgocciolato, un uovo e prezzemolo tritato, quindi amalgamare bene. Formare delle polpettine, passarle nel pangrattato e cuocerle in forno finche dorate.",note_en:"Boil the potatoes and mash them while still hot. Add the drained tuna, an egg and chopped parsley, then mix well. Shape into balls, coat in breadcrumbs and bake until golden.",ingredienti:[{nome:"Patate",qt:"250g"},{nome:"Tonno al naturale sgocciolato",qt:"160g"},{nome:"Uovo",qt:"1"},{nome:"Pangrattato",qt:"30g"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Polpettine di tonno e patate (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:15,gs:.8,g:5,z:1,ch:20,fi:2,ca:25,fe:1.3,mg:30,k2:400,na:220,zn:.9,fo:25,se:25,col:60}},{id:"tpl_1663",nome:"Crackers al parmigiano",nome_en:"Parmesan crackers",categoria:"Spuntino",porzioni:8,note:"Impastare la farina con il parmigiano grattugiato, il burro freddo a pezzetti e acqua fredda. Stendere sottilmente e tagliare a losanghe. Cuocere in forno a 190 gradi finche dorate e croccanti.",note_en:"Knead the flour with grated parmesan, cold diced butter and cold water. Roll out thin and cut into diamonds. Bake at 190 degrees until golden and crisp.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Parmigiano grattugiato",qt:"60g"},{nome:"Burro",qt:"50g"},{nome:"Acqua fredda",qt:"50ml"}],_dbEntry:{n:"Crackers al parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:5,gs:3.5,g:8,z:.5,ch:19,fi:1,ca:80,fe:1,mg:12,k2:60,na:200,zn:.6,fo:15,se:6,col:20}},{id:"tpl_1664",nome:"Crackers di riso soffiato",nome_en:"Puffed rice crackers",categoria:"Spuntino",porzioni:6,note:"Sciogliere un poco di miele con burro di arachidi a bagnomaria. Versare il composto sul riso soffiato e mescolare rapidamente per amalgamare. Pressare in una teglia e tagliare a quadrotti una volta rappreso.",note_en:"Melt a little honey with peanut butter over a bain-marie. Pour the mixture over the puffed rice and mix quickly to combine. Press into a tray and cut into squares once set.",ingredienti:[{nome:"Riso soffiato",qt:"150g"},{nome:"Miele",qt:"50g"},{nome:"Burro di arachidi",qt:"40g"}],_dbEntry:{n:"Crackers di riso soffiato (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:3,gs:1.5,g:6,z:11,ch:22,fi:1,ca:10,fe:.7,mg:20,k2:100,na:40,zn:.5,fo:8,se:2,col:0}},{id:"tpl_1665",nome:"Muffin salati con spinaci e ricotta",nome_en:"Savory muffins with spinach and ricotta",categoria:"Spuntino",porzioni:12,note:"Saltare gli spinaci in padella finche appassiti e lasciarli raffreddare. Mescolare farina, uova, latte e ricotta, quindi unire gli spinaci tritati. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Saute the spinach until wilted and let it cool. Mix flour, eggs, milk and ricotta, then fold in the chopped spinach. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Farina 00",qt:"220g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Ricotta vaccina",qt:"150g"},{nome:"Spinaci freschi",qt:"150g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Muffin salati con spinaci e ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:145,p:6,gs:1.8,g:6,z:1.5,ch:16,fi:1.3,ca:70,fe:1.2,mg:18,k2:120,na:150,zn:.6,fo:40,se:6,col:35}},{id:"tpl_1666",nome:"Muffin dolci alla banana senza zucchero",nome_en:"Sugar-free banana muffins",categoria:"Spuntino",porzioni:12,note:"Schiacciare le banane mature e mescolarle con uova, olio e latte. Incorporare la farina integrale e il lievito setacciati, senza aggiungere zucchero. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Mash the ripe bananas and mix with eggs, oil and milk. Fold in the sifted whole wheat flour and baking powder, without adding sugar. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Banane mature",qt:"3"},{nome:"Farina integrale",qt:"200g"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"40ml"},{nome:"Latte parzialmente scremato",qt:"60ml"}],_dbEntry:{n:"Muffin dolci alla banana senza zucchero (ricetta)",c:"Ricette",src:"RICETTE",k:135,p:3,gs:.8,g:5,z:8,ch:19,fi:1.8,ca:25,fe:1,mg:20,k2:200,na:70,zn:.4,fo:20,se:4,col:30}},{id:"tpl_1667",nome:"Frullato proteico alla fragola",nome_en:"Protein smoothie with strawberry",categoria:"Spuntino",porzioni:1,note:"Frullare le fragole con lo yogurt greco, il latte e la proteina in polvere fino a ottenere una consistenza vellutata. Aggiungere ghiaccio a piacere e servire fresco.",note_en:"Blend the strawberries with Greek yogurt, milk and protein powder until velvety. Add ice as desired and serve chilled.",ingredienti:[{nome:"Fragole",qt:"150g"},{nome:"Yogurt greco magro",qt:"100g"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Proteine in polvere",qt:"20g"}],_dbEntry:{n:"Frullato proteico alla fragola (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:1,g:3,z:16,ch:22,fi:2.5,ca:200,fe:1,mg:35,k2:400,na:100,zn:1,fo:30,se:5,col:10}},{id:"tpl_1668",nome:"Frullato con kiwi e sedano",nome_en:"Kiwi and celery smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare i kiwi sbucciati con il sedano a pezzi, il succo di limone e acqua fredda. Filtrare se si preferisce una consistenza piu liscia. Servire ben freddo.",note_en:"Blend the peeled kiwis with the celery pieces, lemon juice and cold water. Strain if a smoother texture is preferred. Serve well chilled.",ingredienti:[{nome:"Kiwi",qt:"2"},{nome:"Sedano",qt:"1 costa"},{nome:"Limone",qt:"mezzo"},{nome:"Acqua",qt:"100ml"}],_dbEntry:{n:"Frullato con kiwi e sedano (ricetta)",c:"Ricette",src:"RICETTE",k:105,p:2,gs:.1,g:.5,z:16,ch:22,fi:4,ca:50,fe:.7,mg:25,k2:400,na:40,zn:.3,fo:35,se:1,col:0}},{id:"tpl_1669",nome:"Barrette proteiche al cioccolato fondente",nome_en:"Dark chocolate protein bars",categoria:"Spuntino",porzioni:8,note:"Mescolare la proteina in polvere con burro di arachidi, miele e fiocchi di avena fino a ottenere un impasto compatto. Sciogliere il cioccolato fondente e versarlo sopra come copertura. Raffreddare in frigorifero e tagliare a barrette.",note_en:"Mix the protein powder with peanut butter, honey and oat flakes into a compact dough. Melt the dark chocolate and pour over as a coating. Chill in the fridge and cut into bars.",ingredienti:[{nome:"Proteine in polvere",qt:"60g"},{nome:"Burro di arachidi",qt:"80g"},{nome:"Miele",qt:"40g"},{nome:"Fiocchi di avena",qt:"80g"},{nome:"Cioccolato fondente",qt:"50g"}],_dbEntry:{n:"Barrette proteiche al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:11,gs:2.8,g:11,z:11,ch:19,fi:2.5,ca:20,fe:1.3,mg:45,k2:180,na:40,zn:.9,fo:10,se:3,col:0}},{id:"tpl_1670",nome:"Barrette di cereali e frutta secca",nome_en:"Cereal and dried fruit bars",categoria:"Spuntino",porzioni:8,note:"Tostare leggermente i fiocchi di cereali misti in padella. Sciogliere il miele e versarlo sui cereali insieme alla frutta secca tritata, mescolando bene. Pressare in una teglia e tagliare a barrette una volta freddo.",note_en:"Lightly toast the mixed cereal flakes in a pan. Melt the honey and pour it over the cereal along with chopped dried fruit, mixing well. Press into a tray and cut into bars once cool.",ingredienti:[{nome:"Fiocchi di cereali misti",qt:"180g"},{nome:"Miele",qt:"60g"},{nome:"Albicocche secche",qt:"50g"},{nome:"Mandorle",qt:"40g"}],_dbEntry:{n:"Barrette di cereali e frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:.7,g:6,z:16,ch:28,fi:2.5,ca:25,fe:1.2,mg:30,k2:200,na:15,zn:.6,fo:12,se:3,col:0}},{id:"tpl_1671",nome:"Bruschetta con hummus e pomodorini secchi",nome_en:"Bruschetta with hummus and sun-dried tomatoes",categoria:"Spuntino",porzioni:4,note:"Tostare le fette di pane fino a renderle dorate. Spalmare uno strato di hummus e completare con pomodorini secchi tagliati sottili e origano. Servire tiepida.",note_en:"Toast the bread slices until golden. Spread a layer of hummus and top with thinly sliced sun-dried tomatoes and oregano. Serve warm.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Hummus di ceci",qt:"100g"},{nome:"Pomodori secchi sott olio",qt:"40g"},{nome:"Origano secco",qt:"q.b."}],_dbEntry:{n:"Bruschetta con hummus e pomodorini secchi (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:6,gs:.9,g:7,z:3,ch:23,fi:3.5,ca:30,fe:1.6,mg:25,k2:250,na:280,zn:.9,fo:45,se:3,col:0}},{id:"tpl_1672",nome:"Bruschetta con ricotta e miele",nome_en:"Bruschetta with ricotta and honey",categoria:"Spuntino",porzioni:4,note:"Tostare le fette di pane finche croccanti. Spalmare la ricotta ben scolata e completare con un filo di miele e qualche noce tritata. Servire come spuntino dolce e sfizioso.",note_en:"Toast the bread slices until crisp. Spread the well-drained ricotta and finish with a drizzle of honey and a few chopped walnuts. Serve as a sweet, appealing snack.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Ricotta vaccina",qt:"200g"},{nome:"Miele",qt:"30g"},{nome:"Noci sgusciate",qt:"20g"}],_dbEntry:{n:"Bruschetta con ricotta e miele (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:3,g:9,z:8,ch:26,fi:1.5,ca:120,fe:1,mg:20,k2:130,na:150,zn:.7,fo:15,se:6,col:20}},{id:"tpl_1673",nome:"Chips di cavolo nero al forno",nome_en:"Oven-baked kale chips",categoria:"Spuntino",porzioni:4,note:"Lavare e asciugare bene le foglie di cavolo nero, eliminando la costa centrale. Condire con olio e sale, quindi disporre su una teglia in un unico strato. Cuocere a bassa temperatura finche croccanti, senza bruciarle.",note_en:"Wash and thoroughly dry the kale leaves, removing the central rib. Season with oil and salt, then arrange on a tray in a single layer. Bake at low temperature until crisp, without burning.",ingredienti:[{nome:"Cavolo nero",qt:"200g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di cavolo nero al forno (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:3,gs:.5,g:6,z:.5,ch:6,fi:2.5,ca:80,fe:1,mg:25,k2:300,na:150,zn:.4,fo:60,se:1,col:0}},{id:"tpl_1674",nome:"Chips di carote al forno",nome_en:"Oven-baked carrot chips",categoria:"Spuntino",porzioni:4,note:"Affettare le carote sottilmente con una mandolina. Condire con olio, cumino e un pizzico di sale, quindi disporre su una teglia foderata. Cuocere in forno finche croccanti, girando a meta cottura.",note_en:"Thinly slice the carrots with a mandoline. Season with oil, cumin and a pinch of salt, then arrange on a lined tray. Bake until crisp, flipping halfway through.",ingredienti:[{nome:"Carote",qt:"400g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Cumino in polvere",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di carote al forno (ricetta)",c:"Ricette",src:"RICETTE",k:105,p:1.5,gs:.5,g:5,z:8,ch:11,fi:3,ca:30,fe:.5,mg:15,k2:300,na:140,zn:.3,fo:15,se:1,col:0}},{id:"tpl_1675",nome:"Uova sode ripiene leggere",nome_en:"Light stuffed hard-boiled eggs",categoria:"Spuntino",porzioni:2,note:"Cuocere le uova sode, sgusciarle e tagliarle a meta. Prelevare i tuorli e schiacciarli con yogurt greco, senape ed erba cipollina tritata. Farcire nuovamente gli albumi con il composto ottenuto.",note_en:"Hard-boil the eggs, peel and cut in half. Remove the yolks and mash with Greek yogurt, mustard and chopped chives. Refill the egg whites with the mixture obtained.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Yogurt greco magro",qt:"40g"},{nome:"Senape",qt:"q.b."},{nome:"Erba cipollina fresca",qt:"q.b."}],_dbEntry:{n:"Uova sode ripiene leggere (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:13,gs:2.8,g:11,z:.5,ch:1.5,fi:0,ca:40,fe:1.5,mg:15,k2:180,na:120,zn:1.2,fo:45,se:15,col:330}},{id:"tpl_1676",nome:"Uova alla diavola leggere",nome_en:"Light deviled eggs",categoria:"Spuntino",porzioni:2,note:"Cuocere le uova sode, sgusciarle e tagliarle a meta. Amalgamare i tuorli con yogurt greco, un pizzico di paprika piccante e succo di limone. Riempire gli albumi con il composto e spolverare con altra paprika.",note_en:"Hard-boil the eggs, peel and cut in half. Combine the yolks with Greek yogurt, a pinch of hot paprika and lemon juice. Fill the egg whites with the mixture and dust with more paprika.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Yogurt greco magro",qt:"40g"},{nome:"Paprika piccante",qt:"q.b."},{nome:"Limone",qt:"q.b."}],_dbEntry:{n:"Uova alla diavola leggere (ricetta)",c:"Ricette",src:"RICETTE",k:165,p:13,gs:2.7,g:10,z:.5,ch:1,fi:0,ca:40,fe:1.5,mg:14,k2:170,na:110,zn:1.2,fo:45,se:15,col:330}},{id:"tpl_1677",nome:"Mix di mandorle e albicocche secche",nome_en:"Almond and dried apricot mix",categoria:"Spuntino",porzioni:4,note:"Tagliare le albicocche secche a pezzetti e mescolarle con le mandorle intere in una ciotola. Conservare il mix in un barattolo ermetico. Consumare in piccole porzioni come spuntino energetico.",note_en:"Cut the dried apricots into small pieces and mix with whole almonds in a bowl. Store the mix in an airtight jar. Eat in small portions as an energizing snack.",ingredienti:[{nome:"Mandorle",qt:"60g"},{nome:"Albicocche secche",qt:"60g"}],_dbEntry:{n:"Mix di mandorle e albicocche secche (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:6,gs:1.2,g:13,z:12,ch:15,fi:3,ca:60,fe:1.4,mg:60,k2:350,na:5,zn:1,fo:10,se:2,col:0}},{id:"tpl_1678",nome:"Mix tropicale di frutta secca",nome_en:"Tropical dried fruit mix",categoria:"Spuntino",porzioni:4,note:"Mescolare noci di cocco essiccate, ananas disidratato e anacardi in una ciotola. Amalgamare bene per distribuire uniformemente gli ingredienti. Conservare in un contenitore ermetico lontano dalla luce.",note_en:"Mix dried coconut, dehydrated pineapple and cashews in a bowl. Combine well to evenly distribute the ingredients. Store in an airtight container away from light.",ingredienti:[{nome:"Cocco essiccato",qt:"30g"},{nome:"Ananas disidratato",qt:"50g"},{nome:"Anacardi",qt:"50g"}],_dbEntry:{n:"Mix tropicale di frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:5,gs:3.5,g:12,z:18,ch:20,fi:2.5,ca:20,fe:1.5,mg:60,k2:250,na:5,zn:1.3,fo:12,se:4,col:0}},{id:"tpl_1679",nome:"Yogurt con pesca e granola croccante",nome_en:"Yogurt with peach and crunchy granola",categoria:"Spuntino",porzioni:1,note:"Tagliare la pesca a cubetti e disporla sopra lo yogurt bianco versato in una coppa. Completare con la granola croccante appena prima di servire per mantenerne la consistenza.",note_en:"Dice the peach and place it over the plain yogurt poured into a bowl. Finish with the crunchy granola just before serving to keep its texture.",ingredienti:[{nome:"Yogurt bianco intero",qt:"150g"},{nome:"Pesca",qt:"1"},{nome:"Granola",qt:"25g"}],_dbEntry:{n:"Yogurt con pesca e granola croccante (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:8,gs:2.3,g:7,z:16,ch:26,fi:2.5,ca:150,fe:1,mg:25,k2:280,na:45,zn:.8,fo:15,se:4,col:10}},{id:"tpl_1680",nome:"Budino di chia con frutti di bosco",nome_en:"Chia pudding with mixed berries",categoria:"Spuntino",porzioni:2,note:"Mescolare i semi di chia con il latte e lasciar riposare in frigorifero per almeno quattro ore, mescolando una volta a meta. Distribuire in coppette e completare con i frutti di bosco freschi al momento di servire.",note_en:"Mix the chia seeds with milk and let rest in the fridge for at least four hours, stirring once halfway through. Distribute into cups and top with fresh berries just before serving.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte parzialmente scremato",qt:"250ml"},{nome:"Mirtilli",qt:"40g"},{nome:"Fragole",qt:"40g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Budino di chia con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:8,gs:1.8,g:9,z:12,ch:18,fi:6,ca:220,fe:1.8,mg:60,k2:280,na:50,zn:.9,fo:15,se:4,col:6}},{id:"tpl_1681",nome:"Hummus di ceci al curry con verdure",nome_en:"Curried chickpea hummus with vegetables",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con curry in polvere, olio, limone e un poco di yogurt fino a ottenere una crema profumata. Aggiustare di sale. Servire con bastoncini di peperone e cetriolo.",note_en:"Blend the boiled chickpeas with curry powder, oil, lemon and a little yogurt until a fragrant cream forms. Adjust the salt. Serve with pepper and cucumber sticks.",ingredienti:[{nome:"Ceci lessati",qt:"220g"},{nome:"Curry in polvere",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"},{nome:"Limone",qt:"1"},{nome:"Yogurt bianco",qt:"30g"},{nome:"Peperoni",qt:"1"},{nome:"Cetrioli",qt:"1"}],_dbEntry:{n:"Hummus di ceci al curry con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:185,p:7,gs:1.2,g:8,z:5,ch:20,fi:5,ca:45,fe:1.9,mg:35,k2:330,na:180,zn:1.2,fo:60,se:3,col:1}},{id:"tpl_1682",nome:"Hummus di fagioli neri con nachos integrali",nome_en:"Black bean hummus with whole wheat nachos",categoria:"Spuntino",porzioni:4,note:"Frullare i fagioli neri lessati con lime, cumino e olio fino a ottenere una crema densa. Aggiustare con un pizzico di peperoncino. Servire con nachos di mais integrale.",note_en:"Blend the boiled black beans with lime, cumin and oil until a thick cream forms. Adjust with a pinch of chili. Serve with whole wheat corn nachos.",ingredienti:[{nome:"Fagioli neri lessati",qt:"220g"},{nome:"Lime",qt:"1"},{nome:"Cumino in polvere",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"},{nome:"Nachos integrali",qt:"80g"}],_dbEntry:{n:"Hummus di fagioli neri con nachos integrali (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:8,gs:1.3,g:8,z:2,ch:26,fi:6,ca:40,fe:2.2,mg:45,k2:400,na:200,zn:1.2,fo:80,se:3,col:0}},{id:"tpl_1683",nome:"Toast con salmone affumicato e formaggio spalmabile",nome_en:"Toast with smoked salmon and cream cheese",categoria:"Spuntino",porzioni:1,note:"Tostare la fetta di pane di segale e spalmarvi il formaggio fresco spalmabile. Adagiare le fette di salmone affumicato e completare con erba cipollina tritata e una macinata di pepe.",note_en:"Toast the rye bread slice and spread with fresh cream cheese. Lay the smoked salmon slices on top and finish with chopped chives and a grind of pepper.",ingredienti:[{nome:"Pane di segale",qt:"1 fetta"},{nome:"Salmone affumicato",qt:"50g"},{nome:"Formaggio fresco spalmabile",qt:"30g"},{nome:"Erba cipollina fresca",qt:"q.b."}],_dbEntry:{n:"Toast con salmone affumicato e formaggio spalmabile (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:12,gs:3.5,g:12,z:1.5,ch:18,fi:2,ca:60,fe:1,mg:25,k2:230,na:450,zn:.8,fo:15,se:20,col:25}},{id:"tpl_1684",nome:"Toast con crema di ceci e verdure grigliate",nome_en:"Toast with chickpea cream and grilled vegetables",categoria:"Spuntino",porzioni:1,note:"Grigliare fette sottili di melanzana e zucchina finche morbide. Tostare il pane e spalmarvi la crema di ceci. Adagiare le verdure grigliate sopra e completare con un filo di olio.",note_en:"Grill thin slices of eggplant and zucchini until soft. Toast the bread and spread with the chickpea cream. Place the grilled vegetables on top and finish with a drizzle of oil.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Hummus di ceci",qt:"40g"},{nome:"Melanzane",qt:"50g"},{nome:"Zucchine",qt:"50g"},{nome:"Olio extravergine",qt:"5ml"}],_dbEntry:{n:"Toast con crema di ceci e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:6,gs:.8,g:6,z:4,ch:25,fi:5,ca:35,fe:1.6,mg:30,k2:350,na:220,zn:1,fo:50,se:2,col:0}},{id:"tpl_1685",nome:"Polpettine di ricotta e spinaci",nome_en:"Ricotta and spinach balls",categoria:"Spuntino",porzioni:4,note:"Saltare gli spinaci in padella finche appassiti, strizzarli e tritarli finemente. Amalgamarli con la ricotta, un uovo e parmigiano grattugiato. Formare delle piccole polpette e cuocerle in forno finche dorate.",note_en:"Saute the spinach until wilted, squeeze and finely chop it. Mix with the ricotta, an egg and grated parmesan. Shape into small balls and bake until golden.",ingredienti:[{nome:"Ricotta vaccina",qt:"200g"},{nome:"Spinaci freschi",qt:"150g"},{nome:"Uovo",qt:"1"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Pangrattato",qt:"20g"}],_dbEntry:{n:"Polpettine di ricotta e spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:10,gs:3.5,g:9,z:1,ch:9,fi:2,ca:150,fe:1.8,mg:30,k2:280,na:180,zn:.9,fo:80,se:8,col:60}},{id:"tpl_1686",nome:"Polpettine di melanzane al forno",nome_en:"Baked eggplant balls",categoria:"Spuntino",porzioni:4,note:"Cuocere le melanzane a cubetti in padella finche morbide, quindi lasciarle raffreddare e schiacciarle. Amalgamare con pangrattato, uovo e menta tritata. Formare delle polpettine e cuocerle in forno finche dorate.",note_en:"Cook the diced eggplant in a pan until soft, then let it cool and mash it. Combine with breadcrumbs, egg and chopped mint. Shape into small balls and bake until golden.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Pangrattato",qt:"40g"},{nome:"Uovo",qt:"1"},{nome:"Menta fresca",qt:"q.b."},{nome:"Olio extravergine",qt:"10ml"}],_dbEntry:{n:"Polpettine di melanzane al forno (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:4,gs:.6,g:5,z:3,ch:16,fi:3,ca:25,fe:1,mg:20,k2:250,na:140,zn:.6,fo:20,se:6,col:40}},{id:"tpl_1687",nome:"Crackers integrali ai semi di lino",nome_en:"Whole wheat flaxseed crackers",categoria:"Spuntino",porzioni:8,note:"Impastare la farina integrale con i semi di lino macinati, acqua e olio fino a ottenere un composto omogeneo. Stendere sottilmente e tagliare a rettangoli. Cuocere in forno a 180 gradi finche croccanti.",note_en:"Knead the whole wheat flour with ground flaxseed, water and oil into a homogeneous dough. Roll out thin and cut into rectangles. Bake at 180 degrees until crisp.",ingredienti:[{nome:"Farina integrale",qt:"220g"},{nome:"Semi di lino macinati",qt:"30g"},{nome:"Acqua",qt:"100ml"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Crackers integrali ai semi di lino (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:4,gs:.6,g:6,z:.5,ch:20,fi:3.5,ca:25,fe:1.5,mg:35,k2:130,na:170,zn:.8,fo:18,se:5,col:0}},{id:"tpl_1688",nome:"Crackers al rosmarino",nome_en:"Rosemary crackers",categoria:"Spuntino",porzioni:8,note:"Impastare la farina con olio, acqua, sale e rosmarino tritato finemente fino a ottenere un panetto liscio. Stendere sottilmente e bucherellare con una forchetta. Cuocere in forno a 190 gradi finche dorati.",note_en:"Knead the flour with oil, water, salt and finely chopped rosemary into a smooth dough. Roll out thin and prick with a fork. Bake at 190 degrees until golden.",ingredienti:[{nome:"Farina 00",qt:"220g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Acqua",qt:"90ml"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Crackers al rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3.5,gs:.6,g:6,z:.3,ch:22,fi:1.3,ca:15,fe:1.2,mg:15,k2:60,na:190,zn:.5,fo:12,se:4,col:0}},{id:"tpl_1689",nome:"Muffin salati alle carote e feta",nome_en:"Savory carrot and feta muffins",categoria:"Spuntino",porzioni:12,note:"Mescolare farina, lievito, uova e olio fino a ottenere una pastella. Incorporare le carote grattugiate e la feta sbriciolata. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Mix flour, baking powder, eggs and oil into a batter. Fold in grated carrots and crumbled feta. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Farina 00",qt:"240g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Olio extravergine",qt:"50ml"},{nome:"Carote",qt:"150g"},{nome:"Feta",qt:"100g"}],_dbEntry:{n:"Muffin salati alle carote e feta (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:5,gs:2.1,g:8,z:3,ch:16,fi:1.2,ca:70,fe:1,mg:15,k2:110,na:200,zn:.6,fo:20,se:5,col:35}},{id:"tpl_1690",nome:"Muffin salati con broccoli e formaggio",nome_en:"Savory broccoli and cheese muffins",categoria:"Spuntino",porzioni:12,note:"Cuocere i broccoli al vapore e tritarli grossolanamente. Mescolare farina, uova, latte e formaggio grattugiato, quindi unire i broccoli. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Steam the broccoli and coarsely chop it. Mix flour, eggs, milk and grated cheese, then fold in the broccoli. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Farina 00",qt:"230g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Broccoli",qt:"150g"},{nome:"Formaggio grattugiato",qt:"70g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Muffin salati con broccoli e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:2,g:7,z:2,ch:16,fi:1.5,ca:80,fe:1,mg:16,k2:130,na:190,zn:.6,fo:35,se:6,col:35}},{id:"tpl_1691",nome:"Frullato proteico con avena e frutti di bosco",nome_en:"Protein smoothie with oats and berries",categoria:"Spuntino",porzioni:1,note:"Frullare i fiocchi di avena con i frutti di bosco, il latte e la proteina in polvere fino a ottenere una consistenza densa e cremosa. Aggiungere ghiaccio a piacere e servire subito.",note_en:"Blend the oat flakes with the berries, milk and protein powder until thick and creamy. Add ice as desired and serve immediately.",ingredienti:[{nome:"Fiocchi di avena",qt:"30g"},{nome:"Mirtilli",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Proteine in polvere",qt:"20g"}],_dbEntry:{n:"Frullato proteico con avena e frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:22,gs:1.3,g:5,z:16,ch:32,fi:4,ca:220,fe:1.6,mg:60,k2:450,na:100,zn:1.1,fo:25,se:5,col:10}},{id:"tpl_1692",nome:"Frullato di mango e yogurt",nome_en:"Mango and yogurt smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare la polpa di mango maturo con lo yogurt bianco e un poco di succo di lime fino a ottenere una crema liscia. Aggiungere ghiaccio se gradito e servire subito.",note_en:"Blend the ripe mango flesh with the plain yogurt and a little lime juice until smooth. Add ice if desired and serve immediately.",ingredienti:[{nome:"Mango",qt:"1"},{nome:"Yogurt bianco intero",qt:"100g"},{nome:"Lime",qt:"mezzo"}],_dbEntry:{n:"Frullato di mango e yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:5,gs:1.8,g:4,z:28,ch:33,fi:2.5,ca:130,fe:.6,mg:25,k2:350,na:40,zn:.6,fo:60,se:2,col:8}},{id:"tpl_1693",nome:"Barrette al cocco e cioccolato",nome_en:"Coconut and chocolate bars",categoria:"Spuntino",porzioni:8,note:"Mescolare il cocco rapé con il latte condensato leggero fino a formare un impasto compatto. Formare delle barrette e immergerle nel cioccolato fondente fuso. Lasciar raffreddare in frigorifero finche solide.",note_en:"Mix the shredded coconut with light condensed milk into a compact dough. Shape into bars and dip in melted dark chocolate. Chill in the fridge until firm.",ingredienti:[{nome:"Cocco rapé",qt:"150g"},{nome:"Latte condensato leggero",qt:"80g"},{nome:"Cioccolato fondente",qt:"60g"}],_dbEntry:{n:"Barrette al cocco e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:3,gs:8,g:14,z:15,ch:16,fi:3,ca:30,fe:1.3,mg:35,k2:150,na:20,zn:.5,fo:5,se:2,col:3}},{id:"tpl_1694",nome:"Barrette di riso soffiato e miele",nome_en:"Puffed rice and honey bars",categoria:"Spuntino",porzioni:8,note:"Scaldare il miele in un pentolino finche fluido. Versarlo sul riso soffiato e sulle mandorle a lamelle, mescolando rapidamente. Pressare in una teglia rivestita e tagliare a barrette una volta rappreso.",note_en:"Warm the honey in a small pot until runny. Pour over the puffed rice and sliced almonds, mixing quickly. Press into a lined tray and cut into bars once set.",ingredienti:[{nome:"Riso soffiato",qt:"150g"},{nome:"Miele",qt:"70g"},{nome:"Mandorle a lamelle",qt:"30g"}],_dbEntry:{n:"Barrette di riso soffiato e miele (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:.5,g:4,z:15,ch:28,fi:1,ca:15,fe:.7,mg:20,k2:110,na:15,zn:.4,fo:8,se:2,col:0}},{id:"tpl_1695",nome:"Bruschetta con robiola e noci",nome_en:"Bruschetta with robiola cheese and walnuts",categoria:"Spuntino",porzioni:4,note:"Tostare le fette di pane finche dorate. Spalmare uno strato generoso di robiola morbida. Completare con noci tritate grossolanamente e un filo di miele.",note_en:"Toast the bread slices until golden. Spread a generous layer of soft robiola cheese. Finish with coarsely chopped walnuts and a drizzle of honey.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Robiola",qt:"150g"},{nome:"Noci sgusciate",qt:"30g"},{nome:"Miele",qt:"15g"}],_dbEntry:{n:"Bruschetta con robiola e noci (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:8,gs:4,g:14,z:5,ch:20,fi:1.5,ca:100,fe:1,mg:30,k2:130,na:180,zn:.8,fo:15,se:6,col:25}},{id:"tpl_1696",nome:"Bruschetta ai funghi trifolati",nome_en:"Bruschetta with sauteed mushrooms",categoria:"Spuntino",porzioni:4,note:"Saltare i funghi affettati in padella con aglio, olio e prezzemolo tritato finche morbidi e dorati. Tostare le fette di pane e distribuirvi sopra i funghi caldi. Servire subito.",note_en:"Saute the sliced mushrooms in a pan with garlic, oil and chopped parsley until soft and golden. Toast the bread slices and spoon the warm mushrooms on top. Serve immediately.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Funghi champignon",qt:"300g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Bruschetta ai funghi trifolati (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:.8,g:6,z:2,ch:19,fi:2.5,ca:25,fe:1.3,mg:20,k2:350,na:180,zn:.7,fo:20,se:8,col:0}},{id:"tpl_1697",nome:"Chips di barbabietola al forno",nome_en:"Oven-baked beetroot chips",categoria:"Spuntino",porzioni:4,note:"Affettare le barbabietole crude molto sottilmente con una mandolina. Condire con olio e sale, quindi disporle su una teglia foderata in un unico strato. Cuocere in forno a bassa temperatura finche croccanti.",note_en:"Thinly slice the raw beetroot with a mandoline. Season with oil and salt, then arrange on a lined tray in a single layer. Bake at low temperature until crisp.",ingredienti:[{nome:"Barbabietola cruda",qt:"400g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Chips di barbabietola al forno (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2,gs:.5,g:5,z:8,ch:12,fi:2.5,ca:20,fe:1,mg:20,k2:320,na:150,zn:.4,fo:80,se:1,col:0}},{id:"tpl_1698",nome:"Chips di mele essiccate",nome_en:"Dried apple chips",categoria:"Spuntino",porzioni:4,note:"Tagliare le mele a fette sottilissime senza sbucciarle. Disporle su una teglia foderata con carta forno e spolverare con cannella. Essiccare in forno a bassa temperatura per circa due ore finche croccanti.",note_en:"Cut the apples into very thin slices without peeling. Arrange on a tray lined with baking paper and dust with cinnamon. Dry in the oven at low temperature for about two hours until crisp.",ingredienti:[{nome:"Mele",qt:"4"},{nome:"Cannella in polvere",qt:"q.b."}],_dbEntry:{n:"Chips di mele essiccate (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:.5,gs:.1,g:.3,z:18,ch:24,fi:3,ca:10,fe:.3,mg:8,k2:180,na:2,zn:.1,fo:5,se:.5,col:0}},{id:"tpl_1699",nome:"Uova sode con hummus",nome_en:"Hard-boiled eggs with hummus",categoria:"Spuntino",porzioni:1,note:"Cuocere le uova in acqua bollente per circa nove minuti, quindi raffreddarle e sgusciarle. Tagliarle a meta e servirle accanto a una porzione di hummus di ceci con un filo di olio.",note_en:"Cook the eggs in boiling water for about nine minutes, then cool and peel them. Cut in half and serve alongside a portion of chickpea hummus with a drizzle of oil.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Hummus di ceci",qt:"50g"},{nome:"Olio extravergine",qt:"5ml"}],_dbEntry:{n:"Uova sode con hummus (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:15,gs:2.9,g:16,z:1,ch:8,fi:2,ca:60,fe:2,mg:30,k2:250,na:200,zn:1.3,fo:70,se:15,col:330}},{id:"tpl_1700",nome:"Involtini di uovo e verdure",nome_en:"Egg and vegetable roll-ups",categoria:"Spuntino",porzioni:2,note:"Sbattere le uova e cuocerle in padella come una sottile frittata. Farcire con carote e zucchine crude julienne e un velo di formaggio spalmabile. Arrotolare strettamente e tagliare a rondelle.",note_en:"Beat the eggs and cook them in a pan like a thin omelette. Fill with julienned raw carrots and zucchini and a thin layer of cream cheese. Roll tightly and cut into rounds.",ingredienti:[{nome:"Uova",qt:"3"},{nome:"Carote",qt:"1"},{nome:"Zucchine",qt:"1"},{nome:"Formaggio fresco spalmabile",qt:"40g"}],_dbEntry:{n:"Involtini di uovo e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:13,gs:3.2,g:13,z:2,ch:4,fi:1.3,ca:50,fe:1.6,mg:20,k2:250,na:150,zn:1.1,fo:50,se:15,col:280}},{id:"tpl_1701",nome:"Mix energetico di semi misti",nome_en:"Energizing mixed seed snack",categoria:"Spuntino",porzioni:4,note:"Tostare leggermente semi di zucca, girasole e sesamo in padella antiaderente per pochi minuti. Lasciar raffreddare completamente e mescolare con uvetta. Conservare in un vasetto ermetico.",note_en:"Lightly toast pumpkin, sunflower and sesame seeds in a nonstick pan for a few minutes. Let cool completely and mix with raisins. Store in an airtight jar.",ingredienti:[{nome:"Semi di zucca",qt:"40g"},{nome:"Semi di girasole",qt:"40g"},{nome:"Semi di sesamo",qt:"20g"},{nome:"Uvetta",qt:"30g"}],_dbEntry:{n:"Mix energetico di semi misti (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:7,gs:1.6,g:15,z:9,ch:12,fi:2.5,ca:60,fe:2,mg:90,k2:280,na:5,zn:1.5,fo:20,se:5,col:0}},{id:"tpl_1702",nome:"Mix di noci pecan e mirtilli",nome_en:"Pecan and blueberry mix",categoria:"Spuntino",porzioni:4,note:"Mescolare le noci pecan con i mirtilli essiccati in una ciotola. Amalgamare bene per distribuire uniformemente gli ingredienti. Conservare in un contenitore ermetico e consumare in piccole porzioni.",note_en:"Mix the pecans with dried blueberries in a bowl. Combine well to evenly distribute the ingredients. Store in an airtight container and eat in small portions.",ingredienti:[{nome:"Noci pecan",qt:"60g"},{nome:"Mirtilli essiccati",qt:"50g"}],_dbEntry:{n:"Mix di noci pecan e mirtilli (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:3,gs:1.6,g:17,z:16,ch:16,fi:2.5,ca:20,fe:.9,mg:35,k2:150,na:5,zn:.8,fo:8,se:2,col:0}},{id:"tpl_1703",nome:"Yogurt greco con granola e fichi",nome_en:"Greek yogurt with granola and figs",categoria:"Spuntino",porzioni:1,note:"Tagliare i fichi freschi a spicchi. Versare lo yogurt greco in una coppa e distribuire sopra i fichi e la granola croccante. Completare con un filo di miele se gradito.",note_en:"Cut the fresh figs into wedges. Pour the Greek yogurt into a bowl and top with the figs and crunchy granola. Finish with a drizzle of honey if desired.",ingredienti:[{nome:"Yogurt greco magro",qt:"150g"},{nome:"Fichi freschi",qt:"2"},{nome:"Granola",qt:"20g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Yogurt greco con granola e fichi (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:14,gs:1.5,g:6,z:22,ch:28,fi:3,ca:180,fe:1.1,mg:35,k2:300,na:55,zn:1,fo:15,se:5,col:5}},{id:"tpl_1704",nome:"Cheesecake proteico in vasetto",nome_en:"Protein cheesecake in a jar",categoria:"Spuntino",porzioni:2,note:"Frullare il formaggio quark con la proteina in polvere, un poco di miele e succo di limone fino a ottenere una crema liscia. Sbriciolare qualche biscotto secco sul fondo dei vasetti. Versare la crema sopra e lasciar riposare in frigorifero un ora prima di servire.",note_en:"Blend the quark cheese with protein powder, a little honey and lemon juice until smooth. Crumble a few dry biscuits at the bottom of the jars. Pour the cream on top and let rest in the fridge for an hour before serving.",ingredienti:[{nome:"Formaggio quark magro",qt:"200g"},{nome:"Proteine in polvere",qt:"20g"},{nome:"Miele",qt:"15g"},{nome:"Limone",qt:"q.b."},{nome:"Biscotti secchi",qt:"30g"}],_dbEntry:{n:"Cheesecake proteico in vasetto (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1.8,g:5,z:14,ch:22,fi:.8,ca:150,fe:.8,mg:20,k2:200,na:100,zn:1,fo:12,se:6,col:15}},{id:"tpl_1705",nome:"Hummus di lenticchie rosse con verdure crude",nome_en:"Red lentil hummus with raw vegetables",categoria:"Spuntino",porzioni:4,note:"Cuocere le lenticchie rosse fino a renderle morbide e lasciarle raffreddare. Frullarle con tahina, limone, aglio e olio fino a ottenere una crema liscia. Servire con bastoncini di sedano e peperone.",note_en:"Cook the red lentils until soft and let them cool. Blend with tahini, lemon, garlic and oil until smooth. Serve with celery and pepper sticks.",ingredienti:[{nome:"Lenticchie rosse decorticate",qt:"150g"},{nome:"Tahina",qt:"25g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sedano",qt:"2 coste"},{nome:"Peperoni",qt:"1"}],_dbEntry:{n:"Hummus di lenticchie rosse con verdure crude (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:8,gs:1,g:7,z:3,ch:22,fi:5,ca:35,fe:2.3,mg:35,k2:350,na:150,zn:1.2,fo:70,se:3,col:0}},{id:"tpl_1706",nome:"Hummus classico con pane pita integrale",nome_en:"Classic hummus with whole wheat pita bread",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con tahina, limone, aglio e olio fino a ottenere una crema liscia e omogenea. Aggiustare di sale e regolare con acqua fredda se necessario. Servire con triangoli di pane pita integrale tostato.",note_en:"Blend the boiled chickpeas with tahini, lemon, garlic and oil until smooth and even. Adjust the salt and thin with cold water if needed. Serve with toasted whole wheat pita triangles.",ingredienti:[{nome:"Ceci lessati",qt:"220g"},{nome:"Tahina",qt:"30g"},{nome:"Limone",qt:"1"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Pane pita integrale",qt:"2"}],_dbEntry:{n:"Hummus classico con pane pita integrale (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:8,gs:1.3,g:9,z:2,ch:29,fi:5,ca:45,fe:2.1,mg:35,k2:300,na:250,zn:1.3,fo:60,se:3,col:0}},{id:"tpl_1707",nome:"Toast con burro di arachidi e banana",nome_en:"Toast with peanut butter and banana",categoria:"Spuntino",porzioni:1,note:"Tostare la fetta di pane integrale e spalmarvi il burro di arachidi. Tagliare la banana a rondelle e disporla sopra. Completare con un pizzico di cannella.",note_en:"Toast the whole wheat bread slice and spread with peanut butter. Slice the banana into rounds and arrange on top. Finish with a pinch of cinnamon.",ingredienti:[{nome:"Pane integrale",qt:"1 fetta"},{nome:"Burro di arachidi",qt:"20g"},{nome:"Banana",qt:"mezza"},{nome:"Cannella in polvere",qt:"q.b."}],_dbEntry:{n:"Toast con burro di arachidi e banana (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:8,gs:2,g:11,z:13,ch:30,fi:4,ca:25,fe:1.3,mg:50,k2:350,na:150,zn:.9,fo:25,se:3,col:0}},{id:"tpl_1708",nome:"Toast con pomodoro e origano",nome_en:"Toast with tomato and oregano",categoria:"Spuntino",porzioni:1,note:"Tostare la fetta di pane e strofinarla con uno spicchio di aglio. Disporre sopra fette di pomodoro maturo, un filo di olio e una spolverata di origano. Servire subito mentre il pane e ancora caldo.",note_en:"Toast the bread slice and rub it with a clove of garlic. Arrange ripe tomato slices on top, a drizzle of oil and a dusting of oregano. Serve immediately while the bread is still warm.",ingredienti:[{nome:"Pane casereccio",qt:"1 fetta"},{nome:"Pomodori maturi",qt:"1"},{nome:"Aglio",qt:"q.b."},{nome:"Origano secco",qt:"q.b."},{nome:"Olio extravergine",qt:"8ml"}],_dbEntry:{n:"Toast con pomodoro e origano (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:3,gs:.8,g:6,z:3,ch:20,fi:2,ca:20,fe:1.2,mg:18,k2:200,na:180,zn:.5,fo:15,se:3,col:0}},{id:"tpl_1709",nome:"Polpettine di ceci al forno con spezie",nome_en:"Baked spiced chickpea balls",categoria:"Spuntino",porzioni:4,note:"Frullare i ceci lessati con cumino, coriandolo, aglio e prezzemolo fino a ottenere un composto sodo. Formare delle piccole polpette e disporle su una teglia foderata. Cuocere in forno a 200 gradi finche dorate e croccanti fuori.",note_en:"Blend the boiled chickpeas with cumin, coriander, garlic and parsley until firm. Shape into small balls and place on a lined tray. Bake at 200 degrees until golden and crisp outside.",ingredienti:[{nome:"Ceci lessati",qt:"220g"},{nome:"Cumino in polvere",qt:"q.b."},{nome:"Coriandolo in polvere",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Polpettine di ceci al forno con spezie (ricetta)",c:"Ricette",src:"RICETTE",k:175,p:7,gs:.8,g:7,z:2,ch:20,fi:5,ca:40,fe:2,mg:35,k2:300,na:150,zn:1.2,fo:60,se:2,col:0}},{id:"tpl_1710",nome:"Polpettine di piselli e menta",nome_en:"Pea and mint balls",categoria:"Spuntino",porzioni:4,note:"Cuocere i piselli finche teneri e frullarli grossolanamente con menta fresca e ricotta. Amalgamare con pangrattato fino a ottenere un composto modellabile. Formare delle polpettine e cuocerle in forno finche dorate.",note_en:"Cook the peas until tender and coarsely blend with fresh mint and ricotta. Mix with breadcrumbs until moldable. Shape into small balls and bake until golden.",ingredienti:[{nome:"Piselli surgelati",qt:"200g"},{nome:"Ricotta vaccina",qt:"80g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Pangrattato",qt:"30g"}],_dbEntry:{n:"Polpettine di piselli e menta (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:1.6,g:5,z:3,ch:20,fi:4.5,ca:60,fe:1.5,mg:25,k2:250,na:120,zn:.8,fo:50,se:4,col:12}},{id:"tpl_1711",nome:"Crackers ai semi di zucca",nome_en:"Pumpkin seed crackers",categoria:"Spuntino",porzioni:8,note:"Impastare la farina con i semi di zucca tritati grossolanamente, acqua, olio e sale fino a ottenere un panetto liscio. Stendere sottilmente e tagliare a quadrotti. Cuocere in forno a 180 gradi finche croccanti.",note_en:"Knead the flour with coarsely chopped pumpkin seeds, water, oil and salt into a smooth dough. Roll out thin and cut into squares. Bake at 180 degrees until crisp.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Semi di zucca",qt:"40g"},{nome:"Acqua",qt:"90ml"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Crackers ai semi di zucca (ricetta)",c:"Ricette",src:"RICETTE",k:165,p:4.5,gs:.8,g:7,z:.5,ch:20,fi:1.8,ca:20,fe:1.4,mg:35,k2:120,na:170,zn:.9,fo:15,se:5,col:0}},{id:"tpl_1712",nome:"Crackers alle olive",nome_en:"Olive crackers",categoria:"Spuntino",porzioni:8,note:"Tritare finemente le olive denocciolate e amalgamarle con farina, olio e acqua fino a ottenere un impasto compatto. Stendere sottilmente e tagliare a losanghe. Cuocere in forno a 190 gradi finche dorate.",note_en:"Finely chop the pitted olives and combine with flour, oil and water into a compact dough. Roll out thin and cut into diamonds. Bake at 190 degrees until golden.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Olive nere denocciolate",qt:"60g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Acqua",qt:"70ml"}],_dbEntry:{n:"Crackers alle olive (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:4,gs:.9,g:8,z:.5,ch:20,fi:1.5,ca:20,fe:1.2,mg:15,k2:80,na:280,zn:.5,fo:12,se:4,col:0}},{id:"tpl_1713",nome:"Muffin salati con pomodori secchi",nome_en:"Savory sun-dried tomato muffins",categoria:"Spuntino",porzioni:12,note:"Tritare grossolanamente i pomodori secchi sott olio. Mescolare farina, uova, latte e olio, quindi unire i pomodori e origano. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Coarsely chop the sun-dried tomatoes in oil. Mix flour, eggs, milk and oil, then fold in the tomatoes and oregano. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Farina 00",qt:"240g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"120ml"},{nome:"Pomodori secchi sott olio",qt:"60g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Origano secco",qt:"q.b."}],_dbEntry:{n:"Muffin salati con pomodori secchi (ricetta)",c:"Ricette",src:"RICETTE",k:155,p:4,gs:1.5,g:8,z:2,ch:17,fi:1.2,ca:35,fe:1.1,mg:14,k2:120,na:220,zn:.5,fo:18,se:5,col:30}},{id:"tpl_1714",nome:"Muffin salati alla zucca",nome_en:"Savory pumpkin muffins",categoria:"Spuntino",porzioni:12,note:"Cuocere la zucca a cubetti finche morbida e schiacciarla in purea. Mescolare farina, uova, olio e la purea di zucca fino a ottenere una pastella omogenea. Versare negli stampini e cuocere in forno a 180 gradi per venti minuti.",note_en:"Cook the diced pumpkin until soft and mash into a puree. Mix flour, eggs, oil and the pumpkin puree into a smooth batter. Pour into muffin cups and bake at 180 degrees for twenty minutes.",ingredienti:[{nome:"Farina 00",qt:"230g"},{nome:"Lievito per torte salate",qt:"1 bustina"},{nome:"Uova",qt:"2"},{nome:"Zucca",qt:"200g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Formaggio grattugiato",qt:"40g"}],_dbEntry:{n:"Muffin salati alla zucca (ricetta)",c:"Ricette",src:"RICETTE",k:145,p:4,gs:1.5,g:7,z:2.5,ch:17,fi:1.3,ca:45,fe:1,mg:14,k2:150,na:150,zn:.5,fo:20,se:5,col:30}},{id:"tpl_1715",nome:"Frullato di ananas e cocco",nome_en:"Pineapple and coconut smoothie",categoria:"Spuntino",porzioni:1,note:"Frullare l ananas a pezzi con il latte di cocco e qualche cubetto di ghiaccio fino a ottenere una bevanda cremosa. Versare in un bicchiere alto e servire subito ben freddo.",note_en:"Blend the pineapple chunks with coconut milk and a few ice cubes until creamy. Pour into a tall glass and serve immediately, well chilled.",ingredienti:[{nome:"Ananas fresco",qt:"200g"},{nome:"Latte di cocco",qt:"100ml"},{nome:"Ghiaccio",qt:"q.b."}],_dbEntry:{n:"Frullato di ananas e cocco (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:2,gs:6,g:9,z:20,ch:24,fi:2.5,ca:30,fe:1,mg:30,k2:280,na:15,zn:.4,fo:20,se:2,col:0}},{id:"tpl_1716",nome:"Frullato detox con cetriolo e mela verde",nome_en:"Detox smoothie with cucumber and green apple",categoria:"Spuntino",porzioni:1,note:"Frullare il cetriolo con la mela verde a pezzi, il succo di limone e acqua fredda fino a ottenere una consistenza omogenea. Filtrare se si desidera una bevanda piu limpida. Servire ben freddo.",note_en:"Blend the cucumber with the green apple pieces, lemon juice and cold water until smooth. Strain if a clearer drink is desired. Serve well chilled.",ingredienti:[{nome:"Cetrioli",qt:"1"},{nome:"Mela verde",qt:"1"},{nome:"Limone",qt:"mezzo"},{nome:"Acqua",qt:"100ml"}],_dbEntry:{n:"Frullato detox con cetriolo e mela verde (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:1,gs:.1,g:.4,z:18,ch:22,fi:3.5,ca:25,fe:.5,mg:15,k2:250,na:10,zn:.2,fo:20,se:.5,col:0}},{id:"tpl_1717",nome:"Barrette ai semi e miele",nome_en:"Seed and honey bars",categoria:"Spuntino",porzioni:8,note:"Tostare leggermente semi di girasole, zucca e sesamo in padella. Scaldare il miele finche fluido e versarlo sui semi, mescolando bene. Pressare in una teglia rivestita e tagliare a barrette una volta raffreddato.",note_en:"Lightly toast sunflower, pumpkin and sesame seeds in a pan. Warm the honey until runny and pour over the seeds, mixing well. Press into a lined tray and cut into bars once cooled.",ingredienti:[{nome:"Semi di girasole",qt:"80g"},{nome:"Semi di zucca",qt:"50g"},{nome:"Semi di sesamo",qt:"30g"},{nome:"Miele",qt:"60g"}],_dbEntry:{n:"Barrette ai semi e miele (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:6,gs:1.5,g:14,z:11,ch:14,fi:2.5,ca:50,fe:1.8,mg:60,k2:220,na:5,zn:1.2,fo:15,se:4,col:0}},{id:"tpl_1718",nome:"Barrette di muesli fatte in casa",nome_en:"Homemade muesli bars",categoria:"Spuntino",porzioni:8,note:"Mescolare i fiocchi di avena con frutta secca tritata, uvetta e semi vari. Scaldare il miele con un poco di burro e versarlo sul composto, amalgamando bene. Pressare in una teglia e cuocere in forno a 170 gradi, quindi tagliare a barrette da fredde.",note_en:"Mix the oat flakes with chopped dried fruit, raisins and assorted seeds. Warm the honey with a little butter and pour over the mixture, combining well. Press into a tray and bake at 170 degrees, then cut into bars once cold.",ingredienti:[{nome:"Fiocchi di avena",qt:"180g"},{nome:"Uvetta",qt:"40g"},{nome:"Mandorle",qt:"30g"},{nome:"Semi di girasole",qt:"20g"},{nome:"Miele",qt:"60g"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Barrette di muesli fatte in casa (ricetta)",c:"Ricette",src:"RICETTE",k:195,p:4.5,gs:1.6,g:7,z:14,ch:29,fi:2.8,ca:25,fe:1.3,mg:35,k2:200,na:15,zn:.7,fo:12,se:4,col:6}},{id:"tpl_1719",nome:"Bruschetta con caprino e miele",nome_en:"Bruschetta with goat cheese and honey",categoria:"Spuntino",porzioni:4,note:"Tostare le fette di pane finche dorate e croccanti. Spalmare il formaggio caprino morbido sulla superficie calda. Completare con un filo di miele e una macinata di pepe nero.",note_en:"Toast the bread slices until golden and crisp. Spread the soft goat cheese over the warm surface. Finish with a drizzle of honey and a grind of black pepper.",ingredienti:[{nome:"Pane casereccio",qt:"4 fette"},{nome:"Formaggio caprino",qt:"120g"},{nome:"Miele",qt:"25g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Bruschetta con caprino e miele (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:8,gs:4.5,g:10,z:8,ch:22,fi:1.2,ca:80,fe:.9,mg:18,k2:100,na:200,zn:.7,fo:12,se:5,col:20}},{id:"tpl_1720",nome:"Spiedini di frutta fresca con yogurt",nome_en:"Fresh fruit skewers with yogurt dip",categoria:"Spuntino",porzioni:4,note:"Tagliare a cubetti fragole, ananas, melone e uva, quindi infilzarli alternati su piccoli spiedini di legno. Preparare una salsa mescolando yogurt bianco con un cucchiaino di miele. Servire gli spiedini freddi accompagnati dalla salsa.",note_en:"Cut strawberries, pineapple, melon and grapes into cubes, then thread them alternately onto small wooden skewers. Prepare a dip by mixing plain yogurt with a teaspoon of honey. Serve the skewers chilled alongside the dip.",ingredienti:[{nome:"Fragole",qt:"100g"},{nome:"Ananas fresco",qt:"100g"},{nome:"Melone",qt:"100g"},{nome:"Uva",qt:"80g"},{nome:"Yogurt bianco intero",qt:"80g"},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Spiedini di frutta fresca con yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:115,p:2.5,gs:.8,g:2,z:20,ch:22,fi:2,ca:60,fe:.5,mg:15,k2:250,na:20,zn:.3,fo:20,se:1.5,col:3}},{id:"tpl_1721",nome:"Porridge d'avena con mele e cannella",nome_en:"Oat porridge with apple and cinnamon",categoria:"Colazione",porzioni:1,note:"Cuocere i fiocchi d'avena nel latte a fuoco basso mescolando per 5-6 minuti. Aggiungere la mela tagliata a cubetti e la cannella, cuocere ancora 2 minuti. Versare in una ciotola e completare con un filo di miele.",note_en:"Cook the oats in milk over low heat, stirring for 5-6 minutes. Add the diced apple and cinnamon, cook for another 2 minutes. Pour into a bowl and finish with a drizzle of honey.",ingredienti:[{nome:"Fiocchi d'avena",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Mela",qt:"1"},{nome:"Cannella in polvere",qt:"1 pizzico"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Porridge d'avena con mele e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:13,gs:2.5,g:8,z:18,ch:55,fi:6,ca:220,fe:2.2,mg:70,k2:380,na:90,zn:1.8,fo:35,se:8,col:10}},{id:"tpl_1722",nome:"Pancakes proteici alla banana",nome_en:"Protein banana pancakes",categoria:"Colazione",porzioni:2,note:"Schiacciare la banana con una forchetta e unire le uova sbattute. Aggiungere i fiocchi d'avena macinati, il lievito e la cannella, mescolare fino a ottenere una pastella omogenea. Cuocere piccole porzioni in padella antiaderente 2-3 minuti per lato.",note_en:"Mash the banana with a fork and mix in the beaten eggs. Add the ground oats, baking powder and cinnamon, stir until smooth. Cook small portions in a nonstick pan for 2-3 minutes per side.",ingredienti:[{nome:"Banana matura",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Fiocchi d'avena macinati",qt:"60g"},{nome:"Lievito per dolci",qt:"1 cucchiaino"},{nome:"Cannella in polvere",qt:"1 pizzico"}],_dbEntry:{n:"Pancakes proteici alla banana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:18,gs:2.5,g:10,z:12,ch:38,fi:4,ca:80,fe:2,mg:50,k2:420,na:180,zn:1.5,fo:40,se:20,col:185}},{id:"tpl_1723",nome:"Yogurt greco con miele e noci (versione 3)",nome_en:"Greek yogurt with honey and walnuts (version 3)",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt greco in una ciotola. Sminuzzare grossolanamente le noci e distribuirle sopra. Completare con un cucchiaio di miele a filo.",note_en:"Pour the Greek yogurt into a bowl. Coarsely chop the walnuts and scatter them on top. Finish with a drizzle of honey.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Noci sgusciate",qt:"20g"}],_dbEntry:{n:"Yogurt greco con miele e noci (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:16,gs:5,g:16,z:18,ch:20,fi:1.5,ca:180,fe:1,mg:40,k2:280,na:55,zn:1,fo:15,se:6,col:20}},{id:"tpl_1724",nome:"Uova strapazzate con toast integrale",nome_en:"Scrambled eggs with whole wheat toast",categoria:"Colazione",porzioni:1,note:"Sbattere le uova con un pizzico di sale e pepe. Cuocere in padella con il burro a fuoco basso mescolando continuamente fino a ottenere una consistenza cremosa. Tostare il pane e servire insieme alle uova.",note_en:"Beat the eggs with a pinch of salt and pepper. Cook in a pan with butter over low heat, stirring constantly until creamy. Toast the bread and serve alongside the eggs.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Burro",qt:"10g"},{nome:"Sale",qt:"q.b."},{nome:"Pepe",qt:"q.b."}],_dbEntry:{n:"Uova strapazzate con toast integrale (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:19,gs:7,g:21,z:3,ch:22,fi:3,ca:70,fe:2.3,mg:30,k2:210,na:420,zn:1.6,fo:55,se:24,col:380}},{id:"tpl_1725",nome:"Smoothie bowl ai frutti di bosco",nome_en:"Mixed berry smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare i frutti di bosco surgelati con la banana e lo yogurt greco fino a ottenere una crema densa. Versare nella ciotola e guarnire con granola e semi di chia. Servire subito ben freddo.",note_en:"Blend the frozen mixed berries with the banana and Greek yogurt until thick and creamy. Pour into the bowl and top with granola and chia seeds. Serve immediately, well chilled.",ingredienti:[{nome:"Frutti di bosco misti surgelati",qt:"150g"},{nome:"Banana",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Granola",qt:"20g"},{nome:"Semi di chia",qt:"1 cucchiaino"}],_dbEntry:{n:"Smoothie bowl ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:10,gs:2,g:8,z:28,ch:50,fi:8,ca:130,fe:1.8,mg:60,k2:560,na:35,zn:1,fo:45,se:5,col:5}},{id:"tpl_1726",nome:"Torta soffice allo yogurt",nome_en:"Soft yogurt cake",categoria:"Colazione",porzioni:10,note:"Montare le uova con lo zucchero fino a renderle chiare e spumose. Incorporare yogurt, olio e scorza di limone, poi la farina setacciata con il lievito. Versare in uno stampo imburrato e cuocere a 180 gradi per 35-40 minuti.",note_en:"Beat the eggs with sugar until pale and fluffy. Mix in yogurt, oil and lemon zest, then fold in the sifted flour and baking powder. Pour into a greased pan and bake at 180C for 35-40 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Yogurt bianco",qt:"125g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Scorza di limone",qt:"1"}],_dbEntry:{n:"Torta soffice allo yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:5,gs:2.5,g:10,z:18,ch:35,fi:1,ca:50,fe:1,mg:15,k2:110,na:140,zn:.5,fo:18,se:10,col:65}},{id:"tpl_1727",nome:"Fette biscottate con marmellata e ricotta",nome_en:"Crispbread with jam and ricotta",categoria:"Colazione",porzioni:1,note:"Spalmare la ricotta su ogni fetta biscottata. Completare con un cucchiaino di marmellata di albicocche su ciascuna. Servire subito.",note_en:"Spread ricotta over each crispbread. Top each one with a teaspoon of apricot jam. Serve right away.",ingredienti:[{nome:"Fette biscottate",qt:"4"},{nome:"Ricotta vaccina",qt:"60g"},{nome:"Marmellata di albicocche",qt:"30g"}],_dbEntry:{n:"Fette biscottate con marmellata e ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:9,gs:4,g:9,z:18,ch:42,fi:2,ca:90,fe:1.2,mg:25,k2:150,na:180,zn:.8,fo:20,se:6,col:25}},{id:"tpl_1728",nome:"Muesli fatto in casa",nome_en:"Homemade muesli",categoria:"Colazione",porzioni:8,note:"Mescolare in una ciotola capiente i fiocchi d'avena con uvetta, mandorle, semi di girasole e cocco rape. Scaldare leggermente il miele e versarlo sul composto amalgamando bene. Conservare in un barattolo ermetico e servire con latte o yogurt.",note_en:"Mix the oats with raisins, almond flakes, sunflower seeds and shredded coconut in a large bowl. Gently warm the honey and pour it over the mixture, stirring well. Store in an airtight jar and serve with milk or yogurt.",ingredienti:[{nome:"Fiocchi d'avena",qt:"200g"},{nome:"Uvetta",qt:"40g"},{nome:"Mandorle a scaglie",qt:"40g"},{nome:"Semi di girasole",qt:"30g"},{nome:"Cocco rape",qt:"20g"},{nome:"Miele",qt:"2 cucchiai"}],_dbEntry:{n:"Muesli fatto in casa (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:9,gs:3,g:13,z:14,ch:44,fi:5,ca:60,fe:2,mg:70,k2:280,na:15,zn:1.5,fo:25,se:6,col:0}},{id:"tpl_1729",nome:"Pane e marmellata di albicocche",nome_en:"Bread with apricot jam",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane. Spalmare un velo di burro e completare con la marmellata di albicocche. Servire con il caffe o il latte.",note_en:"Lightly toast the bread slices. Spread a thin layer of butter and top with apricot jam. Serve with coffee or milk.",ingredienti:[{nome:"Pane casereccio",qt:"2 fette"},{nome:"Marmellata di albicocche",qt:"40g"},{nome:"Burro",qt:"10g"}],_dbEntry:{n:"Pane e marmellata di albicocche (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:6,gs:3,g:8,z:20,ch:52,fi:2,ca:30,fe:1.5,mg:20,k2:130,na:280,zn:.6,fo:25,se:5,col:15}},{id:"tpl_1730",nome:"Cappuccino d'avena con frutta secca",nome_en:"Oat milk cappuccino with nuts",categoria:"Colazione",porzioni:1,note:"Preparare un espresso e montare il latte d'avena caldo fino a renderlo schiumoso. Versare il latte montato sul caffe spolverando con cacao amaro. Accompagnare con un mix di mandorle e noci.",note_en:"Brew an espresso and froth the hot oat milk until foamy. Pour the frothed milk over the coffee and dust with cocoa powder. Serve alongside a mix of almonds and walnuts.",ingredienti:[{nome:"Latte d'avena",qt:"200ml"},{nome:"Caffe espresso",qt:"1"},{nome:"Mandorle",qt:"15g"},{nome:"Noci",qt:"15g"},{nome:"Cacao amaro in polvere",qt:"1 pizzico"}],_dbEntry:{n:"Cappuccino d'avena con frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:2,g:18,z:8,ch:18,fi:3,ca:150,fe:1.8,mg:80,k2:320,na:70,zn:1.3,fo:20,se:5,col:0}},{id:"tpl_1731",nome:"Frittata di albumi con verdure",nome_en:"Egg white frittata with vegetables",categoria:"Colazione",porzioni:1,note:"Tagliare a cubetti zucchine e peperoni e saltarli brevemente in padella con un filo di olio. Aggiungere gli albumi sbattuti con un pizzico di sale e cuocere a fuoco medio-basso fino a rassodare. Piegare a meta e servire calda.",note_en:"Dice the zucchini and peppers and briefly saute them in a pan with a drizzle of oil. Add the beaten egg whites with a pinch of salt and cook over medium-low heat until set. Fold in half and serve warm.",ingredienti:[{nome:"Albumi d'uovo",qt:"4"},{nome:"Zucchine",qt:"50g"},{nome:"Peperoni",qt:"50g"},{nome:"Sale",qt:"q.b."},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"}],_dbEntry:{n:"Frittata di albumi con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:22,gs:.8,g:6,z:4,ch:7,fi:1.5,ca:40,fe:1.2,mg:25,k2:320,na:280,zn:1,fo:25,se:15,col:0}},{id:"tpl_1732",nome:"Budino di chia al cacao",nome_en:"Chocolate chia pudding",categoria:"Colazione",porzioni:1,note:"Mescolare i semi di chia con il latte e il cacao amaro in un barattolo. Lasciare riposare in frigorifero per almeno 4 ore o tutta la notte mescolando una volta. Dolcificare con miele prima di servire.",note_en:"Mix the chia seeds with milk and cocoa powder in a jar. Let rest in the fridge for at least 4 hours or overnight, stirring once. Sweeten with honey before serving.",ingredienti:[{nome:"Semi di chia",qt:"30g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Cacao amaro in polvere",qt:"1 cucchiaio"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Budino di chia al cacao (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:10,gs:3,g:12,z:14,ch:24,fi:9,ca:280,fe:2.5,mg:90,k2:380,na:70,zn:1.3,fo:20,se:6,col:10}},{id:"tpl_1733",nome:"Overnight oats con frutti rossi",nome_en:"Overnight oats with red berries",categoria:"Colazione",porzioni:1,note:"Mescolare i fiocchi d'avena con latte e yogurt greco in un barattolo con coperchio. Lasciare riposare in frigorifero per tutta la notte. Al mattino guarnire con lamponi e fragole tagliate.",note_en:"Mix the oats with milk and Greek yogurt in a jar with a lid. Let rest in the fridge overnight. In the morning, top with raspberries and sliced strawberries.",ingredienti:[{nome:"Fiocchi d'avena",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"150ml"},{nome:"Yogurt greco",qt:"50g"},{nome:"Lamponi",qt:"40g"},{nome:"Fragole",qt:"40g"}],_dbEntry:{n:"Overnight oats con frutti rossi (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:15,gs:2.5,g:8,z:16,ch:48,fi:6,ca:240,fe:2,mg:65,k2:420,na:75,zn:1.5,fo:30,se:7,col:12}},{id:"tpl_1734",nome:"Pancake alla ricotta e limone",nome_en:"Ricotta and lemon pancakes",categoria:"Colazione",porzioni:2,note:"Amalgamare ricotta, uova e zucchero fino a ottenere un composto liscio. Incorporare farina, lievito e scorza di limone grattugiata. Cuocere piccole porzioni in padella antiaderente fino a doratura su entrambi i lati.",note_en:"Combine ricotta, eggs and sugar until smooth. Fold in flour, baking powder and grated lemon zest. Cook small portions in a nonstick pan until golden on both sides.",ingredienti:[{nome:"Ricotta vaccina",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Farina 00",qt:"60g"},{nome:"Scorza di limone",qt:"1"},{nome:"Lievito per dolci",qt:"mezza bustina"},{nome:"Zucchero",qt:"20g"}],_dbEntry:{n:"Pancake alla ricotta e limone (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:14,gs:3.5,g:11,z:10,ch:36,fi:1.5,ca:140,fe:1.5,mg:25,k2:180,na:160,zn:1,fo:25,se:15,col:150}},{id:"tpl_1735",nome:"Toast avocado e uovo in camicia",nome_en:"Avocado toast with poached egg",categoria:"Colazione",porzioni:1,note:"Portare a ebollizione acqua con aceto e cuocere un uovo in camicia per 3 minuti. Tostare il pane e spalmarlo con avocado schiacciato, salato e pepato. Adagiare l'uovo in camicia sopra il toast.",note_en:"Bring water with vinegar to a boil and poach the egg for 3 minutes. Toast the bread and spread with mashed avocado seasoned with salt and pepper. Place the poached egg on top of the toast.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"mezzo"},{nome:"Uova",qt:"1"},{nome:"Aceto di mele",qt:"1 cucchiaio"},{nome:"Sale",qt:"q.b."},{nome:"Pepe",qt:"q.b."}],_dbEntry:{n:"Toast avocado e uovo in camicia (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:14,gs:4,g:20,z:3,ch:28,fi:7,ca:60,fe:2.2,mg:50,k2:550,na:320,zn:1.4,fo:60,se:18,col:190}},{id:"tpl_1736",nome:"Crepe dolci con crema di nocciole",nome_en:"Sweet crepes with hazelnut-cocoa spread",categoria:"Colazione",porzioni:2,note:"Preparare la pastella mescolando farina, latte e uovo fino a renderla liscia. Cuocere sottili crepe in padella imburrata girandole a meta cottura. Farcire ogni crepe con la crema al cacao e nocciole e arrotolare.",note_en:"Prepare the batter by mixing flour, milk and egg until smooth. Cook thin crepes in a buttered pan, flipping halfway through. Fill each crepe with the cocoa-hazelnut spread and roll up.",ingredienti:[{nome:"Farina 00",qt:"100g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Uova",qt:"1"},{nome:"Crema spalmabile al cacao e nocciole",qt:"40g"},{nome:"Burro",qt:"10g"}],_dbEntry:{n:"Crepe dolci con crema di nocciole (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:11,gs:6,g:16,z:18,ch:48,fi:2,ca:140,fe:1.8,mg:35,k2:220,na:150,zn:1,fo:30,se:12,col:90}},{id:"tpl_1737",nome:"Waffle integrali con sciroppo d'acero",nome_en:"Whole wheat waffles with maple syrup",categoria:"Colazione",porzioni:4,note:"Mescolare farina integrale, lievito, uova, latte e olio fino a ottenere una pastella liscia. Cuocere nella piastra per waffle fino a doratura. Servire caldi irrorati con sciroppo d'acero.",note_en:"Mix whole wheat flour, baking powder, eggs, milk and oil into a smooth batter. Cook in a waffle iron until golden. Serve warm drizzled with maple syrup.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"250ml"},{nome:"Olio di semi",qt:"40ml"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Sciroppo d'acero",qt:"40ml"}],_dbEntry:{n:"Waffle integrali con sciroppo d'acero (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:9,gs:2.5,g:11,z:14,ch:48,fi:3.5,ca:90,fe:1.8,mg:30,k2:200,na:280,zn:1,fo:25,se:10,col:90}},{id:"tpl_1738",nome:"French toast alla cannella",nome_en:"Cinnamon French toast",categoria:"Colazione",porzioni:2,note:"Sbattere uova, latte, cannella e zucchero in una ciotola larga. Immergere le fette di pane nel composto fino a farle inzuppare bene. Cuocere in padella con il burro fino a doratura su entrambi i lati.",note_en:"Beat eggs, milk, cinnamon and sugar in a wide bowl. Soak the bread slices in the mixture until well saturated. Cook in a pan with butter until golden on both sides.",ingredienti:[{nome:"Pane in cassetta",qt:"4 fette"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Cannella in polvere",qt:"1 pizzico"},{nome:"Burro",qt:"15g"},{nome:"Zucchero di canna",qt:"1 cucchiaio"}],_dbEntry:{n:"French toast alla cannella (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:5,g:14,z:14,ch:40,fi:2,ca:110,fe:1.8,mg:25,k2:200,na:350,zn:1,fo:35,se:16,col:170}},{id:"tpl_1739",nome:"Granola croccante fatta in casa",nome_en:"Homemade crunchy granola",categoria:"Colazione",porzioni:10,note:"Mescolare i fiocchi d'avena con miele, olio, mandorle, semi di zucca e cannella. Distribuire su una teglia rivestita di carta forno e cuocere a 160 gradi per 25-30 minuti mescolando a meta cottura. Lasciare raffreddare prima di sgranare e conservare in barattolo.",note_en:"Mix the oats with honey, oil, almonds, pumpkin seeds and cinnamon. Spread on a baking sheet lined with parchment and bake at 160C for 25-30 minutes, stirring halfway. Let cool before breaking apart and storing in a jar.",ingredienti:[{nome:"Fiocchi d'avena",qt:"250g"},{nome:"Miele",qt:"80g"},{nome:"Olio di semi",qt:"40ml"},{nome:"Mandorle",qt:"50g"},{nome:"Semi di zucca",qt:"30g"},{nome:"Cannella in polvere",qt:"1 cucchiaino"}],_dbEntry:{n:"Granola croccante fatta in casa (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:8,gs:2,g:13,z:12,ch:40,fi:4.5,ca:50,fe:1.8,mg:60,k2:230,na:10,zn:1.2,fo:18,se:5,col:0}},{id:"tpl_1740",nome:"Parfait allo yogurt e granola",nome_en:"Yogurt and granola parfait",categoria:"Colazione",porzioni:1,note:"Alternare in un bicchiere alto strati di yogurt greco, granola e fragole tagliate a pezzetti. Ripetere gli strati fino a riempire il bicchiere. Completare con un filo di miele.",note_en:"Layer Greek yogurt, granola and chopped strawberries in a tall glass. Repeat the layers until the glass is full. Finish with a drizzle of honey.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Granola",qt:"30g"},{nome:"Fragole",qt:"60g"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Parfait allo yogurt e granola (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:16,gs:3.5,g:11,z:20,ch:34,fi:3,ca:200,fe:1.5,mg:40,k2:340,na:60,zn:1,fo:25,se:6,col:15}},{id:"tpl_1741",nome:"Ciambellone allo yogurt",nome_en:"Yogurt bundt cake",categoria:"Colazione",porzioni:10,note:"Sbattere uova e zucchero fino a ottenere un composto chiaro e spumoso. Aggiungere yogurt e olio, poi incorporare farina e lievito setacciati. Versare nello stampo a ciambella e cuocere a 180 gradi per 40 minuti.",note_en:"Beat the eggs with sugar until pale and foamy. Add yogurt and oil, then fold in the sifted flour and baking powder. Pour into a bundt pan and bake at 180C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Yogurt bianco",qt:"125g"},{nome:"Zucchero",qt:"180g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"100ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Ciambellone allo yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:2.5,g:11,z:19,ch:38,fi:1,ca:55,fe:1.1,mg:16,k2:115,na:150,zn:.5,fo:18,se:10,col:70}},{id:"tpl_1742",nome:"Plumcake ai mirtilli",nome_en:"Blueberry plumcake",categoria:"Colazione",porzioni:10,note:"Lavorare il burro morbido con lo zucchero fino a ottenere una crema. Aggiungere le uova una alla volta, poi farina, lievito e latte alternandoli. Incorporare i mirtilli infarinati e cuocere in stampo da plumcake a 170 gradi per 45 minuti.",note_en:"Cream the softened butter with sugar until fluffy. Add the eggs one at a time, then alternate flour, baking powder and milk. Fold in the floured blueberries and bake in a loaf pan at 170C for 45 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Mirtilli freschi",qt:"150g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Burro",qt:"100g"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Latte parzialmente scremato",qt:"50ml"}],_dbEntry:{n:"Plumcake ai mirtilli (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:5,gs:6,g:13,z:18,ch:40,fi:1.5,ca:35,fe:1.2,mg:16,k2:120,na:140,zn:.5,fo:18,se:10,col:75}},{id:"tpl_1743",nome:"Torta di mele senza burro (versione 2)",nome_en:"Butter-free apple cake (version 2)",categoria:"Colazione",porzioni:10,note:"Sbucciare e tagliare a fettine sottili le mele. Mescolare uova, zucchero e olio, poi incorporare farina, lievito e cannella. Unire le mele all'impasto, versare in una teglia e cuocere a 180 gradi per 45 minuti.",note_en:"Peel and thinly slice the apples. Mix eggs, sugar and oil, then fold in flour, baking powder and cinnamon. Add the apples to the batter, pour into a baking pan and bake at 180C for 45 minutes.",ingredienti:[{nome:"Mele",qt:"4"},{nome:"Farina 00",qt:"250g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Cannella in polvere",qt:"1 pizzico"}],_dbEntry:{n:"Torta di mele senza burro (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:4,gs:1,g:7,z:18,ch:38,fi:2,ca:25,fe:1,mg:14,k2:140,na:120,zn:.4,fo:15,se:7,col:40}},{id:"tpl_1744",nome:"Budino di semolino al limone",nome_en:"Lemon semolina pudding",categoria:"Colazione",porzioni:2,note:"Portare il latte a bollore con la scorza di limone e versare a pioggia il semolino mescolando. Cuocere per 5-6 minuti fino ad addensare, poi togliere dal fuoco e incorporare un uovo sbattuto con lo zucchero. Versare in coppette e lasciare raffreddare prima di servire.",note_en:"Bring the milk to a boil with the lemon zest and pour in the semolina, stirring. Cook for 5-6 minutes until thickened, then remove from heat and mix in the beaten egg and sugar. Pour into cups and let cool before serving.",ingredienti:[{nome:"Semolino",qt:"60g"},{nome:"Latte parzialmente scremato",qt:"400ml"},{nome:"Zucchero",qt:"40g"},{nome:"Scorza di limone",qt:"1"},{nome:"Uovo",qt:"1"}],_dbEntry:{n:"Budino di semolino al limone (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:3,g:7,z:20,ch:40,fi:1,ca:180,fe:1,mg:25,k2:260,na:75,zn:1,fo:15,se:8,col:85}},{id:"tpl_1745",nome:"Porridge di grano saraceno",nome_en:"Buckwheat porridge",categoria:"Colazione",porzioni:1,note:"Sciacquare il grano saraceno e cuocerlo nel latte a fuoco basso per 12-15 minuti mescolando spesso. Versare in una ciotola quando sara cremoso. Completare con miele e noci sminuzzate.",note_en:"Rinse the buckwheat and cook it in the milk over low heat for 12-15 minutes, stirring often. Pour into a bowl once creamy. Finish with honey and chopped walnuts.",ingredienti:[{nome:"Grano saraceno in chicchi",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Noci",qt:"15g"}],_dbEntry:{n:"Porridge di grano saraceno (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:2.5,g:10,z:16,ch:52,fi:5,ca:200,fe:2.2,mg:90,k2:360,na:70,zn:1.6,fo:30,se:7,col:10}},{id:"tpl_1746",nome:"Pancakes alle mele",nome_en:"Apple pancakes",categoria:"Colazione",porzioni:2,note:"Grattugiare la mela e unirla alla pastella preparata con farina, uova, latte e lievito. Profumare con cannella e mescolare fino a ottenere un composto omogeneo. Cuocere in padella antiaderente piccole porzioni fino a doratura.",note_en:"Grate the apple and fold it into the batter made with flour, eggs, milk and baking powder. Flavor with cinnamon and mix until smooth. Cook small portions in a nonstick pan until golden.",ingredienti:[{nome:"Farina 00",qt:"120g"},{nome:"Mela",qt:"1"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Lievito per dolci",qt:"mezza bustina"},{nome:"Cannella in polvere",qt:"1 pizzico"}],_dbEntry:{n:"Pancakes alle mele (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:10,gs:2.5,g:8,z:14,ch:45,fi:2.5,ca:90,fe:1.6,mg:25,k2:210,na:160,zn:1,fo:25,se:14,col:150}},{id:"tpl_1747",nome:"Yogurt con muesli e frutta fresca",nome_en:"Yogurt with muesli and fresh fruit",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt in una ciotola e distribuire sopra il muesli. Tagliare a fettine kiwi e banana e disporli sulla superficie. Mescolare leggermente prima di gustare.",note_en:"Pour the yogurt into a bowl and scatter the muesli on top. Slice the kiwi and banana and arrange them on top. Stir lightly before enjoying.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Muesli",qt:"40g"},{nome:"Kiwi",qt:"1"},{nome:"Banana",qt:"mezza"}],_dbEntry:{n:"Yogurt con muesli e frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:11,gs:3,g:9,z:22,ch:48,fi:5,ca:180,fe:1.8,mg:55,k2:440,na:60,zn:1,fo:30,se:6,col:10}},{id:"tpl_1748",nome:"Uova al tegamino con speck",nome_en:"Fried eggs with speck",categoria:"Colazione",porzioni:1,note:"Scaldare l'olio in una padella antiaderente e rosolare lo speck fino a renderlo croccante. Aggiungere le uova intere e cuocere a fuoco basso fino a rassodare l'albume mantenendo il tuorlo morbido. Servire con una fetta di pane tostato.",note_en:"Heat the oil in a nonstick pan and brown the speck until crisp. Add the whole eggs and cook over low heat until the white sets while the yolk stays soft. Serve with a slice of toasted bread.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Speck",qt:"40g"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"},{nome:"Pane casereccio",qt:"1 fetta"}],_dbEntry:{n:"Uova al tegamino con speck (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:22,gs:6,g:25,z:2,ch:16,fi:1,ca:50,fe:2,mg:25,k2:240,na:650,zn:1.8,fo:40,se:22,col:380}},{id:"tpl_1749",nome:"Smoothie bowl al mango",nome_en:"Mango smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare il mango con la banana e lo yogurt greco fino a ottenere una consistenza densa e cremosa. Versare nella ciotola e guarnire con cocco rape e semi di chia. Servire immediatamente.",note_en:"Blend the mango with the banana and Greek yogurt until thick and creamy. Pour into the bowl and top with shredded coconut and chia seeds. Serve immediately.",ingredienti:[{nome:"Mango",qt:"150g"},{nome:"Banana",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Cocco rape",qt:"10g"},{nome:"Semi di chia",qt:"1 cucchiaino"}],_dbEntry:{n:"Smoothie bowl al mango (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:9,gs:3,g:9,z:30,ch:48,fi:5,ca:110,fe:1.2,mg:50,k2:520,na:35,zn:.9,fo:50,se:4,col:5}},{id:"tpl_1750",nome:"Ricotta con miele e noci",nome_en:"Ricotta with honey and walnuts",categoria:"Colazione",porzioni:1,note:"Disporre la ricotta in una ciotola e lavorarla leggermente con una forchetta per renderla cremosa. Guarnire con le noci sminuzzate e un filo di miele. Spolverare con un pizzico di cannella.",note_en:"Place the ricotta in a bowl and work it lightly with a fork until creamy. Top with the chopped walnuts and a drizzle of honey. Dust with a pinch of cinnamon.",ingredienti:[{nome:"Ricotta vaccina",qt:"150g"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Noci sgusciate",qt:"20g"},{nome:"Cannella in polvere",qt:"1 pizzico"}],_dbEntry:{n:"Ricotta con miele e noci (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:14,gs:6,g:18,z:16,ch:18,fi:1,ca:220,fe:1,mg:35,k2:200,na:90,zn:1.2,fo:20,se:8,col:45}},{id:"tpl_1751",nome:"Toast con hummus e pomodorini",nome_en:"Toast with hummus and cherry tomatoes",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane integrale. Spalmare l'hummus di ceci e disporre sopra i pomodorini tagliati a meta. Completare con un filo d'olio.",note_en:"Lightly toast the whole wheat bread slices. Spread the hummus and top with the halved cherry tomatoes. Finish with a drizzle of oil.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Hummus di ceci",qt:"50g"},{nome:"Pomodorini",qt:"6"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"}],_dbEntry:{n:"Toast con hummus e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:11,gs:1.5,g:11,z:5,ch:40,fi:7,ca:50,fe:2.2,mg:50,k2:380,na:380,zn:1.3,fo:60,se:4,col:0}},{id:"tpl_1752",nome:"Frittatine di zucchine",nome_en:"Small zucchini frittatas",categoria:"Colazione",porzioni:2,note:"Grattugiare le zucchine e strizzarle per eliminare l'acqua in eccesso. Mescolare con uova, parmigiano, farina e un pizzico di sale. Versare piccole porzioni in padella calda con olio e cuocere fino a doratura su entrambi i lati.",note_en:"Grate the zucchini and squeeze out the excess water. Mix with eggs, parmesan, flour and a pinch of salt. Pour small portions into a hot pan with oil and cook until golden on both sides.",ingredienti:[{nome:"Zucchine",qt:"200g"},{nome:"Uova",qt:"3"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Farina 00",qt:"20g"},{nome:"Sale",qt:"q.b."},{nome:"Olio extravergine di oliva",qt:"1 cucchiaio"}],_dbEntry:{n:"Frittatine di zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:15,gs:3.5,g:15,z:2,ch:9,fi:1.5,ca:140,fe:1.5,mg:25,k2:280,na:320,zn:1.3,fo:35,se:15,col:220}},{id:"tpl_1753",nome:"Budino di riso alla vaniglia",nome_en:"Vanilla rice pudding",categoria:"Colazione",porzioni:2,note:"Cuocere il riso nel latte con la vaniglia a fuoco basso per circa 25 minuti mescolando spesso fino a ottenere una crema densa. Aggiungere lo zucchero e mescolare fino a scioglierlo completamente. Versare in coppette e servire tiepido o freddo.",note_en:"Cook the rice in milk with vanilla over low heat for about 25 minutes, stirring often, until creamy. Add the sugar and stir until fully dissolved. Pour into cups and serve warm or chilled.",ingredienti:[{nome:"Riso originario",qt:"60g"},{nome:"Latte parzialmente scremato",qt:"400ml"},{nome:"Zucchero",qt:"40g"},{nome:"Baccello di vaniglia",qt:"mezzo"}],_dbEntry:{n:"Budino di riso alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:7,gs:3,g:6,z:18,ch:46,fi:.8,ca:180,fe:.6,mg:22,k2:230,na:60,zn:.8,fo:10,se:6,col:15}},{id:"tpl_1754",nome:"Muffin salati con spinaci e feta",nome_en:"Spinach and feta savory muffins",categoria:"Colazione",porzioni:8,note:"Saltare brevemente gli spinaci in padella e lasciarli intiepidire. Mescolare farina, lievito, uova, latte e olio, poi incorporare spinaci e feta a cubetti. Versare negli stampini da muffin e cuocere a 180 gradi per 20-25 minuti.",note_en:"Briefly saute the spinach in a pan and let it cool slightly. Mix flour, baking powder, eggs, milk and oil, then fold in the spinach and cubed feta. Pour into muffin tins and bake at 180C for 20-25 minutes.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Spinaci freschi",qt:"100g"},{nome:"Feta",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Olio extravergine di oliva",qt:"60ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Muffin salati con spinaci e feta (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:8,gs:3.5,g:12,z:2,ch:18,fi:1.5,ca:130,fe:1.3,mg:20,k2:160,na:320,zn:.9,fo:40,se:10,col:75}},{id:"tpl_1755",nome:"Pane tostato con burro di arachidi e banana",nome_en:"Toast with peanut butter and banana",categoria:"Colazione",porzioni:1,note:"Tostare le fette di pane integrale fino a doratura. Spalmare il burro di arachidi su ciascuna fetta e completare con le fettine di banana. Servire subito.",note_en:"Toast the whole wheat bread slices until golden. Spread the peanut butter on each slice and top with banana slices. Serve immediately.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Burro di arachidi",qt:"30g"},{nome:"Banana",qt:"1"}],_dbEntry:{n:"Pane tostato con burro di arachidi e banana (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:13,gs:4,g:18,z:18,ch:48,fi:6,ca:50,fe:2,mg:80,k2:520,na:280,zn:1.5,fo:40,se:6,col:0}},{id:"tpl_1756",nome:"Cappuccino classico con cornetto",nome_en:"Classic cappuccino with croissant",categoria:"Colazione",porzioni:1,note:"Preparare un espresso e montare il latte caldo fino a ottenere una schiuma densa. Versare il latte montato sul caffe. Accompagnare con un cornetto semplice appena scaldato.",note_en:"Brew an espresso and froth the hot milk until dense foam forms. Pour the frothed milk over the coffee. Serve with a warmed plain croissant.",ingredienti:[{nome:"Latte intero",qt:"150ml"},{nome:"Caffe espresso",qt:"1"},{nome:"Cornetto semplice",qt:"1"}],_dbEntry:{n:"Cappuccino classico con cornetto (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:9,gs:7,g:16,z:14,ch:40,fi:1.5,ca:190,fe:1.2,mg:30,k2:260,na:320,zn:1,fo:25,se:8,col:40}},{id:"tpl_1757",nome:"Torta all'arancia",nome_en:"Orange cake",categoria:"Colazione",porzioni:10,note:"Spremere le arance e grattugiarne la scorza. Sbattere uova e zucchero, unire succo, scorza e olio, poi incorporare farina e lievito setacciati. Versare in uno stampo e cuocere a 180 gradi per 40 minuti.",note_en:"Squeeze the oranges and zest one of them. Beat eggs and sugar, add the juice, zest and oil, then fold in the sifted flour and baking powder. Pour into a pan and bake at 180C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Arance",qt:"2"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta all'arancia (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:4,gs:2,g:9,z:19,ch:38,fi:1.2,ca:35,fe:1,mg:15,k2:140,na:130,zn:.4,fo:25,se:8,col:65}},{id:"tpl_1758",nome:"Crostata di marmellata (versione 2)",nome_en:"Jam tart (version 2)",categoria:"Colazione",porzioni:10,note:"Impastare farina, burro freddo a pezzetti, zucchero, uova e lievito fino a ottenere una pasta frolla omogenea. Stendere due terzi della pasta frolla in una tortiera e farcire con la marmellata. Decorare con strisce di pasta frolla rimasta e cuocere a 180 gradi per 30 minuti.",note_en:"Knead flour, cold cubed butter, sugar, eggs and baking powder into a smooth shortcrust pastry. Roll out two thirds of the dough in a tart pan and fill with the jam. Decorate with strips of the remaining pastry and bake at 180C for 30 minutes.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Burro",qt:"150g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Marmellata di albicocche",qt:"250g"},{nome:"Lievito per dolci",qt:"mezza bustina"}],_dbEntry:{n:"Crostata di marmellata (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:4,gs:7,g:13,z:22,ch:44,fi:1,ca:25,fe:1,mg:12,k2:100,na:110,zn:.4,fo:14,se:9,col:60}},{id:"tpl_1759",nome:"Biscotti d'avena e miele",nome_en:"Oat and honey biscuits",categoria:"Colazione",porzioni:16,note:"Lavorare il burro morbido con il miele e l'uovo fino a ottenere una crema. Incorporare fiocchi d'avena, farina e lievito fino a formare un impasto compatto. Formare palline, schiacciarle leggermente su una teglia e cuocere a 180 gradi per 12-15 minuti.",note_en:"Work the softened butter with honey and egg until creamy. Fold in oats, flour and baking powder until a firm dough forms. Shape into balls, flatten slightly on a baking sheet and bake at 180C for 12-15 minutes.",ingredienti:[{nome:"Fiocchi d'avena",qt:"200g"},{nome:"Farina 00",qt:"100g"},{nome:"Miele",qt:"100g"},{nome:"Burro",qt:"80g"},{nome:"Uovo",qt:"1"},{nome:"Lievito per dolci",qt:"mezza bustina"}],_dbEntry:{n:"Biscotti d'avena e miele (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:3.5,gs:3,g:7,z:10,ch:28,fi:2,ca:20,fe:1,mg:18,k2:100,na:60,zn:.5,fo:10,se:4,col:25}},{id:"tpl_1760",nome:"Yogurt con semi di chia e frutta secca",nome_en:"Yogurt with chia seeds and nuts",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt greco in una ciotola e cospargere con i semi di chia. Aggiungere mandorle e noci tritate grossolanamente. Completare con un cucchiaino di miele.",note_en:"Pour the Greek yogurt into a bowl and sprinkle with chia seeds. Add coarsely chopped almonds and walnuts. Finish with a teaspoon of honey.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Semi di chia",qt:"1 cucchiaio"},{nome:"Mandorle",qt:"15g"},{nome:"Noci",qt:"15g"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Yogurt con semi di chia e frutta secca (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:18,gs:5,g:20,z:14,ch:18,fi:5,ca:220,fe:1.8,mg:70,k2:340,na:55,zn:1.5,fo:20,se:8,col:20}},{id:"tpl_1761",nome:"Uova alla coque con soldatini",nome_en:"Soft-boiled eggs with toast soldiers",categoria:"Colazione",porzioni:1,note:"Immergere le uova in acqua bollente e cuocere per 5-6 minuti per ottenere il tuorlo morbido. Tostare il pane, spalmarlo di burro e tagliarlo a listarelle per formare i soldatini. Servire le uova nel portauovo con i soldatini per intingere.",note_en:"Dip the eggs in boiling water and cook for 5-6 minutes for a soft yolk. Toast the bread, spread with butter and cut into strips to make soldiers. Serve the eggs in egg cups with the soldiers for dipping.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Pane in cassetta",qt:"2 fette"},{nome:"Burro",qt:"10g"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Uova alla coque con soldatini (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:16,gs:6,g:19,z:3,ch:18,fi:1,ca:60,fe:2,mg:25,k2:180,na:320,zn:1.4,fo:45,se:22,col:370}},{id:"tpl_1762",nome:"Smoothie bowl verde detox",nome_en:"Green detox smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare spinaci, banana, mela verde e latte di mandorla fino a ottenere un composto liscio e denso. Versare nella ciotola e cospargere con i semi di lino. Servire subito ben fresco.",note_en:"Blend spinach, banana, green apple and almond milk until smooth and thick. Pour into the bowl and sprinkle with flax seeds. Serve immediately, well chilled.",ingredienti:[{nome:"Spinaci freschi",qt:"30g"},{nome:"Banana",qt:"1"},{nome:"Mela verde",qt:"1"},{nome:"Latte di mandorla",qt:"100ml"},{nome:"Semi di lino",qt:"1 cucchiaino"}],_dbEntry:{n:"Smoothie bowl verde detox (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:.5,g:5,z:28,ch:42,fi:7,ca:90,fe:1.6,mg:55,k2:500,na:60,zn:.8,fo:60,se:3,col:0}},{id:"tpl_1763",nome:"Porridge proteico al cioccolato",nome_en:"Chocolate protein porridge",categoria:"Colazione",porzioni:1,note:"Cuocere i fiocchi d'avena nel latte a fuoco basso per 5 minuti mescolando. Togliere dal fuoco e incorporare le proteine in polvere e il cacao amaro mescolando bene per evitare grumi. Versare in una ciotola e servire caldo.",note_en:"Cook the oats in milk over low heat for 5 minutes, stirring. Remove from heat and stir in the protein powder and cocoa, mixing well to avoid lumps. Pour into a bowl and serve warm.",ingredienti:[{nome:"Fiocchi d'avena",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Proteine in polvere al cioccolato",qt:"20g"},{nome:"Cacao amaro in polvere",qt:"1 cucchiaino"}],_dbEntry:{n:"Porridge proteico al cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:26,gs:2.5,g:9,z:14,ch:48,fi:6,ca:280,fe:2.5,mg:80,k2:440,na:160,zn:2,fo:30,se:8,col:10}},{id:"tpl_1764",nome:"Pancakes salati con formaggio",nome_en:"Savory cheese pancakes",categoria:"Colazione",porzioni:2,note:"Mescolare farina, uova e latte fino a ottenere una pastella liscia. Incorporare formaggio grattugiato, erba cipollina tritata e un pizzico di sale. Cuocere piccole porzioni in padella antiaderente fino a doratura.",note_en:"Mix flour, eggs and milk into a smooth batter. Fold in the grated cheese, chopped chives and a pinch of salt. Cook small portions in a nonstick pan until golden.",ingredienti:[{nome:"Farina 00",qt:"120g"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Formaggio grattugiato",qt:"40g"},{nome:"Erba cipollina",qt:"1 cucchiaio"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Pancakes salati con formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:14,gs:4.5,g:13,z:4,ch:34,fi:1.5,ca:180,fe:1.5,mg:25,k2:180,na:380,zn:1.3,fo:25,se:15,col:160}},{id:"tpl_1765",nome:"Toast con crema di nocciole e cacao",nome_en:"Toast with cocoa-hazelnut spread",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane. Spalmare la crema al cacao e nocciole su ciascuna fetta. Servire subito, ideale con latte o cappuccino.",note_en:"Lightly toast the bread slices. Spread the cocoa-hazelnut cream on each slice. Serve right away, ideal with milk or cappuccino.",ingredienti:[{nome:"Pane in cassetta",qt:"2 fette"},{nome:"Crema spalmabile al cacao e nocciole",qt:"40g"}],_dbEntry:{n:"Toast con crema di nocciole e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:7,gs:6,g:16,z:24,ch:52,fi:2,ca:80,fe:1.5,mg:30,k2:160,na:280,zn:.8,fo:25,se:6,col:5}},{id:"tpl_1766",nome:"Frittata al forno con pomodorini",nome_en:"Baked frittata with cherry tomatoes",categoria:"Colazione",porzioni:2,note:"Sbattere le uova con latte, parmigiano, sale e origano. Versare in una teglia imburrata e distribuire sopra i pomodorini tagliati a meta. Cuocere in forno a 180 gradi per 20 minuti fino a doratura.",note_en:"Beat the eggs with milk, parmesan, salt and oregano. Pour into a greased baking dish and top with the halved cherry tomatoes. Bake at 180C for 20 minutes until golden.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Pomodorini",qt:"100g"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Latte parzialmente scremato",qt:"50ml"},{nome:"Sale",qt:"q.b."},{nome:"Origano",qt:"q.b."}],_dbEntry:{n:"Frittata al forno con pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:19,gs:5,g:18,z:3,ch:6,fi:1,ca:150,fe:2,mg:30,k2:280,na:350,zn:1.6,fo:50,se:20,col:340}},{id:"tpl_1767",nome:"Budino di cocco e mango",nome_en:"Coconut and mango pudding",categoria:"Colazione",porzioni:2,note:"Mescolare i semi di chia con il latte di cocco in un contenitore con coperchio. Lasciare riposare in frigorifero per almeno 4 ore mescolando una volta. Servire guarnito con cubetti di mango fresco e un filo di miele.",note_en:"Mix the chia seeds with coconut milk in a container with a lid. Let rest in the fridge for at least 4 hours, stirring once. Serve topped with fresh mango cubes and a drizzle of honey.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte di cocco",qt:"250ml"},{nome:"Mango",qt:"100g"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Budino di cocco e mango (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:9,g:16,z:16,ch:24,fi:9,ca:120,fe:2.2,mg:80,k2:320,na:20,zn:1,fo:15,se:5,col:0}},{id:"tpl_1768",nome:"Muesli croccante al cioccolato",nome_en:"Crunchy chocolate muesli",categoria:"Colazione",porzioni:8,note:"Mescolare fiocchi d'avena, nocciole tritate, miele e olio in una ciotola. Distribuire su una teglia e cuocere a 160 gradi per 20 minuti mescolando a meta cottura. Lasciare raffreddare completamente prima di aggiungere le gocce di cioccolato.",note_en:"Mix oats, chopped hazelnuts, honey and oil in a bowl. Spread on a baking sheet and bake at 160C for 20 minutes, stirring halfway. Let cool completely before adding the chocolate chips.",ingredienti:[{nome:"Fiocchi d'avena",qt:"200g"},{nome:"Gocce di cioccolato fondente",qt:"50g"},{nome:"Nocciole",qt:"40g"},{nome:"Miele",qt:"60g"},{nome:"Olio di semi",qt:"30ml"}],_dbEntry:{n:"Muesli croccante al cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:8,gs:4,g:16,z:16,ch:40,fi:4,ca:50,fe:1.8,mg:60,k2:230,na:10,zn:1.2,fo:18,se:5,col:0}},{id:"tpl_1769",nome:"Torta margherita",nome_en:"Margherita sponge cake",categoria:"Colazione",porzioni:10,note:"Montare le uova con lo zucchero fino a renderle chiare e gonfie. Aggiungere il burro fuso intiepidito e incorporare delicatamente farina, fecola e lievito setacciati. Versare in uno stampo imburrato e cuocere a 170 gradi per 35 minuti.",note_en:"Beat the eggs with sugar until pale and airy. Add the melted, cooled butter and gently fold in the sifted flour, potato starch and baking powder. Pour into a greased pan and bake at 170C for 35 minutes.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Fecola di patate",qt:"50g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Burro",qt:"100g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta margherita (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:5,gs:6,g:12,z:17,ch:34,fi:.8,ca:30,fe:1,mg:12,k2:100,na:140,zn:.4,fo:15,se:9,col:85}},{id:"tpl_1770",nome:"Pane integrale con salmone e crema di formaggio",nome_en:"Whole wheat bread with salmon and cream cheese",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane integrale. Spalmare il formaggio cremoso e adagiare sopra le fette di salmone affumicato. Guarnire con erba cipollina tritata.",note_en:"Lightly toast the whole wheat bread slices. Spread the cream cheese and top with the smoked salmon slices. Garnish with chopped chives.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Salmone affumicato",qt:"50g"},{nome:"Formaggio spalmabile",qt:"30g"},{nome:"Erba cipollina",qt:"q.b."}],_dbEntry:{n:"Pane integrale con salmone e crema di formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:18,gs:5,g:16,z:3,ch:26,fi:4,ca:70,fe:1.8,mg:35,k2:320,na:580,zn:1.2,fo:40,se:20,col:35}},{id:"tpl_1771",nome:"Yogurt greco con frutta secca e cacao",nome_en:"Greek yogurt with nuts and cocoa",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt greco in una ciotola e spolverare con il cacao amaro mescolando leggermente. Aggiungere mandorle e noci sminuzzate. Completare con un filo di miele.",note_en:"Pour the Greek yogurt into a bowl and dust with cocoa powder, stirring lightly. Add chopped almonds and walnuts. Finish with a drizzle of honey.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Mandorle",qt:"15g"},{nome:"Noci",qt:"15g"},{nome:"Cacao amaro in polvere",qt:"1 cucchiaino"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Yogurt greco con frutta secca e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:17,gs:5,g:19,z:13,ch:16,fi:3,ca:200,fe:1.8,mg:60,k2:340,na:55,zn:1.3,fo:18,se:8,col:20}},{id:"tpl_1772",nome:"Uova strapazzate con funghi",nome_en:"Scrambled eggs with mushrooms",categoria:"Colazione",porzioni:1,note:"Pulire e affettare i funghi champignon e saltarli in padella con olio fino a farli asciugare. Aggiungere le uova sbattute con sale e cuocere mescolando fino a ottenere una consistenza cremosa. Completare con prezzemolo tritato.",note_en:"Clean and slice the mushrooms and saute them in a pan with oil until they release their moisture. Add the beaten eggs with salt and cook, stirring, until creamy. Finish with chopped parsley.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Funghi champignon",qt:"80g"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Uova strapazzate con funghi (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:17,gs:3.5,g:16,z:2,ch:5,fi:1.5,ca:50,fe:2,mg:25,k2:380,na:280,zn:1.5,fo:45,se:20,col:370}},{id:"tpl_1773",nome:"Smoothie bowl alla fragola",nome_en:"Strawberry smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare le fragole con la banana e lo yogurt fino a ottenere una crema liscia e densa. Versare nella ciotola e guarnire con il muesli. Servire subito ben freddo.",note_en:"Blend the strawberries with the banana and yogurt until smooth and thick. Pour into the bowl and top with muesli. Serve immediately, well chilled.",ingredienti:[{nome:"Fragole",qt:"200g"},{nome:"Banana",qt:"1"},{nome:"Yogurt bianco",qt:"80g"},{nome:"Muesli",qt:"20g"}],_dbEntry:{n:"Smoothie bowl alla fragola (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:8,gs:1.5,g:6,z:28,ch:46,fi:5,ca:140,fe:1.2,mg:45,k2:480,na:45,zn:.8,fo:40,se:5,col:5}},{id:"tpl_1774",nome:"Crepe salate con prosciutto e formaggio",nome_en:"Savory crepes with ham and cheese",categoria:"Colazione",porzioni:2,note:"Preparare la pastella con farina, latte e uovo fino a renderla liscia. Cuocere sottili crepe in padella antiaderente girandole a meta cottura. Farcire con prosciutto cotto e formaggio filante, piegare e scaldare brevemente fino a far sciogliere il formaggio.",note_en:"Prepare the batter with flour, milk and egg until smooth. Cook thin crepes in a nonstick pan, flipping halfway through. Fill with ham and melting cheese, fold and briefly heat until the cheese melts.",ingredienti:[{nome:"Farina 00",qt:"100g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Uova",qt:"1"},{nome:"Prosciutto cotto",qt:"80g"},{nome:"Formaggio filante",qt:"60g"}],_dbEntry:{n:"Crepe salate con prosciutto e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:20,gs:7,g:18,z:5,ch:34,fi:1.5,ca:220,fe:1.5,mg:30,k2:260,na:620,zn:1.8,fo:25,se:15,col:120}},{id:"tpl_1775",nome:"Pancake proteici all'uovo",nome_en:"Protein egg pancakes",categoria:"Colazione",porzioni:1,note:"Frullare uova, albume e fiocchi d'avena macinati fino a ottenere una pastella liscia. Aggiungere il lievito e mescolare rapidamente. Cuocere piccole porzioni in padella antiaderente fino a doratura su entrambi i lati.",note_en:"Blend the eggs, egg white and ground oats until smooth. Add the baking powder and mix quickly. Cook small portions in a nonstick pan until golden on both sides.",ingredienti:[{nome:"Uova",qt:"3"},{nome:"Fiocchi d'avena macinati",qt:"40g"},{nome:"Albume d'uovo",qt:"1"},{nome:"Lievito per dolci",qt:"mezzo cucchiaino"}],_dbEntry:{n:"Pancake proteici all'uovo (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:26,gs:4,g:16,z:2,ch:22,fi:3,ca:70,fe:2.5,mg:40,k2:280,na:220,zn:2,fo:50,se:28,col:480}},{id:"tpl_1776",nome:"Toast con marmellata di fichi",nome_en:"Toast with fig jam",categoria:"Colazione",porzioni:1,note:"Tostare le fette di pane casereccio. Spalmare la ricotta e completare con la marmellata di fichi. Servire subito.",note_en:"Toast the bread slices. Spread the ricotta and top with the fig jam. Serve right away.",ingredienti:[{nome:"Pane casereccio",qt:"2 fette"},{nome:"Marmellata di fichi",qt:"40g"},{nome:"Ricotta vaccina",qt:"40g"}],_dbEntry:{n:"Toast con marmellata di fichi (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:8,gs:3,g:7,z:22,ch:48,fi:2.5,ca:90,fe:1.3,mg:25,k2:150,na:160,zn:.7,fo:18,se:5,col:15}},{id:"tpl_1777",nome:"Porridge d'avena al cocco",nome_en:"Coconut oat porridge",categoria:"Colazione",porzioni:1,note:"Cuocere i fiocchi d'avena nel latte di cocco allungato con acqua a fuoco basso per 6-7 minuti mescolando. Versare in una ciotola e cospargere con il cocco rape. Completare con un filo di miele.",note_en:"Cook the oats in coconut milk diluted with water over low heat for 6-7 minutes, stirring. Pour into a bowl and sprinkle with shredded coconut. Finish with a drizzle of honey.",ingredienti:[{nome:"Fiocchi d'avena",qt:"50g"},{nome:"Latte di cocco",qt:"150ml"},{nome:"Acqua",qt:"50ml"},{nome:"Cocco rape",qt:"10g"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Porridge d'avena al cocco (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:7,gs:8,g:16,z:16,ch:46,fi:6,ca:80,fe:2.2,mg:60,k2:280,na:25,zn:1.3,fo:20,se:5,col:0}},{id:"tpl_1778",nome:"Budino di chia al mango",nome_en:"Mango chia pudding",categoria:"Colazione",porzioni:1,note:"Mescolare i semi di chia con il latte e lasciare riposare in frigorifero per almeno 4 ore fino ad addensare. Frullare il mango fino a ottenere una purea e versarla sopra il budino. Dolcificare con un cucchiaino di miele.",note_en:"Mix the chia seeds with milk and let rest in the fridge for at least 4 hours until thickened. Blend the mango into a puree and pour it over the pudding. Sweeten with a teaspoon of honey.",ingredienti:[{nome:"Semi di chia",qt:"30g"},{nome:"Latte parzialmente scremato",qt:"180ml"},{nome:"Mango",qt:"80g"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Budino di chia al mango (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:2.5,g:10,z:18,ch:32,fi:8,ca:220,fe:2,mg:80,k2:350,na:55,zn:1,fo:18,se:6,col:10}},{id:"tpl_1779",nome:"Torta di carote",nome_en:"Carrot cake",categoria:"Colazione",porzioni:10,note:"Grattugiare finemente le carote. Sbattere uova, zucchero e olio, aggiungere le carote e le noci tritate, poi incorporare farina, lievito e cannella. Versare in uno stampo e cuocere a 180 gradi per 45 minuti.",note_en:"Finely grate the carrots. Beat eggs, sugar and oil, add the carrots and chopped walnuts, then fold in flour, baking powder and cinnamon. Pour into a pan and bake at 180C for 45 minutes.",ingredienti:[{nome:"Carote",qt:"250g"},{nome:"Farina 00",qt:"250g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"100ml"},{nome:"Noci",qt:"50g"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Cannella in polvere",qt:"1 cucchiaino"}],_dbEntry:{n:"Torta di carote (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:5,gs:2,g:14,z:18,ch:35,fi:2,ca:35,fe:1.3,mg:22,k2:170,na:130,zn:.6,fo:20,se:9,col:45}},{id:"tpl_1780",nome:"Muffin dolci ai mirtilli",nome_en:"Blueberry muffins",categoria:"Colazione",porzioni:8,note:"Lavorare il burro morbido con lo zucchero e le uova fino a ottenere una crema. Incorporare farina, lievito e latte, poi aggiungere delicatamente i mirtilli infarinati. Versare negli stampini e cuocere a 180 gradi per 20-22 minuti.",note_en:"Cream the softened butter with sugar and eggs until fluffy. Fold in flour, baking powder and milk, then gently add the floured blueberries. Pour into muffin tins and bake at 180C for 20-22 minutes.",ingredienti:[{nome:"Farina 00",qt:"200g"},{nome:"Mirtilli freschi",qt:"100g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Burro",qt:"80g"},{nome:"Latte parzialmente scremato",qt:"60ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Muffin dolci ai mirtilli (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:4.5,gs:5.5,g:11,z:16,ch:35,fi:1.5,ca:40,fe:1.1,mg:16,k2:100,na:160,zn:.5,fo:16,se:9,col:65}},{id:"tpl_1781",nome:"Yogurt con granola e miele",nome_en:"Yogurt with granola and honey",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt greco in una ciotola. Distribuire la granola sopra in modo uniforme. Completare con un filo di miele.",note_en:"Pour the Greek yogurt into a bowl. Scatter the granola evenly on top. Finish with a drizzle of honey.",ingredienti:[{nome:"Yogurt greco",qt:"150g"},{nome:"Granola",qt:"40g"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Yogurt con granola e miele (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:16,gs:3.5,g:13,z:20,ch:40,fi:3.5,ca:200,fe:1.6,mg:50,k2:320,na:60,zn:1.1,fo:20,se:6,col:15}},{id:"tpl_1782",nome:"Uova in camicia su spinaci",nome_en:"Poached eggs on spinach",categoria:"Colazione",porzioni:1,note:"Saltare gli spinaci in padella con un filo di olio fino ad appassirli, salare leggermente. Cuocere le uova in camicia in acqua bollente con aceto per 3 minuti. Adagiare le uova sul letto di spinaci e servire caldo.",note_en:"Saute the spinach in a pan with a drizzle of oil until wilted, season lightly with salt. Poach the eggs in boiling water with vinegar for 3 minutes. Place the eggs on the bed of spinach and serve warm.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Spinaci freschi",qt:"100g"},{nome:"Aceto di mele",qt:"1 cucchiaio"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Uova in camicia su spinaci (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:16,gs:3,g:16,z:1,ch:5,fi:3,ca:100,fe:3,mg:50,k2:450,na:220,zn:1.5,fo:120,se:20,col:370}},{id:"tpl_1783",nome:"Smoothie bowl tropicale (versione 2)",nome_en:"Tropical smoothie bowl (version 2)",categoria:"Colazione",porzioni:1,note:"Frullare ananas, mango e banana con il latte di cocco fino a ottenere una crema densa. Versare nella ciotola e guarnire con il cocco rape. Servire subito ben freddo.",note_en:"Blend pineapple, mango and banana with the coconut milk until thick and creamy. Pour into the bowl and top with shredded coconut. Serve immediately, well chilled.",ingredienti:[{nome:"Ananas",qt:"100g"},{nome:"Mango",qt:"80g"},{nome:"Banana",qt:"1"},{nome:"Latte di cocco",qt:"60ml"},{nome:"Cocco rape",qt:"10g"}],_dbEntry:{n:"Smoothie bowl tropicale (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:4,gs:5,g:9,z:34,ch:54,fi:6,ca:50,fe:1,mg:50,k2:540,na:25,zn:.7,fo:45,se:4,col:0}},{id:"tpl_1784",nome:"Pane con crema di nocciole e cacao e banana",nome_en:"Bread with cocoa-hazelnut spread and banana",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane. Spalmare la crema al cacao e nocciole e completare con le fettine di banana. Servire subito.",note_en:"Lightly toast the bread slices. Spread the cocoa-hazelnut cream and top with banana slices. Serve right away.",ingredienti:[{nome:"Pane casereccio",qt:"2 fette"},{nome:"Crema spalmabile al cacao e nocciole",qt:"30g"},{nome:"Banana",qt:"1"}],_dbEntry:{n:"Pane con crema di nocciole e cacao e banana (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:8,gs:5,g:14,z:28,ch:58,fi:4,ca:70,fe:1.6,mg:50,k2:420,na:220,zn:.9,fo:30,se:6,col:5}},{id:"tpl_1785",nome:"Frittata di patate",nome_en:"Potato frittata",categoria:"Colazione",porzioni:2,note:"Lessare o cuocere in padella le patate tagliate a fettine sottili fino a renderle morbide. Sbattere le uova con parmigiano e sale, unire le patate e versare in padella con olio. Cuocere a fuoco basso girando la frittata a meta cottura.",note_en:"Boil or pan-cook the thinly sliced potatoes until soft. Beat the eggs with parmesan and salt, add the potatoes and pour into a pan with oil. Cook over low heat, flipping the frittata halfway through.",ingredienti:[{nome:"Patate",qt:"200g"},{nome:"Uova",qt:"4"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaio"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Frittata di patate (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:16,gs:4,g:16,z:2,ch:22,fi:2,ca:120,fe:1.8,mg:30,k2:450,na:280,zn:1.5,fo:35,se:18,col:330}},{id:"tpl_1786",nome:"Ricotta con frutti di bosco",nome_en:"Ricotta with mixed berries",categoria:"Colazione",porzioni:1,note:"Disporre la ricotta in una ciotola lavorandola leggermente con una forchetta. Distribuire sopra i frutti di bosco freschi. Completare con un filo di miele.",note_en:"Place the ricotta in a bowl, working it lightly with a fork. Top with the fresh mixed berries. Finish with a drizzle of honey.",ingredienti:[{nome:"Ricotta vaccina",qt:"150g"},{nome:"Frutti di bosco misti",qt:"80g"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Ricotta con frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:12,gs:5,g:14,z:14,ch:16,fi:3,ca:200,fe:1,mg:30,k2:220,na:80,zn:1,fo:20,se:7,col:40}},{id:"tpl_1787",nome:"Pancakes ai fiocchi d'avena",nome_en:"Oat flake pancakes",categoria:"Colazione",porzioni:2,note:"Frullare i fiocchi d'avena fino a ridurli in farina grossolana. Mescolare con uova, latte e lievito fino a ottenere una pastella omogenea. Cuocere piccole porzioni in padella antiaderente e servire con un filo di miele.",note_en:"Blend the oats into a coarse flour. Mix with eggs, milk and baking powder until smooth. Cook small portions in a nonstick pan and serve with a drizzle of honey.",ingredienti:[{nome:"Fiocchi d'avena",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"100ml"},{nome:"Lievito per dolci",qt:"mezza bustina"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Pancakes ai fiocchi d'avena (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:14,gs:2.5,g:9,z:12,ch:42,fi:4,ca:100,fe:2,mg:45,k2:280,na:170,zn:1.3,fo:30,se:15,col:150}},{id:"tpl_1788",nome:"Toast con crema di mandorle",nome_en:"Toast with almond butter",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane integrale. Spalmare la crema di mandorle su ciascuna fetta. Completare con un filo di miele.",note_en:"Lightly toast the whole wheat bread slices. Spread the almond butter on each slice. Finish with a drizzle of honey.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Crema di mandorle",qt:"30g"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Toast con crema di mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:11,gs:2.5,g:18,z:14,ch:36,fi:5,ca:100,fe:2,mg:80,k2:320,na:220,zn:1.3,fo:30,se:6,col:0}},{id:"tpl_1789",nome:"Cappuccino con biscotti secchi",nome_en:"Cappuccino with plain biscuits",categoria:"Colazione",porzioni:1,note:"Preparare un espresso e montare il latte caldo fino a renderlo ben schiumoso. Versare il latte montato sul caffe. Accompagnare con i biscotti secchi da inzuppare.",note_en:"Brew an espresso and froth the hot milk until well foamed. Pour the frothed milk over the coffee. Serve with plain biscuits for dipping.",ingredienti:[{nome:"Latte intero",qt:"150ml"},{nome:"Caffe espresso",qt:"1"},{nome:"Biscotti secchi",qt:"4"}],_dbEntry:{n:"Cappuccino con biscotti secchi (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:8,gs:5,g:11,z:18,ch:40,fi:1,ca:180,fe:1.2,mg:25,k2:250,na:180,zn:.8,fo:20,se:6,col:30}},{id:"tpl_1790",nome:"Budino di semi di lino e cacao",nome_en:"Flaxseed and cocoa pudding",categoria:"Colazione",porzioni:1,note:"Mescolare i semi di lino macinati con il latte e il cacao amaro in un barattolo. Lasciare riposare in frigorifero per almeno 3 ore fino ad addensare. Dolcificare con miele prima di servire.",note_en:"Mix the ground flax seeds with milk and cocoa powder in a jar. Let rest in the fridge for at least 3 hours until thickened. Sweeten with honey before serving.",ingredienti:[{nome:"Semi di lino macinati",qt:"30g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Cacao amaro in polvere",qt:"1 cucchiaio"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Budino di semi di lino e cacao (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:10,gs:2.5,g:11,z:12,ch:22,fi:7,ca:220,fe:2.3,mg:90,k2:380,na:65,zn:1.3,fo:20,se:6,col:10}},{id:"tpl_1791",nome:"Porridge di miglio",nome_en:"Millet porridge",categoria:"Colazione",porzioni:1,note:"Sciacquare il miglio e cuocerlo nel latte a fuoco basso per 15-18 minuti mescolando spesso fino a renderlo cremoso. Versare in una ciotola e aggiungere l'uvetta. Completare con un filo di miele.",note_en:"Rinse the millet and cook it in the milk over low heat for 15-18 minutes, stirring often, until creamy. Pour into a bowl and add the raisins. Finish with a drizzle of honey.",ingredienti:[{nome:"Miglio decorticato",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Uvetta",qt:"15g"}],_dbEntry:{n:"Porridge di miglio (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:11,gs:2,g:6,z:18,ch:58,fi:3,ca:190,fe:2,mg:50,k2:320,na:70,zn:1.3,fo:20,se:6,col:10}},{id:"tpl_1792",nome:"Torta paradiso",nome_en:"Paradise cake",categoria:"Colazione",porzioni:10,note:"Montare il burro morbido con lo zucchero fino a renderlo spumoso. Aggiungere le uova una alla volta continuando a montare, poi incorporare farina, fecola, lievito e vaniglia setacciati. Versare in uno stampo imburrato e cuocere a 170 gradi per 40 minuti.",note_en:"Beat the softened butter with sugar until fluffy. Add the eggs one at a time while beating, then fold in the sifted flour, potato starch, baking powder and vanilla. Pour into a greased pan and bake at 170C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"150g"},{nome:"Fecola di patate",qt:"100g"},{nome:"Zucchero",qt:"150g"},{nome:"Burro",qt:"150g"},{nome:"Uova",qt:"4"},{nome:"Lievito per dolci",qt:"1 bustina"},{nome:"Vaniglia",qt:"1 bustina"}],_dbEntry:{n:"Torta paradiso (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:4,gs:8,g:15,z:18,ch:35,fi:.6,ca:25,fe:.9,mg:10,k2:90,na:140,zn:.4,fo:14,se:9,col:95}},{id:"tpl_1793",nome:"Muesli con yogurt e mela grattugiata",nome_en:"Muesli with yogurt and grated apple",categoria:"Colazione",porzioni:1,note:"Grattugiare la mela con la buccia direttamente sopra lo yogurt. Aggiungere il muesli e mescolare delicatamente. Servire subito per mantenere la croccantezza.",note_en:"Grate the apple, peel included, directly over the yogurt. Add the muesli and stir gently. Serve immediately to keep the crunch.",ingredienti:[{nome:"Muesli",qt:"40g"},{nome:"Yogurt bianco",qt:"150g"},{nome:"Mela",qt:"1"}],_dbEntry:{n:"Muesli con yogurt e mela grattugiata (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:10,gs:3,g:8,z:24,ch:52,fi:5,ca:180,fe:1.6,mg:50,k2:380,na:55,zn:1,fo:25,se:6,col:10}},{id:"tpl_1794",nome:"Uova sode con toast e verdure",nome_en:"Hard-boiled eggs with toast and vegetables",categoria:"Colazione",porzioni:1,note:"Cuocere le uova in acqua bollente per 9 minuti per ottenere uova sode. Tostare il pane e servire con pomodoro a fette e insalata condita con un filo di olio. Sgusciare le uova, tagliarle a meta e servirle a fianco.",note_en:"Cook the eggs in boiling water for 9 minutes for hard-boiled eggs. Toast the bread and serve with sliced tomato and lettuce dressed with a drizzle of oil. Shell the eggs, halve them and serve alongside.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Pane integrale",qt:"2 fette"},{nome:"Pomodori",qt:"1"},{nome:"Insalata verde",qt:"30g"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"}],_dbEntry:{n:"Uova sode con toast e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:18,gs:4,g:16,z:4,ch:28,fi:5,ca:70,fe:2.5,mg:35,k2:400,na:320,zn:1.6,fo:60,se:22,col:370}},{id:"tpl_1795",nome:"Smoothie bowl ai frutti tropicali con granola",nome_en:"Tropical fruit smoothie bowl with granola",categoria:"Colazione",porzioni:1,note:"Frullare ananas e mango con lo yogurt greco fino a ottenere una crema liscia. Versare nella ciotola e guarnire con la granola croccante. Servire subito.",note_en:"Blend pineapple and mango with the Greek yogurt until smooth. Pour into the bowl and top with crunchy granola. Serve immediately.",ingredienti:[{nome:"Ananas",qt:"100g"},{nome:"Mango",qt:"80g"},{nome:"Yogurt greco",qt:"60g"},{nome:"Granola",qt:"25g"}],_dbEntry:{n:"Smoothie bowl ai frutti tropicali con granola (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:11,gs:2.5,g:10,z:28,ch:50,fi:5,ca:140,fe:1.5,mg:55,k2:480,na:45,zn:1,fo:40,se:5,col:8}},{id:"tpl_1796",nome:"Pane tostato con avocado e feta",nome_en:"Toast with avocado and feta",categoria:"Colazione",porzioni:1,note:"Tostare le fette di pane integrale. Schiacciare la polpa di avocado con succo di limone e spalmarla sul pane. Sbriciolare sopra la feta e completare con i semi di sesamo.",note_en:"Toast the whole wheat bread slices. Mash the avocado with lemon juice and spread it on the bread. Crumble the feta on top and finish with sesame seeds.",ingredienti:[{nome:"Pane integrale",qt:"2 fette"},{nome:"Avocado",qt:"mezzo"},{nome:"Feta",qt:"30g"},{nome:"Semi di sesamo",qt:"1 cucchiaino"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Pane tostato con avocado e feta (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:12,gs:6,g:20,z:3,ch:28,fi:7,ca:150,fe:2,mg:55,k2:500,na:420,zn:1.4,fo:55,se:10,col:25}},{id:"tpl_1797",nome:"Frittata di albumi con spinaci (versione 2)",nome_en:"Egg white frittata with spinach (version 2)",categoria:"Colazione",porzioni:1,note:"Saltare brevemente gli spinaci in padella con un filo di olio fino ad appassirli. Aggiungere gli albumi sbattuti con parmigiano e sale e cuocere a fuoco basso fino a rassodare. Piegare a meta e servire calda.",note_en:"Briefly saute the spinach in a pan with a drizzle of oil until wilted. Add the beaten egg whites with parmesan and salt and cook over low heat until set. Fold in half and serve warm.",ingredienti:[{nome:"Albumi d'uovo",qt:"5"},{nome:"Spinaci freschi",qt:"80g"},{nome:"Parmigiano grattugiato",qt:"15g"},{nome:"Sale",qt:"q.b."},{nome:"Olio extravergine di oliva",qt:"1 cucchiaino"}],_dbEntry:{n:"Frittata di albumi con spinaci (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:24,gs:1.5,g:6,z:1,ch:5,fi:2,ca:150,fe:1.8,mg:40,k2:400,na:350,zn:1.2,fo:80,se:18,col:10}},{id:"tpl_1798",nome:"Ciambelle allo yogurt e limone",nome_en:"Yogurt and lemon donuts",categoria:"Colazione",porzioni:8,note:"Mescolare uova, zucchero, yogurt, olio e scorza di limone fino a ottenere un composto omogeneo. Incorporare farina e lievito setacciati. Formare piccole ciambelle e cuocere a 180 gradi per 15-18 minuti.",note_en:"Mix eggs, sugar, yogurt, oil and lemon zest until smooth. Fold in the sifted flour and baking powder. Shape into small rings and bake at 180C for 15-18 minutes.",ingredienti:[{nome:"Farina 00",qt:"250g"},{nome:"Yogurt bianco",qt:"125g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Scorza di limone",qt:"1"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Ciambelle allo yogurt e limone (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:5,gs:2,g:8,z:16,ch:36,fi:1,ca:50,fe:1,mg:15,k2:110,na:140,zn:.5,fo:18,se:8,col:55}},{id:"tpl_1799",nome:"Budino di chia alla vaniglia",nome_en:"Vanilla chia pudding",categoria:"Colazione",porzioni:1,note:"Mescolare i semi di chia con il latte e la vaniglia in un barattolo. Lasciare riposare in frigorifero per almeno 4 ore fino ad addensare. Dolcificare con miele prima di servire.",note_en:"Mix the chia seeds with milk and vanilla in a jar. Let rest in the fridge for at least 4 hours until thickened. Sweeten with honey before serving.",ingredienti:[{nome:"Semi di chia",qt:"30g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Vaniglia",qt:"1 cucchiaino"},{nome:"Miele",qt:"1 cucchiaio"}],_dbEntry:{n:"Budino di chia alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:9,gs:3,g:11,z:16,ch:26,fi:9,ca:280,fe:2.4,mg:90,k2:380,na:70,zn:1.3,fo:18,se:6,col:10}},{id:"tpl_1800",nome:"Torta allo yogurt e cioccolato",nome_en:"Yogurt and chocolate cake",categoria:"Colazione",porzioni:10,note:"Sbattere uova e zucchero fino a renderli spumosi, poi unire yogurt e olio. Incorporare farina, cacao e lievito setacciati insieme, infine le gocce di cioccolato. Versare in uno stampo e cuocere a 180 gradi per 40 minuti.",note_en:"Beat the eggs with sugar until fluffy, then add yogurt and oil. Fold in the flour, cocoa and baking powder sifted together, then the chocolate chips. Pour into a pan and bake at 180C for 40 minutes.",ingredienti:[{nome:"Farina 00",qt:"220g"},{nome:"Yogurt bianco",qt:"125g"},{nome:"Zucchero",qt:"150g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Cacao amaro in polvere",qt:"30g"},{nome:"Gocce di cioccolato fondente",qt:"60g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta allo yogurt e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:6,gs:4,g:13,z:20,ch:40,fi:2.5,ca:55,fe:1.8,mg:30,k2:160,na:140,zn:.7,fo:18,se:10,col:65}},{id:"tpl_1801",nome:"Pancakes integrali con frutti di bosco (versione 2)",nome_en:"Whole wheat pancakes with mixed berries (version 2)",categoria:"Colazione",porzioni:2,note:"Preparare la pastella con farina integrale, uova, latte e lievito fino a renderla omogenea. Cuocere piccole porzioni in padella antiaderente fino a doratura. Servire i pancakes guarniti con i frutti di bosco freschi.",note_en:"Prepare the batter with whole wheat flour, eggs, milk and baking powder until smooth. Cook small portions in a nonstick pan until golden. Serve the pancakes topped with fresh mixed berries.",ingredienti:[{nome:"Farina integrale",qt:"120g"},{nome:"Uova",qt:"2"},{nome:"Latte parzialmente scremato",qt:"120ml"},{nome:"Lievito per dolci",qt:"mezza bustina"},{nome:"Frutti di bosco misti",qt:"80g"}],_dbEntry:{n:"Pancakes integrali con frutti di bosco (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:2.5,g:8,z:10,ch:44,fi:5,ca:110,fe:2,mg:40,k2:280,na:170,zn:1.3,fo:30,se:14,col:150}},{id:"tpl_1802",nome:"Yogurt bianco con miele e mandorle",nome_en:"Plain yogurt with honey and almonds",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt bianco in una ciotola. Tritare grossolanamente le mandorle e distribuirle sopra. Completare con un filo di miele.",note_en:"Pour the plain yogurt into a bowl. Coarsely chop the almonds and scatter over. Finish with a drizzle of honey.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Mandorle",qt:"20g"}],_dbEntry:{n:"Yogurt bianco con miele e mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:9,gs:3,g:11,z:18,ch:24,fi:2,ca:180,fe:1,mg:50,k2:280,na:55,zn:.8,fo:15,se:6,col:15}},{id:"tpl_1803",nome:"Toast con ricotta e miele (versione 3)",nome_en:"Toast with ricotta and honey (version 3)",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane casereccio. Spalmare la ricotta e completare con miele e noci sminuzzate. Servire subito.",note_en:"Toast the bread slices lightly. Spread the ricotta and top with honey and chopped walnuts. Serve right away.",ingredienti:[{nome:"Pane casereccio",qt:"2 fette"},{nome:"Ricotta vaccina",qt:"80g"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Noci",qt:"10g"}],_dbEntry:{n:"Toast con ricotta e miele (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:12,gs:4.5,g:13,z:18,ch:40,fi:1.5,ca:130,fe:1.3,mg:30,k2:200,na:170,zn:.9,fo:20,se:7,col:30}},{id:"tpl_1804",nome:"Uova strapazzate con salmone affumicato",nome_en:"Scrambled eggs with smoked salmon",categoria:"Colazione",porzioni:1,note:"Sbattere le uova e cuocerle in padella con il burro a fuoco basso mescolando fino a renderle cremose. Unire il salmone affumicato a listarelle a fine cottura. Guarnire con erba cipollina tritata.",note_en:"Beat the eggs and cook them in a pan with butter over low heat, stirring until creamy. Add the smoked salmon in strips at the end of cooking. Garnish with chopped chives.",ingredienti:[{nome:"Uova",qt:"2"},{nome:"Salmone affumicato",qt:"40g"},{nome:"Erba cipollina",qt:"q.b."},{nome:"Burro",qt:"5g"}],_dbEntry:{n:"Uova strapazzate con salmone affumicato (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:22,gs:5.5,g:20,z:1,ch:3,fi:.3,ca:60,fe:2,mg:25,k2:280,na:480,zn:1.5,fo:45,se:28,col:390}},{id:"tpl_1805",nome:"Smoothie bowl all'ananas",nome_en:"Pineapple smoothie bowl",categoria:"Colazione",porzioni:1,note:"Frullare l'ananas con la banana e lo yogurt fino a ottenere una crema liscia e densa. Versare nella ciotola e guarnire con il cocco rape. Servire subito ben freddo.",note_en:"Blend the pineapple with the banana and yogurt until smooth and thick. Pour into the bowl and top with shredded coconut. Serve immediately, well chilled.",ingredienti:[{nome:"Ananas",qt:"200g"},{nome:"Banana",qt:"1"},{nome:"Yogurt bianco",qt:"60g"},{nome:"Cocco rape",qt:"10g"}],_dbEntry:{n:"Smoothie bowl all'ananas (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:2,g:6,z:34,ch:52,fi:4.5,ca:70,fe:1,mg:45,k2:450,na:30,zn:.6,fo:35,se:4,col:5}},{id:"tpl_1806",nome:"Porridge d'avena con banana e cioccolato",nome_en:"Oat porridge with banana and chocolate",categoria:"Colazione",porzioni:1,note:"Cuocere i fiocchi d'avena nel latte a fuoco basso per 5-6 minuti mescolando spesso. Versare in una ciotola e guarnire con la banana a fettine. Completare con le gocce di cioccolato fondente.",note_en:"Cook the oats in milk over low heat for 5-6 minutes, stirring often. Pour into a bowl and top with sliced banana. Finish with dark chocolate chips.",ingredienti:[{nome:"Fiocchi d'avena",qt:"50g"},{nome:"Latte parzialmente scremato",qt:"200ml"},{nome:"Banana",qt:"1"},{nome:"Gocce di cioccolato fondente",qt:"15g"}],_dbEntry:{n:"Porridge d'avena con banana e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:13,gs:4,g:11,z:24,ch:62,fi:6,ca:220,fe:2.3,mg:80,k2:450,na:85,zn:1.7,fo:35,se:8,col:10}},{id:"tpl_1807",nome:"Crostatine integrali alla marmellata",nome_en:"Whole wheat jam tartlets",categoria:"Colazione",porzioni:8,note:"Impastare farina integrale, burro freddo, zucchero, uovo e lievito fino a ottenere una frolla compatta. Stendere l'impasto, foderare piccoli stampini e farcire con la marmellata. Cuocere a 180 gradi per 18-20 minuti fino a doratura.",note_en:"Knead whole wheat flour, cold butter, sugar, egg and baking powder into a firm shortcrust dough. Roll out the dough, line small tart pans and fill with jam. Bake at 180C for 18-20 minutes until golden.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Burro",qt:"100g"},{nome:"Zucchero",qt:"80g"},{nome:"Uovo",qt:"1"},{nome:"Marmellata di albicocche",qt:"150g"},{nome:"Lievito per dolci",qt:"mezza bustina"}],_dbEntry:{n:"Crostatine integrali alla marmellata (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:4,gs:6,g:11,z:18,ch:36,fi:2.5,ca:25,fe:1.2,mg:18,k2:110,na:100,zn:.5,fo:15,se:7,col:45}},{id:"tpl_1808",nome:"Budino di riso al cioccolato",nome_en:"Chocolate rice pudding",categoria:"Colazione",porzioni:2,note:"Cuocere il riso nel latte a fuoco basso per circa 25 minuti mescolando spesso fino ad addensare. Aggiungere cacao amaro e zucchero mescolando fino a scioglierli completamente. Versare in coppette e lasciare raffreddare prima di servire.",note_en:"Cook the rice in milk over low heat for about 25 minutes, stirring often, until thickened. Add cocoa powder and sugar, stirring until fully dissolved. Pour into cups and let cool before serving.",ingredienti:[{nome:"Riso originario",qt:"60g"},{nome:"Latte parzialmente scremato",qt:"350ml"},{nome:"Cacao amaro in polvere",qt:"20g"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Budino di riso al cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:8,gs:3,g:6,z:18,ch:48,fi:2.5,ca:190,fe:1.5,mg:35,k2:280,na:65,zn:1,fo:12,se:6,col:12}},{id:"tpl_1809",nome:"Muesli con yogurt e frutta secca mista",nome_en:"Muesli with yogurt and mixed nuts",categoria:"Colazione",porzioni:1,note:"Versare lo yogurt in una ciotola e aggiungere il muesli mescolando delicatamente. Completare con mandorle, noci e uvetta sparse in superficie. Servire subito.",note_en:"Pour the yogurt into a bowl and add the muesli, stirring gently. Top with almonds, walnuts and raisins scattered on top. Serve immediately.",ingredienti:[{nome:"Muesli",qt:"40g"},{nome:"Yogurt bianco",qt:"150g"},{nome:"Mandorle",qt:"10g"},{nome:"Noci",qt:"10g"},{nome:"Uvetta",qt:"10g"}],_dbEntry:{n:"Muesli con yogurt e frutta secca mista (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:12,gs:3.5,g:13,z:22,ch:48,fi:4,ca:190,fe:1.8,mg:60,k2:400,na:60,zn:1.2,fo:25,se:7,col:10}},{id:"tpl_1810",nome:"Bruschetta mattutina con pomodoro e olio",nome_en:"Morning bruschetta with tomato and oil",categoria:"Colazione",porzioni:1,note:"Tostare leggermente le fette di pane casereccio e strofinarle con aglio. Tagliare i pomodori a cubetti e condirli con olio, sale e basilico spezzettato. Distribuire il composto di pomodoro sulle fette di pane.",note_en:"Lightly toast the bread slices and rub with the garlic clove. Dice the tomatoes and season with oil, salt and torn basil. Spread the tomato mixture over the bread slices.",ingredienti:[{nome:"Pane casereccio",qt:"2 fette"},{nome:"Pomodori maturi",qt:"2"},{nome:"Aglio",qt:"mezzo spicchio"},{nome:"Olio extravergine di oliva",qt:"1 cucchiaio"},{nome:"Sale",qt:"q.b."},{nome:"Basilico",qt:"q.b."}],_dbEntry:{n:"Bruschetta mattutina con pomodoro e olio (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:6,gs:2,g:11,z:5,ch:34,fi:3,ca:30,fe:1.5,mg:25,k2:280,na:320,zn:.7,fo:25,se:4,col:0}},{id:"tpl_1811",nome:"Insalata di pollo grigliato con avocado e pomodorini",nome_en:"Grilled chicken salad with avocado and cherry tomatoes",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e tagliarlo a fette. Comporre l'insalata con lattuga, pomodorini tagliati a metà e avocado a fette. Condire con olio, limone, sale e pepe.",note_en:"Grill the chicken breast and slice it. Assemble the salad with lettuce, halved cherry tomatoes and sliced avocado. Dress with oil, lemon, salt and pepper.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Pomodorini",qt:"150g"},{nome:"Lattuga",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo grigliato con avocado e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:28,gs:4,g:20,z:4,ch:9,fi:5,ca:40,fe:1.8,mg:45,k2:650,na:220,zn:1.5,fo:60,se:20,col:70}},{id:"tpl_1812",nome:"Insalata caprese classica",nome_en:"Classic caprese salad",categoria:"Insalata",porzioni:2,note:"Affettare pomodori e mozzarella di bufala allo stesso spessore. Alternarli su un piatto con foglie di basilico fresco. Condire con olio extravergine, sale e origano.",note_en:"Slice tomatoes and buffalo mozzarella to the same thickness. Alternate them on a plate with fresh basil leaves. Dress with extra virgin oil, salt and oregano.",ingredienti:[{nome:"Pomodori",qt:"300g"},{nome:"Mozzarella di bufala",qt:"250g"},{nome:"Basilico fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Origano",qt:"q.b."}],_dbEntry:{n:"Insalata caprese classica (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:16,gs:9,g:22,z:5,ch:6,fi:2,ca:350,fe:.8,mg:25,k2:300,na:280,zn:1.6,fo:25,se:8,col:45}},{id:"tpl_1813",nome:"Insalata di farro e verdure grigliate (versione 2)",nome_en:"Farro salad with grilled vegetables (version 2)",categoria:"Insalata",porzioni:4,note:"Lessare il farro in acqua salata e scolarlo. Grigliare zucchine, melanzane e peperoni a fette. Unire farro e verdure, condire con olio, aceto balsamico e prezzemolo.",note_en:"Boil farro in salted water and drain. Grill sliced zucchini, eggplant and peppers. Combine farro and vegetables, dress with oil, balsamic vinegar and parsley.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Olio extravergine",qt:"3 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di farro e verdure grigliate (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:8,gs:1,g:9,z:5,ch:42,fi:6,ca:35,fe:2,mg:50,k2:400,na:150,zn:1.4,fo:35,se:10,col:0}},{id:"tpl_1814",nome:"Insalata di tonno e fagioli cannellini",nome_en:"Tuna and cannellini bean salad",categoria:"Insalata",porzioni:2,note:"Scolare i fagioli cannellini e il tonno. Unire con cipolla rossa tagliata sottile e prezzemolo tritato. Condire con olio extravergine, sale e pepe.",note_en:"Drain the cannellini beans and tuna. Combine with thinly sliced red onion and chopped parsley. Dress with extra virgin oil, salt and pepper.",ingredienti:[{nome:"Fagioli cannellini lessati",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Cipolla rossa",qt:"1/2"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di tonno e fagioli cannellini (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:26,gs:2.5,g:16,z:2,ch:28,fi:8,ca:70,fe:3,mg:60,k2:550,na:400,zn:1.8,fo:100,se:35,col:30}},{id:"tpl_1815",nome:"Insalata di quinoa e ceci al limone",nome_en:"Quinoa and chickpea salad with lemon",categoria:"Insalata",porzioni:4,note:"Cuocere la quinoa in acqua salata e lasciarla raffreddare. Unire i ceci lessati, cetrioli a cubetti e menta fresca. Condire con succo di limone e olio extravergine.",note_en:"Cook the quinoa in salted water and let it cool. Add boiled chickpeas, diced cucumber and fresh mint. Dress with lemon juice and extra virgin oil.",ingredienti:[{nome:"Quinoa",qt:"200g"},{nome:"Ceci lessati",qt:"200g"},{nome:"Cetrioli",qt:"150g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di quinoa e ceci al limone (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:9,gs:1,g:8,z:3,ch:38,fi:7,ca:45,fe:2.5,mg:65,k2:380,na:120,zn:1.5,fo:80,se:6,col:0}},{id:"tpl_1816",nome:"Insalata mista con feta e noci",nome_en:"Mixed salad with feta and walnuts",categoria:"Insalata",porzioni:2,note:"Lavare insalata mista e disporla in una ciotola. Aggiungere feta a cubetti, gherigli di noci e uvetta. Condire con olio extravergine e un filo di miele.",note_en:"Wash mixed salad leaves and arrange in a bowl. Add cubed feta, walnut kernels and raisins. Dress with extra virgin oil and a drizzle of honey.",ingredienti:[{nome:"Insalata mista",qt:"150g"},{nome:"Feta",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Uvetta",qt:"20g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Miele",qt:"1 cucchiaino"}],_dbEntry:{n:"Insalata mista con feta e noci (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:8,g:26,z:10,ch:14,fi:3,ca:220,fe:1.5,mg:50,k2:280,na:400,zn:1.6,fo:30,se:10,col:35}},{id:"tpl_1817",nome:"Panzanella toscana (versione 2)",nome_en:"Tuscan panzanella (version 2)",categoria:"Insalata",porzioni:4,note:"Ammollare il pane raffermo in acqua e strizzarlo. Sbriciolarlo in una ciotola con pomodori, cetrioli e cipolla rossa a fette. Condire con olio, aceto, sale e basilico.",note_en:"Soak stale bread in water and squeeze it out. Crumble it into a bowl with tomatoes, cucumbers and sliced red onion. Dress with oil, vinegar, salt and basil.",ingredienti:[{nome:"Pane raffermo",qt:"200g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Cetrioli",qt:"150g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Basilico",qt:"q.b."},{nome:"Olio extravergine",qt:"3 cucchiai"},{nome:"Aceto di vino",qt:"1 cucchiaio"}],_dbEntry:{n:"Panzanella toscana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:6,gs:1.5,g:11,z:6,ch:38,fi:4,ca:40,fe:2,mg:30,k2:350,na:300,zn:1,fo:25,se:8,col:0}},{id:"tpl_1818",nome:"Insalata russa alleggerita",nome_en:"Lightened Russian salad",categoria:"Insalata",porzioni:4,note:"Lessare patate, carote e piselli separatamente e tagliarli a cubetti. Unire con yogurt greco e un cucchiaio di maionese leggera. Aggiustare di sale e mescolare bene.",note_en:"Boil potatoes, carrots and peas separately and dice them. Combine with Greek yogurt and a spoonful of light mayonnaise. Adjust salt and mix well.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Carote",qt:"150g"},{nome:"Piselli",qt:"150g"},{nome:"Yogurt greco",qt:"100g"},{nome:"Maionese leggera",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata russa alleggerita (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:5,gs:1,g:5,z:5,ch:28,fi:4,ca:50,fe:1,mg:25,k2:400,na:200,zn:.6,fo:30,se:3,col:8}},{id:"tpl_1819",nome:"Insalata di riso estiva",nome_en:"Summer rice salad",categoria:"Insalata",porzioni:4,note:"Lessare il riso e raffreddarlo sotto acqua corrente. Unire mais, wurstel a rondelle, pomodorini e olive. Condire con olio extravergine e una manciata di prezzemolo.",note_en:"Boil the rice and cool it under running water. Add corn, sliced frankfurters, cherry tomatoes and olives. Dress with extra virgin oil and a handful of parsley.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Mais",qt:"100g"},{nome:"Wurstel",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olive verdi",qt:"50g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso estiva (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:9,gs:2.5,g:11,z:5,ch:50,fi:2.5,ca:30,fe:1.8,mg:30,k2:280,na:450,zn:1.2,fo:20,se:8,col:15}},{id:"tpl_1820",nome:"Insalata di polpo e patate (versione 2)",nome_en:"Octopus and potato salad (version 2)",categoria:"Insalata",porzioni:4,note:"Lessare il polpo in acqua con alloro fino a renderlo tenero. Lessare le patate e tagliarle a cubetti. Unire polpo e patate, condire con olio, prezzemolo e limone.",note_en:"Boil the octopus in water with bay leaf until tender. Boil the potatoes and dice them. Combine octopus and potatoes, dress with oil, parsley and lemon.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Patate",qt:"300g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata di polpo e patate (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:26,gs:1.5,g:11,z:1,ch:20,fi:2,ca:40,fe:2.5,mg:60,k2:600,na:380,zn:1.8,fo:35,se:45,col:60}},{id:"tpl_1821",nome:"Insalata di rucola, parmigiano e speck",nome_en:"Arugula salad with parmesan and speck",categoria:"Insalata",porzioni:2,note:"Rosolare lo speck a listarelle in padella fino a renderlo croccante. Disporre la rucola in una ciotola con scaglie di parmigiano e lo speck. Condire con olio e aceto balsamico.",note_en:"Sauté the speck strips in a pan until crispy. Arrange the arugula in a bowl with parmesan shavings and the speck. Dress with oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Parmigiano a scaglie",qt:"50g"},{nome:"Speck",qt:"80g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di rucola, parmigiano e speck (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:20,gs:8,g:24,z:1,ch:2,fi:1,ca:280,fe:1.5,mg:35,k2:300,na:750,zn:2,fo:40,se:12,col:55}},{id:"tpl_1822",nome:"Insalata greca (versione 2)",nome_en:"Greek salad (version 2)",categoria:"Insalata",porzioni:4,note:"Tagliare a pezzi pomodori, cetrioli, peperone verde e cipolla rossa. Aggiungere olive nere e feta a cubotti. Condire con olio extravergine, origano e sale.",note_en:"Cut tomatoes, cucumbers, green pepper and red onion into pieces. Add black olives and cubed feta. Dress with extra virgin oil, oregano and salt.",ingredienti:[{nome:"Pomodori",qt:"300g"},{nome:"Cetrioli",qt:"200g"},{nome:"Peperone verde",qt:"100g"},{nome:"Cipolla rossa",qt:"1/2"},{nome:"Olive nere",qt:"60g"},{nome:"Feta",qt:"150g"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata greca (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:8,g:22,z:6,ch:10,fi:3,ca:250,fe:1.2,mg:30,k2:400,na:550,zn:1.4,fo:35,se:8,col:35}},{id:"tpl_1823",nome:"Insalata di lenticchie e feta (versione 2)",nome_en:"Lentil and feta salad (version 2)",categoria:"Insalata",porzioni:2,note:"Lessare le lenticchie oppure usarle già cotte. Unire feta sbriciolata, pomodorini e cipollotto affettato. Condire con olio extravergine, limone e origano.",note_en:"Boil the lentils or use pre-cooked ones. Add crumbled feta, cherry tomatoes and sliced spring onion. Dress with extra virgin oil, lemon and oregano.",ingredienti:[{nome:"Lenticchie lessate",qt:"250g"},{nome:"Feta",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Cipollotto",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di lenticchie e feta (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:16,gs:6,g:14,z:4,ch:30,fi:9,ca:180,fe:4,mg:55,k2:500,na:400,zn:2,fo:120,se:6,col:25}},{id:"tpl_1824",nome:"Insalata di gamberi e avocado (versione 2)",nome_en:"Shrimp and avocado salad (version 2)",categoria:"Insalata",porzioni:2,note:"Sbollentare i gamberi per due minuti e raffreddarli in acqua e ghiaccio. Tagliare l'avocado a fette e disporlo con lattuga e gamberi. Condire con olio, limone e sale.",note_en:"Blanch the shrimp for two minutes and cool in ice water. Slice the avocado and arrange with lettuce and shrimp. Dress with oil, lemon and salt.",ingredienti:[{nome:"Gamberi",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di gamberi e avocado (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:24,gs:3,g:19,z:2,ch:8,fi:5,ca:60,fe:1.2,mg:45,k2:600,na:350,zn:1.5,fo:50,se:30,col:170}},{id:"tpl_1825",nome:"Insalata Caesar con pollo",nome_en:"Chicken Caesar salad",categoria:"Insalata",porzioni:2,note:"Grigliare il pollo e tagliarlo a strisce. Disporre lattuga romana, crostini di pane e parmigiano a scaglie. Condire con salsa Caesar e completare con il pollo.",note_en:"Grill the chicken and slice it into strips. Arrange romaine lettuce, bread croutons and parmesan shavings. Dress with Caesar sauce and top with chicken.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Lattuga romana",qt:"150g"},{nome:"Crostini di pane",qt:"50g"},{nome:"Parmigiano a scaglie",qt:"30g"},{nome:"Salsa Caesar",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata Caesar con pollo (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:32,gs:6,g:22,z:3,ch:22,fi:2,ca:180,fe:1.8,mg:40,k2:450,na:600,zn:1.8,fo:40,se:22,col:80}},{id:"tpl_1826",nome:"Insalata di farro, pomodorini e mozzarella",nome_en:"Farro salad with cherry tomatoes and mozzarella",categoria:"Insalata",porzioni:4,note:"Lessare il farro e lasciarlo raffreddare. Unire pomodorini tagliati a metà, mozzarella a cubetti e basilico spezzettato. Condire con olio extravergine e sale.",note_en:"Boil the farro and let it cool. Add halved cherry tomatoes, cubed mozzarella and torn basil. Dress with extra virgin oil and salt.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Pomodorini",qt:"200g"},{nome:"Mozzarella",qt:"200g"},{nome:"Basilico",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, pomodorini e mozzarella (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:15,gs:6,g:15,z:4,ch:38,fi:5,ca:220,fe:2,mg:40,k2:350,na:250,zn:1.5,fo:35,se:10,col:30}},{id:"tpl_1827",nome:"Insalata di ceci e tonno con peperoni",nome_en:"Chickpea and tuna salad with peppers",categoria:"Insalata",porzioni:2,note:"Scolare ceci e tonno e unirli in una ciotola. Aggiungere peperoni grigliati a listarelle e prezzemolo. Condire con olio extravergine e un pizzico di sale.",note_en:"Drain chickpeas and tuna and combine in a bowl. Add grilled pepper strips and parsley. Dress with extra virgin oil and a pinch of salt.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Peperoni grigliati",qt:"150g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di ceci e tonno con peperoni (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:27,gs:2.5,g:16,z:5,ch:30,fi:8,ca:70,fe:3.2,mg:65,k2:550,na:420,zn:2,fo:110,se:35,col:30}},{id:"tpl_1828",nome:"Insalata di salmone affumicato e finocchi",nome_en:"Smoked salmon and fennel salad",categoria:"Insalata",porzioni:2,note:"Affettare i finocchi sottilmente con una mandolina. Disporli su un piatto con il salmone affumicato a fette. Condire con olio extravergine, limone e pepe.",note_en:"Slice the fennel thinly with a mandoline. Arrange on a plate with sliced smoked salmon. Dress with extra virgin oil, lemon and pepper.",ingredienti:[{nome:"Salmone affumicato",qt:"150g"},{nome:"Finocchi",qt:"200g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aneto",qt:"q.b."}],_dbEntry:{n:"Insalata di salmone affumicato e finocchi (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:18,gs:3,g:17,z:3,ch:6,fi:3,ca:40,fe:1,mg:35,k2:450,na:750,zn:.8,fo:30,se:25,col:35}},{id:"tpl_1829",nome:"Insalata di orzo perlato e verdure",nome_en:"Pearl barley salad with vegetables",categoria:"Insalata",porzioni:4,note:"Lessare l'orzo perlato in acqua salata e scolarlo. Unire zucchine e carote a cubetti saltate in padella e olive verdi. Condire con olio extravergine e prezzemolo.",note_en:"Boil the pearl barley in salted water and drain. Add pan-sautéed diced zucchini and carrots and green olives. Dress with extra virgin oil and parsley.",ingredienti:[{nome:"Orzo perlato",qt:"250g"},{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Olive verdi",qt:"50g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di orzo perlato e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:7,gs:1,g:8,z:4,ch:40,fi:6,ca:35,fe:2,mg:40,k2:320,na:280,zn:1.2,fo:30,se:8,col:0}},{id:"tpl_1830",nome:"Insalata di couscous e verdure grigliate",nome_en:"Couscous salad with grilled vegetables",categoria:"Insalata",porzioni:4,note:"Reidratare il couscous con acqua bollente e sgranarlo con una forchetta. Unire melanzane e zucchine grigliate a cubetti. Condire con olio extravergine, limone e menta.",note_en:"Rehydrate the couscous with boiling water and fluff it with a fork. Add diced grilled eggplant and zucchini. Dress with extra virgin oil, lemon and mint.",ingredienti:[{nome:"Couscous",qt:"250g"},{nome:"Melanzane",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di couscous e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:1,g:8,z:4,ch:44,fi:4,ca:30,fe:1.8,mg:35,k2:300,na:150,zn:1,fo:25,se:6,col:0}},{id:"tpl_1831",nome:"Insalata di patate e uova sode",nome_en:"Potato and hard-boiled egg salad",categoria:"Insalata",porzioni:4,note:"Lessare le patate e le uova separatamente. Tagliare a cubetti e affettare le uova, unire a cipollotto e prezzemolo tritato. Condire con olio extravergine, senape e sale.",note_en:"Boil the potatoes and eggs separately. Dice the potatoes and slice the eggs, combine with spring onion and chopped parsley. Dress with extra virgin oil, mustard and salt.",ingredienti:[{nome:"Patate",qt:"400g"},{nome:"Uova",qt:"4"},{nome:"Cipollotto",qt:"1"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Senape",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di patate e uova sode (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:3,g:14,z:2,ch:26,fi:2.5,ca:50,fe:1.8,mg:30,k2:500,na:200,zn:1.2,fo:50,se:20,col:200}},{id:"tpl_1832",nome:"Insalata di fagioli borlotti e cipolla rossa",nome_en:"Borlotti bean and red onion salad",categoria:"Insalata",porzioni:2,note:"Scolare i fagioli borlotti lessati e unirli a cipolla rossa affettata sottile. Aggiungere prezzemolo tritato. Condire con olio extravergine, aceto di vino e sale.",note_en:"Drain the boiled borlotti beans and combine with thinly sliced red onion. Add chopped parsley. Dress with extra virgin oil, wine vinegar and salt.",ingredienti:[{nome:"Fagioli borlotti lessati",qt:"300g"},{nome:"Cipolla rossa",qt:"1"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Aceto di vino",qt:"1 cucchiaio"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di fagioli borlotti e cipolla rossa (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:11,gs:1,g:9,z:4,ch:32,fi:9,ca:70,fe:3,mg:60,k2:600,na:150,zn:1.5,fo:130,se:4,col:0}},{id:"tpl_1833",nome:"Insalata di radicchio, noci e gorgonzola",nome_en:"Radicchio salad with walnuts and gorgonzola",categoria:"Insalata",porzioni:2,note:"Tagliare il radicchio a listarelle e disporlo in una ciotola. Aggiungere gorgonzola a pezzetti e gherigli di noci. Condire con olio extravergine e aceto balsamico.",note_en:"Cut the radicchio into strips and place in a bowl. Add gorgonzola pieces and walnut kernels. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Radicchio",qt:"150g"},{nome:"Gorgonzola",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di radicchio, noci e gorgonzola (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:9,g:28,z:3,ch:6,fi:2.5,ca:220,fe:1.2,mg:50,k2:350,na:450,zn:1.6,fo:35,se:10,col:35}},{id:"tpl_1834",nome:"Insalata di finocchi e arance",nome_en:"Fennel and orange salad",categoria:"Insalata",porzioni:2,note:"Affettare sottilmente i finocchi e sbucciare a vivo le arance. Disporli alternati su un piatto con olive nere. Condire con olio extravergine e una macinata di pepe.",note_en:"Slice the fennel thinly and peel the oranges into segments. Arrange alternated on a plate with black olives. Dress with extra virgin oil and a grind of pepper.",ingredienti:[{nome:"Finocchi",qt:"200g"},{nome:"Arance",qt:"2"},{nome:"Olive nere",qt:"40g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di finocchi e arance (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:3,gs:1.5,g:10,z:16,ch:20,fi:5,ca:70,fe:1,mg:25,k2:450,na:250,zn:.5,fo:40,se:2,col:0}},{id:"tpl_1835",nome:"Insalata di pollo, mele e sedano",nome_en:"Chicken, apple and celery salad",categoria:"Insalata",porzioni:2,note:"Cuocere il petto di pollo e tagliarlo a cubetti. Unire mela a fette, sedano affettato e gherigli di noci. Condire con yogurt greco, limone e sale.",note_en:"Cook the chicken breast and dice it. Combine with sliced apple, chopped celery and walnut kernels. Dress with Greek yogurt, lemon and salt.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Mela",qt:"1"},{nome:"Sedano",qt:"100g"},{nome:"Noci",qt:"30g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"1/2"}],_dbEntry:{n:"Insalata di pollo, mele e sedano (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:30,gs:3,g:14,z:12,ch:16,fi:3,ca:60,fe:1.5,mg:40,k2:550,na:150,zn:1.5,fo:35,se:22,col:75}},{id:"tpl_1836",nome:"Insalata di farro e gamberetti al limone",nome_en:"Farro salad with shrimp and lemon",categoria:"Insalata",porzioni:2,note:"Lessare il farro e i gamberetti separatamente. Unirli in una ciotola con scorza e succo di limone e prezzemolo tritato. Condire con olio extravergine e sale.",note_en:"Boil the farro and shrimp separately. Combine in a bowl with lemon zest and juice and chopped parsley. Dress with extra virgin oil and salt.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Gamberetti",qt:"200g"},{nome:"Limone",qt:"1"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro e gamberetti al limone (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:22,gs:1.5,g:9,z:2,ch:36,fi:4,ca:70,fe:1.5,mg:50,k2:400,na:350,zn:1.5,fo:35,se:35,col:150}},{id:"tpl_1837",nome:"Insalata di riso, tonno e piselli",nome_en:"Rice salad with tuna and peas",categoria:"Insalata",porzioni:4,note:"Lessare il riso e i piselli e raffreddarli. Unire tonno sgocciolato e carote a cubetti. Condire con olio extravergine, sale e un pizzico di prezzemolo.",note_en:"Boil the rice and peas and let cool. Add drained tuna and diced carrots. Dress with extra virgin oil, salt and a touch of parsley.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Piselli",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso, tonno e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:18,gs:2,g:11,z:4,ch:50,fi:4,ca:40,fe:2,mg:40,k2:400,na:350,zn:1.5,fo:40,se:28,col:25}},{id:"tpl_1838",nome:"Insalata di ceci, feta e cetrioli",nome_en:"Chickpea salad with feta and cucumber",categoria:"Insalata",porzioni:2,note:"Scolare i ceci lessati e unirli a cetrioli a cubetti e feta sbriciolata. Aggiungere menta fresca. Condire con olio extravergine e succo di limone.",note_en:"Drain the boiled chickpeas and combine with diced cucumber and crumbled feta. Add fresh mint. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Feta",qt:"100g"},{nome:"Cetrioli",qt:"150g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di ceci, feta e cetrioli (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:14,gs:6,g:16,z:4,ch:30,fi:8,ca:200,fe:3,mg:60,k2:450,na:450,zn:1.8,fo:110,se:6,col:25}},{id:"tpl_1839",nome:"Insalata di rucola, pere e parmigiano",nome_en:"Arugula salad with pears and parmesan",categoria:"Insalata",porzioni:2,note:"Disporre la rucola su un piatto con pere a fettine sottili. Aggiungere scaglie di parmigiano e gherigli di noci. Condire con olio extravergine e aceto balsamico.",note_en:"Arrange the arugula on a plate with thinly sliced pears. Add parmesan shavings and walnut kernels. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Pere",qt:"1"},{nome:"Parmigiano a scaglie",qt:"40g"},{nome:"Noci",qt:"30g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di rucola, pere e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:10,gs:5,g:20,z:12,ch:16,fi:4,ca:250,fe:1,mg:35,k2:350,na:200,zn:1.4,fo:35,se:8,col:25}},{id:"tpl_1840",nome:"Insalata di polpo, sedano e olive taggiasche",nome_en:"Octopus salad with celery and taggiasca olives",categoria:"Insalata",porzioni:4,note:"Lessare il polpo fino a renderlo tenero e tagliarlo a pezzi. Unire sedano affettato sottile e olive taggiasche. Condire con olio extravergine, limone e prezzemolo.",note_en:"Boil the octopus until tender and cut into pieces. Add thinly sliced celery and taggiasca olives. Dress with extra virgin oil, lemon and parsley.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Sedano",qt:"150g"},{nome:"Olive taggiasche",qt:"60g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata di polpo, sedano e olive taggiasche (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:24,gs:1.8,g:13,z:1,ch:9,fi:2,ca:50,fe:2.5,mg:55,k2:550,na:400,zn:1.8,fo:35,se:42,col:60}},{id:"tpl_1841",nome:"Insalata di mozzarella di bufala e pomodori cuore di bue",nome_en:"Buffalo mozzarella and beefsteak tomato salad",categoria:"Insalata",porzioni:2,note:"Tagliare a fette spesse i pomodori cuore di bue e la mozzarella di bufala. Disporli su un piatto con basilico fresco. Condire con olio extravergine e un pizzico di sale.",note_en:"Cut thick slices of beefsteak tomatoes and buffalo mozzarella. Arrange on a plate with fresh basil. Dress with extra virgin oil and a pinch of salt.",ingredienti:[{nome:"Pomodori cuore di bue",qt:"300g"},{nome:"Mozzarella di bufala",qt:"250g"},{nome:"Basilico",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di mozzarella di bufala e pomodori cuore di bue (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:17,gs:9,g:23,z:6,ch:6,fi:2,ca:360,fe:.8,mg:25,k2:320,na:270,zn:1.6,fo:25,se:8,col:45}},{id:"tpl_1842",nome:"Insalata di lenticchie e salsiccia",nome_en:"Lentil and sausage salad",categoria:"Insalata",porzioni:2,note:"Cuocere la salsiccia in padella e tagliarla a pezzi. Unire lenticchie lessate e cipolla rossa affettata. Condire con olio extravergine, aceto e prezzemolo tritato.",note_en:"Cook the sausage in a pan and cut into pieces. Combine with boiled lentils and sliced red onion. Dress with extra virgin oil, vinegar and chopped parsley.",ingredienti:[{nome:"Salsiccia",qt:"200g"},{nome:"Lenticchie lessate",qt:"250g"},{nome:"Cipolla rossa",qt:"1/2"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di lenticchie e salsiccia (ricetta)",c:"Ricette",src:"RICETTE",k:420,p:22,gs:9,g:24,z:3,ch:28,fi:8,ca:60,fe:4,mg:55,k2:550,na:650,zn:2.5,fo:110,se:15,col:55}},{id:"tpl_1843",nome:"Insalata di tacchino, avocado e mais",nome_en:"Turkey salad with avocado and corn",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di tacchino e tagliarlo a striscioline. Unire avocado a cubetti e mais scolato su lattuga. Condire con olio extravergine e succo di lime.",note_en:"Grill the turkey breast and cut into strips. Combine with diced avocado and drained corn on lettuce. Dress with extra virgin oil and lime juice.",ingredienti:[{nome:"Petto di tacchino",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Mais",qt:"100g"},{nome:"Lattuga",qt:"100g"},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di tacchino, avocado e mais (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:29,gs:3.5,g:18,z:5,ch:14,fi:5,ca:40,fe:1.5,mg:45,k2:600,na:200,zn:1.5,fo:55,se:20,col:65}},{id:"tpl_1844",nome:"Insalata di farro, ceci e verdure estive",nome_en:"Farro salad with chickpeas and summer vegetables",categoria:"Insalata",porzioni:4,note:"Lessare il farro e i ceci separatamente. Unire zucchine e pomodorini a cubetti. Condire con olio extravergine, basilico fresco e sale.",note_en:"Boil the farro and chickpeas separately. Add diced zucchini and cherry tomatoes. Dress with extra virgin oil, fresh basil and salt.",ingredienti:[{nome:"Farro",qt:"200g"},{nome:"Ceci lessati",qt:"200g"},{nome:"Zucchine",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Basilico",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, ceci e verdure estive (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:10,gs:1,g:9,z:4,ch:46,fi:8,ca:50,fe:3,mg:60,k2:420,na:150,zn:1.6,fo:100,se:8,col:0}},{id:"tpl_1845",nome:"Insalata di quinoa, avocado e pomodorini",nome_en:"Quinoa salad with avocado and cherry tomatoes",categoria:"Insalata",porzioni:2,note:"Cuocere la quinoa e lasciarla raffreddare. Unire avocado a cubetti e pomodorini tagliati a metà. Condire con olio extravergine, lime e coriandolo fresco.",note_en:"Cook the quinoa and let it cool. Add diced avocado and halved cherry tomatoes. Dress with extra virgin oil, lime and fresh cilantro.",ingredienti:[{nome:"Quinoa",qt:"150g"},{nome:"Avocado",qt:"1"},{nome:"Pomodorini",qt:"150g"},{nome:"Coriandolo fresco",qt:"q.b."},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di quinoa, avocado e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:8,gs:2.5,g:19,z:4,ch:32,fi:7,ca:40,fe:2.5,mg:60,k2:600,na:100,zn:1.5,fo:70,se:6,col:0}},{id:"tpl_1846",nome:"Insalata di riso, gamberetti e curry",nome_en:"Rice salad with shrimp and curry",categoria:"Insalata",porzioni:4,note:"Lessare il riso e i gamberetti separatamente. Unire mela a cubetti e uvetta. Condire con maionese leggera aromatizzata al curry e un pizzico di sale.",note_en:"Boil the rice and shrimp separately. Add diced apple and raisins. Dress with light mayonnaise flavored with curry and a pinch of salt.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Gamberetti",qt:"200g"},{nome:"Mela",qt:"1"},{nome:"Uvetta",qt:"30g"},{nome:"Curry",qt:"1 cucchiaino"},{nome:"Maionese leggera",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso, gamberetti e curry (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:16,gs:2,g:9,z:10,ch:56,fi:2.5,ca:50,fe:1.5,mg:35,k2:350,na:400,zn:1.2,fo:30,se:28,col:110}},{id:"tpl_1847",nome:"Insalata di spinacini, uova e speck croccante",nome_en:"Baby spinach salad with eggs and crispy speck",categoria:"Insalata",porzioni:2,note:"Rosolare lo speck a listarelle fino a renderlo croccante. Disporre gli spinacini con uova sode a fette e lo speck. Condire con olio extravergine e aceto balsamico.",note_en:"Sauté the speck strips until crispy. Arrange the baby spinach with sliced hard-boiled eggs and the speck. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Spinacini freschi",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Speck",qt:"80g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di spinacini, uova e speck croccante (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:20,gs:6,g:24,z:1,ch:4,fi:2,ca:90,fe:2.5,mg:45,k2:500,na:700,zn:1.8,fo:120,se:20,col:230}},{id:"tpl_1848",nome:"Insalata di fagiolini e patate lesse",nome_en:"Green bean and boiled potato salad",categoria:"Insalata",porzioni:4,note:"Lessare fagiolini e patate separatamente fino a renderli teneri. Tagliare le patate a cubetti e unire il tutto. Condire con olio extravergine, aglio e prezzemolo.",note_en:"Boil the green beans and potatoes separately until tender. Dice the potatoes and combine everything. Dress with extra virgin oil, garlic and parsley.",ingredienti:[{nome:"Fagiolini",qt:"250g"},{nome:"Patate",qt:"300g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di fagiolini e patate lesse (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:1,g:7,z:3,ch:30,fi:5,ca:60,fe:1.8,mg:35,k2:550,na:100,zn:.8,fo:60,se:3,col:0}},{id:"tpl_1849",nome:"Insalata di carciofi, grana e rucola",nome_en:"Artichoke salad with grana cheese and arugula",categoria:"Insalata",porzioni:2,note:"Affettare sottilmente i cuori di carciofo crudi e condirli subito con limone. Disporli su rucola con scaglie di grana. Condire con olio extravergine e pepe.",note_en:"Thinly slice raw artichoke hearts and immediately toss with lemon. Arrange on arugula with grana shavings. Dress with extra virgin oil and pepper.",ingredienti:[{nome:"Carciofi",qt:"4"},{nome:"Rucola",qt:"80g"},{nome:"Grana a scaglie",qt:"50g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di carciofi, grana e rucola (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:11,gs:5,g:17,z:2,ch:12,fi:6,ca:280,fe:2,mg:40,k2:450,na:350,zn:1.5,fo:60,se:8,col:25}},{id:"tpl_1850",nome:"Insalata di pollo, quinoa e verdure grigliate",nome_en:"Chicken and quinoa salad with grilled vegetables",categoria:"Insalata",porzioni:2,note:"Cuocere la quinoa e grigliare il petto di pollo con zucchine e peperoni. Tagliare il pollo a fette e unire tutti gli ingredienti. Condire con olio extravergine e limone.",note_en:"Cook the quinoa and grill the chicken breast with zucchini and peppers. Slice the chicken and combine all the ingredients. Dress with extra virgin oil and lemon.",ingredienti:[{nome:"Petto di pollo",qt:"200g"},{nome:"Quinoa",qt:"150g"},{nome:"Zucchine",qt:"100g"},{nome:"Peperoni",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo, quinoa e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:32,gs:2,g:12,z:5,ch:36,fi:6,ca:45,fe:2.5,mg:60,k2:600,na:200,zn:1.8,fo:70,se:22,col:70}},{id:"tpl_1851",nome:"Insalata di tonno, fagioli e cipolla",nome_en:"Tuna, bean and onion salad",categoria:"Insalata",porzioni:2,note:"Scolare tonno e fagioli e unirli in una ciotola. Aggiungere cipolla bianca affettata sottile. Condire con olio extravergine, aceto di vino e prezzemolo tritato.",note_en:"Drain the tuna and beans and combine in a bowl. Add thinly sliced white onion. Dress with extra virgin oil, wine vinegar and chopped parsley.",ingredienti:[{nome:"Tonno sott'olio",qt:"160g"},{nome:"Fagioli cannellini lessati",qt:"250g"},{nome:"Cipolla bianca",qt:"1/2"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di tonno, fagioli e cipolla (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:26,gs:2.5,g:16,z:2,ch:28,fi:8,ca:70,fe:3,mg:60,k2:550,na:400,zn:1.8,fo:100,se:35,col:30}},{id:"tpl_1852",nome:"Insalata di farro, salmone e finocchi",nome_en:"Farro salad with salmon and fennel",categoria:"Insalata",porzioni:2,note:"Lessare il farro e lasciarlo raffreddare. Unire salmone affumicato a listarelle e finocchi affettati sottili. Condire con olio extravergine, limone e aneto.",note_en:"Boil the farro and let it cool. Add strips of smoked salmon and thinly sliced fennel. Dress with extra virgin oil, lemon and dill.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Salmone affumicato",qt:"150g"},{nome:"Finocchi",qt:"150g"},{nome:"Limone",qt:"1"},{nome:"Aneto",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, salmone e finocchi (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:18,gs:3,g:15,z:3,ch:36,fi:5,ca:50,fe:1.5,mg:45,k2:500,na:650,zn:1,fo:40,se:22,col:25}},{id:"tpl_1853",nome:"Insalata di ceci, tonno e pomodori secchi",nome_en:"Chickpea salad with tuna and sun-dried tomatoes",categoria:"Insalata",porzioni:2,note:"Scolare ceci e tonno e unirli in una ciotola. Aggiungere pomodori secchi tagliuzzati e capperi. Condire con olio extravergine e origano.",note_en:"Drain chickpeas and tuna and combine in a bowl. Add chopped sun-dried tomatoes and capers. Dress with extra virgin oil and oregano.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Pomodori secchi",qt:"40g"},{nome:"Capperi",qt:"1 cucchiaio"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di ceci, tonno e pomodori secchi (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:28,gs:2.5,g:17,z:5,ch:32,fi:8,ca:75,fe:3.2,mg:65,k2:600,na:500,zn:2,fo:110,se:35,col:30}},{id:"tpl_1854",nome:"Insalata di rucola, bresaola e grana",nome_en:"Arugula salad with bresaola and grana cheese",categoria:"Insalata",porzioni:2,note:"Disporre la rucola su un piatto con fette di bresaola. Aggiungere scaglie di grana e pinoli tostati. Condire con olio extravergine, limone e pepe.",note_en:"Arrange the arugula on a plate with slices of bresaola. Add grana shavings and toasted pine nuts. Dress with extra virgin oil, lemon and pepper.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Bresaola",qt:"150g"},{nome:"Grana a scaglie",qt:"40g"},{nome:"Pinoli",qt:"20g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di rucola, bresaola e grana (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:32,gs:5,g:20,z:1,ch:3,fi:1.5,ca:250,fe:3,mg:45,k2:500,na:750,zn:2.2,fo:35,se:20,col:75}},{id:"tpl_1855",nome:"Insalata di riso, verdure e feta",nome_en:"Rice salad with vegetables and feta",categoria:"Insalata",porzioni:4,note:"Lessare il riso e lasciarlo raffreddare. Unire cetrioli e pomodorini a cubetti e feta sbriciolata. Condire con olio extravergine, origano e limone.",note_en:"Boil the rice and let it cool. Add diced cucumbers and cherry tomatoes and crumbled feta. Dress with extra virgin oil, oregano and lemon.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Cetrioli",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Feta",qt:"150g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso, verdure e feta (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:10,gs:6,g:14,z:5,ch:44,fi:3,ca:220,fe:1.5,mg:35,k2:350,na:450,zn:1.4,fo:30,se:6,col:30}},{id:"tpl_1856",nome:"Insalata di polpo, patate e olive nere",nome_en:"Octopus salad with potatoes and black olives",categoria:"Insalata",porzioni:4,note:"Lessare il polpo e le patate separatamente. Tagliare a pezzi e unire con olive nere e prezzemolo. Condire con olio extravergine e succo di limone.",note_en:"Boil the octopus and potatoes separately. Cut into pieces and combine with black olives and parsley. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Patate",qt:"250g"},{nome:"Olive nere",qt:"60g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata di polpo, patate e olive nere (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:25,gs:1.8,g:13,z:1,ch:22,fi:2.5,ca:45,fe:2.8,mg:55,k2:600,na:400,zn:1.8,fo:35,se:42,col:60}},{id:"tpl_1857",nome:"Insalata di pollo, mango e avocado",nome_en:"Chicken salad with mango and avocado",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e tagliarlo a cubetti. Unire mango e avocado a dadini su un letto di lattuga. Condire con olio extravergine, lime e coriandolo.",note_en:"Grill the chicken breast and dice it. Combine with diced mango and avocado on a bed of lettuce. Dress with extra virgin oil, lime and cilantro.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Mango",qt:"1"},{nome:"Avocado",qt:"1"},{nome:"Lattuga",qt:"100g"},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo, mango e avocado (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:29,gs:3.5,g:20,z:14,ch:22,fi:6,ca:45,fe:1.8,mg:50,k2:700,na:180,zn:1.5,fo:65,se:22,col:70}},{id:"tpl_1858",nome:"Insalata di couscous, gamberetti e zucchine",nome_en:"Couscous salad with shrimp and zucchini",categoria:"Insalata",porzioni:2,note:"Reidratare il couscous con acqua bollente. Saltare le zucchine a listarelle e i gamberetti in padella con aglio. Unire tutto e condire con olio extravergine e limone.",note_en:"Rehydrate the couscous with boiling water. Sauté the zucchini strips and shrimp in a pan with garlic. Combine everything and dress with extra virgin oil and lemon.",ingredienti:[{nome:"Couscous",qt:"150g"},{nome:"Gamberetti",qt:"200g"},{nome:"Zucchine",qt:"150g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di couscous, gamberetti e zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:22,gs:1.5,g:9,z:4,ch:42,fi:3.5,ca:60,fe:1.5,mg:40,k2:400,na:350,zn:1.4,fo:35,se:32,col:150}},{id:"tpl_1859",nome:"Insalata di lenticchie e wurstel",nome_en:"Lentil and frankfurter salad",categoria:"Insalata",porzioni:2,note:"Scolare le lenticchie lessate e tagliare i wurstel a rondelle. Unire carota grattugiata e un filo di olio extravergine. Aggiustare di sale e mescolare bene.",note_en:"Drain the boiled lentils and slice the frankfurters into rounds. Add grated carrot and a drizzle of extra virgin oil. Adjust salt and mix well.",ingredienti:[{nome:"Lenticchie lessate",qt:"250g"},{nome:"Wurstel",qt:"150g"},{nome:"Carote",qt:"80g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di lenticchie e wurstel (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:17,gs:5,g:14,z:4,ch:32,fi:8,ca:55,fe:3.5,mg:50,k2:500,na:600,zn:1.8,fo:100,se:8,col:35}},{id:"tpl_1860",nome:"Insalata di fagioli cannellini, tonno e cipolla dolce",nome_en:"Cannellini bean salad with tuna and sweet onion",categoria:"Insalata",porzioni:2,note:"Scolare fagioli e tonno e unirli in una ciotola. Aggiungere cipolla dolce affettata sottile e prezzemolo. Condire con olio extravergine e un pizzico di pepe.",note_en:"Drain the beans and tuna and combine in a bowl. Add thinly sliced sweet onion and parsley. Dress with extra virgin oil and a pinch of pepper.",ingredienti:[{nome:"Fagioli cannellini lessati",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Cipolla dolce",qt:"1/2"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di fagioli cannellini, tonno e cipolla dolce (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:26,gs:2.5,g:16,z:3,ch:28,fi:8,ca:70,fe:3,mg:60,k2:550,na:400,zn:1.8,fo:100,se:35,col:30}},{id:"tpl_1861",nome:"Insalata di quinoa, melanzane grigliate e feta",nome_en:"Quinoa salad with grilled eggplant and feta",categoria:"Insalata",porzioni:2,note:"Cuocere la quinoa e lasciarla raffreddare. Grigliare le melanzane a cubetti e unirle con feta sbriciolata. Condire con olio extravergine, menta e limone.",note_en:"Cook the quinoa and let it cool. Grill the diced eggplant and combine with crumbled feta. Dress with extra virgin oil, mint and lemon.",ingredienti:[{nome:"Quinoa",qt:"150g"},{nome:"Melanzane",qt:"200g"},{nome:"Feta",qt:"100g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di quinoa, melanzane grigliate e feta (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:6,g:18,z:5,ch:32,fi:7,ca:200,fe:2.5,mg:60,k2:450,na:400,zn:1.6,fo:75,se:6,col:25}},{id:"tpl_1862",nome:"Insalata di farro, tonno e piselli",nome_en:"Farro salad with tuna and peas",categoria:"Insalata",porzioni:4,note:"Lessare il farro e i piselli separatamente. Unire tonno sgocciolato e carote a cubetti. Condire con olio extravergine, sale e prezzemolo tritato.",note_en:"Boil the farro and peas separately. Add drained tuna and diced carrots. Dress with extra virgin oil, salt and chopped parsley.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Piselli",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, tonno e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:18,gs:2,g:11,z:4,ch:44,fi:6,ca:45,fe:2.5,mg:55,k2:450,na:350,zn:1.5,fo:60,se:28,col:25}},{id:"tpl_1863",nome:"Insalata di rucola, fichi e parmigiano",nome_en:"Arugula salad with figs and parmesan",categoria:"Insalata",porzioni:2,note:"Disporre la rucola su un piatto con fichi freschi tagliati a spicchi. Aggiungere scaglie di parmigiano e gherigli di noci. Condire con olio extravergine e aceto balsamico.",note_en:"Arrange the arugula on a plate with fresh figs cut into wedges. Add parmesan shavings and walnut kernels. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Fichi freschi",qt:"4"},{nome:"Parmigiano a scaglie",qt:"40g"},{nome:"Noci",qt:"30g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di rucola, fichi e parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:10,gs:5,g:19,z:16,ch:20,fi:4,ca:250,fe:1,mg:40,k2:380,na:200,zn:1.4,fo:35,se:8,col:25}},{id:"tpl_1864",nome:"Insalata di orzo, pomodori e olive",nome_en:"Barley salad with tomatoes and olives",categoria:"Insalata",porzioni:4,note:"Lessare l'orzo perlato e lasciarlo raffreddare. Unire pomodori a cubetti, olive verdi e origano. Condire con olio extravergine e un pizzico di sale.",note_en:"Boil the pearl barley and let it cool. Add diced tomatoes, green olives and oregano. Dress with extra virgin oil and a pinch of salt.",ingredienti:[{nome:"Orzo perlato",qt:"250g"},{nome:"Pomodori",qt:"200g"},{nome:"Olive verdi",qt:"60g"},{nome:"Origano",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di orzo, pomodori e olive (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:7,gs:1.5,g:10,z:5,ch:42,fi:6,ca:40,fe:2,mg:40,k2:400,na:400,zn:1.2,fo:35,se:8,col:0}},{id:"tpl_1865",nome:"Insalata di pollo, sedano e uva",nome_en:"Chicken salad with celery and grapes",categoria:"Insalata",porzioni:2,note:"Cuocere il petto di pollo e tagliarlo a cubetti. Unire sedano affettato e chicchi d'uva tagliati a metà. Condire con yogurt greco, limone e sale.",note_en:"Cook the chicken breast and dice it. Combine with sliced celery and halved grapes. Dress with Greek yogurt, lemon and salt.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Sedano",qt:"100g"},{nome:"Uva",qt:"150g"},{nome:"Yogurt greco",qt:"80g"},{nome:"Limone",qt:"1/2"}],_dbEntry:{n:"Insalata di pollo, sedano e uva (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:30,gs:2.5,g:10,z:18,ch:22,fi:2,ca:60,fe:1.5,mg:40,k2:550,na:150,zn:1.5,fo:35,se:22,col:75}},{id:"tpl_1866",nome:"Insalata di orzo, gamberi e zucchine",nome_en:"Barley salad with shrimp and zucchini",categoria:"Insalata",porzioni:2,note:"Lessare l'orzo perlato e i gamberi separatamente. Saltare le zucchine a listarelle in padella. Unire tutto e condire con olio extravergine e limone.",note_en:"Boil the pearl barley and shrimp separately. Sauté the zucchini strips in a pan. Combine everything and dress with extra virgin oil and lemon.",ingredienti:[{nome:"Orzo perlato",qt:"150g"},{nome:"Gamberi",qt:"200g"},{nome:"Zucchine",qt:"150g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di orzo, gamberi e zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:22,gs:1.5,g:9,z:3,ch:36,fi:4,ca:65,fe:1.5,mg:45,k2:420,na:350,zn:1.5,fo:35,se:34,col:170}},{id:"tpl_1867",nome:"Insalata di tonno, riso e mais",nome_en:"Tuna salad with rice and corn",categoria:"Insalata",porzioni:4,note:"Lessare il riso e lasciarlo raffreddare. Unire tonno sgocciolato, mais e peperone rosso a cubetti. Condire con olio extravergine e un pizzico di sale.",note_en:"Boil the rice and let it cool. Add drained tuna, corn and diced red pepper. Dress with extra virgin oil and a pinch of salt.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Mais",qt:"100g"},{nome:"Peperone rosso",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di tonno, riso e mais (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:19,gs:2,g:11,z:5,ch:52,fi:3,ca:40,fe:2,mg:40,k2:380,na:350,zn:1.4,fo:35,se:28,col:25}},{id:"tpl_1868",nome:"Insalata di ceci, avocado e pomodorini",nome_en:"Chickpea salad with avocado and cherry tomatoes",categoria:"Insalata",porzioni:2,note:"Scolare i ceci lessati e unirli ad avocado a cubetti e pomodorini tagliati a metà. Aggiungere cipollotto affettato. Condire con olio extravergine e succo di lime.",note_en:"Drain the boiled chickpeas and combine with diced avocado and halved cherry tomatoes. Add sliced spring onion. Dress with extra virgin oil and lime juice.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Pomodorini",qt:"150g"},{nome:"Cipollotto",qt:"1"},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di ceci, avocado e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:11,gs:2.5,g:19,z:5,ch:34,fi:10,ca:60,fe:3.2,mg:70,k2:650,na:150,zn:1.8,fo:120,se:6,col:0}},{id:"tpl_1869",nome:"Insalata di patate, tonno e fagiolini",nome_en:"Potato salad with tuna and green beans",categoria:"Insalata",porzioni:4,note:"Lessare patate e fagiolini separatamente fino a renderli teneri. Tagliare le patate a cubetti e unire il tonno sgocciolato. Condire con olio extravergine e prezzemolo.",note_en:"Boil the potatoes and green beans separately until tender. Dice the potatoes and add the drained tuna. Dress with extra virgin oil and parsley.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Fagiolini",qt:"200g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di patate, tonno e fagiolini (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:1.8,g:11,z:3,ch:28,fi:4,ca:40,fe:2,mg:40,k2:550,na:300,zn:1.2,fo:50,se:24,col:20}},{id:"tpl_1870",nome:"Insalata di mozzarella, rucola e prosciutto crudo",nome_en:"Mozzarella salad with arugula and prosciutto",categoria:"Insalata",porzioni:2,note:"Disporre la rucola su un piatto con mozzarella a fette e prosciutto crudo. Aggiungere pomodorini tagliati a metà. Condire con olio extravergine e pepe.",note_en:"Arrange the arugula on a plate with sliced mozzarella and prosciutto. Add halved cherry tomatoes. Dress with extra virgin oil and pepper.",ingredienti:[{nome:"Mozzarella",qt:"200g"},{nome:"Rucola",qt:"80g"},{nome:"Prosciutto crudo",qt:"100g"},{nome:"Pomodorini",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di mozzarella, rucola e prosciutto crudo (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:26,gs:11,g:28,z:3,ch:4,fi:1.5,ca:300,fe:1.2,mg:35,k2:350,na:800,zn:2,fo:35,se:15,col:80}},{id:"tpl_1871",nome:"Insalata di farro, feta e olive",nome_en:"Farro salad with feta and olives",categoria:"Insalata",porzioni:4,note:"Lessare il farro e lasciarlo raffreddare. Unire feta a cubetti, olive nere e pomodorini. Condire con olio extravergine, origano e limone.",note_en:"Boil the farro and let it cool. Add cubed feta, black olives and cherry tomatoes. Dress with extra virgin oil, oregano and lemon.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Feta",qt:"150g"},{nome:"Olive nere",qt:"60g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, feta e olive (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:11,gs:6,g:16,z:4,ch:40,fi:6,ca:200,fe:2.5,mg:50,k2:380,na:500,zn:1.6,fo:60,se:8,col:25}},{id:"tpl_1872",nome:"Insalata di quinoa, gamberi e mango",nome_en:"Quinoa salad with shrimp and mango",categoria:"Insalata",porzioni:2,note:"Cuocere la quinoa e i gamberi separatamente. Unire mango a cubetti e coriandolo fresco. Condire con olio extravergine, lime e un pizzico di peperoncino.",note_en:"Cook the quinoa and shrimp separately. Add diced mango and fresh cilantro. Dress with extra virgin oil, lime and a pinch of chili.",ingredienti:[{nome:"Quinoa",qt:"150g"},{nome:"Gamberi",qt:"200g"},{nome:"Mango",qt:"1"},{nome:"Coriandolo fresco",qt:"q.b."},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di quinoa, gamberi e mango (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:23,gs:1.5,g:10,z:14,ch:38,fi:5,ca:65,fe:1.8,mg:55,k2:550,na:350,zn:1.5,fo:50,se:34,col:170}},{id:"tpl_1873",nome:"Insalata di riso, uova e piselli",nome_en:"Rice salad with eggs and peas",categoria:"Insalata",porzioni:4,note:"Lessare il riso, i piselli e le uova separatamente. Tagliare le uova a spicchi e unire tutto. Condire con olio extravergine, sale e prezzemolo tritato.",note_en:"Boil the rice, peas and eggs separately. Cut the eggs into wedges and combine everything. Dress with extra virgin oil, salt and chopped parsley.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Uova",qt:"4"},{nome:"Piselli",qt:"150g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso, uova e piselli (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:13,gs:3,g:12,z:4,ch:48,fi:3.5,ca:50,fe:2,mg:35,k2:400,na:200,zn:1.4,fo:60,se:20,col:200}},{id:"tpl_1874",nome:"Insalata di lenticchie, feta e rucola",nome_en:"Lentil salad with feta and arugula",categoria:"Insalata",porzioni:2,note:"Scolare le lenticchie lessate e disporle su un letto di rucola. Aggiungere feta sbriciolata e pomodorini. Condire con olio extravergine e succo di limone.",note_en:"Drain the boiled lentils and place on a bed of arugula. Add crumbled feta and cherry tomatoes. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Lenticchie lessate",qt:"250g"},{nome:"Feta",qt:"100g"},{nome:"Rucola",qt:"80g"},{nome:"Pomodorini",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di lenticchie, feta e rucola (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:17,gs:6,g:15,z:4,ch:30,fi:9,ca:190,fe:4,mg:60,k2:550,na:420,zn:2,fo:130,se:6,col:25}},{id:"tpl_1875",nome:"Insalata di polpo, ceci e prezzemolo",nome_en:"Octopus salad with chickpeas and parsley",categoria:"Insalata",porzioni:4,note:"Lessare il polpo fino a renderlo tenero e tagliarlo a pezzi. Unire ceci lessati e prezzemolo tritato. Condire con olio extravergine, limone e aglio.",note_en:"Boil the octopus until tender and cut into pieces. Add boiled chickpeas and chopped parsley. Dress with extra virgin oil, lemon and garlic.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Ceci lessati",qt:"250g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata di polpo, ceci e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:28,gs:2,g:15,z:2,ch:24,fi:6,ca:60,fe:3.5,mg:70,k2:650,na:400,zn:2,fo:100,se:45,col:60}},{id:"tpl_1876",nome:"Insalata di finocchi, arance e olive nere",nome_en:"Fennel salad with oranges and black olives",categoria:"Insalata",porzioni:2,note:"Affettare sottilmente i finocchi e sbucciare a vivo le arance. Unire olive nere e disporre su un piatto. Condire con olio extravergine e pepe nero.",note_en:"Thinly slice the fennel and peel the oranges into segments. Add black olives and arrange on a plate. Dress with extra virgin oil and black pepper.",ingredienti:[{nome:"Finocchi",qt:"200g"},{nome:"Arance",qt:"2"},{nome:"Olive nere",qt:"50g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di finocchi, arance e olive nere (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:3,gs:1.8,g:11,z:16,ch:22,fi:6,ca:75,fe:1.2,mg:28,k2:460,na:320,zn:.6,fo:42,se:2,col:0}},{id:"tpl_1877",nome:"Insalata di rucola, noci e caprino",nome_en:"Arugula salad with walnuts and goat cheese",categoria:"Insalata",porzioni:2,note:"Disporre la rucola su un piatto con caprino fresco a pezzetti. Aggiungere gherigli di noci e un filo di miele. Condire con olio extravergine e aceto balsamico.",note_en:"Arrange the arugula on a plate with pieces of fresh goat cheese. Add walnut kernels and a drizzle of honey. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Caprino fresco",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Miele",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di rucola, noci e caprino (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:11,gs:8,g:27,z:8,ch:10,fi:3,ca:180,fe:1.5,mg:50,k2:320,na:300,zn:1.4,fo:35,se:8,col:35}},{id:"tpl_1878",nome:"Insalata di farro, zucchine grigliate e scamorza affumicata",nome_en:"Farro salad with grilled zucchini and smoked scamorza",categoria:"Insalata",porzioni:4,note:"Lessare il farro e lasciarlo raffreddare. Grigliare le zucchine a fette e tagliare la scamorza a cubetti. Unire tutto e condire con olio extravergine e basilico.",note_en:"Boil the farro and let it cool. Grill the zucchini slices and cube the scamorza. Combine everything and dress with extra virgin oil and basil.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Zucchine",qt:"200g"},{nome:"Scamorza affumicata",qt:"150g"},{nome:"Basilico",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, zucchine grigliate e scamorza affumicata (ricetta)",c:"Ricette",src:"RICETTE",k:350,p:15,gs:7,g:16,z:3,ch:40,fi:5,ca:230,fe:2,mg:45,k2:350,na:400,zn:1.6,fo:40,se:10,col:35}},{id:"tpl_1879",nome:"Insalata di couscous, ceci e verdure croccanti",nome_en:"Couscous salad with chickpeas and crunchy vegetables",categoria:"Insalata",porzioni:4,note:"Reidratare il couscous con acqua bollente e sgranarlo. Unire ceci lessati, carote e peperone a julienne. Condire con olio extravergine, limone e menta.",note_en:"Rehydrate the couscous with boiling water and fluff it. Add boiled chickpeas, julienned carrots and pepper. Dress with extra virgin oil, lemon and mint.",ingredienti:[{nome:"Couscous",qt:"250g"},{nome:"Ceci lessati",qt:"200g"},{nome:"Carote",qt:"100g"},{nome:"Peperone",qt:"100g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di couscous, ceci e verdure croccanti (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:10,gs:1,g:9,z:6,ch:52,fi:8,ca:50,fe:2.8,mg:55,k2:400,na:150,zn:1.6,fo:90,se:6,col:0}},{id:"tpl_1880",nome:"Insalata di pollo, quinoa e melograno",nome_en:"Chicken and quinoa salad with pomegranate",categoria:"Insalata",porzioni:2,note:"Cuocere la quinoa e grigliare il petto di pollo. Tagliare il pollo a cubetti e unire chicchi di melograno freschi. Condire con olio extravergine e succo di limone.",note_en:"Cook the quinoa and grill the chicken breast. Dice the chicken and add fresh pomegranate seeds. Dress with extra virgin oil and lemon juice.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Quinoa",qt:"150g"},{nome:"Melograno",qt:"1"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo, quinoa e melograno (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:32,gs:2,g:12,z:10,ch:36,fi:5,ca:40,fe:2.2,mg:55,k2:600,na:150,zn:1.6,fo:60,se:22,col:70}},{id:"tpl_1881",nome:"Insalata di gamberetti, avocado e pompelmo rosa",nome_en:"Shrimp salad with avocado and pink grapefruit",categoria:"Insalata",porzioni:2,note:"Sbollentare i gamberetti e raffreddarli. Sbucciare a vivo il pompelmo rosa e unire avocado a fette. Condire con olio extravergine, sale e un pizzico di zenzero.",note_en:"Blanch the shrimp and cool them. Peel the pink grapefruit into segments and add sliced avocado. Dress with extra virgin oil, salt and a pinch of ginger.",ingredienti:[{nome:"Gamberetti",qt:"200g"},{nome:"Avocado",qt:"1"},{nome:"Pompelmo rosa",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di gamberetti, avocado e pompelmo rosa (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:20,gs:2.5,g:18,z:8,ch:12,fi:5,ca:60,fe:1,mg:45,k2:600,na:300,zn:1.2,fo:50,se:28,col:140}},{id:"tpl_1882",nome:"Insalata di tonno, ceci e peperoni grigliati",nome_en:"Tuna salad with chickpeas and grilled peppers",categoria:"Insalata",porzioni:2,note:"Scolare tonno e ceci e unirli in una ciotola. Aggiungere peperoni grigliati a listarelle e capperi. Condire con olio extravergine e origano.",note_en:"Drain tuna and chickpeas and combine in a bowl. Add grilled pepper strips and capers. Dress with extra virgin oil and oregano.",ingredienti:[{nome:"Tonno sott'olio",qt:"160g"},{nome:"Ceci lessati",qt:"250g"},{nome:"Peperoni grigliati",qt:"150g"},{nome:"Capperi",qt:"1 cucchiaio"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di tonno, ceci e peperoni grigliati (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:27,gs:2.5,g:16,z:5,ch:30,fi:8,ca:70,fe:3.2,mg:65,k2:550,na:450,zn:2,fo:110,se:35,col:30}},{id:"tpl_1883",nome:"Insalata di riso venere con verdure e semi di zucca",nome_en:"Black rice salad with vegetables and pumpkin seeds",categoria:"Insalata",porzioni:4,note:"Lessare il riso venere e lasciarlo raffreddare. Unire carote e zucchine a julienne e semi di zucca. Condire con olio extravergine, limone e prezzemolo.",note_en:"Boil the black rice and let it cool. Add julienned carrots and zucchini and pumpkin seeds. Dress with extra virgin oil, lemon and parsley.",ingredienti:[{nome:"Riso venere",qt:"250g"},{nome:"Carote",qt:"100g"},{nome:"Zucchine",qt:"100g"},{nome:"Semi di zucca",qt:"30g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso venere con verdure e semi di zucca (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:7,gs:1.5,g:10,z:3,ch:44,fi:4,ca:35,fe:2.5,mg:60,k2:350,na:100,zn:1.5,fo:30,se:6,col:0}},{id:"tpl_1884",nome:"Insalata di farro, gamberi e pomodorini",nome_en:"Farro salad with shrimp and cherry tomatoes",categoria:"Insalata",porzioni:2,note:"Lessare il farro e i gamberi separatamente. Unire pomodorini tagliati a metà e basilico fresco. Condire con olio extravergine, limone e sale.",note_en:"Boil the farro and shrimp separately. Add halved cherry tomatoes and fresh basil. Dress with extra virgin oil, lemon and salt.",ingredienti:[{nome:"Farro",qt:"150g"},{nome:"Gamberi",qt:"200g"},{nome:"Pomodorini",qt:"150g"},{nome:"Basilico",qt:"q.b."},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, gamberi e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:23,gs:1.5,g:9,z:4,ch:38,fi:5,ca:70,fe:1.6,mg:55,k2:450,na:350,zn:1.5,fo:40,se:35,col:150}},{id:"tpl_1885",nome:"Insalata di lenticchie, uova e speck",nome_en:"Lentil salad with eggs and speck",categoria:"Insalata",porzioni:2,note:"Scolare le lenticchie lessate e rosolare lo speck a listarelle fino a renderlo croccante. Unire uova sode a spicchi. Condire con olio extravergine e prezzemolo.",note_en:"Drain the boiled lentils and sauté the speck strips until crispy. Add hard-boiled egg wedges. Dress with extra virgin oil and parsley.",ingredienti:[{nome:"Lenticchie lessate",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Speck",qt:"80g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di lenticchie, uova e speck (ricetta)",c:"Ricette",src:"RICETTE",k:400,p:26,gs:6,g:20,z:3,ch:30,fi:8,ca:80,fe:4.5,mg:60,k2:600,na:700,zn:2.2,fo:130,se:22,col:230}},{id:"tpl_1886",nome:"Insalata di rucola, grana e pere caramellate",nome_en:"Arugula salad with grana cheese and caramelized pears",categoria:"Insalata",porzioni:2,note:"Saltare le pere a fette in padella con un cucchiaino di zucchero fino a caramellarle. Disporre la rucola con le pere e scaglie di grana. Condire con olio extravergine e aceto balsamico.",note_en:"Sauté the sliced pears in a pan with a teaspoon of sugar until caramelized. Arrange the arugula with the pears and grana shavings. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Pere",qt:"1"},{nome:"Grana a scaglie",qt:"40g"},{nome:"Zucchero",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di rucola, grana e pere caramellate (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:9,gs:5,g:18,z:16,ch:20,fi:3.5,ca:250,fe:1,mg:32,k2:350,na:220,zn:1.3,fo:35,se:8,col:25}},{id:"tpl_1887",nome:"Insalata di ceci, curry e uvetta",nome_en:"Chickpea salad with curry and raisins",categoria:"Insalata",porzioni:2,note:"Scolare i ceci lessati e unirli a uvetta e cipollotto affettato. Condire con yogurt greco, curry in polvere e un pizzico di sale, mescolando bene.",note_en:"Drain the boiled chickpeas and combine with raisins and sliced spring onion. Dress with Greek yogurt, curry powder and a pinch of salt, mixing well.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Uvetta",qt:"30g"},{nome:"Cipollotto",qt:"1"},{nome:"Yogurt greco",qt:"80g"},{nome:"Curry",qt:"1 cucchiaino"}],_dbEntry:{n:"Insalata di ceci, curry e uvetta (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:12,gs:1,g:6,z:14,ch:46,fi:9,ca:80,fe:3,mg:65,k2:500,na:150,zn:1.6,fo:110,se:5,col:5}},{id:"tpl_1888",nome:"Insalata di pollo, avocado e mais dolce",nome_en:"Chicken salad with avocado and sweet corn",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo e tagliarlo a strisce. Unire avocado a fette e mais dolce scolato su lattuga. Condire con olio extravergine e succo di lime.",note_en:"Grill the chicken breast and cut into strips. Combine with sliced avocado and drained sweet corn on lettuce. Dress with extra virgin oil and lime juice.",ingredienti:[{nome:"Petto di pollo",qt:"250g"},{nome:"Avocado",qt:"1"},{nome:"Mais dolce",qt:"100g"},{nome:"Lattuga",qt:"100g"},{nome:"Lime",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo, avocado e mais dolce (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:29,gs:3.5,g:19,z:5,ch:16,fi:5,ca:40,fe:1.6,mg:48,k2:620,na:180,zn:1.5,fo:55,se:22,col:70}},{id:"tpl_1889",nome:"Insalata di polpo, patate e prezzemolo",nome_en:"Octopus salad with potatoes and parsley",categoria:"Insalata",porzioni:4,note:"Lessare il polpo e le patate separatamente. Tagliare a pezzi e unire con abbondante prezzemolo tritato. Condire con olio extravergine, aglio e limone.",note_en:"Boil the octopus and potatoes separately. Cut into pieces and add plenty of chopped parsley. Dress with extra virgin oil, garlic and lemon.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Patate",qt:"300g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"3 cucchiai"}],_dbEntry:{n:"Insalata di polpo, patate e prezzemolo (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:26,gs:1.5,g:11,z:1,ch:20,fi:2,ca:40,fe:2.5,mg:60,k2:600,na:380,zn:1.8,fo:35,se:45,col:60}},{id:"tpl_1890",nome:"Insalata di farro, melanzane e ricotta salata",nome_en:"Farro salad with eggplant and salted ricotta",categoria:"Insalata",porzioni:4,note:"Lessare il farro e lasciarlo raffreddare. Grigliare le melanzane a cubetti e grattugiare la ricotta salata sopra. Condire con olio extravergine, menta e sale.",note_en:"Boil the farro and let it cool. Grill the diced eggplant and grate salted ricotta over it. Dress with extra virgin oil, mint and salt.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Melanzane",qt:"200g"},{nome:"Ricotta salata",qt:"100g"},{nome:"Menta fresca",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, melanzane e ricotta salata (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:13,gs:5,g:13,z:4,ch:44,fi:6,ca:180,fe:2.2,mg:50,k2:400,na:380,zn:1.5,fo:50,se:8,col:25}},{id:"tpl_1891",nome:"Insalata di orzo, feta e pomodorini",nome_en:"Barley salad with feta and cherry tomatoes",categoria:"Insalata",porzioni:4,note:"Lessare l'orzo perlato e lasciarlo raffreddare. Unire feta a cubetti e pomodorini tagliati a metà. Condire con olio extravergine, origano e limone.",note_en:"Boil the pearl barley and let it cool. Add cubed feta and halved cherry tomatoes. Dress with extra virgin oil, oregano and lemon.",ingredienti:[{nome:"Orzo perlato",qt:"250g"},{nome:"Feta",qt:"150g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di orzo, feta e pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:11,gs:6,g:15,z:4,ch:38,fi:5,ca:210,fe:2,mg:40,k2:350,na:480,zn:1.5,fo:35,se:8,col:30}},{id:"tpl_1892",nome:"Insalata di fagioli, tonno e cipolla rossa",nome_en:"Bean salad with tuna and red onion",categoria:"Insalata",porzioni:2,note:"Scolare i fagioli lessati e il tonno e unirli in una ciotola. Aggiungere cipolla rossa affettata sottile. Condire con olio extravergine, aceto e prezzemolo.",note_en:"Drain the boiled beans and tuna and combine in a bowl. Add thinly sliced red onion. Dress with extra virgin oil, vinegar and parsley.",ingredienti:[{nome:"Fagioli borlotti lessati",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Cipolla rossa",qt:"1/2"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di fagioli, tonno e cipolla rossa (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:26,gs:2.5,g:16,z:3,ch:30,fi:9,ca:75,fe:3.2,mg:65,k2:600,na:400,zn:1.9,fo:120,se:35,col:30}},{id:"tpl_1893",nome:"Insalata di farro, ceci, tonno e verdure miste",nome_en:"Farro salad with chickpeas, tuna and mixed vegetables",categoria:"Insalata",porzioni:4,note:"Lessare farro e ceci separatamente. Unire tonno sgocciolato, carote e peperoni a cubetti. Condire con olio extravergine, limone e prezzemolo tritato.",note_en:"Boil the farro and chickpeas separately. Add drained tuna, diced carrots and peppers. Dress with extra virgin oil, lemon and chopped parsley.",ingredienti:[{nome:"Farro",qt:"200g"},{nome:"Ceci lessati",qt:"150g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Carote",qt:"100g"},{nome:"Peperoni",qt:"100g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, ceci, tonno e verdure miste (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:2,g:13,z:5,ch:48,fi:9,ca:60,fe:3.5,mg:70,k2:550,na:400,zn:1.8,fo:110,se:28,col:25}},{id:"tpl_1894",nome:"Insalata di rucola, speck e grana padano",nome_en:"Arugula salad with speck and grana padano",categoria:"Insalata",porzioni:2,note:"Rosolare lo speck a listarelle in padella fino a renderlo croccante. Disporre la rucola con lo speck e scaglie di grana padano. Condire con olio extravergine e aceto balsamico.",note_en:"Sauté the speck strips in a pan until crispy. Arrange the arugula with the speck and grana padano shavings. Dress with extra virgin oil and balsamic vinegar.",ingredienti:[{nome:"Rucola",qt:"100g"},{nome:"Speck",qt:"80g"},{nome:"Grana padano a scaglie",qt:"50g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di rucola, speck e grana padano (ricetta)",c:"Ricette",src:"RICETTE",k:330,p:21,gs:8,g:25,z:1,ch:2,fi:1,ca:290,fe:1.5,mg:35,k2:300,na:780,zn:2,fo:40,se:12,col:55}},{id:"tpl_1895",nome:"Insalata di riso, gamberi e curry piccante",nome_en:"Rice salad with shrimp and spicy curry",categoria:"Insalata",porzioni:4,note:"Lessare il riso e i gamberi separatamente. Unire peperone rosso a cubetti e cipollotto. Condire con maionese leggera, curry piccante e succo di lime.",note_en:"Boil the rice and shrimp separately. Add diced red pepper and spring onion. Dress with light mayonnaise, spicy curry and lime juice.",ingredienti:[{nome:"Riso",qt:"280g"},{nome:"Gamberi",qt:"200g"},{nome:"Peperone rosso",qt:"100g"},{nome:"Cipollotto",qt:"1"},{nome:"Curry piccante",qt:"1 cucchiaino"},{nome:"Maionese leggera",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di riso, gamberi e curry piccante (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:20,gs:2,g:10,z:5,ch:54,fi:3,ca:60,fe:1.6,mg:40,k2:400,na:400,zn:1.4,fo:35,se:34,col:170}},{id:"tpl_1896",nome:"Insalata di pollo, farro e verdure grigliate",nome_en:"Chicken and farro salad with grilled vegetables",categoria:"Insalata",porzioni:2,note:"Grigliare il petto di pollo con zucchine e melanzane a fette. Lessare il farro e unire tutti gli ingredienti a cubetti. Condire con olio extravergine e limone.",note_en:"Grill the chicken breast with sliced zucchini and eggplant. Boil the farro and combine all the diced ingredients. Dress with extra virgin oil and lemon.",ingredienti:[{nome:"Petto di pollo",qt:"200g"},{nome:"Farro",qt:"150g"},{nome:"Zucchine",qt:"100g"},{nome:"Melanzane",qt:"100g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di pollo, farro e verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:370,p:31,gs:2,g:11,z:4,ch:38,fi:6,ca:45,fe:2.4,mg:58,k2:580,na:200,zn:1.7,fo:65,se:22,col:70}},{id:"tpl_1897",nome:"Insalata di lenticchie, tonno e pomodori",nome_en:"Lentil salad with tuna and tomatoes",categoria:"Insalata",porzioni:2,note:"Scolare le lenticchie lessate e il tonno e unirli in una ciotola. Aggiungere pomodori a cubetti e cipollotto affettato. Condire con olio extravergine e origano.",note_en:"Drain the boiled lentils and tuna and combine in a bowl. Add diced tomatoes and sliced spring onion. Dress with extra virgin oil and oregano.",ingredienti:[{nome:"Lenticchie lessate",qt:"250g"},{nome:"Tonno sott'olio",qt:"160g"},{nome:"Pomodori",qt:"150g"},{nome:"Cipollotto",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di lenticchie, tonno e pomodori (ricetta)",c:"Ricette",src:"RICETTE",k:360,p:28,gs:2.5,g:15,z:4,ch:30,fi:9,ca:65,fe:4,mg:60,k2:600,na:400,zn:2,fo:130,se:35,col:30}},{id:"tpl_1898",nome:"Insalata di ceci, uova e speck croccante",nome_en:"Chickpea salad with eggs and crispy speck",categoria:"Insalata",porzioni:2,note:"Scolare i ceci lessati e rosolare lo speck a listarelle fino a renderlo croccante. Unire uova sode a spicchi. Condire con olio extravergine e prezzemolo tritato.",note_en:"Drain the boiled chickpeas and sauté the speck strips until crispy. Add hard-boiled egg wedges. Dress with extra virgin oil and chopped parsley.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Uova",qt:"2"},{nome:"Speck",qt:"80g"},{nome:"Prezzemolo",qt:"q.b."},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata di ceci, uova e speck croccante (ricetta)",c:"Ricette",src:"RICETTE",k:390,p:23,gs:6,g:20,z:3,ch:32,fi:9,ca:90,fe:4.2,mg:65,k2:600,na:680,zn:2,fo:130,se:20,col:230}},{id:"tpl_1899",nome:"Insalata di farro, verdure e feta greca",nome_en:"Farro salad with vegetables and Greek feta",categoria:"Insalata",porzioni:4,note:"Lessare il farro e lasciarlo raffreddare. Unire cetrioli e peperoni a cubetti e feta greca sbriciolata. Condire con olio extravergine, origano e limone.",note_en:"Boil the farro and let it cool. Add diced cucumbers and peppers and crumbled Greek feta. Dress with extra virgin oil, oregano and lemon.",ingredienti:[{nome:"Farro",qt:"250g"},{nome:"Cetrioli",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Feta greca",qt:"150g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Insalata di farro, verdure e feta greca (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:12,gs:6,g:15,z:5,ch:42,fi:6,ca:210,fe:2.5,mg:50,k2:400,na:480,zn:1.6,fo:60,se:8,col:25}},{id:"tpl_1900",nome:"Insalata mista di stagione con noci e formaggio",nome_en:"Mixed seasonal salad with walnuts and cheese",categoria:"Insalata",porzioni:2,note:"Lavare insalata mista di stagione e disporla in una ciotola. Aggiungere cubetti di formaggio stagionato e gherigli di noci. Condire con olio extravergine, aceto balsamico e sale.",note_en:"Wash mixed seasonal salad leaves and arrange in a bowl. Add cubes of aged cheese and walnut kernels. Dress with extra virgin oil, balsamic vinegar and salt.",ingredienti:[{nome:"Insalata mista",qt:"150g"},{nome:"Formaggio stagionato",qt:"100g"},{nome:"Noci",qt:"40g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Aceto balsamico",qt:"1 cucchiaio"}],_dbEntry:{n:"Insalata mista di stagione con noci e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:14,gs:9,g:27,z:3,ch:8,fi:2.5,ca:280,fe:1.4,mg:50,k2:300,na:420,zn:1.8,fo:35,se:10,col:40}},{id:"tpl_1901",nome:"Bruschetta al pomodoro e basilico (versione 3)",nome_en:"Bruschetta with tomato and basil (version 3)",categoria:"Antipasto",porzioni:4,note:"Tagliare il pane a fette e tostarlo in forno o su griglia. Strofinare uno spicchio di aglio sulla superficie ancora calda. Condire i pomodori a cubetti con basilico, sale e olio, quindi distribuirli sulle fette di pane.",note_en:"Slice the bread and toast it in the oven or on a griddle. Rub a garlic clove over the still-warm surface. Season the diced tomatoes with basil, salt and oil, then spoon over the bread slices.",ingredienti:[{nome:"Pane casereccio",qt:"200g"},{nome:"Pomodori maturi",qt:"300g"},{nome:"Basilico fresco",qt:"10g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Bruschetta al pomodoro e basilico (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:4,gs:1.2,g:8,z:3,ch:28,fi:2,ca:30,fe:1,mg:15,k2:150,na:200,zn:.5,fo:15,se:3,col:0}},{id:"tpl_1902",nome:"Bruschetta con burrata e alici",nome_en:"Bruschetta with burrata and anchovies",categoria:"Antipasto",porzioni:4,note:"Tostare le fette di pane fino a doratura. Adagiare su ognuna la burrata a pezzi, i pomodorini tagliati e le alici sott'olio. Completare con un filo di olio extravergine.",note_en:"Toast the bread slices until golden. Top each with pieces of burrata, halved cherry tomatoes and anchovy fillets. Finish with a drizzle of extra virgin olive oil.",ingredienti:[{nome:"Pane casereccio",qt:"200g"},{nome:"Burrata",qt:"200g"},{nome:"Alici sott'olio",qt:"40g"},{nome:"Pomodorini",qt:"100g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Bruschetta con burrata e alici (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:10,gs:6,g:18,z:2,ch:22,fi:1,ca:150,fe:1,mg:20,k2:150,na:350,zn:1,fo:10,se:5,col:30}},{id:"tpl_1903",nome:"Crostini di fegatini di pollo",nome_en:"Chicken liver crostini",categoria:"Antipasto",porzioni:4,note:"Rosolare la cipolla tritata nel burro, aggiungere i fegatini e sfumare con il vino bianco. Cuocere fino a cottura completa, unire i capperi e frullare grossolanamente. Spalmare la crema sulle fette di pane tostato.",note_en:"Sauté the chopped onion in butter, add the livers and deglaze with white wine. Cook through, stir in the capers and blend coarsely. Spread the pâté onto toasted bread slices.",ingredienti:[{nome:"Fegatini di pollo",qt:"300g"},{nome:"Pane casereccio",qt:"200g"},{nome:"Cipolla",qt:"50g"},{nome:"Vino bianco",qt:"30ml"},{nome:"Capperi",qt:"10g"},{nome:"Burro",qt:"20g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Crostini di fegatini di pollo (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:14,gs:3,g:10,z:1,ch:24,fi:1.5,ca:20,fe:4,mg:18,k2:220,na:250,zn:2,fo:150,se:10,col:180}},{id:"tpl_1904",nome:"Caprese classica",nome_en:"Classic caprese salad",categoria:"Antipasto",porzioni:4,note:"Affettare la mozzarella e i pomodori dello stesso spessore. Alternare le fette su un piatto da portata e guarnire con foglie di basilico. Condire con olio extravergine, sale e origano.",note_en:"Slice the mozzarella and tomatoes to the same thickness. Alternate the slices on a serving plate and garnish with basil leaves. Season with extra virgin olive oil, salt and oregano.",ingredienti:[{nome:"Mozzarella di bufala",qt:"320g"},{nome:"Pomodori cuore di bue",qt:"300g"},{nome:"Basilico fresco",qt:"10g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Origano",qt:"q.b."}],_dbEntry:{n:"Caprese classica (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:14,gs:7,g:20,z:3,ch:4,fi:1.5,ca:250,fe:.5,mg:20,k2:250,na:200,zn:1.5,fo:20,se:5,col:40}},{id:"tpl_1905",nome:"Involtini di melanzane alla ricotta",nome_en:"Eggplant rolls with ricotta",categoria:"Antipasto",porzioni:4,note:"Grigliare le fette di melanzana tagliate per il lungo. Mescolare la ricotta con parmigiano, basilico e un pizzico di sale. Distribuire il ripieno sulle fette e arrotolarle, servendo con un filo di olio.",note_en:"Grill the eggplant slices cut lengthwise. Mix the ricotta with parmesan, basil and a pinch of salt. Spread the filling over the slices and roll them up, serving with a drizzle of oil.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Ricotta",qt:"200g"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Basilico fresco",qt:"5g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Involtini di melanzane alla ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:9,gs:4,g:11,z:4,ch:8,fi:3,ca:150,fe:.8,mg:20,k2:300,na:150,zn:1,fo:20,se:5,col:25}},{id:"tpl_1906",nome:"Tagliere di verdure grigliate",nome_en:"Grilled vegetable platter",categoria:"Antipasto",porzioni:4,note:"Tagliare zucchine, melanzane e peperoni a fette regolari. Grigliarle su piastra rovente fino a doratura leggera. Disporle su un tagliere e condire con olio, aceto balsamico e aglio tritato.",note_en:"Cut the zucchini, eggplant and peppers into even slices. Grill them on a hot griddle until lightly charred. Arrange on a board and season with oil, balsamic vinegar and chopped garlic.",ingredienti:[{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aceto balsamico",qt:"10ml"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Tagliere di verdure grigliate (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:3,gs:1,g:9,z:6,ch:10,fi:4,ca:30,fe:1,mg:25,k2:400,na:50,zn:.5,fo:40,se:2,col:0}},{id:"tpl_1907",nome:"Carpaccio di manzo al limone",nome_en:"Beef carpaccio with lemon",categoria:"Antipasto",porzioni:4,note:"Affettare sottilmente il controfiletto crudo e disporlo su un piatto. Condire con succo di limone, olio extravergine e sale. Completare con rucola fresca e scaglie di grana.",note_en:"Thinly slice the raw sirloin and arrange on a plate. Dress with lemon juice, extra virgin olive oil and salt. Finish with fresh arugula and shaved grana cheese.",ingredienti:[{nome:"Controfiletto di manzo",qt:"320g"},{nome:"Limone",qt:"1"},{nome:"Rucola",qt:"40g"},{nome:"Grana a scaglie",qt:"40g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Carpaccio di manzo al limone (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:22,gs:5,g:18,z:.5,ch:1,fi:.5,ca:120,fe:2.5,mg:25,k2:350,na:150,zn:4,fo:15,se:15,col:60}},{id:"tpl_1908",nome:"Vitello tonnato leggero",nome_en:"Light vitello tonnato",categoria:"Antipasto",porzioni:4,note:"Cuocere il girello di vitello in acqua aromatizzata e lasciarlo raffreddare, quindi affettarlo sottile. Frullare il tonno con lo yogurt greco, i capperi e le acciughe fino a ottenere una crema. Nappare le fette di vitello con la salsa e servire freddo.",note_en:"Poach the veal in aromatic water, let it cool, then slice thinly. Blend the tuna with Greek yogurt, capers and anchovies into a smooth sauce. Coat the veal slices with the sauce and serve cold.",ingredienti:[{nome:"Girello di vitello",qt:"400g"},{nome:"Tonno sott'olio",qt:"100g"},{nome:"Yogurt greco",qt:"100g"},{nome:"Capperi",qt:"15g"},{nome:"Acciughe",qt:"10g"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Vitello tonnato leggero (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:26,gs:2,g:9,z:1,ch:2,fi:.3,ca:40,fe:1.5,mg:28,k2:380,na:300,zn:3,fo:10,se:20,col:70}},{id:"tpl_1909",nome:"Polpo e patate",nome_en:"Octopus and potato salad",categoria:"Antipasto",porzioni:4,note:"Lessare il polpo in acqua fino a renderlo tenero, quindi tagliarlo a pezzi. Lessare separatamente le patate e tagliarle a cubetti. Unire i due ingredienti, condire con olio, limone e prezzemolo tritato.",note_en:"Boil the octopus in water until tender, then cut into pieces. Separately boil the potatoes and dice them. Combine the two, dressing with oil, lemon and chopped parsley.",ingredienti:[{nome:"Polpo",qt:"500g"},{nome:"Patate",qt:"300g"},{nome:"Prezzemolo",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Polpo e patate (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:20,gs:1,g:9,z:1,ch:15,fi:1.5,ca:30,fe:2,mg:50,k2:500,na:250,zn:1.5,fo:25,se:35,col:60}},{id:"tpl_1910",nome:"Affettati misti con verdure sott'olio",nome_en:"Mixed cured meats with pickled vegetables",categoria:"Antipasto",porzioni:4,note:"Disporre su un tagliere il prosciutto crudo e il salame affettati sottilmente. Aggiungere le verdure grigliate sott'olio ben scolate. Servire accompagnato da fette di pane casereccio.",note_en:"Arrange thinly sliced prosciutto and salami on a board. Add well-drained oil-preserved grilled vegetables. Serve with slices of country bread.",ingredienti:[{nome:"Prosciutto crudo",qt:"120g"},{nome:"Salame",qt:"80g"},{nome:"Verdure grigliate sott'olio",qt:"200g"},{nome:"Pane casereccio",qt:"100g"}],_dbEntry:{n:"Affettati misti con verdure sott'olio (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:16,gs:6,g:20,z:2,ch:14,fi:2,ca:30,fe:1.2,mg:20,k2:250,na:700,zn:1.5,fo:15,se:10,col:50}},{id:"tpl_1911",nome:"Cozze alla marinara",nome_en:"Marinara-style mussels",categoria:"Antipasto",porzioni:4,note:"Pulire bene le cozze eliminando il bisso. Rosolare aglio e prezzemolo in olio, aggiungere le cozze e sfumare con vino bianco. Unire i pomodorini e cuocere con coperchio finché le cozze si aprono.",note_en:"Clean the mussels thoroughly, removing the beard. Sauté garlic and parsley in oil, add the mussels and deglaze with white wine. Add cherry tomatoes and cook covered until the mussels open.",ingredienti:[{nome:"Cozze",qt:"800g"},{nome:"Pomodorini",qt:"150g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Prezzemolo",qt:"10g"},{nome:"Vino bianco",qt:"50ml"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Cozze alla marinara (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:16,gs:1,g:8,z:2,ch:6,fi:1,ca:50,fe:5,mg:30,k2:350,na:400,zn:2,fo:15,se:30,col:40}},{id:"tpl_1912",nome:"Insalata di mare",nome_en:"Seafood salad",categoria:"Antipasto",porzioni:4,note:"Lessare separatamente calamari, gamberi e cozze fino a cottura. Tagliare i calamari ad anelli e sgusciare i gamberi. Unire tutto con il sedano a fettine, condire con olio, limone e prezzemolo.",note_en:"Separately boil the squid, shrimp and mussels until cooked. Slice the squid into rings and shell the shrimp. Combine everything with sliced celery, dressing with oil, lemon and parsley.",ingredienti:[{nome:"Calamari",qt:"150g"},{nome:"Gamberi",qt:"150g"},{nome:"Cozze",qt:"150g"},{nome:"Sedano",qt:"50g"},{nome:"Limone",qt:"mezzo"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Prezzemolo",qt:"5g"}],_dbEntry:{n:"Insalata di mare (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:20,gs:1,g:9,z:.5,ch:3,fi:.5,ca:60,fe:2,mg:35,k2:350,na:300,zn:2,fo:20,se:40,col:150}},{id:"tpl_1913",nome:"Prosciutto e melone",nome_en:"Prosciutto and melon",categoria:"Antipasto",porzioni:4,note:"Tagliare il melone a spicchi o a palline, eliminando i semi. Avvolgere ogni porzione con una fetta sottile di prosciutto crudo. Servire ben freddo.",note_en:"Cut the melon into wedges or balls, removing the seeds. Wrap each portion with a thin slice of prosciutto. Serve well chilled.",ingredienti:[{nome:"Melone",qt:"400g"},{nome:"Prosciutto crudo",qt:"120g"}],_dbEntry:{n:"Prosciutto e melone (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:9,gs:1.5,g:5,z:14,ch:16,fi:1,ca:15,fe:.8,mg:15,k2:300,na:500,zn:1,fo:20,se:8,col:30}},{id:"tpl_1914",nome:"Crostini con crema di carciofi",nome_en:"Crostini with artichoke cream",categoria:"Antipasto",porzioni:4,note:"Pulire i carciofi e stufarli con aglio e olio fino a renderli morbidi. Frullarli con succo di limone fino a ottenere una crema liscia. Spalmarla sulle fette di pane tostato.",note_en:"Clean the artichokes and stew them with garlic and oil until soft. Blend with lemon juice into a smooth cream. Spread onto toasted bread slices.",ingredienti:[{nome:"Carciofi",qt:"300g"},{nome:"Pane casereccio",qt:"150g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Crostini con crema di carciofi (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:1,g:10,z:2,ch:24,fi:4,ca:30,fe:1.2,mg:20,k2:300,na:150,zn:.6,fo:40,se:3,col:0}},{id:"tpl_1915",nome:"Bresaola con rucola e grana",nome_en:"Bresaola with arugula and grana cheese",categoria:"Antipasto",porzioni:4,note:"Disporre le fette di bresaola su un piatto largo. Guarnire con rucola fresca e scaglie di grana. Condire con olio extravergine e succo di limone.",note_en:"Arrange the bresaola slices on a large plate. Garnish with fresh arugula and grana shavings. Dress with extra virgin olive oil and lemon juice.",ingredienti:[{nome:"Bresaola",qt:"200g"},{nome:"Rucola",qt:"60g"},{nome:"Grana a scaglie",qt:"50g"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Bresaola con rucola e grana (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:24,gs:4,g:14,z:.5,ch:1,fi:1,ca:200,fe:2,mg:30,k2:350,na:500,zn:3,fo:30,se:15,col:50}},{id:"tpl_1916",nome:"Vol-au-vent ai funghi",nome_en:"Mushroom vol-au-vent",categoria:"Antipasto",porzioni:4,note:"Saltare i funghi champignon affettati in burro fino a farli asciugare. Aggiungere la panna e il prezzemolo, facendo restringere leggermente. Riempire i vol-au-vent già cotti e servire tiepidi.",note_en:"Sauté the sliced mushrooms in butter until dry. Add the cream and parsley, letting it reduce slightly. Fill the pre-baked vol-au-vent shells and serve warm.",ingredienti:[{nome:"Vol-au-vent (pasta sfoglia)",qt:"4 pz"},{nome:"Funghi champignon",qt:"250g"},{nome:"Panna fresca",qt:"100ml"},{nome:"Prezzemolo",qt:"5g"},{nome:"Burro",qt:"20g"}],_dbEntry:{n:"Vol-au-vent ai funghi (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:5,gs:7,g:16,z:2,ch:22,fi:1.5,ca:30,fe:1,mg:15,k2:250,na:200,zn:.7,fo:15,se:5,col:35}},{id:"tpl_1917",nome:"Peperoni ripieni freddi",nome_en:"Cold stuffed peppers",categoria:"Antipasto",porzioni:4,note:"Arrostire i peperoni interi e privarli della pelle. Mescolare il tonno sgocciolato con capperi, olive tritate e pane grattugiato. Farcire i peperoni con il composto e lasciar riposare in frigorifero prima di servire.",note_en:"Roast the whole peppers and peel off the skin. Mix the drained tuna with capers, chopped olives and breadcrumbs. Stuff the peppers with the mixture and chill before serving.",ingredienti:[{nome:"Peperoni",qt:"4"},{nome:"Tonno sott'olio",qt:"150g"},{nome:"Capperi",qt:"10g"},{nome:"Olive nere",qt:"40g"},{nome:"Pane grattugiato",qt:"20g"}],_dbEntry:{n:"Peperoni ripieni freddi (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:12,gs:1.5,g:9,z:5,ch:10,fi:2,ca:30,fe:1.2,mg:20,k2:350,na:350,zn:.8,fo:30,se:15,col:20}},{id:"tpl_1918",nome:"Involtini di prosciutto e formaggio",nome_en:"Ham and cheese rolls",categoria:"Antipasto",porzioni:4,note:"Stendere le fette di prosciutto cotto su un tagliere. Adagiare sopra la fontina a listarelle e la rucola. Arrotolare stretto e tagliare a metà prima di servire.",note_en:"Lay the cooked ham slices on a board. Place strips of fontina and arugula on top. Roll tightly and cut in half before serving.",ingredienti:[{nome:"Prosciutto cotto",qt:"200g"},{nome:"Fontina",qt:"150g"},{nome:"Rucola",qt:"30g"}],_dbEntry:{n:"Involtini di prosciutto e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:18,gs:9,g:19,z:.5,ch:1,fi:.3,ca:250,fe:.8,mg:15,k2:150,na:600,zn:2,fo:10,se:8,col:55}},{id:"tpl_1919",nome:"Panzanella",nome_en:"Panzanella bread salad",categoria:"Antipasto",porzioni:4,note:"Ammorbidire il pane raffermo in acqua e strizzarlo bene. Sbriciolarlo in una ciotola con pomodori, cetrioli e cipolla rossa a fette. Condire con olio, aceto, sale e basilico spezzettato.",note_en:"Soak the stale bread in water and squeeze it well. Crumble it into a bowl with tomatoes, cucumbers and sliced red onion. Dress with oil, vinegar, salt and torn basil.",ingredienti:[{nome:"Pane raffermo",qt:"200g"},{nome:"Pomodori",qt:"300g"},{nome:"Cetrioli",qt:"150g"},{nome:"Cipolla rossa",qt:"50g"},{nome:"Basilico",qt:"5g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Aceto di vino",qt:"15ml"}],_dbEntry:{n:"Panzanella (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:1,g:10,z:5,ch:30,fi:3,ca:30,fe:1.5,mg:25,k2:300,na:150,zn:.6,fo:25,se:3,col:0}},{id:"tpl_1920",nome:"Frittatine di zucchine (versione 2)",nome_en:"Small zucchini frittatas (version 2)",categoria:"Antipasto",porzioni:4,note:"Sbattere le uova con il parmigiano e la menta tritata. Aggiungere le zucchine grattugiate o a fettine sottili. Cuocere piccole porzioni in padella con un filo di olio fino a doratura su entrambi i lati.",note_en:"Beat the eggs with parmesan and chopped mint. Add the grated or thinly sliced zucchini. Cook small portions in a pan with a drizzle of oil until golden on both sides.",ingredienti:[{nome:"Uova",qt:"4"},{nome:"Zucchine",qt:"250g"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Olio extravergine",qt:"15ml"},{nome:"Menta",qt:"q.b."}],_dbEntry:{n:"Frittatine di zucchine (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:11,gs:3,g:13,z:2,ch:4,fi:1,ca:100,fe:1.5,mg:20,k2:250,na:150,zn:1,fo:30,se:15,col:190}},{id:"tpl_1921",nome:"Arancini di riso",nome_en:"Rice arancini",categoria:"Antipasto",porzioni:4,note:"Cuocere il riso e condirlo con parte del ragù. Formare palline riempite con ragù, piselli e mozzarella a cubetti. Passarle in uovo e pangrattato e friggerle in olio caldo fino a doratura.",note_en:"Cook the rice and season with some of the ragù. Shape balls filled with ragù, peas and diced mozzarella. Coat in egg and breadcrumbs, then fry in hot oil until golden.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Ragù di carne",qt:"150g"},{nome:"Piselli",qt:"50g"},{nome:"Mozzarella",qt:"100g"},{nome:"Uova",qt:"1"},{nome:"Pangrattato",qt:"60g"},{nome:"Olio di semi per friggere",qt:"100ml"}],_dbEntry:{n:"Arancini di riso (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:10,gs:4,g:14,z:2,ch:35,fi:2,ca:80,fe:1.5,mg:25,k2:200,na:300,zn:1.2,fo:20,se:8,col:40}},{id:"tpl_1922",nome:"Supplì al telefono",nome_en:"Suppli al telefono",categoria:"Antipasto",porzioni:4,note:"Cuocere il riso nella passata di pomodoro fino ad assorbimento. Formare i supplì inserendo un cubetto di mozzarella al centro di ognuno. Impanare e friggere in olio caldo fino a doratura croccante.",note_en:"Cook the rice in the tomato passata until absorbed. Shape the suppli, inserting a cube of mozzarella in the center of each. Bread and fry in hot oil until crisply golden.",ingredienti:[{nome:"Riso",qt:"300g"},{nome:"Passata di pomodoro",qt:"150g"},{nome:"Mozzarella",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Uova",qt:"1"},{nome:"Pangrattato",qt:"60g"},{nome:"Olio di semi",qt:"100ml"}],_dbEntry:{n:"Supplì al telefono (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:9,gs:4,g:13,z:3,ch:36,fi:1.5,ca:120,fe:1,mg:20,k2:200,na:350,zn:1,fo:15,se:5,col:40}},{id:"tpl_1923",nome:"Polpette di melanzane",nome_en:"Eggplant fritters",categoria:"Antipasto",porzioni:4,note:"Lessare le melanzane e strizzarle bene. Impastarle con pane raffermo ammollato, parmigiano, uovo e prezzemolo. Formare le polpette e friggerle in olio caldo fino a doratura.",note_en:"Boil the eggplant and squeeze it well. Mix with soaked stale bread, parmesan, egg and parsley. Shape into balls and fry in hot oil until golden.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Pane raffermo",qt:"80g"},{nome:"Parmigiano grattugiato",qt:"40g"},{nome:"Uova",qt:"1"},{nome:"Prezzemolo",qt:"5g"},{nome:"Olio per friggere",qt:"50ml"}],_dbEntry:{n:"Polpette di melanzane (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:6,gs:2,g:10,z:3,ch:16,fi:3,ca:100,fe:1,mg:18,k2:300,na:200,zn:.7,fo:20,se:4,col:50}},{id:"tpl_1924",nome:"Chips di parmigiano",nome_en:"Parmesan crisps",categoria:"Antipasto",porzioni:4,note:"Formare piccoli mucchietti di parmigiano grattugiato su una teglia rivestita di carta forno. Cuocere in forno caldo finché non si sciolgono e dorano. Lasciar raffreddare fino a farli diventare croccanti, spolverando di pepe.",note_en:"Form small mounds of grated parmesan on a parchment-lined tray. Bake in a hot oven until melted and golden. Let cool until crisp, dusting with pepper.",ingredienti:[{nome:"Parmigiano grattugiato",qt:"200g"},{nome:"Pepe nero",qt:"q.b."}],_dbEntry:{n:"Chips di parmigiano (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:14,gs:7,g:12,z:0,ch:1,fi:0,ca:400,fe:.2,mg:10,k2:30,na:350,zn:2,fo:5,se:5,col:30}},{id:"tpl_1925",nome:"Uova sode ripiene",nome_en:"Stuffed hard-boiled eggs",categoria:"Antipasto",porzioni:4,note:"Lessare le uova, sgusciarle e tagliarle a metà. Estrarre i tuorli e mescolarli con maionese, tonno sgocciolato e capperi tritati. Riempire nuovamente gli albumi con il composto.",note_en:"Boil the eggs, shell and halve them. Remove the yolks and mix with mayonnaise, drained tuna and chopped capers. Refill the egg whites with the mixture.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Maionese",qt:"40g"},{nome:"Tonno sott'olio",qt:"40g"},{nome:"Capperi",qt:"5g"}],_dbEntry:{n:"Uova sode ripiene (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:9,gs:3,g:15,z:.5,ch:1,fi:0,ca:30,fe:1,mg:10,k2:100,na:250,zn:1,fo:40,se:15,col:250}},{id:"tpl_1926",nome:"Caponata siciliana (versione 2)",nome_en:"Sicilian caponata (version 2)",categoria:"Antipasto",porzioni:4,note:"Friggere le melanzane a cubetti e metterle da parte. Nella stessa padella stufare sedano e cipolla, aggiungere olive, capperi e passata di pomodoro. Unire le melanzane, zucchero e aceto, cuocendo finché si amalgama tutto.",note_en:"Fry the diced eggplant and set aside. In the same pan, stew celery and onion, add olives, capers and tomato passata. Combine with the eggplant, sugar and vinegar, cooking until well blended.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Sedano",qt:"100g"},{nome:"Olive verdi",qt:"60g"},{nome:"Capperi",qt:"15g"},{nome:"Passata di pomodoro",qt:"150g"},{nome:"Cipolla",qt:"50g"},{nome:"Zucchero",qt:"10g"},{nome:"Aceto di vino",qt:"20ml"},{nome:"Olio extravergine",qt:"40ml"}],_dbEntry:{n:"Caponata siciliana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:2,gs:1,g:14,z:7,ch:14,fi:4,ca:40,fe:1.2,mg:25,k2:350,na:350,zn:.5,fo:25,se:2,col:0}},{id:"tpl_1927",nome:"Farinata di ceci",nome_en:"Chickpea flour flatbread",categoria:"Antipasto",porzioni:4,note:"Stemperare la farina di ceci nell'acqua evitando grumi e lasciar riposare. Aggiungere olio e sale, versare in una teglia unta. Cuocere in forno molto caldo finché la superficie è dorata e croccante.",note_en:"Whisk the chickpea flour into the water avoiding lumps and let it rest. Add oil and salt, pour into a greased pan. Bake in a very hot oven until the surface is golden and crisp.",ingredienti:[{nome:"Farina di ceci",qt:"200g"},{nome:"Acqua",qt:"500ml"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Rosmarino",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Farinata di ceci (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:7,gs:1,g:11,z:1,ch:20,fi:4,ca:30,fe:2,mg:40,k2:300,na:200,zn:1,fo:100,se:5,col:0}},{id:"tpl_1928",nome:"Focaccia con rosmarino a listarelle",nome_en:"Rosemary focaccia strips",categoria:"Antipasto",porzioni:4,note:"Impastare la farina con acqua, lievito e olio, lasciando lievitare fino al raddoppio. Stendere l'impasto in teglia, cospargere con rosmarino e sale grosso. Cuocere in forno caldo e tagliare a listarelle.",note_en:"Knead the flour with water, yeast and oil, letting it rise until doubled. Spread the dough in a pan, sprinkle with rosemary and coarse salt. Bake in a hot oven and cut into strips.",ingredienti:[{nome:"Farina 00",qt:"300g"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Lievito di birra",qt:"5g"},{nome:"Rosmarino",qt:"q.b."},{nome:"Sale grosso",qt:"q.b."}],_dbEntry:{n:"Focaccia con rosmarino a listarelle (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:6,gs:1.5,g:10,z:1,ch:35,fi:1.5,ca:15,fe:1.5,mg:15,k2:100,na:350,zn:.5,fo:30,se:10,col:0}},{id:"tpl_1929",nome:"Insalata di polpo e sedano",nome_en:"Octopus and celery salad",categoria:"Antipasto",porzioni:4,note:"Lessare il polpo finché è tenero e tagliarlo a pezzetti. Unirlo al sedano affettato sottile e alle olive taggiasche. Condire con olio extravergine e succo di limone.",note_en:"Boil the octopus until tender and cut into pieces. Combine with thinly sliced celery and taggiasca olives. Dress with extra virgin olive oil and lemon juice.",ingredienti:[{nome:"Polpo",qt:"400g"},{nome:"Sedano",qt:"150g"},{nome:"Olive taggiasche",qt:"40g"},{nome:"Limone",qt:"mezzo"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Insalata di polpo e sedano (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:19,gs:1,g:10,z:1,ch:4,fi:1.5,ca:40,fe:2,mg:45,k2:450,na:300,zn:1.5,fo:20,se:35,col:55}},{id:"tpl_1930",nome:"Tartare di tonno",nome_en:"Tuna tartare",categoria:"Antipasto",porzioni:4,note:"Tagliare il tonno fresco a piccoli cubetti con un coltello affilato. Condire con salsa di soia, succo di lime e semi di sesamo. Servire con fette di avocado a completare il piatto.",note_en:"Cut the fresh tuna into small cubes with a sharp knife. Season with soy sauce, lime juice and sesame seeds. Serve with avocado slices to complete the dish.",ingredienti:[{nome:"Tonno fresco",qt:"320g"},{nome:"Avocado",qt:"100g"},{nome:"Salsa di soia",qt:"20ml"},{nome:"Semi di sesamo",qt:"10g"},{nome:"Lime",qt:"mezzo"}],_dbEntry:{n:"Tartare di tonno (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:24,gs:2,g:13,z:1,ch:4,fi:2,ca:20,fe:1.5,mg:40,k2:450,na:350,zn:1,fo:15,se:50,col:40}},{id:"tpl_1931",nome:"Alici marinate",nome_en:"Marinated anchovies",categoria:"Antipasto",porzioni:4,note:"Pulire le alici fresche eliminando lisca e testa. Disporle in un contenitore e coprirle con succo di limone, lasciando marinare in frigorifero. Condire poi con aglio tritato, prezzemolo e olio extravergine.",note_en:"Clean the fresh anchovies, removing bone and head. Place them in a container and cover with lemon juice, letting them marinate in the fridge. Then season with chopped garlic, parsley and extra virgin olive oil.",ingredienti:[{nome:"Alici fresche",qt:"400g"},{nome:"Limone",qt:"2"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Alici marinate (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:18,gs:1.5,g:10,z:.5,ch:1,fi:.2,ca:50,fe:1.5,mg:30,k2:300,na:200,zn:1,fo:10,se:35,col:50}},{id:"tpl_1932",nome:"Baccalà mantecato",nome_en:"Creamed salt cod",categoria:"Antipasto",porzioni:4,note:"Lessare il baccalà già dissalato nel latte fino a cottura. Sminuzzarlo e montarlo con l'olio a filo, aglio e prezzemolo, fino a ottenere una crema morbida. Servire su fette di polenta abbrustolita.",note_en:"Poach the pre-soaked salt cod in milk until cooked. Flake it and whip in the oil gradually with garlic and parsley until creamy. Serve on slices of toasted polenta.",ingredienti:[{nome:"Baccalà dissalato",qt:"400g"},{nome:"Latte",qt:"100ml"},{nome:"Olio extravergine",qt:"60ml"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"5g"},{nome:"Polenta",qt:"200g"}],_dbEntry:{n:"Baccalà mantecato (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:20,gs:2,g:16,z:1,ch:10,fi:.5,ca:40,fe:1,mg:35,k2:350,na:300,zn:1,fo:10,se:40,col:60}},{id:"tpl_1933",nome:"Crostini con lardo di colonnata",nome_en:"Crostini with lardo di Colonnata",categoria:"Antipasto",porzioni:4,note:"Tostare le fette di pane casereccio fino a doratura. Adagiare sopra fettine sottili di lardo di Colonnata ancora calde sul pane. Completare con rosmarino tritato e un filo di miele.",note_en:"Toast the country bread slices until golden. Lay thin slices of Lardo di Colonnata on the still-warm bread. Finish with chopped rosemary and a drizzle of honey.",ingredienti:[{nome:"Pane casereccio",qt:"200g"},{nome:"Lardo di Colonnata",qt:"100g"},{nome:"Rosmarino",qt:"q.b."},{nome:"Miele",qt:"10g"}],_dbEntry:{n:"Crostini con lardo di colonnata (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:5,gs:7,g:18,z:4,ch:24,fi:1,ca:15,fe:1,mg:10,k2:100,na:350,zn:.7,fo:15,se:5,col:30}},{id:"tpl_1934",nome:"Salmone affumicato con crema di ricotta",nome_en:"Smoked salmon with ricotta cream",categoria:"Antipasto",porzioni:4,note:"Montare la ricotta con erba cipollina tritata fino a renderla cremosa. Spalmarla su fette di pane nero e adagiarvi sopra il salmone affumicato. Completare con una spruzzata di succo di limone.",note_en:"Whip the ricotta with chopped chives until creamy. Spread onto slices of dark bread and top with smoked salmon. Finish with a squeeze of lemon juice.",ingredienti:[{nome:"Salmone affumicato",qt:"160g"},{nome:"Ricotta",qt:"150g"},{nome:"Erba cipollina",qt:"5g"},{nome:"Pane nero",qt:"100g"},{nome:"Limone",qt:"mezzo"}],_dbEntry:{n:"Salmone affumicato con crema di ricotta (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:16,gs:4,g:14,z:2,ch:18,fi:1.5,ca:90,fe:1,mg:25,k2:300,na:450,zn:1,fo:15,se:20,col:35}},{id:"tpl_1935",nome:"Torta salata di verdure",nome_en:"Savory vegetable pie",categoria:"Antipasto",porzioni:4,note:"Stendere la pasta sfoglia in uno stampo. Saltare zucchine e spinaci, quindi mescolarli con uova sbattute, formaggio filante e parmigiano. Versare il ripieno sulla base e cuocere in forno fino a doratura.",note_en:"Roll out the puff pastry into a mold. Sauté the zucchini and spinach, then mix with beaten eggs, melting cheese and parmesan. Pour the filling onto the base and bake until golden.",ingredienti:[{nome:"Pasta sfoglia",qt:"230g"},{nome:"Zucchine",qt:"150g"},{nome:"Spinaci",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Formaggio filante",qt:"100g"},{nome:"Parmigiano",qt:"20g"}],_dbEntry:{n:"Torta salata di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:9,gs:5,g:18,z:2,ch:22,fi:2,ca:150,fe:1.5,mg:20,k2:250,na:300,zn:1,fo:40,se:10,col:90}},{id:"tpl_1936",nome:"Involtini di speck e formaggio",nome_en:"Speck and cheese rolls",categoria:"Antipasto",porzioni:4,note:"Stendere le fette di speck su un tagliere. Spalmare sopra il formaggio spalmabile e cospargere di erba cipollina tritata. Arrotolare stretto e tagliare a rondelle prima di servire.",note_en:"Lay the speck slices on a board. Spread the soft cheese over them and sprinkle with chopped chives. Roll tightly and cut into rounds before serving.",ingredienti:[{nome:"Speck",qt:"160g"},{nome:"Formaggio molle spalmabile",qt:"100g"},{nome:"Erba cipollina",qt:"5g"}],_dbEntry:{n:"Involtini di speck e formaggio (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:14,gs:7,g:19,z:1,ch:2,fi:0,ca:100,fe:.5,mg:10,k2:150,na:500,zn:1,fo:5,se:8,col:55}},{id:"tpl_1937",nome:"Melanzane a funghetto",nome_en:"Mushroom-style eggplant",categoria:"Antipasto",porzioni:4,note:"Tagliare le melanzane a cubetti e saltarle in padella con olio e aglio. Aggiungere i pomodorini tagliati a metà e cuocere fino ad ammorbidire tutto. Completare con prezzemolo tritato prima di servire.",note_en:"Cut the eggplant into cubes and sauté in a pan with oil and garlic. Add the halved cherry tomatoes and cook until everything softens. Finish with chopped parsley before serving.",ingredienti:[{nome:"Melanzane",qt:"400g"},{nome:"Pomodorini",qt:"150g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"10g"},{nome:"Olio extravergine",qt:"30ml"}],_dbEntry:{n:"Melanzane a funghetto (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:2,gs:1,g:10,z:5,ch:9,fi:4,ca:25,fe:.8,mg:20,k2:300,na:150,zn:.4,fo:25,se:2,col:0}},{id:"tpl_1938",nome:"Gamberi in salsa cocktail",nome_en:"Shrimp cocktail",categoria:"Antipasto",porzioni:4,note:"Lessare i gamberi e lasciarli raffreddare. Mescolare maionese, ketchup e un goccio di brandy per la salsa cocktail. Disporre i gamberi su un letto di lattuga e condire con la salsa.",note_en:"Boil the shrimp and let them cool. Mix mayonnaise, ketchup and a splash of brandy for the cocktail sauce. Arrange the shrimp on a bed of lettuce and dress with the sauce.",ingredienti:[{nome:"Gamberi",qt:"400g"},{nome:"Maionese",qt:"40g"},{nome:"Ketchup",qt:"20g"},{nome:"Brandy",qt:"5ml"},{nome:"Lattuga",qt:"40g"}],_dbEntry:{n:"Gamberi in salsa cocktail (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:20,gs:1.5,g:11,z:4,ch:6,fi:.5,ca:50,fe:1,mg:30,k2:250,na:350,zn:1.5,fo:15,se:40,col:180}},{id:"tpl_1939",nome:"Insalata russa (versione 2)",nome_en:"Russian salad (version 2)",categoria:"Antipasto",porzioni:4,note:"Lessare patate e carote a cubetti insieme ai piselli. Lasciar raffreddare completamente le verdure. Condire con maionese e sottaceti tritati, mescolando bene.",note_en:"Boil diced potatoes and carrots together with the peas. Let the vegetables cool completely. Dress with mayonnaise and chopped pickles, mixing well.",ingredienti:[{nome:"Patate",qt:"200g"},{nome:"Carote",qt:"100g"},{nome:"Piselli",qt:"80g"},{nome:"Maionese",qt:"80g"},{nome:"Sottaceti",qt:"30g"}],_dbEntry:{n:"Insalata russa (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4,gs:2,g:16,z:4,ch:16,fi:3,ca:30,fe:1,mg:20,k2:350,na:300,zn:.5,fo:20,se:2,col:40}},{id:"tpl_1940",nome:"Crostini con hummus di ceci",nome_en:"Crostini with chickpea hummus",categoria:"Antipasto",porzioni:4,note:"Frullare i ceci lessati con tahina, aglio e succo di limone fino a ottenere una crema liscia. Aggiungere olio extravergine a filo per amalgamare. Spalmare l'hummus sulle fette di pane tostato.",note_en:"Blend the boiled chickpeas with tahini, garlic and lemon juice into a smooth cream. Add extra virgin olive oil gradually to bind. Spread the hummus onto toasted bread slices.",ingredienti:[{nome:"Ceci lessati",qt:"250g"},{nome:"Tahina",qt:"30g"},{nome:"Limone",qt:"mezzo"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Pane casereccio",qt:"150g"}],_dbEntry:{n:"Crostini con hummus di ceci (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:8,gs:1.5,g:11,z:2,ch:28,fi:5,ca:50,fe:2,mg:40,k2:300,na:200,zn:1,fo:80,se:4,col:0}},{id:"tpl_1941",nome:"Bruschette con crema di fave",nome_en:"Bruschette with fava bean cream",categoria:"Antipasto",porzioni:4,note:"Cuocere le fave secche decorticate fino a farle disfare, aggiungendo olio a filo. Passare la crema al setaccio per renderla vellutata. Servire su crostoni di pane con cicoria ripassata a lato.",note_en:"Cook the peeled dried fava beans until they break down, adding oil gradually. Pass the cream through a sieve for a velvety texture. Serve on bread slices with sautéed chicory on the side.",ingredienti:[{nome:"Fave secche decorticate",qt:"200g"},{nome:"Cicoria",qt:"100g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Pane casereccio",qt:"150g"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Bruschette con crema di fave (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:9,gs:1,g:10,z:2,ch:26,fi:6,ca:40,fe:2,mg:40,k2:350,na:150,zn:1,fo:60,se:4,col:0}},{id:"tpl_1942",nome:"Fagottini di bresaola e caprino",nome_en:"Bresaola and goat cheese bundles",categoria:"Antipasto",porzioni:4,note:"Stendere le fette di bresaola su un piano di lavoro. Farcire con formaggio caprino, rucola e gherigli di noce tritati. Richiudere a fagottino e servire freddo.",note_en:"Lay the bresaola slices on a work surface. Fill with goat cheese, arugula and chopped walnuts. Fold into small bundles and serve cold.",ingredienti:[{nome:"Bresaola",qt:"160g"},{nome:"Formaggio caprino",qt:"100g"},{nome:"Rucola",qt:"30g"},{nome:"Noci",qt:"20g"}],_dbEntry:{n:"Fagottini di bresaola e caprino (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:18,gs:5,g:15,z:.5,ch:2,fi:.8,ca:80,fe:1.5,mg:25,k2:300,na:450,zn:1.5,fo:10,se:10,col:45}},{id:"tpl_1943",nome:"Sformatini di verdure",nome_en:"Small vegetable timbales",categoria:"Antipasto",porzioni:4,note:"Cuocere a vapore zucchine e carote e frullarle grossolanamente. Mescolare con uova, parmigiano e besciamella. Versare negli stampini e cuocere a bagnomaria in forno finché rassodano.",note_en:"Steam the zucchini and carrots and coarsely blend them. Mix with eggs, parmesan and bechamel. Pour into molds and bake in a water bath until set.",ingredienti:[{nome:"Zucchine",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"30g"},{nome:"Panna fresca",qt:"50ml"},{nome:"Besciamella",qt:"50g"}],_dbEntry:{n:"Sformatini di verdure (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:9,gs:5,g:14,z:3,ch:9,fi:1.5,ca:120,fe:1,mg:15,k2:250,na:150,zn:.8,fo:25,se:10,col:140}},{id:"tpl_1944",nome:"Terrina di verdure grigliate (versione 2)",nome_en:"Grilled vegetable terrine (version 2)",categoria:"Antipasto",porzioni:4,note:"Grigliare melanzane, zucchine e peperoni a fette. Stratificarli in uno stampo alternando con basilico, aggiungendo la gelatina vegetale sciolta. Lasciar raffreddare in frigorifero prima di sformare e affettare.",note_en:"Grill the eggplant, zucchini and peppers into slices. Layer them in a mold alternating with basil, adding dissolved vegetable gelatin. Chill before unmolding and slicing.",ingredienti:[{nome:"Melanzane",qt:"150g"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Gelatina vegetale",qt:"5g"},{nome:"Basilico",qt:"5g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Terrina di verdure grigliate (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:2,gs:.5,g:7,z:6,ch:9,fi:3.5,ca:25,fe:.8,mg:22,k2:350,na:50,zn:.4,fo:35,se:2,col:0}},{id:"tpl_1945",nome:"Millefoglie di melanzane e pomodoro",nome_en:"Eggplant and tomato millefeuille",categoria:"Antipasto",porzioni:4,note:"Grigliare le fette di melanzana. Alternarle in piccoli stampi con fette di pomodoro e mozzarella, spolverando di parmigiano. Cuocere in forno pochi minuti finché il formaggio fonde, guarnendo con basilico.",note_en:"Grill the eggplant slices. Layer them in small molds with tomato and mozzarella slices, dusting with parmesan. Bake briefly until the cheese melts, garnishing with basil.",ingredienti:[{nome:"Melanzane",qt:"300g"},{nome:"Pomodori",qt:"200g"},{nome:"Mozzarella",qt:"150g"},{nome:"Basilico",qt:"5g"},{nome:"Parmigiano",qt:"20g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Millefoglie di melanzane e pomodoro (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:10,gs:4,g:13,z:4,ch:9,fi:2.5,ca:180,fe:.8,mg:20,k2:300,na:200,zn:1,fo:25,se:8,col:30}},{id:"tpl_1946",nome:"Patate al forno con rosmarino",nome_en:"Roasted potatoes with rosemary",categoria:"Contorno",porzioni:4,note:"Tagliare le patate a spicchi e condirle con olio, aglio e rosmarino. Disporle su una teglia in un solo strato. Cuocere in forno caldo finché sono dorate e croccanti fuori, morbide dentro.",note_en:"Cut the potatoes into wedges and season with oil, garlic and rosemary. Arrange on a tray in a single layer. Bake in a hot oven until golden and crisp outside, soft inside.",ingredienti:[{nome:"Patate",qt:"600g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Rosmarino",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Patate al forno con rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:3,gs:.5,g:7,z:1,ch:28,fi:2.5,ca:15,fe:1,mg:25,k2:450,na:150,zn:.4,fo:20,se:1,col:0}},{id:"tpl_1947",nome:"Spinaci saltati all'aglio",nome_en:"Sautéed spinach with garlic",categoria:"Contorno",porzioni:4,note:"Lavare bene gli spinaci e scolarli. Saltarli in padella con olio, aglio e un pizzico di peperoncino finché appassiscono. Servire caldi.",note_en:"Wash the spinach well and drain. Sauté in a pan with oil, garlic and a pinch of chili until wilted. Serve hot.",ingredienti:[{nome:"Spinaci freschi",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Peperoncino",qt:"q.b."}],_dbEntry:{n:"Spinaci saltati all'aglio (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:4,gs:.5,g:6,z:.5,ch:3,fi:3,ca:150,fe:3,mg:60,k2:500,na:100,zn:.6,fo:150,se:1,col:0}},{id:"tpl_1948",nome:"Melanzane alla parmigiana leggera",nome_en:"Light eggplant parmigiana",categoria:"Contorno",porzioni:4,note:"Grigliare le fette di melanzana invece di friggerle. Stratificarle in una teglia alternando con passata di pomodoro e mozzarella light. Cospargere di parmigiano e cuocere in forno finché gratinato.",note_en:"Grill the eggplant slices instead of frying. Layer them in a dish alternating with tomato passata and light mozzarella. Sprinkle with parmesan and bake until gratinated.",ingredienti:[{nome:"Melanzane grigliate",qt:"500g"},{nome:"Passata di pomodoro",qt:"200g"},{nome:"Mozzarella light",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Basilico",qt:"q.b."}],_dbEntry:{n:"Melanzane alla parmigiana leggera (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:11,gs:4,g:11,z:5,ch:9,fi:3,ca:200,fe:1,mg:25,k2:350,na:250,zn:1,fo:30,se:8,col:25}},{id:"tpl_1949",nome:"Zucchine trifolate (versione 2)",nome_en:"Sautéed zucchini (version 2)",categoria:"Contorno",porzioni:4,note:"Tagliare le zucchine a rondelle sottili. Saltarle in padella con olio e aglio fino ad ammorbidirle. Completare con prezzemolo tritato fresco.",note_en:"Slice the zucchini thinly. Sauté in a pan with oil and garlic until softened. Finish with fresh chopped parsley.",ingredienti:[{nome:"Zucchine",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"10g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Zucchine trifolate (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:2,gs:.5,g:7,z:4,ch:5,fi:2,ca:30,fe:.6,mg:25,k2:350,na:50,zn:.4,fo:35,se:1,col:0}},{id:"tpl_1950",nome:"Peperonata",nome_en:"Peperonata (stewed peppers)",categoria:"Contorno",porzioni:4,note:"Tagliare i peperoni a listarelle e la cipolla a fette. Stufarli in olio finché si ammorbidiscono. Aggiungere la passata di pomodoro e un pizzico di zucchero, cuocendo a fuoco lento.",note_en:"Cut the peppers into strips and slice the onion. Stew them in oil until softened. Add the tomato passata and a pinch of sugar, cooking gently.",ingredienti:[{nome:"Peperoni",qt:"500g"},{nome:"Cipolla",qt:"100g"},{nome:"Passata di pomodoro",qt:"100g"},{nome:"Olio extravergine",qt:"25ml"},{nome:"Zucchero",qt:"q.b."}],_dbEntry:{n:"Peperonata (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2,gs:.5,g:7,z:8,ch:10,fi:3,ca:25,fe:.8,mg:20,k2:300,na:100,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1951",nome:"Carciofi alla romana (versione 2)",nome_en:"Roman-style artichokes (version 2)",categoria:"Contorno",porzioni:4,note:"Pulire i carciofi eliminando le foglie esterne dure. Farcirli con mentuccia e aglio tritati, quindi disporli in una pentola con olio e vino bianco. Cuocere coperti a fuoco lento finché sono teneri.",note_en:"Clean the artichokes, removing the tough outer leaves. Stuff with chopped mint and garlic, then place in a pot with oil and white wine. Cook covered on low heat until tender.",ingredienti:[{nome:"Carciofi",qt:"4"},{nome:"Mentuccia",qt:"5g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"40ml"},{nome:"Vino bianco",qt:"30ml"}],_dbEntry:{n:"Carciofi alla romana (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:1,g:11,z:1,ch:10,fi:5,ca:50,fe:1.5,mg:40,k2:400,na:100,zn:.5,fo:90,se:1,col:0}},{id:"tpl_1952",nome:"Funghi trifolati (versione 2)",nome_en:"Sautéed mushrooms (version 2)",categoria:"Contorno",porzioni:4,note:"Pulire i funghi champignon e affettarli. Saltarli in padella con olio e aglio a fuoco vivace finché rilasciano l'acqua e si asciugano. Completare con prezzemolo tritato.",note_en:"Clean the mushrooms and slice them. Sauté in a pan with oil and garlic on high heat until they release their water and dry out. Finish with chopped parsley.",ingredienti:[{nome:"Funghi champignon",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo",qt:"10g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Funghi trifolati (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:.5,g:7,z:2,ch:4,fi:2,ca:15,fe:1,mg:20,k2:450,na:100,zn:1,fo:30,se:15,col:0}},{id:"tpl_1953",nome:"Insalata di fagiolini",nome_en:"Green bean salad",categoria:"Contorno",porzioni:4,note:"Lessare i fagiolini in acqua salata finché sono teneri ma ancora sodi. Scolarli e lasciarli raffreddare. Condire con cipolla rossa affettata, olio e aceto di vino.",note_en:"Boil the green beans in salted water until tender but still firm. Drain and let cool. Dress with sliced red onion, oil and wine vinegar.",ingredienti:[{nome:"Fagiolini",qt:"400g"},{nome:"Cipolla rossa",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto di vino",qt:"10ml"}],_dbEntry:{n:"Insalata di fagiolini (ricetta)",c:"Ricette",src:"RICETTE",k:85,p:2.5,gs:.5,g:6,z:4,ch:7,fi:3.5,ca:50,fe:1.2,mg:25,k2:300,na:50,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1954",nome:"Purè di patate",nome_en:"Mashed potatoes",categoria:"Contorno",porzioni:4,note:"Lessare le patate intere con la buccia finché sono morbide. Sbucciarle e schiacciarle ancora calde. Incorporare latte caldo e burro, mescolando fino a ottenere una crema liscia con un pizzico di noce moscata.",note_en:"Boil the potatoes whole with the skin on until soft. Peel and mash while still hot. Stir in hot milk and butter until smooth, with a pinch of nutmeg.",ingredienti:[{nome:"Patate",qt:"500g"},{nome:"Latte",qt:"150ml"},{nome:"Burro",qt:"40g"},{nome:"Noce moscata",qt:"q.b."}],_dbEntry:{n:"Purè di patate (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:4,gs:5,g:9,z:3,ch:24,fi:2,ca:60,fe:.8,mg:25,k2:450,na:150,zn:.5,fo:15,se:2,col:25}},{id:"tpl_1955",nome:"Cavolfiore gratinato",nome_en:"Gratinated cauliflower",categoria:"Contorno",porzioni:4,note:"Lessare il cavolfiore a cimette in acqua salata. Disporlo in una teglia e ricoprirlo con besciamella. Cospargere di parmigiano e gratinare in forno finché dorato.",note_en:"Boil the cauliflower florets in salted water. Arrange in a baking dish and cover with bechamel. Sprinkle with parmesan and gratinate in the oven until golden.",ingredienti:[{nome:"Cavolfiore",qt:"500g"},{nome:"Besciamella",qt:"150g"},{nome:"Parmigiano grattugiato",qt:"40g"}],_dbEntry:{n:"Cavolfiore gratinato (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:8,gs:5,g:11,z:4,ch:12,fi:3,ca:180,fe:1,mg:25,k2:350,na:200,zn:.8,fo:60,se:5,col:25}},{id:"tpl_1956",nome:"Broccoli saltati in padella",nome_en:"Pan-sautéed broccoli",categoria:"Contorno",porzioni:4,note:"Lessare brevemente i broccoli a cimette in acqua salata. Scolarli e saltarli in padella con olio, aglio e peperoncino. Servire ben caldi.",note_en:"Briefly boil the broccoli florets in salted water. Drain and sauté in a pan with oil, garlic and chili. Serve hot.",ingredienti:[{nome:"Broccoli",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Peperoncino",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Broccoli saltati in padella (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:4,gs:.5,g:6,z:2,ch:5,fi:3.5,ca:70,fe:1,mg:25,k2:350,na:50,zn:.5,fo:90,se:2,col:0}},{id:"tpl_1957",nome:"Carote al burro",nome_en:"Buttered carrots",categoria:"Contorno",porzioni:4,note:"Tagliare le carote a rondelle e lessarle in acqua salata. Scolarle e ripassarle in padella con burro e un pizzico di zucchero fino a caramellare leggermente. Guarnire con prezzemolo tritato.",note_en:"Cut the carrots into rounds and boil in salted water. Drain and toss in a pan with butter and a pinch of sugar until lightly caramelized. Garnish with chopped parsley.",ingredienti:[{nome:"Carote",qt:"400g"},{nome:"Burro",qt:"30g"},{nome:"Zucchero",qt:"q.b."},{nome:"Prezzemolo",qt:"5g"}],_dbEntry:{n:"Carote al burro (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1.5,gs:4,g:6,z:7,ch:10,fi:2.5,ca:40,fe:.5,mg:15,k2:300,na:80,zn:.3,fo:15,se:1,col:15}},{id:"tpl_1958",nome:"Finocchi gratinati (versione 2)",nome_en:"Gratinated fennel (version 2)",categoria:"Contorno",porzioni:4,note:"Tagliare i finocchi a spicchi e lessarli in acqua salata. Disporli in una pirofila e ricoprire con besciamella. Cospargere di parmigiano e gratinare in forno finché dorati.",note_en:"Cut the fennel into wedges and boil in salted water. Arrange in a baking dish and cover with bechamel. Sprinkle with parmesan and gratinate in the oven until golden.",ingredienti:[{nome:"Finocchi",qt:"500g"},{nome:"Besciamella",qt:"100g"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Finocchi gratinati (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:4,g:9,z:4,ch:10,fi:3,ca:150,fe:.7,mg:20,k2:400,na:200,zn:.6,fo:50,se:4,col:20}},{id:"tpl_1959",nome:"Zucca al forno",nome_en:"Roasted pumpkin",categoria:"Contorno",porzioni:4,note:"Tagliare la zucca a fette o cubetti. Condirla con olio, rosmarino e sale, disponendola su una teglia. Cuocere in forno caldo finché è morbida e leggermente caramellata ai bordi.",note_en:"Cut the pumpkin into slices or cubes. Season with oil, rosemary and salt, arranging on a tray. Bake in a hot oven until soft and lightly caramelized at the edges.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Rosmarino",qt:"q.b."},{nome:"Sale",qt:"q.b."}],_dbEntry:{n:"Zucca al forno (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1.5,gs:.5,g:6,z:5,ch:9,fi:2,ca:30,fe:.6,mg:15,k2:350,na:50,zn:.3,fo:20,se:1,col:0}},{id:"tpl_1960",nome:"Patate arrosto con paprika",nome_en:"Roasted potatoes with paprika",categoria:"Contorno",porzioni:4,note:"Tagliare le patate a cubotti e condirle con olio, paprika dolce e aglio tritato. Disporle su una teglia in un solo strato. Cuocere in forno caldo mescolando a metà cottura finché sono dorate.",note_en:"Cut the potatoes into chunks and season with oil, sweet paprika and chopped garlic. Arrange on a tray in a single layer. Bake in a hot oven, stirring halfway, until golden.",ingredienti:[{nome:"Patate",qt:"600g"},{nome:"Olio extravergine",qt:"30ml"},{nome:"Paprika dolce",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Patate arrosto con paprika (ricetta)",c:"Ricette",src:"RICETTE",k:185,p:3,gs:.5,g:7,z:1,ch:28,fi:2.5,ca:15,fe:1,mg:25,k2:450,na:150,zn:.4,fo:20,se:1,col:0}},{id:"tpl_1961",nome:"Insalata di finocchi e arance (versione 2)",nome_en:"Fennel and orange salad (version 2)",categoria:"Contorno",porzioni:4,note:"Affettare sottilmente i finocchi e sbucciare le arance a vivo. Unire i due ingredienti in una ciotola con le olive nere. Condire con olio extravergine.",note_en:"Thinly slice the fennel and segment the oranges. Combine in a bowl with black olives. Dress with extra virgin olive oil.",ingredienti:[{nome:"Finocchi",qt:"300g"},{nome:"Arance",qt:"2"},{nome:"Olive nere",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Insalata di finocchi e arance (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:130,p:2,gs:.5,g:7,z:12,ch:14,fi:3.5,ca:50,fe:.8,mg:20,k2:350,na:100,zn:.3,fo:40,se:1,col:0}},{id:"tpl_1962",nome:"Verdure grigliate miste (versione 2)",nome_en:"Mixed grilled vegetables (version 2)",categoria:"Contorno",porzioni:4,note:"Tagliare zucchine, melanzane, peperoni e radicchio a pezzi regolari. Grigliarli su piastra rovente fino a doratura leggera. Condire con olio extravergine e servire tiepidi.",note_en:"Cut zucchini, eggplant, peppers and radicchio into even pieces. Grill on a hot griddle until lightly charred. Season with extra virgin olive oil and serve warm.",ingredienti:[{nome:"Zucchine",qt:"150g"},{nome:"Melanzane",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Radicchio",qt:"100g"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Verdure grigliate miste (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:2.5,gs:.5,g:8,z:5,ch:7,fi:3.5,ca:30,fe:1,mg:25,k2:400,na:50,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1963",nome:"Cicoria ripassata",nome_en:"Sautéed chicory",categoria:"Contorno",porzioni:4,note:"Lessare la cicoria in acqua salata finché tenera e scolarla bene. Ripassarla in padella con olio, aglio e peperoncino a fuoco vivace. Servire calda.",note_en:"Boil the chicory in salted water until tender and drain well. Sauté in a pan with oil, garlic and chili on high heat. Serve hot.",ingredienti:[{nome:"Cicoria",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Cicoria ripassata (ricetta)",c:"Ricette",src:"RICETTE",k:85,p:3,gs:.5,g:6,z:1,ch:3,fi:3,ca:120,fe:2,mg:30,k2:350,na:80,zn:.4,fo:80,se:1,col:0}},{id:"tpl_1964",nome:"Fagiolini con pomodorini",nome_en:"Green beans with cherry tomatoes",categoria:"Contorno",porzioni:4,note:"Lessare i fagiolini in acqua salata finché teneri. Saltarli in padella con aglio, olio e pomodorini tagliati a metà. Cuocere pochi minuti finché i pomodorini si ammorbidiscono.",note_en:"Boil the green beans in salted water until tender. Sauté in a pan with garlic, oil and halved cherry tomatoes. Cook briefly until the tomatoes soften.",ingredienti:[{nome:"Fagiolini",qt:"400g"},{nome:"Pomodorini",qt:"150g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Fagiolini con pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:2.5,gs:.5,g:6,z:5,ch:8,fi:3.5,ca:50,fe:1.2,mg:25,k2:330,na:50,zn:.4,fo:40,se:1,col:0}},{id:"tpl_1965",nome:"Piselli al prosciutto",nome_en:"Peas with prosciutto",categoria:"Contorno",porzioni:4,note:"Rosolare la cipolla tritata in olio finché trasparente. Aggiungere il prosciutto crudo a listarelle e i piselli. Cuocere a fuoco lento aggiungendo un po' d'acqua se necessario, finché i piselli sono teneri.",note_en:"Sauté the chopped onion in oil until translucent. Add the prosciutto strips and the peas. Cook gently, adding a little water if needed, until the peas are tender.",ingredienti:[{nome:"Piselli",qt:"400g"},{nome:"Prosciutto crudo",qt:"60g"},{nome:"Cipolla",qt:"50g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Piselli al prosciutto (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:9,gs:1,g:7,z:4,ch:14,fi:5,ca:30,fe:2,mg:30,k2:250,na:350,zn:1,fo:60,se:3,col:10}},{id:"tpl_1966",nome:"Cavolo nero saltato",nome_en:"Sautéed black cabbage",categoria:"Contorno",porzioni:4,note:"Lavare e tagliare a listarelle il cavolo nero. Saltarlo in padella con aglio, peperoncino e olio finché appassisce. Servire caldo come contorno rustico.",note_en:"Wash and cut the black cabbage into strips. Sauté in a pan with garlic, chili and oil until wilted. Serve hot as a rustic side dish.",ingredienti:[{nome:"Cavolo nero",qt:"400g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Cavolo nero saltato (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:3,gs:.5,g:6,z:1,ch:4,fi:3.5,ca:150,fe:1.5,mg:30,k2:350,na:60,zn:.4,fo:70,se:1,col:0}},{id:"tpl_1967",nome:"Rape rosse al forno",nome_en:"Roasted beets",categoria:"Contorno",porzioni:4,note:"Avvolgere le barbabietole intere in carta forno e cuocerle in forno finché tenere. Sbucciarle e tagliarle a spicchi. Condire con olio extravergine, aceto balsamico e timo.",note_en:"Wrap the whole beets in parchment and bake until tender. Peel and cut into wedges. Season with extra virgin olive oil, balsamic vinegar and thyme.",ingredienti:[{nome:"Barbabietole",qt:"500g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto balsamico",qt:"10ml"},{nome:"Timo",qt:"q.b."}],_dbEntry:{n:"Rape rosse al forno (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:2,gs:.3,g:5,z:9,ch:11,fi:2.5,ca:20,fe:1,mg:25,k2:350,na:80,zn:.4,fo:110,se:1,col:0}},{id:"tpl_1968",nome:"Radicchio grigliato",nome_en:"Grilled radicchio",categoria:"Contorno",porzioni:4,note:"Tagliare il radicchio di Treviso a metà per il lungo. Grigliarlo su piastra calda fino ad appassire leggermente. Condire con olio extravergine e aceto balsamico.",note_en:"Cut the Treviso radicchio in half lengthwise. Grill on a hot griddle until slightly wilted. Season with extra virgin olive oil and balsamic vinegar.",ingredienti:[{nome:"Radicchio di Treviso",qt:"400g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto balsamico",qt:"10ml"}],_dbEntry:{n:"Radicchio grigliato (ricetta)",c:"Ricette",src:"RICETTE",k:75,p:1.5,gs:.3,g:6,z:1.5,ch:3,fi:2,ca:20,fe:.5,mg:10,k2:200,na:50,zn:.3,fo:50,se:1,col:0}},{id:"tpl_1969",nome:"Bietole ripassate",nome_en:"Sautéed Swiss chard",categoria:"Contorno",porzioni:4,note:"Lessare le bietole in acqua salata finché tenere e scolarle bene. Ripassarle in padella con aglio e olio a fuoco vivace. Servire calde.",note_en:"Boil the Swiss chard in salted water until tender and drain well. Sauté in a pan with garlic and oil on high heat. Serve hot.",ingredienti:[{nome:"Bietole",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Bietole ripassate (ricetta)",c:"Ricette",src:"RICETTE",k:85,p:3,gs:.5,g:6,z:1,ch:4,fi:3,ca:100,fe:2,mg:60,k2:450,na:150,zn:.5,fo:40,se:1,col:0}},{id:"tpl_1970",nome:"Patate al vapore con erbe",nome_en:"Steamed potatoes with herbs",categoria:"Contorno",porzioni:4,note:"Tagliare le patate a cubetti e cuocerle al vapore finché tenere. Condirle con olio extravergine ancora calde. Completare con erba cipollina e prezzemolo tritati.",note_en:"Cut the potatoes into cubes and steam until tender. Dress with extra virgin olive oil while still warm. Finish with chopped chives and parsley.",ingredienti:[{nome:"Patate",qt:"500g"},{nome:"Erba cipollina",qt:"5g"},{nome:"Prezzemolo",qt:"5g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Patate al vapore con erbe (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:3,gs:.3,g:4,z:1,ch:26,fi:2,ca:15,fe:.8,mg:25,k2:450,na:50,zn:.4,fo:15,se:1,col:0}},{id:"tpl_1971",nome:"Melanzane grigliate al basilico",nome_en:"Grilled eggplant with basil",categoria:"Contorno",porzioni:4,note:"Tagliare le melanzane a fette non troppo sottili. Grigliarle su piastra rovente fino a doratura. Condire con olio, aglio tritato e basilico spezzettato.",note_en:"Cut the eggplant into slices, not too thin. Grill on a hot griddle until browned. Season with oil, chopped garlic and torn basil.",ingredienti:[{nome:"Melanzane",qt:"500g"},{nome:"Basilico",qt:"10g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Melanzane grigliate al basilico (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:2,gs:.5,g:8,z:4,ch:6,fi:3.5,ca:20,fe:.6,mg:20,k2:300,na:50,zn:.3,fo:20,se:1,col:0}},{id:"tpl_1972",nome:"Peperoni al forno",nome_en:"Roasted peppers",categoria:"Contorno",porzioni:4,note:"Tagliare i peperoni a falde eliminando semi e filamenti. Disporli su una teglia con olio e aglio tritato. Cuocere in forno caldo finché la pelle si abbrustolisce leggermente.",note_en:"Cut the peppers into strips, removing seeds and membranes. Arrange on a tray with oil and chopped garlic. Bake in a hot oven until the skin lightly chars.",ingredienti:[{nome:"Peperoni",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Prezzemolo",qt:"5g"}],_dbEntry:{n:"Peperoni al forno (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:1.5,gs:.3,g:7,z:6,ch:7,fi:2.5,ca:20,fe:.6,mg:15,k2:250,na:50,zn:.3,fo:40,se:1,col:0}},{id:"tpl_1973",nome:"Insalata di patate e fagiolini",nome_en:"Potato and green bean salad",categoria:"Contorno",porzioni:4,note:"Lessare separatamente patate e fagiolini finché teneri. Tagliare le patate a cubetti e unirle ai fagiolini con la cipolla rossa affettata. Condire con olio extravergine e aceto di vino.",note_en:"Separately boil the potatoes and green beans until tender. Dice the potatoes and combine with the beans and sliced red onion. Dress with extra virgin olive oil and wine vinegar.",ingredienti:[{nome:"Patate",qt:"250g"},{nome:"Fagiolini",qt:"250g"},{nome:"Cipolla rossa",qt:"30g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Aceto di vino",qt:"10ml"}],_dbEntry:{n:"Insalata di patate e fagiolini (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:3,gs:.5,g:6,z:3,ch:19,fi:3,ca:40,fe:1.2,mg:25,k2:400,na:80,zn:.4,fo:30,se:1,col:0}},{id:"tpl_1974",nome:"Cardi gratinati",nome_en:"Gratinated cardoons",categoria:"Contorno",porzioni:4,note:"Pulire i cardi eliminando i filamenti e lessarli in acqua acidulata. Disporli in una pirofila e ricoprire con besciamella. Cospargere di parmigiano e gratinare in forno.",note_en:"Clean the cardoons, removing the strings, and boil in acidulated water. Arrange in a baking dish and cover with bechamel. Sprinkle with parmesan and gratinate in the oven.",ingredienti:[{nome:"Cardi",qt:"500g"},{nome:"Besciamella",qt:"120g"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Cardi gratinati (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:6,gs:4,g:10,z:3,ch:10,fi:2.5,ca:150,fe:.8,mg:20,k2:300,na:200,zn:.6,fo:30,se:4,col:20}},{id:"tpl_1975",nome:"Sformato di zucchine",nome_en:"Zucchini timbale",categoria:"Contorno",porzioni:4,note:"Saltare le zucchine a fette in padella finché morbide. Frullarle grossolanamente e unirle a uova sbattute, parmigiano e besciamella. Versare in una teglia e cuocere in forno finché rassoda.",note_en:"Sauté the sliced zucchini in a pan until soft. Coarsely blend and combine with beaten eggs, parmesan and bechamel. Pour into a baking dish and bake until set.",ingredienti:[{nome:"Zucchine",qt:"400g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"30g"},{nome:"Besciamella",qt:"50g"}],_dbEntry:{n:"Sformato di zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:8,gs:3,g:10,z:2,ch:6,fi:1.5,ca:120,fe:1,mg:15,k2:250,na:150,zn:.7,fo:25,se:8,col:130}},{id:"tpl_1976",nome:"Puntarelle in salsa di alici",nome_en:"Puntarelle with anchovy dressing",categoria:"Contorno",porzioni:4,note:"Tagliare le puntarelle a striscioline sottili e lasciarle in acqua fredda finché si arricciano. Pestare le alici con aglio, aceto e olio fino a ottenere una salsa. Condire le puntarelle scolate con la salsa.",note_en:"Cut the puntarelle into thin strips and soak in cold water until they curl. Mash the anchovies with garlic, vinegar and oil into a dressing. Toss the drained puntarelle with the dressing.",ingredienti:[{nome:"Puntarelle",qt:"400g"},{nome:"Alici sott'olio",qt:"30g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Aceto di vino",qt:"10ml"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Puntarelle in salsa di alici (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4,gs:.8,g:9,z:1,ch:3,fi:2,ca:50,fe:1,mg:20,k2:300,na:250,zn:.4,fo:40,se:5,col:10}},{id:"tpl_1977",nome:"Zucchine alla scapece",nome_en:"Scapece-style zucchini",categoria:"Contorno",porzioni:4,note:"Tagliare le zucchine a fettine sottili e friggerle in olio caldo fino a doratura. Scolarle su carta assorbente. Marinare con aceto, aglio e menta per almeno un'ora prima di servire.",note_en:"Cut the zucchini into thin slices and fry in hot oil until golden. Drain on paper towels. Marinate with vinegar, garlic and mint for at least an hour before serving.",ingredienti:[{nome:"Zucchine",qt:"500g"},{nome:"Aceto di vino",qt:"30ml"},{nome:"Menta",qt:"5g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio per friggere",qt:"60ml"}],_dbEntry:{n:"Zucchine alla scapece (ricetta)",c:"Ricette",src:"RICETTE",k:140,p:2,gs:.8,g:10,z:3,ch:7,fi:2,ca:30,fe:.6,mg:20,k2:300,na:50,zn:.3,fo:30,se:1,col:0}},{id:"tpl_1978",nome:"Friarielli saltati",nome_en:"Sautéed friarielli (broccoli rabe)",categoria:"Contorno",porzioni:4,note:"Lavare i friarielli e sgrondarli. Saltarli in padella con abbondante aglio, peperoncino e olio a fuoco vivace. Cuocere finché sono teneri, mescolando spesso.",note_en:"Wash the broccoli rabe and drain. Sauté in a pan with plenty of garlic, chili and oil on high heat. Cook until tender, stirring often.",ingredienti:[{nome:"Friarielli (cime di rapa)",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Friarielli saltati (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4,gs:.6,g:9,z:1,ch:4,fi:3.5,ca:150,fe:1.5,mg:30,k2:350,na:80,zn:.5,fo:90,se:1,col:0}},{id:"tpl_1979",nome:"Cavolfiore in umido",nome_en:"Stewed cauliflower",categoria:"Contorno",porzioni:4,note:"Dividere il cavolfiore in cimette. Stufarlo in padella con aglio, olio e passata di pomodoro. Cuocere a fuoco lento finché tenero, aggiungendo acqua se necessario.",note_en:"Break the cauliflower into florets. Stew in a pan with garlic, oil and tomato passata. Cook gently until tender, adding water if needed.",ingredienti:[{nome:"Cavolfiore",qt:"500g"},{nome:"Passata di pomodoro",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Cavolfiore in umido (ricetta)",c:"Ricette",src:"RICETTE",k:95,p:3,gs:.5,g:6,z:3,ch:7,fi:3,ca:40,fe:.8,mg:20,k2:350,na:100,zn:.4,fo:60,se:2,col:0}},{id:"tpl_1980",nome:"Tortino di patate e porri",nome_en:"Potato and leek pie",categoria:"Contorno",porzioni:4,note:"Affettare patate e porri sottilmente e stufarli in padella. Mescolarli con uova sbattute e parmigiano. Versare il composto in una teglia con besciamella e cuocere in forno finché dorato.",note_en:"Thinly slice the potatoes and leeks and stew in a pan. Mix with beaten eggs and parmesan. Pour the mixture into a baking dish with bechamel and bake until golden.",ingredienti:[{nome:"Patate",qt:"300g"},{nome:"Porri",qt:"200g"},{nome:"Uova",qt:"2"},{nome:"Parmigiano",qt:"30g"},{nome:"Besciamella",qt:"40g"}],_dbEntry:{n:"Tortino di patate e porri (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:7,gs:3,g:10,z:3,ch:24,fi:2.5,ca:90,fe:1,mg:25,k2:400,na:150,zn:.6,fo:30,se:7,col:110}},{id:"tpl_1981",nome:"Asparagi al vapore con limone",nome_en:"Steamed asparagus with lemon",categoria:"Contorno",porzioni:4,note:"Pulire gli asparagi eliminando la parte legnosa. Cuocerli a vapore finché teneri ma sodi. Condire con olio extravergine, succo di limone e scaglie di parmigiano.",note_en:"Clean the asparagus, removing the woody part. Steam until tender but firm. Season with extra virgin olive oil, lemon juice and parmesan shavings.",ingredienti:[{nome:"Asparagi",qt:"500g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Parmigiano",qt:"15g"}],_dbEntry:{n:"Asparagi al vapore con limone (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:4,gs:1,g:7,z:2,ch:5,fi:3,ca:50,fe:1.5,mg:20,k2:250,na:80,zn:.5,fo:90,se:2,col:5}},{id:"tpl_1982",nome:"Fagioli cannellini al forno",nome_en:"Baked cannellini beans",categoria:"Contorno",porzioni:4,note:"Mescolare i fagioli lessati con passata di pomodoro, aglio e salvia. Versare in una pirofila con un filo di olio. Cuocere in forno finché il composto si addensa leggermente.",note_en:"Mix the boiled beans with tomato passata, garlic and sage. Pour into a baking dish with a drizzle of oil. Bake until the mixture thickens slightly.",ingredienti:[{nome:"Fagioli cannellini lessati",qt:"400g"},{nome:"Passata di pomodoro",qt:"100g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Salvia",qt:"q.b."}],_dbEntry:{n:"Fagioli cannellini al forno (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:9,gs:.5,g:6,z:2,ch:22,fi:7,ca:60,fe:2.5,mg:50,k2:400,na:150,zn:1.2,fo:100,se:3,col:0}},{id:"tpl_1983",nome:"Lenticchie in umido (versione 2)",nome_en:"Stewed lentils (version 2)",categoria:"Contorno",porzioni:4,note:"Soffriggere sedano, carota e cipolla tritati in olio. Aggiungere le lenticchie e la passata di pomodoro, coprendo con acqua. Cuocere a fuoco lento finché le lenticchie sono morbide.",note_en:"Sauté chopped celery, carrot and onion in oil. Add the lentils and tomato passata, covering with water. Cook gently until the lentils are soft.",ingredienti:[{nome:"Lenticchie",qt:"350g"},{nome:"Passata di pomodoro",qt:"100g"},{nome:"Sedano",qt:"50g"},{nome:"Carota",qt:"50g"},{nome:"Cipolla",qt:"50g"},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Lenticchie in umido (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:11,gs:.5,g:7,z:3,ch:26,fi:8,ca:30,fe:3,mg:40,k2:400,na:150,zn:1.5,fo:120,se:3,col:0}},{id:"tpl_1984",nome:"Porri gratinati",nome_en:"Gratinated leeks",categoria:"Contorno",porzioni:4,note:"Pulire i porri e tagliarli a tocchetti. Lessarli finché teneri e disporli in una pirofila con besciamella. Cospargere di parmigiano e gratinare in forno finché dorati.",note_en:"Clean the leeks and cut into chunks. Boil until tender and arrange in a baking dish with bechamel. Sprinkle with parmesan and gratinate in the oven until golden.",ingredienti:[{nome:"Porri",qt:"500g"},{nome:"Besciamella",qt:"120g"},{nome:"Parmigiano",qt:"30g"}],_dbEntry:{n:"Porri gratinati (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:6,gs:4,g:10,z:5,ch:12,fi:2.5,ca:150,fe:1,mg:20,k2:300,na:200,zn:.6,fo:40,se:4,col:20}},{id:"tpl_1985",nome:"Patate novelle al rosmarino",nome_en:"New potatoes with rosemary",categoria:"Contorno",porzioni:4,note:"Lavare bene le patate novelle lasciando la buccia. Condirle con olio, aglio e rosmarino in una teglia. Cuocere in forno caldo finché sono dorate e croccanti.",note_en:"Wash the new potatoes well, keeping the skin on. Season with oil, garlic and rosemary in a baking tray. Bake in a hot oven until golden and crisp.",ingredienti:[{nome:"Patate novelle",qt:"500g"},{nome:"Rosmarino",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Patate novelle al rosmarino (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:3,gs:.5,g:7,z:1,ch:25,fi:2,ca:15,fe:1,mg:25,k2:400,na:100,zn:.4,fo:15,se:1,col:0}},{id:"tpl_1986",nome:"Zucca gialla saltata",nome_en:"Sautéed yellow pumpkin",categoria:"Contorno",porzioni:4,note:"Tagliare la zucca a cubetti piccoli. Saltarla in padella con aglio, salvia e olio finché morbida. Servire calda come contorno autunnale.",note_en:"Cut the pumpkin into small cubes. Sauté in a pan with garlic, sage and oil until soft. Serve hot as an autumn side dish.",ingredienti:[{nome:"Zucca",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Salvia",qt:"q.b."},{nome:"Olio extravergine",qt:"20ml"}],_dbEntry:{n:"Zucca gialla saltata (ricetta)",c:"Ricette",src:"RICETTE",k:90,p:1.5,gs:.5,g:6,z:5,ch:9,fi:2,ca:30,fe:.6,mg:15,k2:350,na:50,zn:.3,fo:20,se:1,col:0}},{id:"tpl_1987",nome:"Verza ripassata",nome_en:"Sautéed savoy cabbage",categoria:"Contorno",porzioni:4,note:"Tagliare la verza a listarelle e lessarla brevemente. Saltarla in padella con aglio e pancetta a dadini fino a insaporire. Servire calda.",note_en:"Cut the savoy cabbage into strips and briefly boil. Sauté in a pan with garlic and diced pancetta until flavorful. Serve hot.",ingredienti:[{nome:"Verza",qt:"500g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Pancetta",qt:"30g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Verza ripassata (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:4,gs:1.5,g:8,z:2,ch:5,fi:3,ca:60,fe:.8,mg:20,k2:300,na:150,zn:.5,fo:50,se:2,col:10}},{id:"tpl_1988",nome:"Topinambur al forno",nome_en:"Roasted Jerusalem artichokes",categoria:"Contorno",porzioni:4,note:"Sbucciare i topinambur e tagliarli a pezzi. Condirli con olio, timo e aglio, disponendoli su una teglia. Cuocere in forno caldo finché sono morbidi e dorati.",note_en:"Peel the Jerusalem artichokes and cut into pieces. Season with oil, thyme and garlic, arranging on a tray. Bake in a hot oven until soft and golden.",ingredienti:[{nome:"Topinambur",qt:"500g"},{nome:"Olio extravergine",qt:"20ml"},{nome:"Timo",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Topinambur al forno (ricetta)",c:"Ricette",src:"RICETTE",k:120,p:2.5,gs:.5,g:6,z:4,ch:15,fi:2,ca:20,fe:1,mg:20,k2:400,na:50,zn:.3,fo:15,se:1,col:0}},{id:"tpl_1989",nome:"Barbabietole in agrodolce",nome_en:"Sweet and sour beets",categoria:"Contorno",porzioni:4,note:"Lessare le barbabietole finché tenere, quindi tagliarle a fette. Preparare un composto di aceto e zucchero scaldato leggermente. Versarlo sulle barbabietole e condire con un filo di olio.",note_en:"Boil the beets until tender, then slice them. Prepare a lightly warmed mixture of vinegar and sugar. Pour it over the beets and finish with a drizzle of oil.",ingredienti:[{nome:"Barbabietole",qt:"400g"},{nome:"Aceto di vino",qt:"20ml"},{nome:"Zucchero",qt:"10g"},{nome:"Olio extravergine",qt:"15ml"}],_dbEntry:{n:"Barbabietole in agrodolce (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1.5,gs:.3,g:5,z:12,ch:14,fi:2.5,ca:20,fe:1,mg:25,k2:350,na:80,zn:.4,fo:110,se:1,col:0}},{id:"tpl_1990",nome:"Misticanza saltata con aglio e peperoncino",nome_en:"Sautéed mixed greens with garlic and chili",categoria:"Contorno",porzioni:4,note:"Lavare bene la misticanza e sgrondarla. Saltarla in padella con olio, aglio in camicia e peperoncino finché appassisce leggermente. Servire subito ben calda.",note_en:"Wash the mixed greens well and drain. Sauté in a pan with oil, unpeeled garlic and chili until slightly wilted. Serve immediately, hot.",ingredienti:[{nome:"Misticanza (insalata mista)",qt:"500g"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Peperoncino",qt:"q.b."},{nome:"Olio extravergine",qt:"25ml"}],_dbEntry:{n:"Misticanza saltata con aglio e peperoncino (ricetta)",c:"Ricette",src:"RICETTE",k:100,p:3,gs:.5,g:8,z:1,ch:3,fi:2.5,ca:80,fe:1.2,mg:25,k2:350,na:80,zn:.4,fo:60,se:1,col:0}},{id:"tpl_1991",nome:"Tiramisù leggero allo yogurt",nome_en:"Light yogurt tiramisù",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco con mascarpone in parti uguali e poco zucchero. Inzuppare i savoiardi nel caffè freddo senza alcolico. Alternare strati di crema e savoiardi, spolverare con cacao amaro e riporre in frigo per almeno 2 ore.",note_en:"Mix Greek yogurt with mascarpone in equal parts and a little sugar. Dip ladyfingers in cold coffee without alcohol. Alternate layers of cream and ladyfingers, dust with cocoa and chill for at least 2 hours.",ingredienti:[{nome:"Savoiardi",qt:"150g"},{nome:"Yogurt greco",qt:"250g"},{nome:"Mascarpone",qt:"125g"},{nome:"Caffè espresso",qt:"200ml"},{nome:"Zucchero",qt:"40g"},{nome:"Cacao amaro",qt:"10g"}],_dbEntry:{n:"Tiramisù leggero allo yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:7,gs:6,g:12,z:16,ch:28,fi:1,ca:100,fe:1,mg:20,k2:150,na:60,zn:.7,fo:15,se:5,col:35}},{id:"tpl_1992",nome:"Panna cotta ai frutti di bosco",nome_en:"Panna cotta with mixed berries",categoria:"Dolce",porzioni:4,note:"Scaldare panna e latte con zucchero e vaniglia, sciogliere la gelatina ammorbidita. Versare negli stampini e far raffreddare in frigo per almeno 4 ore. Servire con coulis di frutti di bosco freschi.",note_en:"Heat cream and milk with sugar and vanilla, dissolve softened gelatin. Pour into molds and chill for at least 4 hours. Serve with fresh mixed berry coulis.",ingredienti:[{nome:"Panna fresca",qt:"250ml"},{nome:"Latte",qt:"100ml"},{nome:"Zucchero",qt:"50g"},{nome:"Gelatina in fogli",qt:"6g"},{nome:"Frutti di bosco",qt:"150g"},{nome:"Vaniglia",qt:"1 bacca"}],_dbEntry:{n:"Panna cotta ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:3,gs:11,g:17,z:18,ch:19,fi:1.5,ca:80,fe:.5,mg:12,k2:130,na:30,zn:.4,fo:8,se:2,col:55}},{id:"tpl_1993",nome:"Crostata di frutta fresca",nome_en:"Fresh fruit tart",categoria:"Dolce",porzioni:8,note:"Preparare una pasta frolla con farina, burro, zucchero e uovo, cuocere in bianco a 180°C per 20 minuti. Farcire con crema pasticcera raffreddata. Decorare con frutta fresca mista a piacere.",note_en:"Prepare shortcrust pastry with flour, butter, sugar and egg, blind bake at 180°C for 20 minutes. Fill with cooled pastry cream. Decorate with mixed fresh fruit.",ingredienti:[{nome:"Farina",qt:"250g"},{nome:"Burro",qt:"125g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"1"},{nome:"Latte",qt:"250ml"},{nome:"Tuorli",qt:"3"},{nome:"Frutta mista fresca",qt:"300g"}],_dbEntry:{n:"Crostata di frutta fresca (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:5,gs:8,g:13,z:20,ch:38,fi:1.5,ca:50,fe:1,mg:15,k2:120,na:70,zn:.5,fo:20,se:5,col:80}},{id:"tpl_1994",nome:"Torta di mele senza burro (versione 3)",nome_en:"Butter-free apple cake (version 3)",categoria:"Dolce",porzioni:8,note:"Mescolare farina, zucchero, lievito e olio con le uova. Aggiungere le mele tagliate a cubetti e amalgamare bene. Versare in uno stampo e cuocere a 180°C per 40 minuti.",note_en:"Mix flour, sugar, baking powder and oil with the eggs. Add diced apples and combine well. Pour into a pan and bake at 180°C for 40 minutes.",ingredienti:[{nome:"Mele",qt:"3"},{nome:"Farina",qt:"250g"},{nome:"Zucchero",qt:"120g"},{nome:"Olio di semi",qt:"80ml"},{nome:"Uova",qt:"2"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di mele senza burro (versione 3) (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4,gs:1.5,g:8,z:18,ch:34,fi:2,ca:30,fe:1,mg:15,k2:140,na:60,zn:.4,fo:15,se:4,col:45}},{id:"tpl_1995",nome:"Budino al cioccolato fondente",nome_en:"Dark chocolate pudding",categoria:"Dolce",porzioni:4,note:"Sciogliere il cioccolato fondente a bagnomaria con il latte. Aggiungere amido di mais sciolto in poco latte freddo e cuocere mescolando fino ad addensare. Versare nelle coppette e raffreddare in frigo.",note_en:"Melt dark chocolate in a bain-marie with milk. Add cornstarch dissolved in a little cold milk and cook stirring until thickened. Pour into cups and chill.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"100g"},{nome:"Latte",qt:"400ml"},{nome:"Amido di mais",qt:"25g"},{nome:"Zucchero",qt:"30g"}],_dbEntry:{n:"Budino al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:5,gs:6,g:10,z:16,ch:26,fi:2.5,ca:100,fe:1.8,mg:40,k2:220,na:40,zn:.8,fo:10,se:4,col:8}},{id:"tpl_1996",nome:"Semifreddo allo yogurt e miele",nome_en:"Yogurt and honey semifreddo",categoria:"Dolce",porzioni:6,note:"Montare la panna e unire delicatamente yogurt greco e miele. Versare il composto in uno stampo foderato e riporre in freezer per almeno 5 ore. Servire a fette con una spolverata di granella di nocciole.",note_en:"Whip the cream and gently fold in Greek yogurt and honey. Pour into a lined mold and freeze for at least 5 hours. Serve in slices with crushed hazelnuts.",ingredienti:[{nome:"Panna fresca",qt:"200ml"},{nome:"Yogurt greco",qt:"200g"},{nome:"Miele",qt:"60g"},{nome:"Nocciole tritate",qt:"30g"}],_dbEntry:{n:"Semifreddo allo yogurt e miele (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:4,gs:10,g:18,z:16,ch:16,fi:.5,ca:90,fe:.4,mg:15,k2:120,na:30,zn:.4,fo:6,se:2,col:50}},{id:"tpl_1997",nome:"Biscotti d'avena e miele (versione 2)",nome_en:"Oat and honey cookies (version 2)",categoria:"Dolce",porzioni:10,note:"Mescolare fiocchi d'avena, farina, miele e olio fino a ottenere un impasto omogeneo. Formare delle palline schiacciate e disporle su una teglia. Cuocere a 180°C per 15 minuti fino a doratura.",note_en:"Mix oat flakes, flour, honey and oil until smooth. Form flattened balls and place on a baking tray. Bake at 180°C for 15 minutes until golden.",ingredienti:[{nome:"Fiocchi di avena",qt:"150g"},{nome:"Farina integrale",qt:"100g"},{nome:"Miele",qt:"80g"},{nome:"Olio di semi",qt:"50ml"},{nome:"Uova",qt:"1"}],_dbEntry:{n:"Biscotti d'avena e miele (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:4,gs:1,g:7,z:12,ch:26,fi:2.5,ca:20,fe:1.2,mg:25,k2:110,na:20,zn:.6,fo:12,se:5,col:20}},{id:"tpl_1998",nome:"Mousse ai frutti di bosco",nome_en:"Mixed berry mousse",categoria:"Dolce",porzioni:4,note:"Frullare i frutti di bosco con lo zucchero fino a ottenere una purea liscia. Montare la panna e incorporarla delicatamente alla purea. Versare in coppette e raffreddare per almeno 2 ore.",note_en:"Blend the berries with sugar into a smooth puree. Whip the cream and gently fold it into the puree. Pour into cups and chill for at least 2 hours.",ingredienti:[{nome:"Frutti di bosco misti",qt:"250g"},{nome:"Panna fresca",qt:"200ml"},{nome:"Zucchero",qt:"40g"}],_dbEntry:{n:"Mousse ai frutti di bosco (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:2,gs:10,g:16,z:14,ch:12,fi:2.5,ca:40,fe:.6,mg:12,k2:130,na:15,zn:.3,fo:15,se:1,col:55}},{id:"tpl_1999",nome:"Torta della nonna leggera",nome_en:"Light grandmother cake",categoria:"Dolce",porzioni:8,note:"Preparare una pasta frolla leggera con poco burro e farcire con crema pasticcera al limone. Coprire con un secondo disco di pasta e cuocere a 180°C per 30 minuti. Guarnire con pinoli e zucchero a velo.",note_en:"Prepare a light shortcrust pastry with little butter and fill with lemon pastry cream. Cover with a second pastry disc and bake at 180°C for 30 minutes. Garnish with pine nuts and icing sugar.",ingredienti:[{nome:"Farina",qt:"300g"},{nome:"Burro",qt:"100g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"1"},{nome:"Latte",qt:"300ml"},{nome:"Tuorli",qt:"3"},{nome:"Pinoli",qt:"30g"},{nome:"Scorza di limone",qt:"1"}],_dbEntry:{n:"Torta della nonna leggera (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:6,gs:7,g:14,z:20,ch:36,fi:1.5,ca:60,fe:1.3,mg:20,k2:130,na:70,zn:.6,fo:20,se:6,col:85}},{id:"tpl_2000",nome:"Cheesecake senza cottura al limone",nome_en:"No-bake lemon cheesecake",categoria:"Dolce",porzioni:8,note:"Tritare i biscotti e unirli al burro fuso, pressare sul fondo di uno stampo. Mescolare formaggio spalmabile, yogurt, zucchero e succo di limone, unire la gelatina sciolta. Versare sopra la base e raffreddare in frigo per 4 ore.",note_en:"Crush biscuits and mix with melted butter, press into a mold base. Mix cream cheese, yogurt, sugar and lemon juice, add dissolved gelatin. Pour over the base and chill for 4 hours.",ingredienti:[{nome:"Biscotti secchi",qt:"150g"},{nome:"Burro",qt:"60g"},{nome:"Formaggio spalmabile",qt:"250g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Zucchero",qt:"70g"},{nome:"Succo di limone",qt:"2 limoni"},{nome:"Gelatina in fogli",qt:"8g"}],_dbEntry:{n:"Cheesecake senza cottura al limone (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:5,gs:11,g:19,z:18,ch:28,fi:.8,ca:70,fe:.7,mg:15,k2:100,na:150,zn:.5,fo:10,se:3,col:55}},{id:"tpl_2001",nome:"Gelato alla fragola fatto in casa",nome_en:"Homemade strawberry ice cream",categoria:"Dolce",porzioni:6,note:"Frullare le fragole con lo zucchero e il succo di limone. Unire panna e yogurt e mescolare bene. Versare nella gelatiera e mantecare, oppure riporre in freezer mescolando ogni 30 minuti.",note_en:"Blend strawberries with sugar and lemon juice. Add cream and yogurt and mix well. Churn in an ice cream maker, or freeze stirring every 30 minutes.",ingredienti:[{nome:"Fragole",qt:"300g"},{nome:"Panna fresca",qt:"150ml"},{nome:"Yogurt greco",qt:"100g"},{nome:"Zucchero",qt:"70g"},{nome:"Succo di limone",qt:"1 cucchiaio"}],_dbEntry:{n:"Gelato alla fragola fatto in casa (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:2,gs:7,g:11,z:18,ch:20,fi:1.2,ca:60,fe:.4,mg:10,k2:150,na:20,zn:.3,fo:15,se:1,col:35}},{id:"tpl_2002",nome:"Torta al cioccolato fondente senza farina",nome_en:"Flourless dark chocolate cake",categoria:"Dolce",porzioni:8,note:"Sciogliere cioccolato fondente e burro a bagnomaria. Montare le uova con lo zucchero fino a renderle spumose e unire al cioccolato con le mandorle tritate. Cuocere a 170°C per 25 minuti.",note_en:"Melt dark chocolate and butter in a bain-marie. Whip eggs with sugar until fluffy and fold into the chocolate with ground almonds. Bake at 170°C for 25 minutes.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Uova",qt:"4"},{nome:"Zucchero",qt:"100g"},{nome:"Mandorle tritate",qt:"80g"}],_dbEntry:{n:"Torta al cioccolato fondente senza farina (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:7,gs:10,g:22,z:19,ch:22,fi:3,ca:50,fe:2.5,mg:60,k2:220,na:40,zn:1,fo:20,se:6,col:110}},{id:"tpl_2003",nome:"Crostata di ricotta e pere",nome_en:"Ricotta and pear tart",categoria:"Dolce",porzioni:8,note:"Preparare una base di pasta frolla e cuocerla in bianco per 15 minuti. Mescolare ricotta, zucchero e uova, versare sulla base e disporre le pere a fette. Cuocere a 180°C per 30 minuti.",note_en:"Prepare a shortcrust base and blind bake for 15 minutes. Mix ricotta, sugar and eggs, pour over the base and arrange sliced pears. Bake at 180°C for 30 minutes.",ingredienti:[{nome:"Farina",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Ricotta",qt:"250g"},{nome:"Zucchero",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Pere",qt:"2"}],_dbEntry:{n:"Crostata di ricotta e pere (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:7,gs:6,g:12,z:16,ch:33,fi:2,ca:80,fe:1,mg:18,k2:150,na:60,zn:.6,fo:18,se:6,col:75}},{id:"tpl_2004",nome:"Budino di riso alla cannella",nome_en:"Cinnamon rice pudding",categoria:"Dolce",porzioni:4,note:"Cuocere il riso nel latte a fuoco lento con zucchero e cannella, mescolando spesso fino a cremosità. Lasciare intiepidire e versare nelle coppette. Servire con una spolverata di cannella.",note_en:"Cook the rice in milk over low heat with sugar and cinnamon, stirring often until creamy. Let cool slightly and pour into cups. Serve with a dusting of cinnamon.",ingredienti:[{nome:"Riso",qt:"100g"},{nome:"Latte",qt:"500ml"},{nome:"Zucchero",qt:"50g"},{nome:"Cannella",qt:"1 cucchiaino"}],_dbEntry:{n:"Budino di riso alla cannella (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:6,gs:2.5,g:4,z:18,ch:40,fi:.8,ca:150,fe:.5,mg:20,k2:220,na:60,zn:.6,fo:10,se:4,col:12}},{id:"tpl_2005",nome:"Mousse al limone",nome_en:"Lemon mousse",categoria:"Dolce",porzioni:4,note:"Sbattere i tuorli con lo zucchero e il succo di limone finché spumosi, poi cuocere a bagnomaria fino ad addensare leggermente. Montare gli albumi a neve e incorporarli delicatamente. Raffreddare in frigo per 2 ore.",note_en:"Beat egg yolks with sugar and lemon juice until foamy, then cook in a bain-marie until slightly thickened. Whip egg whites to stiff peaks and fold in gently. Chill for 2 hours.",ingredienti:[{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"60g"},{nome:"Succo di limone",qt:"2 limoni"},{nome:"Scorza di limone",qt:"1"}],_dbEntry:{n:"Mousse al limone (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:5,gs:2,g:5,z:16,ch:20,fi:.3,ca:30,fe:.7,mg:8,k2:80,na:40,zn:.5,fo:15,se:8,col:140}},{id:"tpl_2006",nome:"Torta di carote e mandorle (versione 2)",nome_en:"Carrot and almond cake (version 2)",categoria:"Dolce",porzioni:8,note:"Grattugiare le carote e unirle a farina di mandorle, uova, zucchero e lievito. Amalgamare bene e versare in uno stampo. Cuocere a 180°C per 35 minuti.",note_en:"Grate the carrots and mix with almond flour, eggs, sugar and baking powder. Combine well and pour into a mold. Bake at 180°C for 35 minutes.",ingredienti:[{nome:"Carote",qt:"250g"},{nome:"Farina di mandorle",qt:"150g"},{nome:"Farina",qt:"80g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"100g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di carote e mandorle (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:7,gs:2.5,g:14,z:16,ch:26,fi:3,ca:70,fe:1.5,mg:45,k2:220,na:50,zn:.8,fo:20,se:6,col:70}},{id:"tpl_2007",nome:"Yogurt greco con miele e noci (versione 4)",nome_en:"Greek yogurt with honey and walnuts (version 4)",categoria:"Dolce",porzioni:2,note:"Versare lo yogurt greco in una coppa. Aggiungere un filo di miele e completare con gherigli di noci spezzettati. Servire subito a temperatura ambiente.",note_en:"Pour Greek yogurt into a bowl. Drizzle with honey and top with crushed walnut kernels. Serve immediately at room temperature.",ingredienti:[{nome:"Yogurt greco",qt:"300g"},{nome:"Miele",qt:"30g"},{nome:"Noci",qt:"30g"}],_dbEntry:{n:"Yogurt greco con miele e noci (versione 4) (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:11,gs:4,g:14,z:14,ch:14,fi:1,ca:120,fe:.8,mg:35,k2:200,na:40,zn:.8,fo:8,se:3,col:15}},{id:"tpl_2008",nome:"Pere cotte al vino rosso",nome_en:"Pears poached in red wine",categoria:"Dolce",porzioni:4,note:"Sbucciare le pere lasciando il gambo e cuocerle intere nel vino rosso con zucchero, cannella e chiodi di garofano per 25 minuti. Lasciar raffreddare nel liquido di cottura. Servire irrorate con lo sciroppo ridotto.",note_en:"Peel the pears leaving the stem and simmer whole in red wine with sugar, cinnamon and cloves for 25 minutes. Let cool in the cooking liquid. Serve drizzled with the reduced syrup.",ingredienti:[{nome:"Pere",qt:"4"},{nome:"Vino rosso",qt:"500ml"},{nome:"Zucchero",qt:"70g"},{nome:"Cannella",qt:"1 stecca"},{nome:"Chiodi di garofano",qt:"2"}],_dbEntry:{n:"Pere cotte al vino rosso (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:.6,gs:0,g:.3,z:28,ch:33,fi:3.5,ca:20,fe:.6,mg:12,k2:200,na:5,zn:.2,fo:8,se:1,col:0}},{id:"tpl_2009",nome:"Mele al forno con cannella",nome_en:"Baked apples with cinnamon",categoria:"Dolce",porzioni:4,note:"Svuotare il torsolo delle mele e riempire con uvetta, noci e un cucchiaino di miele. Spolverare con cannella e cuocere in forno a 180°C per 30 minuti. Servire tiepide.",note_en:"Core the apples and fill with raisins, walnuts and a teaspoon of honey. Dust with cinnamon and bake at 180°C for 30 minutes. Serve warm.",ingredienti:[{nome:"Mele",qt:"4"},{nome:"Uvetta",qt:"30g"},{nome:"Noci",qt:"30g"},{nome:"Miele",qt:"40g"},{nome:"Cannella",qt:"1 cucchiaino"}],_dbEntry:{n:"Mele al forno con cannella (ricetta)",c:"Ricette",src:"RICETTE",k:180,p:1.5,gs:.8,g:6,z:26,ch:32,fi:4,ca:25,fe:.7,mg:18,k2:220,na:5,zn:.3,fo:6,se:1,col:0}},{id:"tpl_2010",nome:"Torta soffice allo yogurt (versione 2)",nome_en:"Fluffy yogurt cake (version 2)",categoria:"Dolce",porzioni:8,note:"Mescolare yogurt, uova, zucchero e olio, poi aggiungere farina setacciata e lievito. Amalgamare fino a impasto liscio e versare in uno stampo. Cuocere a 180°C per 35 minuti.",note_en:"Mix yogurt, eggs, sugar and oil, then add sifted flour and baking powder. Combine into a smooth batter and pour into a mold. Bake at 180°C for 35 minutes.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Farina",qt:"220g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"60ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta soffice allo yogurt (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:5,gs:2,g:9,z:16,ch:34,fi:1,ca:50,fe:1.1,mg:15,k2:110,na:60,zn:.5,fo:15,se:5,col:65}},{id:"tpl_2011",nome:"Biscotti alle mandorle senza burro",nome_en:"Butter-free almond cookies",categoria:"Dolce",porzioni:10,note:"Montare gli albumi con lo zucchero fino a neve ferma. Incorporare delicatamente la farina di mandorle. Formare dei mucchietti su carta forno e cuocere a 160°C per 18 minuti.",note_en:"Whip egg whites with sugar to stiff peaks. Gently fold in almond flour. Pipe small mounds onto baking paper and bake at 160°C for 18 minutes.",ingredienti:[{nome:"Albumi",qt:"3"},{nome:"Zucchero",qt:"100g"},{nome:"Farina di mandorle",qt:"150g"}],_dbEntry:{n:"Biscotti alle mandorle senza burro (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:4,gs:.8,g:8,z:11,ch:14,fi:1.5,ca:35,fe:.7,mg:30,k2:100,na:15,zn:.4,fo:8,se:2,col:0}},{id:"tpl_2012",nome:"Crema catalana light",nome_en:"Light crema catalana",categoria:"Dolce",porzioni:4,note:"Scaldare il latte con scorza di limone e cannella. Sbattere i tuorli con lo zucchero e l'amido, unire il latte caldo filtrato e cuocere fino ad addensare. Versare nelle cocotte, raffreddare e caramellare la superficie con zucchero prima di servire.",note_en:"Heat milk with lemon zest and cinnamon. Beat egg yolks with sugar and cornstarch, add the strained hot milk and cook until thickened. Pour into ramekins, chill and caramelize the top with sugar before serving.",ingredienti:[{nome:"Latte",qt:"500ml"},{nome:"Tuorli",qt:"4"},{nome:"Zucchero",qt:"70g"},{nome:"Amido di mais",qt:"20g"},{nome:"Scorza di limone",qt:"1"},{nome:"Cannella",qt:"1 stecca"}],_dbEntry:{n:"Crema catalana light (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:5,gs:3,g:7,z:19,ch:26,fi:.2,ca:110,fe:.8,mg:12,k2:150,na:50,zn:.6,fo:10,se:8,col:180}},{id:"tpl_2013",nome:"Torta di banane e avena",nome_en:"Banana and oat cake",categoria:"Dolce",porzioni:8,note:"Schiacciare le banane mature e unirle a fiocchi d'avena, uova, miele e lievito. Amalgamare bene e versare in uno stampo. Cuocere a 180°C per 35 minuti.",note_en:"Mash ripe bananas and mix with oat flakes, eggs, honey and baking powder. Combine well and pour into a mold. Bake at 180°C for 35 minutes.",ingredienti:[{nome:"Banane mature",qt:"3"},{nome:"Fiocchi di avena",qt:"150g"},{nome:"Uova",qt:"2"},{nome:"Miele",qt:"50g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di banane e avena (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:5,gs:1,g:5,z:18,ch:36,fi:3,ca:30,fe:1.3,mg:35,k2:280,na:40,zn:.6,fo:15,se:5,col:45}},{id:"tpl_2014",nome:"Sorbetto al limone fatto in casa",nome_en:"Homemade lemon sorbet",categoria:"Dolce",porzioni:6,note:"Preparare uno sciroppo con acqua e zucchero, lasciar raffreddare. Unire il succo e la scorza di limone e mescolare bene. Versare nella gelatiera e mantecare, o congelare mescolando ogni ora.",note_en:"Prepare a syrup with water and sugar, let cool. Add lemon juice and zest and mix well. Churn in an ice cream maker, or freeze stirring every hour.",ingredienti:[{nome:"Acqua",qt:"300ml"},{nome:"Zucchero",qt:"150g"},{nome:"Succo di limone",qt:"4 limoni"},{nome:"Scorza di limone",qt:"1"}],_dbEntry:{n:"Sorbetto al limone fatto in casa (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:.3,gs:0,g:.1,z:32,ch:36,fi:.3,ca:8,fe:.2,mg:5,k2:60,na:2,zn:.1,fo:5,se:0,col:0}},{id:"tpl_2015",nome:"Ciambella integrale al miele",nome_en:"Whole-wheat honey ring cake",categoria:"Dolce",porzioni:10,note:"Mescolare farina integrale, miele, uova e olio con il lievito. Versare l'impasto in uno stampo a ciambella. Cuocere a 180°C per 40 minuti.",note_en:"Mix whole-wheat flour, honey, eggs and oil with baking powder. Pour the batter into a ring mold. Bake at 180°C for 40 minutes.",ingredienti:[{nome:"Farina integrale",qt:"300g"},{nome:"Miele",qt:"120g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"80ml"},{nome:"Latte",qt:"100ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Ciambella integrale al miele (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:1.5,g:8,z:16,ch:34,fi:2.5,ca:35,fe:1.4,mg:30,k2:150,na:50,zn:.6,fo:15,se:6,col:55}},{id:"tpl_2016",nome:"Tortino al cioccolato fondente",nome_en:"Molten dark chocolate cake",categoria:"Dolce",porzioni:4,note:"Sciogliere cioccolato fondente e burro a bagnomaria. Montare le uova con lo zucchero, unire il cioccolato e poca farina. Versare negli stampini e cuocere a 200°C per 9 minuti, così il cuore resta fondente.",note_en:"Melt dark chocolate and butter in a bain-marie. Whip eggs with sugar, fold in the chocolate and a little flour. Pour into molds and bake at 200°C for 9 minutes so the center stays molten.",ingredienti:[{nome:"Cioccolato fondente 70%",qt:"120g"},{nome:"Burro",qt:"80g"},{nome:"Uova",qt:"3"},{nome:"Zucchero",qt:"60g"},{nome:"Farina",qt:"40g"}],_dbEntry:{n:"Tortino al cioccolato fondente (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:6,gs:12,g:24,z:18,ch:24,fi:2.5,ca:35,fe:2.2,mg:50,k2:200,na:50,zn:.9,fo:15,se:8,col:150}},{id:"tpl_2017",nome:"Composta di frutta con yogurt",nome_en:"Fruit compote with yogurt",categoria:"Dolce",porzioni:4,note:"Cuocere la frutta a pezzi in poca acqua con zucchero e cannella fino ad ammorbidire. Lasciar raffreddare completamente. Servire fredda su yogurt greco.",note_en:"Cook diced fruit in a little water with sugar and cinnamon until softened. Let cool completely. Serve cold over Greek yogurt.",ingredienti:[{nome:"Mele",qt:"2"},{nome:"Pere",qt:"2"},{nome:"Zucchero",qt:"30g"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Yogurt greco",qt:"200g"}],_dbEntry:{n:"Composta di frutta con yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:4,gs:1.2,g:3,z:22,ch:28,fi:3.5,ca:60,fe:.5,mg:15,k2:220,na:20,zn:.4,fo:8,se:2,col:5}},{id:"tpl_2018",nome:"Torta di zucca e cannella",nome_en:"Pumpkin and cinnamon cake",categoria:"Dolce",porzioni:8,note:"Cuocere la zucca al vapore e schiacciarla in purea. Mescolare con farina, zucchero, uova, olio, cannella e lievito. Versare in uno stampo e cuocere a 180°C per 40 minuti.",note_en:"Steam the pumpkin and mash into a puree. Mix with flour, sugar, eggs, oil, cinnamon and baking powder. Pour into a mold and bake at 180°C for 40 minutes.",ingredienti:[{nome:"Zucca",qt:"300g"},{nome:"Farina",qt:"220g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di zucca e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4,gs:1.5,g:8,z:16,ch:33,fi:2,ca:30,fe:1.2,mg:20,k2:200,na:60,zn:.5,fo:15,se:5,col:45}},{id:"tpl_2019",nome:"Muffin ai mirtilli integrali (versione 2)",nome_en:"Whole-wheat blueberry muffins (version 2)",categoria:"Dolce",porzioni:8,note:"Mescolare farina integrale, zucchero e lievito, poi unire uova, yogurt e olio. Aggiungere i mirtilli infarinati e mescolare delicatamente. Distribuire nei pirottini e cuocere a 180°C per 20 minuti.",note_en:"Mix whole-wheat flour, sugar and baking powder, then add eggs, yogurt and oil. Fold in floured blueberries gently. Divide into muffin cups and bake at 180°C for 20 minutes.",ingredienti:[{nome:"Farina integrale",qt:"200g"},{nome:"Mirtilli",qt:"150g"},{nome:"Zucchero",qt:"80g"},{nome:"Uova",qt:"2"},{nome:"Yogurt bianco",qt:"100g"},{nome:"Olio di semi",qt:"50ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Muffin ai mirtilli integrali (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:4,gs:1.2,g:7,z:14,ch:30,fi:2.8,ca:40,fe:1.1,mg:25,k2:130,na:55,zn:.5,fo:15,se:5,col:45}},{id:"tpl_2020",nome:"Panna cotta al caffè (versione 2)",nome_en:"Coffee panna cotta (version 2)",categoria:"Dolce",porzioni:4,note:"Scaldare panna e latte con zucchero e caffè solubile fino a sciogliere bene. Sciogliere la gelatina ammorbidita e unirla al composto. Versare negli stampini e raffreddare in frigo per 4 ore.",note_en:"Heat cream and milk with sugar and instant coffee until well dissolved. Dissolve softened gelatin and stir into the mixture. Pour into molds and chill for 4 hours.",ingredienti:[{nome:"Panna fresca",qt:"250ml"},{nome:"Latte",qt:"100ml"},{nome:"Zucchero",qt:"50g"},{nome:"Caffè solubile",qt:"2 cucchiaini"},{nome:"Gelatina in fogli",qt:"6g"}],_dbEntry:{n:"Panna cotta al caffè (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:235,p:3,gs:11,g:17,z:18,ch:19,fi:.2,ca:75,fe:.4,mg:12,k2:140,na:30,zn:.3,fo:6,se:2,col:55}},{id:"tpl_2021",nome:"Mousse al cioccolato bianco e lamponi",nome_en:"White chocolate and raspberry mousse",categoria:"Dolce",porzioni:4,note:"Sciogliere il cioccolato bianco a bagnomaria e lasciar intiepidire. Montare la panna e incorporarla delicatamente al cioccolato. Distribuire in coppette alternando con lamponi freschi e raffreddare 2 ore.",note_en:"Melt white chocolate in a bain-marie and let cool slightly. Whip the cream and gently fold into the chocolate. Layer into cups alternating with fresh raspberries and chill for 2 hours.",ingredienti:[{nome:"Cioccolato bianco",qt:"100g"},{nome:"Panna fresca",qt:"200ml"},{nome:"Lamponi",qt:"150g"}],_dbEntry:{n:"Mousse al cioccolato bianco e lamponi (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:3,gs:14,g:20,z:20,ch:20,fi:2,ca:70,fe:.5,mg:15,k2:150,na:35,zn:.5,fo:10,se:2,col:55}},{id:"tpl_2022",nome:"Torta di ricotta e pere senza zucchero aggiunto",nome_en:"No added sugar ricotta and pear cake",categoria:"Dolce",porzioni:8,note:"Mescolare ricotta, uova, farina e miele fino a impasto omogeneo. Aggiungere le pere a cubetti e amalgamare. Cuocere in uno stampo a 180°C per 40 minuti.",note_en:"Mix ricotta, eggs, flour and honey until smooth. Add diced pears and combine. Bake in a mold at 180°C for 40 minutes.",ingredienti:[{nome:"Ricotta",qt:"250g"},{nome:"Uova",qt:"3"},{nome:"Farina",qt:"100g"},{nome:"Miele",qt:"60g"},{nome:"Pere",qt:"2"}],_dbEntry:{n:"Torta di ricotta e pere senza zucchero aggiunto (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:7,gs:3,g:7,z:14,ch:26,fi:2,ca:80,fe:1,mg:15,k2:160,na:50,zn:.6,fo:15,se:6,col:80}},{id:"tpl_2023",nome:"Budino di semolino al cocco",nome_en:"Coconut semolina pudding",categoria:"Dolce",porzioni:4,note:"Cuocere il semolino nel latte con zucchero e cocco rapé, mescolando finché addensa. Versare nelle coppette e lasciar raffreddare. Servire spolverato con altro cocco rapé.",note_en:"Cook semolina in milk with sugar and desiccated coconut, stirring until thick. Pour into cups and let cool. Serve dusted with more coconut.",ingredienti:[{nome:"Semolino",qt:"80g"},{nome:"Latte",qt:"450ml"},{nome:"Zucchero",qt:"40g"},{nome:"Cocco rapé",qt:"30g"}],_dbEntry:{n:"Budino di semolino al cocco (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:6,gs:4,g:7,z:16,ch:33,fi:1.5,ca:140,fe:.8,mg:25,k2:200,na:60,zn:.6,fo:10,se:5,col:12}},{id:"tpl_2024",nome:"Macedonia di frutta fresca con menta",nome_en:"Fresh fruit salad with mint",categoria:"Dolce",porzioni:4,note:"Tagliare a pezzi la frutta fresca di stagione. Condire con succo di limone e poco zucchero. Guarnire con foglie di menta fresca prima di servire.",note_en:"Cut fresh seasonal fruit into pieces. Dress with lemon juice and a little sugar. Garnish with fresh mint leaves before serving.",ingredienti:[{nome:"Frutta mista di stagione",qt:"500g"},{nome:"Succo di limone",qt:"1 limone"},{nome:"Zucchero",qt:"20g"},{nome:"Menta fresca",qt:"q.b."}],_dbEntry:{n:"Macedonia di frutta fresca con menta (ricetta)",c:"Ricette",src:"RICETTE",k:110,p:1,gs:.1,g:.4,z:22,ch:26,fi:3.5,ca:20,fe:.5,mg:15,k2:250,na:2,zn:.2,fo:20,se:1,col:0}},{id:"tpl_2025",nome:"Crostatine di frutta secca e miele",nome_en:"Nut and honey mini tarts",categoria:"Dolce",porzioni:8,note:"Preparare una pasta frolla e foderare degli stampini singoli, cuocendo in bianco 12 minuti. Mescolare frutta secca tritata con miele e un uovo, versare negli stampini. Cuocere altri 15 minuti a 180°C.",note_en:"Prepare shortcrust pastry and line individual molds, blind baking for 12 minutes. Mix chopped nuts with honey and an egg, pour into the molds. Bake another 15 minutes at 180°C.",ingredienti:[{nome:"Farina",qt:"200g"},{nome:"Burro",qt:"80g"},{nome:"Noci e mandorle miste",qt:"100g"},{nome:"Miele",qt:"70g"},{nome:"Uova",qt:"1"}],_dbEntry:{n:"Crostatine di frutta secca e miele (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:5,gs:5,g:15,z:14,ch:26,fi:2,ca:40,fe:1.2,mg:35,k2:150,na:60,zn:.7,fo:15,se:5,col:35}},{id:"tpl_2026",nome:"Torta all'arancia senza burro",nome_en:"Butter-free orange cake",categoria:"Dolce",porzioni:8,note:"Frullare le arance intere private dei semi con lo zucchero e le uova. Aggiungere farina, olio e lievito e amalgamare bene. Cuocere in uno stampo a 180°C per 40 minuti.",note_en:"Blend whole seeded oranges with sugar and eggs. Add flour, oil and baking powder and combine well. Bake in a mold at 180°C for 40 minutes.",ingredienti:[{nome:"Arance",qt:"2"},{nome:"Farina",qt:"220g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"60ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta all'arancia senza burro (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:5,gs:1.3,g:8,z:18,ch:34,fi:1.8,ca:35,fe:1.2,mg:18,k2:180,na:50,zn:.5,fo:20,se:5,col:65}},{id:"tpl_2027",nome:"Gelato allo yogurt alla vaniglia",nome_en:"Vanilla frozen yogurt",categoria:"Dolce",porzioni:6,note:"Mescolare yogurt greco, zucchero e semi di vaniglia fino a scioglierlo bene. Versare nella gelatiera e mantecare, oppure congelare mescolando ogni 30 minuti. Servire subito o dopo breve riposo in freezer.",note_en:"Mix Greek yogurt, sugar and vanilla seeds until well dissolved. Churn in an ice cream maker, or freeze stirring every 30 minutes. Serve immediately or after a short rest in the freezer.",ingredienti:[{nome:"Yogurt greco",qt:"400g"},{nome:"Zucchero",qt:"70g"},{nome:"Vaniglia",qt:"1 bacca"}],_dbEntry:{n:"Gelato allo yogurt alla vaniglia (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:6,gs:2.5,g:5,z:16,ch:18,fi:0,ca:100,fe:.2,mg:12,k2:130,na:40,zn:.5,fo:5,se:2,col:15}},{id:"tpl_2028",nome:"Palline energetiche datteri e cocco",nome_en:"Date and coconut energy balls",categoria:"Dolce",porzioni:10,note:"Frullare i datteri denocciolati con le mandorle fino a ottenere un impasto compatto. Formare delle palline con le mani. Rotolarle nel cocco rapé prima di servire.",note_en:"Blend pitted dates with almonds into a compact paste. Shape into balls by hand. Roll them in desiccated coconut before serving.",ingredienti:[{nome:"Datteri",qt:"200g"},{nome:"Mandorle",qt:"100g"},{nome:"Cocco rapé",qt:"40g"}],_dbEntry:{n:"Palline energetiche datteri e cocco (ricetta)",c:"Ricette",src:"RICETTE",k:160,p:3,gs:1.8,g:8,z:18,ch:20,fi:3,ca:30,fe:.8,mg:35,k2:220,na:5,zn:.5,fo:8,se:2,col:0}},{id:"tpl_2029",nome:"Torta di mele e cannella integrale",nome_en:"Whole-wheat apple cinnamon cake",categoria:"Dolce",porzioni:8,note:"Mescolare farina integrale, zucchero, cannella e lievito con le uova e l'olio. Aggiungere le mele tagliate a fettine sottili. Cuocere a 180°C per 40 minuti.",note_en:"Mix whole-wheat flour, sugar, cinnamon and baking powder with eggs and oil. Add thinly sliced apples. Bake at 180°C for 40 minutes.",ingredienti:[{nome:"Mele",qt:"3"},{nome:"Farina integrale",qt:"250g"},{nome:"Zucchero",qt:"100g"},{nome:"Cannella",qt:"1 cucchiaino"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"70ml"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta di mele e cannella integrale (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:4,gs:1.4,g:8,z:17,ch:34,fi:3,ca:30,fe:1.3,mg:22,k2:170,na:55,zn:.5,fo:16,se:5,col:45}},{id:"tpl_2030",nome:"Semifreddo al pistacchio (versione 2)",nome_en:"Pistachio semifreddo (version 2)",categoria:"Dolce",porzioni:6,note:"Tritare i pistacchi finemente e mescolarli con yogurt greco e miele. Montare la panna e incorporarla delicatamente al composto. Versare in uno stampo e congelare per almeno 5 ore.",note_en:"Finely chop the pistachios and mix with Greek yogurt and honey. Whip the cream and gently fold it into the mixture. Pour into a mold and freeze for at least 5 hours.",ingredienti:[{nome:"Pistacchi",qt:"80g"},{nome:"Yogurt greco",qt:"150g"},{nome:"Miele",qt:"50g"},{nome:"Panna fresca",qt:"200ml"}],_dbEntry:{n:"Semifreddo al pistacchio (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:5,gs:9,g:19,z:14,ch:14,fi:1.5,ca:80,fe:.9,mg:30,k2:200,na:30,zn:.7,fo:10,se:2,col:50}},{id:"tpl_2031",nome:"Budino di chia ai frutti rossi",nome_en:"Chia pudding with red fruits",categoria:"Dolce",porzioni:4,note:"Mescolare i semi di chia con latte e un cucchiaio di miele, lasciando riposare in frigo per almeno 4 ore fino a formare un gel. Mescolare di tanto in tanto per evitare grumi. Servire con frutti rossi freschi.",note_en:"Mix chia seeds with milk and a spoonful of honey, letting it rest in the fridge for at least 4 hours until it forms a gel. Stir occasionally to avoid clumps. Serve with fresh red fruits.",ingredienti:[{nome:"Semi di chia",qt:"40g"},{nome:"Latte",qt:"300ml"},{nome:"Miele",qt:"30g"},{nome:"Frutti rossi misti",qt:"100g"}],_dbEntry:{n:"Budino di chia ai frutti rossi (ricetta)",c:"Ricette",src:"RICETTE",k:190,p:6,gs:1.5,g:8,z:15,ch:22,fi:6,ca:180,fe:1.5,mg:50,k2:250,na:40,zn:.7,fo:12,se:4,col:6}},{id:"tpl_2032",nome:"Torta rustica di pere e cioccolato",nome_en:"Rustic pear and chocolate cake",categoria:"Dolce",porzioni:8,note:"Mescolare farina, zucchero, uova, olio e lievito fino a ottenere un impasto liscio. Unire le pere a cubetti e le gocce di cioccolato fondente. Cuocere in uno stampo a 180°C per 40 minuti.",note_en:"Mix flour, sugar, eggs, oil and baking powder into a smooth batter. Fold in diced pears and dark chocolate chips. Bake in a mold at 180°C for 40 minutes.",ingredienti:[{nome:"Pere",qt:"2"},{nome:"Farina",qt:"220g"},{nome:"Zucchero",qt:"90g"},{nome:"Uova",qt:"2"},{nome:"Olio di semi",qt:"60ml"},{nome:"Gocce di cioccolato fondente",qt:"60g"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta rustica di pere e cioccolato (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:4,gs:3,g:10,z:19,ch:38,fi:2.5,ca:35,fe:1.4,mg:25,k2:180,na:55,zn:.6,fo:16,se:5,col:45}},{id:"tpl_2033",nome:"Biscotti di farro al miele",nome_en:"Spelt and honey biscuits",categoria:"Dolce",porzioni:10,note:"Mescolare farina di farro, olio, miele e un uovo fino a ottenere un impasto compatto. Stendere e ritagliare i biscotti con uno stampino. Cuocere a 180°C per 15 minuti.",note_en:"Mix spelt flour, oil, honey and an egg into a compact dough. Roll out and cut biscuits with a cutter. Bake at 180°C for 15 minutes.",ingredienti:[{nome:"Farina di farro",qt:"250g"},{nome:"Olio di semi",qt:"60ml"},{nome:"Miele",qt:"90g"},{nome:"Uova",qt:"1"}],_dbEntry:{n:"Biscotti di farro al miele (ricetta)",c:"Ricette",src:"RICETTE",k:170,p:3,gs:.9,g:6,z:11,ch:26,fi:2,ca:15,fe:1,mg:20,k2:90,na:15,zn:.5,fo:10,se:4,col:20}},{id:"tpl_2034",nome:"Frutta grigliata con miele e cannella",nome_en:"Grilled fruit with honey and cinnamon",categoria:"Dolce",porzioni:4,note:"Tagliare a fette ananas, pesche e banane. Grigliarle brevemente su piastra calda fino a leggera caramellizzazione. Servire calde con un filo di miele e una spolverata di cannella.",note_en:"Slice pineapple, peaches and bananas. Grill briefly on a hot griddle until lightly caramelized. Serve warm with a drizzle of honey and a dusting of cinnamon.",ingredienti:[{nome:"Ananas",qt:"150g"},{nome:"Pesche",qt:"150g"},{nome:"Banane",qt:"1"},{nome:"Miele",qt:"30g"},{nome:"Cannella",qt:"1 cucchiaino"}],_dbEntry:{n:"Frutta grigliata con miele e cannella (ricetta)",c:"Ricette",src:"RICETTE",k:150,p:1.2,gs:.1,g:.5,z:28,ch:34,fi:3,ca:20,fe:.6,mg:20,k2:280,na:5,zn:.3,fo:15,se:1,col:0}},{id:"tpl_2035",nome:"Torta soffice al limone e yogurt",nome_en:"Fluffy lemon yogurt cake",categoria:"Dolce",porzioni:8,note:"Mescolare yogurt, uova, zucchero, olio e scorza di limone. Aggiungere farina setacciata e lievito, amalgamando bene. Versare in uno stampo e cuocere a 180°C per 35 minuti.",note_en:"Mix yogurt, eggs, sugar, oil and lemon zest. Add sifted flour and baking powder, combining well. Pour into a mold and bake at 180°C for 35 minutes.",ingredienti:[{nome:"Yogurt bianco",qt:"150g"},{nome:"Farina",qt:"220g"},{nome:"Zucchero",qt:"100g"},{nome:"Uova",qt:"3"},{nome:"Olio di semi",qt:"60ml"},{nome:"Scorza di limone",qt:"1"},{nome:"Lievito per dolci",qt:"1 bustina"}],_dbEntry:{n:"Torta soffice al limone e yogurt (ricetta)",c:"Ricette",src:"RICETTE",k:245,p:5,gs:2,g:9,z:16,ch:35,fi:1,ca:50,fe:1.1,mg:15,k2:110,na:60,zn:.5,fo:15,se:5,col:65}},{id:"tpl_2036",nome:"Petto di pollo alle erbe aromatiche",nome_en:"Herb-crusted chicken breast",categoria:"Secondo piatto",porzioni:4,note:"Massaggiare i petti di pollo con rosmarino, timo, aglio e olio. Cuocere in padella antiaderente a fuoco medio per 6-7 minuti per lato. Lasciar riposare qualche minuto prima di affettare.",note_en:"Rub the chicken breasts with rosemary, thyme, garlic and oil. Cook in a nonstick pan over medium heat for 6-7 minutes per side. Let rest a few minutes before slicing.",ingredienti:[{nome:"Petto di pollo",qt:"480g"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Timo fresco",qt:"q.b."},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Petto di pollo alle erbe aromatiche (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:34,gs:1.5,g:8,z:.2,ch:.5,fi:.2,ca:15,fe:1,mg:30,k2:380,na:70,zn:1,fo:8,se:25,col:85}},{id:"tpl_2037",nome:"Filetto di salmone al forno con limone",nome_en:"Baked salmon fillet with lemon",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di salmone su una teglia con fette di limone e rosmarino. Condire con olio, sale e pepe. Cuocere in forno a 200°C per 15 minuti.",note_en:"Arrange the salmon fillets on a baking tray with lemon slices and rosemary. Season with oil, salt and pepper. Bake at 200°C for 15 minutes.",ingredienti:[{nome:"Filetto di salmone",qt:"480g"},{nome:"Limone",qt:"1"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Filetto di salmone al forno con limone (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:29,gs:3.5,g:19,z:.3,ch:.8,fi:.1,ca:20,fe:.9,mg:35,k2:450,na:65,zn:.8,fo:20,se:35,col:70}},{id:"tpl_2038",nome:"Polpette di manzo al sugo",nome_en:"Beef meatballs in tomato sauce",categoria:"Secondo piatto",porzioni:4,note:"Impastare la carne macinata con pane ammollato nel latte, uovo, parmigiano e prezzemolo. Formare le polpette e rosolarle in padella. Terminare la cottura nel sugo di pomodoro per 20 minuti.",note_en:"Mix ground beef with bread soaked in milk, egg, parmesan and parsley. Shape into meatballs and brown in a pan. Finish cooking in tomato sauce for 20 minutes.",ingredienti:[{nome:"Carne di manzo macinata",qt:"400g"},{nome:"Pane raffermo",qt:"50g"},{nome:"Latte",qt:"50ml"},{nome:"Uova",qt:"1"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Passata di pomodoro",qt:"400g"}],_dbEntry:{n:"Polpette di manzo al sugo (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:26,gs:6,g:16,z:4,ch:14,fi:1.5,ca:90,fe:2.8,mg:30,k2:420,na:280,zn:4,fo:15,se:20,col:100}},{id:"tpl_2039",nome:"Scaloppine di vitello al limone",nome_en:"Veal scaloppine with lemon",categoria:"Secondo piatto",porzioni:4,note:"Infarinare leggermente le fettine di vitello e rosolarle in padella con burro. Sfumare con succo di limone e vino bianco, cuocendo per pochi minuti. Servire irrorate con il fondo di cottura.",note_en:"Lightly flour the veal slices and brown in a pan with butter. Deglaze with lemon juice and white wine, cooking for a few minutes. Serve drizzled with the pan juices.",ingredienti:[{nome:"Fettine di vitello",qt:"480g"},{nome:"Farina",qt:"20g"},{nome:"Burro",qt:"20g"},{nome:"Succo di limone",qt:"1 limone"},{nome:"Vino bianco",qt:"50ml"}],_dbEntry:{n:"Scaloppine di vitello al limone (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:32,gs:4,g:11,z:.5,ch:4,fi:.2,ca:15,fe:1.8,mg:28,k2:400,na:80,zn:3.5,fo:10,se:20,col:105}},{id:"tpl_2040",nome:"Orata al cartoccio con verdure",nome_en:"Sea bream in parchment with vegetables",categoria:"Secondo piatto",porzioni:4,note:"Pulire l'orata e disporla su carta forno con zucchine, pomodorini e olive tagliate. Condire con olio, sale e prezzemolo e chiudere il cartoccio. Cuocere in forno a 200°C per 20 minuti.",note_en:"Clean the sea bream and place it on parchment with zucchini, cherry tomatoes and sliced olives. Season with oil, salt and parsley and close the parcel. Bake at 200°C for 20 minutes.",ingredienti:[{nome:"Orata",qt:"2 (600g totali)"},{nome:"Zucchine",qt:"200g"},{nome:"Pomodorini",qt:"150g"},{nome:"Olive nere",qt:"40g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Orata al cartoccio con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:28,gs:2.5,g:12,z:2.5,ch:5,fi:1.8,ca:40,fe:1.2,mg:40,k2:480,na:180,zn:.9,fo:20,se:30,col:65}},{id:"tpl_2041",nome:"Tofu saltato con verdure miste",nome_en:"Stir-fried tofu with mixed vegetables",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il tofu a cubetti e rosolarlo in padella con poco olio fino a doratura. Aggiungere peperoni, carote e broccoli tagliati sottili e saltare a fuoco vivo. Insaporire con salsa di soia e zenzero.",note_en:"Cut tofu into cubes and brown in a pan with a little oil until golden. Add thinly sliced peppers, carrots and broccoli and stir-fry over high heat. Season with soy sauce and ginger.",ingredienti:[{nome:"Tofu",qt:"400g"},{nome:"Peperoni",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Broccoli",qt:"150g"},{nome:"Salsa di soia",qt:"2 cucchiai"},{nome:"Zenzero fresco",qt:"1 pezzetto"}],_dbEntry:{n:"Tofu saltato con verdure miste (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:16,gs:2,g:12,z:4,ch:11,fi:4,ca:180,fe:3,mg:60,k2:450,na:400,zn:1.5,fo:60,se:5,col:0}},{id:"tpl_2042",nome:"Hamburger di lenticchie",nome_en:"Lentil burgers",categoria:"Secondo piatto",porzioni:4,note:"Frullare le lenticchie cotte con cipolla, pangrattato e spezie fino a un composto compatto. Formare gli hamburger e farli riposare in frigo 30 minuti. Cuocere in padella con poco olio per 4 minuti per lato.",note_en:"Blend cooked lentils with onion, breadcrumbs and spices into a compact mixture. Shape into burgers and rest in the fridge for 30 minutes. Cook in a pan with a little oil for 4 minutes per side.",ingredienti:[{nome:"Lenticchie cotte",qt:"350g"},{nome:"Cipolla",qt:"1/2"},{nome:"Pangrattato",qt:"40g"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Hamburger di lenticchie (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:14,gs:1.2,g:8,z:3,ch:34,fi:9,ca:50,fe:4,mg:55,k2:520,na:150,zn:2,fo:150,se:5,col:0}},{id:"tpl_2043",nome:"Spezzatino di manzo alle verdure",nome_en:"Beef and vegetable stew",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i cubetti di manzo con cipolla, carota e sedano. Sfumare con vino rosso e aggiungere brodo e pomodoro. Cuocere a fuoco lento coperto per circa 90 minuti fino a intenerire la carne.",note_en:"Brown the beef cubes with onion, carrot and celery. Deglaze with red wine and add broth and tomato. Simmer covered for about 90 minutes until the meat is tender.",ingredienti:[{nome:"Spezzatino di manzo",qt:"500g"},{nome:"Cipolla",qt:"1"},{nome:"Carota",qt:"1"},{nome:"Sedano",qt:"1 costa"},{nome:"Vino rosso",qt:"100ml"},{nome:"Passata di pomodoro",qt:"150g"},{nome:"Brodo vegetale",qt:"300ml"}],_dbEntry:{n:"Spezzatino di manzo alle verdure (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:32,gs:5,g:14,z:4,ch:9,fi:2,ca:35,fe:3.5,mg:35,k2:550,na:200,zn:5,fo:20,se:22,col:95}},{id:"tpl_2044",nome:"Seppie in umido con piselli (versione 2)",nome_en:"Cuttlefish stew with peas (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Rosolare le seppie tagliate ad anelli con aglio e olio. Aggiungere passata di pomodoro e piselli, cuocendo a fuoco lento per 30 minuti. Aggiustare di sale e servire con prezzemolo fresco.",note_en:"Brown the sliced cuttlefish rings with garlic and oil. Add tomato passata and peas, simmering for 30 minutes. Season with salt and serve with fresh parsley.",ingredienti:[{nome:"Seppie",qt:"500g"},{nome:"Piselli",qt:"200g"},{nome:"Passata di pomodoro",qt:"200g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Seppie in umido con piselli (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:240,p:26,gs:1.5,g:9,z:4,ch:12,fi:3.5,ca:60,fe:2,mg:50,k2:450,na:250,zn:1.8,fo:60,se:35,col:220}},{id:"tpl_2045",nome:"Coniglio alla ligure con olive",nome_en:"Ligurian rabbit with olives",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di coniglio con aglio, rosmarino e olio. Sfumare con vino bianco e aggiungere olive taggiasche e pinoli. Cuocere coperto a fuoco lento per 45 minuti.",note_en:"Brown the rabbit pieces with garlic, rosemary and oil. Deglaze with white wine and add taggiasca olives and pine nuts. Cook covered over low heat for 45 minutes.",ingredienti:[{nome:"Coniglio a pezzi",qt:"600g"},{nome:"Olive taggiasche",qt:"60g"},{nome:"Pinoli",qt:"20g"},{nome:"Vino bianco",qt:"100ml"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Aglio",qt:"2 spicchi"}],_dbEntry:{n:"Coniglio alla ligure con olive (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:30,gs:3,g:18,z:.5,ch:2,fi:1,ca:30,fe:1.5,mg:25,k2:380,na:220,zn:2,fo:10,se:15,col:90}},{id:"tpl_2046",nome:"Tacchino alla milanese",nome_en:"Milanese-style turkey cutlet",categoria:"Secondo piatto",porzioni:4,note:"Passare le fettine di tacchino nell'uovo sbattuto e poi nel pangrattato. Cuocere in forno su una teglia foderata con un filo di olio a 200°C per 20 minuti girando a metà cottura. Servire con spicchi di limone.",note_en:"Dip the turkey slices in beaten egg and then in breadcrumbs. Bake on a lined tray with a drizzle of oil at 200°C for 20 minutes, turning halfway. Serve with lemon wedges.",ingredienti:[{nome:"Fettine di tacchino",qt:"480g"},{nome:"Uova",qt:"1"},{nome:"Pangrattato",qt:"80g"},{nome:"Olio extravergine",qt:"1 cucchiaio"},{nome:"Limone",qt:"1"}],_dbEntry:{n:"Tacchino alla milanese (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:33,gs:2.5,g:9,z:1,ch:16,fi:.8,ca:30,fe:1.5,mg:30,k2:350,na:130,zn:1.5,fo:15,se:22,col:120}},{id:"tpl_2047",nome:"Merluzzo al forno con pomodorini",nome_en:"Baked cod with cherry tomatoes",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di merluzzo in teglia con pomodorini tagliati e olive. Condire con olio, origano e sale. Cuocere in forno a 200°C per 18 minuti.",note_en:"Arrange the cod fillets in a baking dish with halved cherry tomatoes and olives. Season with oil, oregano and salt. Bake at 200°C for 18 minutes.",ingredienti:[{nome:"Filetto di merluzzo",qt:"480g"},{nome:"Pomodorini",qt:"200g"},{nome:"Olive nere",qt:"30g"},{nome:"Origano",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Merluzzo al forno con pomodorini (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:27,gs:1.5,g:8,z:2.5,ch:4,fi:1.2,ca:35,fe:.8,mg:30,k2:400,na:200,zn:.6,fo:15,se:30,col:60}},{id:"tpl_2048",nome:"Straccetti di pollo ai peperoni",nome_en:"Chicken strips with peppers",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il petto di pollo a striscioline e rosolarlo in padella con olio. Aggiungere i peperoni tagliati a listarelle e cuocere a fuoco vivo per 10 minuti. Insaporire con aglio e prezzemolo.",note_en:"Cut the chicken breast into strips and brown in a pan with oil. Add the peppers sliced into strips and cook over high heat for 10 minutes. Season with garlic and parsley.",ingredienti:[{nome:"Petto di pollo",qt:"450g"},{nome:"Peperoni",qt:"250g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Straccetti di pollo ai peperoni (ricetta)",c:"Ricette",src:"RICETTE",k:225,p:32,gs:1.5,g:8,z:4,ch:6,fi:2,ca:20,fe:1.1,mg:32,k2:420,na:80,zn:1,fo:20,se:24,col:85}},{id:"tpl_2049",nome:"Polpettone di tacchino ripieno",nome_en:"Stuffed turkey meatloaf",categoria:"Secondo piatto",porzioni:6,note:"Mescolare la carne di tacchino macinata con pangrattato, uovo e parmigiano. Stendere l'impasto e farcire con spinaci saltati e scamorza. Arrotolare e cuocere in forno a 180°C per 40 minuti.",note_en:"Mix ground turkey with breadcrumbs, egg and parmesan. Flatten the mixture and fill with sautéed spinach and scamorza cheese. Roll up and bake at 180°C for 40 minutes.",ingredienti:[{nome:"Carne di tacchino macinata",qt:"500g"},{nome:"Pangrattato",qt:"40g"},{nome:"Uova",qt:"1"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Spinaci",qt:"150g"},{nome:"Scamorza",qt:"80g"}],_dbEntry:{n:"Polpettone di tacchino ripieno (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:29,gs:5,g:13,z:1,ch:9,fi:1.2,ca:150,fe:2,mg:35,k2:400,na:280,zn:2,fo:60,se:20,col:110}},{id:"tpl_2050",nome:"Trota al forno con mandorle",nome_en:"Baked trout with almonds",categoria:"Secondo piatto",porzioni:4,note:"Disporre le trote pulite in teglia con fettine di limone. Cospargere con mandorle a lamelle e un filo di olio. Cuocere in forno a 200°C per 20 minuti.",note_en:"Arrange the cleaned trout in a baking dish with lemon slices. Sprinkle with sliced almonds and a drizzle of oil. Bake at 200°C for 20 minutes.",ingredienti:[{nome:"Trota",qt:"4 (600g totali)"},{nome:"Mandorle a lamelle",qt:"40g"},{nome:"Limone",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Trota al forno con mandorle (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:30,gs:2.5,g:16,z:.5,ch:2,fi:1,ca:50,fe:1.3,mg:45,k2:450,na:90,zn:1,fo:15,se:20,col:75}},{id:"tpl_2051",nome:"Cotoletta di pollo al forno",nome_en:"Oven-baked chicken cutlet",categoria:"Secondo piatto",porzioni:4,note:"Battere leggermente i petti di pollo e passarli nell'uovo e poi nel pangrattato con parmigiano. Disporre su una teglia con carta forno e un filo di olio. Cuocere a 200°C per 20 minuti girando a metà cottura.",note_en:"Lightly flatten the chicken breasts and dip in egg then breadcrumbs with parmesan. Place on a lined tray with a drizzle of oil. Bake at 200°C for 20 minutes, turning halfway.",ingredienti:[{nome:"Petto di pollo",qt:"480g"},{nome:"Uova",qt:"1"},{nome:"Pangrattato",qt:"70g"},{nome:"Parmigiano grattugiato",qt:"20g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Cotoletta di pollo al forno (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:36,gs:3,g:10,z:1,ch:15,fi:.7,ca:60,fe:1.3,mg:32,k2:380,na:180,zn:1.2,fo:15,se:24,col:130}},{id:"tpl_2052",nome:"Involtini di manzo al sugo",nome_en:"Beef rolls in tomato sauce",categoria:"Secondo piatto",porzioni:4,note:"Farcire le fettine di manzo con prosciutto, formaggio e prezzemolo, arrotolare e fermare con uno stuzzicadenti. Rosolare gli involtini in padella e cuocere nella passata di pomodoro per 30 minuti.",note_en:"Fill the beef slices with ham, cheese and parsley, roll up and secure with a toothpick. Brown the rolls in a pan and cook in tomato passata for 30 minutes.",ingredienti:[{nome:"Fettine di manzo",qt:"480g"},{nome:"Prosciutto cotto",qt:"80g"},{nome:"Formaggio a fette",qt:"80g"},{nome:"Passata di pomodoro",qt:"250g"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Involtini di manzo al sugo (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:35,gs:8,g:19,z:3,ch:6,fi:1,ca:180,fe:2.8,mg:30,k2:420,na:450,zn:4,fo:15,se:20,col:110}},{id:"tpl_2053",nome:"Baccalà alla livornese (versione 2)",nome_en:"Livorno-style salt cod (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Dissalare il baccalà e tagliarlo a pezzi. Cuocerlo in un sugo di pomodoro con aglio, prezzemolo e capperi per 20 minuti. Servire caldo con il sugo.",note_en:"Desalt the cod and cut into pieces. Cook it in a tomato sauce with garlic, parsley and capers for 20 minutes. Serve hot with the sauce.",ingredienti:[{nome:"Baccalà dissalato",qt:"500g"},{nome:"Passata di pomodoro",qt:"300g"},{nome:"Capperi",qt:"20g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Baccalà alla livornese (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:210,p:28,gs:1,g:6,z:4,ch:8,fi:1.5,ca:40,fe:1.2,mg:35,k2:450,na:400,zn:.8,fo:20,se:35,col:65}},{id:"tpl_2054",nome:"Petto d'anatra all'arancia",nome_en:"Duck breast with orange",categoria:"Secondo piatto",porzioni:4,note:"Incidere la pelle del petto d'anatra e rosolarlo dal lato della pelle finché croccante. Girare e completare la cottura in forno per 8 minuti. Servire con salsa ridotta di succo d'arancia e miele.",note_en:"Score the duck breast skin and sear it skin-side down until crisp. Turn and finish cooking in the oven for 8 minutes. Serve with a reduced orange juice and honey sauce.",ingredienti:[{nome:"Petto d'anatra",qt:"480g"},{nome:"Arance",qt:"2"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Vino bianco",qt:"50ml"}],_dbEntry:{n:"Petto d'anatra all'arancia (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:28,gs:6,g:20,z:9,ch:11,fi:.5,ca:20,fe:2.5,mg:25,k2:400,na:80,zn:2,fo:15,se:15,col:110}},{id:"tpl_2055",nome:"Polpo alla griglia con patate",nome_en:"Grilled octopus with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Lessare il polpo in acqua bollente per circa 40 minuti fino a intenerire. Tagliarlo a pezzi e grigliarlo brevemente su piastra calda. Servire con patate lesse condite con olio e prezzemolo.",note_en:"Boil the octopus in boiling water for about 40 minutes until tender. Cut into pieces and grill briefly on a hot griddle. Serve with boiled potatoes dressed with oil and parsley.",ingredienti:[{nome:"Polpo",qt:"600g"},{nome:"Patate",qt:"300g"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Polpo alla griglia con patate (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:26,gs:1.5,g:9,z:1,ch:20,fi:2,ca:40,fe:2.5,mg:45,k2:550,na:200,zn:2,fo:20,se:40,col:80}},{id:"tpl_2056",nome:"Frittata di verdure al forno",nome_en:"Baked vegetable frittata",categoria:"Secondo piatto",porzioni:4,note:"Sbattere le uova con parmigiano, sale e pepe. Aggiungere zucchine, peperoni e cipolla saltati in precedenza. Versare in una teglia e cuocere in forno a 180°C per 25 minuti.",note_en:"Beat the eggs with parmesan, salt and pepper. Add previously sautéed zucchini, peppers and onion. Pour into a baking dish and bake at 180°C for 25 minutes.",ingredienti:[{nome:"Uova",qt:"6"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"100g"},{nome:"Cipolla",qt:"1/2"},{nome:"Parmigiano grattugiato",qt:"30g"}],_dbEntry:{n:"Frittata di verdure al forno (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:15,gs:4,g:15,z:3,ch:5,fi:1.5,ca:120,fe:1.8,mg:25,k2:300,na:200,zn:1.3,fo:40,se:20,col:330}},{id:"tpl_2057",nome:"Burger di ceci e curry",nome_en:"Chickpea curry burgers",categoria:"Secondo piatto",porzioni:4,note:"Frullare i ceci cotti con curry, cipolla e pangrattato fino a un composto compatto. Formare gli hamburger e farli riposare 20 minuti in frigo. Cuocere in padella con poco olio per 4 minuti per lato.",note_en:"Blend cooked chickpeas with curry, onion and breadcrumbs into a compact mixture. Shape into burgers and rest in the fridge for 20 minutes. Cook in a pan with a little oil for 4 minutes per side.",ingredienti:[{nome:"Ceci cotti",qt:"350g"},{nome:"Curry in polvere",qt:"1 cucchiaino"},{nome:"Cipolla",qt:"1/2"},{nome:"Pangrattato",qt:"40g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Burger di ceci e curry (ricetta)",c:"Ricette",src:"RICETTE",k:280,p:12,gs:1.5,g:9,z:4,ch:38,fi:8,ca:60,fe:3,mg:50,k2:450,na:150,zn:1.8,fo:120,se:5,col:0}},{id:"tpl_2058",nome:"Tonno scottato con sesamo",nome_en:"Sesame-seared tuna",categoria:"Secondo piatto",porzioni:4,note:"Passare i tranci di tonno nei semi di sesamo misti. Scottare in padella rovente per 1-2 minuti per lato lasciando il cuore rosa. Servire con salsa di soia e lime.",note_en:"Coat the tuna steaks in mixed sesame seeds. Sear in a very hot pan for 1-2 minutes per side leaving the center pink. Serve with soy sauce and lime.",ingredienti:[{nome:"Tonno fresco a tranci",qt:"480g"},{nome:"Semi di sesamo",qt:"30g"},{nome:"Salsa di soia",qt:"2 cucchiai"},{nome:"Lime",qt:"1"}],_dbEntry:{n:"Tonno scottato con sesamo (ricetta)",c:"Ricette",src:"RICETTE",k:270,p:34,gs:2.5,g:12,z:.5,ch:2,fi:1,ca:60,fe:1.8,mg:45,k2:450,na:350,zn:1,fo:15,se:60,col:55}},{id:"tpl_2059",nome:"Pollo al curry leggero",nome_en:"Light chicken curry",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i bocconcini di pollo con cipolla e curry in poco olio. Aggiungere latte di cocco light e cuocere a fuoco lento per 20 minuti. Servire caldo con coriandolo fresco.",note_en:"Brown the chicken chunks with onion and curry in a little oil. Add light coconut milk and simmer for 20 minutes. Serve hot with fresh coriander.",ingredienti:[{nome:"Petto di pollo",qt:"450g"},{nome:"Cipolla",qt:"1"},{nome:"Curry in polvere",qt:"1 cucchiaio"},{nome:"Latte di cocco light",qt:"200ml"},{nome:"Coriandolo fresco",qt:"q.b."}],_dbEntry:{n:"Pollo al curry leggero (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:32,gs:6,g:15,z:3,ch:6,fi:1.5,ca:25,fe:1.5,mg:35,k2:420,na:120,zn:1.2,fo:15,se:22,col:85}},{id:"tpl_2060",nome:"Vitello tonnato light",nome_en:"Light vitello tonnato",categoria:"Secondo piatto",porzioni:4,note:"Cuocere il girello di vitello in acqua aromatizzata con verdure per circa 1 ora, poi lasciar raffreddare e affettare sottile. Frullare tonno, yogurt greco e capperi per la salsa. Nappare le fette di vitello con la salsa e guarnire con capperi.",note_en:"Cook the veal in vegetable-flavored water for about 1 hour, then let cool and slice thinly. Blend tuna, Greek yogurt and capers for the sauce. Coat the veal slices with the sauce and garnish with capers.",ingredienti:[{nome:"Girello di vitello",qt:"400g"},{nome:"Tonno sott'olio",qt:"100g"},{nome:"Yogurt greco",qt:"100g"},{nome:"Capperi",qt:"20g"}],_dbEntry:{n:"Vitello tonnato light (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:33,gs:3,g:11,z:1,ch:2,fi:.3,ca:40,fe:1.7,mg:30,k2:400,na:250,zn:3.5,fo:12,se:30,col:90}},{id:"tpl_2061",nome:"Gamberi saltati con zucchine",nome_en:"Stir-fried shrimp with zucchini",categoria:"Secondo piatto",porzioni:4,note:"Saltare i gamberi sgusciati in padella con aglio e olio finché rosati. Aggiungere le zucchine a rondelle e cuocere a fuoco vivo per 5 minuti. Insaporire con prezzemolo e un filo di limone.",note_en:"Stir-fry the peeled shrimp in a pan with garlic and oil until pink. Add sliced zucchini and cook over high heat for 5 minutes. Season with parsley and a squeeze of lemon.",ingredienti:[{nome:"Gamberi sgusciati",qt:"400g"},{nome:"Zucchine",qt:"250g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Limone",qt:"1/2"}],_dbEntry:{n:"Gamberi saltati con zucchine (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:24,gs:1.5,g:9,z:2,ch:5,fi:1.5,ca:70,fe:1.5,mg:40,k2:380,na:300,zn:1.5,fo:20,se:35,col:190}},{id:"tpl_2062",nome:"Falafel di ceci al forno",nome_en:"Oven-baked chickpea falafel",categoria:"Secondo piatto",porzioni:4,note:"Frullare i ceci ammollati con cipolla, aglio, cumino e coriandolo fino a un composto denso. Formare delle palline schiacciate e disporle su una teglia con carta forno. Cuocere a 200°C per 25 minuti girando a metà.",note_en:"Blend soaked chickpeas with onion, garlic, cumin and coriander into a thick mixture. Form flattened balls and place on a lined tray. Bake at 200°C for 25 minutes, turning halfway.",ingredienti:[{nome:"Ceci secchi ammollati",qt:"250g"},{nome:"Cipolla",qt:"1/2"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Coriandolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Falafel di ceci al forno (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:11,gs:1,g:9,z:3,ch:34,fi:8,ca:60,fe:3,mg:50,k2:400,na:100,zn:1.8,fo:130,se:5,col:0}},{id:"tpl_2063",nome:"Arrosto di maiale alle mele",nome_en:"Pork roast with apples",categoria:"Secondo piatto",porzioni:6,note:"Rosolare l'arrosto di maiale a fuoco vivo su tutti i lati. Aggiungere le mele a spicchi, il vino bianco e il rosmarino, coprire e cuocere a fuoco lento per 1 ora. Affettare e servire con le mele stufate.",note_en:"Brown the pork roast on all sides over high heat. Add the sliced apples, white wine and rosemary, cover and simmer for 1 hour. Slice and serve with the stewed apples.",ingredienti:[{nome:"Arrosto di maiale",qt:"700g"},{nome:"Mele",qt:"3"},{nome:"Vino bianco",qt:"150ml"},{nome:"Rosmarino fresco",qt:"q.b."}],_dbEntry:{n:"Arrosto di maiale alle mele (ricetta)",c:"Ricette",src:"RICETTE",k:320,p:32,gs:5,g:15,z:8,ch:12,fi:1.5,ca:20,fe:1.5,mg:30,k2:450,na:80,zn:2.5,fo:10,se:25,col:95}},{id:"tpl_2064",nome:"Calamari ripieni al forno (versione 2)",nome_en:"Oven-baked stuffed squid (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Tritare i tentacoli dei calamari e mescolarli con pangrattato, prezzemolo e aglio. Farcire le sacche dei calamari con il composto e chiuderle con uno stecchino. Cuocere in forno a 200°C per 25 minuti con un filo di olio e vino bianco.",note_en:"Chop the squid tentacles and mix with breadcrumbs, parsley and garlic. Stuff the squid tubes with the mixture and close with a toothpick. Bake at 200°C for 25 minutes with a drizzle of oil and white wine.",ingredienti:[{nome:"Calamari",qt:"500g"},{nome:"Pangrattato",qt:"50g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Aglio",qt:"1 spicchio"},{nome:"Vino bianco",qt:"50ml"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Calamari ripieni al forno (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:26,gs:1.5,g:9,z:1,ch:14,fi:1,ca:50,fe:1.5,mg:35,k2:380,na:250,zn:1.5,fo:20,se:35,col:280}},{id:"tpl_2065",nome:"Petto di pollo in crosta di pistacchi",nome_en:"Pistachio-crusted chicken breast",categoria:"Secondo piatto",porzioni:4,note:"Passare i petti di pollo nella senape e poi nei pistacchi tritati grossolanamente. Disporre su una teglia con carta forno. Cuocere a 190°C per 22 minuti.",note_en:"Coat the chicken breasts with mustard and then coarsely chopped pistachios. Place on a lined tray. Bake at 190°C for 22 minutes.",ingredienti:[{nome:"Petto di pollo",qt:"480g"},{nome:"Pistacchi tritati",qt:"60g"},{nome:"Senape",qt:"1 cucchiaio"}],_dbEntry:{n:"Petto di pollo in crosta di pistacchi (ricetta)",c:"Ricette",src:"RICETTE",k:310,p:37,gs:2.5,g:14,z:1,ch:6,fi:1.5,ca:30,fe:1.5,mg:40,k2:420,na:120,zn:1.3,fo:15,se:26,col:85}},{id:"tpl_2066",nome:"Salmone in crosta di erbe (versione 2)",nome_en:"Herb-crusted salmon (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Mescolare pangrattato con prezzemolo, erba cipollina e scorza di limone. Premere il composto sui filetti di salmone e disporli in teglia. Cuocere in forno a 200°C per 15 minuti.",note_en:"Mix breadcrumbs with parsley, chives and lemon zest. Press the mixture onto the salmon fillets and place them in a baking dish. Bake at 200°C for 15 minutes.",ingredienti:[{nome:"Filetto di salmone",qt:"480g"},{nome:"Pangrattato",qt:"40g"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Erba cipollina",qt:"q.b."},{nome:"Scorza di limone",qt:"1"}],_dbEntry:{n:"Salmone in crosta di erbe (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:30,gs:3.5,g:18,z:1,ch:8,fi:.5,ca:25,fe:1,mg:35,k2:440,na:100,zn:.9,fo:20,se:35,col:70}},{id:"tpl_2067",nome:"Spiedini di pollo e verdure (versione 2)",nome_en:"Chicken and vegetable skewers (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il pollo a cubetti e marinarlo con olio, limone e origano per 30 minuti. Infilzare alternando con peperoni e cipolla su spiedini. Grigliare per circa 12 minuti girando spesso.",note_en:"Cut the chicken into cubes and marinate with oil, lemon and oregano for 30 minutes. Thread onto skewers alternating with peppers and onion. Grill for about 12 minutes, turning often.",ingredienti:[{nome:"Petto di pollo",qt:"450g"},{nome:"Peperoni",qt:"150g"},{nome:"Cipolla",qt:"1"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Limone",qt:"1"},{nome:"Origano",qt:"q.b."}],_dbEntry:{n:"Spiedini di pollo e verdure (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:33,gs:1.5,g:8,z:5,ch:8,fi:2,ca:25,fe:1.2,mg:32,k2:420,na:80,zn:1,fo:20,se:24,col:85}},{id:"tpl_2068",nome:"Bocconcini di tacchino ai funghi",nome_en:"Turkey bites with mushrooms",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il tacchino a bocconcini e rosolarlo in padella con olio. Aggiungere i funghi affettati e cuocere a fuoco medio per 15 minuti. Sfumare con vino bianco e insaporire con prezzemolo.",note_en:"Cut the turkey into bite-size pieces and brown in a pan with oil. Add sliced mushrooms and cook over medium heat for 15 minutes. Deglaze with white wine and season with parsley.",ingredienti:[{nome:"Petto di tacchino",qt:"450g"},{nome:"Funghi champignon",qt:"250g"},{nome:"Vino bianco",qt:"50ml"},{nome:"Olio extravergine",qt:"2 cucchiai"},{nome:"Prezzemolo fresco",qt:"q.b."}],_dbEntry:{n:"Bocconcini di tacchino ai funghi (ricetta)",c:"Ricette",src:"RICETTE",k:220,p:32,gs:1.5,g:7,z:2,ch:4,fi:1.5,ca:20,fe:1.5,mg:35,k2:480,na:70,zn:1.5,fo:20,se:20,col:85}},{id:"tpl_2069",nome:"Sgombro al forno con patate",nome_en:"Baked mackerel with potatoes",categoria:"Secondo piatto",porzioni:4,note:"Disporre i filetti di sgombro in teglia su un letto di patate a fette. Condire con olio, limone e rosmarino. Cuocere in forno a 200°C per 25 minuti.",note_en:"Arrange the mackerel fillets in a baking dish over a layer of sliced potatoes. Season with oil, lemon and rosemary. Bake at 200°C for 25 minutes.",ingredienti:[{nome:"Filetto di sgombro",qt:"480g"},{nome:"Patate",qt:"300g"},{nome:"Limone",qt:"1"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Sgombro al forno con patate (ricetta)",c:"Ricette",src:"RICETTE",k:340,p:26,gs:4,g:18,z:1.5,ch:20,fi:2,ca:30,fe:1.8,mg:45,k2:600,na:100,zn:1,fo:25,se:35,col:65}},{id:"tpl_2070",nome:"Seitan alla piastra con verdure",nome_en:"Grilled seitan with vegetables",categoria:"Secondo piatto",porzioni:4,note:"Marinare il seitan a fette con olio, salsa di soia e aglio per 20 minuti. Cuocerlo su piastra calda per 4 minuti per lato. Servire con verdure grigliate miste.",note_en:"Marinate the sliced seitan with oil, soy sauce and garlic for 20 minutes. Cook on a hot griddle for 4 minutes per side. Serve with mixed grilled vegetables.",ingredienti:[{nome:"Seitan",qt:"400g"},{nome:"Salsa di soia",qt:"2 cucchiai"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Zucchine",qt:"150g"},{nome:"Peperoni",qt:"150g"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Seitan alla piastra con verdure (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:26,gs:1,g:8,z:3,ch:12,fi:2.5,ca:40,fe:2.5,mg:35,k2:350,na:450,zn:1,fo:20,se:5,col:0}},{id:"tpl_2071",nome:"Cotechino leggero con lenticchie",nome_en:"Light cotechino with lentils",categoria:"Secondo piatto",porzioni:4,note:"Lessare il cotechino in acqua per il tempo indicato sulla confezione. Cuocere le lenticchie con cipolla, carota e alloro fino a morbidezza. Affettare il cotechino e servirlo caldo sulle lenticchie.",note_en:"Boil the cotechino in water for the time indicated on the package. Cook the lentils with onion, carrot and bay leaf until tender. Slice the cotechino and serve hot over the lentils.",ingredienti:[{nome:"Cotechino",qt:"400g"},{nome:"Lenticchie",qt:"200g"},{nome:"Cipolla",qt:"1/2"},{nome:"Carota",qt:"1"},{nome:"Alloro",qt:"1 foglia"}],_dbEntry:{n:"Cotechino leggero con lenticchie (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:22,gs:10,g:22,z:3,ch:22,fi:6,ca:40,fe:3.5,mg:45,k2:500,na:600,zn:2.5,fo:100,se:15,col:60}},{id:"tpl_2072",nome:"Pollo alla cacciatora (versione 2)",nome_en:"Chicken cacciatore (version 2)",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i pezzi di pollo con cipolla e aglio in olio. Sfumare con vino bianco e aggiungere pomodori e olive. Cuocere coperto a fuoco lento per 40 minuti.",note_en:"Brown the chicken pieces with onion and garlic in oil. Deglaze with white wine and add tomatoes and olives. Cook covered over low heat for 40 minutes.",ingredienti:[{nome:"Pollo a pezzi",qt:"600g"},{nome:"Cipolla",qt:"1"},{nome:"Aglio",qt:"2 spicchi"},{nome:"Vino bianco",qt:"100ml"},{nome:"Pomodori pelati",qt:"300g"},{nome:"Olive nere",qt:"40g"}],_dbEntry:{n:"Pollo alla cacciatora (versione 2) (ricetta)",c:"Ricette",src:"RICETTE",k:290,p:31,gs:3,g:14,z:4,ch:8,fi:2,ca:35,fe:1.8,mg:35,k2:450,na:250,zn:1.3,fo:20,se:22,col:110}},{id:"tpl_2073",nome:"Filetto di branzino all'acqua pazza",nome_en:"Sea bass in acqua pazza",categoria:"Secondo piatto",porzioni:4,note:"Rosolare aglio e pomodorini in olio. Aggiungere i filetti di branzino, un po' di acqua e prezzemolo. Cuocere coperto a fuoco medio per 12 minuti.",note_en:"Sauté garlic and cherry tomatoes in oil. Add the sea bass fillets, a splash of water and parsley. Cook covered over medium heat for 12 minutes.",ingredienti:[{nome:"Filetto di branzino",qt:"480g"},{nome:"Pomodorini",qt:"150g"},{nome:"Aglio",qt:"1 spicchio"},{nome:"Prezzemolo fresco",qt:"q.b."},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Filetto di branzino all'acqua pazza (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:28,gs:1.5,g:10,z:2,ch:4,fi:1,ca:30,fe:1,mg:35,k2:420,na:150,zn:.8,fo:15,se:30,col:65}},{id:"tpl_2074",nome:"Polpette di lenticchie e verdure",nome_en:"Lentil and vegetable meatballs",categoria:"Secondo piatto",porzioni:4,note:"Frullare le lenticchie cotte con carote grattugiate, pangrattato e spezie. Formare le polpette e disporle su una teglia. Cuocere in forno a 200°C per 20 minuti girando a metà.",note_en:"Blend cooked lentils with grated carrots, breadcrumbs and spices. Shape into meatballs and place on a tray. Bake at 200°C for 20 minutes, turning halfway.",ingredienti:[{nome:"Lenticchie cotte",qt:"300g"},{nome:"Carote",qt:"100g"},{nome:"Pangrattato",qt:"40g"},{nome:"Cumino",qt:"1 cucchiaino"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Polpette di lenticchie e verdure (ricetta)",c:"Ricette",src:"RICETTE",k:230,p:13,gs:.8,g:6,z:4,ch:32,fi:8,ca:50,fe:3.5,mg:50,k2:480,na:120,zn:1.8,fo:140,se:5,col:0}},{id:"tpl_2075",nome:"Scaloppine di tacchino ai funghi porcini",nome_en:"Turkey scaloppine with porcini mushrooms",categoria:"Secondo piatto",porzioni:4,note:"Infarinare leggermente le fettine di tacchino e rosolarle in padella con olio. Aggiungere i funghi porcini ammollati e tagliati, cuocendo per 10 minuti. Sfumare con vino bianco e servire caldo.",note_en:"Lightly flour the turkey slices and brown in a pan with oil. Add soaked and sliced porcini mushrooms, cooking for 10 minutes. Deglaze with white wine and serve hot.",ingredienti:[{nome:"Fettine di tacchino",qt:"480g"},{nome:"Funghi porcini secchi",qt:"30g"},{nome:"Farina",qt:"20g"},{nome:"Vino bianco",qt:"50ml"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Scaloppine di tacchino ai funghi porcini (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:34,gs:1.5,g:9,z:1,ch:8,fi:1.5,ca:25,fe:2,mg:35,k2:450,na:100,zn:1.5,fo:20,se:22,col:85}},{id:"tpl_2076",nome:"Costolette di agnello alle erbe",nome_en:"Herb-crusted lamb chops",categoria:"Secondo piatto",porzioni:4,note:"Marinare le costolette di agnello con rosmarino, aglio e olio per 30 minuti. Grigliare o cuocere in padella per 3-4 minuti per lato. Lasciar riposare qualche minuto prima di servire.",note_en:"Marinate the lamb chops with rosemary, garlic and oil for 30 minutes. Grill or pan-cook for 3-4 minutes per side. Let rest a few minutes before serving.",ingredienti:[{nome:"Costolette di agnello",qt:"600g"},{nome:"Rosmarino fresco",qt:"q.b."},{nome:"Aglio",qt:"2 spicchi"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Costolette di agnello alle erbe (ricetta)",c:"Ricette",src:"RICETTE",k:380,p:30,gs:12,g:26,z:.3,ch:1,fi:.2,ca:25,fe:2,mg:25,k2:350,na:80,zn:4,fo:12,se:20,col:100}},{id:"tpl_2077",nome:"Frittata di zucchine al forno",nome_en:"Baked zucchini frittata",categoria:"Secondo piatto",porzioni:4,note:"Saltare le zucchine a rondelle in padella con poco olio. Sbattere le uova con parmigiano e unire le zucchine. Versare in teglia e cuocere in forno a 180°C per 25 minuti.",note_en:"Sauté sliced zucchini in a pan with a little oil. Beat the eggs with parmesan and mix in the zucchini. Pour into a baking dish and bake at 180°C for 25 minutes.",ingredienti:[{nome:"Zucchine",qt:"300g"},{nome:"Uova",qt:"6"},{nome:"Parmigiano grattugiato",qt:"30g"},{nome:"Olio extravergine",qt:"1 cucchiaio"}],_dbEntry:{n:"Frittata di zucchine al forno (ricetta)",c:"Ricette",src:"RICETTE",k:200,p:14,gs:3.5,g:14,z:2,ch:3,fi:1,ca:110,fe:1.6,mg:22,k2:280,na:180,zn:1.2,fo:35,se:18,col:320}},{id:"tpl_2078",nome:"Tempeh saltato con verdure asiatiche",nome_en:"Stir-fried tempeh with Asian vegetables",categoria:"Secondo piatto",porzioni:4,note:"Tagliare il tempeh a fette e rosolarlo in padella con poco olio fino a doratura. Aggiungere cavolo cinese, carote e germogli di soia e saltare a fuoco vivo. Insaporire con salsa di soia e zenzero fresco.",note_en:"Cut the tempeh into slices and brown in a pan with a little oil until golden. Add Chinese cabbage, carrots and bean sprouts and stir-fry over high heat. Season with soy sauce and fresh ginger.",ingredienti:[{nome:"Tempeh",qt:"350g"},{nome:"Cavolo cinese",qt:"150g"},{nome:"Carote",qt:"100g"},{nome:"Germogli di soia",qt:"100g"},{nome:"Salsa di soia",qt:"2 cucchiai"},{nome:"Zenzero fresco",qt:"1 pezzetto"}],_dbEntry:{n:"Tempeh saltato con verdure asiatiche (ricetta)",c:"Ricette",src:"RICETTE",k:250,p:20,gs:2,g:13,z:4,ch:12,fi:5,ca:120,fe:3,mg:70,k2:500,na:420,zn:1.8,fo:50,se:5,col:0}},{id:"tpl_2079",nome:"Pollo alle mandorle e miele",nome_en:"Almond and honey chicken",categoria:"Secondo piatto",porzioni:4,note:"Rosolare i bocconcini di pollo in padella con olio fino a doratura. Aggiungere un cucchiaio di miele e le mandorle a lamelle, cuocendo ancora 5 minuti. Servire caldo con il fondo di cottura.",note_en:"Brown the chicken chunks in a pan with oil until golden. Add a spoonful of honey and sliced almonds, cooking for another 5 minutes. Serve hot with the pan juices.",ingredienti:[{nome:"Petto di pollo",qt:"450g"},{nome:"Mandorle a lamelle",qt:"40g"},{nome:"Miele",qt:"1 cucchiaio"},{nome:"Olio extravergine",qt:"2 cucchiai"}],_dbEntry:{n:"Pollo alle mandorle e miele (ricetta)",c:"Ricette",src:"RICETTE",k:300,p:34,gs:2,g:14,z:6,ch:8,fi:1.5,ca:40,fe:1.5,mg:40,k2:400,na:80,zn:1.2,fo:15,se:24,col:85}},{id:"tpl_2080",nome:"Baccalà mantecato leggero",nome_en:"Light whipped salt cod",categoria:"Secondo piatto",porzioni:4,note:"Lessare il baccalà dissalato in acqua e latte fino a cottura. Frullarlo con un filo di olio a filo e uno spicchio d'aglio fino a ottenere una crema morbida. Servire tiepido con crostini di pane.",note_en:"Boil the desalted cod in water and milk until cooked. Blend it with a drizzle of oil and a garlic clove into a soft cream. Serve warm with bread crostini.",ingredienti:[{nome:"Baccalà dissalato",qt:"500g"},{nome:"Latte",qt:"200ml"},{nome:"Olio extravergine",qt:"3 cucchiai"},{nome:"Aglio",qt:"1 spicchio"}],_dbEntry:{n:"Baccalà mantecato leggero (ricetta)",c:"Ricette",src:"RICETTE",k:260,p:27,gs:2,g:14,z:1,ch:3,fi:.2,ca:60,fe:1,mg:30,k2:400,na:350,zn:.8,fo:15,se:35,col:65}}],"function"==typeof rebuildDB&&rebuildDB();